  -------------------------------------------------------------------
  -- Função para Verificar se Usa Regra Específica de Medicamentos --
  -------------------------------------------------------------------
  FUNCTION FUSA_REGRA_MEDICAMENTOS(pi_vCodFilial IN VARCHAR2,
                                   pi_vNome      IN VARCHAR2)
  RETURN VARCHAR2 IS
    vvRetUsaRegraMedicamentos VARCHAR2(1);
  BEGIN
    -- Verifica se usa regra
    BEGIN
      EXECUTE IMMEDIATE ' SELECT VALOR FROM PCREGRASEXCECAOMED WHERE NOME = ' || '''' || pi_vNome || '''' || ' AND CODFILIAL = ' || '''' || pi_vCodFilial || ''''
                   INTO vvRetUsaRegraMedicamentos;
    EXCEPTION
      WHEN NO_DATA_FOUND THEN
        vvRetUsaRegraMedicamentos := 'N';
      WHEN OTHERS THEN
        vvRetUsaRegraMedicamentos := 'N';
    END;
    -- Retorno
    RETURN vvRetUsaRegraMedicamentos;
  END FUSA_REGRA_MEDICAMENTOS;
    
 /************************************************************
  Procedimento para Obter o Verba da Promoção - DDMEDICA-5009
  ***********************************************************/
  PROCEDURE P_OBTER_VERBA_PROMOCAO(pi_nCodPromocaoMed        IN NUMBER,
                                   pi_nCodFornec             IN NUMBER,
                                   pio_nVlDescCmvPromocaoMed IN OUT NUMBER,
                                   po_nNumVerba              OUT NUMBER,
                                   po_nValorCotaNumVerba     OUT NUMBER,
                                   po_vSemVerbaVlDescCmv     OUT VARCHAR2) IS
  BEGIN
  
    -- Inicializa Retornos
    po_nNumVerba          := NULL;
    po_nValorCotaNumVerba := NULL; 
    po_vSemVerbaVlDescCmv := NULL;
    
    -- Se tem Verba de Fornecedor para Rebaixa de CMV na Promoção
    IF (NVL(pio_nVlDescCmvPromocaoMed,0) > 0) THEN
      BEGIN
        SELECT PCPROMOCAOVERBAMED.NUMVERBA
             , PCPROMOCAOVERBAMED.VALORCOTA
             , 'N'
          INTO po_nNumVerba
             , po_nValorCotaNumVerba
             , po_vSemVerbaVlDescCmv
         FROM PCPROMOCAOVERBAMED
            , PCVERBA
        WHERE (PCPROMOCAOVERBAMED.CODPROMOCAOMED = pi_nCodPromocaoMed) 
          AND (PCPROMOCAOVERBAMED.NUMVERBA       = PCVERBA.NUMVERBA)
          AND (PCVERBA.CODFORNEC                 = pi_nCodFornec)
          AND (ROWNUM                            = 1);
      EXCEPTION
        WHEN NO_DATA_FOUND THEN
          po_vSemVerbaVlDescCmv := 'S';
      END;
      -- Se não tiver verba, não poderá rebaixar o CMV
      IF (NVL(po_vSemVerbaVlDescCmv,'N') = 'S') THEN
        pio_nVlDescCmvPromocaoMed := 0;
      END IF;
    END IF;
    
  END P_OBTER_VERBA_PROMOCAO;

 /************************************************************************************
  Função para Retornar o Percentual de Comissão por Grupo da Promoção - DDVENDAS-35939
  ************************************************************************************/
  FUNCTION F_OBTER_COMISS_GRUPO_PROMOCAO(pi_nCodPromocaoMed   IN NUMBER,
                                         pi_nCodGrupoComissao IN NUMBER,
                                         pi_nCodProd          IN NUMBER) RETURN NUMBER IS
    -- Retorno
    vnRetPerCom        PCDESCONTO.PERCOMREP%TYPE;
    -- Variáveis auxiliares
    vnCodMarca         PCPRODUT.CODMARCA%TYPE;
  BEGIN

    -- Pesquisa a Marca do Produto
    BEGIN
      SELECT CODMARCA
        INTO vnCodMarca
        FROM PCPRODUT
       WHERE (CODPROD = pi_nCodProd);
    EXCEPTION
      WHEN NO_DATA_FOUND THEN
        vnCodMarca := NULL;
    END;

    -- Pesquisa a Comissão
    BEGIN
      SELECT T.PERCENTUAL
        INTO vnRetPerCom
        FROM PCTABELACOMISSAOGRUPOMED T
       WHERE T.CODGRUPO = pi_nCodGrupoComissao
         AND (T.CAMPO  = 'MA')
         AND (T.CODIGO = vnCodMarca);
    EXCEPTION
      WHEN NO_DATA_FOUND THEN
        vnRetPerCom := 0;
    END;

    -- Retorno
    RETURN NVL(vnRetPerCom,0);

  END F_OBTER_COMISS_GRUPO_PROMOCAO;

 /************************************************************
  Funcao para retornar o texto delimitado com aspas simples
  ***********************************************************/
  FUNCTION FQUOTEDSTR(pi_vTexto IN VARCHAR) 
  RETURN VARCHAR2 IS
  BEGIN
    RETURN CHR(39) || pi_vTexto || CHR(39);
  END FQUOTEDSTR;

 /************************************************************
  Função para Retornar se Bloqueia a Comissão do RCA
  ***********************************************************/
  FUNCTION F_BLOQUEIA_COMISSAO(pi_nCodUsur IN NUMBER) RETURN VARCHAR2 IS
    vvBloqComis                  PCUSUARI.BLOQCOMIS%TYPE;
    vUSABLOQUEIOCOMISSAOVENDEDOR VARCHAR2(100);
  BEGIN
  
    BEGIN
      SELECT PCUSUARI.BLOQCOMIS
        INTO vvBloqComis
        FROM PCUSUARI
       WHERE (PCUSUARI.CODUSUR = pi_nCodUsur);       
    EXCEPTION
      WHEN NO_DATA_FOUND THEN
        vvBloqComis := 'N';
    END;
    
    IF (vvBloqComis = 'S') THEN
      vUSABLOQUEIOCOMISSAOVENDEDOR := FUSA_REGRA_MEDICAMENTOS('99',
                                                              'USABLOQUEIOCOMISSAOVENDEDOR');
      IF (NVL(vUSABLOQUEIOCOMISSAOVENDEDOR,'N') <> 'S') THEN
        vvBloqComis := 'N';
      END IF;
    END IF;
    
    RETURN vvBloqComis;
    
  END F_BLOQUEIA_COMISSAO;                                       

 /***********************************************************************************************
  PROCEDURE: F_OBTER_RCA_LINHAPROD
  DESCRIÇÃO: DDMEDICA-1835 - Obter o RCA da Linha de Produto
  ***********************************************************************************************/
  FUNCTION F_OBTER_RCA_LINHAPROD(pi_nCodCli                    IN NUMBER,
                                 pi_nCodProd                   IN NUMBER,
                                 pi_vCodFilial                 IN VARCHAR2 DEFAULT NULL,
                                 pi_vUsarClienteLinhaFilialMed IN VARCHAR2 DEFAULT 'N') RETURN NUMBER IS
    nCODLINHAPROD PCPRODUT.CODLINHAPROD%TYPE;
    nCODUSUR      PCCLIUSURLINHAPROD.CODUSUR%TYPE;    
  BEGIN
   
    BEGIN
      SELECT CODLINHAPROD
        INTO nCODLINHAPROD
        FROM PCPRODUT
       WHERE (CODPROD = pi_nCodProd);
    EXCEPTION 
      WHEN NO_DATA_FOUND THEN
        nCODLINHAPROD := NULL;
    END;
    
    IF (NVL(pi_vUsarClienteLinhaFilialMed,'N') = 'S') THEN
      BEGIN
        SELECT CODUSUR
          INTO nCODUSUR
          FROM PCCLIUSURFILIALLINHAPROD
         WHERE (CODCLI       = pi_nCodCli) 
           AND (CODLINHAPROD = nCODLINHAPROD)
           AND (CODFILIAL    = pi_vCodFilial);
      EXCEPTION 
        WHEN NO_DATA_FOUND THEN
          nCODUSUR := NULL;
      END;
    ELSE
      BEGIN
        SELECT CODUSUR
          INTO nCODUSUR
          FROM PCCLIUSURLINHAPROD
         WHERE (CODCLI       = pi_nCodCli) 
           AND (CODLINHAPROD = nCODLINHAPROD);
      EXCEPTION 
        WHEN NO_DATA_FOUND THEN
          nCODUSUR := NULL;
      END;
    END IF;
    
    RETURN nCODUSUR;
    
  END F_OBTER_RCA_LINHAPROD;                                    

 /*******************************************************************************
  Nome      : FOBTEM_PRECO_ENTRADA
  Descricão : Função para Retornar o Preço da Entrada
  *******************************************************************************/
  FUNCTION FOBTEM_PRECO_ENTRADA(pi_vCodFilial    IN VARCHAR2,
                                pi_nCodProd      IN NUMBER,
                                pi_nValorDefault IN NUMBER)
  RETURN NUMBER IS
    vnRetPrecoEntrada NUMBER;
  BEGIN

    SELECT MAX(DECODE(PUNIT, 0, PUNITCONT, PUNIT)) AS PUNIT
      INTO vnRetPrecoEntrada
      FROM PCMOV
     WHERE (PCMOV.DTCANCEL IS NULL)
       AND (PCMOV.CODOPER LIKE 'E%')
       AND (NUMTRANSVENDA IS NULL)
       AND (PCMOV.CODPROD = pi_nCodProd)
       AND (PCMOV.CODFILIAL = pi_vCodFilial);

    IF ((NVL(vnRetPrecoEntrada,0) <= 0) AND
        (NVL(pi_nValorDefault,0)   > 0)) THEN
      vnRetPrecoEntrada := NVL(pi_nValorDefault,0);
    END IF;

    RETURN NVL(vnRetPrecoEntrada,0);

  END FOBTEM_PRECO_ENTRADA;

 /*******************************************************************************
  Nome      : F_PROMOCAO_MARKUP_PRECOFIXO
  Descricão : Função para Retornar se é Promoção de MarkUP por Preço Fixo
  *******************************************************************************/
  FUNCTION F_PROMOCAO_MARKUP_PRECOFIXO(pi_nCodPromocao IN NUMBER)
  RETURN BOOLEAN IS
    vbRetorno      BOOLEAN;
    vvTIPOPROMOCAO PCPROMOCAOMED.TIPOPROMOCAO%TYPE;
    vvTIPOPOLITICA PCPROMOCAOMED.TIPOPOLITICA%TYPE;
  BEGIN
    BEGIN
      SELECT TIPOPROMOCAO
           , TIPOPOLITICA
        INTO vvTIPOPROMOCAO
           , vvTIPOPOLITICA
        FROM PCPROMOCAOMED
       WHERE (CODPROMOCAOMED = pi_nCodPromocao);
    EXCEPTION
      WHEN NO_DATA_FOUND THEN
        vvTIPOPROMOCAO := 'C';
        vvTIPOPOLITICA := 'D';
    END;
    -- Retorno
    IF (NVL(vvTIPOPROMOCAO,' ') IN ('R')) AND
       (NVL(vvTIPOPOLITICA,' ') IN ('P','F')) THEN
      RETURN TRUE;
    ELSE
      RETURN FALSE;
    END IF;
  END F_PROMOCAO_MARKUP_PRECOFIXO;

