                                    , PERCDESCRESTRICAO
                                    , CONSIDERACALCGIROMEDIC
                                    , CONCEDERMAIORCOMISSREG
                                    , ALTERADESCONTO
                                    , ENCARTEFECHADO
                                    , PRIORIZACOMISSAO
                                    , INICIOINTERVALO
                                    , FIMINTERVALO
                                    , PRECOFIXO
