                                    , UTILIZAPERCDESCBASERCA
                                    , PERMITIRAUMENTARQTDEKIT
                                    , PERCDESCBASERCA
                                    , ORIGEMPRECO
                                    , PERCBONIFICMERC
                                    , PERCMARKUPMED
                                    , PROMOCAOMEDOBRIGATORIO
                                    , NUMLOTE
                                    , CODIGOINTEGRACAOWMS
                                    , VALIDADELOTE
                                    )
                             VALUES ( reg_descontos.codpromocaomed
                                    , reg_descontos.coddesconto
                                    , vvTIPOPOLITICA
                                    , vvDESCRICAORESUMIDA
                                    , vvDESCRICAODETALHADA
                                    , vdDATAINICIAL
                                    , vdDATAFINAL
                                    , vvAPLICADESCONTO
                                    , vnPercDesc
                                    , reg_descontos.basecreddebrca
                                    , reg_descontos.percdescfin
                                    , reg_descontos.creditasobrepolitica
                                    , vstempalteraptabela
                                    , reg_descontos.prioritaria
                                    , reg_descontos.percdesc
                                    , reg_descontos.consideracalcgiromedic
                                    , reg_descontos.concedermaiorcomissreg
                                    , vvALTERADESCONTO
                                    , vvENCARTEFECHADO
                                    , vvPRIORIZACOMISSAO
                                    , reg_descontos.INICIOINTERVALOPROMOCAOMED
                                    , reg_descontos.FIMINTERVALOPROMOCAOMED
                                    , vntempprecofixopromocaomed
                                    , vvVALIDARINTERVALOVALIDADEPROD
                                    , vvDTINICIOPROMOLOTE
                                    , vvDTFIMPROMOLOTE
                                    , vvTIPOPROMOCAO
                                    , reg_descontos.participacomissgarantida
                                    , vvUTILIZAPERCDESCBASERCA
                                    , NVL(reg_descontos.PERMITIRAUMENTARQTDEKITMED,vvPERMITIRAUMENTARQTDEKIT)
                                    , reg_descontos.percdescbaserca
                                    , vORIGEMPRECO
                                    , reg_descontos.PERCBONIFICMERC
                                    , reg_descontos.percmarkupmed
                                    , reg_descontos.PROMOCAOMEDOBRIGATORIO
                                    , reg_descontos.NUMLOTE
                                    , reg_descontos.CODIGOINTEGRACAOWMS
                                    , vdValidadeLote
                                    );
                        EXCEPTION
                          WHEN DUP_VAL_ON_INDEX THEN
                            NULL;
                        END;

                      END IF; -- Fim Condição Se Aceita a Promoção conforme Prioridade

                    END IF; -- Fim Condição Verifica Promoção Casadinha
                    END IF; -- Fim Condição Verifica Promoção de KIT
                    -- HIS.01889.2017 - A partir da Campanha a Promoção de Cabeçalho virou de Item
                    --END IF; -- Fim Condição Verifica Promoção de Cabeçalho de Pedido
                    END IF; -- Fim Condição Verifica Promoção Encarte
                    END IF; -- Fim Condição Verifica Promoção Encarte

                  END IF; -- Fim Condição Tipo Chamada

                END LOOP;
/*
                FOR reg_comrede IN c_comrede(vncodepto,
                                             vncodsec,
                                             vncodcategoria,
                                             vncodfornec,
                                             vncodsupervisor,
                                             vncodatv1,
                                             vncodpraca,
                                             vncodcliprinc,
                                             vsaplicadesconto,
                                             vsareaatuacao,
                                             vssimplesnacional,
                                             vncodrede,
                                             vncodmarca,
                                             vncodlinhaprod) LOOP

                  -- Se Chamado para Obter as Politicas de Desconto / Quantidade no Operador Logístico ou Venda NormaL
                  IF ((pi_nTipoChamada = 1) AND (reg_comrede.codpromocaomed IS NULL) AND (NVL(reg_comrede.aplicadesconto,'N') = 'S')) OR  --somente descontos automaticos se Operador Logístico
                     ((pi_nTipoChamada = 4) AND (reg_comrede.codpromocaomed IS NULL)) THEN                                                --todos os descontos automaticos se Venda Normal

                    vbresult                   := TRUE;
                    vntempperdesc              := reg_comrede.percdesc;
                    vntempperdescfin           := reg_comrede.percdescfin;
                    vntemppbaserca             := reg_comrede.percdesc;
                    vstempbasecreddebrca       := reg_comrede.basecreddebrca;
                    vstempcreditasobrepolitica := reg_comrede.creditasobrepolitica;
                    vstempalteraptabela        := reg_comrede.alteraptabela;

                    vstempprioritaria          := reg_comrede.prioritaria;


                    if vsprioritaria = 'N' then

                      if vstempprioritaria = 'S' then
                        --registro atual é de politica prioritaria

                        if vsusaprioritaria = 'S' then

                          vnpercdesc             := vntempperdesc;
                          vnPerDescfin           := vntempperdescfin;
                          vsprioritaria          := vstempprioritaria;
                          vsalteraptabela        := vstempalteraptabela;

                          p_mensagem := to_char(reg_comrede.dtinicio,
                                                'dd/mm/yyyy') || ',' ||
                                        reg_comrede.coddesconto;


                                  if p_naousarautdebcredpoldesc = 'S' and vstempbasecreddebrca = 'S' then

                                      vsbasecreddebrca       := vstempbasecreddebrca;
                                      vnpercbaserca          := vntemppbaserca;
                                      vscreditasobrepolitica := vstempcreditasobrepolitica;

                              end if;


                        end if;

                      else
                        --registro atual não é de politica prioritaria

                        IF (vntempperdesc + vntempperdescfin) > (vnpercdesc + vnPerDescfin) THEN

                              vnpercdesc := vntempperdesc;
                              vnPerDescfin := vntempperdescfin;
                              vsprioritaria          := 'N';
                              vsalteraptabela        := vstempalteraptabela;

                              p_mensagem := to_char(reg_comrede.dtinicio,
                                                    'dd/mm/yyyy') || ',' ||
                                            reg_comrede.coddesconto;

                                  if p_naousarautdebcredpoldesc = 'S' and vstempbasecreddebrca = 'S' then

                                      vsbasecreddebrca       := vstempbasecreddebrca;
                                      vnpercbaserca          := vntemppbaserca;
                                      vscreditasobrepolitica := vstempcreditasobrepolitica;

                              end if;


                        END IF;

                              if p_naousarautdebcredpoldesc = 'S' and vstempbasecreddebrca = 'S' and
                                 vntemppbaserca > vnpercbaserca then

                                  vsbasecreddebrca       := vstempbasecreddebrca;
                                  vnpercbaserca          := vntemppbaserca;
                                  vscreditasobrepolitica := vstempcreditasobrepolitica;

                                  end if;

                      end if;

                    else
                      -- já tem uma politica prioritaria

                            IF (vntempperdesc + vntempperdescfin) > (vnpercdesc + vnPerDescfin) THEN

                              vnpercdesc             := vntempperdesc;
                              vnPerDesc              := vntempperdescfin;
                              vsprioritaria          := vstempprioritaria;
                              vsalteraptabela        := vstempalteraptabela;

                              p_mensagem := to_char(reg_comrede.dtinicio, 'dd/mm/yyyy') || ',' ||
                                            reg_comrede.coddesconto;

                                    if p_naousarautdebcredpoldesc = 'S' and vstempbasecreddebrca = 'S' then

                                      vsbasecreddebrca       := vstempbasecreddebrca;
                                      vnpercbaserca          := vntemppbaserca;
                                      vscreditasobrepolitica := vstempcreditasobrepolitica;

                                      end if;

                            END IF;

                    end if;

                    -- Se Chamado para Obter as Politicas de Desconto / Quantidade da Venda Normal
                    IF ((pi_nTipoChamada = 4) AND (reg_comrede.codpromocaomed IS NULL)) THEN
                      -- Se Desconto por Faixa de Quantidade
                      IF (reg_comrede.qtini > 0) THEN
                        -- Define o Tipo de Política Desconto (mesmo sendo por faixa de quantidade por ser 561)
                        vvTIPOPOLITICA       := 'D';
                        -- Define o Período
                        vdDATAINICIAL        := reg_comrede.dtinicio;
                        vdDATAFINAL          := reg_comrede.dtfim;
                        -- Define a Descrição Resumida e Detalhada
                        vvDESCRICAORESUMIDA  := 'Faixas de Desconto por Quantidade';
                        vvDESCRICAODETALHADA := 'Faixas de Desconto por Quantidade';
                        -- Insere Dados na Tabela Temporária
                        BEGIN
                          INSERT INTO PCMED_SELPROMOCAO
                                    ( CODPROMOCAOMED
                                    , CODDESCONTO
                                    , TIPOPOLITICA
                                    , DESCRICAORESUMIDA
                                    , DESCRICAODETALHADA
                                    , DATAINICIAL
                                    , DATAFINAL
                                    , APLICADESCONTO
                                    , PERCDESC
                                    , BASECREDDEBRCA
                                    , PERCDESCFIN
                                    , CREDITASOBREPOLITICA
                                    , ALTERAPTABELA
                                    , PRIORITARIA
                                    , PERCDESCRESTRICAO
                                    , CONSIDERACALCGIROMEDIC
                                    , CONCEDERMAIORCOMISSREG
                                    , ALTERADESCONTO
                                    , ENCARTEFECHADO
                                    , PRIORIZACOMISSAO
                                    , INICIOINTERVALO
                                    , FIMINTERVALO
                                    , PRECOFIXO
                                    , VALIDARINTERVALOVALIDADEPROD
                                    , DTINICIOPROMOLOTE
                                    , DTFIMPROMOLOTE
                                    , TIPOPROMOCAO
                                    , PARTICIPACOMISSGARANTIDA
                                    , UTILIZAPERCDESCBASERCA
                                    , PERMITIRAUMENTARQTDEKIT
                                    , PERCDESCBASERCA
                                    , ORIGEMPRECO
                                    , PERCBONIFICMERC
                                    , PROMOCAOMEDOBRIGATORIO )
                             VALUES ( -1  -->> -1 se Chamada 4
                                    , reg_comrede.coddesconto
                                    , vvTIPOPOLITICA
                                    , vvDESCRICAORESUMIDA
                                    , vvDESCRICAODETALHADA
                                    , vdDATAINICIAL
                                    , vdDATAFINAL
                                    , vvAPLICADESCONTO
                                    , reg_comrede.percdesc
                                    , reg_comrede.basecreddebrca
                                    , reg_comrede.percdescfin
                                    , reg_comrede.creditasobrepolitica
                                    , vstempalteraptabela
                                    , reg_comrede.prioritaria
                                    , reg_comrede.percdesc
                                    , reg_comrede.consideracalcgiromedic
                                    , reg_comrede.concedermaiorcomissreg
                                    , vvALTERADESCONTO
                                    , vvENCARTEFECHADO
                                    , vvPRIORIZACOMISSAO
                                    , reg_comrede.qtini
                                    , reg_comrede.qtfim
                                    , vntempprecofixopromocaomed
                                    , vvVALIDARINTERVALOVALIDADEPROD
                                    , vvDTINICIOPROMOLOTE
                                    , vvDTFIMPROMOLOTE
                                    , vvTIPOPROMOCAO
                                    , reg_comrede.participacomissgarantida
                                    , vvUTILIZAPERCDESCBASERCA
                                    , NVL(reg_comrede.PERMITIRAUMENTARQTDEKITMED,vvPERMITIRAUMENTARQTDEKIT)
                                    , reg_comrede.percdescbaserca
                                    , vORIGEMPRECO
                                    , reg_comrede.PERCBONIFICMERC
                                    , reg_comrede.PROMOCAOMEDOBRIGATORIO );
                        EXCEPTION
                          WHEN DUP_VAL_ON_INDEX THEN
                            NULL;
                        END;
                      END IF;
                    END IF;

                  -- Se Chamado para Obter as Promoção
                  ELSIF ((pi_nTipoChamada = 2) and (reg_comrede.codpromocaomed IS NOT NULL)) THEN

                    -- Se a Promoção do Cabeçalho do Pedido for de Encarte, só pode carregar Desconto da Própria Promoção
                    IF ( (F_PROMOCAO_ENCARTE(pi_nCodPromocaoMed) AND (pi_nCodPromocaoMed = reg_comrede.codpromocaomed)) OR
                         (NOT F_PROMOCAO_ENCARTE(pi_nCodPromocaoMed)) ) THEN
                    -- Se a Promoção a ser Carregada for de Encarte, somente pode ser igual ao Código da Promoção de Encarte do Cabeçalho do Pedido
                    IF ( (F_PROMOCAO_ENCARTE(reg_comrede.codpromocaomed) AND (reg_comrede.codpromocaomed = pi_nCodPromocaoMed)) OR
                         (NOT F_PROMOCAO_ENCARTE(reg_comrede.codpromocaomed)) ) THEN
                    -- HIS.01889.2017 - A partir da Campanha a Promoção de Cabeçalho virou de Item
                    -- Se a Promoção a ser Carregada for de Cabeçalho de Pedido, somente pode ser igual ao Código da Promoção do Cabeçalho do Pedido
                    --IF ( (F_PROMOCAO_CABECALHO(reg_comrede.codpromocaomed) AND (reg_comrede.codpromocaomed = pi_nCodPromocaoMed)) OR
                    --     (NOT F_PROMOCAO_CABECALHO(reg_comrede.codpromocaomed)) ) THEN
                    -- Se a Promoção a ser Carregada for de Cabeçalho de KIT, somente pode ser igual ao Código da Promoção do Item do Pedido
                    IF ( (F_PROMOCAO_KIT(reg_comrede.codpromocaomed) AND (reg_comrede.codpromocaomed = pi_nCodPromocaoItem)) OR
                         (NOT F_PROMOCAO_KIT(reg_comrede.codpromocaomed)) ) THEN
                    -- Se a Promoção a ser Carregada for de CASADINHA como Produto PRINCIPAL, somente pode ser o Produto cadastrado como Principal - HIS.01152.2015
                    IF ( (F_PROMOCAO_CASADINHA(reg_comrede.codpromocaomed, p_codprod) = 'P') OR
                         (F_PROMOCAO_CASADINHA(reg_comrede.codpromocaomed, p_codprod) = 'N') ) THEN

                      -- Pesquisa Dados da Promoção
                      P_OBTEM_DADOS_PROMOCAO(reg_comrede.codpromocaomed,
                                             vvACHOUPROMOCAO,
                                             vvTIPOPOLITICA,
                                             vvDESCRICAORESUMIDA,
                                             vvDESCRICAODETALHADA,
                                             vdDATAINICIAL,
                                             vdDATAFINAL,
                                             vvAPLICADESCONTO,
                                             vvALTERADESCONTO,
                                             vvENCARTEFECHADO,
                                             vvPRIORIZACOMISSAO,
                                             vvVALIDARINTERVALOVALIDADEPROD,
                                             vvDTINICIOPROMOLOTE,
                                             vvDTFIMPROMOLOTE,
                                             vvTIPOPROMOCAO,
                                             vvBLOQUEIO,
                                             vvPROMOESPECIAL,
                                             vvUTILIZAPERCDESCBASERCA,
                                             vvPERMITIRAUMENTARQTDEKIT,
                                             vORIGEMPRECO);

                      -- Se Aceita a Promoção conforme Prioridade e/ou bloqueio
                      IF (FACEITA_PROMOCAO_PRIORIDADE(reg_comrede.codpromocaomed,
                                                      reg_comrede.prioridade,
                                                      vvBLOQUEIO,
                                                      vvPROMOESPECIAL,
                                                      pi_vVisualizarPromoBloq,
                                                      pi_vVisualizarPromoEsp,
                                                      --
                                                      p_codfilial,
                                                      p_codcli,
                                                      p_numregiao,
                                                      p_codusur,
                                                      p_codplpag,
                                                      p_codcondicaovenda,
                                                      p_origempedido,
                                                      p_tipofv,
                                                      p_data,
                                                      vvTIPOPROMOCAO -- HIS.01889.2017
                                                      )) THEN

                      -- Apaga registro atual do Código da Promoção (caso exista registro de menor prioridade)
                      --DELETE FROM PCMED_SELPROMOCAO
                       --WHERE (CODPROMOCAOMED = reg_comrede.codpromocaomed);

                        -- Iniciando Variável com o valor de Preço Fixo da PCDESCONTO
                        vntempprecofixopromocaomed := reg_comrede.PRECOFIXOPROMOCAOMED;
                        vstempalteraptabela        := reg_comrede.alteraptabela;

                        -- Se for Preço Fábrica verificar se é zona franca
                        vnPrecoTabelaMarkup := pi_npTabela;
                        if vORIGEMPRECO = 'F' then
                          vstempalteraptabela := 'S';
                          if vsregiaozfm = 'S' then
                              vntempprecofixopromocaomed := vncustorepzfm;
                          else
                              vntempprecofixopromocaomed := vncustorep;
                          end if;
                          vnPrecoTabelaMarkup := vntempprecofixopromocaomed;
                        end if;

                        --- Processo de Markup
                        vnPercDesc    := reg_comrede.percdesc;
                        IF (F_PROMOCAO_MARKUP(reg_comrede.codpromocaomed)) THEN
                          IF NVL(reg_comrede.percmarkupmed,0) = 0 THEN
                              vnPercDesc           := 0;
                          ELSE
                              vnPrecoVendaMarkup   := pi_nCustoFin * (1+(NVL(reg_comrede.percmarkupmed,0)*0.01));
                              vnPercDesc           := (1-(vnPrecoVendaMarkup/vnPrecoTabelaMarkup))*100   ;
                          END IF;
                        END IF;

                        -- Validade do Lote
                        IF (reg_comrede.NUMLOTE IS NOT NULL) THEN
                          BEGIN
                            SELECT DTVALIDADE
                              INTO vdValidadeLote
                              FROM PCLOTE
                             WHERE (CODPROD = pi_nCodProd)
                               AND (NUMLOTE = reg_comrede.NUMLOTE)
                               AND (QT      > 0)
                               AND (ROWNUM  = 1);
                          EXCEPTION
                            WHEN NO_DATA_FOUND THEN
                              vdValidadeLote := NULL;
                          END;
                        ELSE
                          vdValidadeLote := NULL;
                        END IF;

                        -- Insere Dados na Tabela Temporária
                        BEGIN
                          INSERT INTO PCMED_SELPROMOCAO
                                    ( CODPROMOCAOMED
                                    , CODDESCONTO
                                    , TIPOPOLITICA
                                    , DESCRICAORESUMIDA
                                    , DESCRICAODETALHADA
                                    , DATAINICIAL
                                    , DATAFINAL
                                    , APLICADESCONTO
                                    , PERCDESC
                                    , BASECREDDEBRCA
                                    , PERCDESCFIN
                                    , CREDITASOBREPOLITICA
                                    , ALTERAPTABELA
                                    , PRIORITARIA
                                    , PERCDESCRESTRICAO
                                    , CONSIDERACALCGIROMEDIC
                                    , CONCEDERMAIORCOMISSREG
                                    , ALTERADESCONTO
                                    , ENCARTEFECHADO
                                    , PRIORIZACOMISSAO
                                    , INICIOINTERVALO
                                    , FIMINTERVALO
                                    , PRECOFIXO
                                    , VALIDARINTERVALOVALIDADEPROD
                                    , DTINICIOPROMOLOTE
                                    , DTFIMPROMOLOTE
                                    , TIPOPROMOCAO
                                    , PARTICIPACOMISSGARANTIDA
                                    , UTILIZAPERCDESCBASERCA
                                    , PERMITIRAUMENTARQTDEKIT
                                    , PERCDESCBASERCA
                                    , ORIGEMPRECO
                                    , PERCBONIFICMERC
                                    , PERCMARKUPMED
                                    , PROMOCAOMEDOBRIGATORIO
                                    , NUMLOTE
                                    , CODIGOINTEGRACAOWMS
                                    , VALIDADELOTE
                                    )
                             VALUES ( reg_comrede.codpromocaomed
                                    , reg_comrede.coddesconto
                                    , vvTIPOPOLITICA
                                    , vvDESCRICAORESUMIDA
                                    , vvDESCRICAODETALHADA
                                    , vdDATAINICIAL
                                    , vdDATAFINAL
                                    , vvAPLICADESCONTO
                                    , vnPercDesc
                                    , reg_comrede.basecreddebrca
                                    , reg_comrede.percdescfin
                                    , reg_comrede.creditasobrepolitica
                                    , vstempalteraptabela
                                    , reg_comrede.prioritaria
                                    , reg_comrede.percdesc
                                    , reg_comrede.consideracalcgiromedic
                                    , reg_comrede.concedermaiorcomissreg
                                    , vvALTERADESCONTO
                                    , vvENCARTEFECHADO
                                    , vvPRIORIZACOMISSAO
                                    , reg_comrede.INICIOINTERVALOPROMOCAOMED
                                    , reg_comrede.FIMINTERVALOPROMOCAOMED
                                    , vntempprecofixopromocaomed
                                    , vvVALIDARINTERVALOVALIDADEPROD
                                    , vvDTINICIOPROMOLOTE
                                    , vvDTFIMPROMOLOTE
                                    , vvTIPOPROMOCAO
                                    , reg_comrede.participacomissgarantida
                                    , vvUTILIZAPERCDESCBASERCA
                                    , NVL(reg_comrede.PERMITIRAUMENTARQTDEKITMED,vvPERMITIRAUMENTARQTDEKIT)
                                    , reg_comrede.percdescbaserca
                                    , vORIGEMPRECO
                                    , reg_comrede.PERCBONIFICMERC
                                    , reg_comrede.percmarkupmed
                                    , reg_comrede.PROMOCAOMEDOBRIGATORIO
                                    , reg_comrede.NUMLOTE
                                    , reg_comrede.CODIGOINTEGRACAOWMS
                                    , vdValidadeLote
                                    );
                        EXCEPTION
                          WHEN DUP_VAL_ON_INDEX THEN
                            NULL;
                        END;

                      END IF; -- Fim Condição Se Aceita a Promoção conforme Prioridade

                    END IF; -- Fim Condição Verifica Promoção Casadinha
                    END IF; -- Fim Condição Verifica Promoção de KIT
                    -- HIS.01889.2017 - A partir da Campanha a Promoção de Cabeçalho virou de Item
                    --END IF; -- Fim Condição Verifica Promoção de Cabeçalho de Pedido
                    END IF; -- Fim Condição Verifica Promoção Encarte
                    END IF; -- Fim Condição Verifica Promoção Encarte

                  END IF; -- Fim Condição Tipo Chamada

                END LOOP;
*/
            ELSE
              p_mensagem := 'Não foi possível buscar dados do PCREGIAO!';
            END IF;
          ELSE
            p_mensagem := 'Não foi possível buscar dados do PCPRODUT!';
          END IF;
        ELSE
          p_mensagem := 'Não foi possível buscar dados do PCUSUARI!';
        END IF; --dados do PCCLIENT
      ELSE
        p_mensagem := 'Não foi possível buscar dados do PCCLIENT!';
      END IF;


      p_perdesc              := round(vnpercdesc, p_numcasasdecvenda);
      p_perdescfin           := round(vnPerDescfin,p_numcasasdecvenda);
      p_basecreddebrca       := vsbasecreddebrca;
      p_creditasobrepolitica := vscreditasobrepolitica;
      p_pbaserca             := round(vnpercbaserca, p_numcasasdecvenda);
      p_alteraptabela        := vsalteraptabela;


      RETURN vbresult;
    EXCEPTION
      WHEN OTHERS THEN
        p_mensagem := 'Erro ao Validar Politica de Descontos: ' || SQLCODE || '-' ||
                      SQLERRM;
        RETURN FALSE;
    END FUNCAO_OBTEM_DESC_POLITICA;



  FUNCTION FUNCAO_OBTEM_DESC_QUANTIDADE
    (pi_nTipoChamada       IN  NUMBER,
     pi_nCodPromocaoMed    IN  NUMBER,
     p_codprod             IN NUMBER,
     p_qtde                IN NUMBER,
     p_numregiao           IN NUMBER,
   --  p_ptabela             IN NUMBER,
  --   p_pvenda1             IN NUMBER,
     p_codpraca            IN NUMBER,
  --   p_numcasasdecvenda    IN NUMBER,
     p_numdias             IN NUMBER,
     p_codprodprinc        IN NUMBER,
     p_usaprioritaria      IN VARCHAR2,
     p_tipofv              IN pcintegradora.tipofv%type,
     p_mensagem            OUT VARCHAR2,
     p_perdesc             OUT NUMBER,
     p_creditasobreptabela OUT VARCHAR2,
     p_basedebcredrca      OUT VARCHAR2,
     p_percbaserca         OUT NUMBER) RETURN BOOLEAN IS

      vbresult         BOOLEAN;
      vnpercdesc       NUMBER;
      vnperdesctemp    number;
      vnperdescmax     NUMBER;
  --    vnperdescmaxtemp number;
  --    vnptabela        NUMBER;

  --    vnptabela_quantmax        NUMBER;
  --    vnptabela_quant           NUMBER;
      vscreditasobreptabela     VARCHAR2(1);
      vscreditasobreptabelatemp VARCHAR2(1);
      vddtinicio                DATE;
      vniniciointervalo         NUMBER;
      vnfimintervalo            NUMBER;
      vsbasecreddebrca          pcdescquant.basecreddebrca%type;
      vsbasecreddebrcatemp      pcdescquant.basecreddebrca%type;
      vnpercbaserca             number;
      vnpercbasercatemp         number;
      vsprioritaria             pcdescquant.prioritaria%type;
      vstempprioritaria         pcdescquant.prioritaria%type;

      -- Dados da Promoção
      vvACHOUPROMOCAO            VARCHAR2(1);
      vvTIPOPOLITICA             PCMED_SELPROMOCAO.TIPOPOLITICA%TYPE;
      vvDESCRICAORESUMIDA        PCMED_SELPROMOCAO.DESCRICAORESUMIDA%TYPE;
      vvDESCRICAODETALHADA       PCMED_SELPROMOCAO.DESCRICAODETALHADA%TYPE;
      vdDATAINICIAL              PCMED_SELPROMOCAO.DATAINICIAL%TYPE;
      vdDATAFINAL                PCMED_SELPROMOCAO.DATAFINAL%TYPE;
      vvAPLICADESCONTO           PCMED_SELPROMOCAO.APLICADESCONTO%TYPE;
      vvALTERADESCONTO           PCMED_SELPROMOCAO.ALTERADESCONTO%TYPE;
      vvENCARTEFECHADO           PCMED_SELPROMOCAO.ENCARTEFECHADO%TYPE;
      vvPRIORIZACOMISSAO         PCMED_SELPROMOCAO.PRIORIZACOMISSAO%TYPE;
      vvVALIDARINTERVALOVALIDADEPROD PCMED_SELPROMOCAO.VALIDARINTERVALOVALIDADEPROD%TYPE;
      vvDTINICIOPROMOLOTE            PCMED_SELPROMOCAO.DTINICIOPROMOLOTE%TYPE;
      vvDTFIMPROMOLOTE               PCMED_SELPROMOCAO.DTFIMPROMOLOTE%TYPE;
      vvTIPOPROMOCAO                 PCMED_SELPROMOCAO.TIPOPROMOCAO%TYPE;
      vvBLOQUEIO                     VARCHAR2(1);
      vvPROMOESPECIAL                VARCHAR2(1);
      vvUTILIZAPERCDESCBASERCA       PCMED_SELPROMOCAO.UTILIZAPERCDESCBASERCA%TYPE;
      vvPERMITIRAUMENTARQTDEKIT      PCMED_SELPROMOCAO.PERMITIRAUMENTARQTDEKIT%TYPE;
      vORIGEMPRECO                   PCMED_SELPROMOCAO.ORIGEMPRECO%TYPE;

      -- Arrays para Pesquisa das Faixas de Desconto
      TYPE TT_INICIOINTERVALO    IS TABLE OF PCMED_SELPROMOCAO.INICIOINTERVALO%TYPE INDEX BY BINARY_INTEGER;
      TYPE TT_FIMINTERVALO       IS TABLE OF PCMED_SELPROMOCAO.FIMINTERVALO%TYPE INDEX BY BINARY_INTEGER;
      TYPE TT_PERCDESC           IS TABLE OF PCMED_SELPROMOCAO.PERCDESC%TYPE INDEX BY BINARY_INTEGER;
      vtINICIOINTERVALO          TT_INICIOINTERVALO;
      vtFIMINTERVALO             TT_FIMINTERVALO;
      vtPERCDESC                 TT_PERCDESC;

      vncodlinhaprod             pcprodut.codlinhaprod%type;

    BEGIN


      vbresult      := FALSE;
  --    vnptabela     := p_ptabela;
      vnpercdesc    := null;
      vnpercbaserca := null;
      vsprioritaria := 'N';

      -- Se Chamado para Obter as Politicas de Desconto Quantidade no Operador Logístico
      IF (pi_nTipoChamada = 1) THEN

          for reg in (SELECT pcdescquant.percdesc,
                               pcdescquant.dtfim,
                               pcdescquant.perdescmax,
                               pcdescquant.creditasobreptabela,
                               pcdescquant.dtinicio,
                               pcdescquant.iniciointervalo,
                               pcdescquant.fimintervalo,
                               nvl(pcdescquant.basecreddebrca, 'N') basecreddebrca,
                               pcdescquant.prioritaria,
                               pcdescquant.questionausoprioritaria,
                               pcdescquant.codpromocaomed,
                               pcdescquant.coddesconto,
                               pcdescquant.consideracalcgiromedic
                          FROM pcdescquant, pcplpag
                         WHERE pcdescquant.codprod =
                               decode(pcdescquant.APLICAFAMILIAPRODUTOS,
                                      'S',
                                      p_codprodprinc,
                                      p_codprod)
                           AND pcdescquant.codplpagmax = pcplpag.codplpag(+)
                           AND decode(pcdescquant.codplpagmax,
                                      NULL,
                                      p_numdias,
                                      pcplpag.numdias) >= p_numdias
                           AND pcdescquant.iniciointervalo <= p_qtde
                           AND pcdescquant.fimintervalo >= p_qtde
                           AND ((pcdescquant.numregiao = p_numregiao) OR
                               (pcdescquant.numregiao IS NULL))
                           AND ((pcdescquant.codpraca = p_codpraca) OR
                               (pcdescquant.codpraca IS NULL))
                           AND ((trunc(SYSDATE) BETWEEN pcdescquant.dtinicio AND
                               pcdescquant.dtfim) OR ((pcdescquant.dtinicio IS NULL) AND
                               (pcdescquant.dtfim IS NULL)))
                           AND nvl(pcdescquant.tipodesconto, 'A') = 'A'
                           AND (pcdescquant.tipofv = p_tipofv)
                           AND (case when pcdescquant.tipofv = 'OL' then pcdescquant.aplicaoperlog else pcdescquant.aplicapedelet end) = 'S'
                           AND (codpromocaomed IS NULL) -- Somente Descontos sem Promoção atrelada
                         ORDER BY pcdescquant.percdesc) loop

              vbresult                   := TRUE;
              vnperdesctemp              := reg.percdesc;
              vsbasecreddebrcatemp       := reg.basecreddebrca;
              vscreditasobreptabelatemp  := reg.creditasobreptabela;
              vnpercbasercatemp          := reg.percdesc;
              vstempprioritaria          := reg.prioritaria;


              if vnperdesctemp < 0 then
                --desconto


               if vsprioritaria = 'N' then

                if vstempprioritaria = 'S' then --registro atual é de politica prioritaria


                   if p_usaprioritaria = 'S' then


                      vnpercdesc        := vnperdesctemp;
                      vddtinicio        := reg.dtinicio;
                      vniniciointervalo := reg.iniciointervalo;
                      vnfimintervalo    := reg.fimintervalo;
                      vnperdescmax      := reg.perdescmax;
                      vsprioritaria          := reg.prioritaria;



                      if vsbasecreddebrcatemp = 'S'  then
                        vsbasecreddebrca      := vsbasecreddebrcatemp;
                        vnpercbaserca         := vnpercbasercatemp;
                        vscreditasobreptabela := vscreditasobreptabelatemp;
                      end if;

                   end if;


               else --registro atual não é prioritaria

                    IF (vnperdesctemp < vnpercdesc) or vnpercdesc is null THEN


                      vnpercdesc        := vnperdesctemp;
                      vddtinicio        := reg.dtinicio;
                      vniniciointervalo := reg.iniciointervalo;
                      vnfimintervalo    := reg.fimintervalo;
                      vnperdescmax      := reg.perdescmax;
                      vsprioritaria          := 'N';


                    END IF;

                    if vsbasecreddebrcatemp = 'S' and
                       ((vnpercbasercatemp < vnpercbaserca) or vnpercbaserca is null) then
                      vsbasecreddebrca      := vsbasecreddebrcatemp;
                      vnpercbaserca         := vnpercbasercatemp;
                      vscreditasobreptabela := vscreditasobreptabelatemp;
                    end if;
                 end if;

                else -- já tem politica prioritaria

                    IF (vnperdesctemp < vnpercdesc) or vnpercdesc is null THEN


                      vnpercdesc        := vnperdesctemp;
                      vddtinicio        := reg.dtinicio;
                      vniniciointervalo := reg.iniciointervalo;
                      vnfimintervalo    := reg.fimintervalo;
                      vnperdescmax      := reg.perdescmax;
                      vsprioritaria          := reg.prioritaria;



                    END IF;

                    if vsbasecreddebrcatemp = 'S' and
                       ((vnpercbasercatemp < vnpercbaserca) or vnpercbaserca is null) then
                      vsbasecreddebrca      := vsbasecreddebrcatemp;
                      vnpercbaserca         := vnpercbasercatemp;
                      vscreditasobreptabela := vscreditasobreptabelatemp;
                    end if;


                end if;

              end if;

          END loop;

      -- Se Chamado para Obter as Promoções
      ELSIF (pi_nTipoChamada = 2) THEN

         BEGIN
           SELECT codlinhaprod
             INTO vncodlinhaprod
             FROM pcprodut
            WHERE codprod = p_codprod;
          EXCEPTION
            WHEN NO_DATA_FOUND THEN
              vncodlinhaprod := NULL;
          END;

          for reg in (SELECT pcdescquant.percdesc,
                               pcdescquant.dtfim,
                               pcdescquant.perdescmax,
                               pcdescquant.creditasobreptabela,
                               pcdescquant.dtinicio,
                               pcdescquant.iniciointervalo,
                               pcdescquant.fimintervalo,
                               nvl(pcdescquant.basecreddebrca, 'N') basecreddebrca,
                               pcdescquant.prioritaria,
                               pcdescquant.questionausoprioritaria,
                               pcdescquant.codpromocaomed,
                               pcdescquant.coddesconto,
                               pcdescquant.consideracalcgiromedic
                          FROM pcdescquant, pcplpag
                         WHERE ((pcdescquant.codprod =
                                 decode(pcdescquant.APLICAFAMILIAPRODUTOS,
                                        'S',
                                        p_codprodprinc,
                                        p_codprod)) OR
                                (pcdescquant.codprod IS NULL))
                           AND pcdescquant.codplpagmax = pcplpag.codplpag(+)
                           AND decode(pcdescquant.codplpagmax,
                                      NULL,
                                      p_numdias,
                                      pcplpag.numdias) >= p_numdias
                           AND ((pcdescquant.numregiao = p_numregiao) OR
                               (pcdescquant.numregiao IS NULL))
                           AND ((pcdescquant.codpraca = p_codpraca) OR
                               (pcdescquant.codpraca IS NULL))
                           AND ((trunc(SYSDATE) BETWEEN pcdescquant.dtinicio AND
                               pcdescquant.dtfim) OR ((pcdescquant.dtinicio IS NULL) AND
                               (pcdescquant.dtfim IS NULL)))
                           AND (NVL(pcdescquant.tipofv,'TL') = p_tipofv)
                           AND (codpromocaomed IS NOT NULL) -- Somente Descontos com Promoção atrelada
                           AND ((pcdescquant.codlinhaprod = vncodlinhaprod) OR (pcdescquant.codlinhaprod IS NULL)) -->> Promoção tem Linha de Produto
                         ORDER BY pcdescquant.percdesc) loop

              -- Se a Promoção do Cabeçalho do Pedido for de Encarte, só pode carregar Desconto da Própria Promoção
              IF ( (F_PROMOCAO_ENCARTE(pi_nCodPromocaoMed) AND (pi_nCodPromocaoMed = reg.codpromocaomed)) OR
                   (NOT F_PROMOCAO_ENCARTE(pi_nCodPromocaoMed)) ) THEN
              -- Se a Promoção a ser Carregada for de Encarte, somente pode ser igual ao Código da Promoção de Encarte do Cabeçalho do Pedido
              IF ( (F_PROMOCAO_ENCARTE(reg.codpromocaomed) AND (reg.codpromocaomed = pi_nCodPromocaoMed)) OR
                   (NOT F_PROMOCAO_ENCARTE(reg.codpromocaomed)) ) THEN
              -- Se a Promoção a ser Carregada for de Cabeçalho de Pedido, somente pode ser igual ao Código da Promoção do Cabeçalho do Pedido
              IF ( (F_PROMOCAO_CABECALHO(reg.codpromocaomed) AND (reg.codpromocaomed = pi_nCodPromocaoMed)) OR
                   (NOT F_PROMOCAO_CABECALHO(reg.codpromocaomed)) ) THEN
              -- Se a Promoção a ser Carregada for de KIT, somente pode ser igual ao Código da Promoção do Item do Pedido
              IF ( (F_PROMOCAO_KIT(reg.codpromocaomed) AND (reg.codpromocaomed = pi_nCodPromocaoItem)) OR
                   (NOT F_PROMOCAO_KIT(reg.codpromocaomed)) ) THEN
              -- Não foi necessário implementar a Casadinha aqui - descontinuada a pcdescquant

                -- Pesquisa Dados da Promoção
                P_OBTEM_DADOS_PROMOCAO(reg.codpromocaomed,
                                       vvACHOUPROMOCAO,
                                       vvTIPOPOLITICA,
                                       vvDESCRICAORESUMIDA,
                                       vvDESCRICAODETALHADA,
                                       vdDATAINICIAL,
                                       vdDATAFINAL,
                                       vvAPLICADESCONTO,
                                       vvALTERADESCONTO,
                                       vvENCARTEFECHADO,
                                       vvPRIORIZACOMISSAO,
                                       vvVALIDARINTERVALOVALIDADEPROD,
                                       vvDTINICIOPROMOLOTE,
                                       vvDTFIMPROMOLOTE,
                                       vvTIPOPROMOCAO,
                                       vvBLOQUEIO,
                                       vvPROMOESPECIAL,
                                       vvUTILIZAPERCDESCBASERCA,
                                       vvPERMITIRAUMENTARQTDEKIT,
                                       vORIGEMPRECO);

                -- Insere Dados na Tabela Temporária
                BEGIN
                  INSERT INTO PCMED_SELPROMOCAO
                            ( CODPROMOCAOMED
                            , CODDESCONTO
                            , TIPOPOLITICA
                            , DESCRICAORESUMIDA
                            , DESCRICAODETALHADA
                            , DATAINICIAL
                            , DATAFINAL
                            , APLICADESCONTO
                            , PERCDESC
                            , BASECREDDEBRCA
                            , CONSIDERACALCGIROMEDIC
                            , CREDITASOBREPTABELA
                            , INICIOINTERVALO
                            , FIMINTERVALO
                            , ALTERADESCONTO
                            , ENCARTEFECHADO
                            , PRIORIZACOMISSAO
                            , VALIDARINTERVALOVALIDADEPROD
                            , DTINICIOPROMOLOTE
                            , DTFIMPROMOLOTE
                            , TIPOPROMOCAO )
                     VALUES ( reg.codpromocaomed
                            , reg.coddesconto
                            , vvTIPOPOLITICA
                            , vvDESCRICAORESUMIDA
                            , vvDESCRICAODETALHADA
                            , vdDATAINICIAL
                            , vdDATAFINAL
                            , vvAPLICADESCONTO
                            , ABS(reg.percdesc) -- Valor Absoluto porque o desconto é gravado com sinal negativo
                            , reg.basecreddebrca
                            , reg.consideracalcgiromedic
                            , reg.creditasobreptabela
                            , reg.iniciointervalo
                            , reg.fimintervalo
                            , vvALTERADESCONTO
                            , vvENCARTEFECHADO
                            , vvPRIORIZACOMISSAO
                            , vvVALIDARINTERVALOVALIDADEPROD
                            , vvDTINICIOPROMOLOTE
                            , vvDTFIMPROMOLOTE
                            , vvTIPOPROMOCAO );
                EXCEPTION
                  WHEN DUP_VAL_ON_INDEX THEN
                    NULL;
                END;

              END IF; -- Fim Condição Verifica Promoção de KIT
              END IF; -- Fim Condição Verifica Promoção de Cabeçalho de Pedido
              END IF; -- Fim Condição Verifica Promoção Encarte
              END IF; -- Fim Condição Verifica Promoção Encarte

          END loop;

      -- Se Chamado para Carregar a Tabela Temporária com as Políticas de Desconto por Quantidade
      -- Se Chamado para Obter as Politicas de Desconto Quantidade na Venda Normal
      ELSIF (pi_nTipoChamada IN (3,4,18)) THEN

          -- Neste Select, carrega no Cursor todas as informações independente da quantidade,
          -- para apresentar todas as faixas válidas
          for reg in (SELECT pcdescquant.percdesc,
                               pcdescquant.dtfim,
                               pcdescquant.perdescmax,
                               pcdescquant.creditasobreptabela,
                               pcdescquant.dtinicio,
                               pcdescquant.iniciointervalo,
                               pcdescquant.fimintervalo,
                               nvl(pcdescquant.basecreddebrca, 'N') basecreddebrca,
                               pcdescquant.prioritaria,
                               pcdescquant.questionausoprioritaria,
                               pcdescquant.codpromocaomed,
                               pcdescquant.coddesconto,
                               pcdescquant.consideracalcgiromedic,
                               pcdescquant.tipodesconto
                          FROM pcdescquant, pcplpag
                         WHERE pcdescquant.codprod =
                               decode(pcdescquant.APLICAFAMILIAPRODUTOS,
                                      'S',
                                      p_codprodprinc,
                                      p_codprod)
                           AND pcdescquant.codplpagmax = pcplpag.codplpag(+)
                           AND decode(pcdescquant.codplpagmax,
                                      NULL,
                                      p_numdias,
                                      pcplpag.numdias) >= p_numdias
                           AND ((pcdescquant.numregiao = p_numregiao) OR
                               (pcdescquant.numregiao IS NULL))
                           AND ((pcdescquant.codpraca = p_codpraca) OR
                               (pcdescquant.codpraca IS NULL))
                           AND ((trunc(SYSDATE) BETWEEN pcdescquant.dtinicio AND
                               pcdescquant.dtfim) OR ((pcdescquant.dtinicio IS NULL) AND
                               (pcdescquant.dtfim IS NULL)))
                           AND (NVL(pcdescquant.tipofv,'TL') = p_tipofv)
                           AND (codpromocaomed IS NULL) -- Somente Descontos sem Promoção atrelada
                           AND ((pi_nTipoChamada IN (3,18)) OR ((pi_nTipoChamada = 4) AND (NVL(pcdescquant.percdesc,0) < 0))) -- Venda Normal somente Descontos
                         ORDER BY pcdescquant.percdesc) loop

              -- Define se Aplica Desconto Automaticamente
              IF (NVL(reg.tipodesconto,' ') = 'A') THEN
                vvAPLICADESCONTO := 'S';
              ELSE
                vvAPLICADESCONTO := 'N';
              END IF;

              -- Define a Descrição Resumida e Detalhada
              vvDESCRICAORESUMIDA  := 'Faixas de Desconto por Quantidade';
              vvDESCRICAODETALHADA := 'Faixas de Desconto por Quantidade';

              -- Insere Dados na Tabela Temporária
              BEGIN
                INSERT INTO PCMED_SELPROMOCAO
                          ( CODPROMOCAOMED
                          , CODDESCONTO
                          , TIPOPOLITICA
                          , DESCRICAORESUMIDA
                          , DESCRICAODETALHADA
                          , DATAINICIAL
                          , DATAFINAL
                          , APLICADESCONTO
                          , PERCDESC
                          , BASECREDDEBRCA
                          , CONSIDERACALCGIROMEDIC
                          , CREDITASOBREPTABELA
                          , INICIOINTERVALO
                          , FIMINTERVALO
                          , ALTERADESCONTO )
                   VALUES ( DECODE(pi_nTipoChamada,4,  -1  -->> -1 se Chamada 4
                                                    ,NULL) -->> Sem Promoção se Chamada 3
                          , reg.coddesconto
                          , 'Q' -->> Política de Desconto por Quantidade
                          , vvDESCRICAORESUMIDA
                          , vvDESCRICAODETALHADA
                          , reg.dtinicio
                          , reg.dtfim
                          , vvAPLICADESCONTO
                          , ABS(reg.percdesc) -- Valor Absoluto porque o desconto é gravado com sinal negativo
                          , reg.basecreddebrca
                          , reg.consideracalcgiromedic
                          , reg.creditasobreptabela
                          , reg.iniciointervalo
                          , reg.fimintervalo
                          , 'S' );
              EXCEPTION
                WHEN DUP_VAL_ON_INDEX THEN
                  NULL;
              END;

          END loop;

          -- Carrega os maiores descontos por faixa
          SELECT INICIOINTERVALO
               , FIMINTERVALO
               , MAX(PERCDESC)
            BULK COLLECT INTO vtINICIOINTERVALO
                            , vtFIMINTERVALO
                            , vtPERCDESC
            FROM PCMED_SELPROMOCAO
           GROUP BY INICIOINTERVALO,
                    FIMINTERVALO;

          -- Processa os maiores descontos por faixa
          IF (vtPERCDESC.COUNT > 0) THEN
            FOR viLaco IN vtPERCDESC.FIRST..vtPERCDESC.LAST LOOP
              -- Deleta as mesmas faixas com desconto menor
              DELETE FROM PCMED_SELPROMOCAO
                    WHERE (INICIOINTERVALO = vtINICIOINTERVALO(viLaco))
                      AND (FIMINTERVALO    = vtFIMINTERVALO(viLaco))
                      AND (PERCDESC        < vtPERCDESC(viLaco));
            END LOOP;
          END IF;

      END IF; -- Fim Condição Tipo Chamada

      --utilizado só para retornar o percentual
      p_perdesc := abs(vnpercdesc);


      --4. Desconto ou Acrescimo


      p_creditasobreptabela := vscreditasobreptabela;

      p_basedebcredrca := vsbasecreddebrca;

      p_percbaserca := abs(vnpercbaserca);




      if vddtinicio is not null then
        p_mensagem := to_char(vddtinicio, 'dd/mm/yyyy') || ',' ||
                      vniniciointervalo || ',' || vnfimintervalo;
      end if;

      RETURN vbresult;
    EXCEPTION
      WHEN OTHERS THEN
        p_mensagem := 'Erro validar desconto por quantidade ' || SQLCODE || '-' ||
                      SQLERRM;
        RETURN FALSE;
    END FUNCAO_OBTEM_DESC_QUANTIDADE;



  BEGIN

   /**************************
    Inicializacao de Variaveis
    **************************/

    -- Inicializa Retornos de indicacao de erros
    po_vOcorreramErros := 'N';
    po_vMsgErros       := NULL;

    -- Inicializa variáveis auxiliares
    vnPerDesc          := NVL(vnPerDesc,0);
    vnPerBonific       := NVL(vnPerBonific,0);
    vnPerComerc        := NVL(vnPerComerc,0);
    vnPerBoleto        := NVL(vnPerBoleto,0);
    vnPercDescFinLinha := NVL(vnPercDescFinLinha,0);

    -- Se Chamado para obter as Politicas de Desconto / Quantidade
    IF (pi_nTipoChamada = 1) THEN

      -- Pesquisa Parâmetro Tipo de Prazo de Medicamentos
      BEGIN
        SELECT PCPARAMFILIAL.valor
          INTO vvTipoPrazoMedicam
          FROM PCPARAMFILIAL
         WHERE (PCPARAMFILIAL.nome      = 'TIPOPRAZOMEDICAMEN')
           AND (PCPARAMFILIAL.codfilial = 99);
      EXCEPTION
        WHEN NO_DATA_FOUND THEN
          -- Atualiza Mensagem de Erro e Aborta
          po_vMsgErros := 'Parâmetro [TIPOPRAZOMEDICAMEN] não encontrado.';
          RAISE e_Generico;
      END;

      -- Pesquisa parâmetro da condicao de venda que define a Origem do Desconto de Bonificacao
      BEGIN
        SELECT PCCONDICAOVENDA.tipodescbonif
          INTO vvTipoDescBonif
          FROM PCCONDICAOVENDA
         WHERE (PCCONDICAOVENDA.codcondicaovenda = pi_nCodCondicaoVenda);
      EXCEPTION
        WHEN NO_DATA_FOUND THEN
          -- Atualiza Mensagem de Erro e Aborta
          po_vMsgErros := 'Condicao Venda [' || pi_nCodCondicaoVenda || '] não cadastrada.';
          RAISE e_Generico;
      END;

      -- Pesquisa Parâmetro que define se o Cliente pode ter Desconto Comercial no Boleto
      BEGIN
        SELECT nvl(pcclient.usadescfinseparadodesccom,'S')
          INTO vcPermiteDescBoleto
          FROM PCCLIENT
         WHERE (PCCLIENT.codcli = pi_nCodCli);
      EXCEPTION
        WHEN NO_DATA_FOUND THEN
          -- Atualiza Mensagem de Erro e Aborta
          po_vMsgErros := 'Cliente [' || pi_nCodCli || '] não cadastrado.';
          RAISE e_Generico;
      END;

    END IF; -- Se Chamado para obter as Politicas de Desconto / Quantidade

   /**********************************************************
    Obtem o maior Desconto cadastrado na Politica de Descontos
    **********************************************************/
    -- FUNCAO PARA OBTER O MAIOR DESCONTO CADASTRADOS NA POLITICA DE DESCONTOS

     BEGIN

     vbpoliticadescvalida := FUNCAO_OBTEM_DESC_POLITICA(pi_nTipoChamada,
                                                       pi_nCodPromocaoMed,
                                                       pi_ncodprod ,
                                                       pi_ddata,
                                                       pi_scodfilial,
                                                       pi_nnumregiao,
                                                       pi_ncodcli,
                                                       pi_ncodusur,
                                                       pi_sorigempedido,
                                                       pi_ncodprodprinc,
                                                       pi_nnumcasasdecvenda,
                                                       pi_ncodplpag,
                                                       pi_sclassevenda,
                                                       pi_snaousarautdebcredpoldesc,
                                                       pi_susaprioritaria,
                                                       pi_stipofv,
                                                       pi_ncodcondicaovenda,
                                                       pi_nnumdias,
                                                       vsmensagempoldesc,
                                                       vnPercDescComercPolitica,
                                                       vnPercDescBoletoPolitica,
                                                       po_sbasecreddebrca,
                                                       po_screditasobrepolitica,
                                                       po_salteraptabela,
                                                       po_ndescpbaserca  );

        if vbpoliticadescvalida = false then
           vnPercDescComercPolitica := 0;
           vnPercDescBoletoPolitica := 0;

           po_vMsgErros := vsmensagempoldesc;


        end if;


    EXCEPTION WHEN OTHERS THEN
      -- Se Chamado para obter as Politicas de Desconto / Quantidade
      IF (pi_nTipoChamada = 1) THEN
        vnPercDescComercPolitica := 0;
        vnPercDescBoletoPolitica := 0;
        po_vMsgErros := 'Erro ao verificar politica de descontos. '||SQLCODE|| ' - ' ||SQLERRM;
        RAISE e_Generico;
      END IF;
    END;

   /**************************************************************
    Obtem o maior Desconto cadastrado nos Descontos por Quantidade
    **************************************************************/
    -- FUNCAO PARA OBTER O MAIOR DESCONTO CADASTRADO NOS DESCONTOS POR QUANTIDADE

    BEGIN

      vbvalidodescquant :=  FUNCAO_OBTEM_DESC_QUANTIDADE
                            (pi_nTipoChamada,
                             pi_nCodPromocaoMed,
                             pi_nCodProd,
                             pi_nqtde,
                             pi_nnumregiao,
                           --  p_ptabela,
                           --  p_pvenda1,
                             pi_ncodpraca,
                           --  pi_nnumcasasdecvenda,
                             pi_nnumdias,
                             pi_ncodprodprinc,
                             pi_susaprioritaria ,
                             pi_stipofv,
                             vsmensagemdescquant,
                             vnPercDescComercQuantid,
                             po_creditasobreptabela_quant,
                             po_basedebcredrca_quant,
                             po_percbaserca_quant);

        if vbvalidodescquant = false then

           vnPercDescComercQuantid := 0;

           po_vMsgErros := vsmensagemdescquant;


        end if;


   EXCEPTION WHEN OTHERS THEN
     -- Se Chamado para obter as Politicas de Desconto / Quantidade
     IF (pi_nTipoChamada = 1) THEN
        vnPercDescComercQuantid := 0;
        po_vMsgErros := 'Erro ao verificar politica de descontos por quantidade: '||vsmensagemdescquant;
        RAISE e_Generico;
      END IF;
    END;

    -- Se Chamado para obter as Politicas de Desconto / Quantidade
    IF (pi_nTipoChamada = 1) THEN

     /**********************************************************
      Definição do Desconto Promocional:
      Maior Desconto entre o cadastrado na Politica de Descontos
      e o cadastrado nos Descontos por Quantidade
      **********************************************************/

      -- Escolhe o maior Desconto entre os cadastrados na Politica de Descontos e o Desconto por Quantidade
      IF ((NVL(vnPercDescComercPolitica,0) + NVL(vnPercDescBoletoPolitica,0)) >= NVL(vnPercDescComercQuantid,0)) THEN

        -- Se pode ser concedido Desconto no Boleto para o Cliente
        IF    (NVL(vcPermiteDescBoleto,' ') = 'S') THEN

          -- Desconto a conceder em NF
          vnPercDescComercPromocao := NVL(vnPercDescComercPolitica,0);
          -- Desconto a conceder em Boleto
          vnPercDescBoletoPromocao := NVL(vnPercDescBoletoPolitica,0);

        -- Se NÃO pode ser concedido Desconto no Boleto para o Cliente
        ELSE

          -- Desconto a conceder em NF (adiciona o desconto que seria dado no boleto ao desconto da nota fiscal)
          vnPercDescComercPromocao := (NVL(vnPercDescComercPolitica,0) + NVL(vnPercDescBoletoPolitica,0));
          -- Desconto a conceder em Boleto = ZERO (não pode conceder desconto no boleto)
          vnPercDescBoletoPromocao := 0;

        END IF;

      ELSE

        -- Desconto a conceder em NF
        vnPercDescComercPromocao := NVL(vnPercDescComercQuantid,0);
        -- Desconto a conceder em Boleto = ZERO (Desconto por Quantidade não possui cadastro de desconto financeiro)
        vnPercDescBoletoPromocao := 0;

      END IF;

      -- Desconto Total da Promoção
      vnPercDescTotalPromocao  := NVL(vnPercDescComercPromocao,0) + NVL(vnPercDescBoletoPromocao,0);

     /***************************************
      Obtem o Desconto, Grupo de Faturamento
      e Linha de Prazo do Cadastro do Produto
      ****************************************/
      BEGIN
        SELECT PCPRODUT.percbonificvenda,
               PCPRODUT.grupofaturamento,
               PCPRODUT.codlinhaprazo
          INTO vnPercDescBonifProduto,
               vvGrupoFaturamento,
               vnCodLinhaPrazo
          FROM PCPRODUT
         WHERE (PCPRODUT.codprod = pi_nCodProd);
      EXCEPTION
        WHEN NO_DATA_FOUND THEN
          -- Atualiza Mensagem de Erro e Aborta
          po_vMsgErros := 'Produto [' || pi_nCodProd || '] não cadastrado.';
          RAISE e_Generico;
      END;

     /**************************************************
      Redefine a Linha de Prazo do Produto para atender
      os Clientes que trabalham com Grupo de Faturamento
      **************************************************/
      IF (NVL(vvTipoPrazoMedicam,' ') = '1') THEN

        -- Define a Linha de Prazo conforme o Grupo de Produto
        IF    (NVL(vvGrupoFaturamento,' ') = 'E') THEN
          -- Grupo de Faturamento Etico = Linha 1
          vnCodLinhaPrazo := 1;
        ELSIF (NVL(vvGrupoFaturamento,' ') = 'G') THEN
          -- Grupo de Faturamento Generico = Linha 2
          vnCodLinhaPrazo := 2;
        ELSE
          vnCodLinhaPrazo := NULL;
        END IF;

      END IF;

     /**************************************************
      Obtem o Plano, Descontos e Parametro de Incidencia
      da Linha da Condição de Venda
      **************************************************/
      BEGIN
        SELECT PCCONDVENDALINHA.codplpag,
               PCCONDVENDALINHA.percdescbonifnota,
               PCCONDVENDALINHA.percdescomnota,
               PCCONDVENDALINHA.percdescboleto,
               PCCONDVENDALINHA.percdescfin,
               PCCONDVENDALINHA.tipoincidenciadescom
          INTO vnCodPlPag,
               vnPercDescBonifLinha,
               vnPercDescComercLinha,
               vnPercDescBoletoLinha,
               vnPercDescFinLinha,
               vvTipoIncidencia
          FROM PCCONDVENDALINHA
         WHERE (PCCONDVENDALINHA.codcondicaovenda = pi_nCodCondicaoVenda)
           AND (PCCONDVENDALINHA.codlinhaprazo    = vnCodLinhaPrazo);
      EXCEPTION
        WHEN NO_DATA_FOUND THEN
          -- Atualiza Mensagem de Erro e Aborta
          po_vMsgErros := 'Linha [' || vnCodLinhaPrazo || '] não cadastrada na Cond. Venda [' || pi_nCodCondicaoVenda || '].';
          RAISE e_Generico;
      END;

     /****************************************************
      Redefine Descontos da Linha conforme parametrizações
      da Condição de Venda e do Cliente
      ****************************************************/

      -- Se a Origem do Desconto de Bonificacao for o Cadastro do Produto, substitui
      -- o Desconto de Bonificação da Linha da Condição de Venda pela Bonificação do cadastro do Produto
      IF (NVL(vvTipoDescBonif,' ') = 'P') THEN
        vnPercDescBonifLinha := NVL(vnPercDescBonifProduto,0);
      END IF;

      -- Se NÃO pode ser concedido Desconto no Boleto para o Cliente
      IF    (NVL(vcPermiteDescBoleto,' ') <> 'S') THEN

        -- Desconto a conceder em NF (adiciona o desconto que seria dado no boleto ao desconto da nota fiscal)
        vnPercDescComercLinha := NVL(vnPercDescComercLinha,0) + NVL(vnPercDescBoletoLinha,0);
        -- Desconto a conceder em Boleto = ZERO (não pode conceder desconto no boleto)
        vnPercDescBoletoLinha := 0;

      END IF;

     /**********************************************************
      Definição dos Descontos da Condição de Venda:
      Descontos a serem concedidos conforme o Tipo de Incidencia
      dos Descontos Promocionais sobre os Descontos por Linha
      na Condição de Venda
      *********************************************************/

      -- Cálculo do Total de Descontos da Linha (descontos bonificação + comercial + boleto)
      -- para utilização na validação do maior desconto entre os descontos da Condição de Venda e os Descontos Promocionais
      vnPercDescTotalLinha := F_CalcDescontoSobreDesconto((NVL(vnPercDescBonifLinha,0)),
                                                          (NVL(vnPercDescComercLinha,0) + NVL(vnPercDescBoletoLinha,0)));

      ------------------------------------------------------------------------------
      -- Se Agrega Desconto:
      -- Substitui o Desconto Comercial da Linha da Condição de Venda pelo Desconto
      -- Comercial Promocional e a agrega o resultado ao Desconto de Bonificação
      ------------------------------------------------------------------------------
      IF    (NVL(vvTipoIncidencia,' ') = 'A') THEN

        -- Desconto Total a ser concedido em Nota Fiscal
        vnPerDesc    := F_CalcDescontoSobreDesconto(NVL(vnPercDescBonifLinha,0),
                                                    NVL(vnPercDescComercPromocao,0));
        -- Desconto de Bonificação a ser concedido em Nota Fiscal
        vnPerBonific := NVL(vnPercDescBonifLinha,0);
        -- Desconto Comercial a ser concedido em Nota Fiscal
        vnPerComerc  := NVL(vnPercDescComercPromocao,0);
        -- Desconto do Produto a ser concedido no Boleto
        vnPerBoleto  := NVL(vnPercDescBoletoPromocao,0);

      ------------------------------------------------------------------------------
      -- Se Prioriza Desconto:
      -- Concede somente o Desconto Promocional caso exista, se não existir concede
      -- somente o Desconto da Linha da Condição de Venda
      ------------------------------------------------------------------------------
      ELSIF (NVL(vvTipoIncidencia,' ') = 'P') THEN

        -- Se encontrou Desconto Promocional, somente concederá no Produto os Descontos Promocionais
        IF ((NVL(vnPercDescComercPromocao,0) + NVL(vnPercDescBoletoPromocao,0)) > 0) THEN

          -- Desconto Total a ser concedido em Nota Fiscal
          vnPerDesc    := NVL(vnPercDescComercPromocao,0);
          -- Não concede Desconto de Bonificação em Nota Fiscal
          vnPerBonific := 0;
          -- Desconto Comercial a ser concedido em Nota Fiscal
          vnPerComerc  := NVL(vnPercDescComercPromocao,0);
          -- Desconto do produto a ser concedido no Boleto
          vnPerBoleto  := NVL(vnPercDescBoletoPromocao,0);

        -- Se não encontrou Desconto Promocional, somente concederá no Produto os Descontos da Linha da Condição de Venda
        ELSE

          -- Desconto Total a ser concedido em Nota Fiscal
          vnPerDesc    := F_CalcDescontoSobreDesconto(NVL(vnPercDescBonifLinha,0),
                                                      NVL(vnPercDescComercLinha,0));
          -- Desconto de Bonificação a ser concedido em Nota Fiscal
          vnPerBonific := NVL(vnPercDescBonifLinha,0);
          -- Desconto Comercial a ser concedido em Nota Fiscal
          vnPerComerc  := NVL(vnPercDescComercLinha,0);
          -- Desconto do produto a ser concedido no Boleto
          vnPerBoleto  := NVL(vnPercDescBoletoLinha,0);

        END IF;

      ------------------------------------------------------------------------------
      -- Se Ignora:
      -- Ignora o Desconto Promocional e concede somente o Desconto da Linha da
      -- Condição de Venda
      ------------------------------------------------------------------------------
      ELSIF (NVL(vvTipoIncidencia,' ') = 'I') THEN

        -- Desconto Total a ser concedido em Nota Fiscal
        vnPerDesc    := F_CalcDescontoSobreDesconto(NVL(vnPercDescBonifLinha,0),
                                                    NVL(vnPercDescComercLinha,0));
        -- Desconto de Bonificação a ser concedido em Nota Fiscal
        vnPerBonific := NVL(vnPercDescBonifLinha,0);
        -- Desconto Comercial a ser concedido em Nota Fiscal
        vnPerComerc  := NVL(vnPercDescComercLinha,0);
        -- Desconto do produto a ser concedido no Boleto
        vnPerBoleto  := NVL(vnPercDescBoletoLinha,0);

      ------------------------------------------------------------------------------
      -- Se Maior Desconto:
      -- Concede o maior desconto entre o Desconto Promocional e o Desconto da Linha
      -- da Condição de Venda
      ------------------------------------------------------------------------------
      ELSIF (NVL(vvTipoIncidencia,' ') = 'M') THEN

        -- Se o maior Desconto for o Promocional, concede o Desconto Promocional
        IF ((NVL(vnPercDescComercPromocao,0) + NVL(vnPercDescBoletoPromocao,0)) > NVL(vnPercDescTotalLinha,0)) THEN

          -- Desconto Total a ser concedido em Nota Fiscal
          vnPerDesc    := NVL(vnPercDescComercPromocao,0);
          -- Não concede Desconto de Bonificação em Nota Fiscal
          vnPerBonific := 0;
          -- Desconto Comercial a ser concedido em Nota Fiscal
          vnPerComerc  := NVL(vnPercDescComercPromocao,0);
          -- Desconto do produto a ser concedido no Boleto
          vnPerBoleto  := NVL(vnPercDescBoletoPromocao,0);

        -- Se o maior Desconto não for o Promocional, concede os Desconto da Linha da Condição de Venda
        ELSE

          -- Desconto Total a ser concedido em Nota Fiscal
          vnPerDesc    := F_CalcDescontoSobreDesconto(NVL(vnPercDescBonifLinha,0),
                                                      NVL(vnPercDescComercLinha,0));
          -- Desconto de Bonificação a ser concedido em Nota Fiscal
          vnPerBonific := NVL(vnPercDescBonifLinha,0);
          -- Desconto Comercial a ser concedido em Nota Fiscal
          vnPerComerc  := NVL(vnPercDescComercLinha,0);
          -- Desconto do produto a ser concedido no Boleto
          vnPerBoleto  := NVL(vnPercDescBoletoLinha,0);

        END IF;

      END IF;

     /*********************************
      Atualiza Retornos do Procedimento
      *********************************/
      po_nPerDesc     := NVL(vnPerDesc,0);
      po_nPerBonific  := NVL(vnPerBonific,0);
      po_nPerComerc   := NVL(vnPerComerc,0);
      po_nPerBoleto   := NVL(vnPerBoleto,0);
      po_nPercDescFin := NVL(vnPercDescFinLinha,0);
      pio_CodLinhaPrazo := vnCodLinhaPrazo; -- 155824

    END IF; -- Se Chamado para obter as Politicas de Desconto / Quantidade

  EXCEPTION
    WHEN e_Generico THEN
      -- Atualiza Retorno indicando que ocorreram erros
      po_vOcorreramErros := 'S';
    WHEN OTHERS THEN
      -- Atualiza Retorno indicando que ocorreram erros
      po_vOcorreramErros := 'S';
      po_vMsgErros       := 'Erro ao obter os descontos da Cond. Venda [' || pi_nCodCondicaoVenda || '] - ' || SQLCODE || '-' || SQLERRM;
  END PRC_VEN_OBTEM_DESC_CONDVENDA;

  /*******************************************************************************
                     INICIO DO PROCESSAMENTO PRINCIPAL
   *******************************************************************************/
  BEGIN

    -- Limpa Tabela Temporária (conforme Chamada)
    IF (pi_nTipoChamada IN (2,3,4)) THEN
      DELETE FROM PCMED_SELPROMOCAO;
      --COMMIT;
    END IF;

    -- Se passou a Praça do Cliente no Parâmetro
    IF (NVL(pi_nCodPraca,0) > 0) THEN
      -- Utiliza a Praça passada no Parâmetro
      vnCodPraca := pi_nCodPraca;
    -- Se não passou a Regiao do Cliente no Parâmetro
    ELSE
      -- Obtem Praca do Cliente
      -- e a Classe de venda
      BEGIN
        SELECT PCCLIENT.CODPRACA,
               PCCLIENT.CLASSEVENDA
          INTO vnCodPraca,
               vvClasseVenda
          FROM PCCLIENT
         WHERE (PCCLIENT.CODCLI = pi_nCodCli);
      EXCEPTION
        WHEN NO_DATA_FOUND THEN
          vnCodPraca    := NULL;
          vvClasseVenda := NULL;
      END;
    END IF;

    -- Se passou a Classe de Venda do Cliente
    IF    (pi_vClasseVenda IS NULL) THEN
      -- Utiliza a Classe de Venda do Cliente
      vvClasseVenda :=  pi_vClasseVenda;
    -- Se não passou a Classe de Venda do Cliente e ainda
    -- não foram pesquisados os dados do Cliente
    ELSIF (vvClasseVenda IS NULL) THEN
      -- Obtem a Classe de Venda do Cliente
      BEGIN
        SELECT PCCLIENT.CLASSEVENDA
          INTO vvClasseVenda
          FROM PCCLIENT
         WHERE (PCCLIENT.CODCLI = pi_nCodCli);
      EXCEPTION
        WHEN NO_DATA_FOUND THEN
          vvClasseVenda := NULL;
      END;
    END IF;

    -- Se passou a Regiao do Cliente no Parâmetro
    IF (NVL(pi_nNumRegiao,0) > 0) THEN
      -- Utiliza a Região passada no Parâmetro
      vnNumRegiao := pi_nNumRegiao;
    -- Se não passou a Regiao do Cliente no Parâmetro
    ELSE
      -- Obtem a Regiao do Cliente
      BEGIN
        SELECT PCPRACA.NUMREGIAO
          INTO vnNumRegiao
          FROM PCPRACA
         WHERE (PCPRACA.CODPRACA = vnCodPraca);
      EXCEPTION
        WHEN NO_DATA_FOUND THEN
          vnNumRegiao := NULL;
      END;
    END IF;

    -- Obtém a Qtde. de Casas Decimais
    BEGIN
      SELECT PCCONSUM.NUMCASASDECVENDA
        INTO vnNumCasasDecVenda
        FROM PCCONSUM;
    EXCEPTION
      WHEN NO_DATA_FOUND THEN
        vnNumCasasDecVenda := 2;
    END;

    -- Obtém a Qtde. de Dias do Plano de Pagamento
    BEGIN
      SELECT PCPLPAG.NUMDIAS
        INTO vnNumDias
        FROM PCPLPAG
       WHERE (PCPLPAG.CODPLPAG = pi_nCodPlPag);
    EXCEPTION
      WHEN NO_DATA_FOUND THEN
        vnNumDias := 0;
    END;

    -- Obtém Parâmetros da Filial
    BEGIN
      SELECT NVL(PCPARAMFILIAL.VALOR,'N')
        INTO vvNaoUsarAutDevCredPolDesc
        FROM PCPARAMFILIAL
       WHERE (PCPARAMFILIAL.CODFILIAL = pi_vCodFilial)
         AND (PCPARAMFILIAL.NOME      = 'NAOUSARAUTDEBCREDPOLDESC');
    EXCEPTION
      WHEN OTHERS THEN
        vvNaoUsarAutDevCredPolDesc := 'N';
    END;

    -- Obtém Parâmetros da Regra de Desconto Adicional para Plano Pagamento À Vista
    BEGIN
      SELECT NVL(PCPARAMFILIAL.VALOR,'N')
        INTO vvMedUsaDescAdicPlPAgVista
        FROM PCPARAMFILIAL
       WHERE (PCPARAMFILIAL.CODFILIAL = pi_vCodFilial)
         AND (PCPARAMFILIAL.NOME      = 'MEDUSADESCADICPLPAGVISTA');
    EXCEPTION
      WHEN OTHERS THEN
        vvNaoUsarAutDevCredPolDesc := 'N';
    END;
    IF (NVL(vvMedUsaDescAdicPlPAgVista,'N') = 'S') THEN
      BEGIN
        SELECT NVL(PCPARAMFILIAL.VALOR,'0')
          INTO vvMedPerDescAdicPlPagVista
          FROM PCPARAMFILIAL
         WHERE (PCPARAMFILIAL.CODFILIAL = pi_vCodFilial)
           AND (PCPARAMFILIAL.NOME      = 'MEDPERDESCADICPLPAGVISTA');
        vnMedPerDescAdicPlPagVista := TO_NUMBER(REPLACE(NVL(vvMedPerDescAdicPlPagVista,'0'),',','.'));
      EXCEPTION
        WHEN OTHERS THEN
          vnMedPerDescAdicPlPagVista := 0;
      END;
    ELSE
      vnMedPerDescAdicPlPagVista := 0;
    END IF;

    -- Chama Procedimento da para obter os Descontos
    PRC_VEN_OBTEM_DESC_CONDVENDA(pi_nTipoChamada,
                                 pi_nCodPromocaoMed,
                                 pi_nCodProd,
                                 pi_nQtde,
                                 pi_nCodCondicaoVenda,
                                 pi_nCodCli,
                                 pi_dData,
                                 pi_vCodFilial,
                                 vnNumRegiao,
                                 pi_nCodUsur,
                                 pi_vOrigemPed,
                                 pi_nCodProd,
                                 vnNumCasasDecVenda,
                                 pi_nCodPlPag,
                                 vnNumDias,
                                 vvClasseVenda,
                                 vnCodPraca,
                                 vvNaoUsarAutDevCredPolDesc,
                                 pi_vUsaPrioritaria,
                                 pi_vTipoFv,
                                 vvBasecreddebrca,
                                 vvCreditasobrepolitica,
                                 vvAlteraptabela,
                                 vnDescpbaserca,
                                 vvCreditaSobrePTabela_Quant,
                                 vnBaseDebCredRca_Quant,
                                 vnPercBaseRca_Quant,
                                 po_nPerDesc,
                                 po_nPerBonific,
                                 po_nPerComerc,
                                 po_nPerBoleto,
                                 po_nPercDescFin,
                                 po_vOcorreramErros,
                                 po_vMsgErros,
                                 po_nCodLinhaPrazo);

    -- HIS.03612.2015 - Se Chamado da Carga de Promoções e Usando Plano Pagto. a Vista
    IF (pi_nTipoChamada = 2)                   AND
       (vvMedUsaDescAdicPlPAgVista = 'S')      AND
       (NVL(vnMedPerDescAdicPlPagVista,0) > 0) THEN
      -- Verifica se existe alguma Promoção que não seja por Intervalo de Quantidade (Desconto ou Valor ou Bonificação)
      BEGIN
        SELECT 'S'
          INTO vvAchouSelPromocao
          FROM PCMED_SELPROMOCAO
         WHERE (PCMED_SELPROMOCAO.TIPOPOLITICA NOT IN ('Q','F','B','V'))
           AND (ROWNUM = 1);
      EXCEPTION
        WHEN NO_DATA_FOUND THEN
          vvAchouSelPromocao := 'N';
      END;
      -- Se não carregou Promoções
      IF (vvAchouSelPromocao = 'N') THEN
        BEGIN
          SELECT TIPOVENDA
            INTO vvTipoVenda
            FROM PCPLPAG
           WHERE (PCPLPAG.CODPLPAG = pi_nCodPlPag);
        EXCEPTION
          WHEN NO_DATA_FOUND THEN
            vvTipoVenda := NULL;
        END;
        -- Se Plano de Pagamento À Vista
        IF (vvTipoVenda = 'VV') THEN
          -- Insere Dados na Tabela Temporária
          BEGIN
            INSERT INTO PCMED_SELPROMOCAO
                      ( CODPROMOCAOMED
                      , CODDESCONTO
                      , TIPOPOLITICA
                      , DESCRICAORESUMIDA
                      , DESCRICAODETALHADA
                      , DATAINICIAL
                      , DATAFINAL
                      , APLICADESCONTO
                      , PERCDESC
                      , BASECREDDEBRCA
                      , PERCDESCFIN
                      , CREDITASOBREPOLITICA
                      , ALTERAPTABELA
                      , PRIORITARIA
                      , PERCDESCRESTRICAO
                      , CONSIDERACALCGIROMEDIC
                      , CONCEDERMAIORCOMISSREG
                      , ALTERADESCONTO
                      , ENCARTEFECHADO
                      , PRIORIZACOMISSAO
                      , INICIOINTERVALO
                      , FIMINTERVALO
                      , PRECOFIXO
                      , VALIDARINTERVALOVALIDADEPROD
                      , DTINICIOPROMOLOTE
                      , DTFIMPROMOLOTE
                      , TIPOPROMOCAO
                      , PARTICIPACOMISSGARANTIDA
                      , UTILIZAPERCDESCBASERCA
                      , PERMITIRAUMENTARQTDEKIT
                      , PERCDESCBASERCA
                      , ORIGEMPRECO
                      , PERCBONIFICMERC
                      , PROMOCAOMEDOBRIGATORIO )
               VALUES ( -1                         --CODPROMOCAOMED (-1 identifica Promoção à Vista)
                      , 0
                      , 'V'                        --TIPOPOLITICA = 'V' - Desconto Plano Pgto. à Vista
                      , 'Desc. Adicional à vista'  --DESCRICAORESUMIDA
                      , 'Desc. Adicional à vista'  --DESCRICAODETALHADA
                      , TRUNC(SYSDATE)             --DATAINICIAL
                      , TRUNC(SYSDATE)             --DATAFINAL
                      , 'S'                        --APLICADESCONTO
                      , vnMedPerDescAdicPlPagVista --percdesc
                      , 'N'                        --basecreddebrca
                      , 0                          --percdescfin
                      , 'N'                        --creditasobrepolitica
                      , 'N'                        --alteraptabela
                      , 'N'                        --prioritaria
                      , vnMedPerDescAdicPlPagVista --percdesc
                      , 'S'                        --consideracalcgiromedic
                      , 'N'                        --concedermaiorcomissreg
                      , 'S'                        --ALTERADESCONTO
                      , 'N'                        --ENCARTEFECHADO
                      , 'N'                        --PRIORIZACOMISSAO
                      , NULL                       --INICIOINTERVALOPROMOCAOMED
                      , NULL                       --FIMINTERVALOPROMOCAOMED
                      , NULL                       --precofixopromocaomed
                      , 'N'                        --VALIDARINTERVALOVALIDADEPROD
                      , NULL                       --DTINICIOPROMOLOTE
                      , NULL                       --DTFIMPROMOLOTE
                      , 'C'                        --TIPOPROMOCAO
                      , 'N'                        --participacomissgarantida
                      , 'N'                        --UTILIZAPERCDESCBASERCA
                      , 'N'                        --PERMITIRAUMENTARQTDEKIT
                      , NULL                       --percdescbaserca
                      , 'T'                        --ORIGEMPRECO
                      , NULL                       --PERCBONIFICMERC
                      , 'S'                        --PROMOCAOMEDOBRIGATORIO
                      );
          EXCEPTION
            WHEN DUP_VAL_ON_INDEX THEN
              NULL;
          END;
        END IF;
      END IF;
    END IF; -- Fim Condição HIS.03612.2015 - Se Chamado da Carga de Promoções e Usando Plano Pagto. a Vista

    -- Efetiva Transações (conforme Chamada)
    --IF (pi_nTipoChamada IN (2,3)) THEN
      --COMMIT;
    --END IF;

  EXCEPTION
    WHEN OTHERS THEN
      po_vMsgErros := 'S';
      po_vMsgErros := SQLERRM;
  END P_OBTEM_DESC_TELEVENDAS;

  /*******************************************************************************
   Nome         : P_OBTEM_DESC_TELEVENDAS_01
   Descricão    : Procedimento para Obter os Descontos do Produto para os
                  critérios estabelecidos nos Parãmetros
                  a partir da Verba para Rebaixa de CMV da Promoção - DDMEDICA-5009
   Parâmetros   : ENTRADA:
                  pi_nTipoChamada          = 1 - Obter as Politicas de Desconto / Quantidade (Operador Logístico)
                                             2 - Obter as Promoções
                                             3 - Gravar na Tabela Temporária os
                                                 Descontos por Quantidade das Políticas
                                                 de Desconto por Quantidade
