    -- Array para Guardar a Prioridade das Promoções Gravadas
    TYPE TTPrioridadePromocao   IS TABLE OF NUMBER(2) INDEX BY BINARY_INTEGER;
    vtPrioridadePromocao        TTPrioridadePromocao;
    -- Validade do Lote
    vdValidadeLote              DATE;
    -- Regra de Alteração do Desconto/Preco
    vvRegraAlterarDesconto      PCDESCONTO.REGRAALTERARDESCONTO%TYPE;

    FUNCTION FACEITA_PROMOCAO_PRIORIDADE(pi_nCodPromocao         IN NUMBER,
                                         pi_nPrioridade          IN NUMBER,
                                         pi_vBloqueio            IN VARCHAR2,
                                         pi_vPromoEspecial       IN VARCHAR2,
                                         pi_vVisualizarPromoBloq IN VARCHAR2,
                                         pi_vVisualizarPromoEsp  IN VARCHAR2,
                                         --
                                         pi_vCodFilial           IN VARCHAR2,
                                         pi_nCodCli              IN NUMBER,
                                         pi_nNumRegiao           IN NUMBER,
                                         pi_nCodUsur             IN NUMBER,
                                         pi_nCodPlPag            IN NUMBER,
                                         pi_nCodCondicaoVenda    IN NUMBER,
                                         pi_vOrigemPed           IN VARCHAR2,
                                         pi_vTipoFv              IN VARCHAR2,
                                         pi_dDataPedido          IN DATE,
                                         --
                                         pi_vTipoPromocao        IN VARCHAR2)
    RETURN BOOLEAN IS
      vbRetAceita BOOLEAN;
    BEGIN

      -- PROMOÇÃO DE CAMPANHA NÃO PODE SER SELECIONADA - HIS.01889.2017
      IF (pi_vTipoPromocao = 'N') THEN

        vbRetAceita := FALSE;

      -- DEMAIS PROMOÇÕES DIFERENTES DE CAMPANHA
      ELSE

        -- Inicializa como Aceitar ou se Usar Normalização da PCDESCONTO o resultado da validação
        vbRetAceita := (PKG_FUNCOESVENDAS_MED.F_PODECOMPRARPROMOCAO(pi_nCodPromocao,
                                                                    pi_vCodFilial,
                                                                    pi_nCodCli,
                                                                    pi_nNumRegiao,
                                                                    pi_nCodUsur,
                                                                    pi_nCodPlPag,
                                                                    pi_nCodCondicaoVenda,
                                                                    pi_vOrigemPed,
                                                                    pi_vTipoFv,
                                                                    pi_dDataPedido) = 'S');

        -- Se Aceita a Promoção
        IF (vbRetAceita) THEN

          -- Se a Promoção ainda não existir para o Produto aceita sem restrições
          IF (NOT vtPrioridadePromocao.EXISTS(pi_nCodPromocao)) THEN
            vtPrioridadePromocao(pi_nCodPromocao) := pi_nPrioridade;
            vbRetAceita := TRUE;
          -- Se a Promoção já existe
          ELSE
            -- Somente aceita Promoção com maior prioridade
            -- (Se a prioridade atual é 3, somente aceitará promoção com prioridades 1 e 2)
            IF (pi_nPrioridade <= vtPrioridadePromocao(pi_nCodPromocao)) THEN
              vtPrioridadePromocao(pi_nCodPromocao) := pi_nPrioridade;
              vbRetAceita := TRUE;
            ELSE
              vbRetAceita := FALSE;
            END IF;
          END IF;

          IF (pi_vBloqueio = 'S') AND (NVL(pi_vVisualizarPromoBloq,'N') <> 'S') THEN
              vbRetAceita := FALSE;
          END IF;

          IF (pi_vPromoEspecial = 'S') AND (NVL(pi_vVisualizarPromoEsp,'N') <> 'S') THEN
              vbRetAceita := FALSE;
          END IF;

        END IF;

      END IF; -- FIM CONDIÇÃO: PROMOÇÃO DE CAMPANHA - HIS.01889.2017

      -- Retorno
      RETURN vbRetAceita;

    END FACEITA_PROMOCAO_PRIORIDADE;

    PROCEDURE PRC_VEN_OBTEM_DESC_CONDVENDA(pi_nTipoChamada      IN  NUMBER,
                                                           pi_nCodPromocaoMed   IN  NUMBER,
                                                           pi_nCodProd                  IN  pcprodut.codprod%type,
                                                           pi_nqtde                     IN  pcpedi.qt%type,
                                                           pi_nCodCondicaoVenda         IN  pccondicaovenda.codcondicaovenda%type,
                                                           pi_nCodCli                   IN  pcclient.codcli%type,
                                                           pi_dData                     IN  DATE,
                                                           pi_sCodFilial                IN  pcfilial.codigo%type,
                                                           pi_nNumregiao                IN  pcregiao.numregiao%type,
                                                           pi_nCodusur                  IN  pcusuari.codusur%type,
                                                           pi_sOrigempedido             IN  pcpedc.origemped%type,
                                                           pi_nCodProdPrinc             IN  pcprodut.codprodprinc%type,
                                                           pi_nNumcasasdecvenda         IN  pcconsum.numcasasdecvenda%type,
                                                           pi_nCodPlPag                 IN  pcplpag.codplpag%type,
                                                           pi_nnumdias                  IN  pcplpag.numdias%type,
                                                           pi_sclassevenda              IN  pcclient.classevenda%type,
                                                           pi_ncodpraca                 IN  pcclient.codpraca%type,
                                                           pi_snaousarautdebcredpoldesc IN varchar2,
                                                           pi_sUsaprioritaria           IN varchar2,
                                                           pi_sTipofv                   IN pcpedretorno.tipofv%type,
                                                           po_sBasecreddebrca           OUT pcdesconto.basecreddebrca%type,
                                                           po_sCreditasobrepolitica     OUT pcdesconto.creditasobrepolitica%type,
                                                           po_sAlteraptabela            OUT pcdesconto.alteraptabela%type,
                                                           po_nDescpbaserca             OUT pcdesconto.percdesc%type,
                                                           po_creditasobreptabela_quant  OUT pcdescquant.creditasobreptabela%type,
                                                           po_basedebcredrca_quant      OUT pcdescquant.basecreddebrca%type,
                                                           po_percbaserca_quant         OUT pcdescquant.percdesc%type,
                                                           po_nPerDesc                  OUT NUMBER,
                                                           po_nPerBonific               OUT NUMBER,
                                                           po_nPerComerc                OUT NUMBER,
                                                           po_nPerBoleto                OUT NUMBER,
                                                           po_nPercDescFin              OUT NUMBER,
                                                           po_vOcorreramErros           OUT VARCHAR2,
                                                           po_vMsgErros                 OUT VARCHAR2,
                                                           pio_CodLinhaPrazo            IN  OUT VARCHAR2) IS -- 155824)
  /*******************************************************************************
    Proposito: Procedimento para obter os Descontos da Condição de Venda de
               Medicamentos
    Versao   :

    Parâmetros de Entrada:
    ---------------------
    pi_nCodProd          = Código do Produto no Winthor
    pi_nCodCondicaoVenda = Código da Condição de Venda no Winthor
    pi_nCodCli           = Código do Cliente no Winthor

    Parâmetros de Saída:
    -------------------
    po_nPerDesc          = Percentual de Desconto do Produto a ser concedido na
                           Nota Fiscal
    po_nPerBonific       = Percentual de Desconto de Bonificação a ser concedido
                           na Nota Fiscal. Este percentual está contido em po_nPerDesc
    po_nPerComerc        = Percentual de Desconto Comercial a ser concedido
                           na Nota Fiscal. Este percentual está contido em po_nPerDesc
    po_nPerBoleto        = Percentual de Desconto do Produto a ser concedido no Boleto
    po_nPercDescFin      = Percentual de Desconto Financeiro da Linha de Prazo
    po_vOcorreramErros   = Indicação se ocorreram erros: S-Sim; N-Não
    po_vMsgErros         = Mensagem com o erro

   *******************************************************************************/

    -- Parametro da Empresa Tipo de Prazo de Medicamentos
    vvTipoPrazoMedicam       PCPARAMFILIAL.valor%TYPE;

    vcPermiteDescBoleto      pcclient.usadescfinseparadodesccom%type;

    -- Descontos cadastrados na Politica de Descontos
    vnPercDescComercPolitica PCDESCONTO.percdesc%TYPE;
    vnPercDescBoletoPolitica PCDESCONTO.percdescfin%TYPE;
    vbpoliticadescvalida     boolean;
    vsmensagempoldesc        varchar2(300);

    -- Desconto cadastrado por Quantidade
    vnPercDescComercQuantid  PCDESCQUANT.percdesc%TYPE;
    vbvalidodescquant        boolean;
    vsmensagemdescquant      varchar2(300);

    -- Descontos Promocionais (Recebera o maior entre a Politica de Descontos e os Descontos por Quantidade)
    vnPercDescComercPromocao PCDESCONTO.percdesc%TYPE;
    vnPercDescBoletoPromocao PCDESCONTO.percdescfin%TYPE;
    vnPercDescTotalPromocao  PCDESCONTO.percdesc%TYPE;

    -- Percentual de Desconto de Bonificação, Grupo Faturamento e Linha de Prazo do Cadastro do Produto
    vnPercDescBonifProduto   PCPRODUT.percbonificvenda%TYPE;
    vvGrupoFaturamento       PCPRODUT.grupofaturamento%TYPE;
    vnCodLinhaPrazo          PCPRODUT.codlinhaprazo%TYPE;

    -- Plano Pagamento, Descontos e Parametro de Tipo de Incidencia da Linha da Condicao de Venda
    vnCodPlPag               PCCONDVENDALINHA.codplpag%TYPE;
    vnPercDescBonifLinha     PCCONDVENDALINHA.percdescbonifnota%TYPE;
    vnPercDescComercLinha    PCCONDVENDALINHA.percdescomnota%TYPE;
    vnPercDescBoletoLinha    PCCONDVENDALINHA.percdescboleto%TYPE;
    vnPercDescFinLinha       PCCONDVENDALINHA.percdescfin%TYPE;
    vvTipoIncidencia         PCCONDVENDALINHA.tipoincidenciadescom%TYPE;

    -- Parâmetro da condicao de venda que define a Origem do Desconto de Bonificação
    vvTipoDescBonif          PCCONDICAOVENDA.tipodescbonif%TYPE;

    -- Percentual de Desconto Total da Linha
    vnPercDescTotalLinha     PCCONDVENDALINHA.percdescbonifnota%TYPE;

    -- Percentual de Desconto do Produto que será Concedido em Nota Fiscal
    vnPerDesc                PCPEDI.perdesc%TYPE;
    -- Percentual de Desconto de Bonificação
    vnPerBonific             PCPEDI.perbonific%TYPE;
    -- Percentual de Desconto Comercial
    vnPerComerc              PCPEDI.perdesccom%TYPE;
    -- Percentual de Desconto do Produto que será Concedido no Boleto
    vnPerBoleto              PCPEDI.perdescboleto%TYPE;

    -- Excecao de Erro Generico
    e_Generico               EXCEPTION;

    -- Função para calcular Desconto sobre Desconto
    FUNCTION F_CalcDescontoSobreDesconto(pi_nDesconto1 IN NUMBER,
                                         pi_nDesconto2 IN NUMBER)
    RETURN NUMBER IS
      vnPercDesconto    PCCONDVENDALINHA.percdescbonifnota%TYPE;
      vnPercDescRetorno PCCONDVENDALINHA.percdescbonifnota%TYPE;
    BEGIN
      -- Cálculo do Desconto sobre Desconto
      vnPercDesconto    := 100;
      vnPercDesconto    := (vnPercDesconto * (1 - (NVL(pi_nDesconto1,0) / 100)));
      vnPercDesconto    := (vnPercDesconto * (1 - (NVL(pi_nDesconto2,0) / 100)));
      vnPercDescRetorno := 100 - NVL(vnPercDesconto,0);
      -- Retorno
      RETURN vnPercDescRetorno;
    END F_CalcDescontoSobreDesconto;

    -- Procedimento para obter os dados da promoção
    PROCEDURE P_OBTEM_DADOS_PROMOCAO(pi_nCodPromocao             IN  NUMBER,
                                     po_vACHOUPROMOCAO           OUT VARCHAR2,
                                     po_vTIPOPOLITICA            OUT VARCHAR2,
                                     po_vDESCRICAORESUMIDA       OUT VARCHAR2,
                                     po_vDESCRICAODETALHADA      OUT VARCHAR2,
                                     po_dDATAINICIAL             OUT DATE,
                                     po_dDATAFINAL               OUT DATE,
                                     po_vAPLICADESCONTO          OUT VARCHAR2,
                                     po_vALTERADESCONTO          OUT VARCHAR2,
                                     po_vENCARTEFECHADO          OUT VARCHAR2,
                                     po_vPRIORIZACOMISSAO        OUT VARCHAR2,
                                     po_vVALIDARINTERVALO        OUT VARCHAR2,
                                     po_vDTINICIOPROMOLOTE       OUT DATE,
                                     po_vDTFIMPROMOLOTE          OUT DATE,
                                     po_vTIPOPROMOCAO            OUT VARCHAR2,
                                     po_vBLOQUEIO                OUT VARCHAR2,
                                     po_vPROMOESPECIAL           OUT VARCHAR2,
                                     po_vUTILIZAPERCDESCBASERCA  OUT VARCHAR2,
                                     po_vPERMITIRAUMENTARQTDEKIT OUT VARCHAR2,
                                     po_vORIGEMPRECO             OUT VARCHAR2) IS
    BEGIN
      -- Pesquisa Dados na Tabela de Promoções
      BEGIN
        SELECT 'S'
             , TIPOPOLITICA
             , SUBSTR(NVL(DESCRICAORESUMIDA,' ') || ' (' || CODPROMOCAOMED || ')',1,40) DESCRICAORESUMIDA
             , DESCRICAODETALHADA
             , DATAINICIAL
             , DATAFINAL
             , NVL(ALTERADESCONTO,'S') ALTERADESCONTO -- Default S-Sim
             , NVL(ENCARTEFECHADO,'N') ENCARTEFECHADO
             , NVL(PRIORIZACOMISSAO,'N') PRIORIZACOMISSAO
             , NVL(VALIDARINTERVALOVALIDADEPROD, 'N') VALIDARINTERVALOVALIDADEPROD
             , DTINICIOPROMOLOTE
             , DTFIMPROMOLOTE
             , TIPOPROMOCAO
             , NVL(BLOQUEIO,'N') BLOQUEIO
             , NVL(VISUALIZARPROMOESP,'N') VISUALIZARPROMOESP
             , NVL(UTILIZAPERCDESCBASERCA,'N') UTILIZAPERCDESCBASERCA
             , NVL(PERMITIRAUMENTARQTDEKIT,'N') PERMITIRAUMENTARQTDEKIT
             , NVL(ORIGEMPRECO,'T') ORIGEMPRECO
          INTO po_vACHOUPROMOCAO
             , po_vTIPOPOLITICA
             , po_vDESCRICAORESUMIDA
             , po_vDESCRICAODETALHADA
             , po_dDATAINICIAL
             , po_dDATAFINAL
             , po_vALTERADESCONTO
             , po_vENCARTEFECHADO
             , po_vPRIORIZACOMISSAO
             , po_vVALIDARINTERVALO
             , po_vDTINICIOPROMOLOTE
             , po_vDTFIMPROMOLOTE
             , po_vTIPOPROMOCAO
             , po_vBLOQUEIO
             , po_vPROMOESPECIAL
             , po_vUTILIZAPERCDESCBASERCA
             , po_vPERMITIRAUMENTARQTDEKIT
             , po_vORIGEMPRECO
          FROM PCPROMOCAOMED
         WHERE (CODPROMOCAOMED = pi_nCodPromocao);
      EXCEPTION
        WHEN NO_DATA_FOUND THEN
          po_vACHOUPROMOCAO := 'N';
      END;
      -- Promoção sempre aplica desconto automaticamente
      po_vAPLICADESCONTO := 'S';
    END P_OBTEM_DADOS_PROMOCAO;

    -- Função para Retornar se é Promoção de Encarte
    FUNCTION F_PROMOCAO_ENCARTE(pi_nCodPromocao IN NUMBER)
    RETURN BOOLEAN IS
      vbRetorno      BOOLEAN;
      vvTIPOPROMOCAO PCPROMOCAOMED.TIPOPROMOCAO%TYPE;
    BEGIN
      BEGIN
        SELECT TIPOPROMOCAO
          INTO vvTIPOPROMOCAO
          FROM PCPROMOCAOMED
         WHERE (CODPROMOCAOMED = pi_nCodPromocao);
      EXCEPTION
        WHEN NO_DATA_FOUND THEN
          vvTIPOPROMOCAO := 'C';
      END;
      -- Retorno
      IF (NVL(vvTIPOPROMOCAO,' ') IN ('E')) THEN
        RETURN TRUE;
      ELSE
        RETURN FALSE;
      END IF;
    END F_PROMOCAO_ENCARTE;

    -- Função para Retornar se é Promoção de Cabeçalho
    FUNCTION F_PROMOCAO_CABECALHO(pi_nCodPromocao IN NUMBER)
    RETURN BOOLEAN IS
      vbRetorno      BOOLEAN;
      vvTIPOPROMOCAO PCPROMOCAOMED.TIPOPROMOCAO%TYPE;
    BEGIN
      BEGIN
        SELECT TIPOPROMOCAO
          INTO vvTIPOPROMOCAO
          FROM PCPROMOCAOMED
         WHERE (CODPROMOCAOMED = pi_nCodPromocao);
      EXCEPTION
        WHEN NO_DATA_FOUND THEN
          vvTIPOPROMOCAO := 'C';
      END;
      -- Retorno
      IF (NVL(vvTIPOPROMOCAO,' ') IN ('V','M')) THEN
        RETURN TRUE;
      ELSE
        RETURN FALSE;
      END IF;
    END F_PROMOCAO_CABECALHO;

    -- Função para Retornar se é Promoção de KIT
    FUNCTION F_PROMOCAO_KIT(pi_nCodPromocao IN NUMBER)
    RETURN BOOLEAN IS
      vbRetorno      BOOLEAN;
      vvTIPOPROMOCAO PCPROMOCAOMED.TIPOPROMOCAO%TYPE;
    BEGIN
      BEGIN
        SELECT TIPOPROMOCAO
          INTO vvTIPOPROMOCAO
          FROM PCPROMOCAOMED
         WHERE (CODPROMOCAOMED = pi_nCodPromocao);
      EXCEPTION
        WHEN NO_DATA_FOUND THEN
          vvTIPOPROMOCAO := 'C';
      END;
      -- Retorno
      IF (NVL(vvTIPOPROMOCAO,' ') IN ('K')) THEN
        RETURN TRUE;
      ELSE
        RETURN FALSE;
      END IF;
    END F_PROMOCAO_KIT;

    -- Função para Retornar se é Promoção de MarkUP
    FUNCTION F_PROMOCAO_MARKUP(pi_nCodPromocao IN NUMBER)
    RETURN BOOLEAN IS
      vbRetorno      BOOLEAN;
      vvTIPOPROMOCAO PCPROMOCAOMED.TIPOPROMOCAO%TYPE;
    BEGIN
      BEGIN
        SELECT TIPOPROMOCAO
          INTO vvTIPOPROMOCAO
          FROM PCPROMOCAOMED
         WHERE (CODPROMOCAOMED = pi_nCodPromocao);
      EXCEPTION
        WHEN NO_DATA_FOUND THEN
          vvTIPOPROMOCAO := 'C';
      END;
      -- Retorno
      IF (NVL(vvTIPOPROMOCAO,' ') IN ('R')) THEN
        RETURN TRUE;
      ELSE
        RETURN FALSE;
      END IF;
    END F_PROMOCAO_MARKUP;

    -- Função para Retornar se é Promoção Casadinha Válida - HIS.01152.2015
    FUNCTION F_PROMOCAO_CASADINHA(pi_nCodPromocao IN NUMBER,
                                 pi_nCodProd     IN NUMBER)
    RETURN VARCHAR2 IS
      vvTIPOPROMOCAO  PCPROMOCAOMED.TIPOPROMOCAO%TYPE;
      vnCODPRODBRINDE PCPROMOCAOMED.CODPRODBRINDE%TYPE;
    BEGIN
      BEGIN
        SELECT TIPOPROMOCAO
             , CODPRODBRINDE
          INTO vvTIPOPROMOCAO
             , vnCODPRODBRINDE
          FROM PCPROMOCAOMED
         WHERE (CODPROMOCAOMED = pi_nCodPromocao);
      EXCEPTION
        WHEN NO_DATA_FOUND THEN
          vvTIPOPROMOCAO  := 'C';
          vnCODPRODBRINDE := NULL;
      END;
      -- Retorno
      IF (NVL(vvTIPOPROMOCAO,' ') IN ('S')) THEN
        -- Verifica se o Produto é Principal
        IF (NVL(vnCODPRODBRINDE,0) = NVL(pi_nCodProd,0)) THEN
          RETURN 'P'; -- Produto Principal
        ELSE
          RETURN 'S'; -- Produto Secundário
        END IF;
      ELSE
        RETURN 'N'; -- Não é Casadinha
      END IF;
    END F_PROMOCAO_CASADINHA;

  FUNCTION FUNCAO_OBTEM_DESC_POLITICA
    (pi_nTipoChamada            IN NUMBER,
     pi_nCodPromocaoMed         IN NUMBER,
     p_codprod                  IN NUMBER,
     p_data                     IN DATE,
     p_codfilial                IN VARCHAR2,
     p_numregiao                IN NUMBER,
     p_codcli                   IN NUMBER,
     p_codusur                  IN NUMBER,
     p_origempedido             IN VARCHAR2,
     p_codprodprinc             IN NUMBER,
     p_numcasasdecvenda         IN NUMBER,
     p_codplpag                 IN NUMBER,
     p_classevenda              IN pcclient.classevenda%TYPE,
     p_naousarautdebcredpoldesc IN varchar2 default 'N',
     p_usaprioritaria           IN varchar2 default 'S',
     p_tipofv                   IN pcintegradora.tipofv%type,
     p_codcondicaovenda         IN pccondicaovenda.codcondicaovenda%type,
     p_numdias                  IN NUMBER,
     p_mensagem                 OUT VARCHAR2,
     p_perdesc                  OUT NUMBER,
     p_perdescfin               OUT NUMBER,
     p_basecreddebrca           OUT VARCHAR2,
     p_creditasobrepolitica     OUT VARCHAR2,
     p_alteraptabela            OUT VARCHAR2,
     p_pbaserca                 OUT NUMBER
  ) RETURN BOOLEAN IS

      CURSOR c_principal(vncodepto IN NUMBER, vncodsec IN NUMBER, vncodcategoria IN NUMBER, vncodfornec IN NUMBER, vncodsupervisor IN NUMBER, vncodatv1 IN NUMBER, vncodpraca IN NUMBER, vsaplicadesconto IN VARCHAR2, vsareaatuacao IN VARCHAR2, vssimplesnacional IN varchar2,
                       vncodrede IN number , vncodmarca IN number, vncodlinhaprod IN NUMBER, vncodcliprinc IN number) IS
        SELECT percdesc,nvl(percdescfin,0) percdescfin,
               nvl(basecreddebrca, 'N') basecreddebrca,
               dtfim,
               nvl(creditasobrepolitica, 'S') creditasobrepolitica,
               pcdesconto.dtinicio,
               pcdesconto.coddesconto,
               pcdesconto.alteraptabela,
               pcdesconto.prioritaria,
               pcdesconto.questionausoprioritaria,
               pcdesconto.codpromocaomed,
               pcdesconto.consideracalcgiromedic,
               pcdesconto.concedermaiorcomissreg,
               pcdesconto.aplicadesconto,
               pcdesconto.participacomissgarantida,
               CASE WHEN (NVL(pi_nTipoChamada,0) <> 2)         THEN 1 -->> Garantir que Politicas de Desconto não usem a Regra de Prioridade no ORDER BY
                    WHEN (pcdesconto.codprod      IS NOT NULL) THEN 1
                    WHEN (pcdesconto.codfornec    IS NOT NULL) THEN 2
                    WHEN (pcdesconto.codmarca     IS NOT NULL) THEN 3
                    WHEN (pcdesconto.codcategoria IS NOT NULL) THEN 4
                    WHEN (pcdesconto.codsec       IS NOT NULL) THEN 5
                    WHEN (pcdesconto.codlinhaprod IS NOT NULL) THEN 6
                    WHEN (pcdesconto.codepto      IS NOT NULL) THEN 7
                    ELSE 8 END PRIORIDADE,
               pcdesconto.iniciointervalopromocaomed,
               pcdesconto.fimintervalopromocaomed,
               pcdesconto.precofixopromocaomed,
               nvl(pcdesconto.PERCDESCBASERCA,0) PERCDESCBASERCA,
               nvl(pcdesconto.PERCBONIFICMERC,0) PERCBONIFICMERC,
               pcdesconto.qtini,
               pcdesconto.qtfim,
               pcdesconto.percmarkupmed,
               PERMITIRAUMENTARQTDEKITMED, -- Não pode ter NVL aqui pra fazer depois com a PCPROMOCAOMED.PERMITIRAUMENTARQTDEKIT depois
               NVL(pcdesconto.PROMOCAOMEDOBRIGATORIO,'S') PROMOCAOMEDOBRIGATORIO, -- NVL para "S" para garantir que no kit criado antes dessa customização não permita excluir o item na 2316
               pcdesconto.numlote,
               pcdesconto.codigointegracaowms,
               pcdesconto.vldesccmvpromocaomed, -- DDMEDICA-5009
               NVL(pcdesconto.regraalterardesconto,'P') regraalterardesconto
          FROM pcdesconto
         WHERE TRUNC(p_data) BETWEEN dtinicio AND dtfim
           --AND nvl(utilizadescrede, 'N') = 'N'
           --AND ((codcli = p_codcli) OR (codcli IS NULL))
           --DDMEDICA-1733
           AND ( ((nvl(utilizadescrede, 'N') = 'S') AND (codcli IN (p_codcli,vncodcliprinc))) OR
               ((nvl(utilizadescrede, 'N') = 'N') AND (codcli  = p_codcli))       OR
               (codcli IS NULL) )

           AND ((codepto = vncodepto) OR (codepto IS NULL))
           AND ((codsec = vncodsec) OR (codsec IS NULL))
           AND ((codcategoria = vncodcategoria) OR (codcategoria IS NULL))
           AND ((codprod = p_codprod) OR (codprod IS NULL))
           AND ((codfornec = vncodfornec) OR (codfornec IS NULL))
           AND ((codusur = p_codusur) OR (codusur IS NULL))
           AND ((codsupervisor = vncodsupervisor) OR (codsupervisor IS NULL))

           AND ((numregiao = p_numregiao) OR (numregiao IS NULL))
           AND ((codativ = vncodatv1) OR (codativ IS NULL))
           AND ((origemped = p_origempedido) OR (nvl(origemped, 'O') = 'O'))
           AND ((codpraca = vncodpraca) OR (codpraca IS NULL))
           AND ((codprodprinc = p_codprodprinc) OR (codprodprinc IS NULL))
           --AND ((codplpag = p_codplpag) OR (codplpag IS NULL))
           AND ( ( ( NVL( APENASPLPAGMAX, 'S' ) = 'N' ) AND ( ( SELECT NVL(PCPLPAG.NUMDIAS,0) FROM PCPLPAG WHERE CODPLPAG = NVL(PCDESCONTO.CODPLPAG, p_codplpag) ) >= NVL(p_numdias,0) ) )
               OR ( ( NVL( APENASPLPAGMAX, 'S' ) = 'S' ) AND ( ( NVL(CODPLPAG, p_codplpag) = p_codplpag ) ) ) )
           AND ((classevenda = p_classevenda) OR (classevenda IS NULL))
           AND ((pcdesconto.areaatuacao = vsareaatuacao) OR
               (pcdesconto.areaatuacao is null))
           AND ((pcdesconto.codfilial  = p_codfilial ) or (pcdesconto.codfilial is null ))
           AND ((pcdesconto.codrede  = vncodrede) or (pcdesconto.codrede is null))
           AND ((pcdesconto.codmarca  = vncodmarca) or (pcdesconto.codmarca is null))
           AND ((pcdesconto.codlinhaprod  = vncodlinhaprod) or (pcdesconto.codlinhaprod is null))
           -- HIS.01889.2017
           AND ((PCDESCONTO.TIPOGRUPOREST IS NULL) OR
                (PCDESCONTO.CODGRUPOREST  = (SELECT PCGRUPOSCAMPANHAI.CODGRUPO
                                              FROM PCGRUPOSCAMPANHAI
                                             WHERE PCGRUPOSCAMPANHAI.DTEXCLUSAO IS NULL
                                               AND PCGRUPOSCAMPANHAI.CODGRUPO = PCDESCONTO.CODGRUPOREST
                                               AND PCGRUPOSCAMPANHAI.CODITEM  = DECODE(PCDESCONTO.TIPOGRUPOREST,'CL',p_codcli,
                                                                                                                'GR',p_codusur,
                                                                                                                'GP',p_codprod))))
           --AND (nvl(percdesc, 0) > 0) -- somente desconto
           --AND ((nvl(pcdesconto.tipofv,'TL') = p_tipofv ))
           AND (nvl(nvl(pcdesconto.tipovenda,pcdesconto.tipofv),'TL') = NVL(p_tipofv,'TL')) -- DDMEDICA-641 - CrossDocking ou Avaria (p_tipofv = PC ou PA)
           AND ((pcdesconto.codcondicaovenda = p_codcondicaovenda)or (pcdesconto.codcondicaovenda is null))
           AND case when pcdesconto.aplicadescsimplesnacional in ('S', 'N') then pcdesconto.aplicadescsimplesnacional else nvl(vssimplesnacional, 'T') end = nvl(vssimplesnacional, 'T')
         ORDER BY PRIORIDADE ASC,
                  pcdesconto.percdesc DESC;

/*
      CURSOR c_comrede(vncodepto IN NUMBER, vncodsec IN NUMBER, vncodcategoria IN NUMBER, vncodfornec IN NUMBER, vncodsupervisor IN NUMBER, vncodatv1 IN NUMBER, vncodpraca IN NUMBER, vncodcliprinc IN NUMBER, vsaplicadesconto IN VARCHAR2, vsareaatuacao IN VARCHAR2, vssimplesnacional IN varchar2,
                       vncodrede IN number , vncodmarca IN number, vncodlinhaprod IN NUMBER) IS
        SELECT percdesc,nvl(percdescfin,0) percdescfin,
               nvl(basecreddebrca, 'N') basecreddebrca,
               dtfim,
               nvl(creditasobrepolitica, 'S') creditasobrepolitica,
               pcdesconto.dtinicio,
               pcdesconto.coddesconto,
               pcdesconto.alteraptabela,
               pcdesconto.prioritaria,
               pcdesconto.questionausoprioritaria,
               pcdesconto.codpromocaomed,
               pcdesconto.consideracalcgiromedic,
               pcdesconto.concedermaiorcomissreg,
               pcdesconto.aplicadesconto,
               pcdesconto.participacomissgarantida,
               CASE WHEN (NVL(pi_nTipoChamada,0) <> 2)         THEN 1 -->> Garantir que Politicas de Desconto não usem a Regra de Prioridade no ORDER BY
                    WHEN (pcdesconto.codprod      IS NOT NULL) THEN 1
                    WHEN (pcdesconto.codfornec    IS NOT NULL) THEN 2
                    WHEN (pcdesconto.codmarca     IS NOT NULL) THEN 3
                    WHEN (pcdesconto.codcategoria IS NOT NULL) THEN 4
                    WHEN (pcdesconto.codsec       IS NOT NULL) THEN 5
                    WHEN (pcdesconto.codlinhaprod IS NOT NULL) THEN 6
                    WHEN (pcdesconto.codepto      IS NOT NULL) THEN 7
                    ELSE 8 END PRIORIDADE,
               pcdesconto.iniciointervalopromocaomed,
               pcdesconto.fimintervalopromocaomed,
               pcdesconto.precofixopromocaomed,
               nvl(pcdesconto.PERCDESCBASERCA,0) PERCDESCBASERCA,
               nvl(pcdesconto.PERCBONIFICMERC,0) PERCBONIFICMERC,
               pcdesconto.qtini,
               pcdesconto.qtfim,
               pcdesconto.percmarkupmed,
               PERMITIRAUMENTARQTDEKITMED, -- Não pode ter NVL aqui pra fazer depois com a PCPROMOCAOMED.PERMITIRAUMENTARQTDEKIT depois
               NVL(pcdesconto.PROMOCAOMEDOBRIGATORIO,'S') PROMOCAOMEDOBRIGATORIO, -- NVL para "S" para garantir que no kit criado antes dessa customização não permita excluir o item na 2316
               pcdesconto.numlote,
               pcdesconto.codigointegracaowms
          FROM pcdesconto
         WHERE codcli = vncodcliprinc
           AND p_data BETWEEN dtinicio AND dtfim
           AND nvl(utilizadescrede, 'N') = 'S'
           AND ((codepto = vncodepto) OR (codepto IS NULL))
           AND ((codsec = vncodsec) OR (codsec IS NULL))
           AND ((codcategoria = vncodcategoria) OR (codcategoria IS NULL))
           AND ((codprod = p_codprod) OR (codprod IS NULL))
           AND ((codusur = p_codusur) OR (codusur IS NULL))
           AND ((codsupervisor = vncodsupervisor) OR (codsupervisor IS NULL))
           AND ((codfornec = vncodfornec) OR (codfornec IS NULL))
           AND ((numregiao = p_numregiao) OR (numregiao IS NULL))
           AND ((codativ = vncodatv1) OR (codativ IS NULL))
           AND ((origemped = p_origempedido) OR (nvl(origemped, 'O') = 'O'))
           AND ((codpraca = vncodpraca) OR (codpraca IS NULL))
           --AND ((codplpag = p_codplpag) OR (codplpag IS NULL))
           AND ( ( ( NVL( APENASPLPAGMAX, 'S' ) = 'N' ) AND ( ( SELECT NVL(PCPLPAG.NUMDIAS,0) FROM PCPLPAG WHERE CODPLPAG = NVL(PCDESCONTO.CODPLPAG, p_codplpag) ) >= NVL(p_numdias,0) ) )
               OR ( ( NVL( APENASPLPAGMAX, 'S' ) = 'S' ) AND ( ( NVL(CODPLPAG, p_codplpag) = p_codplpag ) ) ) )
           AND ((classevenda = p_classevenda) OR (classevenda IS NULL))
           AND ((pcdesconto.areaatuacao = vsareaatuacao) OR
               (pcdesconto.areaatuacao is null))
           --AND (nvl(percdesc, 0) > 0) --somente desconto
           AND ((pcdesconto.codfilial  = p_codfilial ) or (codfilial is null ))
           AND ((pcdesconto.codrede  = vncodrede) or (pcdesconto.codrede is null))
           AND ((pcdesconto.codmarca  = vncodmarca) or (pcdesconto.codmarca is null))
           AND ((pcdesconto.codlinhaprod  = vncodlinhaprod) or (pcdesconto.codlinhaprod is null))
           -- HIS.01889.2017
           AND ((PCDESCONTO.TIPOGRUPOREST IS NULL) OR
                (PCDESCONTO.TIPOGRUPOREST = 'GC' ) OR -->> Colocado para não deixar de trazer os registros com Filtro de Grupo de Cliente
                (PCDESCONTO.TIPOGRUPOREST = 'GR' ) OR  -->> Colocado para não deixar de trazer os registros com Filtro de Grupo de Cliente
                (PCDESCONTO.CODGRUPOREST  = (SELECT PCGRUPOSCAMPANHAI.CODGRUPO
                                              FROM PCGRUPOSCAMPANHAI
                                             WHERE PCGRUPOSCAMPANHAI.DTEXCLUSAO IS NULL
                                               AND PCGRUPOSCAMPANHAI.CODGRUPO = PCDESCONTO.CODGRUPOREST
                                               AND PCGRUPOSCAMPANHAI.CODITEM  = DECODE(PCDESCONTO.TIPOGRUPOREST,'CL',p_codcli,
                                                                                                                'GR',p_codusur,
                                                                                                                'GP',p_codprod))))
           --AND ((NVL(pcdesconto.tipofv,'TL') = p_tipofv ) )
           AND (nvl(nvl(pcdesconto.tipovenda,pcdesconto.tipofv),'TL') = NVL(p_tipofv,'TL')) -- DDMEDICA-641 - CrossDocking ou Avaria (p_tipofv = PC ou PA)
           AND ((pcdesconto.codcondicaovenda = p_codcondicaovenda)or (pcdesconto.codcondicaovenda is null))
           AND case when pcdesconto.aplicadescsimplesnacional in ('S', 'N') then pcdesconto.aplicadescsimplesnacional else nvl(vssimplesnacional, 'T') end = nvl(vssimplesnacional, 'T')
           ORDER BY PRIORIDADE ASC,
                    pcdesconto.percdesc DESC;
*/
      vbresult             BOOLEAN;
      vntempperdesc        NUMBER;
      vstempbasecreddebrca VARCHAR2(2);
      vnpercdesc           NUMBER;
      vsbasecreddebrca     VARCHAR2(2);

      --Dados do Cliente
      vncodcliprinc NUMBER;
      vncodatv1     NUMBER;
      vncodpraca    NUMBER;
      --Dados do RCA
      vncodsupervisor NUMBER;
      --Dados do Produto}
      vncodfornec                NUMBER;
      vncodepto                  NUMBER;
      vncodsec                   NUMBER;
      vncodcategoria             NUMBER;
      vncodsubcategoria          NUMBER;
      vicont                     NUMBER;
      vicont2                    NUMBER;
      vicont3                    NUMBER;
      vicont4                    NUMBER;
      vncustorep                 NUMBER;
      vncustorepzfm              NUMBER;
      vsaplicadesconto           VARCHAR2(1);
      vscreditasobrepolitica     VARCHAR2(1);
      vstempcreditasobrepolitica VARCHAR2(1);
      vsareaatuacao              pcusuari.areaatuacao%type;
      vnpercbaserca              number;
      vntemppbaserca             number;
      vssimplesnacional          pcclient.simplesnacional%type;
      vsalteraptabela            varchar2(1);
      vstempalteraptabela        varchar2(1);
      vntempprecofixopromocaomed NUMBER;
      vntempvldesccmvpromocaomed NUMBER;      -- DDMEDICA-5009
      vntempnumverba             NUMBER;      -- DDMEDICA-5009
      vntempvalorcotanumverba    NUMBER;      -- DDMEDICA-5009
      vvtempsemverbavldesccmv    VARCHAR2(1); -- DDMEDICA-5009
      vncodrede                  pcclient.codrede%type;
      vncodmarca                 pcprodut.codmarca%type;
      vncodlinhaprod             pcprodut.codlinhaprod%type;
      vstempprioritaria          varchar2(1);
      vsprioritaria              varchar2(1);
      vsusaprioritaria           varchar2(1);
      vnPerDescfin               number;
      vntempperdescfin           number;
      vsregiaozfm                varchar2(1);
      vnPrecoTabelaMarkup        number;
      vnPrecoVendaMarkup         number;

      -- Dados da Promoção
      vvACHOUPROMOCAO                VARCHAR2(1);
      vvTIPOPOLITICA                 PCMED_SELPROMOCAO.TIPOPOLITICA%TYPE;
      vvDESCRICAORESUMIDA            PCMED_SELPROMOCAO.DESCRICAORESUMIDA%TYPE;
      vvDESCRICAODETALHADA           PCMED_SELPROMOCAO.DESCRICAODETALHADA%TYPE;
      vdDATAINICIAL                  PCMED_SELPROMOCAO.DATAINICIAL%TYPE;
      vdDATAFINAL                    PCMED_SELPROMOCAO.DATAFINAL%TYPE;
      vvAPLICADESCONTO               PCMED_SELPROMOCAO.APLICADESCONTO%TYPE;
      vvALTERADESCONTO               PCMED_SELPROMOCAO.ALTERADESCONTO%TYPE;
      vvENCARTEFECHADO               PCMED_SELPROMOCAO.ENCARTEFECHADO%TYPE;
      vvPRIORIZACOMISSAO             PCMED_SELPROMOCAO.PRIORIZACOMISSAO%TYPE;
      vvVALIDARINTERVALOVALIDADEPROD PCMED_SELPROMOCAO.VALIDARINTERVALOVALIDADEPROD%TYPE;
      vvDTINICIOPROMOLOTE            PCMED_SELPROMOCAO.DTINICIOPROMOLOTE%TYPE;
      vvDTFIMPROMOLOTE               PCMED_SELPROMOCAO.DTFIMPROMOLOTE%TYPE;
      vvTIPOPROMOCAO                 PCMED_SELPROMOCAO.TIPOPROMOCAO%TYPE;
      vvPARTICIPACOMISSGARANTIDA     PCMED_SELPROMOCAO.PARTICIPACOMISSGARANTIDA%TYPE;
      vvBLOQUEIO                     VARCHAR2(1);
      vvPROMOESPECIAL                VARCHAR2(1);
      vvUTILIZAPERCDESCBASERCA       PCMED_SELPROMOCAO.UTILIZAPERCDESCBASERCA%TYPE;
      vvPERMITIRAUMENTARQTDEKIT      PCMED_SELPROMOCAO.PERMITIRAUMENTARQTDEKIT%TYPE;
      vORIGEMPRECO                   PCMED_SELPROMOCAO.ORIGEMPRECO%TYPE;

      -- Mensagem Retorno PMC - 0.130545.2016
      vvUfCliente                    PCCLIENT.ESTENT%TYPE;
      vnPrecoMaxConsum               NUMBER;
      vnPrecoFabrica                 NUMBER;
      vvMensagemRetornoPMC           VARCHAR2(2000);

    BEGIN
      vbresult      := FALSE;
      vnpercdesc    := 0;
      vnperdescfin  := 0;
      vnpercbaserca := 0;
      --    vnpercdesc_cr          := 0;
      vsbasecreddebrca       := 'N';
      vscreditasobrepolitica := 'S';
      vsalteraptabela        := 'N';
      vsprioritaria          := 'N';
      vsusaprioritaria       := p_usaprioritaria;

      --Buscar dados do cliente
      SELECT COUNT(*) INTO vicont FROM pcclient WHERE codcli = p_codcli;
      IF vicont <> 0 THEN
        SELECT nvl(codcliprinc, codcli) codcliprinc,
               codatv1,
               codpraca,
               pcclient.simplesnacional,
               pcclient.codrede
          INTO vncodcliprinc, vncodatv1, vncodpraca, vssimplesnacional,vncodrede
          FROM pcclient
         WHERE codcli = p_codcli;

        --Buscar dados do RCA
        SELECT COUNT(*) INTO vicont2 FROM pcusuari WHERE codusur = p_codusur;
        IF vicont2 <> 0 THEN
          SELECT codsupervisor, pcusuari.areaatuacao
            INTO vncodsupervisor, vsareaatuacao
            FROM pcusuari
           WHERE codusur = p_codusur;

          --Buscar dados do produto
          SELECT COUNT(*)
            INTO vicont3
            FROM pcprodut
           WHERE codprod = p_codprod;

          IF vicont3 <> 0 THEN
            SELECT codfornec,
                   codepto,
                   codsec,
                   codcategoria,
                   codsubcategoria,
                   codmarca,
                   codlinhaprod,
                   custorep,
                   nvl(vncustorepzfm, custorep)
              INTO vncodfornec,
                   vncodepto,
                   vncodsec,
                   vncodcategoria,
                   vncodsubcategoria,
                   vncodmarca,
                   vncodlinhaprod,
                   vncustorep,
                   vncustorepzfm
              FROM pcprodut
             WHERE codprod = p_codprod;


            --Buscar dados do região
            SELECT COUNT(*)
              INTO vicont4
              FROM pcregiao
             WHERE numregiao = p_numregiao;

            IF vicont4 <> 0 THEN

              SELECT nvl(regiaozfm,'N')
                INTO vsregiaozfm
                FROM pcregiao
               WHERE numregiao = p_numregiao;

                --Verificação de Políticas de Descontos}
                FOR reg_descontos IN c_principal(vncodepto,
                                             vncodsec,
                                             vncodcategoria,
                                             vncodfornec,
                                             vncodsupervisor,
                                             vncodatv1,
                                             vncodpraca,
                                             vsaplicadesconto,
                                             vsareaatuacao,
                                             vssimplesnacional,
                                             vncodrede,
                                             vncodmarca,
                                             vncodlinhaprod,
                                             vncodcliprinc) LOOP

                  -- Se Chamado para Obter as Politicas de Desconto / Quantidade no Operador Logístico ou Venda Normal
                  IF ((pi_nTipoChamada = 1) AND (reg_descontos.codpromocaomed IS NULL) AND (NVL(reg_descontos.aplicadesconto,'N') = 'S')) OR  --somente descontos automaticos se Operador Logístico
                     ((pi_nTipoChamada = 4) AND (reg_descontos.codpromocaomed IS NULL)) THEN                                                --todos os descontos automaticos se Venda Normal


                    vbresult                   := TRUE;
                    vntempperdesc              := reg_descontos.percdesc;
                    vntempperdescfin           := reg_descontos.percdescfin;
                    vntemppbaserca             := reg_descontos.percdesc;
                    vstempbasecreddebrca       := reg_descontos.basecreddebrca;
                    vstempcreditasobrepolitica := reg_descontos.creditasobrepolitica;
                    vstempalteraptabela        := reg_descontos.alteraptabela;
                    vstempprioritaria          := reg_descontos.prioritaria;

                    if vsprioritaria = 'N' then

                      if vstempprioritaria = 'S' then
                        --registro atual é de politica prioritaria

                        if vsusaprioritaria = 'S' then

                          vnpercdesc             := vntempperdesc;
                          vnperdescfin           := vntempperdescfin;
                          vsprioritaria          := vstempprioritaria;
                          vsalteraptabela        := vstempalteraptabela;

                          p_mensagem := to_char(reg_descontos.dtinicio,
                                                'dd/mm/yyyy') || ',' ||
                                        reg_descontos.coddesconto;

                                  if p_naousarautdebcredpoldesc = 'S' and vstempbasecreddebrca = 'S' then

                                      vsbasecreddebrca       := vstempbasecreddebrca;
                                      vnpercbaserca          := vntemppbaserca;
                                      vscreditasobrepolitica := vstempcreditasobrepolitica;

                              end if;

                        end if;

                      else
                        --registro atual não é de politica prioritaria

                        IF (vntempperdesc + vntempperdescfin) > (vnpercdesc + vnPerDescfin) THEN

                              vnpercdesc := vntempperdesc;
                              vnPerDescfin := vntempperdescfin;
                              vsprioritaria          := 'N';

                              vsalteraptabela        := vstempalteraptabela;

                              p_mensagem := to_char(reg_descontos.dtinicio,
                                                    'dd/mm/yyyy') || ',' ||
                                            reg_descontos.coddesconto;


                                  if p_naousarautdebcredpoldesc = 'S' and vstempbasecreddebrca = 'S' then

                                      vsbasecreddebrca       := vstempbasecreddebrca;
                                      vnpercbaserca          := vntemppbaserca;
                                      vscreditasobrepolitica := vstempcreditasobrepolitica;

                              end if;



                        END IF;

                              if p_naousarautdebcredpoldesc = 'S' and vstempbasecreddebrca = 'S' and
                                 vntemppbaserca > vnpercbaserca then

                                  vsbasecreddebrca       := vstempbasecreddebrca;
                                  vnpercbaserca          := vntemppbaserca;
                                  vscreditasobrepolitica := vstempcreditasobrepolitica;

                                  end if;

                      end if;

                    else
                      -- já tem uma politica prioritaria

                            IF (vntempperdesc + vntempperdescfin) > (vnpercdesc + vnPerDescfin) THEN

                              vnpercdesc             := vntempperdesc;
                              vnperdescfin           := vntempperdescfin;
                              vsprioritaria          := vstempprioritaria;
                              vsalteraptabela        := vstempalteraptabela;

                              p_mensagem := to_char(reg_descontos.dtinicio, 'dd/mm/yyyy') || ',' ||
                                            reg_descontos.coddesconto;

                                    if p_naousarautdebcredpoldesc = 'S' and vstempbasecreddebrca = 'S' then

                                      vsbasecreddebrca       := vstempbasecreddebrca;
                                      vnpercbaserca          := vntemppbaserca;
                                      vscreditasobrepolitica := vstempcreditasobrepolitica;

                                      end if;


                            END IF;

                    end if;

                    -- Se Chamado para Obter as Politicas de Desconto / Quantidade da Venda Normal
                    IF ((pi_nTipoChamada = 4) AND (reg_descontos.codpromocaomed IS NULL)) THEN
                      -- Se Desconto por Faixa de Quantidade
                      IF (reg_descontos.qtini > 0) THEN
                        -- Define o Tipo de Política - Desconto (mesmo sendo por faixa de quantidade)
                        vvTIPOPOLITICA       := 'D';
                        -- Define o Período
                        vdDATAINICIAL        := reg_descontos.dtinicio;
                        vdDATAFINAL          := reg_descontos.dtfim;
                        -- Define a Descrição Resumida e Detalhada
                        vvDESCRICAORESUMIDA  := 'Faixas de Desconto por Quantidade';
                        vvDESCRICAODETALHADA := 'Faixas de Desconto por Quantidade';
                        -- Insere Dados na Tabela Temporária
                        BEGIN
                          INSERT INTO PCMED_SELPROMOCAO
                                    ( CODPROMOCAOMED
                                    , CODDESCONTO
                                    , TIPOPOLITICA
                                    , DESCRICAORESUMIDA
                                    , DESCRICAODETALHADA
                                    , DATAINICIAL
                                    , DATAFINAL
                                    , APLICADESCONTO
                                    , PERCDESC
                                    , BASECREDDEBRCA
                                    , PERCDESCFIN
                                    , CREDITASOBREPOLITICA
                                    , ALTERAPTABELA
                                    , PRIORITARIA
                                    , PERCDESCRESTRICAO
                                    , CONSIDERACALCGIROMEDIC
                                    , CONCEDERMAIORCOMISSREG
                                    , ALTERADESCONTO
                                    , ENCARTEFECHADO
                                    , PRIORIZACOMISSAO
                                    , INICIOINTERVALO
                                    , FIMINTERVALO
                                    , PRECOFIXO
                                    , VALIDARINTERVALOVALIDADEPROD
                                    , DTINICIOPROMOLOTE
                                    , DTFIMPROMOLOTE
                                    , TIPOPROMOCAO
                                    , PARTICIPACOMISSGARANTIDA
                                    , UTILIZAPERCDESCBASERCA
                                    , PERMITIRAUMENTARQTDEKIT
                                    , PERCDESCBASERCA
                                    , ORIGEMPRECO
                                    , PERCBONIFICMERC
                                    , PROMOCAOMEDOBRIGATORIO )
                             VALUES ( -1  -->> -1 se Chamada 4
                                    , reg_descontos.coddesconto
                                    , vvTIPOPOLITICA
                                    , vvDESCRICAORESUMIDA
                                    , vvDESCRICAODETALHADA
                                    , vdDATAINICIAL
                                    , vdDATAFINAL
                                    , vvAPLICADESCONTO
                                    , reg_descontos.percdesc
                                    , reg_descontos.basecreddebrca
                                    , reg_descontos.percdescfin
                                    , reg_descontos.creditasobrepolitica
                                    , vstempalteraptabela
                                    , reg_descontos.prioritaria
                                    , reg_descontos.percdesc
                                    , reg_descontos.consideracalcgiromedic
                                    , reg_descontos.concedermaiorcomissreg
                                    , vvALTERADESCONTO
                                    , vvENCARTEFECHADO
                                    , vvPRIORIZACOMISSAO
                                    , reg_descontos.qtini
                                    , reg_descontos.qtfim
                                    , vntempprecofixopromocaomed
                                    , vvVALIDARINTERVALOVALIDADEPROD
                                    , vvDTINICIOPROMOLOTE
                                    , vvDTFIMPROMOLOTE
                                    , vvTIPOPROMOCAO
                                    , reg_descontos.participacomissgarantida
                                    , vvUTILIZAPERCDESCBASERCA
                                    , NVL(reg_descontos.PERMITIRAUMENTARQTDEKITMED,vvPERMITIRAUMENTARQTDEKIT)
                                    , reg_descontos.percdescbaserca
                                    , vORIGEMPRECO
                                    , reg_descontos.PERCBONIFICMERC
                                    , reg_descontos.PROMOCAOMEDOBRIGATORIO );
                        EXCEPTION
                          WHEN DUP_VAL_ON_INDEX THEN
                            NULL;
                        END;
                      END IF;
                    END IF;

                  -- Se Chamado para Obter as Promoção
                  ELSIF ((pi_nTipoChamada = 2) and (reg_descontos.codpromocaomed IS NOT NULL)) THEN

                    -- Se a Promoção do Cabeçalho do Pedido for de Encarte, só pode carregar Desconto da Própria Promoção
                    IF ( (F_PROMOCAO_ENCARTE(pi_nCodPromocaoMed) AND (pi_nCodPromocaoMed = reg_descontos.codpromocaomed)) OR
                         (NOT F_PROMOCAO_ENCARTE(pi_nCodPromocaoMed)) ) THEN
                    -- Se a Promoção a ser Carregada for de Encarte, somente pode ser igual ao Código da Promoção de Encarte do Cabeçalho do Pedido
                    IF ( (F_PROMOCAO_ENCARTE(reg_descontos.codpromocaomed) AND (reg_descontos.codpromocaomed = pi_nCodPromocaoMed)) OR
                         (NOT F_PROMOCAO_ENCARTE(reg_descontos.codpromocaomed)) ) THEN
                    -- HIS.01889.2017 - A partir da Campanha a Promoção de Cabeçalho virou de Item
                    -- Se a Promoção a ser Carregada for de Cabeçalho de Pedido, somente pode ser igual ao Código da Promoção do Cabeçalho do Pedido
                    --IF ( (F_PROMOCAO_CABECALHO(reg_semrede.codpromocaomed) AND (reg_semrede.codpromocaomed = pi_nCodPromocaoMed)) OR
                    --     (NOT F_PROMOCAO_CABECALHO(reg_semrede.codpromocaomed)) ) THEN
                    -- Se a Promoção a ser Carregada for de KIT, somente pode ser igual ao Código da Promoção do Item do Pedido
                    IF ( (F_PROMOCAO_KIT(reg_descontos.codpromocaomed) AND (reg_descontos.codpromocaomed = pi_nCodPromocaoItem)) OR
                         (NOT F_PROMOCAO_KIT(reg_descontos.codpromocaomed)) ) THEN
                    -- Se a Promoção a ser Carregada for de CASADINHA como Produto PRINCIPAL, somente pode ser o Produto cadastrado como Principal - HIS.01152.2015
                    IF ( (F_PROMOCAO_CASADINHA(reg_descontos.codpromocaomed, p_codprod) = 'P') OR
                         (F_PROMOCAO_CASADINHA(reg_descontos.codpromocaomed, p_codprod) = 'N') ) THEN

                      -- Pesquisa Dados da Promoção
                      P_OBTEM_DADOS_PROMOCAO(reg_descontos.codpromocaomed,
                                             vvACHOUPROMOCAO,
                                             vvTIPOPOLITICA,
                                             vvDESCRICAORESUMIDA,
                                             vvDESCRICAODETALHADA,
                                             vdDATAINICIAL,
                                             vdDATAFINAL,
                                             vvAPLICADESCONTO,
                                             vvALTERADESCONTO,
                                             vvENCARTEFECHADO,
                                             vvPRIORIZACOMISSAO,
                                             vvVALIDARINTERVALOVALIDADEPROD,
                                             vvDTINICIOPROMOLOTE,
                                             vvDTFIMPROMOLOTE,
                                             vvTIPOPROMOCAO,
                                             vvBLOQUEIO,
                                             vvPROMOESPECIAL,
                                             vvUTILIZAPERCDESCBASERCA,
                                             vvPERMITIRAUMENTARQTDEKIT,
                                             vORIGEMPRECO);


                      -- Se Aceita a Promoção conforme Prioridade e/ou bloqueio
                      IF (FACEITA_PROMOCAO_PRIORIDADE(reg_descontos.codpromocaomed,
                                                      reg_descontos.prioridade,
                                                      vvBLOQUEIO,
                                                      vvPROMOESPECIAL,
                                                      pi_vVisualizarPromoBloq,
                                                      pi_vVisualizarPromoEsp,
                                                      --
                                                      p_codfilial,
                                                      p_codcli,
                                                      p_numregiao,
                                                      p_codusur,
                                                      p_codplpag,
                                                      p_codcondicaovenda,
                                                      p_origempedido,
                                                      p_tipofv,
                                                      p_data,
                                                      vvTIPOPROMOCAO -- HIS.01889.2017
                                                      )) THEN

                        -- Apaga registro atual do Código da Promoção (caso exista registro de menor prioridade)
                        --DELETE FROM PCMED_SELPROMOCAO
                         --WHERE (CODPROMOCAOMED = reg_semrede.codpromocaomed);

                        -- Iniciando Variável com o valor de Preço Fixo da PCDESCONTO
                        vntempprecofixopromocaomed := reg_descontos.PRECOFIXOPROMOCAOMED;
                        vstempalteraptabela        := reg_descontos.alteraptabela;

                        -- Inicializando Variável com o Valor da Verba para Rebaixa de CMV da Promoção da PCDESCONTO - DDMEDICA-5009
                        vntempvldesccmvpromocaomed := reg_descontos.VLDESCCMVPROMOCAOMED;
                        -- Obter Verba Relacionada com o Valor da Verba para Rebaixa de CMV da Promoção da PCDESCONTO - DDMEDICA-5009
                        P_OBTER_VERBA_PROMOCAO(reg_descontos.codpromocaomed,
                                               vncodfornec,
                                               vntempvldesccmvpromocaomed,
                                               vntempnumverba,
                                               vntempvalorcotanumverba,
                                               vvtempsemverbavldesccmv);

                        -- Se for Preço Fábrica verificar se é zona franca
                        vnPrecoTabelaMarkup := pi_npTabela;
                        if vORIGEMPRECO = 'F' then
                          -- DDVENDAS-33920 - Se o Preço Fábrica for passado no parâmetro
                          IF (NVL(pi_nPrecoFabrica,0) > 0) THEN
                            -- Pega o Preço Fábrica do Parâmetro
                            vnPrecoFabrica := NVL(pi_nPrecoFabrica,0);
                          ELSE
                            BEGIN
                              SELECT PCCLIENT.ESTENT
                                INTO vvUfCliente
                                FROM PCCLIENT
                               WHERE (CODCLI = pi_nCodCli);
                            EXCEPTION
                              WHEN NO_DATA_FOUND THEN
                                vvUfCliente := NULL;
                            END;
                            -- OBTEM PMC e PREÇO FÁBRICA - 0.130545.2016
                            PKG_MEDICAMENTOS.P_OBTEM_PMC_PRODUTO(pi_vCodFilial,
                                                                 pi_nCodProd,
                                                                 vvUfCliente,
                                                                 pi_nNumRegiao,
                                                                 vnPrecoMaxConsum,
                                                                 vnPrecoFabrica,
                                                                 vvMensagemRetornoPMC);
                          END IF;
                          IF (vnPrecoFabrica > 0) THEN
                            vntempprecofixopromocaomed := vnPrecoFabrica;
                            vstempalteraptabela        := 'S';
                            vnPrecoTabelaMarkup       := vntempprecofixopromocaomed;
                          END IF;
                        end if;

                        --- Processo de Markup
                        vnPercDesc  := reg_descontos.percdesc;
                        IF (F_PROMOCAO_MARKUP(reg_descontos.codpromocaomed)) THEN
                          IF NVL(reg_descontos.percmarkupmed,0) = 0 THEN
                              vnPercDesc            := 0;
                          ELSE
                              IF (NVL(pi_nCustoFin,0) = 0) THEN
                                -- 0.018397.2016 - Não carregar desconto da promoção markup com custo zero
                                vnPercDesc            := 0;
                              ELSE
                                vnPrecoVendaMarkup   := pi_nCustoFin * (1+(NVL(reg_descontos.percmarkupmed,0) * 0.01));
                                vnPercDesc           := (1-(vnPrecoVendaMarkup/vnPrecoTabelaMarkup))*100;
                              END IF;
                          END IF;
                        END IF;
                        --- Processo de Markup com Preço Fixo - DDMEDICA-6841
                        IF (F_PROMOCAO_MARKUP_PRECOFIXO(reg_descontos.codpromocaomed)) THEN
                          IF (NVL(vnPercDesc,0) = 0) THEN
                            vntempprecofixopromocaomed := NVL(vnPrecoTabelaMarkup,0);
                          ELSE                         
                            vntempprecofixopromocaomed := NVL(vnPrecoVendaMarkup,0);
                          END IF;
                          -- Altera Preço Tabela
                          vstempalteraptabela := 'S';
                          -- Não tem desconto (já vai aplicado no Preço Fixo)
                          vnPercDesc := 0;
                        END IF;

                        -- Validade do Lote
                        IF (reg_descontos.NUMLOTE IS NOT NULL) THEN
                          BEGIN
                            SELECT DTVALIDADE
                              INTO vdValidadeLote
                              FROM PCLOTE
                             WHERE (CODPROD = pi_nCodProd)
                               AND (NUMLOTE = reg_descontos.NUMLOTE)
                               AND (QT      > 0)
                               AND (ROWNUM  = 1);
                          EXCEPTION
                            WHEN NO_DATA_FOUND THEN
                              vdValidadeLote := NULL;
                          END;
                        ELSE
                          vdValidadeLote := NULL;
                        END IF;
                        
                        -- Regra de Alteração do Desconto/Preco
                        IF (NVL(reg_descontos.regraalterardesconto,'P') = 'P') THEN
                          vvRegraAlterarDesconto := vvALTERADESCONTO;
                        ELSE
                          vvRegraAlterarDesconto := reg_descontos.regraalterardesconto;
                        END IF;

                        -- Insere Dados na Tabela Temporária
                        BEGIN
                          INSERT INTO PCMED_SELPROMOCAO
                                    ( CODPROMOCAOMED
                                    , CODDESCONTO
                                    , TIPOPOLITICA
                                    , DESCRICAORESUMIDA
                                    , DESCRICAODETALHADA
                                    , DATAINICIAL
                                    , DATAFINAL
                                    , APLICADESCONTO
                                    , PERCDESC
                                    , BASECREDDEBRCA
                                    , PERCDESCFIN
                                    , CREDITASOBREPOLITICA
                                    , ALTERAPTABELA
                                    , PRIORITARIA
                                    , PERCDESCRESTRICAO
                                    , CONSIDERACALCGIROMEDIC
                                    , CONCEDERMAIORCOMISSREG
                                    , ALTERADESCONTO
                                    , ENCARTEFECHADO
                                    , PRIORIZACOMISSAO
                                    , INICIOINTERVALO
                                    , FIMINTERVALO
                                    , PRECOFIXO
                                    , VALIDARINTERVALOVALIDADEPROD
                                    , DTINICIOPROMOLOTE
                                    , DTFIMPROMOLOTE
                                    , TIPOPROMOCAO
                                    , PARTICIPACOMISSGARANTIDA
                                    , UTILIZAPERCDESCBASERCA
                                    , PERMITIRAUMENTARQTDEKIT
                                    , PERCDESCBASERCA
                                    , ORIGEMPRECO
                                    , PERCBONIFICMERC
                                    , PERCMARKUPMED
                                    , PROMOCAOMEDOBRIGATORIO
                                    , NUMLOTE
                                    , CODIGOINTEGRACAOWMS
                                    , VALIDADELOTE
                                    , VLDESCCMVPROMOCAOMED -- DDMEDICA-5009
                                    , NUMVERBA             -- DDMEDICA-5009
                                    , VALORCOTANUMVERBA    -- DDMEDICA-5009
                                    , SEMVERBAVLDESCCMV    -- DDMEDICA-5009   
                                    )
                             VALUES ( reg_descontos.codpromocaomed
                                    , reg_descontos.coddesconto
                                    , vvTIPOPOLITICA
                                    , vvDESCRICAORESUMIDA
                                    , vvDESCRICAODETALHADA
                                    , vdDATAINICIAL
                                    , vdDATAFINAL
                                    , vvAPLICADESCONTO
                                    , vnPercDesc
                                    , reg_descontos.basecreddebrca
                                    , reg_descontos.percdescfin
                                    , reg_descontos.creditasobrepolitica
                                    , vstempalteraptabela
                                    , reg_descontos.prioritaria
                                    , reg_descontos.percdesc
                                    , reg_descontos.consideracalcgiromedic
                                    , reg_descontos.concedermaiorcomissreg
                                    , vvRegraAlterarDesconto
                                    , vvENCARTEFECHADO
                                    , vvPRIORIZACOMISSAO
                                    , reg_descontos.INICIOINTERVALOPROMOCAOMED
                                    , reg_descontos.FIMINTERVALOPROMOCAOMED
                                    , vntempprecofixopromocaomed
                                    , vvVALIDARINTERVALOVALIDADEPROD
                                    , vvDTINICIOPROMOLOTE
                                    , vvDTFIMPROMOLOTE
                                    , vvTIPOPROMOCAO
                                    , reg_descontos.participacomissgarantida
                                    , vvUTILIZAPERCDESCBASERCA
                                    , NVL(reg_descontos.PERMITIRAUMENTARQTDEKITMED,vvPERMITIRAUMENTARQTDEKIT)
                                    , reg_descontos.percdescbaserca
                                    , vORIGEMPRECO
                                    , reg_descontos.PERCBONIFICMERC
                                    , reg_descontos.percmarkupmed
                                    , reg_descontos.PROMOCAOMEDOBRIGATORIO
                                    , reg_descontos.NUMLOTE
                                    , reg_descontos.CODIGOINTEGRACAOWMS
                                    , vdValidadeLote
                                    , vntempvldesccmvpromocaomed -- DDMEDICA-5009
                                    , vntempnumverba             -- DDMEDICA-5009
                                    , vntempvalorcotanumverba    -- DDMEDICA-5009
                                    , vvtempsemverbavldesccmv    -- DDMEDICA-5009
                                    );
                        EXCEPTION
                          WHEN DUP_VAL_ON_INDEX THEN
                            NULL;
                        END;

                      END IF; -- Fim Condição Se Aceita a Promoção conforme Prioridade

                    END IF; -- Fim Condição Verifica Promoção Casadinha
                    END IF; -- Fim Condição Verifica Promoção de KIT
                    -- HIS.01889.2017 - A partir da Campanha a Promoção de Cabeçalho virou de Item
                    --END IF; -- Fim Condição Verifica Promoção de Cabeçalho de Pedido
                    END IF; -- Fim Condição Verifica Promoção Encarte
                    END IF; -- Fim Condição Verifica Promoção Encarte

                  END IF; -- Fim Condição Tipo Chamada

                END LOOP;
/*
                FOR reg_comrede IN c_comrede(vncodepto,
                                             vncodsec,
                                             vncodcategoria,
                                             vncodfornec,
                                             vncodsupervisor,
                                             vncodatv1,
                                             vncodpraca,
                                             vncodcliprinc,
                                             vsaplicadesconto,
                                             vsareaatuacao,
                                             vssimplesnacional,
                                             vncodrede,
                                             vncodmarca,
                                             vncodlinhaprod) LOOP

                  -- Se Chamado para Obter as Politicas de Desconto / Quantidade no Operador Logístico ou Venda NormaL
                  IF ((pi_nTipoChamada = 1) AND (reg_comrede.codpromocaomed IS NULL) AND (NVL(reg_comrede.aplicadesconto,'N') = 'S')) OR  --somente descontos automaticos se Operador Logístico
                     ((pi_nTipoChamada = 4) AND (reg_comrede.codpromocaomed IS NULL)) THEN                                                --todos os descontos automaticos se Venda Normal

                    vbresult                   := TRUE;
                    vntempperdesc              := reg_comrede.percdesc;
                    vntempperdescfin           := reg_comrede.percdescfin;
                    vntemppbaserca             := reg_comrede.percdesc;
                    vstempbasecreddebrca       := reg_comrede.basecreddebrca;
                    vstempcreditasobrepolitica := reg_comrede.creditasobrepolitica;
                    vstempalteraptabela        := reg_comrede.alteraptabela;

                    vstempprioritaria          := reg_comrede.prioritaria;


                    if vsprioritaria = 'N' then

                      if vstempprioritaria = 'S' then
                        --registro atual é de politica prioritaria

                        if vsusaprioritaria = 'S' then

                          vnpercdesc             := vntempperdesc;
                          vnPerDescfin           := vntempperdescfin;
                          vsprioritaria          := vstempprioritaria;
                          vsalteraptabela        := vstempalteraptabela;

                          p_mensagem := to_char(reg_comrede.dtinicio,
                                                'dd/mm/yyyy') || ',' ||
                                        reg_comrede.coddesconto;


                                  if p_naousarautdebcredpoldesc = 'S' and vstempbasecreddebrca = 'S' then

                                      vsbasecreddebrca       := vstempbasecreddebrca;
                                      vnpercbaserca          := vntemppbaserca;
                                      vscreditasobrepolitica := vstempcreditasobrepolitica;

                              end if;


                        end if;

                      else
                        --registro atual não é de politica prioritaria

                        IF (vntempperdesc + vntempperdescfin) > (vnpercdesc + vnPerDescfin) THEN

                              vnpercdesc := vntempperdesc;
                              vnPerDescfin := vntempperdescfin;
                              vsprioritaria          := 'N';
                              vsalteraptabela        := vstempalteraptabela;

                              p_mensagem := to_char(reg_comrede.dtinicio,
                                                    'dd/mm/yyyy') || ',' ||
                                            reg_comrede.coddesconto;

                                  if p_naousarautdebcredpoldesc = 'S' and vstempbasecreddebrca = 'S' then

                                      vsbasecreddebrca       := vstempbasecreddebrca;
                                      vnpercbaserca          := vntemppbaserca;
                                      vscreditasobrepolitica := vstempcreditasobrepolitica;

                              end if;


                        END IF;

                              if p_naousarautdebcredpoldesc = 'S' and vstempbasecreddebrca = 'S' and
                                 vntemppbaserca > vnpercbaserca then

                                  vsbasecreddebrca       := vstempbasecreddebrca;
                                  vnpercbaserca          := vntemppbaserca;
                                  vscreditasobrepolitica := vstempcreditasobrepolitica;

                                  end if;

                      end if;

                    else
                      -- já tem uma politica prioritaria

                            IF (vntempperdesc + vntempperdescfin) > (vnpercdesc + vnPerDescfin) THEN

                              vnpercdesc             := vntempperdesc;
                              vnPerDesc              := vntempperdescfin;
                              vsprioritaria          := vstempprioritaria;
                              vsalteraptabela        := vstempalteraptabela;

                              p_mensagem := to_char(reg_comrede.dtinicio, 'dd/mm/yyyy') || ',' ||
                                            reg_comrede.coddesconto;

                                    if p_naousarautdebcredpoldesc = 'S' and vstempbasecreddebrca = 'S' then

                                      vsbasecreddebrca       := vstempbasecreddebrca;
                                      vnpercbaserca          := vntemppbaserca;
                                      vscreditasobrepolitica := vstempcreditasobrepolitica;

                                      end if;

                            END IF;

                    end if;

                    -- Se Chamado para Obter as Politicas de Desconto / Quantidade da Venda Normal
                    IF ((pi_nTipoChamada = 4) AND (reg_comrede.codpromocaomed IS NULL)) THEN
                      -- Se Desconto por Faixa de Quantidade
                      IF (reg_comrede.qtini > 0) THEN
                        -- Define o Tipo de Política Desconto (mesmo sendo por faixa de quantidade por ser 561)
                        vvTIPOPOLITICA       := 'D';
                        -- Define o Período
                        vdDATAINICIAL        := reg_comrede.dtinicio;
                        vdDATAFINAL          := reg_comrede.dtfim;
                        -- Define a Descrição Resumida e Detalhada
                        vvDESCRICAORESUMIDA  := 'Faixas de Desconto por Quantidade';
                        vvDESCRICAODETALHADA := 'Faixas de Desconto por Quantidade';
                        -- Insere Dados na Tabela Temporária
                        BEGIN
                          INSERT INTO PCMED_SELPROMOCAO
                                    ( CODPROMOCAOMED
                                    , CODDESCONTO
                                    , TIPOPOLITICA
                                    , DESCRICAORESUMIDA
                                    , DESCRICAODETALHADA
                                    , DATAINICIAL
                                    , DATAFINAL
                                    , APLICADESCONTO
                                    , PERCDESC
                                    , BASECREDDEBRCA
                                    , PERCDESCFIN
                                    , CREDITASOBREPOLITICA
                                    , ALTERAPTABELA
                                    , PRIORITARIA
                                    , PERCDESCRESTRICAO
                                    , CONSIDERACALCGIROMEDIC
                                    , CONCEDERMAIORCOMISSREG
                                    , ALTERADESCONTO
                                    , ENCARTEFECHADO
                                    , PRIORIZACOMISSAO
                                    , INICIOINTERVALO
                                    , FIMINTERVALO
                                    , PRECOFIXO
                                    , VALIDARINTERVALOVALIDADEPROD
                                    , DTINICIOPROMOLOTE
                                    , DTFIMPROMOLOTE
                                    , TIPOPROMOCAO
                                    , PARTICIPACOMISSGARANTIDA
                                    , UTILIZAPERCDESCBASERCA
                                    , PERMITIRAUMENTARQTDEKIT
                                    , PERCDESCBASERCA
                                    , ORIGEMPRECO
                                    , PERCBONIFICMERC
                                    , PROMOCAOMEDOBRIGATORIO )
                             VALUES ( -1  -->> -1 se Chamada 4
                                    , reg_comrede.coddesconto
                                    , vvTIPOPOLITICA
                                    , vvDESCRICAORESUMIDA
                                    , vvDESCRICAODETALHADA
                                    , vdDATAINICIAL
                                    , vdDATAFINAL
                                    , vvAPLICADESCONTO
                                    , reg_comrede.percdesc
                                    , reg_comrede.basecreddebrca
                                    , reg_comrede.percdescfin
                                    , reg_comrede.creditasobrepolitica
                                    , vstempalteraptabela
                                    , reg_comrede.prioritaria
                                    , reg_comrede.percdesc
                                    , reg_comrede.consideracalcgiromedic
                                    , reg_comrede.concedermaiorcomissreg
                                    , vvALTERADESCONTO
                                    , vvENCARTEFECHADO
                                    , vvPRIORIZACOMISSAO
                                    , reg_comrede.qtini
                                    , reg_comrede.qtfim
                                    , vntempprecofixopromocaomed
                                    , vvVALIDARINTERVALOVALIDADEPROD
                                    , vvDTINICIOPROMOLOTE
                                    , vvDTFIMPROMOLOTE
                                    , vvTIPOPROMOCAO
                                    , reg_comrede.participacomissgarantida
                                    , vvUTILIZAPERCDESCBASERCA
                                    , NVL(reg_comrede.PERMITIRAUMENTARQTDEKITMED,vvPERMITIRAUMENTARQTDEKIT)
                                    , reg_comrede.percdescbaserca
                                    , vORIGEMPRECO
                                    , reg_comrede.PERCBONIFICMERC
                                    , reg_comrede.PROMOCAOMEDOBRIGATORIO );
                        EXCEPTION
                          WHEN DUP_VAL_ON_INDEX THEN
                            NULL;
                        END;
                      END IF;
                    END IF;

                  -- Se Chamado para Obter as Promoção
                  ELSIF ((pi_nTipoChamada = 2) and (reg_comrede.codpromocaomed IS NOT NULL)) THEN

                    -- Se a Promoção do Cabeçalho do Pedido for de Encarte, só pode carregar Desconto da Própria Promoção
                    IF ( (F_PROMOCAO_ENCARTE(pi_nCodPromocaoMed) AND (pi_nCodPromocaoMed = reg_comrede.codpromocaomed)) OR
                         (NOT F_PROMOCAO_ENCARTE(pi_nCodPromocaoMed)) ) THEN
                    -- Se a Promoção a ser Carregada for de Encarte, somente pode ser igual ao Código da Promoção de Encarte do Cabeçalho do Pedido
                    IF ( (F_PROMOCAO_ENCARTE(reg_comrede.codpromocaomed) AND (reg_comrede.codpromocaomed = pi_nCodPromocaoMed)) OR
                         (NOT F_PROMOCAO_ENCARTE(reg_comrede.codpromocaomed)) ) THEN
                    -- HIS.01889.2017 - A partir da Campanha a Promoção de Cabeçalho virou de Item
                    -- Se a Promoção a ser Carregada for de Cabeçalho de Pedido, somente pode ser igual ao Código da Promoção do Cabeçalho do Pedido
                    --IF ( (F_PROMOCAO_CABECALHO(reg_comrede.codpromocaomed) AND (reg_comrede.codpromocaomed = pi_nCodPromocaoMed)) OR
                    --     (NOT F_PROMOCAO_CABECALHO(reg_comrede.codpromocaomed)) ) THEN
                    -- Se a Promoção a ser Carregada for de Cabeçalho de KIT, somente pode ser igual ao Código da Promoção do Item do Pedido
                    IF ( (F_PROMOCAO_KIT(reg_comrede.codpromocaomed) AND (reg_comrede.codpromocaomed = pi_nCodPromocaoItem)) OR
                         (NOT F_PROMOCAO_KIT(reg_comrede.codpromocaomed)) ) THEN
                    -- Se a Promoção a ser Carregada for de CASADINHA como Produto PRINCIPAL, somente pode ser o Produto cadastrado como Principal - HIS.01152.2015
                    IF ( (F_PROMOCAO_CASADINHA(reg_comrede.codpromocaomed, p_codprod) = 'P') OR
                         (F_PROMOCAO_CASADINHA(reg_comrede.codpromocaomed, p_codprod) = 'N') ) THEN

                      -- Pesquisa Dados da Promoção
                      P_OBTEM_DADOS_PROMOCAO(reg_comrede.codpromocaomed,
                                             vvACHOUPROMOCAO,
                                             vvTIPOPOLITICA,
                                             vvDESCRICAORESUMIDA,
                                             vvDESCRICAODETALHADA,
                                             vdDATAINICIAL,
                                             vdDATAFINAL,
                                             vvAPLICADESCONTO,
                                             vvALTERADESCONTO,
                                             vvENCARTEFECHADO,
                                             vvPRIORIZACOMISSAO,
                                             vvVALIDARINTERVALOVALIDADEPROD,
                                             vvDTINICIOPROMOLOTE,
                                             vvDTFIMPROMOLOTE,
                                             vvTIPOPROMOCAO,
                                             vvBLOQUEIO,
                                             vvPROMOESPECIAL,
                                             vvUTILIZAPERCDESCBASERCA,
                                             vvPERMITIRAUMENTARQTDEKIT,
                                             vORIGEMPRECO);

                      -- Se Aceita a Promoção conforme Prioridade e/ou bloqueio
                      IF (FACEITA_PROMOCAO_PRIORIDADE(reg_comrede.codpromocaomed,
                                                      reg_comrede.prioridade,
                                                      vvBLOQUEIO,
                                                      vvPROMOESPECIAL,
                                                      pi_vVisualizarPromoBloq,
                                                      pi_vVisualizarPromoEsp,
                                                      --
                                                      p_codfilial,
                                                      p_codcli,
                                                      p_numregiao,
                                                      p_codusur,
                                                      p_codplpag,
                                                      p_codcondicaovenda,
                                                      p_origempedido,
                                                      p_tipofv,
                                                      p_data,
                                                      vvTIPOPROMOCAO -- HIS.01889.2017
                                                      )) THEN

                      -- Apaga registro atual do Código da Promoção (caso exista registro de menor prioridade)
                      --DELETE FROM PCMED_SELPROMOCAO
                       --WHERE (CODPROMOCAOMED = reg_comrede.codpromocaomed);

                        -- Iniciando Variável com o valor de Preço Fixo da PCDESCONTO
                        vntempprecofixopromocaomed := reg_comrede.PRECOFIXOPROMOCAOMED;
                        vstempalteraptabela        := reg_comrede.alteraptabela;

                        -- Se for Preço Fábrica verificar se é zona franca
                        vnPrecoTabelaMarkup := pi_npTabela;
                        if vORIGEMPRECO = 'F' then
                          vstempalteraptabela := 'S';
                          if vsregiaozfm = 'S' then
                              vntempprecofixopromocaomed := vncustorepzfm;
                          else
                              vntempprecofixopromocaomed := vncustorep;
                          end if;
                          vnPrecoTabelaMarkup := vntempprecofixopromocaomed;
                        end if;

                        --- Processo de Markup
                        vnPercDesc    := reg_comrede.percdesc;
                        IF (F_PROMOCAO_MARKUP(reg_comrede.codpromocaomed)) THEN
                          IF NVL(reg_comrede.percmarkupmed,0) = 0 THEN
                              vnPercDesc           := 0;
                          ELSE
                              vnPrecoVendaMarkup   := pi_nCustoFin * (1+(NVL(reg_comrede.percmarkupmed,0)*0.01));
                              vnPercDesc           := (1-(vnPrecoVendaMarkup/vnPrecoTabelaMarkup))*100   ;
                          END IF;
                        END IF;

                        -- Validade do Lote
                        IF (reg_comrede.NUMLOTE IS NOT NULL) THEN
                          BEGIN
                            SELECT DTVALIDADE
                              INTO vdValidadeLote
                              FROM PCLOTE
                             WHERE (CODPROD = pi_nCodProd)
                               AND (NUMLOTE = reg_comrede.NUMLOTE)
                               AND (QT      > 0)
                               AND (ROWNUM  = 1);
                          EXCEPTION
                            WHEN NO_DATA_FOUND THEN
                              vdValidadeLote := NULL;
                          END;
                        ELSE
                          vdValidadeLote := NULL;
                        END IF;

                        -- Insere Dados na Tabela Temporária
                        BEGIN
                          INSERT INTO PCMED_SELPROMOCAO
                                    ( CODPROMOCAOMED
                                    , CODDESCONTO
                                    , TIPOPOLITICA
                                    , DESCRICAORESUMIDA
                                    , DESCRICAODETALHADA
                                    , DATAINICIAL
                                    , DATAFINAL
                                    , APLICADESCONTO
                                    , PERCDESC
                                    , BASECREDDEBRCA
                                    , PERCDESCFIN
                                    , CREDITASOBREPOLITICA
                                    , ALTERAPTABELA
                                    , PRIORITARIA
                                    , PERCDESCRESTRICAO
                                    , CONSIDERACALCGIROMEDIC
                                    , CONCEDERMAIORCOMISSREG
                                    , ALTERADESCONTO
                                    , ENCARTEFECHADO
                                    , PRIORIZACOMISSAO
                                    , INICIOINTERVALO
                                    , FIMINTERVALO
                                    , PRECOFIXO
                                    , VALIDARINTERVALOVALIDADEPROD
                                    , DTINICIOPROMOLOTE
                                    , DTFIMPROMOLOTE
                                    , TIPOPROMOCAO
                                    , PARTICIPACOMISSGARANTIDA
                                    , UTILIZAPERCDESCBASERCA
                                    , PERMITIRAUMENTARQTDEKIT
                                    , PERCDESCBASERCA
                                    , ORIGEMPRECO
                                    , PERCBONIFICMERC
                                    , PERCMARKUPMED
                                    , PROMOCAOMEDOBRIGATORIO
                                    , NUMLOTE
                                    , CODIGOINTEGRACAOWMS
                                    , VALIDADELOTE
                                    )
                             VALUES ( reg_comrede.codpromocaomed
                                    , reg_comrede.coddesconto
                                    , vvTIPOPOLITICA
                                    , vvDESCRICAORESUMIDA
                                    , vvDESCRICAODETALHADA
                                    , vdDATAINICIAL
                                    , vdDATAFINAL
                                    , vvAPLICADESCONTO
                                    , vnPercDesc
                                    , reg_comrede.basecreddebrca
                                    , reg_comrede.percdescfin
                                    , reg_comrede.creditasobrepolitica
                                    , vstempalteraptabela
                                    , reg_comrede.prioritaria
                                    , reg_comrede.percdesc
                                    , reg_comrede.consideracalcgiromedic
                                    , reg_comrede.concedermaiorcomissreg
                                    , vvALTERADESCONTO
                                    , vvENCARTEFECHADO
                                    , vvPRIORIZACOMISSAO
                                    , reg_comrede.INICIOINTERVALOPROMOCAOMED
                                    , reg_comrede.FIMINTERVALOPROMOCAOMED
                                    , vntempprecofixopromocaomed
                                    , vvVALIDARINTERVALOVALIDADEPROD
                                    , vvDTINICIOPROMOLOTE
                                    , vvDTFIMPROMOLOTE
                                    , vvTIPOPROMOCAO
                                    , reg_comrede.participacomissgarantida
                                    , vvUTILIZAPERCDESCBASERCA
                                    , NVL(reg_comrede.PERMITIRAUMENTARQTDEKITMED,vvPERMITIRAUMENTARQTDEKIT)
                                    , reg_comrede.percdescbaserca
                                    , vORIGEMPRECO
                                    , reg_comrede.PERCBONIFICMERC
                                    , reg_comrede.percmarkupmed
                                    , reg_comrede.PROMOCAOMEDOBRIGATORIO
                                    , reg_comrede.NUMLOTE
                                    , reg_comrede.CODIGOINTEGRACAOWMS
                                    , vdValidadeLote
                                    );
                        EXCEPTION
                          WHEN DUP_VAL_ON_INDEX THEN
                            NULL;
                        END;

                      END IF; -- Fim Condição Se Aceita a Promoção conforme Prioridade

                    END IF; -- Fim Condição Verifica Promoção Casadinha
                    END IF; -- Fim Condição Verifica Promoção de KIT
                    -- HIS.01889.2017 - A partir da Campanha a Promoção de Cabeçalho virou de Item
                    --END IF; -- Fim Condição Verifica Promoção de Cabeçalho de Pedido
                    END IF; -- Fim Condição Verifica Promoção Encarte
                    END IF; -- Fim Condição Verifica Promoção Encarte

                  END IF; -- Fim Condição Tipo Chamada

                END LOOP;
*/
            ELSE
              p_mensagem := 'Não foi possível buscar dados do PCREGIAO!';
            END IF;
          ELSE
            p_mensagem := 'Não foi possível buscar dados do PCPRODUT!';
          END IF;
        ELSE
          p_mensagem := 'Não foi possível buscar dados do PCUSUARI!';
        END IF; --dados do PCCLIENT
      ELSE
        p_mensagem := 'Não foi possível buscar dados do PCCLIENT!';
      END IF;


      p_perdesc              := round(vnpercdesc, p_numcasasdecvenda);
      p_perdescfin           := round(vnPerDescfin,p_numcasasdecvenda);
      p_basecreddebrca       := vsbasecreddebrca;
      p_creditasobrepolitica := vscreditasobrepolitica;
      p_pbaserca             := round(vnpercbaserca, p_numcasasdecvenda);
      p_alteraptabela        := vsalteraptabela;


      RETURN vbresult;
    EXCEPTION
      WHEN OTHERS THEN
        p_mensagem := 'Erro ao Validar Politica de Descontos: ' || SQLCODE || '-' ||
                      SQLERRM;
        RETURN FALSE;
    END FUNCAO_OBTEM_DESC_POLITICA;



  FUNCTION FUNCAO_OBTEM_DESC_QUANTIDADE
    (pi_nTipoChamada       IN  NUMBER,
     pi_nCodPromocaoMed    IN  NUMBER,
     p_codprod             IN NUMBER,
     p_qtde                IN NUMBER,
     p_numregiao           IN NUMBER,
   --  p_ptabela             IN NUMBER,
  --   p_pvenda1             IN NUMBER,
     p_codpraca            IN NUMBER,
  --   p_numcasasdecvenda    IN NUMBER,
     p_numdias             IN NUMBER,
     p_codprodprinc        IN NUMBER,
     p_usaprioritaria      IN VARCHAR2,
     p_tipofv              IN pcintegradora.tipofv%type,
     p_mensagem            OUT VARCHAR2,
     p_perdesc             OUT NUMBER,
     p_creditasobreptabela OUT VARCHAR2,
     p_basedebcredrca      OUT VARCHAR2,
     p_percbaserca         OUT NUMBER) RETURN BOOLEAN IS

      vbresult         BOOLEAN;
      vnpercdesc       NUMBER;
      vnperdesctemp    number;
      vnperdescmax     NUMBER;
  --    vnperdescmaxtemp number;
  --    vnptabela        NUMBER;

  --    vnptabela_quantmax        NUMBER;
  --    vnptabela_quant           NUMBER;
      vscreditasobreptabela     VARCHAR2(1);
      vscreditasobreptabelatemp VARCHAR2(1);
      vddtinicio                DATE;
      vniniciointervalo         NUMBER;
      vnfimintervalo            NUMBER;
      vsbasecreddebrca          pcdescquant.basecreddebrca%type;
      vsbasecreddebrcatemp      pcdescquant.basecreddebrca%type;
      vnpercbaserca             number;
      vnpercbasercatemp         number;
      vsprioritaria             pcdescquant.prioritaria%type;
      vstempprioritaria         pcdescquant.prioritaria%type;

      -- Dados da Promoção
      vvACHOUPROMOCAO            VARCHAR2(1);
      vvTIPOPOLITICA             PCMED_SELPROMOCAO.TIPOPOLITICA%TYPE;
      vvDESCRICAORESUMIDA        PCMED_SELPROMOCAO.DESCRICAORESUMIDA%TYPE;
      vvDESCRICAODETALHADA       PCMED_SELPROMOCAO.DESCRICAODETALHADA%TYPE;
      vdDATAINICIAL              PCMED_SELPROMOCAO.DATAINICIAL%TYPE;
      vdDATAFINAL                PCMED_SELPROMOCAO.DATAFINAL%TYPE;
      vvAPLICADESCONTO           PCMED_SELPROMOCAO.APLICADESCONTO%TYPE;
      vvALTERADESCONTO           PCMED_SELPROMOCAO.ALTERADESCONTO%TYPE;
      vvENCARTEFECHADO           PCMED_SELPROMOCAO.ENCARTEFECHADO%TYPE;
      vvPRIORIZACOMISSAO         PCMED_SELPROMOCAO.PRIORIZACOMISSAO%TYPE;
      vvVALIDARINTERVALOVALIDADEPROD PCMED_SELPROMOCAO.VALIDARINTERVALOVALIDADEPROD%TYPE;
      vvDTINICIOPROMOLOTE            PCMED_SELPROMOCAO.DTINICIOPROMOLOTE%TYPE;
      vvDTFIMPROMOLOTE               PCMED_SELPROMOCAO.DTFIMPROMOLOTE%TYPE;
      vvTIPOPROMOCAO                 PCMED_SELPROMOCAO.TIPOPROMOCAO%TYPE;
      vvBLOQUEIO                     VARCHAR2(1);
      vvPROMOESPECIAL                VARCHAR2(1);
      vvUTILIZAPERCDESCBASERCA       PCMED_SELPROMOCAO.UTILIZAPERCDESCBASERCA%TYPE;
      vvPERMITIRAUMENTARQTDEKIT      PCMED_SELPROMOCAO.PERMITIRAUMENTARQTDEKIT%TYPE;
      vORIGEMPRECO                   PCMED_SELPROMOCAO.ORIGEMPRECO%TYPE;

      -- Arrays para Pesquisa das Faixas de Desconto
      TYPE TT_INICIOINTERVALO    IS TABLE OF PCMED_SELPROMOCAO.INICIOINTERVALO%TYPE INDEX BY BINARY_INTEGER;
      TYPE TT_FIMINTERVALO       IS TABLE OF PCMED_SELPROMOCAO.FIMINTERVALO%TYPE INDEX BY BINARY_INTEGER;
      TYPE TT_PERCDESC           IS TABLE OF PCMED_SELPROMOCAO.PERCDESC%TYPE INDEX BY BINARY_INTEGER;
      vtINICIOINTERVALO          TT_INICIOINTERVALO;
      vtFIMINTERVALO             TT_FIMINTERVALO;
      vtPERCDESC                 TT_PERCDESC;

      vncodlinhaprod             pcprodut.codlinhaprod%type;

    BEGIN


      vbresult      := FALSE;
  --    vnptabela     := p_ptabela;
      vnpercdesc    := null;
      vnpercbaserca := null;
      vsprioritaria := 'N';

      -- Se Chamado para Obter as Politicas de Desconto Quantidade no Operador Logístico
      IF (pi_nTipoChamada = 1) THEN

          for reg in (SELECT pcdescquant.percdesc,
                               pcdescquant.dtfim,
                               pcdescquant.perdescmax,
                               pcdescquant.creditasobreptabela,
                               pcdescquant.dtinicio,
                               pcdescquant.iniciointervalo,
                               pcdescquant.fimintervalo,
                               nvl(pcdescquant.basecreddebrca, 'N') basecreddebrca,
                               pcdescquant.prioritaria,
                               pcdescquant.questionausoprioritaria,
                               pcdescquant.codpromocaomed,
                               pcdescquant.coddesconto,
                               pcdescquant.consideracalcgiromedic
                          FROM pcdescquant, pcplpag
                         WHERE pcdescquant.codprod =
                               decode(pcdescquant.APLICAFAMILIAPRODUTOS,
                                      'S',
                                      p_codprodprinc,
                                      p_codprod)
                           AND pcdescquant.codplpagmax = pcplpag.codplpag(+)
                           AND decode(pcdescquant.codplpagmax,
                                      NULL,
                                      p_numdias,
                                      pcplpag.numdias) >= p_numdias
                           AND pcdescquant.iniciointervalo <= p_qtde
                           AND pcdescquant.fimintervalo >= p_qtde
                           AND ((pcdescquant.numregiao = p_numregiao) OR
                               (pcdescquant.numregiao IS NULL))
                           AND ((pcdescquant.codpraca = p_codpraca) OR
                               (pcdescquant.codpraca IS NULL))
                           AND ((trunc(SYSDATE) BETWEEN pcdescquant.dtinicio AND
                               pcdescquant.dtfim) OR ((pcdescquant.dtinicio IS NULL) AND
                               (pcdescquant.dtfim IS NULL)))
                           AND nvl(pcdescquant.tipodesconto, 'A') = 'A'
                           AND (pcdescquant.tipofv = p_tipofv)
                           AND (case when pcdescquant.tipofv = 'OL' then pcdescquant.aplicaoperlog else pcdescquant.aplicapedelet end) = 'S'
                           AND (codpromocaomed IS NULL) -- Somente Descontos sem Promoção atrelada
                         ORDER BY pcdescquant.percdesc) loop

              vbresult                   := TRUE;
              vnperdesctemp              := reg.percdesc;
              vsbasecreddebrcatemp       := reg.basecreddebrca;
              vscreditasobreptabelatemp  := reg.creditasobreptabela;
              vnpercbasercatemp          := reg.percdesc;
              vstempprioritaria          := reg.prioritaria;


              if vnperdesctemp < 0 then
                --desconto


               if vsprioritaria = 'N' then

                if vstempprioritaria = 'S' then --registro atual é de politica prioritaria


                   if p_usaprioritaria = 'S' then


                      vnpercdesc        := vnperdesctemp;
                      vddtinicio        := reg.dtinicio;
                      vniniciointervalo := reg.iniciointervalo;
                      vnfimintervalo    := reg.fimintervalo;
                      vnperdescmax      := reg.perdescmax;
                      vsprioritaria          := reg.prioritaria;



                      if vsbasecreddebrcatemp = 'S'  then
                        vsbasecreddebrca      := vsbasecreddebrcatemp;
                        vnpercbaserca         := vnpercbasercatemp;
                        vscreditasobreptabela := vscreditasobreptabelatemp;
                      end if;

                   end if;


               else --registro atual não é prioritaria

                    IF (vnperdesctemp < vnpercdesc) or vnpercdesc is null THEN


                      vnpercdesc        := vnperdesctemp;
                      vddtinicio        := reg.dtinicio;
                      vniniciointervalo := reg.iniciointervalo;
                      vnfimintervalo    := reg.fimintervalo;
                      vnperdescmax      := reg.perdescmax;
                      vsprioritaria          := 'N';


                    END IF;

                    if vsbasecreddebrcatemp = 'S' and
                       ((vnpercbasercatemp < vnpercbaserca) or vnpercbaserca is null) then
                      vsbasecreddebrca      := vsbasecreddebrcatemp;
                      vnpercbaserca         := vnpercbasercatemp;
                      vscreditasobreptabela := vscreditasobreptabelatemp;
                    end if;
                 end if;

                else -- já tem politica prioritaria

                    IF (vnperdesctemp < vnpercdesc) or vnpercdesc is null THEN


                      vnpercdesc        := vnperdesctemp;
                      vddtinicio        := reg.dtinicio;
                      vniniciointervalo := reg.iniciointervalo;
                      vnfimintervalo    := reg.fimintervalo;
                      vnperdescmax      := reg.perdescmax;
                      vsprioritaria          := reg.prioritaria;



                    END IF;

                    if vsbasecreddebrcatemp = 'S' and
                       ((vnpercbasercatemp < vnpercbaserca) or vnpercbaserca is null) then
                      vsbasecreddebrca      := vsbasecreddebrcatemp;
                      vnpercbaserca         := vnpercbasercatemp;
                      vscreditasobreptabela := vscreditasobreptabelatemp;
                    end if;


                end if;

              end if;

          END loop;

      -- Se Chamado para Obter as Promoções
      ELSIF (pi_nTipoChamada = 2) THEN

         BEGIN
           SELECT codlinhaprod
             INTO vncodlinhaprod
             FROM pcprodut
            WHERE codprod = p_codprod;
          EXCEPTION
            WHEN NO_DATA_FOUND THEN
              vncodlinhaprod := NULL;
          END;

          for reg in (SELECT pcdescquant.percdesc,
                               pcdescquant.dtfim,
                               pcdescquant.perdescmax,
                               pcdescquant.creditasobreptabela,
                               pcdescquant.dtinicio,
                               pcdescquant.iniciointervalo,
                               pcdescquant.fimintervalo,
                               nvl(pcdescquant.basecreddebrca, 'N') basecreddebrca,
                               pcdescquant.prioritaria,
                               pcdescquant.questionausoprioritaria,
                               pcdescquant.codpromocaomed,
                               pcdescquant.coddesconto,
                               pcdescquant.consideracalcgiromedic
                          FROM pcdescquant, pcplpag
                         WHERE ((pcdescquant.codprod =
                                 decode(pcdescquant.APLICAFAMILIAPRODUTOS,
                                        'S',
                                        p_codprodprinc,
                                        p_codprod)) OR
                                (pcdescquant.codprod IS NULL))
                           AND pcdescquant.codplpagmax = pcplpag.codplpag(+)
                           AND decode(pcdescquant.codplpagmax,
                                      NULL,
                                      p_numdias,
                                      pcplpag.numdias) >= p_numdias
                           AND ((pcdescquant.numregiao = p_numregiao) OR
                               (pcdescquant.numregiao IS NULL))
                           AND ((pcdescquant.codpraca = p_codpraca) OR
                               (pcdescquant.codpraca IS NULL))
                           AND ((trunc(SYSDATE) BETWEEN pcdescquant.dtinicio AND
                               pcdescquant.dtfim) OR ((pcdescquant.dtinicio IS NULL) AND
                               (pcdescquant.dtfim IS NULL)))
                           AND (NVL(pcdescquant.tipofv,'TL') = p_tipofv)
                           AND (codpromocaomed IS NOT NULL) -- Somente Descontos com Promoção atrelada
                           AND ((pcdescquant.codlinhaprod = vncodlinhaprod) OR (pcdescquant.codlinhaprod IS NULL)) -->> Promoção tem Linha de Produto
                         ORDER BY pcdescquant.percdesc) loop

              -- Se a Promoção do Cabeçalho do Pedido for de Encarte, só pode carregar Desconto da Própria Promoção
              IF ( (F_PROMOCAO_ENCARTE(pi_nCodPromocaoMed) AND (pi_nCodPromocaoMed = reg.codpromocaomed)) OR
                   (NOT F_PROMOCAO_ENCARTE(pi_nCodPromocaoMed)) ) THEN
              -- Se a Promoção a ser Carregada for de Encarte, somente pode ser igual ao Código da Promoção de Encarte do Cabeçalho do Pedido
              IF ( (F_PROMOCAO_ENCARTE(reg.codpromocaomed) AND (reg.codpromocaomed = pi_nCodPromocaoMed)) OR
                   (NOT F_PROMOCAO_ENCARTE(reg.codpromocaomed)) ) THEN
              -- Se a Promoção a ser Carregada for de Cabeçalho de Pedido, somente pode ser igual ao Código da Promoção do Cabeçalho do Pedido
              IF ( (F_PROMOCAO_CABECALHO(reg.codpromocaomed) AND (reg.codpromocaomed = pi_nCodPromocaoMed)) OR
                   (NOT F_PROMOCAO_CABECALHO(reg.codpromocaomed)) ) THEN
              -- Se a Promoção a ser Carregada for de KIT, somente pode ser igual ao Código da Promoção do Item do Pedido
              IF ( (F_PROMOCAO_KIT(reg.codpromocaomed) AND (reg.codpromocaomed = pi_nCodPromocaoItem)) OR
                   (NOT F_PROMOCAO_KIT(reg.codpromocaomed)) ) THEN
              -- Não foi necessário implementar a Casadinha aqui - descontinuada a pcdescquant

                -- Pesquisa Dados da Promoção
                P_OBTEM_DADOS_PROMOCAO(reg.codpromocaomed,
                                       vvACHOUPROMOCAO,
                                       vvTIPOPOLITICA,
                                       vvDESCRICAORESUMIDA,
                                       vvDESCRICAODETALHADA,
                                       vdDATAINICIAL,
                                       vdDATAFINAL,
                                       vvAPLICADESCONTO,
                                       vvALTERADESCONTO,
                                       vvENCARTEFECHADO,
                                       vvPRIORIZACOMISSAO,
                                       vvVALIDARINTERVALOVALIDADEPROD,
                                       vvDTINICIOPROMOLOTE,
                                       vvDTFIMPROMOLOTE,
                                       vvTIPOPROMOCAO,
                                       vvBLOQUEIO,
                                       vvPROMOESPECIAL,
                                       vvUTILIZAPERCDESCBASERCA,
                                       vvPERMITIRAUMENTARQTDEKIT,
                                       vORIGEMPRECO);

                -- Insere Dados na Tabela Temporária
                BEGIN
                  INSERT INTO PCMED_SELPROMOCAO
                            ( CODPROMOCAOMED
                            , CODDESCONTO
                            , TIPOPOLITICA
                            , DESCRICAORESUMIDA
                            , DESCRICAODETALHADA
                            , DATAINICIAL
                            , DATAFINAL
                            , APLICADESCONTO
                            , PERCDESC
                            , BASECREDDEBRCA
                            , CONSIDERACALCGIROMEDIC
                            , CREDITASOBREPTABELA
                            , INICIOINTERVALO
                            , FIMINTERVALO
                            , ALTERADESCONTO
                            , ENCARTEFECHADO
                            , PRIORIZACOMISSAO
                            , VALIDARINTERVALOVALIDADEPROD
                            , DTINICIOPROMOLOTE
                            , DTFIMPROMOLOTE
                            , TIPOPROMOCAO )
                     VALUES ( reg.codpromocaomed
                            , reg.coddesconto
                            , vvTIPOPOLITICA
                            , vvDESCRICAORESUMIDA
                            , vvDESCRICAODETALHADA
                            , vdDATAINICIAL
                            , vdDATAFINAL
                            , vvAPLICADESCONTO
                            , ABS(reg.percdesc) -- Valor Absoluto porque o desconto é gravado com sinal negativo
                            , reg.basecreddebrca
                            , reg.consideracalcgiromedic
                            , reg.creditasobreptabela
                            , reg.iniciointervalo
                            , reg.fimintervalo
                            , vvALTERADESCONTO
                            , vvENCARTEFECHADO
                            , vvPRIORIZACOMISSAO
                            , vvVALIDARINTERVALOVALIDADEPROD
                            , vvDTINICIOPROMOLOTE
                            , vvDTFIMPROMOLOTE
                            , vvTIPOPROMOCAO );
                EXCEPTION
                  WHEN DUP_VAL_ON_INDEX THEN
                    NULL;
                END;

              END IF; -- Fim Condição Verifica Promoção de KIT
              END IF; -- Fim Condição Verifica Promoção de Cabeçalho de Pedido
              END IF; -- Fim Condição Verifica Promoção Encarte
              END IF; -- Fim Condição Verifica Promoção Encarte

          END loop;

      -- Se Chamado para Carregar a Tabela Temporária com as Políticas de Desconto por Quantidade
      -- Se Chamado para Obter as Politicas de Desconto Quantidade na Venda Normal
      ELSIF (pi_nTipoChamada IN (3,4,18)) THEN

          -- Neste Select, carrega no Cursor todas as informações independente da quantidade,
          -- para apresentar todas as faixas válidas
          for reg in (SELECT pcdescquant.percdesc,
                               pcdescquant.dtfim,
                               pcdescquant.perdescmax,
                               pcdescquant.creditasobreptabela,
                               pcdescquant.dtinicio,
                               pcdescquant.iniciointervalo,
                               pcdescquant.fimintervalo,
                               nvl(pcdescquant.basecreddebrca, 'N') basecreddebrca,
                               pcdescquant.prioritaria,
                               pcdescquant.questionausoprioritaria,
                               pcdescquant.codpromocaomed,
                               pcdescquant.coddesconto,
                               pcdescquant.consideracalcgiromedic,
                               pcdescquant.tipodesconto
                          FROM pcdescquant, pcplpag
                         WHERE pcdescquant.codprod =
                               decode(pcdescquant.APLICAFAMILIAPRODUTOS,
                                      'S',
                                      p_codprodprinc,
                                      p_codprod)
                           AND pcdescquant.codplpagmax = pcplpag.codplpag(+)
                           AND decode(pcdescquant.codplpagmax,
                                      NULL,
                                      p_numdias,
                                      pcplpag.numdias) >= p_numdias
                           AND ((pcdescquant.numregiao = p_numregiao) OR
                               (pcdescquant.numregiao IS NULL))
                           AND ((pcdescquant.codpraca = p_codpraca) OR
                               (pcdescquant.codpraca IS NULL))
                           AND ((trunc(SYSDATE) BETWEEN pcdescquant.dtinicio AND
                               pcdescquant.dtfim) OR ((pcdescquant.dtinicio IS NULL) AND
                               (pcdescquant.dtfim IS NULL)))
                           AND (NVL(pcdescquant.tipofv,'TL') = p_tipofv)
                           AND (codpromocaomed IS NULL) -- Somente Descontos sem Promoção atrelada
                           AND ((pi_nTipoChamada IN (3,18)) OR ((pi_nTipoChamada = 4) AND (NVL(pcdescquant.percdesc,0) < 0))) -- Venda Normal somente Descontos
                         ORDER BY pcdescquant.percdesc) loop

              -- Define se Aplica Desconto Automaticamente
              IF (NVL(reg.tipodesconto,' ') = 'A') THEN
                vvAPLICADESCONTO := 'S';
              ELSE
                vvAPLICADESCONTO := 'N';
              END IF;

              -- Define a Descrição Resumida e Detalhada
              vvDESCRICAORESUMIDA  := 'Faixas de Desconto por Quantidade';
              vvDESCRICAODETALHADA := 'Faixas de Desconto por Quantidade';

              -- Insere Dados na Tabela Temporária
              BEGIN
                INSERT INTO PCMED_SELPROMOCAO
                          ( CODPROMOCAOMED
                          , CODDESCONTO
                          , TIPOPOLITICA
                          , DESCRICAORESUMIDA
                          , DESCRICAODETALHADA
                          , DATAINICIAL
                          , DATAFINAL
                          , APLICADESCONTO
                          , PERCDESC
                          , BASECREDDEBRCA
                          , CONSIDERACALCGIROMEDIC
                          , CREDITASOBREPTABELA
                          , INICIOINTERVALO
                          , FIMINTERVALO
                          , ALTERADESCONTO )
                   VALUES ( DECODE(pi_nTipoChamada,4,  -1  -->> -1 se Chamada 4
                                                    ,NULL) -->> Sem Promoção se Chamada 3
                          , reg.coddesconto
                          , 'Q' -->> Política de Desconto por Quantidade
                          , vvDESCRICAORESUMIDA
                          , vvDESCRICAODETALHADA
                          , reg.dtinicio
                          , reg.dtfim
                          , vvAPLICADESCONTO
                          , ABS(reg.percdesc) -- Valor Absoluto porque o desconto é gravado com sinal negativo
                          , reg.basecreddebrca
                          , reg.consideracalcgiromedic
                          , reg.creditasobreptabela
                          , reg.iniciointervalo
                          , reg.fimintervalo
                          , 'S' );
              EXCEPTION
                WHEN DUP_VAL_ON_INDEX THEN
                  NULL;
              END;

          END loop;

          -- Carrega os maiores descontos por faixa
          SELECT INICIOINTERVALO
               , FIMINTERVALO
               , MAX(PERCDESC)
            BULK COLLECT INTO vtINICIOINTERVALO
                            , vtFIMINTERVALO
                            , vtPERCDESC
            FROM PCMED_SELPROMOCAO
           GROUP BY INICIOINTERVALO,
                    FIMINTERVALO;

          -- Processa os maiores descontos por faixa
          IF (vtPERCDESC.COUNT > 0) THEN
            FOR viLaco IN vtPERCDESC.FIRST..vtPERCDESC.LAST LOOP
              -- Deleta as mesmas faixas com desconto menor
              DELETE FROM PCMED_SELPROMOCAO
                    WHERE (INICIOINTERVALO = vtINICIOINTERVALO(viLaco))
                      AND (FIMINTERVALO    = vtFIMINTERVALO(viLaco))
                      AND (PERCDESC        < vtPERCDESC(viLaco));
            END LOOP;
          END IF;

      END IF; -- Fim Condição Tipo Chamada

      --utilizado só para retornar o percentual
      p_perdesc := abs(vnpercdesc);


      --4. Desconto ou Acrescimo


      p_creditasobreptabela := vscreditasobreptabela;

      p_basedebcredrca := vsbasecreddebrca;

      p_percbaserca := abs(vnpercbaserca);




      if vddtinicio is not null then
        p_mensagem := to_char(vddtinicio, 'dd/mm/yyyy') || ',' ||
                      vniniciointervalo || ',' || vnfimintervalo;
      end if;

      RETURN vbresult;
    EXCEPTION
      WHEN OTHERS THEN
        p_mensagem := 'Erro validar desconto por quantidade ' || SQLCODE || '-' ||
                      SQLERRM;
        RETURN FALSE;
    END FUNCAO_OBTEM_DESC_QUANTIDADE;



  BEGIN

   /**************************
    Inicializacao de Variaveis
    **************************/

    -- Inicializa Retornos de indicacao de erros
    po_vOcorreramErros := 'N';
    po_vMsgErros       := NULL;

    -- Inicializa variáveis auxiliares
    vnPerDesc          := NVL(vnPerDesc,0);
    vnPerBonific       := NVL(vnPerBonific,0);
    vnPerComerc        := NVL(vnPerComerc,0);
    vnPerBoleto        := NVL(vnPerBoleto,0);
    vnPercDescFinLinha := NVL(vnPercDescFinLinha,0);

    -- Se Chamado para obter as Politicas de Desconto / Quantidade
    IF (pi_nTipoChamada = 1) THEN

      -- Pesquisa Parâmetro Tipo de Prazo de Medicamentos
      BEGIN
        SELECT PCPARAMFILIAL.valor
          INTO vvTipoPrazoMedicam
          FROM PCPARAMFILIAL
         WHERE (PCPARAMFILIAL.nome      = 'TIPOPRAZOMEDICAMEN')
           AND (PCPARAMFILIAL.codfilial = 99);
      EXCEPTION
        WHEN NO_DATA_FOUND THEN
          -- Atualiza Mensagem de Erro e Aborta
          po_vMsgErros := 'Parâmetro [TIPOPRAZOMEDICAMEN] não encontrado.';
          RAISE e_Generico;
      END;

      -- Pesquisa parâmetro da condicao de venda que define a Origem do Desconto de Bonificacao
      BEGIN
        SELECT PCCONDICAOVENDA.tipodescbonif
          INTO vvTipoDescBonif
          FROM PCCONDICAOVENDA
         WHERE (PCCONDICAOVENDA.codcondicaovenda = pi_nCodCondicaoVenda);
      EXCEPTION
        WHEN NO_DATA_FOUND THEN
          -- Atualiza Mensagem de Erro e Aborta
          po_vMsgErros := 'Condicao Venda [' || pi_nCodCondicaoVenda || '] não cadastrada.';
          RAISE e_Generico;
      END;

      -- Pesquisa Parâmetro que define se o Cliente pode ter Desconto Comercial no Boleto
      BEGIN
        SELECT nvl(pcclient.usadescfinseparadodesccom,'S')
          INTO vcPermiteDescBoleto
          FROM PCCLIENT
         WHERE (PCCLIENT.codcli = pi_nCodCli);
      EXCEPTION
        WHEN NO_DATA_FOUND THEN
          -- Atualiza Mensagem de Erro e Aborta
          po_vMsgErros := 'Cliente [' || pi_nCodCli || '] não cadastrado.';
          RAISE e_Generico;
      END;

    END IF; -- Se Chamado para obter as Politicas de Desconto / Quantidade

   /**********************************************************
    Obtem o maior Desconto cadastrado na Politica de Descontos
    **********************************************************/
    -- FUNCAO PARA OBTER O MAIOR DESCONTO CADASTRADOS NA POLITICA DE DESCONTOS

     BEGIN

     vbpoliticadescvalida := FUNCAO_OBTEM_DESC_POLITICA(pi_nTipoChamada,
                                                       pi_nCodPromocaoMed,
                                                       pi_ncodprod ,
                                                       pi_ddata,
                                                       pi_scodfilial,
                                                       pi_nnumregiao,
                                                       pi_ncodcli,
                                                       pi_ncodusur,
                                                       pi_sorigempedido,
                                                       pi_ncodprodprinc,
                                                       pi_nnumcasasdecvenda,
                                                       pi_ncodplpag,
                                                       pi_sclassevenda,
                                                       pi_snaousarautdebcredpoldesc,
                                                       pi_susaprioritaria,
                                                       pi_stipofv,
                                                       pi_ncodcondicaovenda,
                                                       pi_nnumdias,
                                                       vsmensagempoldesc,
                                                       vnPercDescComercPolitica,
                                                       vnPercDescBoletoPolitica,
                                                       po_sbasecreddebrca,
                                                       po_screditasobrepolitica,
                                                       po_salteraptabela,
                                                       po_ndescpbaserca  );

        if vbpoliticadescvalida = false then
           vnPercDescComercPolitica := 0;
           vnPercDescBoletoPolitica := 0;

           po_vMsgErros := vsmensagempoldesc;


        end if;


    EXCEPTION WHEN OTHERS THEN
      -- Se Chamado para obter as Politicas de Desconto / Quantidade
      IF (pi_nTipoChamada = 1) THEN
        vnPercDescComercPolitica := 0;
        vnPercDescBoletoPolitica := 0;
        po_vMsgErros := 'Erro ao verificar politica de descontos. '||SQLCODE|| ' - ' ||SQLERRM;
        RAISE e_Generico;
      END IF;
    END;

   /**************************************************************
    Obtem o maior Desconto cadastrado nos Descontos por Quantidade
    **************************************************************/
    -- FUNCAO PARA OBTER O MAIOR DESCONTO CADASTRADO NOS DESCONTOS POR QUANTIDADE

    BEGIN

      vbvalidodescquant :=  FUNCAO_OBTEM_DESC_QUANTIDADE
                            (pi_nTipoChamada,
                             pi_nCodPromocaoMed,
                             pi_nCodProd,
                             pi_nqtde,
                             pi_nnumregiao,
                           --  p_ptabela,
                           --  p_pvenda1,
                             pi_ncodpraca,
                           --  pi_nnumcasasdecvenda,
                             pi_nnumdias,
                             pi_ncodprodprinc,
                             pi_susaprioritaria ,
                             pi_stipofv,
                             vsmensagemdescquant,
                             vnPercDescComercQuantid,
                             po_creditasobreptabela_quant,
                             po_basedebcredrca_quant,
                             po_percbaserca_quant);

        if vbvalidodescquant = false then

           vnPercDescComercQuantid := 0;

           po_vMsgErros := vsmensagemdescquant;


        end if;


   EXCEPTION WHEN OTHERS THEN
     -- Se Chamado para obter as Politicas de Desconto / Quantidade
     IF (pi_nTipoChamada = 1) THEN
        vnPercDescComercQuantid := 0;
        po_vMsgErros := 'Erro ao verificar politica de descontos por quantidade: '||vsmensagemdescquant;
        RAISE e_Generico;
      END IF;
    END;

    -- Se Chamado para obter as Politicas de Desconto / Quantidade
    IF (pi_nTipoChamada = 1) THEN

     /**********************************************************
      Definição do Desconto Promocional:
      Maior Desconto entre o cadastrado na Politica de Descontos
      e o cadastrado nos Descontos por Quantidade
      **********************************************************/

      -- Escolhe o maior Desconto entre os cadastrados na Politica de Descontos e o Desconto por Quantidade
      IF ((NVL(vnPercDescComercPolitica,0) + NVL(vnPercDescBoletoPolitica,0)) >= NVL(vnPercDescComercQuantid,0)) THEN

        -- Se pode ser concedido Desconto no Boleto para o Cliente
        IF    (NVL(vcPermiteDescBoleto,' ') = 'S') THEN

          -- Desconto a conceder em NF
          vnPercDescComercPromocao := NVL(vnPercDescComercPolitica,0);
          -- Desconto a conceder em Boleto
          vnPercDescBoletoPromocao := NVL(vnPercDescBoletoPolitica,0);

        -- Se NÃO pode ser concedido Desconto no Boleto para o Cliente
        ELSE

          -- Desconto a conceder em NF (adiciona o desconto que seria dado no boleto ao desconto da nota fiscal)
          vnPercDescComercPromocao := (NVL(vnPercDescComercPolitica,0) + NVL(vnPercDescBoletoPolitica,0));
          -- Desconto a conceder em Boleto = ZERO (não pode conceder desconto no boleto)
          vnPercDescBoletoPromocao := 0;

        END IF;

      ELSE

        -- Desconto a conceder em NF
        vnPercDescComercPromocao := NVL(vnPercDescComercQuantid,0);
        -- Desconto a conceder em Boleto = ZERO (Desconto por Quantidade não possui cadastro de desconto financeiro)
        vnPercDescBoletoPromocao := 0;

      END IF;

      -- Desconto Total da Promoção
      vnPercDescTotalPromocao  := NVL(vnPercDescComercPromocao,0) + NVL(vnPercDescBoletoPromocao,0);

     /***************************************
      Obtem o Desconto, Grupo de Faturamento
      e Linha de Prazo do Cadastro do Produto
      ****************************************/
      BEGIN
        SELECT PCPRODUT.percbonificvenda,
               PCPRODUT.grupofaturamento,
               PCPRODUT.codlinhaprazo
          INTO vnPercDescBonifProduto,
               vvGrupoFaturamento,
               vnCodLinhaPrazo
          FROM PCPRODUT
         WHERE (PCPRODUT.codprod = pi_nCodProd);
      EXCEPTION
        WHEN NO_DATA_FOUND THEN
          -- Atualiza Mensagem de Erro e Aborta
          po_vMsgErros := 'Produto [' || pi_nCodProd || '] não cadastrado.';
          RAISE e_Generico;
      END;

     /**************************************************
      Redefine a Linha de Prazo do Produto para atender
      os Clientes que trabalham com Grupo de Faturamento
      **************************************************/
      IF (NVL(vvTipoPrazoMedicam,' ') = '1') THEN

        -- Define a Linha de Prazo conforme o Grupo de Produto
        IF    (NVL(vvGrupoFaturamento,' ') = 'E') THEN
          -- Grupo de Faturamento Etico = Linha 1
          vnCodLinhaPrazo := 1;
        ELSIF (NVL(vvGrupoFaturamento,' ') = 'G') THEN
          -- Grupo de Faturamento Generico = Linha 2
          vnCodLinhaPrazo := 2;
        ELSE
          vnCodLinhaPrazo := NULL;
        END IF;

      END IF;

     /**************************************************
      Obtem o Plano, Descontos e Parametro de Incidencia
      da Linha da Condição de Venda
      **************************************************/
      BEGIN
        SELECT PCCONDVENDALINHA.codplpag,
               PCCONDVENDALINHA.percdescbonifnota,
               PCCONDVENDALINHA.percdescomnota,
               PCCONDVENDALINHA.percdescboleto,
               PCCONDVENDALINHA.percdescfin,
               PCCONDVENDALINHA.tipoincidenciadescom
          INTO vnCodPlPag,
               vnPercDescBonifLinha,
               vnPercDescComercLinha,
               vnPercDescBoletoLinha,
               vnPercDescFinLinha,
               vvTipoIncidencia
          FROM PCCONDVENDALINHA
         WHERE (PCCONDVENDALINHA.codcondicaovenda = pi_nCodCondicaoVenda)
           AND (PCCONDVENDALINHA.codlinhaprazo    = vnCodLinhaPrazo);
      EXCEPTION
        WHEN NO_DATA_FOUND THEN
          -- Atualiza Mensagem de Erro e Aborta
          po_vMsgErros := 'Linha [' || vnCodLinhaPrazo || '] não cadastrada na Cond. Venda [' || pi_nCodCondicaoVenda || '].';
          RAISE e_Generico;
      END;

     /****************************************************
      Redefine Descontos da Linha conforme parametrizações
      da Condição de Venda e do Cliente
      ****************************************************/

      -- Se a Origem do Desconto de Bonificacao for o Cadastro do Produto, substitui
      -- o Desconto de Bonificação da Linha da Condição de Venda pela Bonificação do cadastro do Produto
      IF (NVL(vvTipoDescBonif,' ') = 'P') THEN
        vnPercDescBonifLinha := NVL(vnPercDescBonifProduto,0);
      END IF;

      -- Se NÃO pode ser concedido Desconto no Boleto para o Cliente
      IF    (NVL(vcPermiteDescBoleto,' ') <> 'S') THEN

        -- Desconto a conceder em NF (adiciona o desconto que seria dado no boleto ao desconto da nota fiscal)
        vnPercDescComercLinha := NVL(vnPercDescComercLinha,0) + NVL(vnPercDescBoletoLinha,0);
        -- Desconto a conceder em Boleto = ZERO (não pode conceder desconto no boleto)
        vnPercDescBoletoLinha := 0;

      END IF;

     /**********************************************************
      Definição dos Descontos da Condição de Venda:
      Descontos a serem concedidos conforme o Tipo de Incidencia
      dos Descontos Promocionais sobre os Descontos por Linha
      na Condição de Venda
      *********************************************************/

      -- Cálculo do Total de Descontos da Linha (descontos bonificação + comercial + boleto)
      -- para utilização na validação do maior desconto entre os descontos da Condição de Venda e os Descontos Promocionais
      vnPercDescTotalLinha := F_CalcDescontoSobreDesconto((NVL(vnPercDescBonifLinha,0)),
                                                          (NVL(vnPercDescComercLinha,0) + NVL(vnPercDescBoletoLinha,0)));

      ------------------------------------------------------------------------------
      -- Se Agrega Desconto:
      -- Substitui o Desconto Comercial da Linha da Condição de Venda pelo Desconto
      -- Comercial Promocional e a agrega o resultado ao Desconto de Bonificação
      ------------------------------------------------------------------------------
      IF    (NVL(vvTipoIncidencia,' ') = 'A') THEN

        -- Desconto Total a ser concedido em Nota Fiscal
        vnPerDesc    := F_CalcDescontoSobreDesconto(NVL(vnPercDescBonifLinha,0),
                                                    NVL(vnPercDescComercPromocao,0));
        -- Desconto de Bonificação a ser concedido em Nota Fiscal
        vnPerBonific := NVL(vnPercDescBonifLinha,0);
        -- Desconto Comercial a ser concedido em Nota Fiscal
        vnPerComerc  := NVL(vnPercDescComercPromocao,0);
        -- Desconto do Produto a ser concedido no Boleto
        vnPerBoleto  := NVL(vnPercDescBoletoPromocao,0);

      ------------------------------------------------------------------------------
      -- Se Prioriza Desconto:
      -- Concede somente o Desconto Promocional caso exista, se não existir concede
      -- somente o Desconto da Linha da Condição de Venda
      ------------------------------------------------------------------------------
      ELSIF (NVL(vvTipoIncidencia,' ') = 'P') THEN

        -- Se encontrou Desconto Promocional, somente concederá no Produto os Descontos Promocionais
        IF ((NVL(vnPercDescComercPromocao,0) + NVL(vnPercDescBoletoPromocao,0)) > 0) THEN

          -- Desconto Total a ser concedido em Nota Fiscal
          vnPerDesc    := NVL(vnPercDescComercPromocao,0);
          -- Não concede Desconto de Bonificação em Nota Fiscal
          vnPerBonific := 0;
          -- Desconto Comercial a ser concedido em Nota Fiscal
          vnPerComerc  := NVL(vnPercDescComercPromocao,0);
          -- Desconto do produto a ser concedido no Boleto
          vnPerBoleto  := NVL(vnPercDescBoletoPromocao,0);

        -- Se não encontrou Desconto Promocional, somente concederá no Produto os Descontos da Linha da Condição de Venda
        ELSE

          -- Desconto Total a ser concedido em Nota Fiscal
          vnPerDesc    := F_CalcDescontoSobreDesconto(NVL(vnPercDescBonifLinha,0),
                                                      NVL(vnPercDescComercLinha,0));
          -- Desconto de Bonificação a ser concedido em Nota Fiscal
          vnPerBonific := NVL(vnPercDescBonifLinha,0);
          -- Desconto Comercial a ser concedido em Nota Fiscal
          vnPerComerc  := NVL(vnPercDescComercLinha,0);
          -- Desconto do produto a ser concedido no Boleto
          vnPerBoleto  := NVL(vnPercDescBoletoLinha,0);

        END IF;

      ------------------------------------------------------------------------------
      -- Se Ignora:
      -- Ignora o Desconto Promocional e concede somente o Desconto da Linha da
      -- Condição de Venda
      ------------------------------------------------------------------------------
      ELSIF (NVL(vvTipoIncidencia,' ') = 'I') THEN

        -- Desconto Total a ser concedido em Nota Fiscal
        vnPerDesc    := F_CalcDescontoSobreDesconto(NVL(vnPercDescBonifLinha,0),
                                                    NVL(vnPercDescComercLinha,0));
        -- Desconto de Bonificação a ser concedido em Nota Fiscal
        vnPerBonific := NVL(vnPercDescBonifLinha,0);
        -- Desconto Comercial a ser concedido em Nota Fiscal
        vnPerComerc  := NVL(vnPercDescComercLinha,0);
        -- Desconto do produto a ser concedido no Boleto
        vnPerBoleto  := NVL(vnPercDescBoletoLinha,0);

      ------------------------------------------------------------------------------
      -- Se Maior Desconto:
      -- Concede o maior desconto entre o Desconto Promocional e o Desconto da Linha
      -- da Condição de Venda
      ------------------------------------------------------------------------------
      ELSIF (NVL(vvTipoIncidencia,' ') = 'M') THEN

        -- Se o maior Desconto for o Promocional, concede o Desconto Promocional
        IF ((NVL(vnPercDescComercPromocao,0) + NVL(vnPercDescBoletoPromocao,0)) > NVL(vnPercDescTotalLinha,0)) THEN

          -- Desconto Total a ser concedido em Nota Fiscal
          vnPerDesc    := NVL(vnPercDescComercPromocao,0);
          -- Não concede Desconto de Bonificação em Nota Fiscal
          vnPerBonific := 0;
          -- Desconto Comercial a ser concedido em Nota Fiscal
          vnPerComerc  := NVL(vnPercDescComercPromocao,0);
          -- Desconto do produto a ser concedido no Boleto
          vnPerBoleto  := NVL(vnPercDescBoletoPromocao,0);

        -- Se o maior Desconto não for o Promocional, concede os Desconto da Linha da Condição de Venda
        ELSE

          -- Desconto Total a ser concedido em Nota Fiscal
          vnPerDesc    := F_CalcDescontoSobreDesconto(NVL(vnPercDescBonifLinha,0),
                                                      NVL(vnPercDescComercLinha,0));
          -- Desconto de Bonificação a ser concedido em Nota Fiscal
          vnPerBonific := NVL(vnPercDescBonifLinha,0);
          -- Desconto Comercial a ser concedido em Nota Fiscal
          vnPerComerc  := NVL(vnPercDescComercLinha,0);
          -- Desconto do produto a ser concedido no Boleto
          vnPerBoleto  := NVL(vnPercDescBoletoLinha,0);

        END IF;

      END IF;

     /*********************************
      Atualiza Retornos do Procedimento
      *********************************/
      po_nPerDesc     := NVL(vnPerDesc,0);
      po_nPerBonific  := NVL(vnPerBonific,0);
      po_nPerComerc   := NVL(vnPerComerc,0);
      po_nPerBoleto   := NVL(vnPerBoleto,0);
      po_nPercDescFin := NVL(vnPercDescFinLinha,0);
      pio_CodLinhaPrazo := vnCodLinhaPrazo; -- 155824

    END IF; -- Se Chamado para obter as Politicas de Desconto / Quantidade

  EXCEPTION
    WHEN e_Generico THEN
      -- Atualiza Retorno indicando que ocorreram erros
      po_vOcorreramErros := 'S';
    WHEN OTHERS THEN
      -- Atualiza Retorno indicando que ocorreram erros
      po_vOcorreramErros := 'S';
      po_vMsgErros       := 'Erro ao obter os descontos da Cond. Venda [' || pi_nCodCondicaoVenda || '] - ' || SQLCODE || '-' || SQLERRM;
  END PRC_VEN_OBTEM_DESC_CONDVENDA;

  /*******************************************************************************
                     INICIO DO PROCESSAMENTO PRINCIPAL
   *******************************************************************************/
  BEGIN

    -- Limpa Tabela Temporária (conforme Chamada)
    IF (pi_nTipoChamada IN (2,3,4)) THEN
      DELETE FROM PCMED_SELPROMOCAO;
      --COMMIT;
    END IF;

    -- Se passou a Praça do Cliente no Parâmetro
    IF (NVL(pi_nCodPraca,0) > 0) THEN
      -- Utiliza a Praça passada no Parâmetro
      vnCodPraca := pi_nCodPraca;
    -- Se não passou a Regiao do Cliente no Parâmetro
    ELSE
      -- Obtem Praca do Cliente
      -- e a Classe de venda
      BEGIN
        SELECT PCCLIENT.CODPRACA,
               PCCLIENT.CLASSEVENDA
          INTO vnCodPraca,
               vvClasseVenda
          FROM PCCLIENT
         WHERE (PCCLIENT.CODCLI = pi_nCodCli);
      EXCEPTION
        WHEN NO_DATA_FOUND THEN
          vnCodPraca    := NULL;
          vvClasseVenda := NULL;
      END;
    END IF;

    -- Se passou a Classe de Venda do Cliente
    IF    (pi_vClasseVenda IS NULL) THEN
      -- Utiliza a Classe de Venda do Cliente
      vvClasseVenda :=  pi_vClasseVenda;
    -- Se não passou a Classe de Venda do Cliente e ainda
    -- não foram pesquisados os dados do Cliente
    ELSIF (vvClasseVenda IS NULL) THEN
      -- Obtem a Classe de Venda do Cliente
      BEGIN
        SELECT PCCLIENT.CLASSEVENDA
          INTO vvClasseVenda
          FROM PCCLIENT
         WHERE (PCCLIENT.CODCLI = pi_nCodCli);
      EXCEPTION
        WHEN NO_DATA_FOUND THEN
          vvClasseVenda := NULL;
      END;
    END IF;

    -- Se passou a Regiao do Cliente no Parâmetro
    IF (NVL(pi_nNumRegiao,0) > 0) THEN
      -- Utiliza a Região passada no Parâmetro
      vnNumRegiao := pi_nNumRegiao;
    -- Se não passou a Regiao do Cliente no Parâmetro
    ELSE
      -- Obtem a Regiao do Cliente
      BEGIN
        SELECT PCPRACA.NUMREGIAO
          INTO vnNumRegiao
          FROM PCPRACA
         WHERE (PCPRACA.CODPRACA = vnCodPraca);
      EXCEPTION
        WHEN NO_DATA_FOUND THEN
          vnNumRegiao := NULL;
      END;
    END IF;

    -- Obtém a Qtde. de Casas Decimais
    BEGIN
      SELECT PCCONSUM.NUMCASASDECVENDA
        INTO vnNumCasasDecVenda
        FROM PCCONSUM;
    EXCEPTION
      WHEN NO_DATA_FOUND THEN
        vnNumCasasDecVenda := 2;
    END;

    -- Obtém a Qtde. de Dias do Plano de Pagamento
    BEGIN
      SELECT PCPLPAG.NUMDIAS
        INTO vnNumDias
        FROM PCPLPAG
       WHERE (PCPLPAG.CODPLPAG = pi_nCodPlPag);
    EXCEPTION
      WHEN NO_DATA_FOUND THEN
        vnNumDias := 0;
    END;

    -- Obtém Parâmetros da Filial
    BEGIN
      SELECT NVL(PCPARAMFILIAL.VALOR,'N')
        INTO vvNaoUsarAutDevCredPolDesc
        FROM PCPARAMFILIAL
       WHERE (PCPARAMFILIAL.CODFILIAL = pi_vCodFilial)
         AND (PCPARAMFILIAL.NOME      = 'NAOUSARAUTDEBCREDPOLDESC');
    EXCEPTION
      WHEN OTHERS THEN
        vvNaoUsarAutDevCredPolDesc := 'N';
    END;

    -- Obtém Parâmetros da Regra de Desconto Adicional para Plano Pagamento À Vista
    BEGIN
      SELECT NVL(PCPARAMFILIAL.VALOR,'N')
        INTO vvMedUsaDescAdicPlPAgVista
        FROM PCPARAMFILIAL
       WHERE (PCPARAMFILIAL.CODFILIAL = pi_vCodFilial)
         AND (PCPARAMFILIAL.NOME      = 'MEDUSADESCADICPLPAGVISTA');
    EXCEPTION
      WHEN OTHERS THEN
        vvNaoUsarAutDevCredPolDesc := 'N';
    END;
    IF (NVL(vvMedUsaDescAdicPlPAgVista,'N') = 'S') THEN
      BEGIN
        SELECT NVL(PCPARAMFILIAL.VALOR,'0')
          INTO vvMedPerDescAdicPlPagVista
          FROM PCPARAMFILIAL
         WHERE (PCPARAMFILIAL.CODFILIAL = pi_vCodFilial)
           AND (PCPARAMFILIAL.NOME      = 'MEDPERDESCADICPLPAGVISTA');
        vnMedPerDescAdicPlPagVista := TO_NUMBER(REPLACE(NVL(vvMedPerDescAdicPlPagVista,'0'),',','.'));
      EXCEPTION
        WHEN OTHERS THEN
          vnMedPerDescAdicPlPagVista := 0;
      END;
    ELSE
      vnMedPerDescAdicPlPagVista := 0;
    END IF;

    -- Chama Procedimento da para obter os Descontos
    PRC_VEN_OBTEM_DESC_CONDVENDA(pi_nTipoChamada,
                                 pi_nCodPromocaoMed,
                                 pi_nCodProd,
                                 pi_nQtde,
                                 pi_nCodCondicaoVenda,
                                 pi_nCodCli,
                                 pi_dData,
                                 pi_vCodFilial,
                                 vnNumRegiao,
                                 pi_nCodUsur,
                                 pi_vOrigemPed,
                                 pi_nCodProd,
                                 vnNumCasasDecVenda,
                                 pi_nCodPlPag,
                                 vnNumDias,
                                 vvClasseVenda,
                                 vnCodPraca,
                                 vvNaoUsarAutDevCredPolDesc,
                                 pi_vUsaPrioritaria,
                                 pi_vTipoFv,
                                 vvBasecreddebrca,
                                 vvCreditasobrepolitica,
                                 vvAlteraptabela,
                                 vnDescpbaserca,
                                 vvCreditaSobrePTabela_Quant,
                                 vnBaseDebCredRca_Quant,
                                 vnPercBaseRca_Quant,
                                 po_nPerDesc,
                                 po_nPerBonific,
                                 po_nPerComerc,
                                 po_nPerBoleto,
                                 po_nPercDescFin,
                                 po_vOcorreramErros,
                                 po_vMsgErros,
                                 po_nCodLinhaPrazo);

    -- HIS.03612.2015 - Se Chamado da Carga de Promoções e Usando Plano Pagto. a Vista
    IF (pi_nTipoChamada = 2)                   AND
       (vvMedUsaDescAdicPlPAgVista = 'S')      AND
       (NVL(vnMedPerDescAdicPlPagVista,0) > 0) THEN
      -- Verifica se existe alguma Promoção que não seja por Intervalo de Quantidade (Desconto ou Valor ou Bonificação)
      BEGIN
        SELECT 'S'
          INTO vvAchouSelPromocao
          FROM PCMED_SELPROMOCAO
         WHERE (PCMED_SELPROMOCAO.TIPOPOLITICA NOT IN ('Q','F','B','V'))
           AND (ROWNUM = 1);
      EXCEPTION
        WHEN NO_DATA_FOUND THEN
          vvAchouSelPromocao := 'N';
      END;
      -- Se não carregou Promoções
      IF (vvAchouSelPromocao = 'N') THEN
        BEGIN
          SELECT TIPOVENDA
            INTO vvTipoVenda
            FROM PCPLPAG
           WHERE (PCPLPAG.CODPLPAG = pi_nCodPlPag);
        EXCEPTION
          WHEN NO_DATA_FOUND THEN
            vvTipoVenda := NULL;
        END;
        -- Se Plano de Pagamento À Vista
        IF (vvTipoVenda = 'VV') THEN
          -- Insere Dados na Tabela Temporária
          BEGIN
            INSERT INTO PCMED_SELPROMOCAO
                      ( CODPROMOCAOMED
                      , CODDESCONTO
                      , TIPOPOLITICA
                      , DESCRICAORESUMIDA
                      , DESCRICAODETALHADA
                      , DATAINICIAL
                      , DATAFINAL
                      , APLICADESCONTO
                      , PERCDESC
                      , BASECREDDEBRCA
                      , PERCDESCFIN
                      , CREDITASOBREPOLITICA
                      , ALTERAPTABELA
                      , PRIORITARIA
                      , PERCDESCRESTRICAO
                      , CONSIDERACALCGIROMEDIC
                      , CONCEDERMAIORCOMISSREG
                      , ALTERADESCONTO
                      , ENCARTEFECHADO
                      , PRIORIZACOMISSAO
                      , INICIOINTERVALO
                      , FIMINTERVALO
                      , PRECOFIXO
                      , VALIDARINTERVALOVALIDADEPROD
                      , DTINICIOPROMOLOTE
                      , DTFIMPROMOLOTE
                      , TIPOPROMOCAO
                      , PARTICIPACOMISSGARANTIDA
                      , UTILIZAPERCDESCBASERCA
                      , PERMITIRAUMENTARQTDEKIT
                      , PERCDESCBASERCA
                      , ORIGEMPRECO
                      , PERCBONIFICMERC
                      , PROMOCAOMEDOBRIGATORIO )
               VALUES ( -1                         --CODPROMOCAOMED (-1 identifica Promoção à Vista)
                      , 0
                      , 'V'                        --TIPOPOLITICA = 'V' - Desconto Plano Pgto. à Vista
                      , 'Desc. Adicional à vista'  --DESCRICAORESUMIDA
                      , 'Desc. Adicional à vista'  --DESCRICAODETALHADA
                      , TRUNC(SYSDATE)             --DATAINICIAL
                      , TRUNC(SYSDATE)             --DATAFINAL
                      , 'S'                        --APLICADESCONTO
                      , vnMedPerDescAdicPlPagVista --percdesc
                      , 'N'                        --basecreddebrca
                      , 0                          --percdescfin
                      , 'N'                        --creditasobrepolitica
                      , 'N'                        --alteraptabela
                      , 'N'                        --prioritaria
                      , vnMedPerDescAdicPlPagVista --percdesc
                      , 'S'                        --consideracalcgiromedic
                      , 'N'                        --concedermaiorcomissreg
                      , 'S'                        --ALTERADESCONTO
                      , 'N'                        --ENCARTEFECHADO
                      , 'N'                        --PRIORIZACOMISSAO
                      , NULL                       --INICIOINTERVALOPROMOCAOMED
                      , NULL                       --FIMINTERVALOPROMOCAOMED
                      , NULL                       --precofixopromocaomed
                      , 'N'                        --VALIDARINTERVALOVALIDADEPROD
                      , NULL                       --DTINICIOPROMOLOTE
                      , NULL                       --DTFIMPROMOLOTE
                      , 'C'                        --TIPOPROMOCAO
                      , 'N'                        --participacomissgarantida
                      , 'N'                        --UTILIZAPERCDESCBASERCA
                      , 'N'                        --PERMITIRAUMENTARQTDEKIT
                      , NULL                       --percdescbaserca
                      , 'T'                        --ORIGEMPRECO
                      , NULL                       --PERCBONIFICMERC
                      , 'S'                        --PROMOCAOMEDOBRIGATORIO
                      );
          EXCEPTION
            WHEN DUP_VAL_ON_INDEX THEN
              NULL;
          END;
        END IF;
      END IF;
    END IF; -- Fim Condição HIS.03612.2015 - Se Chamado da Carga de Promoções e Usando Plano Pagto. a Vista

    -- Efetiva Transações (conforme Chamada)
    --IF (pi_nTipoChamada IN (2,3)) THEN
      --COMMIT;
    --END IF;

  EXCEPTION
    WHEN OTHERS THEN
      po_vMsgErros := 'S';
      po_vMsgErros := SQLERRM;
  END P_OBTEM_DESC_TELEVENDAS_01;

 /*******************************************************************************
   Nome         : P_APLICA_MULTIPLOS_BRINDES
   Descricão    : Aplicar Múltiplos Brindes para Promoções de Brindes Fixos
   Alteracão    : Anderson Silva - 08/06/2020 - Criação
  ********************************************************************************/
  PROCEDURE P_APLICA_MULTIPLOS_BRINDES IS
    
    -- Variáveis Auxiliares
    nATINGIDOPEDIDO NUMBER;
    nMULTIPLICADOR  NUMBER;
  
  BEGIN
  
    ----------------------------------------------------------------------------
    -- PROCESSA PROMOCOES DE CAMPANHA COM BRINDES FIXOS E QTDE MULTIPLA -------
    ----------------------------------------------------------------------------
  
    FOR vc_Promocao IN (SELECT SEL
                             , CODPROMOCAOMED
                             , DESCRICAOPROMOCAO
                             , TIPOPROMOCAO
                             , TIPOVALIDAVALORMIN
                             , TIPOCONCESSAOBRINDE
                             , MINIMOPEDIDO
                             , BRINDESCONCESSAO
                             , MULTIPLOSBRINDES
                             , ACEITADESCPROMCAMPANHA
                          FROM PCMED_PROMOCAO_CAMPANHA
                         WHERE (TIPOPROMOCAO = 'N')
                           AND (TIPOCONCESSAOBRINDE = 2)
                           AND (MULTIPLOSBRINDES = 'S')) LOOP
  
     /************************************************************************************************
                                     PRIMEIRA PARTE - TOTALIZA VALORES
      ************************************************************************************************/
  
      -----------------------------------------------------------------------------------------------
      -- Valor Atingindo no Pedido
      ----------------------------
  
      nATINGIDOPEDIDO := 0;
  
      -- Validação Valor Mínimo
      IF ((vc_Promocao.TIPOPROMOCAO = 'N') AND (vc_Promocao.TIPOVALIDAVALORMIN = 'V')) OR
          ((vc_Promocao.TIPOPROMOCAO IN ('V','F'))) THEN -- MED_VLMIN_FXQ - Adicionado 'F'
  
        -- Totaliza o Valor Total Líquido Vendido do Mix
        SELECT SUM(NVL(PCMED_PROMOCAO_CAMPANHA_MIX.VALORLIQUIDO,0))
          INTO nATINGIDOPEDIDO
          FROM PCMED_PROMOCAO_CAMPANHA_MIX
         WHERE (PCMED_PROMOCAO_CAMPANHA_MIX.CODPROMOCAOMEDREF = vc_Promocao.CODPROMOCAOMED);
  
      -- Validação Mix
      ELSIF ((vc_Promocao.TIPOPROMOCAO = 'N') AND (vc_Promocao.TIPOVALIDAVALORMIN = 'M')) OR
            ((vc_Promocao.TIPOPROMOCAO = 'M')) THEN
  
        -- Totaliza a Quantidade de SKus Vendidos
        SELECT COUNT(DISTINCT PCMED_PROMOCAO_CAMPANHA_MIX.CODPROD)
          INTO nATINGIDOPEDIDO
          FROM PCMED_PROMOCAO_CAMPANHA_MIX
         WHERE (PCMED_PROMOCAO_CAMPANHA_MIX.CODPROMOCAOMEDREF = vc_Promocao.CODPROMOCAOMED)
           AND (PCMED_PROMOCAO_CAMPANHA_MIX.QTDEVENDIDA > 0);
  
      -- Validação Quantidade Total
      ELSIF ((vc_Promocao.TIPOPROMOCAO = 'N') AND (vc_Promocao.TIPOVALIDAVALORMIN = 'Q')) THEN
  
        -- Totaliza a Quantidade Vendida do Mix
        SELECT SUM(NVL(PCMED_PROMOCAO_CAMPANHA_MIX.QTDEVENDIDA,0))
          INTO nATINGIDOPEDIDO
          FROM PCMED_PROMOCAO_CAMPANHA_MIX
         WHERE (PCMED_PROMOCAO_CAMPANHA_MIX.CODPROMOCAOMEDREF = vc_Promocao.CODPROMOCAOMED);
  
      -- Sem Validação, mas precisa mostrar o Valor Atingido (Brinde em % sobre a Venda)
      ELSIF ((vc_Promocao.TIPOPROMOCAO = 'N') AND (vc_Promocao.TIPOVALIDAVALORMIN = 'S') AND (vc_Promocao.TIPOCONCESSAOBRINDE = '3')) THEN
  
        -- Totaliza o Valor Total Líquido Vendido do Mix
        SELECT SUM(NVL(PCMED_PROMOCAO_CAMPANHA_MIX.VALORLIQUIDO,0))
          INTO nATINGIDOPEDIDO
          FROM PCMED_PROMOCAO_CAMPANHA_MIX
         WHERE (PCMED_PROMOCAO_CAMPANHA_MIX.CODPROMOCAOMEDREF = vc_Promocao.CODPROMOCAOMED);
  
      -- Sem Validação, mas precisa mostrar a quantidade de unidades atingidas (Brinde em Unidades )
      ELSIF ((vc_Promocao.TIPOPROMOCAO = 'N') AND (vc_Promocao.TIPOVALIDAVALORMIN = 'S') AND (vc_Promocao.TIPOCONCESSAOBRINDE IN ('1','2'))) THEN
  
        -- Totaliza a Quantidade Vendida do Mix
        SELECT SUM(NVL(PCMED_PROMOCAO_CAMPANHA_MIX.QTDEVENDIDA,0))
          INTO nATINGIDOPEDIDO
          FROM PCMED_PROMOCAO_CAMPANHA_MIX
         WHERE (PCMED_PROMOCAO_CAMPANHA_MIX.CODPROMOCAOMEDREF = vc_Promocao.CODPROMOCAOMED);
  
      END IF;
  
      -----------------------------------------------------------------------------------------------
      -- Brindes para Concessão - MULTIPLOS BRINDES
      ---------------------------------------------
  
      -- Calcula o Multiplicador nas Campanhas com Múltiplos Brindes
      nMULTIPLICADOR := FLOOR(NVL(nATINGIDOPEDIDO,0) / NVL(vc_Promocao.MINIMOPEDIDO,0));
    
      -----------------------------------------------------------------------------------------------
      -- Atualiza Qtde. de Brindes para Concessão
      -------------------------------------------

      -- Aplica Multiplicador
      IF (NVL(nMULTIPLICADOR,0) > 1) THEN
        FOR vc_Promo IN (SELECT PCPROMOCAOBRINDEMED.CAMPO
                              , PCPROMOCAOBRINDEMED.CODIGO
                              , PCPROMOCAOBRINDEMED.QTDE
                           FROM PCPROMOCAOBRINDEMED
                          WHERE (PCPROMOCAOBRINDEMED.CODPROMOCAOMED = vc_Promocao.CODPROMOCAOMED)
                            AND (PCPROMOCAOBRINDEMED.CAMPO          = 'PR')) LOOP
          UPDATE PCMED_PROMOCAO_CAMPANHA_BRI
             SET QTDEBRINDES = NVL(vc_Promo.QTDE,0) * NVL(nMULTIPLICADOR,0) 
           WHERE (PCMED_PROMOCAO_CAMPANHA_BRI.CODPROMOCAOMEDREF = vc_Promocao.CODPROMOCAOMED)
             AND (PCMED_PROMOCAO_CAMPANHA_BRI.CODPROD           = vc_Promo.CODIGO);
          UPDATE PCMED_PROMOCAO_CAMPANHA_INF
             SET QTDEBRINDES = NVL(vc_Promo.QTDE,0) * NVL(nMULTIPLICADOR,0)
           WHERE (PCMED_PROMOCAO_CAMPANHA_INF.CODPROMOCAOMEDREF = vc_Promocao.CODPROMOCAOMED)
             AND (PCMED_PROMOCAO_CAMPANHA_INF.CODPROD           = vc_Promo.CODIGO);
        END LOOP;
      END IF;
  
    END LOOP; -- Fim Laço Promoções
  
  EXCEPTION
    WHEN OTHERS THEN
      RAISE_APPLICATION_ERROR(-20000, DBMS_UTILITY.FORMAT_ERROR_BACKTRACE || ' >> ' || SQLERRM);
  END P_APLICA_MULTIPLOS_BRINDES;
    
 /**************************************************************
  DDMEDICA-7318 - Função para Retornar a Filial Retira do Brinde
  ***************************************************************/
  FUNCTION F_OBTEM_FILIAL_RETIRA_BRINDE(pi_vUSAESTOQUEDEPFECHADO IN VARCHAR2,
                                        pi_nCodProd              IN NUMBER,
                                        pi_vCodFilial            IN VARCHAR2,
                                        pi_vCodFilialRetira      IN VARCHAR2) 
  RETURN VARCHAR2 IS
    vvRetCodFilialRetiraBrinde PCFILIAL.CODIGO%TYPE;
  BEGIN
  
    vvRetCodFilialRetiraBrinde := NULL;
  
    -- Pesquisa a Filial Retira Padrão do Brinde
    IF (NVL(pi_vUSAESTOQUEDEPFECHADO,'N') = 'S') THEN
      BEGIN
        SELECT PCPRODFILIAL.CODFILIALRETIRA
          INTO vvRetCodFilialRetiraBrinde
          FROM PCPRODFILIAL
         WHERE (PCPRODFILIAL.CODFILIAL = pi_vCodFilial)
           AND (PCPRODFILIAL.CODPROD   = pi_nCodProd);
      EXCEPTION
        WHEN NO_DATA_FOUND THEN
          vvRetCodFilialRetiraBrinde := NULL;
      END;     
      
      -- Se não tiver na PCPRODFILIAL pega do parâmetro
      IF (vvRetCodFilialRetiraBrinde IS NULL) THEN
        vvRetCodFilialRetiraBrinde := NVL(pi_vCodFilialRetira,pi_vCodFilial);
      END IF;
    END IF;

    RETURN vvRetCodFilialRetiraBrinde;

  END F_OBTEM_FILIAL_RETIRA_BRINDE;
  
  -------------------------------------------------------------
  -- Função para buscar parâmetro de Licitação - DDVENDAS-33442
  -------------------------------------------------------------
  FUNCTION F_OBTEM_PARAM_LICITACAO(pi_vNome    IN VARCHAR2,
                                   pi_vDefault IN VARCHAR2)
  RETURN VARCHAR2 IS
    vvRetParamLicitacao VARCHAR2(1);
  BEGIN
    -- Verifica se usa regra
    BEGIN
      EXECUTE IMMEDIATE ' SELECT ' || pi_vNome || ' FROM PCCONFIGLICITACAO WHERE CODFILIAL = ' || '''' || '99' || ''''
                   INTO vvRetParamLicitacao;
    EXCEPTION
      WHEN NO_DATA_FOUND THEN
        vvRetParamLicitacao := pi_vDefault;
      WHEN OTHERS THEN
        vvRetParamLicitacao := pi_vDefault;
    END;
    IF (vvRetParamLicitacao IS NULL) THEN
      vvRetParamLicitacao := pi_vDefault;
    END IF;
    -- Retorno
    RETURN vvRetParamLicitacao;
  END F_OBTEM_PARAM_LICITACAO;  

  ------------------------------------------------------------------------------------------------------------------
  -- Função para Substituir Caracteres Acentuados por Não Acentuados e Remover Caracteres Especiais - DDVENDAS-33442
  ------------------------------------------------------------------------------------------------------------------
  FUNCTION F_LICIT_ACENTO_CHAR_ESPECIAL (pi_Texto IN VARCHAR2)
  RETURN VARCHAR2
  IS
  
    -- Variáveis auxiliares
    vvComAcento VARCHAR2(38);
    vvSemAcento VARCHAR2(38);
    vvEspecial  VARCHAR2(48);
    vvSaida     VARCHAR2(4000);
  
  BEGIN
     
    -- Caracteres Acentuados 
    vvComAcento := 'áàãâäÁÀÃÂÄéèÉÈíìÍÌóòöõôÓÒÖÕÔúùüÚÙÜçÇñÑ';
    -- Caracteres Sem Acentuação para Substituir os Acentuados
    vvSemAcento := 'aaaaaAAAAAeeEEiiIIoooooOOOOOuuuuuucCnN';
    -- Caracteres Especiais
    vvEspecial := '<>!@#$%¨&*()_+={}[]?;:,|*"~^´`¨æÆø£Ø¿ªº¿®½¼ßµþýÝ';
    -- Retorno
    vvSaida := '';
    
    -- Se o Texto não estiver vazio
    IF LENGTH(pi_Texto) > 0 THEN
       
      -- Laço para Percorrer a String 
      FOR X IN 1..LENGTH(pi_Texto)
        LOOP
        
          -- Se for um caractere acentuado
          IF INSTR(vvComAcento,SUBSTR(pi_Texto,x,1)) > 0 THEN
            -- Substitui pelo mesmo caractere sem acentuação
            vvSaida := vvSaida || SUBSTR(vvSemAcento,(INSTR(vvComAcento,SUBSTR(pi_Texto,x,1))),1);
            
          -- Se for um caractere especial
          ELSIF INSTR(vvEspecial,SUBSTR(pi_Texto,x,1)) > 0 THEN
            -- Substitui por um espaço em branco
            vvSaida := vvSaida || ' ';
              
          ELSE
            vvSaida := vvSaida || SUBSTR(pi_Texto,x,1);
            
          END IF; -- Fim-Se Caractere Acentuado/Especial 
      END LOOP; -- Fim do Laço para percorrer a String
    END IF ; -- Fim-Se Texto > 0
    
    -- Retorna Texto Tratado
    RETURN vvSaida;
    
  END F_LICIT_ACENTO_CHAR_ESPECIAL;
  
 /*******************************************************************************
  Nome         : P_VALIDA_PROMOCAO
  Descricão    : Procedimento para validar a Promoção
  Parâmetros   : ENTRADA:
                 pi_nTipoChamada          = 1  - Validação na Gravação do Pedido
                                            2  - Inserir Itens KIT
                                            3  - Gerar Pedido de Licitação
                                            4  - Alterar Promoção do Pedido
                                            5  - Aplicar Desconto Adicional Plano A Vista
                                            6  - Aplicar as Bonificações de Promoção em TV1
                                            7  - Excluir as Bonificações de Promoção em TV1 (Alteração do Pedido)
                                            8  - Consultar as Futuras Bonificações de Promoção em TV1
                                            9  - Aplicar a Promoção Casadinha
                                            10 - Recalcular o Pedido ao alterar Plano de Pagamento
                                            11 - Recuperando itens do Orçamento
                                            12 - Atualização de Preços de Brinde
                                            13 - Carga da Tabela de Campanhas com todos os Brindes
                                            14 - Carga da Tabela de Mix/Valor
                                            15 - Aplicar as Bonificações de Promoção por Campanha
                                            16 - Incluir Itens Cross Docking
                                            17 - Incluir Itens Importação
                                            18 - Pedido Licitação sem a pcpedc
                 pi_nNumPed               = Número do Pedido
                 pi_nCodCli               = Código do Cliente
                 pi_nCodUsur              = Código do RCA
                 pi_vCodFilial            = Código da Filial
                 pi_nNumRegiao            = Número da Região
                 pi_nCondVenda            = Tipo de Venda
                 pi_nCodPlPag             = Condição de Pagamento
                 pi_nCodPromocaoMedPedido = Código da Promoção do Pedido
                 pi_vPosicao              = Posição do Pedido
                                            (OBS: Na chamada 10, este campo poderá receber o Tipo de Plano de Pagamento - 'E' - Etico; 'G'-Genérico; 'N'-Normal)
                 pi_nOpcaoTipoEntrega     = Opção de Tipo de Entrega
                 pi_nRotinaLanc           = Rotina de Lançamento
                 pi_nQtCombos             = Quantidade de Combos
                 pi_vCodFilialNF          = Código da Filial NF
                 pi_vCodCob               = Código da Cobrança
                 pi_nCodEdital            = Código do Edital
                 pi_nNumEmpenho           = Número do Empenho
                 pi_nCodMatricula         = Código da Matrícula
                 pi_vVisualizarPromoBloq  = Se Funcionário Visualiza Promoção Bloqueada
                 pi_nCodProd              = Código do Produto para uso nas Promoções Casadinhas
                 pi_nCodPlPagEtico        = Código do Plano de Pagamento Ético - utilizado ao recalcular o pedido
                 pi_nCodPlPagGenerico     = Código do Plano de Pagamento Ético - utilizado ao recalcular o pedido
                 pi_nNumOrcamento         = Número do orçamento
                 SAIDA:
                 po_vPodeGravarPedido     = Se pode gravar o Pedido
                                            [S-Sim;N-Não]
                 po_vMotivoNaoPodeGravar  = Descrição do Motivo de não poder gravar o
                                            Pedido
  Observações  : Na Inclusão do Item, está obedecendo a Comissão da Promoção
                 Depois colocar Plano Ético e Genérico
                 Percbonificvenda por regiao
                 Taxas ptabela
                 Anderson Silva - 02/11/2019 - DDMEDICA-1212 - Permitir Qtde. Mín. sem Obrigatório
  ********************************************************************************/
  PROCEDURE P_VALIDA_PROMOCAO(pi_nTipoChamada          IN  NUMBER,
                              pi_nNumPed               IN  NUMBER,
                              pi_nCodCli               IN  NUMBER,
                              pi_nCodUsur              IN  NUMBER,
                              pi_vCodFilial            IN  VARCHAR2,
                              pi_nNumRegiao            IN  NUMBER,
                              pi_nCondVenda            IN  NUMBER,
                              pi_nCodPlPag             IN  NUMBER,
                              pi_nCodPromocaoMedPedido IN  NUMBER,
