    -------------------------------------------------------------------
    -- Procedimento para Consulta da Verba CMV do Cliente - MED-2453
    -------------------------------------------------------------------
    PROCEDURE P_CALCULARPERCVERBACMV(p_codprod             IN NUMBER,
                                     p_codsec              IN NUMBER,
                                     p_codepto             IN NUMBER,
                                     p_data                IN DATE,
                                     p_codcli              IN NUMBER,
                                     p_numcasasdecvenda    IN NUMBER,
                                     p_codrede             IN NUMBER,
                                     p_codpromocaomed      IN NUMBER,
                                     p_alteracontacorrente OUT VARCHAR2,
                                     p_percverba           OUT NUMBER) IS

      vnpercverba           NUMBER;
      vsalteracontacorrente VARCHAR2(1);
      vicont                NUMBER;

     /************************************************************
      Função para Retornar se Isento Rebaixa CMV
      ***********************************************************/
      FUNCTION F_ISENTOREBAIXACMV(pi_nCodPromocaoMed IN NUMBER) RETURN BOOLEAN IS
        vISENTOREBAIXACMV PCPROMOCAOMED.ISENTOREBAIXACMV%TYPE;
      BEGIN
      
        BEGIN
          SELECT NVL(ISENTOREBAIXACMV,'N') ISENTOREBAIXACMV
            INTO vISENTOREBAIXACMV
            FROM PCPROMOCAOMED
           WHERE (CODPROMOCAOMED = pi_nCodPromocaoMed);       
        EXCEPTION
          WHEN NO_DATA_FOUND THEN
            vISENTOREBAIXACMV := 'N';
        END;
        
        RETURN (NVL(vISENTOREBAIXACMV,'N') = 'S');
        
      END F_ISENTOREBAIXACMV;                                       

    BEGIN

      vnpercverba           := 0;
      vsalteracontacorrente := 'N';

      IF (NOT F_ISENTOREBAIXACMV(p_codpromocaomed)) THEN

        SELECT COUNT(*)
          INTO vicont
          FROM pcpoliticaverbacmv
         WHERE p_data BETWEEN dtinicio AND dtfim
           AND ((codepto = p_codepto) OR (codepto IS NULL))
           AND ((codsec = p_codsec) OR (codsec IS NULL))
           AND ((codprod = p_codprod) OR (codprod IS NULL))
           AND ((codcli = p_codcli) OR (codcli IS NULL) OR (codcli = 0))
           and ((codrede = p_codrede) OR (codrede IS null));

        IF vicont > 0 THEN

         begin
          SELECT MAX(percverbacmv)
            INTO vnpercverba
            FROM pcpoliticaverbacmv
           WHERE p_data BETWEEN dtinicio AND dtfim
             AND ((codepto = p_codepto) OR (codepto IS NULL))
             AND ((codsec = p_codsec) OR (codsec IS NULL))
             AND ((codprod = p_codprod) OR (codprod IS NULL))
             AND ((codcli = p_codcli) OR (codcli IS NULL) OR (codcli = 0) )
             and ((codrede = p_codrede) OR (codrede IS null));
           exception when others then

             vnpercverba := 0;

           end;

           select pcpoliticaverbacmv.alteracontacorrente
            INTO vsalteracontacorrente
            FROM pcpoliticaverbacmv
           WHERE p_data BETWEEN dtinicio AND dtfim
             AND ((codepto = p_codepto) OR (codepto IS NULL))
             AND ((codsec = p_codsec) OR (codsec IS NULL))
             AND ((codprod = p_codprod) OR (codprod IS NULL))
             AND ((codcli = p_codcli) OR (codcli IS NULL) OR (codcli = 0) )
             and ((codrede = p_codrede) OR (codrede IS null))
             and  percverbacmv = vnpercverba;

        END IF;

      END IF;

      p_percverba            := round(vnpercverba, p_numcasasdecvenda);
      p_alteracontacorrente  := vsalteracontacorrente;

    END P_CALCULARPERCVERBACMV;

    -----------------------------------------------------------------------------
    -- Funcão para Regra Específica: Se Utiliza o Percentual de Desconto da Base
    --                               do RCA gravado na Importação do Pedido do FV
    -----------------------------------------------------------------------------
    FUNCTION FUtilizarPercDescBaseRCAOrigFv(pi_vOrigemPed                  IN VARCHAR2,
                                            pi_vUSARECALCULOPRECOTELEVENDA IN VARCHAR2,
                                            pi_vTipoComissaoMed            IN VARCHAR2)
    RETURN BOOLEAN IS
      vbRetUtilizarPercDescBaseRCAFv BOOLEAN;
    BEGIN
      vbRetUtilizarPercDescBaseRCAFv := ((pi_vOrigemPed = 'F') AND
                                         (pi_vUSARECALCULOPRECOTELEVENDA = 'S') AND
                                         (SUBSTR(pi_vTipoComissaoMed,1,1) = 'F'));
      RETURN vbRetUtilizarPercDescBaseRCAFv;
    END FUtilizarPercDescBaseRCAOrigFv;

    ------------------------------------------------------------------------------
    -- Procedimento para Inserir Log
    ------------------------------------------------------------------------------
    PROCEDURE P_INSERE_LOG(pi_iLacoValidar IN INTEGER,
                           pi_vMensagem    IN VARCHAR2) IS
    BEGIN
      IF (pi_iLacoValidar = 2) THEN
        IF (pi_vMensagem IS NOT NULL) THEN
          BEGIN
            vvLogProcGeral := vvLogProcGeral || CHR(13) || pi_vMensagem;
          EXCEPTION
            WHEN OTHERS THEN
              NULL;
          END;
        END IF;
      END IF;
    END P_INSERE_LOG;

    ------------------------------------------------------------------------------
    -- Procedimento para Gravar Log
    ------------------------------------------------------------------------------
    PROCEDURE P_GRAVA_LOG(pi_iLacoValidar IN INTEGER) 
    IS PRAGMA AUTONOMOUS_TRANSACTION;
    BEGIN
      IF (pi_iLacoValidar = 2) THEN
        IF (vvLogProcGeral IS NOT NULL) THEN
          BEGIN
            INSERT INTO PCLOGPROCFATURMED
                      ( DTLOG,
                        NUMPED,
                        NUMCAR,
                        NUMTRANSVENDA,
                        OBSERVACAO )
               VALUES ( SYSDATE,
                        pi_nNumPed,
                        -3,
                        -3,
                        vvLogProcGeral );
            COMMIT;
          EXCEPTION
            WHEN OTHERS THEN
              NULL;
          END;
        END IF;
      END IF;
    END P_GRAVA_LOG;

    ------------------------------------------------------------------------------
    -- Procedimento para Verificar se Calculará ICMS Partilha
    ------------------------------------------------------------------------------
    FUNCTION F_EXISTEICMSPARTILHA(pi_nCodCli      IN NUMBER,
                                  pi_vCodFilial   IN VARCHAR2,
                                  pi_vCodFilialNf IN VARCHAR2,
                                  pi_vEstEntrega  IN VARCHAR2) -- DDVENDAS-33920
    RETURN BOOLEAN IS
      vvCodFilial       PCFILIAL.CODIGO%TYPE;
      vvPartilha        VARCHAR2(1);
    BEGIN

      -- Código Filial
      IF (pi_vCodFilialNf IS NOT NULL) THEN
        vvCodFilial := pi_vCodFilialNf;
      ELSE
        vvCodFilial := pi_vCodFilial;
      END IF;

      -- Pesquisa Dados do Cliente e Filial
      BEGIN
        SELECT CASE WHEN (NVL(PCCLIENT.CONSUMIDORFINAL,'N') = 'S')          AND
                         (NVL(PCCLIENT.CONTRIBUINTE,'N')    = 'N')          AND
                         (NVL(NVL(pi_vEstEntrega,PCCLIENT.ESTENT),' ') <> NVL(PCFILIAL.UF,' ')) THEN -- DDVENDAS-33920
                  'S'
                ELSE
                  'N'
                END PARTILHA
          INTO vvPartilha
          FROM PCCLIENT
             , PCFILIAL
         WHERE (PCCLIENT.CODCLI = pi_nCodCli)
           AND (PCFILIAL.CODIGO = vvCodFilial);
      EXCEPTION
        WHEN NO_DATA_FOUND THEN
          vvPartilha := 'N';
      END;

      -- Retorno
      RETURN (NVL(vvPartilha,'N') = 'S');

    END F_EXISTEICMSPARTILHA;

    ------------------------------------------------------------------------------
    -- Procedimento para Calcular os Totais do Pedido
    ------------------------------------------------------------------------------
    PROCEDURE PTOTAIS_PEDIDO(pi_nNumPed IN NUMBER) IS
      -- Declaração de Tipos de Variáveis
      TYPE TT_PED_NUMPED    IS TABLE OF PCPEDI.NUMPED%TYPE INDEX BY BINARY_INTEGER;
      TYPE TT_PED_CODFILIAL IS TABLE OF PCPEDC.CODFILIAL%TYPE INDEX BY BINARY_INTEGER;
      TYPE TT_PED_CODPROD   IS TABLE OF PCPEDI.CODPROD%TYPE INDEX BY BINARY_INTEGER;
      TYPE TT_PED_QT        IS TABLE OF PCPEDI.QT%TYPE INDEX BY BINARY_INTEGER;
      TYPE TT_PED_DTSAIDA   IS TABLE OF DATE INDEX BY BINARY_INTEGER;
      -- Declaração de Variáveis
      vtPED_NUMPED          TT_PED_NUMPED;
      vtPED_CODFILIAL       TT_PED_CODFILIAL;
      vtPED_CODPROD         TT_PED_CODPROD;
      vtPED_QT              TT_PED_QT;
      vtPED_DTSAIDA         TT_PED_DTSAIDA;
      -- Tipo de Venda
      vnCondVenda           PCPEDC.CONDVENDA%TYPE;
    BEGIN

      -- Pesquisa o Tipo de Venda do Pedido
      BEGIN
        SELECT PCPEDC.CONDVENDA
          INTO vnCondVenda
          FROM PCPEDC
         WHERE (PCPEDC.NUMPED = pi_nNumPed);
      EXCEPTION
        WHEN NO_DATA_FOUND THEN
          vnCondVenda := 0; -->> Como é somente para Tratar a Bonificação em TV1, se não achar PCPEDC colocar 0 (zero) para não preencher o VLBONIFIC
      END;

      -- Calcula os Totais do Pedido
      SELECT SUM((NVL(PCPEDI.QT,0) * NVL(PCPEDI.PVENDA,0)))
           , COUNT(*)
           , SUM((NVL(PCPEDI.QT,0) * NVL(PCPEDI.VLCUSTOFIN,0)))
           , SUM((NVL(PCPEDI.QT,0) * NVL(PCPEDI.VLCUSTOREAL,0)))
           , SUM((NVL(PCPEDI.QT,0) * NVL(PCPRODUT.PESOBRUTO,0)))
           , SUM((NVL(PCPEDI.QT,0) * NVL(PCPRODUT.VOLUME,0)))
           , SUM((NVL(PCPEDI.QT,0) * NVl(PCPEDI.VLCUSTOCONT,0)))
           , SUM((NVL(PCPEDI.QT,0) * NVL(PCPEDI.VLCUSTOREP,0)))
           , SUM((NVL(PCPEDI.QT,0) * NVL(PCPEDI.PTABELA,0)))
           , SUM(((NVL(PCPEDI.QT,0) + NVL(PCPEDI.QTFALTA,0)) * NVL(PCPEDI.PVENDA,0)))
           , SUM(DECODE(vnCondVenda, 1, ROUND(NVL(PCPEDI.QT, 0) * DECODE(NVL(PCPEDI.BONIFIC,'N'),'F',NVL(PCPEDI.PBONIFIC,0),0),2),
                                     5, ROUND(NVL(PCPEDI.QT, 0) * NVL(PCPEDI.PVENDA, 0),2),
                                    11, ROUND(NVL(PCPEDI.QT, 0) * NVL(PCPEDI.PVENDA, 0),2),
                                        0)) VLBONIFIC
        INTO vrPedido.nVLATEND
           , vrPedido.nNUMITENS
           , vrPedido.nVLCUSTOFIN
           , vrPedido.nVLCUSTOREAL
           , vrPedido.nTOTPESO
           , vrPedido.nTOTVOLUME
           , vrPedido.nVLCUSTOCONT
           , vrPedido.nVLCUSTOREP
           , vrPedido.nVLTABELA
           , vrPedido.nVLTOTAL
           , vrPedido.nVLBONIFIC
        FROM PCPEDI
           , PCPRODUT
       WHERE (PCPEDI.CODPROD = PCPRODUT.CODPROD)
         AND (NUMPED = pi_nNumPed);

      -- Valores não implementados na Licitação
      vrPedido.nVLOUTRASDESP  := 0;
      vrPedido.nVLFRETE       := 0;
      vrPedido.nVLDESCONTO    := 0;

      -- Complementa alguns Totais com Valores de Cabeçalho
      vrPedido.nVLATEND       := NVL(vrPedido.nVLATEND,0) - NVL(vrPedido.nVLDESCONTO,0) + NVL(vrPedido.nVLOUTRASDESP,0) + NVL(vrPedido.nVLFRETE,0);
      vrPedido.nVLTABELA      := NVL(vrPedido.nVLTABELA,0) + NVL(vrPedido.nVLOUTRASDESP,0) + NVL(vrPedido.nVLFRETE,0);
      vrPedido.nVLTOTAL       := NVL(vrPedido.nVLTOTAL,0) - NVL(vrPedido.nVLDESCONTO,0) + NVL(vrPedido.nVLOUTRASDESP,0) + NVL(vrPedido.nVLFRETE,0);

      -- Atualiza PCPEDC
      UPDATE PCPEDC
         SET PCPEDC.VLATEND       = vrPedido.nVLATEND
           , PCPEDC.NUMITENS      = vrPedido.nNUMITENS
           , PCPEDC.VLCUSTOFIN    = vrPedido.nVLCUSTOFIN
           , PCPEDC.VLCUSTOREAL   = vrPedido.nVLCUSTOREAL
           , PCPEDC.TOTPESO       = vrPedido.nTOTPESO
           , PCPEDC.TOTVOLUME     = vrPedido.nTOTVOLUME
           , PCPEDC.VLCUSTOCONT   = vrPedido.nVLCUSTOCONT
           , PCPEDC.VLCUSTOREP    = vrPedido.nVLCUSTOREP
           , PCPEDC.VLTABELA      = vrPedido.nVLTABELA
           , PCPEDC.VLTOTAL       = vrPedido.nVLTOTAL
           , PCPEDC.VLOUTRASDESP  = vrPedido.nVLOUTRASDESP
           , PCPEDC.VLFRETE       = vrPedido.nVLFRETE
           , PCPEDC.VLDESCONTO    = vrPedido.nVLDESCONTO
           , PCPEDC.VLBONIFIC     = vrPedido.nVLBONIFIC
       WHERE (PCPEDC.NUMPED = pi_nNumPed);

    END PTOTAIS_PEDIDO;

    ------------------------------------------------------------------------------
    -- Procedimento para Obter o Parâmetro da Filial STRING
    ------------------------------------------------------------------------------
    PROCEDURE POBTEM_PARAMFILIAL_STRING(pi_vCodFilial IN  VARCHAR2,
                                        pi_vNomeCampo IN  VARCHAR2,
                                        po_vValor     OUT VARCHAR2,
                                        po_vErro      OUT VARCHAR2,
                                        po_vMsgErro   OUT VARCHAR2) IS
    BEGIN
      -- Inicializa Retornos
      po_vValor   := 0;
      po_vErro    := 'N';
      po_vMsgErro := NULL;

      -- Pesquisa Parametro
      BEGIN
        SELECT PCPARAMFILIAL.VALOR
          INTO po_vValor
          FROM PCPARAMFILIAL
         WHERE (PCPARAMFILIAL.CODFILIAL = pi_vCodFilial)
           AND (PCPARAMFILIAL.NOME      = pi_vNomeCampo);
      EXCEPTION
        WHEN NO_DATA_FOUND THEN
          po_vErro    := 'S';
          po_vMsgErro := 'Não foi encontrado o parâmetro "' || pi_vNomeCampo || '" na filial ' || pi_vCodFilial;
          po_vValor   := NULL;
      END;

    END POBTEM_PARAMFILIAL_STRING;

    ------------------------------------------------------------------------------
    -- Procedimento para Obter o Parâmetro da Filial NUMBER
    ------------------------------------------------------------------------------
    PROCEDURE POBTEM_PARAMFILIAL_NUMBER(pi_vCodFilial IN  VARCHAR2,
                                        pi_vNomeCampo IN  VARCHAR2,
                                        po_nValor     OUT NUMBER,
                                        po_vErro      OUT VARCHAR2,
                                        po_vMsgErro   OUT VARCHAR2) IS

      vvValorString PCPARAMFILIAL.VALOR%TYPE;

    BEGIN
      -- Inicializa Retornos
      po_nValor   := 0;
      po_vErro    := 'N';
      po_vMsgErro := NULL;

      -- Pesquisa Parametro
      BEGIN
        SELECT PCPARAMFILIAL.VALOR
          INTO vvValorString
          FROM PCPARAMFILIAL
         WHERE (PCPARAMFILIAL.CODFILIAL = pi_vCodFilial)
           AND (PCPARAMFILIAL.NOME      = pi_vNomeCampo);
      EXCEPTION
        WHEN NO_DATA_FOUND THEN
          po_vErro      := 'S';
          po_vMsgErro   := 'Não foi encontrado o parâmetro "' || pi_vNomeCampo || '" na filial ' || pi_vCodFilial;
          vvValorString := NULL;
      END;

      -- Se não ocorreu erro ao pesquisar o parâmetro
      IF (po_vErro = 'N') THEN

        -- Tira Espaços em Branco do Valor
        vvValorString := TRIM(vvValorString);
        IF (vvValorString IS NULL) THEN
          vvValorString := '0';
        END IF;

        -- Converte String para Number
        BEGIN
          po_nValor := TO_NUMBER(vvValorString);
        EXCEPTION
          WHEN OTHERS THEN
            po_vErro      := 'S';
            po_vMsgErro   := 'Erro ao converter em numérico o texto "' || vvValorString || '" do parâmetro "' || pi_vNomeCampo || '" na filial ' || pi_vCodFilial;
            po_nValor     := 0;
        END;

      END IF; -- Fim Condição Se não ocorreu erro ao pesquisar o parâmetro

    END POBTEM_PARAMFILIAL_NUMBER;

    ------------------------------------------------------------------------------
    -- Procedimento para Excluir Itens Bonificados
    ------------------------------------------------------------------------------
    PROCEDURE PEXCLUI_ITENSBONIFIC(pi_nNumPed IN NUMBER) IS
    BEGIN

      -- Excluir Registros do Pedido de Promoções de Bonificação
      DELETE FROM PCPEDI
       WHERE (NUMPED  = pi_nNumPed)
         AND (BONIFIC = 'F') -->> Somente Registros de Bonificação em TV1
         AND (CODPROMOCAOMED IN (SELECT CODPROMOCAOMED FROM PCPROMOCAOMED WHERE TIPOPROMOCAO = 'B'));

    END PEXCLUI_ITENSBONIFIC;

    ------------------------------------------------------------------------------
    -- Procedimento para Excluir Itens Bonificados de Campanha
    ------------------------------------------------------------------------------
    PROCEDURE PEXCLUI_ITENSCAMPANHA(pi_nNumPed IN NUMBER) IS
    BEGIN

      -- Excluir Registros do Pedido de Promoções de Bonificação
      DELETE FROM PCPEDI
       WHERE (NUMPED  = pi_nNumPed)
         AND (BONIFIC = 'F') -->> Somente Registros de Bonificação em TV1
         AND (CODPROMOCAOMED IN (SELECT CODPROMOCAOMED FROM PCPROMOCAOMED WHERE TIPOPROMOCAO = 'N'));

    END PEXCLUI_ITENSCAMPANHA;

    -----------------------------------------------------------------------------------------
    -- Função para verificar se pode editar Item que movimentou saldo rca no FV
    -----------------------------------------------------------------------------------------
    FUNCTION F_EDITAR_ITEM_MOV_SALDORCA(pi_vBLOQEDICAOITENSMOVSALDORCA IN VARCHAR2,
                                        pi_nOrigemPed                  IN VARCHAR2,
                                        pi_vTipoFv                     IN VARCHAR2,
                                        pi_nNumPed                     IN NUMBER,
                                        pi_nCodProd                    IN NUMBER,
                                        pi_nNumSeq                     IN NUMBER,
                                        pi_vBonific                    IN VARCHAR2)
    RETURN BOOLEAN IS
      vbRetEditarItemMovSaldoRca BOOLEAN;
      TYPE TRecLogRca            IS RECORD(
      vvMovimentouSaldoRca       VARCHAR2(1),
      vvAutorizouEdicao          VARCHAR2(1));
      vrLogRca                   TRecLogRca;
    BEGIN

      -- Inicializa Retorno indicando que pode editar Item do Pedido
      vbRetEditarItemMovSaldoRca := TRUE;

      -- Se Item Bonificado em TV1
      IF (NVL(pi_vBonific,'N') = 'F') THEN

        -- NÃO PODE EDITAR O ITEM DO PEDIDO
        vbRetEditarItemMovSaldoRca := FALSE;

      ELSE

        -- Se a Empresa Bloqueia Edição de Itens do Pedido que Movimentaram Saldo RCA
        IF (pi_vBLOQEDICAOITENSMOVSALDORCA = 'S') THEN

          -- Se Força de Vendas
          IF (pi_nOrigemPed = 'F')   AND
             (pi_vTipoFv    IS NULL) THEN

            -- Verifica se pode Editar o Item do Pedido
            BEGIN
             /*
              SELECT DECODE(((NVL(PCLOGRCA.PVENDA,0)-NVL(PCLOGRCA.ST,0)) - (NVL(PCLOGRCA.PBASERCA,0)-NVL(PCLOGRCA.STPBASERCA,0))),0,'N','S') MOVIMENTOUSALDORCA
                   , NVL(PCLOGRCA.AUTORIZEDICAOITEMPEDMED,'N') AUTORIZEDICAOITEMPEDMED
                INTO vvMovimentouSaldoRca
                   , vvAutorizouEdicao
                FROM PCLOGRCA
               WHERE (PCLOGRCA.NUMPED  = pi_nNumPed)
                 AND (PCLOGRCA.CODPROD = pi_nCodProd)
                 AND (PCLOGRCA.NUMSEQ  = pi_nNumSeq)
                 AND (PCLOGRCA.ROTINA  IN (2513))
                 AND (ROWNUM           = 1);
              */
              vvSql := 'SELECT DECODE(((NVL(PCLOGRCA.PVENDA,0)-NVL(PCLOGRCA.ST,0)) - (NVL(PCLOGRCA.PBASERCA,0)-NVL(PCLOGRCA.STPBASERCA,0))),0,''N'',''S'')
                             , NVL(PCLOGRCA.AUTORIZEDICAOITEMPEDMED,''N'')
                          FROM PCLOGRCA
                         WHERE (PCLOGRCA.NUMPED  = ' || NVL(pi_nNumPed,0)  || ')
                           AND (PCLOGRCA.CODPROD = ' || NVL(pi_nCodProd,0) || ')
                           AND (PCLOGRCA.NUMSEQ  = ' || NVL(pi_nNumSeq,0)  || ')
                           AND (PCLOGRCA.ROTINA  IN (2513))
                           AND (ROWNUM           = 1)';
              EXECUTE IMMEDIATE vvSql
                           INTO vrLogRca;
            EXCEPTION
              WHEN NO_DATA_FOUND THEN
                vrLogRca.vvMovimentouSaldoRca := 'N';
                vrLogRca.vvAutorizouEdicao    := 'S';
            END;

            -- Se Movimentou Saldo e Não Autorizou
            IF (vrLogRca.vvMovimentouSaldoRca = 'S') AND
               (vrLogRca.vvAutorizouEdicao    = 'N') THEN
              -- NÃO PODE EDITAR O ITEM DO PEDIDO
              vbRetEditarItemMovSaldoRca := FALSE;
            END IF;

          END IF;

        END IF; -- Fim Condição Se a Empresa Bloqueia Edição de Itens do Pedido que Movimentaram Saldo RCA

      END IF; -- Fim Condição Se Item Bonificado em TV1

      -- Retorno
      RETURN vbRetEditarItemMovSaldoRca ;

    END F_EDITAR_ITEM_MOV_SALDORCA;

    PROCEDURE p_calcularcmv_med(p_abaterimpostoscomissaorca   IN VARCHAR2,
                                p_aplicarindicecmv            IN VARCHAR2,
                                p_incluircomissaosugpvendacmv IN VARCHAR2,
                                p_txvenda                     IN NUMBER,
                                p_tipofj                      IN VARCHAR2,
                                p_utilizaiesimplificada       IN VARCHAR2,
                                p_ieent                       IN VARCHAR2,
                                p_freteespecial               IN VARCHAR2,
                                p_perfreteterceiros           IN NUMBER,
                                p_perfreteespecial            IN NUMBER,
                                p_custofin                    IN NUMBER,
                                p_custoreal                   IN NUMBER,
                                p_perdesccusto                IN NUMBER,
                                p_codicmtab                   IN NUMBER,
                                p_codicmtabpf_enulo           IN BOOLEAN,
                                p_codicmtabpf                 IN NUMBER,
                                p_pvenda                      IN NUMBER,
                                p_percom                      IN NUMBER,
                                p_st                          IN NUMBER,
                                p_vlipi                       IN NUMBER,
                                p_vliss                       IN NUMBER,
                                p_contribuinte                IN VARCHAR2,
                                p_prazomedio                  IN NUMBER,   --// HIS.01109.2016 - Rentabilidade do Pedido
                                p_vldescboleto                IN NUMBER,   --// HIS.01109.2016 - Rentabilidade do Pedido
                                p_tipoacrescimoscmvmed        IN NUMBER,   --// HIS.01109.2016 - Rentabilidade do Pedido
                                p_perctaxaprazocmvmed         IN NUMBER,   --// HIS.01109.2016 - Rentabilidade do Pedido
                                p_PRODIMPORTADOPEPS           IN VARCHAR2, -- HIS.02786.2016
                                p_nCODICMTABINTERNAC          IN NUMBER,   -- HIS.02786.2016
                                p_vldesccmvpromocaomed        IN NUMBER,   -- DDMEDICA-5009
                                p_vlicmsstretanterior         IN NUMBER,   -- DDMEDICA-7697
                                p_perfretecmv                 OUT NUMBER,
                                p_custofinest                 OUT NUMBER,
                                p_txvenda_item                OUT NUMBER,
                                p_perdesccusto_item           OUT NUMBER,
                                p_codicmtab_item              OUT NUMBER,
                                p_vlcustoreal                 OUT NUMBER,
                                p_vlcustofin                  OUT NUMBER,
                                p_vldesccustocmv              OUT NUMBER,
                                p_vltaxaprazomedcmv           OUT NUMBER, --// HIS.01109.2016 - Rentabilidade do Pedido
                                p_perctaxaprazomedcmv         OUT NUMBER, --// HIS.01109.2016 - Rentabilidade do Pedido
                                p_vldescboletocmv             OUT NUMBER) --// HIS.01109.2016 - Rentabilidade do Pedido
    IS
      vnbasecalccomissao NUMBER := 0;
    BEGIN
      --Dados para cálculo do CMV
      p_perfretecmv := p_perfreteterceiros;

      IF p_freteespecial = 'S' THEN
        p_perfretecmv := p_perfreteespecial;
      END IF;

      p_custofinest       := p_custofin;
      p_txvenda_item      := NVL(p_txvenda, 0);
      p_perdesccusto_item := NVL(p_perdesccusto, 0);
      p_codicmtab_item    := NVL(p_codicmtab, 0);

      IF (p_tipofj = 'F') AND (p_utilizaiesimplificada = 'N') AND
         ((UPPER(TRIM(p_ieent)) = 'ISENTO') OR
         (UPPER(TRIM(p_ieent)) = 'ISENTA')) AND (p_codicmtabpf IS NOT NULL) THEN
        p_codicmtab_item := NVL(p_codicmtabpf, 0);
      END IF;

      --Tarefa 45842: Pessoa Fisica com Inscricao Estadual e marcada como Contribuinte
      --Sera tratada como pessoa juridica
      IF (p_tipofj = 'F') AND (UPPER(TRIM(p_ieent)) <> 'ISENTO') AND
         (UPPER(TRIM(p_ieent)) <> 'ISENTA') AND (UPPER(TRIM(p_ieent)) <> '') AND
         (p_contribuinte = 'S') THEN
        p_codicmtab_item := NVL(p_codicmtab, 0);
      END IF;

      IF (p_PRODIMPORTADOPEPS = 'S') THEN -- HIS.02786.2016
        p_codicmtab_item := p_nCODICMTABINTERNAC;
      END IF;

      --Tarefa 25188
      vnbasecalccomissao := p_pvenda;

      IF p_abaterimpostoscomissaorca = 'S' THEN
        vnbasecalccomissao := p_pvenda - NVL(p_st, 0) - NVL(p_vlipi, 0) -
                              NVL(p_vliss, 0);
      END IF;

      --tarefas 43617 e 44750
      IF p_aplicarindicecmv = 'S' THEN
        p_vlcustoreal := (p_custoreal -
                         (p_custoreal * NVL(p_perdesccusto_item, 0) / 100) +
                         (p_pvenda * p_txvenda_item / 100) +
                         (vnbasecalccomissao * NVL(p_percom, 0) / 100) +
                         (p_pvenda * NVL(p_perfretecmv, 0) / 100) +
                         ((p_pvenda - NVL(p_st, 0) - NVL(p_vlipi, 0) -
                         NVL(p_vliss, 0)) --Tarefa 43617
                         * (p_codicmtab_item / 100)) + NVL(p_st, 0) +
                         NVL(p_vlipi, 0) + NVL(p_vliss, 0));
        p_vlcustofin  := (p_custofinest -
                         (p_custofinest * NVL(p_perdesccusto_item, 0) / 100) +
                         (p_pvenda * p_txvenda_item / 100) +
                         (vnbasecalccomissao * NVL(p_percom, 0) / 100) +
                         (p_pvenda * NVL(p_perfretecmv, 0) / 100) +
                         ((p_pvenda - NVL(p_st, 0) - NVL(p_vlipi, 0) -
                         NVL(p_vliss, 0)) --Tarefa 43617
                         * (p_codicmtab_item / 100)) + NVL(p_st, 0) +
                         NVL(p_vlipi, 0) + NVL(p_vliss, 0));
      ELSE
        p_vlcustoreal := (p_custoreal -
                         (p_custoreal * NVL(p_perdesccusto_item, 0) / 100) +
                         (p_pvenda * p_txvenda_item / 100) +
                         (vnbasecalccomissao * NVL(p_percom, 0) / 100) +
                         (p_pvenda * NVL(p_perfretecmv, 0) / 100) +
                         ((p_pvenda - NVL(p_st, 0) - NVL(p_vlipi, 0) -
                         NVL(p_vliss, 0)) * (p_codicmtab_item / 100)) + p_st +
                         NVL(p_vlipi, 0) + NVL(p_vliss, 0));
        p_vlcustofin  := (p_custofinest -
                         (p_custofinest * NVL(p_perdesccusto_item, 0) / 100) +
                         (p_pvenda * p_txvenda_item / 100) +
                         (vnbasecalccomissao * NVL(p_percom, 0) / 100) +
                         (p_pvenda * NVL(p_perfretecmv, 0) / 100) +
                         ((p_pvenda - NVL(p_st, 0) - NVL(p_vlipi, 0) -
                         NVL(p_vliss, 0)) * (p_codicmtab_item / 100)) + p_st +
                         NVL(p_vlipi, 0) + NVL(p_vliss, 0));
      END IF;

      -- tarefa 56190
      IF NVL(p_incluircomissaosugpvendacmv, 'S') = 'N' THEN
        p_vlcustoreal := p_vlcustoreal -
                         (vnbasecalccomissao * NVL(p_percom, 0) / 100);
        p_vlcustofin  := p_vlcustofin -
                         (vnbasecalccomissao * NVL(p_percom, 0) / 100);
      END IF;

      -- Acréscimos Custo Gerencial
      p_vltaxaprazomedcmv := NVL(p_pvenda,0)  * (NVL(p_prazomedio,0) * (NVL(p_perctaxaprazomedcmv,0) /100));
      p_vlcustofin        := NVL(p_vlcustofin,0) + (NVL(p_vldescboletocmv,0) + NVL(p_vltaxaprazomedcmv,0));

      -- Valor do Desconto no Custo Financeiro
      p_vldesccustocmv := (ROUND(((NVL(p_custofinest, 0) *
                                 NVL(p_perdesccusto_item, 0) / 100) * 100))) / 100;

      --// HIS.01109.2016 - Rentabilidade do Pedido
      --// Retornar pdVLDESCBOLETOCMV com o valor de pdVLDESCBOLETO se TIPOACRESCIMOSCMVMED IN ('3','4')
      p_vldescboletocmv := 0;
      IF (p_tipoacrescimoscmvmed = '3') OR
         (p_tipoacrescimoscmvmed = '4') THEN
        p_vldescboletocmv := NVL(p_vldescboleto,0);
      END IF;


      --// HIS.01109.2016 - Rentabilidade do Pedido
      --// Retornar pdVLTAXAPRAZOMEDCMV com o valor de pdPVENDA  * (PRAZOMEDIO  * (PERCTAXAPRAZOCMVMED /100))  se ACRESCIMOSCMVMED IN ('2','4')
      p_vltaxaprazomedcmv := 0;
      IF (p_tipoacrescimoscmvmed = '2') OR
         (p_tipoacrescimoscmvmed = '4') THEN
        p_vltaxaprazomedcmv := p_pvenda * (NVL(p_prazomedio,0) * (NVL(p_perctaxaprazocmvmed,0)/100));
      END IF;

      --// HIS.01109.2016 - Rentabilidade do Pedido
      --// Somar ao VLCUSTOFIN dentro da Função calcularCMV os valores
      --// vdVLDESCBOLETOCMV e vnVLTAXAPRAZOMEDCMV que estarão zerados ou com valor
      --// maior que zero conforme regra acima
      p_vlcustofin            := (NVL(p_vlcustofin,0) + NVL(p_vldescboletocmv,0));
      p_vlcustofin            := (NVL(p_vlcustofin,0) + NVL(p_vltaxaprazomedcmv,0));
      p_perctaxaprazomedcmv   := NVL(p_perctaxaprazocmvmed,0);

      -- Verba de Fornecedor da Promoção para Rebaixa CMV - DDMEDICA-5009
      IF (NVL(p_vldesccmvpromocaomed,0) <> 0) THEN
        p_vlcustoreal := (p_vlcustoreal - NVL(p_vldesccmvpromocaomed,0));
        p_vlcustofin  := (p_vlcustofin  - NVL(p_vldesccmvpromocaomed,0));
      END IF;

    END p_calcularcmv_med;

    ------------------------------------------------------------------------------
    -- Procedimento para arredondar o calculo do Suframa - DDMEDICA-1172
    ------------------------------------------------------------------------------
    FUNCTION F_ARREDONDAMENTO_SUFRAMA(pi_nValor            IN NUMBER,
                                      pi_vNumCasasDecimais IN NUMBER)
    RETURN NUMBER IS
      vValorSuframa    NUMBER;
      vTipoCalculo     VARCHAR2(2);
    BEGIN
      --Jorge
      -- Parâmetro de Percentual de Bonificação por Região
        POBTEM_PARAMFILIAL_STRING('99',
                                  'CON_TIPOCALCSULFRAMA',
                                  vTipoCalculo,  --> Valor do Parâmetro
                                  vvErroPesqParam,
                                  vvMsgErroPesqParam);

        IF vTipoCalculo = 'T2' THEN
          SELECT TRUNC(pi_nValor,2) INTO vValorSuframa FROM DUAL;
        ELSE
          IF vTipoCalculo = 'A2' THEN
            SELECT ROUND(pi_nValor,2) INTO vValorSuframa FROM DUAL;
          ELSE
            SELECT ROUND(pi_nValor,pi_vNumCasasDecimais) INTO vValorSuframa FROM DUAL;
          END IF;
        END IF;

      -- Retorno
      RETURN NVL(vValorSuframa,0);

    END F_ARREDONDAMENTO_SUFRAMA;

    ------------------------------------------------------------------------------
    -- Procedimento para arredondar o calculo da desoneração - DDMEDICA-2961
    ------------------------------------------------------------------------------
    FUNCTION F_ARREDONDAMENTO_DESONERACAO(pi_nValor            IN NUMBER,
                                          pi_vNumCasasDecimais IN NUMBER,
                                          pi_vRegraMinimo      IN VARCHAR2,
                                          pi_nCodSt            IN NUMBER)
    RETURN NUMBER IS
      nValorDesoneracao NUMBER;
      vDESTACDESCICMISENCAOCOMERCIAL PCTRIBUT.DESTACDESCICMISENCAOCOMERCIAL%TYPE;
    BEGIN

      SELECT ROUND(pi_nValor,pi_vNumCasasDecimais) INTO nValorDesoneracao FROM DUAL;
      
      IF (nValorDesoneracao = 0) AND
         (pi_vRegraMinimo = 'S') THEN
        BEGIN
          SELECT PCTRIBUT.DESTACDESCICMISENCAOCOMERCIAL
            INTO vDESTACDESCICMISENCAOCOMERCIAL
            FROM PCTRIBUT
           WHERE (PCTRIBUT.CODST = pi_nCodSt);
        EXCEPTION
          WHEN NO_DATA_FOUND THEN
            vDESTACDESCICMISENCAOCOMERCIAL := 'N';
        END;
        IF (NVL(vDESTACDESCICMISENCAOCOMERCIAL,'N') <> 'S') THEN -- DDMEDICA-4289 - Isenção ST não participa da Regra
          -- DDMEDICA-4289 - Condicionar às casas decimais do preço de venda para não gerar preço negativo
          IF    (NVL(pi_vNumCasasDecimais,2) = 3) THEN
            nValorDesoneracao := 0.001;
          ELSIF (NVL(pi_vNumCasasDecimais,2) = 4) THEN
            nValorDesoneracao := 0.0001;
          ELSIF (NVL(pi_vNumCasasDecimais,2) = 5) THEN
            nValorDesoneracao := 0.00001;
          ELSIF (NVL(pi_vNumCasasDecimais,2) = 6) THEN
            nValorDesoneracao := 0.000001;
          ELSE
            nValorDesoneracao := 0.01;
          END IF;
        END IF;
      END IF;

      -- Retorno
      RETURN NVL(nValorDesoneracao,0);

    END F_ARREDONDAMENTO_DESONERACAO;

  /*******************************************************************************
                     INICIO DO PROCESSAMENTO PRINCIPAL
   *******************************************************************************/
  BEGIN

    -- Inicializa Retornos
    po_vPodeGravarPedido    := 'S';
    po_vMotivoNaoPodeGravar := '';

   /******************************************
    Desvios (Situações que não pode continuar)
    ******************************************/
    -- Recalcular Preço ao alterar Plano de Pagamento de uma Bonificação
    IF (pi_nCondVenda   = 5)  AND
       (pi_nTipoChamada = 10) THEN
      RAISE e_Break;
    END IF;

    -- Inicializa Controle de Pedido Inserido
    vbInseriuPedido         := FALSE;

    -- Pesquisa o Tipo de Promoção de Cabeçalho
    BEGIN
      SELECT TIPOPROMOCAO
           , VLRMINITENSPROMOCAO
           , TIPOPOLITICA
           , NVL(UPPER(PERMITEQTMINIMASEMOBRIG),'N')
        INTO vvTipoPromocaoPedido
           , vnVlrMinItensPromocaoPedido
           , vvTipoPoliticaPedido
           , vvPermiteQtMinimaSemObrig
        FROM PCPROMOCAOMED
       WHERE (CODPROMOCAOMED = pi_nCodPromocaoMedPedido);
    EXCEPTION
      WHEN NO_DATA_FOUND THEN
        vvTipoPromocaoPedido        := NULL;
        vnVlrMinItensPromocaoPedido := 0;
        vvTipoPoliticaPedido        := NULL;
        vvPermiteQtMinimaSemObrig   := 'N';
    END;
	
	IF vvTipoPromocaoPedido = 'K' THEN
	
      IF (pi_vTipoFv = 'OL') THEN
        P_MED_OBTEM_QTCOMBOVIRTUAL(pi_nCodPromocaoMedPedido,
                                   pi_nNumRegiao,
                                   NULL, --pi_nCodPraca,
                                   NULL, --pi_nCodRede,
                                   pi_nCodCli,
                                   NULL, --pi_nRamoAtv,
                                   NULL, --pi_vCLASSE,
                                   NULL, --pi_codgrupo,
                                   NULL, --, pi_vUfCliente
                                   vnQtComboVirtual,
                                   vnQtCombovirtual_vendidos,
                                   vsTipoLimitador,
                                   NULL,
                                   pi_vTipoFv
                                   );
         
        vnQtCombovirtual_disponivel := nvl(vnQtComboVirtual,0) - vnQtCombovirtual_vendidos;                          
         
        IF (vnQtCombovirtual_vendidos + pi_nQtCombos)  > vnQtComboVirtual THEN
          po_vMotivoNaoPodeGravar := 'O combo ' || pi_nCodPromocaoMedPedido || ' foi rejeitado pois não há mais quantidades disponíveis de acordo com os limitadores cadastrados. ' || CHR(13) ||
                                     'Tipo Limitador cadastrado: ' || vsTipoLimitador || ' ' || CHR(13) || 
                                     'Limite(Qt. Max. Combo): ' || vnQtComboVirtual || ' ' || CHR(13) ||
                                     'Qt. Disponível da restrição: ' || vnQtCombovirtual_disponivel;
          RAISE e_Tratado;     
        END IF;
      ELSE
        P_MED_OBTEM_QTCOMBOVIRTUAL(pi_nCodPromocaoMedPedido,
                                   pi_nNumRegiao,
                                   NULL, --pi_nCodPraca,
                                   NULL, --pi_nCodRede,
                                   pi_nCodCli,
                                   NULL, --pi_nRamoAtv,
                                   NULL, --pi_vCLASSE,
                                   NULL, --pi_codgrupo,
                                   NULL, --, pi_vUfCliente
                                   vnQtComboVirtual,
                                   vnQtCombovirtual_vendidos,
                                   vsTipoLimitador
                                   );
         
        vnQtCombovirtual_disponivel := nvl(vnQtComboVirtual,0) - vnQtCombovirtual_vendidos;                          
         
        IF (vnQtCombovirtual_vendidos + pi_nQtCombos)  > vnQtComboVirtual THEN
          po_vMotivoNaoPodeGravar := 'O combo ' || pi_nCodPromocaoMedPedido || ' foi rejeitado pois não há mais quantidades disponíveis de acordo com os limitadores cadastrados. ' || CHR(13) ||
                                     'Tipo Limitador cadastrado: ' || vsTipoLimitador || ' ' || CHR(13) || 
                                     'Limite(Qt. Max. Combo): ' || vnQtComboVirtual || ' ' || CHR(13) ||
                                     'Qt. Disponível da restrição: ' || vnQtCombovirtual_disponivel;
          RAISE e_Tratado;     
        END IF;      
      END IF;                                                                                                  
    END IF;

    -- Se o Tipo de Chamada for Casadinha
    IF (pi_nTipoChamada = 9) THEN
      -- Se a Promoção não for Casadinha Aborta
      IF (vvTipoPromocaoPedido <> 'S') THEN
        po_vMotivoNaoPodeGravar := 'Promoção Inválida! Deverá ser do Tipo Casadinha!';
        RAISE e_Tratado;
      END IF;
    END IF;

    -- Se o Tipo de Chamada for Inclusão de itens o orçamento - DDVENDAS-41697
    IF (pi_nTipoChamada = 11) THEN
      SELECT COUNT(1)
        INTO viQtItensPed
        FROM PCPEDI
       WHERE (NUMPED = pi_nNumPed);
      -- Se o Pedido já tiver itens Aborta
      IF (viQtItensPed > 0) THEN
        po_vMotivoNaoPodeGravar := 'Já existem produtos no Pedido, inclusão não permitida!';
        RAISE e_Tratado;
      END IF;
    END IF;

    -- DDMEDICA-5009 - Controle de Verba da Promoção    
    SELECT COUNT(1)
      INTO vnQtVerbaPromocao
      FROM PCPROMOCAOVERBAMED;
    vbUsaVerbaPromocao := (NVL(vnQtVerbaPromocao,0) > 0);

   /******************************************************************************
    SE CHAMADO PARA VALIDAR A PROMOÇÃO AO GRAVAR O PEDIDO
    *****************************************************/
    IF    (pi_nTipoChamada = 1) THEN

     /*--------------------------------------------
      Se a Promoção do Cabeçalho Requerer Validação
      - E - Encarte
      - V - Valor
      - M - Mix Produtos
      - K - Combo Virtual (Kit)
      --------------------------------------------*/
      --MED-2205-Retiradas as Promoções de Valor e Mix
      --IF (vvTipoPromocaoPedido IN ('E','V','M','K')) THEN
      IF (vvTipoPromocaoPedido IN ('E','K','V')) THEN

        -- Carrega Array com Itens da Promoção do Cabeçalho do Pedido
        FOR vc_Promo IN (SELECT DISTINCT
                                PCDESCONTO.CODPROD
                              , PCDESCONTO.INICIOINTERVALOPROMOCAOMED
                           FROM PCDESCONTO
                          WHERE (PCDESCONTO.CODPROMOCAOMED = pi_nCodPromocaoMedPedido)) LOOP

          -- Insere Item no Array
          viIdxNew                          := NVL(vtItensPromo.COUNT,0) + 1;
          vtItensPromo(viIdxNew).vnCodProd  := vc_Promo.CODPROD;
          vtItensPromo(viIdxNew).vnQtdeMin  := NVL(vc_Promo.INICIOINTERVALOPROMOCAOMED,0);

        END LOOP; -- Fim Laço Itens do Pedido com mesma Promoção do Cabeçalho do Pedido

        -- Inicializa Totalizador de Itens do Pedido da Promoção do Pedido
        vnVlTotalItens  := 0;
        vnTotalUnidades := 0;
        vnTotalItens    := 0;

        -- Carrega Array com Itens do Pedido com mesma Promoção do Cabeçalho do Pedido
        FOR vc_ItensPedido IN (SELECT PCPEDI.CODPROD
                                    , SUM(PCPEDI.QT) QTDE
                                    , SUM(PCPEDI.QT * (NVL(PCPEDI.PVENDA,0) - NVL(PCPEDI.VLREPASSE,0) - NVL(PCPEDI.ST,0) - NVL(PCPEDI.VLFECP,0))) VALOR
                                 FROM PCPEDI
                                WHERE (PCPEDI.NUMPED         = pi_nNumPed)
                                  AND (PCPEDI.CODPROMOCAOMED = pi_nCodPromocaoMedPedido)
                                GROUP BY PCPEDI.CODPROD) LOOP

          -- Insere Item no Array
          viIdxNew                          := NVL(vtItensPedido.COUNT,0) + 1;
          vtItensPedido(viIdxNew).vnCodProd := vc_ItensPedido.CODPROD;
          vtItensPedido(viIdxNew).vnQtde    := NVL(vc_ItensPedido.QTDE,0);
          vtItensPedido(viIdxNew).vnValor   := NVL(vc_ItensPedido.VALOR,0);

          -- Acumula Valor Total dos Itens e Unidades do Pedido com mesma Promoção do Cabeçalho do Pedido
          vnVlTotalItens  := NVL(vnVlTotalItens,0)  + NVL(vc_ItensPedido.VALOR,0);
          vnTotalUnidades := NVL(vnTotalUnidades,0) + NVL(vc_ItensPedido.QTDE,0);
          vnTotalItens    := NVL(vnTotalItens,0)    + 1;

        END LOOP; -- Fim Laço Itens da Promoção do Cabeçalho do Pedido

        ----------------------------------------------------
        -- Se Promoção de Valor e não Atingiu o Valor Mínimo
        ----------------------------------------------------
        IF (vvTipoPromocaoPedido = 'V') AND
           (NVL(vnVlTotalItens,0) < NVL(vnVlrMinItensPromocaoPedido,0)) THEN
          -- Aborta
          po_vMotivoNaoPodeGravar := 'Não foi atingido o Valor Mínimo da Promoção.'                                                                        || CHR(13) ||
                                     ' Valor Mínimo da Promoção: ' || TRIM(REPLACE(TO_CHAR(NVL(vnVlrMinItensPromocaoPedido,0),'999999999990.00'),'.',',')) || CHR(13) ||
                                     ' Valor Itens do Pedido: '    || TRIM(REPLACE(TO_CHAR(NVL(vnVlTotalItens,0),'999999999990.00'),'.',','));
          RAISE e_Tratado;
        END IF;

        -------------------------------------------------------------------
        -- Se Promoção de Mix e não Atingiu a Quantidade Minima de ITENS
        -------------------------------------------------------------------
        IF (vvTipoPromocaoPedido = 'M') AND
           (NVL(vnTotalItens,0) < NVL(vnVlrMinItensPromocaoPedido,0)) THEN
          -- Aborta
          po_vMotivoNaoPodeGravar := 'Não foi atingido o Total Mínimo de Itens da Promoção.'                                                                             || CHR(13) ||
                                     ' Quantidade Mínima de Itens da Promoção: ' || TRIM(REPLACE(TO_CHAR(NVL(vnVlrMinItensPromocaoPedido,0),'999999999990'),'.',',')) || CHR(13) ||
                                     ' Quantidade de Itens do Pedido: '          || TRIM(REPLACE(TO_CHAR(NVL(vnTotalItens,0),'999999999990'),'.',','));
          RAISE e_Tratado;
        END IF;

        ------------------------------------------------------------------------
        -- Se Promoção de Encarte, Valor, Mix E Combo, Valida Itens Obrigatórios
        ------------------------------------------------------------------------
        --MED-2205-Retiradas as Promoções de Valor e Mix
        --IF (vvTipoPromocaoPedido IN ('E','V','M','K')) THEN
        IF (vvTipoPromocaoPedido IN ('E','K')) THEN
          -- Se achou Produtos na Promoção
          IF (NVL(vtItensPromo.COUNT,0) > 0) THEN

            -- Inicializa Mensagem
            vvMsgItemGlobalObrigatorio  := NULL;
            viQtItemObrigatorioNaoAtend := 0;

            -- Processa Produtos da Promoção
            FOR viIdxPromo IN vtItensPromo.FIRST..vtItensPromo.LAST LOOP

              -- Se Item da Promoção Obrigatório
              -- ENCARTE e COMBO VIRTUAL, TODOS PRECISAM ESTAR NO PEDIDO, DEMAIS SOMENTE OS SELECIONADOS COMO OBRIGATORIOS NA PROMOÇÃO
              IF ((vvTipoPromocaoPedido IN ('E','K')) OR
                  ((vvTipoPromocaoPedido IN ('V','M')) AND (NVL(vtItensPromo(viIdxPromo).vnQtdeMin,0) > 0))) THEN

                 -- Inicializa Flag de controle de pesquisa do Produto
                 vbAtendeQtMinima   := FALSE;
                 vnQtAtendeQtMinima := 0;
                 vvAchouProduto     := 'N';

                 -- Verifica se o Produto da Promoção está no Pedido
                 IF (NVL(vtItensPedido.COUNT,0) > 0) THEN
                   FOR viIdxPed IN vtItensPedido.FIRST..vtItensPedido.LAST LOOP

                     -- Se Achou o Produto
                     IF (vtItensPedido(viIdxPed).vnCodProd = vtItensPromo(viIdxPromo).vnCodProd) THEN

                        -- Achou Produto da Promoção no Pedido
                        vvAchouProduto := 'S';
                        vnQtAtendeQtMinima := NVL(vtItensPedido(viIdxPed).vnQtde,0);

                       -- Se Encarte e Combo Virtual, somente o fato se encontrar já atende os critérios
                       IF    (vvTipoPromocaoPedido IN ('E','K')) THEN
                         vbAtendeQtMinima  := TRUE;
                       -- Se Promoção por Valor ou Mix, tem que atender a Quantidade Mínima
                       ELSIF ((vvTipoPromocaoPedido IN ('V','M')) AND (NVL(vtItensPedido(viIdxPed).vnQtde,0) >= NVL(vtItensPromo(viIdxPromo).vnQtdeMin,0))) THEN
                         vbAtendeQtMinima  := TRUE;
                       END IF;
                     END IF;

                   END LOOP;
                 END IF;

                 -- Se não achou o Produto, porém a Promoção Permite informar Qt. Mínima s/ Obrigatoriedade do Produto no Pedido [HIS.04843.2014]
                 IF vvAchouProduto = 'N' AND vvPermiteQtMinimaSemObrig = 'S' THEN

                   -- Informa na variável que atende a Qt. Mínima, para não exibir exceção para o item
                   vbAtendeQtMinima := TRUE;

                 END IF;

                 -- Se não atende a Qt. Mínima
                 IF (NOT vbAtendeQtMinima) THEN

                   -- Pesquisa Descrição do Produto
                   BEGIN
                     SELECT DESCRICAO
                       INTO vvDescricaoProduto
                       FROM PCPRODUT
                      WHERE (CODPROD = vtItensPromo(viIdxPromo).vnCodProd);
                   EXCEPTION
                     WHEN NO_DATA_FOUND THEN
                       vvDescricaoProduto := NULL;
                   END;
                   -- Mensagem de Item Obrigatório
                   vvMsgItemObrigatorio := NVL(vtItensPromo(viIdxPromo).vnCodProd,0) || ' - ' || NVL(vvDescricaoProduto,' ');
                   IF (vvTipoPromocaoPedido IN ('V','M')) THEN --> Mensagem Complementar
                     vvMsgItemObrigatorio := vvMsgItemObrigatorio || ' (Qt. Mín: ' || TRIM(REPLACE(TO_CHAR(NVL(vtItensPromo(viIdxPromo).vnQtdeMin,0),'999999999990'),'.',',')) || ' / ' ||
                                                                     ' Qt. Ped: '  || TRIM(REPLACE(TO_CHAR(NVL(vnQtAtendeQtMinima,0),'999999999990'),'.',',')) || ')';
                   END IF;
                   -- Incrementa Mensagem com Produto da Promoção Obrigatório
                   IF (vvMsgItemGlobalObrigatorio IS NULL) THEN
                     vvMsgItemGlobalObrigatorio := vvMsgItemObrigatorio;
                   ELSE
                     vvMsgItemGlobalObrigatorio := vvMsgItemGlobalObrigatorio || CHR(13) || vvMsgItemObrigatorio;
                   END IF;
                   -- Incrementa Quantidade de Ocorrências
                   viQtItemObrigatorioNaoAtend := NVL(viQtItemObrigatorioNaoAtend,0) + 1;

                 END IF;

              END IF; -- Fim Condição Se Item da Promoção Obrigatório

            END LOOP; -- Fim Laço Processa Produtos da Promoção

            -- Aborta se não constarem  no Pedido Itens Obrigatórios
            IF (NVL(viQtItemObrigatorioNaoAtend,0) > 0) THEN
              -- Se Encarte e Combo Virtual
              IF    (vvTipoPromocaoPedido IN ('E','K')) THEN
                po_vMotivoNaoPodeGravar := 'Não foi atingida a quantidade Mínima de Itens Obrigatórios da Promoção.'  || CHR(13) ||
                                           ' Itens que não constam na Promoção: ' || CHR(13) || SUBSTR(vvMsgItemGlobalObrigatorio,1,2000);
               -- Se Promoçãp por Valor ou Mix, tem que atender a Quantidade Mínima
              ELSIF (vvTipoPromocaoPedido IN ('V','M')) THEN
                po_vMotivoNaoPodeGravar := 'Não foram atingidos os critérios mínimos dos Itens Obrigatórios da Promoção:'  || CHR(13) || SUBSTR(vvMsgItemGlobalObrigatorio,1,2000);
              END IF;
              RAISE e_Tratado;
            END IF;

          END IF; -- Se achou Produtos na Promoção
        END IF; -- Fim Condição Valida Itens Obrigatórios

      END IF; -- Fim Condição Se a Promoção do Cabeçalho Requerer Validação

      ------------------------------------------------------------
      -- Pesquisa no Pedido Promoções de Produtos de mesma Família
      -- que não atingiram valor mínimo
      ------------------------------------------------------------

      -- Inicializa Mensagem
      vvMsgPromoGlobalFamilia  := NULL;
      viQtPromoFamiliaNaoAtend := 0;

      -- Laço de Itens do Pedido com Promoção de Família
      FOR vc_ItensPedido IN (SELECT PCPEDI.CODPROMOCAOMED
                                  , PCPROMOCAOMED.DESCRICAORESUMIDA
                                  , PCPROMOCAOMED.VLRMINITENSPROMOCAO
                                  , SUM(PCPEDI.QT) QTDE
                               FROM PCPEDI
                                  , PCPROMOCAOMED
                              WHERE (PCPROMOCAOMED.CODPROMOCAOMED = PCPEDI.CODPROMOCAOMED)
                                AND (PCPEDI.NUMPED                = pi_nNumPed)
                                AND (PCPROMOCAOMED.TIPOPROMOCAO   = 'F') -->> Somente Promoções de Produtos de mesma Família
                              GROUP BY PCPEDI.CODPROMOCAOMED
                                     , PCPROMOCAOMED.DESCRICAORESUMIDA
                                     , PCPROMOCAOMED.VLRMINITENSPROMOCAO) LOOP

        -- Se não atingiu a Quantidade Mínima de Unidades
        IF (NVL(vc_ItensPedido.QTDE,0) < NVL(vc_ItensPedido.VLRMINITENSPROMOCAO,0)) THEN
          -- Promoção do Cursor
          vvMsgPromoFamilia := TO_CHAR(NVL(vc_ItensPedido.CODPROMOCAOMED,0)) || ' - ' ||
                               SUBSTR(NVL(vc_ItensPedido.DESCRICAORESUMIDA,' '),1,20) ||
                               ' Qt. Mín. Promoção: '   || TRIM(REPLACE(TO_CHAR(NVL(vc_ItensPedido.VLRMINITENSPROMOCAO,0),'999999999990'),'.',',')) ||
                               ' / Qt. Unidades Pedido: ' || TRIM(REPLACE(TO_CHAR(NVL(vc_ItensPedido.QTDE,0),'999999999990'),'.',','));
          -- Concatena a Mensagem Global
          IF (vvMsgPromoGlobalFamilia IS NULL) THEN
            vvMsgPromoGlobalFamilia := vvMsgPromoFamilia;
          ELSE
            vvMsgPromoGlobalFamilia := vvMsgPromoGlobalFamilia || CHR(13) || vvMsgPromoFamilia;
          END IF;
          -- Incrementa Quantidade de Ocorrências
          viQtPromoFamiliaNaoAtend := NVL(viQtPromoFamiliaNaoAtend,0) + 1;
        END IF;

      END LOOP; -- Fim Laço Itens da do Pedido com Promoção de Família

      -- Aborta se constarem itens com promoção de mesma família que não atingiram a quantidade mínima de unidades
      IF (NVL(viQtPromoFamiliaNaoAtend,0) > 0) THEN
        IF (viQtPromoFamiliaNaoAtend = 1) THEN
          vvMsgPromoGlobalFamilia := 'Promoção de Produtos de mesma Família que não atingiu a Qtde. Mínima de Unidades:'    || CHR(13) || vvMsgPromoGlobalFamilia;
        ELSE
          vvMsgPromoGlobalFamilia := 'Promoções de Produtos de mesma Família que não atingiram a Qtde. Mínima de Unidades:' || CHR(13) || vvMsgPromoGlobalFamilia;
        END IF;
        po_vMotivoNaoPodeGravar := SUBSTR(vvMsgPromoGlobalFamilia,1,2000);
        RAISE e_Tratado;
      END IF;

   /******************************************************************************
    SE CHAMADO PARA INSERIR KIT
    SE CHAMADO PARA GERAR PEDIDO LICITAÇÃO
    SE CHAMADO PARA ALTERAR PROMOÇÃO DO PEDIDO
    SE CHAMADO PARA APLICAR DESCONTO ADICIONAL PLANO A VISTA
    SE CHAMADO PARA INSERIR BONIFICAÇÃO EM MERCADORIA DE PROMOÇÃO
    SE CHAMADO PARA INSERIR BONIFICAÇÃO EM MERCADORIA DE PROMOÇÃO NA TABELA TEMP
    SE CHAMADO PARA APLICAR A PROMOÇÃO CASADINHA
    SE CHAMADO PARA RECALCULAR PEDIDO AO ALTERAR PLANO DE PAGAMENTO
    SE CHAMADO PARA GERAR ITENS DOS ORÇAMENTOS
    SE CHAMADO PARA ATUALIZAR VALORES DOS ITENS BRINDE
    SE CHAMADO PARA CARREGAR A TABELA DE CAMPANHA  -- HIS.01889.2017
    SE CHAMADO PARA CARREGAR A TABELA DE MIX/VALOR -- HIS.01889.2017
    SE CHAMADO PARA APLICAR BONIFICAÇÃO DE PROMOÇÃO DE CAMPANHA - HIS.01889.2017
    SE CHAMADO PARA INCLUIR ITENS CROSS DOCKING [16] - MED-1096
    ****************************************************************************/
    ELSIF (pi_nTipoChamada IN (2,3,4,5,6,8,9,10,11,12,13,14,15
                              ,16 -- ITENS CROSS DOCKING [16] - MED-1096
                              ,17
                              ,18
                              )) THEN

      ----------------------------------------------------------------------------
      -- Se a Promoção do Cabeçalho do Pedido for KIT OU
      -- Chamado para gerar um Pedido de Licitação
      -- Chamado para Alterar Promoção do Pedido
      -- Chamado para Aplicar Desconto Adicional Plano A Vista
      -- Chamado para Inserir Bonificação em Mercadoria de Promoção
      -- Chamado para Inserir Bonificação em Mercadoria de Promoção na Tabela Temp
      -- Chamado para Aplicar a Promoção Casadinha
      -- Chamado para Recalcular Pedido ao Alterar Plano de Pagamento
      -- Chamado para Atualizar Valores dos Itens Brinde
      -- Chamado para Carregar a Tabela de Campanha  -- HIS.01889.2017
      -- Chamado para Carregar a Tabela de Mix/Valor -- HIS.01889.2017
      -- Chamado para Validar os Brindes informados -- HIS.01889.2017
      -- Chamado para Validar as Promoções de Mix/Valor selecionados -- HIS.01889.2017
      -- Chamado para Aplicar a Bonificação de Promoção de Campanha - HIS.01889.2017
      -- Chamado para Incluir Itens do Cross Docking  [16] - MED-1096
      -- Chamado para Incluir Itens Importação [17]
      ----------------------------------------------------------------------------
      IF ((pi_nTipoChamada =  2)  AND (vvTipoPromocaoPedido = 'K') AND (NVL(pi_nQtCombos,0) <> 0)) OR -- Colocado diferente de zero por causa da melhoria de edição de combos
         ((pi_nTipoChamada =  3)) OR
         ((pi_nTipoChamada =  4)) OR
         ((pi_nTipoChamada =  5)) OR
         ((pi_nTipoChamada =  6)) OR
         ((pi_nTipoChamada =  8)) OR
         ((pi_nTipoChamada =  9)) OR
         ((pi_nTipoChamada = 10)) OR
         ((pi_nTipoChamada = 11)) OR
         ((pi_nTipoChamada = 12)) OR
         ((pi_nTipoChamada = 13)) OR
         ((pi_nTipoChamada = 14)) OR
         ((pi_nTipoChamada = 15)) OR
         ((pi_nTipoChamada = 16)) OR -- ITENS CROSS DOCKING [16] - MED-1096
         ((pi_nTipoChamada = 17)) OR
         ((pi_nTipoChamada = 18))
      THEN

        -- Se Chamado para Aplicar BONIFICAÇÃO DE PROMOÇÃO EM TV1 ou Inserir Bonificação em Mercadoria de Promoção na Tabela Temp
        IF    (pi_nTipoChamada in (6,8)) THEN
          -- Limpa Tabela Temporária
          DELETE FROM PCMED_TEMP_PROMO_BONIFICMERC;
        -- Se Chamado para Recuperar Orçamento
        --ELSIF (pi_nTipoChamada in (11)) THEN
        --  -- Limpa Tabela Temporária
        --  DELETE FROM PCMED_TEMP_PROMO_REJEICAO;
        -- Se Chamado para Carregar Tabela de Campanha  - HIS.01889.2017
        -- Se Chamado para Carregar Tabela de Mix/Valor - HIS.01889.2017
        ELSIF (pi_nTipoChamada in (13,14)) THEN
          -- Limpa Tabelas Temporárias observando que Campanhas deve ser replicado o Valor da Seleção anterior
          -- CAMPANHAS
          IF    (pi_nTipoChamada = 13) THEN
            -- Limpa Tabelas auxiliares para guardar as Seleções das Promoções e os Brindes Informados
            DELETE FROM PCMED_PROMOCAO_CAMPANHA_SEL;
            DELETE FROM PCMED_PROMOCAO_CAMPANHA_INF;
            -- Faz Backup das Campanhas Selecionadas
            INSERT INTO PCMED_PROMOCAO_CAMPANHA_INF
                      ( CODPROMOCAOMEDREF
                      , CODPROD
                      , QTDEBRINDES )
                 SELECT PCMED_PROMOCAO_CAMPANHA_BRI.CODPROMOCAOMEDREF
                      , PCMED_PROMOCAO_CAMPANHA_BRI.CODPROD
                      , PCMED_PROMOCAO_CAMPANHA_BRI.QTDEBRINDES
                   FROM PCMED_PROMOCAO_CAMPANHA_BRI
                  WHERE (PCMED_PROMOCAO_CAMPANHA_BRI.TIPOPROMOCAO = 'N')
                    AND (PCMED_PROMOCAO_CAMPANHA_BRI.QTDEBRINDES > 0);
            -- Faz Backup dos Brindes Informados
            INSERT INTO PCMED_PROMOCAO_CAMPANHA_SEL
                      ( CODPROMOCAOMED
                      , SEL )
                 SELECT PCMED_PROMOCAO_CAMPANHA.CODPROMOCAOMED
                      , PCMED_PROMOCAO_CAMPANHA.SEL
                   FROM PCMED_PROMOCAO_CAMPANHA
                  WHERE (PCMED_PROMOCAO_CAMPANHA.TIPOPROMOCAO = 'N');
            -- Limpa Tabelas Temporárias
            DELETE FROM PCMED_PROMOCAO_CAMPANHA;
            DELETE FROM PCMED_PROMOCAO_CAMPANHA_BRI;
            DELETE FROM PCMED_PROMOCAO_CAMPANHA_MIX;
          -- PROMOÇÃO DE MIX/VALOR
          ELSIF (pi_nTipoChamada = 14) THEN
            -- Limpa Tabelas Temporárias
            -- (No caso do Cabeçaho da Promoção não pode excluir os registros das Promoções de Campanha,
            -- porque pode ter a última seleção do usuário. Com relação ao Mix, pode refazer tudo sempre)
            DELETE FROM PCMED_PROMOCAO_CAMPANHA
                  WHERE (NVL(PCMED_PROMOCAO_CAMPANHA.TIPOPROMOCAO,'C') <> 'N');
            DELETE FROM PCMED_PROMOCAO_CAMPANHA_MIX;
          END IF;
        END IF;

        -- Data do Pedido
        vdDataPedido := TRUNC(SYSDATE);

        -- Parâmetro de Número de Casas Decimais do Preço de Venda
        POBTEM_PARAMFILIAL_NUMBER('99',
                                  'CON_NUMCASASDECVENDA',
                                  vrParamFilial.nCON_NUMCASASDECVENDA, --> Valor do Parâmetro
                                  vvErroPesqParam,
                                  vvMsgErroPesqParam);

        -- Parâmetro de Base de Cálculo do Desconto do Boleto
        POBTEM_PARAMFILIAL_NUMBER(pi_vCodFilial,
                                  'BASECALCDESCFINMED',
                                  vrParamFilial.nBASECALCDESCFINMED, --> Valor do Parâmetro
                                  vvErroPesqParam,
                                  vvMsgErroPesqParam);

        -- Parâmetro de Base de Cálculo do St Fonte
        POBTEM_PARAMFILIAL_NUMBER(pi_vCodFilial,
                                  'TIPOCALCSTFONTE',
                                  vrParamFilial.nTIPOCALCSTFONTE,    --> Valor do Parâmetro
                                  vvErroPesqParam,
                                  vvMsgErroPesqParam);

        -- Parâmetro de Percentual de Bonificação por Região
        POBTEM_PARAMFILIAL_STRING(pi_vCodFilial,
                                  'UTILIZAPERCBONIFIVENDAREGIAO',
                                  vrParamFilial.vUTILIZAPERCBONIFIVENDAREGIAO,  --> Valor do Parâmetro
                                  vvErroPesqParam,
                                  vvMsgErroPesqParam);

        -- Parâmetro Usa Chave Tripla
        POBTEM_PARAMFILIAL_STRING('99',
                                  'CON_USACHAVETRIPLAPCPEDI',
                                  vrParamFilial.vUSACHAVETRIPLAPCPEDI,  --> Valor do Parâmetro
                                  vvErroPesqParam,
                                  vvMsgErroPesqParam);

        -- Parâmetro Usa Desconto Adicional Plano A Vista
        POBTEM_PARAMFILIAL_STRING(pi_vCodFilial,
                                  'MEDUSADESCADICPLPAGVISTA',
                                  vrParamFilial.vMEDUSADESCADICPLPAGVISTA,  --> Valor do Parâmetro
                                  vvErroPesqParam,
                                  vvMsgErroPesqParam);

        -- Parâmetro Percentual de Desconto Adicional Plano A Vista
        POBTEM_PARAMFILIAL_NUMBER(pi_vCodFilial,
                                  'MEDPERDESCADICPLPAGVISTA',
                                  vrParamFilial.nMEDPERDESCADICPLPAGVISTA, --> Valor do Parâmetro
                                  vvErroPesqParam,
                                  vvMsgErroPesqParam);

        -- Parâmetro Quantidade Referência para Cálculo da Promoção de Bonificação de Mercadoria
        POBTEM_PARAMFILIAL_NUMBER('99',
                                  'QTDEREFPROMOBONIFICMERCMED',
                                  vrParamFilial.vQTDEREFPROMOBONIFICMERCMED, --> Valor do Parâmetro
                                  vvErroPesqParam,
                                  vvMsgErroPesqParam);

        -- Parâmetro para Definir a Forma de Débito e Crédito do RCA
        POBTEM_PARAMFILIAL_STRING('99',
                                  'TIPOCONFIGDEBCREDRCAPROMOMED',
                                  vrParamFilial.vTIPOCONFIGDEBCREDRCAPROMOMED, --> Valor do Parâmetro
                                  vvErroPesqParam,
                                  vvMsgErroPesqParam);

        -- Parâmetro para Definir se pode editar Item que Movimentou Saldo RCA no FV
        POBTEM_PARAMFILIAL_STRING('99',
                                  'BLOQEDICAOITENSMOVSALDORCAFV',
                                  vrParamFilial.vBLOQEDICAOITENSMOVSALDORCAFV, --> Valor do Parâmetro
                                  vvErroPesqParam,
                                  vvMsgErroPesqParam);

        -- Parâmetro Aplicar Desconto do Cliente no PTABELA
        POBTEM_PARAMFILIAL_STRING('99',
                                  'MEDAPLICARDESCOMCLIPTABELA',
                                  vrParamFilial.vMEDAPLICARDESCOMCLIPTABELA, --> Valor do Parâmetro
                                  vvErroPesqParam,
                                  vvMsgErroPesqParam);

        -- Parâmetro Bloquear Débito e Crédito em Pedidos do Televendas -- 4493.040816.2016
        POBTEM_PARAMFILIAL_STRING('99',
                                  'BLOQDEBCREDRCATELEVMED',
                                  vrParamFilial.vBLOQDEBCREDRCATELEVMED, --> Valor do Parâmetro
                                  vvErroPesqParam,
                                  vvMsgErroPesqParam);

        -- Parâmetro Tipo de Prazo de Medicamentos
        POBTEM_PARAMFILIAL_STRING('99',
                                  'TIPOPRAZOMEDICAMEN',
                                  vrParamFilial.vTIPOPRAZOMEDICAMEN, --> Valor do Parâmetro
                                  vvErroPesqParam,
                                  vvMsgErroPesqParam);

        -- Parâmetro Usa Desconto do Simples Nacional
        POBTEM_PARAMFILIAL_STRING(pi_vCodFilial,
                                  'USADESCSIMPLESNAC',
                                  vrParamFilial.vUSADESCSIMPLESNAC, --> Valor do Parâmetro
                                  vvErroPesqParam,
                                  vvMsgErroPesqParam);

        -- Parâmetro Tipo Acréscimos CMV
        POBTEM_PARAMFILIAL_STRING(pi_vCodFilial,
                                  'TIPOACRESCIMOSCMVMED',
                                  vrParamFilial.vTIPOACRESCIMOSCMVMED, --> Valor do Parâmetro
                                  vvErroPesqParam,
                                  vvMsgErroPesqParam);

        -- Parâmetro Perc. Taxa Prazo CMV
        POBTEM_PARAMFILIAL_NUMBER(pi_vCodFilial,
                                  'PERCTAXAPRAZOCMVMED',
                                  vrParamFilial.nPERCTAXAPRAZOCMVMED, --> Valor do Parâmetro
                                  vvErroPesqParam,
                                  vvMsgErroPesqParam);

        -- Parâmetro Origem Nacional/Importado
        POBTEM_PARAMFILIAL_STRING(NVL(pi_vCodFilialNf,pi_vCodFilial),
                                  'TRIBUTSAIDAORIGEMNACIMP',
                                  vrParamFilial.vTRIBUTSAIDAORIGEMNACIMP, --> Valor do Parâmetro
                                  vvErroPesqParam,
                                  vvMsgErroPesqParam);

        -- Parâmetro Usa Acréscimos/Descontos do Acordo de Parceria
        POBTEM_PARAMFILIAL_STRING('99',
                                  'USARACRESCDESCACORDOPARCERIA',
                                  vrParamFilial.vUSARACRESCDESCACORDOPARCERIA, --> Valor do Parâmetro
                                  vvErroPesqParam,
                                  vvMsgErroPesqParam);

        -- Regra de Tributação da Transferência
        POBTEM_PARAMFILIAL_STRING(pi_vCodFilial,
                                  'USARTRIBTRANSFVENDA10',
                                  vrParamFilial.vUSARTRIBTRANSFVENDA10, --> Valor do Parâmetro
                                  vvErroPesqParam,
                                  vvMsgErroPesqParam);

        -- Parâmetro de Custo com ST ou Sem ST - DDMEDICA-4799
        POBTEM_PARAMFILIAL_STRING('99',
                                  'PRECIFICREGIAOFORAUFSEMST',
                                  vrParamFilial.vPRECIFICREGIAOFORAUFSEMST, --> Valor do Parâmetro
                                  vvErroPesqParam,
                                  vvMsgErroPesqParam);
                                  
        -- Parâmetro do novo processo de licitação - DDVENDAS-33442
        POBTEM_PARAMFILIAL_STRING('99',
                                  'UTILIZANOVOPROCESSOLICITACAO',
                                  vrParamFilial.vUTILIZANOVOPROCESSOLICITACAO, --> Valor do Parâmetro
                                  vvErroPesqParam,
                                  vvMsgErroPesqParam);
                                  
        -- Parâmetro de Número de Casas Decimais do Estoque - DDVENDAS-33442
        POBTEM_PARAMFILIAL_NUMBER('99',
                                  'CON_NUMCASASDECESTOQUE',
                                  vrParamFilial.nCON_NUMCASASDECESTOQUE, --> Valor do Parâmetro
                                  vvErroPesqParam,
                                  vvMsgErroPesqParam);    

        -- Regra de Conversão de Quantidade - DDVENDAS-33442                                  
        POBTEM_PARAMFILIAL_STRING('99',
                                  'MEDTIPOARREDQTPEDLICIT',
                                  vrParamFilial.vMEDTIPOARREDQTPEDLICIT, --> Valor do Parâmetro
                                  vvErroPesqParam,
                                  vvMsgErroPesqParam);
                                  
        -- DDVENDAS-33920 
        POBTEM_PARAMFILIAL_STRING(pi_vCodFilial,
                                  'UTILIZATRIBENDENT',
                                  vrParamFilial.vUTILIZATRIBENDENT, --> Valor do Parâmetro
                                  vvErroPesqParam,
                                  vvMsgErroPesqParam);

        POBTEM_PARAMFILIAL_STRING(pi_vCodFilial,
                                  'USARCACLIENTELINHAPORFILIALMED',
                                  vrParamFilial.vUSARCACLIENTELINHAPORFILIALME, --> Valor do Parâmetro
                                  vvErroPesqParam,
                                  vvMsgErroPesqParam);

        -- Pesquisa Parâmetros da Filial
        BEGIN
          SELECT NVL(PCFILIAL.TIPOPRECIFICACAO,'P')
               , NVL(PCFILIAL.CALCULARIPIVENDA,'N')
               , PCFILIAL.ORIGEMCUSTOFILIALRETIRA
               , NVL(PCFILIAL.UTILIZAVENDAPOREMBALAGEM,'N')  -- DDMEDICA-5420
               , NVL(PCFILIAL.USAESTOQUEDEPFECHADO,'N') -- DDMEDICA-7318
            INTO vrParamFilial.vTIPOPRECIFICACAO
               , vrParamFilial.vCALCULARIPIVENDA
               , vrParamFilial.vORIGEMCUSTOFILIALRETIRA
               , vrParamFilial.vUTILIZAVENDAPOREMBALAGEM -- DDMEDICA-5420
               , vrParamFilial.vUSAESTOQUEDEPFECHADO -- DDMEDICA-7318
            FROM PCFILIAL
           WHERE (PCFILIAL.CODIGO = pi_vCodFilial);
        EXCEPTION
          WHEN NO_DATA_FOUND THEN
            vrParamFilial.vTIPOPRECIFICACAO := 'P ';
            vrParamFilial.vCALCULARIPIVENDA := 'N';
            vrParamFilial.vORIGEMCUSTOFILIALRETIRA := NULL;
            vrParamFilial.vUSAESTOQUEDEPFECHADO    := 'N'; -- DDMEDICA-7318
        END;

        -- Verifica Parâmetros Gerais
        BEGIN
          SELECT NVL(PCCONSUM.USATRIBUTACAOPORUF,'N')      USATRIBUTACAOPORUF
               , NVL(PCCONSUM.CALCULARSTCOMIPI,'N')        CALCULARSTCOMIPI
               , NVL(PCCONSUM.MOSTRARPVENDASEMST,'N')      MOSTRARPVENDASEMST
               , NVL(PCCONSUM.TIPOCALCIPI,'T2')            TIPOCALCIPI
               , NVL(PCCONSUM.TIPOCALCST,'T2')             TIPOCALCST
               , NVL(PCCONSUM.CALCSTPF,' ')                CALCSTPF
               , NVL(PCCONSUM.CONSIDERAISENTOSCOMOPF,' ')  CONSIDERAISENTOSCOMOPF
               , NVL(PCCONSUM.USACOMISSAOPORCLIENTE,' ')   USACOMISSAOPORCLIENTE
               , NVL(PCCONSUM.USACOMISSAOPORRCA,' ')       USACOMISSAOPORRCA
               , NVL(PCCONSUM.USACOMISSAOPORLINHAPROD,'N') USACOMISSAOPORLINHAPROD
               , PCCONSUM.TXVENDA
               , PCCONSUM.ABATERIMPOSTOSCOMISSAORCA
               , PCCONSUM.APLICARINDICECMV
               , PCCONSUM.INCLUIRCOMISSAOSUGPVENDACMV
               , PCCONSUM.INCLUIRCOMISSAOCMVVENDA
               , PCCONSUM.TIPOCALCSULFRAMA
            INTO vrPcConsum.vUSATRIBUTACAOPORUF
               , vrPcConsum.vCALCULARSTCOMIPI
               , vrPcConsum.vMOSTRARPVENDASEMST
               , vrPcConsum.vTIPOCALCIPI
               , vrPcConsum.vTIPOCALCST
               , vrPcConsum.vCALCSTPF
               , vrPcConsum.vCONSIDERAISENTOSCOMOPF
               , vrPcConsum.vUSACOMISSAOPORCLIENTE
               , vrPcConsum.vUSACOMISSAOPORRCA
               , vrPcConsum.vUSACOMISSAOPORLINHAPROD
               , vrPcConsum.nTXVENDA
               , vrPcConsum.vABATERIMPOSTOSCOMISSAORCA
               , vrPcConsum.vAPLICARINDICECMV
               , vrPcConsum.vINCLUIRCOMISSAOSUGPVENDACMV
               , vrPcConsum.vINCLUIRCOMISSAOCMVVENDA
               , vrPcConsum.vTIPOCALCSULFRAMA
            FROM PCCONSUM;
        EXCEPTION
          WHEN NO_DATA_FOUND THEN
            vrPcConsum.vUSATRIBUTACAOPORUF          := 'N';
            vrPcConsum.vCALCULARSTCOMIPI            := 'N';
            vrPcConsum.vMOSTRARPVENDASEMST          := 'N';
            vrPcConsum.vTIPOCALCIPI                 := 'T2';
            vrPcConsum.vTIPOCALCST                  := 'T2';
            vrPcConsum.vCALCSTPF                    := ' ';
            vrPcConsum.vCONSIDERAISENTOSCOMOPF      := ' ';
            vrPcConsum.vUSACOMISSAOPORCLIENTE       := ' ';
            vrPcConsum.vUSACOMISSAOPORLINHAPROD     := 'N';
            vrPcConsum.nTXVENDA                     := 0;
            vrPcConsum.vABATERIMPOSTOSCOMISSAORCA   := 'N';
            vrPcConsum.vAPLICARINDICECMV            := 'N';
            vrPcConsum.vINCLUIRCOMISSAOSUGPVENDACMV := 'N';
            vrPcConsum.vINCLUIRCOMISSAOCMVVENDA     := 'N';
            vrPcConsum.vTIPOCALCSULFRAMA            := ' ';
        END;

        -- Regras Específicas
        vrRegraMed.vUSARECALCULOPRECOTELEVENDAS   := FUSA_REGRA_MEDICAMENTOS('99','USARECALCULOPRECOTELEVENDAS');
        vrRegraMed.vUSAREGRARECALCPERDESCIMPOSTOS := FUSA_REGRA_MEDICAMENTOS('99','USAREGRARECALCPERDESCIMPOSTOS');
        vrRegraMed.vAPURARCOMISSAOPELORCALINHA    := FUSA_REGRA_MEDICAMENTOS('99','APURARCOMISSAOPELORCALINHA'); -- DDMEDICA-2028

        -- PCNIL - Filial Retira
        -- OBSERVAÇÃO: Antes das Implementações PCIL a Filial Retira era enviado no parâmetro pi_vCodFilialNf.
        --             agora com o Tipo de Chamada 10 (Recalcular Preço ao Alterar Plano de Pagamento) e 11 (Recuperar Orçamento)
        --             o parâmetro pi_vCodFilialNf passou a receber realmente a Filial NF do Pedido
        IF (pi_nTipoChamada IN (10,11,12,14,15)) THEN
          vvCodFilialRetira := NULL;
        -- DDMEDICA-7318 - Outra forma de resolver a Filial Retira nos Brindes que estava anteriormente o IF anterior
        ELSIF (pi_nTipoChamada IN (13)) THEN
          IF (NVL(vrParamFilial.vUSAESTOQUEDEPFECHADO,'N') = 'S') THEN
            BEGIN          
              SELECT PCFILIALRETIRA.CODFILIALRETIRA
                INTO vvCodFilialRetira
                FROM PCFILIALRETIRA
               WHERE (CODFILIALVENDA = pi_vCodFilial)
                 AND (ROWNUM = 1);
            EXCEPTION
              WHEN NO_DATA_FOUND THEN
                vvCodFilialRetira := NULL;
              WHEN DUP_VAL_ON_INDEX THEN
                vvCodFilialRetira := NULL;
            END;
          ELSE
            vvCodFilialRetira := NULL;
          END IF;
        ELSE
          -- Criado a partir da versão das campanhas o pi_vCodFilialRetira
          vvCodFilialRetira := pi_vCodFilialRetira;
        END IF;

        -- Pesquisa Dados da Filial - DDMEDICA-4799
        BEGIN
          SELECT PCFILIAL.UF
            INTO vrFilial.vUF
            FROM PCFILIAL
           WHERE (PCFILIAL.CODIGO = pi_vCodFilial);
        EXCEPTION
          WHEN NO_DATA_FOUND THEN
            vrFilial.vUF := NULL;
        END;

        -- Pesquisa Dados do Pedido Atual
        BEGIN
          SELECT PCPEDC.ORIGEMPED
               , PCPEDC.CODEMITENTE
               , PCPEDC.TIPOFV
               , PCPEDC.CODPLPAGETICO
               , PCPEDC.CODPLPAGGENERICO
               , PCPEDC.DATA
            INTO vrDadosPedidoAtual.vORIGEMPED
               , vrDadosPedidoAtual.nCODEMITENTE
               , vrDadosPedidoAtual.vTIPOFV
               , vrDadosPedidoAtual.nCODPLPAGETICO
               , vrDadosPedidoAtual.nCODPLPAGGENERICO
               , vdDataItemPedido
            FROM PCPEDC
           WHERE (PCPEDC.NUMPED = pi_nNumPed);
        EXCEPTION
          WHEN NO_DATA_FOUND THEN
            vrDadosPedidoAtual.vORIGEMPED        := 'T'; -->> SE NÃO ACHAR ASSUMIR TELEVENDAS - SEM ISSO DÁ DIVERGÊNCIA NA INCLUSÃO DO PEDIDO
            vrDadosPedidoAtual.nCODEMITENTE      := NULL;
            vrDadosPedidoAtual.vTIPOFV           := SUBSTR(pi_vTipoFv,1,2); -- DDMEDICA-619
            vrDadosPedidoAtual.nCODPLPAGETICO    := NULL;
            vrDadosPedidoAtual.nCODPLPAGGENERICO := NULL;
            vdDataItemPedido                     := vdDataPedido; -->> Se não achar o Cab. Pedido, a Data do Item será a Data Atual
        END;
        -- Se passou o Plano e Genérico do Pedido assume eles
        IF (NVL(pi_nCodPlPagEtico,0)    > 0) AND
           (NVL(pi_nCodPlPagGenerico,0) > 0) THEN
          vrDadosPedidoAtual.nCODPLPAGETICO    := pi_nCodPlPagEtico;
          vrDadosPedidoAtual.nCODPLPAGGENERICO := pi_nCodPlPagGenerico;
        END IF;

        -- DDMEDICA-1241- Controle de Tributação de Pedido de Avaria de Perda
        IF (NVL(pi_vTipoFv,'XX') = 'PAP') THEN
          vvTributPedidoAvariaPerda := 'S';
        ELSE
          vvTributPedidoAvariaPerda := 'N';
        END IF;

        -- Pesquisa dados do RCA
        BEGIN
          SELECT 'S'
               , PCUSUARI.CODDISTRIB
               , PCUSUARI.CODSUPERVISOR
               , PCUSUARI.TIPOVEND
               , PCUSUARI.PERCENT2
            INTO vrRca.vcAchouRCA
               , vrRca.vCODDISTRIB
               , vrRca.nCODSUPERVISOR
               , vrRca.vTIPOVEND
               , vrRca.nPERCENT2
            FROM PCUSUARI
           WHERE (PCUSUARI.CODUSUR = pi_nCodUsur);
        EXCEPTION
          WHEN NO_DATA_FOUND THEN
            -- Rejeita
            po_vMotivoNaoPodeGravar := 'RCA ' || NVL(pi_nCodUsur,0) || ' não cadastrado para inclusão do KIT!';
            RAISE e_Tratado;
        END;

        -- Pesquisa Dados do Cliente
        BEGIN
          SELECT 'S' ACHOU_CLIENTE
               , PCCLIENT.CGCENT
               , PCCLIENT.VALIDARMULTIPLOVENDA
               , PCCLIENT.CODCOB
               , PCCLIENT.CODPLPAG
               , PCCLIENT.OBSENTREGA1
               , PCCLIENT.OBSENTREGA2
               , PCCLIENT.OBSENTREGA3
               , PCCLIENT.CODPRACA
               , PCCLIENT.CGCENT
               , NVL(PCCLIENT.TIPOCUSTOTRANSF,'E') TIPOCUSTOTRANSF
               , NVL(PCCLIENT.PERACRESTRANSF,0) PERACRESTRANSF
               , PCCLIENT.ISENTOIPI
               , PCCLIENT.SULFRAMA
               , PCCLIENT.TIPOFJ
               , PCCLIENT.ESTENT
               , PCCLIENT.CALCULAST
               , UPPER(PCCLIENT.IEENT) IEENT
               , PCCLIENT.PERCOMCLI
               , PCCLIENT.TIPOEMPRESA
               , NVL(PCCLIENT.UTILIZAIESIMPLIFICADA,'N') UTILIZAIESIMPLIFICADA
               , PCCLIENT.FANTASIA
               , PCCLIENT.CLIENTEFONTEST
               , PCCLIENT.CODATV1
               , PCCLIENT.REPASSE
               , PCCLIENT.USAIVAFONTEDIFERENCIADO
               , PCCLIENT.TIPODESCISENCAO
               , PCCLIENT.PERDESCISENTOICMS
               , PCCLIENT.CONTRIBUINTE
               , PCCLIENT.CLASSEVENDA
               , PCCLIENT.ORGAOPUB
               , PCCLIENT.ORGAOPUBFEDERAL
               , PCCLIENT.ORGAOPUBMUNICIPAL
               , PCCLIENT.UTILIZAPLPAGMEDICAMENTO
               , PCCLIENT.CONSUMIDORFINAL
               , PCCLIENT.PERDESC
               , PCCLIENT.SIMPLESNACIONAL
               , PCCLIENT.CODREDE -- MED-2453
               , PCCLIENT.TIPOCUSTOTRANSFTV9
            INTO vrClienteDestino.vvAchouDadosCliente
               , vrClienteDestino.vvCgcClienteDestino
               , vrClienteDestino.vVALIDARMULTIPLOVENDA
               , vrClienteDestino.vCODCOB
               , vrClienteDestino.nCODPLPAG
               , vrClienteDestino.vOBSENTREGA1
               , vrClienteDestino.vOBSENTREGA2
               , vrClienteDestino.vOBSENTREGA3
               , vrClienteDestino.nCODPRACA
               , vrClienteDestino.vCGCENT
               , vrClienteDestino.vTIPOCUSTOTRANSF
               , vrClienteDestino.nPERACRESTRANSF
               , vrClienteDestino.nISENTOIPI
               , vrClienteDestino.vSULFRAMA
               , vrClienteDestino.vTIPOFJ
               , vrClienteDestino.vESTENT
               , vrClienteDestino.vCALCULAST
               , vrClienteDestino.vIEENT
               , vrClienteDestino.nPERCOMCLI
               , vrClienteDestino.vTIPOEMPRESA
               , vrClienteDestino.vUTILIZAIESIMPLIFICADA
               , vrClienteDestino.vFANTASIA
               , vrClienteDestino.vCLIENTEFONTEST
               , vrClienteDestino.vCODATV1
               , vrClienteDestino.vREPASSE
               , vrClienteDestino.vUSAIVAFONTEDIFERENCIADO
               , vrClienteDestino.nTIPODESCISENCAO
               , vrClienteDestino.nPERDESCISENTOICMS
               , vrClienteDestino.vCONTRIBUINTE
               , vrClienteDestino.vCLASSEVENDA
               , vrClienteDestino.vORGAOPUB
               , vrClienteDestino.vORGAOPUBFEDERAL
               , vrClienteDestino.vORGAOPUBMUNICIPAL
               , vrClienteDestino.vUTILIZAPLPAGMEDICAMENTO
               , vrClienteDestino.vCONSUMIDORFINAL
               , vrClienteDestino.nPERDESC
               , vrClienteDestino.nSIMPLESNACIONAL
               , vrClienteDestino.nCODREDE -- MED-2453
               , vrClienteDestino.vTIPOCUSTOTRANSFTV9
            FROM PCCLIENT
           WHERE (PCCLIENT.CODCLI = pi_nCodCli);
        EXCEPTION
          WHEN NO_DATA_FOUND THEN
            -- Rejeita
            po_vMotivoNaoPodeGravar := 'Cliente ' || NVL(pi_nCodCli,0) || ' não cadastrado para inclusão do KIT!';
            RAISE e_Tratado;
        END;
        
        -- DDVENDAS-33920 - UF do Endereço de Entrega
        IF (NVL(pi_nCodEndEntCli,0) > 0) AND
           (NVL(vrParamFilial.vUTILIZATRIBENDENT,'N') = 'S') THEN
          BEGIN
            SELECT PCCLIENTENDENT.ESTENT
              INTO vrClienteDestino.vESTENT
              FROM PCCLIENTENDENT
             WHERE (PCCLIENTENDENT.CODCLI       = pi_nCodCli)
               AND (PCCLIENTENDENT.CODENDENTCLI = pi_nCodEndEntCli);
          EXCEPTION
            WHEN NO_DATA_FOUND THEN
              NULL; -->> Não faz nada senão existir (mantém o ESTENT do Cliente)
          END;
        END IF;

        -- Pesquisa Dados do Ramo de Atividade
        BEGIN
          SELECT PCATIVI.PERCDESC
            INTO vrRamoAtividade.nPERCDESC
            FROM PCATIVI
           WHERE (PCATIVI.CODATIV = vrClienteDestino.vCODATV1);
        EXCEPTION
          WHEN NO_DATA_FOUND THEN
            vrRamoAtividade.nPERCDESC := 0;
        END;

        -- Pesquisa Parâmetros de Tributação do Cliente por Filial
        BEGIN
          SELECT PCCLIENTFILIALMED.CLIENTEFONTEST
               , PCCLIENTFILIALMED.REPASSE
            INTO vrClienteDestino.vCLIENTEFONTEST
               , vrClienteDestino.vREPASSE
            FROM PCCLIENTFILIALMED
           WHERE (PCCLIENTFILIALMED.CODCLI    = pi_nCodCli)
             AND (PCCLIENTFILIALMED.CODFILIAL = pi_vCodFilial);
        EXCEPTION
          WHEN NO_DATA_FOUND THEN
            -- Se não encontrar Parâmetros de Tributação do Cliente por Filial, ignora, mantendo os o Cliente
            NULL;
        END;

        -- Se passou a Região
        IF (NVL(pi_nNumRegiao,0) > 0) THEN

          -- Pega Região do Parâmetro
          vrRegiao.nNUMREGIAO := pi_nNumRegiao;

        -- Se NÃO passou a Região
        ELSE

          -- Pesquisa Regiao do Cliente por Filial
          BEGIN
            SELECT NUMREGIAO
              INTO vrRegiao.nNUMREGIAO
              FROM PCTABPRCLI
             WHERE (CODCLI      = pi_nCodCli)
               AND (CODFILIALNF = NVL(pi_vCodFilialNF,pi_vCodFilial)); -- HIS.03764.2016
          EXCEPTION
            -- Se não encontrar Regiao do Cliente por Filial
            WHEN NO_DATA_FOUND THEN
              -- Pesquisa a Região do Cliente
              BEGIN
                SELECT PCPRACA.NUMREGIAO
                  INTO vrRegiao.nNUMREGIAO
                  FROM PCPRACA
                 WHERE (PCPRACA.CODPRACA = vrClienteDestino.nCODPRACA);
              EXCEPTION
                WHEN NO_DATA_FOUND THEN
                  -- Rejeita
                  po_vMotivoNaoPodeGravar := 'Praça ' || NVL(vrClienteDestino.nCODPRACA,0) || ' não cadastrada para inclusão do KIT!';
                  RAISE e_Tratado;
              END;
          END;

        END IF; -- Fim Condição Se passou a Região

        -- PCNIL - REGRA PACOTE - PRIORIZAR REGIÃO DA TABELA DE PREÇOS AO:
        -- RECALCULAR PEDIDO AO MUDAR PLANO DE PAGAMENTO
        -- RECUPERAR ORÇAMENTO
        IF (pi_nTipoChamada IN (10,11,12,13,14,15))             AND
           (vrRegraMed.vUSAREGRARECALCPERDESCIMPOSTOS = 'S')    AND
           (NVL(pi_vCodFilialNF,' ') <> NVL(pi_vCodFilial,' ')) THEN
          -- Verifica se Filial NF Válida
          BEGIN
            SELECT 'S'
              INTO vvFiliaNfExiste
              FROM PCFILIAL
             WHERE (PCFILIAL.CODIGO = pi_vCodFilialNF);
          EXCEPTION
            WHEN NO_DATA_FOUND THEN
              vvFiliaNfExiste := 'N';
          END;
          -- Se Filial NF Válida
          IF (vvFiliaNfExiste = 'S') THEN
            -- Pesquisa Regiao do Cliente por Filial
            BEGIN
              SELECT NUMREGIAO
                INTO vrRegiao.nNUMREGIAO
                FROM PCTABPRCLI
               WHERE (CODCLI      = pi_nCodCli)
                 AND (CODFILIALNF = pi_vCodFilialNF); -->> PCNIL - Aqui somente pelo Código da Filial NF, para o caso de não ser informada manter a Região Original
            EXCEPTION
              -- Se não encontrar Regiao do Cliente por Filial
              WHEN NO_DATA_FOUND THEN
                NULL; -->> Mantém Região Original
            END;
          END IF; -- Fim Condição: -- Se Filial NF Válida
        END IF; -- PCNIL - REGRA PACOTE - PRIORIZAR REGIÃO DA TABELA DE PREÇOS

        -- Pesquisa dados do Plano de Pagamento
        BEGIN
          SELECT PCREGIAO.REGIAOZFM
               , PCREGIAO.PERFRETETERCEIROS
               , PCREGIAO.PERFRETEESPECIAL
            INTO vrRegiao.vREGIAOZFM
               , vrRegiao.nPERFRETETERCEIROS
               , vrRegiao.nPERFRETEESPECIAL
            FROM PCREGIAO
           WHERE (PCREGIAO.NUMREGIAO = vrRegiao.nNUMREGIAO);
        EXCEPTION
          WHEN NO_DATA_FOUND THEN
            -- Rejeita
            po_vMotivoNaoPodeGravar := 'Dados da Região ' || NVL(vrRegiao.nNUMREGIAO,0) || ' não encontrados para inclusão do KIT!';
            RAISE e_Tratado;
        END;

        -----------------------
        -- ITENS DO COMBO - KIT
        -----------------------
        IF    (pi_nTipoChamada = 2) THEN

          -- Controle de Ocorrências dos Produtos noutras Promoções
          viQtOcorrenciasOutrasPromo  := 0;
          vvMsgOcorrenciasOutrasPromo := NULL;

          -- Carrega Array com Itens da Promoção
          FOR vc_Promo IN (SELECT DISTINCT
                                  PCDESCONTO.CODPROD
                                , PCDESCONTO.INICIOINTERVALOPROMOCAOMED
                                , PCDESCONTO.PERCDESC
                                , PCDESCONTO.PERCDESCFIN
                                , MIN(PCDESCONTO.CODDESCONTO) CODDESCONTO -->> Pra não dar Duplicidade
                                , PCDESCONTO.CODPROMOCAOMED
                                , PCDESCONTO.PERCOMMINT
                                , PCDESCONTO.PERCOMEXT
                                , PCDESCONTO.PERCOMREP
                                , PCDESCONTO.CONSIDERACALCGIROMEDIC
                                , PCDESCONTO.PRECOFIXOPROMOCAOMED
                                , PCPRODUT.DESCRICAO
                                , PCDESCONTO.VLDESCCMVPROMOCAOMED -- DDMEDICA-5009
                                , PCPRODUT.CODFORNEC -- DDMEDICA-5009
                                , PCPROMOCAOMED.PRIORIZACOMISSAO -- DDVENDAS-35939
                                , PCPROMOCAOMED.CODGRUPOCOMISSAO -- DDVENDAS-35939
                             FROM PCDESCONTO
                                , PCPRODUT
                                , PCPROMOCAOMED
                            WHERE (PCDESCONTO.CODPROD        = PCPRODUT.CODPROD)
                              AND (PCDESCONTO.CODPROMOCAOMED = pi_nCodPromocaoMedPedido)
                              AND (PCDESCONTO.CODPROMOCAOMED = PCPROMOCAOMED.CODPROMOCAOMED)
                              AND (PCDESCONTO.INICIOINTERVALOPROMOCAOMED > 0) -->> GARANTIR SOMENTE COM QTDE > 0
                            GROUP BY PCDESCONTO.CODPROD
                                   , PCDESCONTO.INICIOINTERVALOPROMOCAOMED
                                   , PCDESCONTO.PERCDESC
                                   , PCDESCONTO.PERCDESCFIN
                                   , PCDESCONTO.CODPROMOCAOMED
                                   , PCDESCONTO.PERCOMMINT
                                   , PCDESCONTO.PERCOMEXT
                                   , PCDESCONTO.PERCOMREP
                                   , PCDESCONTO.CONSIDERACALCGIROMEDIC
                                   , PCDESCONTO.PRECOFIXOPROMOCAOMED
                                   , PCPRODUT.DESCRICAO
                                   , PCDESCONTO.VLDESCCMVPROMOCAOMED -- DDMEDICA-5009
                                   , PCPRODUT.CODFORNEC -- DDMEDICA-5009
                                   , PCPROMOCAOMED.PRIORIZACOMISSAO -- DDVENDAS-35939
                                   , PCPROMOCAOMED.CODGRUPOCOMISSAO -- DDVENDAS-35939
                                   ) LOOP

            -- Pesquisa ocorrências do Produto em Promoções diferentes
            -- (SE NÃO USA CHAVE TRIPLA CRITICA O PRODUTO JÁ INSERIDO)
            IF (NVL(vrParamFilial.vUSACHAVETRIPLAPCPEDI,'N') = 'N') THEN
              BEGIN
                SELECT 'S'
                  INTO vvAchouProduto
                  FROM PCPEDI
                 WHERE (PCPEDI.NUMPED                 = pi_nNumPed)
                   AND (PCPEDI.CODPROD                = vc_Promo.CODPROD)
                   AND (NVL(PCPEDI.CODPROMOCAOMED,0) <> NVL(vc_Promo.CODPROMOCAOMED,0))
                   AND (ROWNUM                        = 1);
               EXCEPTION
                 WHEN NO_DATA_FOUND THEN
                   vvAchouProduto := 'N';
              END;
              IF (vvAchouProduto = 'S') THEN
                -- Incrementa Controle de Ocorrências dos Produtos noutras Promoções
                viQtOcorrenciasOutrasPromo := NVL(viQtOcorrenciasOutrasPromo,0) + 1;
                -- Concatena Produtos
                IF (vvMsgOcorrenciasOutrasPromo IS NULL) THEN
                  vvMsgOcorrenciasOutrasPromo := vc_Promo.CODPROD || ' - ' || vc_Promo.DESCRICAO;
                ELSE
                  vvMsgOcorrenciasOutrasPromo := vvMsgOcorrenciasOutrasPromo || CHR(13) || vc_Promo.CODPROD || ' - ' || vc_Promo.DESCRICAO;
                END IF;
              END IF;
            END IF;

            -- Validação Controlados Combo - DDMEDICA-735
            PKG_FUNCOESVENDAS_MED.P_VALIDACAO_FINAL_PROD_01('C',
                                         'I',
                                         'N',
                                         vrDadosPedidoAtual.vORIGEMPED,
                                         vrDadosPedidoAtual.vTIPOFV,
                                         NULL, -- pi_nIntegradora
                                         pi_vCodFilial,
                                         pi_vCodFilialNf,
                                         pi_vCodFilialRetira,
                                         pi_nCodCli,
                                         pi_nNumRegiao,
                                         pi_nCodUsur,
                                         pi_nCodPlPag,
                                         NULL, -- pi_nCodPromocaoMed,
                                         vc_Promo.CODPROD,
                                         (NVL(vc_Promo.INICIOINTERVALOPROMOCAOMED,0) * NVL(pi_nQtCombos,0)),
                                         NULL, -- pi_nPercDesc
                                         NULL, -- pi_nPUnitario
                                         NULL, -- pi_nNumPed
                                         NULL, -- pi_nNumSeq
                                         0.01, -- pi_nPrecoMaxConsum
                                         vrRetValidaProd.vTipoRejeicaoProduto,
                                         vrRetValidaProd.vMotivoNaoPodeComprar,
                                         vrRetValidaProd.nQtdeLimite,
                                         NULL, -- pi_nCodDesconto
                                         NULL, -- pi_vNumLote
                                         NULL, -- pi_vNumLotePromocaoMed
                                         NULL, -- pi_nPTabela
                                         NULL, -- pi_nPTabelaMarkup
                                         NULL  -- pi_nCustoFin
                                         );
            IF (vrRetValidaProd.vTipoRejeicaoProduto = 'R') THEN
              -- Incrementa Controle de Ocorrências dos Controlados
              viQtOcorrenciasControlados := NVL(viQtOcorrenciasControlados,0) + 1;
              -- Concatena Produtos
              IF (vvMsgOcorrenciasControlados IS NULL) THEN
                vvMsgOcorrenciasControlados := vc_Promo.CODPROD || ' - ' || vc_Promo.DESCRICAO || ': ' || vrRetValidaProd.vMotivoNaoPodeComprar;
              ELSE
                vvMsgOcorrenciasControlados := vvMsgOcorrenciasControlados || CHR(13) || vc_Promo.CODPROD || ' - ' || vc_Promo.DESCRICAO || ': ' || vrRetValidaProd.vMotivoNaoPodeComprar;
              END IF;
            END IF;

            -- Insere Item no Array
            viIdxNew                                           := NVL(vtIncluiItens.COUNT,0) + 1;
            vtIncluiItens(viIdxNew).vnCodProd                  := vc_Promo.CODPROD;
            vtIncluiItens(viIdxNew).vnQtde                     := (NVL(vc_Promo.INICIOINTERVALOPROMOCAOMED,0) * NVL(pi_nQtCombos,0)); -->> MULTIPLICA PELA QUANTIDADE DE COMBOS
            vtIncluiItens(viIdxNew).vnPercDesc                 := NVL(vc_Promo.PERCDESC,0);
            vtIncluiItens(viIdxNew).vnPerDescBoleto            := NVL(vc_Promo.PERCDESCFIN,0);
            vtIncluiItens(viIdxNew).vnCodDesconto              := vc_Promo.CODDESCONTO;
            vtIncluiItens(viIdxNew).vnCodPromocaoMed           := vc_Promo.CODPROMOCAOMED;
            vtIncluiItens(viIdxNew).vnInicioIntervaloDescQuant := vc_Promo.INICIOINTERVALOPROMOCAOMED; -->> AQUI NÃO PODE COLOCAR NVL()
            -- Comissão por Grupo vinculado na PCPROMOCAOMED - DDVENDAS-35939
            IF (NVL(vc_Promo.PRIORIZACOMISSAO,'N') = 'S') AND
               (NVL(vc_Promo.CODGRUPOCOMISSAO,0) > 0)     THEN
              vtIncluiItens(viIdxNew).vnPerComInt              := F_OBTER_COMISS_GRUPO_PROMOCAO(pi_nCodPromocaoMedPedido,
                                                                                                vc_Promo.CODGRUPOCOMISSAO,
                                                                                                vc_Promo.CODPROD);
              vtIncluiItens(viIdxNew).vnPerComExt              := vtIncluiItens(viIdxNew).vnPerComInt;
              vtIncluiItens(viIdxNew).vnPerComRep              := vtIncluiItens(viIdxNew).vnPerComInt;
            -- Comissão da PCDESCONTO              
            ELSE
              vtIncluiItens(viIdxNew).vnPerComInt              := NVL(vc_Promo.PERCOMMINT,0);
              vtIncluiItens(viIdxNew).vnPerComExt              := NVL(vc_Promo.PERCOMEXT,0);
              vtIncluiItens(viIdxNew).vnPerComRep              := NVL(vc_Promo.PERCOMREP,0);
            END IF;              
            vtIncluiItens(viIdxNew).vvParticipaGiro            := NVL(vc_Promo.CONSIDERACALCGIROMEDIC,'S');
            vtIncluiItens(viIdxNew).vnPrecoFixo                := NVL(vc_Promo.PRECOFIXOPROMOCAOMED,0);
            vtIncluiItens(viIdxNew).vvBonific                  := 'N';
            vtIncluiItens(viIdxNew).vnPBonific                 := NULL;
            vtIncluiItens(viIdxNew).vnCodSt                    := NULL;
            -- Verba para Rebaixa de CMV da Promoção - DDMEDICA-5009
            vtIncluiItens(viIdxNew).vnVlDescCmvPromocaoMed     := vc_Promo.VLDESCCMVPROMOCAOMED;
            -- Obter Verba Relacionada com o Valor da Verba para Rebaixa de CMV da Promoção da PCDESCONTO - DDMEDICA-5009
            P_OBTER_VERBA_PROMOCAO(vc_Promo.CODPROMOCAOMED,
                                   vc_Promo.CODFORNEC,
                                   vtIncluiItens(viIdxNew).vnVlDescCmvPromocaoMed,
                                   vtIncluiItens(viIdxNew).vnNumVerbaCampanha,
                                   vtIncluiItens(viIdxNew).vnValorCotaNumVerba,
                                   vtIncluiItens(viIdxNew).vvSemVerbaVlDescCmv);

          END LOOP; -- Fim Laço Itens da Promoção

          -- Se Ocorrências dos Produtos noutras Promoções
          IF (viQtOcorrenciasOutrasPromo > 0) THEN
            IF    (viQtOcorrenciasOutrasPromo = 1) THEN
              vvMsgOcorrenciasOutrasPromo := 'Produto encontrado no Pedido para outra Promoção: ' || CHR(13) || vvMsgOcorrenciasOutrasPromo;
            ELSIF (viQtOcorrenciasOutrasPromo > 1) THEN
              vvMsgOcorrenciasOutrasPromo := 'Produtos encontrados no Pedido para outras Promoções: ' || CHR(13) || vvMsgOcorrenciasOutrasPromo;
            END IF;
            po_vMotivoNaoPodeGravar := SUBSTR(vvMsgOcorrenciasOutrasPromo,1,2000);
            RAISE e_Tratado;
          END IF;

          -- Se Ocorrências dos Produtos Controlados
          IF (viQtOcorrenciasControlados > 0) THEN
            IF    (viQtOcorrenciasControlados = 1) THEN
              vvMsgOcorrenciasControlados := 'Produto Controlado não permitido no Combo: ' || CHR(13) || vvMsgOcorrenciasControlados;
            ELSIF (viQtOcorrenciasControlados > 1) THEN
              vvMsgOcorrenciasControlados := 'Produtos Controlados não permitidos no Combo: ' || CHR(13) || vvMsgOcorrenciasControlados;
            END IF;
            po_vMotivoNaoPodeGravar := SUBSTR(vvMsgOcorrenciasControlados,1,2000);
            RAISE e_Tratado;
          END IF;

        --------------------------------
        -- ITENS DO EMPENHO DA LICITAÇÃO
        --------------------------------
        ELSIF (pi_nTipoChamada = 3) OR (pi_nTipoChamada = 18) THEN

          -- Trata o Pedido como utilizando Promoção de Preço Fixo pra usar o Preço do Edital
          vvTipoPoliticaPedido := 'P';

          -- Monta SQL
          vsSQL := ' SELECT I.LOTE, I.NUMERO_ITEM, I.CODPROD, I.QTPEDIDO, I.PRECO, I.PERCOM FROM PCLICIT_EMPENHOSITENS I WHERE (I.SELECIONADO = ''S'') ';

          -- Processa Cursor
          OPEN vRefCursor FOR vsSQL;
          LOOP

            -- Leitura do Registro do Cursor
            FETCH vRefCursor INTO vrDadosEmpenho;
            EXIT WHEN vRefCursor%NOTFOUND;

            -- Insere Item no Array
            viIdxNew                                           := NVL(vtIncluiItens.COUNT,0) + 1;
            vtIncluiItens(viIdxNew).vnCodProd                  := vrDadosEmpenho.vnCodProd;
            vtIncluiItens(viIdxNew).vnQtde                     := NVL(vrDadosEmpenho.vnQt,0);
            vtIncluiItens(viIdxNew).vnPercDesc                 := 0;
            vtIncluiItens(viIdxNew).vnPerDescBoleto            := 0;
            vtIncluiItens(viIdxNew).vnCodDesconto              := NULL;
            vtIncluiItens(viIdxNew).vnCodPromocaoMed           := NULL;
            vtIncluiItens(viIdxNew).vnInicioIntervaloDescQuant := NULL;
            vtIncluiItens(viIdxNew).vnPerComInt                := 0;
            vtIncluiItens(viIdxNew).vnPerComExt                := 0;
            vtIncluiItens(viIdxNew).vnPerComRep                := NVL(vrDadosEmpenho.vnPerCom,0); -->> PRECISA SER REAAVALIADO
            vtIncluiItens(viIdxNew).vvParticipaGiro            := 'S';
            vtIncluiItens(viIdxNew).vnPrecoFixo                := NVL(vrDadosEmpenho.vnPreco,0);
            vtIncluiItens(viIdxNew).vvLoteContrato             := vrDadosEmpenho.vvLoteContrato;
            vtIncluiItens(viIdxNew).vnNumSeqItemContrato       := vrDadosEmpenho.vnNumSeqItemContrato;
            vtIncluiItens(viIdxNew).vvBonific                  := 'N';
            vtIncluiItens(viIdxNew).vnPBonific                 := NULL;
            vtIncluiItens(viIdxNew).vnCodSt                    := NULL;
            vtIncluiItens(viIdxNew).vnFatorGramaturaLicit      := NULL;
            vtIncluiItens(viIdxNew).vvCodigoIntegracaoWms      := NULL;
            vtIncluiItens(viIdxNew).vvNumLotePromocaoMed       := NULL;
            
            -- DDVENDAS-33442 - Conversão Empenho no novo Processo de Licitação
            IF (vrParamFilial.vUTILIZANOVOPROCESSOLICITACAO = 'S') THEN
              BEGIN
                SELECT FATORCONVERSAO
                     , CODUNIDADE
                     , SUBSTR(DESCRICAO_AUXILIAR,1,120)
                  INTO vnFatorConversaoLicitacao
                     , vvUnidadeLicitacao
                     , vvDescricaoProdutoDanfe 
                  FROM PCEDITAISITENS
                 WHERE (CODEDITAL   = pi_nCodEdital)
                   AND (LOTE        = vrDadosEmpenho.vvLoteContrato)
                   AND (NUMERO_ITEM = vrDadosEmpenho.vnNumSeqItemContrato);
              EXCEPTION
                WHEN NO_DATA_FOUND THEN
                  vnFatorConversaoLicitacao := 0;
                  vvUnidadeLicitacao        := NULL;
                  vvDescricaoProdutoDanfe   := NULL;
              END;
              IF (vnFatorConversaoLicitacao > 0) THEN
                -- Parâmetro de Conversão da Licitação
                vvAplicarFatorLicitacao := F_OBTEM_PARAM_LICITACAO('APLICFATCONVPEDIDOVENDA',
                                                                   'N');
                -- Se possui Conversão no Pedido de Venda
                IF (vvAplicarFatorLicitacao IN ('D','M')) THEN
                  -- Converte Quantidade e Preço
                  IF    (vvAplicarFatorLicitacao = 'D') THEN
                    vtIncluiItens(viIdxNew).vnQtde      := (NVL(vtIncluiItens(viIdxNew).vnQtde,0) / NVL(vnFatorConversaoLicitacao,0));
                    vtIncluiItens(viIdxNew).vnPrecoFixo := (NVL(vtIncluiItens(viIdxNew).vnPrecoFixo,0) * NVL(vnFatorConversaoLicitacao,0));
                  ELSIF (vvAplicarFatorLicitacao = 'M') THEN
                    vtIncluiItens(viIdxNew).vnQtde      := (NVL(vtIncluiItens(viIdxNew).vnQtde,0) * NVL(vnFatorConversaoLicitacao,0));
                    vtIncluiItens(viIdxNew).vnPrecoFixo := (NVL(vtIncluiItens(viIdxNew).vnPrecoFixo,0) / NVL(vnFatorConversaoLicitacao,0));
                  END IF;
                  -- Arredondamento
                  vtIncluiItens(viIdxNew).vnQtde      := ROUND(vtIncluiItens(viIdxNew).vnQtde,vrParamFilial.nCON_NUMCASASDECESTOQUE);
                  vtIncluiItens(viIdxNew).vnPrecoFixo := ROUND(vtIncluiItens(viIdxNew).vnPrecoFixo,vrParamFilial.nCON_NUMCASASDECVENDA);
                  -- Guarda informações de conversão para atualizar na PCPEDI
                  vtIncluiItens(viIdxNew).vnCodEdital                := pi_nCodEdital; 
                  vtIncluiItens(viIdxNew).vnQtPedLicit               := NVL(vrDadosEmpenho.vnQt,0); 
                  vtIncluiItens(viIdxNew).vnTipoConversaoPedLicit    := TO_NUMBER(NVL(vrParamFilial.vMEDTIPOARREDQTPEDLICIT,'0'));
                  vtIncluiItens(viIdxNew).vvUnidadeConversaoPedLicit := vvUnidadeLicitacao; 
                  vtIncluiItens(viIdxNew).vnFatorConversaoPedLicit   := vnFatorConversaoLicitacao; 
                  -- Se conversão de embalagem no DANFE
                  IF (NVL(vrParamFilial.vMEDTIPOARREDQTPEDLICIT,'1') IN ('1','4')) THEN
                    vtIncluiItens(viIdxNew).vvDescricaoProdutoDanfe := F_LICIT_ACENTO_CHAR_ESPECIAL(vvDescricaoProdutoDanfe);
                  END IF;                  
                END IF;
              END IF;
            END IF;

          END LOOP; -- Fim Processamento Cursor

          -- Fecha Cursor
          CLOSE vRefCursor;

        ------------------
        -- ITENS DO PEDIDO
        ------------------
        ELSIF (pi_nTipoChamada IN (4,5,10,12)) THEN

          -- Carrega Array com Itens do Pedido
          FOR vc_ItensPed IN (SELECT PCPEDI.CODPROD
                                   , PCPEDI.QT
                                   , PCPEDI.PERDESC
                                   , PCPEDI.PERDESCBOLETO
                                   , PCPEDI.CODDESCONTO
                                   , PCPEDI.CODPROMOCAOMED
                                   , PCPEDI.INICIOINTERVALODESCQUANT
                                   , PCPEDI.PERCOM
                                   , PCPEDI.NUMSEQ
                                   , PCPEDI.PTABELA
                                   , PCPEDI.PVENDA
                                   , PCPEDI.PBASERCA
                                   , PCPEDI.ST
                                   , PCPEDI.VLREPASSE
                                   , PCPEDI.BONIFIC
                                   , PCPEDI.PBONIFIC
                                   , PCPEDI.PERCDESCBASERCA
                                   , PCPEDI.TIPOCOMISSAOMED
                                   , PCPEDI.VLREDPVENDASIMPLESNA
                                   , PCPEDI.VLREDCMVSIMPLESNAC
                                   , ( (PCPEDI.PTABELA 
                                       - NVL(PCPEDI.VLREPASSE,0) 
                                       - NVL(PCPEDI.ST,0) 
                                       - NVL(PCPEDI.VLICMSSTRETANTERIOR,0) -- DDMEDICA-7697
                                       - NVL(PCPEDI.VLFECP,0)) 
                                       + NVL(PCPEDI.VLDESCICMISENCAO,0)
                                       + NVL(PCPEDI.VLDESCSUFRAMA,0) 
                                       + NVL(PCPEDI.VLDESCREDUCAOPIS,0) 
                                       + NVL(PCPEDI.VLDESCREDUCAOCOFINS,0) ) PRECOBRUTO
                                   , ( (PCPEDI.PVENDA 
                                       - NVL(PCPEDI.VLREPASSE,0) 
                                       - NVL(PCPEDI.ST,0) 
                                       - NVL(PCPEDI.VLICMSSTRETANTERIOR,0) -- DDMEDICA-7697
                                       - NVL(PCPEDI.VLFECP,0))  
                                       + NVL(PCPEDI.VLDESCICMISENCAO,0)
                                       + NVL(PCPEDI.VLDESCSUFRAMA,0) 
                                       + NVL(PCPEDI.VLDESCREDUCAOPIS,0) 
                                       + NVL(PCPEDI.VLDESCREDUCAOCOFINS,0) ) PRECOLIQUIDO
                                   , PCPEDI.CODST
                                   , PCPEDI.BRINDE
                                   , PCPEDI.CODPLPAG -- 4415.145077.2018
                                   , PCPEDI.CODFILIALRETIRA
                                   -- DDMEDICA-5009
                                   , PCPEDI.VLDESCCMVPROMOCAOMED
                                   , PCPEDI.NUMVERBACAMPANHA
                                   , PCPEDI.VLVERBACMV
                                   , PCPEDI.PERCCUSTFORNEC
                                   , PCPEDI.STCLIENTEGNRE -- DDMEDICA-7697
                                   , PCPEDI.BASEICST      -- DDMEDICA-7697
								   , PCPEDI.NUMVERBAREBCMV
                                FROM PCPEDI
                               WHERE (PCPEDI.NUMPED = pi_nNumPed)) LOOP

            -- Inicializa Variável indicando que pode carregar Item
            vbPodeCarregarItem := TRUE;

            -- SE CHAMADO PARA ALTERAR PROMOÇÃO DO PEDIDO, verifica se pode editar o Item do Pedido
            IF    (pi_nTipoChamada = 4) THEN

              -- Se não pode editar o item
              IF (NOT F_EDITAR_ITEM_MOV_SALDORCA(vrParamFilial.vBLOQEDICAOITENSMOVSALDORCAFV,
                                                 vrDadosPedidoAtual.vORIGEMPED,
                                                 vrDadosPedidoAtual.vTIPOFV,
                                                 pi_nNumPed,
                                                 vc_ItensPed.CODPROD,
                                                 vc_ItensPed.NUMSEQ,
                                                 vc_ItensPed.BONIFIC)) THEN
                -- Atualiza Variável indicando que não pode carregar Item
                vbPodeCarregarItem := FALSE;
              END IF;

            -- SE RECALCULO DO PEDIDO AO ALTERAR PLANO DE PAGAMENTO, verifica se a Promoção é de Preço ou Preço por Faixa de Quantidade, e se pode Editar o Pedido
            ELSIF (pi_nTipoChamada = 10) THEN

              -- Se não pode editar o item
              IF (NOT F_EDITAR_ITEM_MOV_SALDORCA(vrParamFilial.vBLOQEDICAOITENSMOVSALDORCAFV,
                                                 vrDadosPedidoAtual.vORIGEMPED,
                                                 vrDadosPedidoAtual.vTIPOFV,
                                                 pi_nNumPed,
                                                 vc_ItensPed.CODPROD,
                                                 vc_ItensPed.NUMSEQ,
                                                 vc_ItensPed.BONIFIC)) THEN
                -- Atualiza Variável indicando que não pode carregar Item
                vbPodeCarregarItem := FALSE;

              -- Se pode editar o item
              ELSE

                -- Se já estiver passando o Plano Ético e Genérico
                IF (NVL(pi_nCodPlPagEtico,0)    > 0) AND
                   (NVL(pi_nCodPlPagGenerico,0) > 0) THEN

                  -- Pesquisa Promoção
                  BEGIN
                    SELECT 'S'
                      INTO vvPromocaoDePreco
                      FROM PCPROMOCAOMED
                     WHERE (PCPROMOCAOMED.CODPROMOCAOMED = vc_ItensPed.CODPROMOCAOMED)
                       AND (PCPROMOCAOMED.TIPOPOLITICA   IN ('P','F'));
                  EXCEPTION
                    WHEN NO_DATA_FOUND THEN -- MED-2649
                      BEGIN
                        SELECT 'S'
                          INTO vvPromocaoDePreco
                          FROM PCLOGPROMOCAOMED
                         WHERE (PCLOGPROMOCAOMED.CODPROMOCAOMED = vc_ItensPed.CODPROMOCAOMED)
                           AND (PCLOGPROMOCAOMED.TIPOPOLITICA   IN ('P','F'))
                           AND (ROWNUM = 1);
                      EXCEPTION
                    WHEN NO_DATA_FOUND THEN
                      vvPromocaoDePreco := 'N';
                  END;
                  END;
                  -- Se Promoção de Preço ou Preço por Faixa de Quantidade, não deixa carregar o item para não recalcular o preço
                  IF (vvPromocaoDePreco = 'S') THEN
                   vbPodeCarregarItem := FALSE;
                  END IF;

                -- Se AINDA NÃO  estiver passando o Plano Ético e Genérico
                ELSE

                 /* 4415.145077.2018 - Alteração do Plano de Pagamento com Linhas de Prazo
                  -- SE PASSOU A LINHA DE PRAZO
                  IF (NVL(pi_nCodLinhaPrazo,0) > 0) THEN

                    -- Pesquisa Dados do Produto
                    BEGIN
                      SELECT PCPRODUT.CODLINHAPRAZO
                        INTO vrProduto_O.nCODLINHAPRAZO
                        FROM PCPRODUT
                       WHERE (PCPRODUT.CODPROD = vc_ItensPed.CODPROD);
                     EXCEPTION
                      WHEN NO_DATA_FOUND THEN
                        vrProduto_O.nCODLINHAPRAZO := NULL;
                    END;

                    -- Condiciona a alteração do Produto à Linha de Prazo
                    IF (NVL(pi_nCodLinhaPrazo,0) = NVL(vrProduto_O.nCODLINHAPRAZO,0)) THEN
                      vbPodeCarregarItem := TRUE;
                    ELSE
                      vbPodeCarregarItem := FALSE;
                    END IF;

                  END IF;
                  */
                  NULL; -->> 4415.145077.2018 - Descontinuada regra acima, que passou a ser tratada mais abaixo


  /*
                  -- Pesquisa Dados do Produto
                  BEGIN
                    SELECT PCPRODUT.GRUPOFATURAMENTO
                      INTO vrProduto_O.vGRUPOFATURAMENTO
                      FROM PCPRODUT
                     WHERE (PCPRODUT.CODPROD = vc_ItensPed.CODPROD);
                  EXCEPTION
                    WHEN NO_DATA_FOUND THEN
                      vrProduto_O.vGRUPOFATURAMENTO := 'N';
                  END;

                  -- Condiciona a alteração do Produto ao Grupo de Faturamento
                  IF ((NVL(pi_vPosicao,'N') NOT IN ('E','G'))) OR                                                      --> Se não for Ético/Genérico (todos os produtos)
                     ((NVL(pi_vPosicao,'N') = 'E') AND (NVL(vrProduto_O.vGRUPOFATURAMENTO,'N') = 'E')) OR              --> Plano Ético e Produto Ético
                     ((NVL(pi_vPosicao,'N') = 'G') AND (NVL(vrProduto_O.vGRUPOFATURAMENTO,'N') = 'G')) OR              --> Plano Genérico e Produto Genérico
                     ((NVL(pi_vPosicao,'N') = 'G') AND (NVL(vrProduto_O.vGRUPOFATURAMENTO,'N') NOT IN ('G','E'))) THEN --> Planos Genérico e Produtos diferentes de Ético e Genérico
                    -- Pesquisa Promoção
                    BEGIN
                      SELECT 'S'
                        INTO vvPromocaoDePreco
                        FROM PCPROMOCAOMED
                       WHERE (PCPROMOCAOMED.CODPROMOCAOMED = vc_ItensPed.CODPROMOCAOMED)
                         AND (PCPROMOCAOMED.TIPOPOLITICA   IN ('P','F'));
                    EXCEPTION
                      WHEN NO_DATA_FOUND THEN
                        vvPromocaoDePreco := 'N';
                    END;
                    -- Se Promoção de Preço ou Preço por Faixa de Quantidade, não deixa carregar o item para não recalcular o preço
                    IF (vvPromocaoDePreco = 'S') THEN
                      vbPodeCarregarItem := FALSE;
                    END IF;
                  -- Se não atender o Grupo de Faturamento, não recalcula o preço do item
                  ELSE
                    vbPodeCarregarItem := FALSE;
                  END IF;
  */
                END IF; -- Fim Condição se já estiver passando o Plano Ético e Genérico

                -- 4415.145077.2018 - Alteração do Plano de Pagamento com Linhas de Prazo,
                -- passou a recalcular todos os produtos (exceto quem tem promoção de preço fixo)
                IF (vrParamFilial.vTIPOPRAZOMEDICAMEN = '4') THEN

                  -- Pesquisa Promoção
                  BEGIN
                    SELECT 'S'
                      INTO vvPromocaoDePreco
                      FROM PCPROMOCAOMED
                     WHERE (PCPROMOCAOMED.CODPROMOCAOMED = vc_ItensPed.CODPROMOCAOMED)
                       AND (PCPROMOCAOMED.TIPOPOLITICA   IN ('P','F'));
                  EXCEPTION
                    WHEN NO_DATA_FOUND THEN -- MED-2649
                      BEGIN
                        SELECT 'S'
                          INTO vvPromocaoDePreco
                          FROM PCLOGPROMOCAOMED
                         WHERE (PCLOGPROMOCAOMED.CODPROMOCAOMED = vc_ItensPed.CODPROMOCAOMED)
                           AND (PCLOGPROMOCAOMED.TIPOPOLITICA   IN ('P','F'));
                      EXCEPTION
                        WHEN NO_DATA_FOUND THEN
                          vvPromocaoDePreco := 'N';
                      END;
                  END;

                  -- Se Promoção de Preço ou Preço por Faixa de Quantidade, não deixa carregar o item para não recalcular o preço
                  IF (vvPromocaoDePreco = 'S') THEN
                   vbPodeCarregarItem := FALSE;
                  ELSE
                    vbPodeCarregarItem := TRUE;
                  END IF;

                END IF; -- Fim Condição: 4415.145077.2018 - Alteração do Plano de Pagamento com Linhas de Prazo

              END IF; -- Fim Condição: SE PODE EDITAR O ITEM

            -- SE ATUALIZAÇÃO DE PREÇO DE BRINDE, somente pode carregar os Itens Brinde
            ELSIF (pi_nTipoChamada = 12) THEN

              -- Brinde - Pode Atualizar
              IF (NVL(vc_ItensPed.BRINDE,'N') = 'S') THEN
                viQtItensBrinde    := NVL(viQtItensBrinde,0) + 1;
              -- Se não for Brinde, ignora o Produto
              ELSE
                viQtItensNaoBrinde := NVL(viQtItensNaoBrinde,0) + 1;
                vbPodeCarregarItem := FALSE;
              END IF;

            END IF; -- Fim Condição: SE PODE CARREGAR O ITEM

            -- Insere Item no Array se pode Carregar Item
            IF (vbPodeCarregarItem) THEN

              viIdxNew                                           := NVL(vtIncluiItens.COUNT,0) + 1;
              vtIncluiItens(viIdxNew).vnCodProd                  := vc_ItensPed.CODPROD;
              vtIncluiItens(viIdxNew).vnQtde                     := vc_ItensPed.QT;
              --vtIncluiItens(viIdxNew).vnPercDesc               := NVL(vc_ItensPed.PERDESC,0);
              -- PCNIL - Devido a clientes não usarem a Trigger trg_pcpedi_ajustavalores_med, ao refazer o preço tem que retirar os impostors para achar o percentual correto de desconto
              IF (NVL(vc_ItensPed.PRECOBRUTO,0) <> 0) THEN
                vtIncluiItens(viIdxNew).vnPercDesc := ((NVL(vc_ItensPed.PRECOBRUTO,0) - NVL(vc_ItensPed.PRECOLIQUIDO,0)) / NVL(vc_ItensPed.PRECOBRUTO,0)) * 100;
              ELSE
                vtIncluiItens(viIdxNew).vnPercDesc := 0;
              END IF;
              vtIncluiItens(viIdxNew).vnPerDescBoleto            := NVL(vc_ItensPed.PERDESCBOLETO,0);
              vtIncluiItens(viIdxNew).vnCodDesconto              := vc_ItensPed.CODDESCONTO;
              vtIncluiItens(viIdxNew).vnCodPromocaoMed           := vc_ItensPed.CODPROMOCAOMED;
              vtIncluiItens(viIdxNew).vnInicioIntervaloDescQuant := vc_ItensPed.INICIOINTERVALODESCQUANT; -->> AQUI NÃO PODE COLOCAR NVL()
              vtIncluiItens(viIdxNew).vnPerCom                   := NVL(vc_ItensPed.PERCOM,0);
              vtIncluiItens(viIdxNew).vnNumSeq                   := vc_ItensPed.NUMSEQ;
              vtIncluiItens(viIdxNew).vnPTabela                  := vc_ItensPed.PTABELA;
              vtIncluiItens(viIdxNew).vnPVenda                   := vc_ItensPed.PVENDA;
              vtIncluiItens(viIdxNew).vnPBaseRca                 := vc_ItensPed.PBASERCA;
              vtIncluiItens(viIdxNew).vnSt                       := vc_ItensPed.ST;
              vtIncluiItens(viIdxNew).vnVlRepasse                := vc_ItensPed.VLREPASSE;
              vtIncluiItens(viIdxNew).vvBonific                  := vc_ItensPed.BONIFIC;
              vtIncluiItens(viIdxNew).vnPBonific                 := vc_ItensPed.PBONIFIC;
              vtIncluiItens(viIdxNew).vnPercDescBaseRca          := vc_ItensPed.PERCDESCBASERCA;
              vtIncluiItens(viIdxNew).vvTipoComissaoMed          := vc_ItensPed.TIPOCOMISSAOMED;
              vtIncluiItens(viIdxNew).vnVlRedPVendaSimplesNa     := vc_ItensPed.VLREDPVENDASIMPLESNA;
              vtIncluiItens(viIdxNew).vnVrRedCmvSimplesNac       := vc_ItensPed.VLREDCMVSIMPLESNAC;
              vtIncluiItens(viIdxNew).vnCodSt                    := vc_ItensPed.CODST;
              vtIncluiItens(viIdxNew).vvCodFilialRetira          := vc_ItensPed.CODFILIALRETIRA;
              -- Verba para Rebaixa de CMV da Promoção - DDMEDICA-5009
              vtIncluiItens(viIdxNew).vnVlDescCmvPromocaoMed     := vc_ItensPed.VLDESCCMVPROMOCAOMED;
              vtIncluiItens(viIdxNew).vnNumVerbaCampanha         := vc_ItensPed.NUMVERBACAMPANHA;
              vtIncluiItens(viIdxNew).vnVlVerbaCmv               := vc_ItensPed.VLVERBACMV;
              vtIncluiItens(viIdxNew).vnPercCustFornec           := vc_ItensPed.PERCCUSTFORNEC;
              vtIncluiItens(viIdxNew).vnStClienteGnre            := vc_ItensPed.STCLIENTEGNRE; -- DDMEDICA-7697
              vtIncluiItens(viIdxNew).vnBaseIcst                 := vc_ItensPed.BASEICST;      -- DDMEDICA-7697
			  vtIncluiItens(viIdxNew).vnNumverbarebcmv           := vc_ItensPed.NUMVERBAREBCMV;

              -- NÃO PODE SENÃO PODE RETIRAR OS DESCONTOS FLEXÍVEIS
             /*
              -- SE RECALCULO DO PEDIDO AO ALTERAR PLANO DE PAGAMENTO, procurar usar o desconto da política para evitar perda de preço por arredondamento do desconto
              IF (pi_nTipoChamada = 10) THEN
                -- Pesquisa dados na PCDESCONTO pela Promoção e Código do Desconto e Tipo de Política
                BEGIN
                  SELECT PCDESCONTO.PERCDESC
                       , PCDESCONTO.PERCDESCFIN
                    INTO vrDadosPromocaoAtual.vnPerDesc
                       , vrDadosPromocaoAtual.vnPerBoleto
                    FROM PCDESCONTO
                       , PCPROMOCAOMED
                   WHERE (PCPROMOCAOMED.CODPROMOCAOMED = PCDESCONTO.CODPROMOCAOMED)
                     AND (PCDESCONTO.CODPROMOCAOMED    = vc_ItensPed.CODPROMOCAOMED)
                     AND (PCDESCONTO.CODDESCONTO       = vc_ItensPed.CODDESCONTO)
                     AND (PCPROMOCAOMED.TIPOPOLITICA   IN ('D','Q')) -->> Somente Promoções de Desconto ou Desconto por Intervalo de Quantidade
                     AND (ROWNUM                       = 1);
                  -- Se achou a PCDESCONTO pela Promoção e Código do Desconto e Tipo de Política
                  vtIncluiItens(viIdxNew).vnPercDesc      := NVL(vrDadosPromocaoAtual.vnPerDesc,0);
                  vtIncluiItens(viIdxNew).vnPerDescBoleto := NVL(vrDadosPromocaoAtual.vnPerBoleto,0);
                EXCEPTION
                  WHEN NO_DATA_FOUND THEN
                    vrDadosPromocaoAtual.vnPerDesc   := NULL;
                    vrDadosPromocaoAtual.vnPerBoleto := NULL;
                END;
              END IF;
              */

             /* MED-871 - Merge Campanha - Adotado o que fazia no Processo da Campanha
              -- Se Recálculo do Pedido ao alterar o Plano de Pagamento,
              -- verificar se usa Promoção de Preço Fixo
              IF (pi_nTipoChamada = 10) THEN
                -- Pesquisa Promoção
                BEGIN
                  SELECT 'S'
                    INTO vvPromocaoDePreco
                    FROM PCPROMOCAOMED
                   WHERE (PCPROMOCAOMED.CODPROMOCAOMED = vc_ItensPed.CODPROMOCAOMED)
                     AND (PCPROMOCAOMED.TIPOPOLITICA   IN ('P','F'));
                EXCEPTION
                  WHEN NO_DATA_FOUND THEN
                    vvPromocaoDePreco := 'N';
                END;
                -- Se Promoção de Preço, Substitui Preço Fixo
                IF (vvPromocaoDePreco = 'S') THEN
                  -- Pesquisa dados na PCDESCONTO pela Promoção e Código do Desconto e Tipo de Política
                  BEGIN
                    SELECT PCDESCONTO.PRECOFIXOPROMOCAOMED
                      INTO vrDadosPromocaoAtual.vnPrecoFixo
                      FROM PCDESCONTO
                         , PCPROMOCAOMED
                     WHERE (PCPROMOCAOMED.CODPROMOCAOMED = PCDESCONTO.CODPROMOCAOMED)
                       AND (PCDESCONTO.CODPROMOCAOMED    = vc_ItensPed.CODPROMOCAOMED)
                       AND (PCDESCONTO.CODDESCONTO       = vc_ItensPed.CODDESCONTO)
                       AND (PCPROMOCAOMED.TIPOPOLITICA   IN ('P','F')) -->> Somente Promoções de Preço Fixo ou Preço Fixo por Intervalo de Quantidade
                       AND (ROWNUM                       = 1);
                    -- Guarda Preço Fixo se achou a PCDESCONTO pela Promoção e Código do Desconto e Tipo de Política
                    vtIncluiItens(viIdxNew).vnPrecoFixo := NVL(vrDadosPromocaoAtual.vnPrecoFixo,0);
                  EXCEPTION
                    WHEN NO_DATA_FOUND THEN
                      vrDadosPromocaoAtual.vnPrecoFixo := NULL;
                  END;
                END IF;
              END IF;
              */
              -->> MED-871 - Merge Campanha - Adotado o que fazia no Processo da Campanha
              -- COMBOS com Preço Fixo precisa restaurar o Preço Tabela Original ao Mudar Plano Pagamento - 4954.101076.2017
              IF (pi_nTipoChamada = 10) AND
                 (NVL(vc_ItensPed.PRECOBRUTO,0) > 0) THEN
                -- Verifica se Promoção
                BEGIN
                  SELECT TIPOPROMOCAO
                       , TIPOPOLITICA
                    INTO vvTipoPromocaoItemAux
                       , vvTipoPoliticaItemAux
                    FROM PCPROMOCAOMED
                   WHERE (PCPROMOCAOMED.CODPROMOCAOMED = vc_ItensPed.CODPROMOCAOMED);
                EXCEPTION
                  WHEN NO_DATA_FOUND THEN -- MED-2649
                    BEGIN
                      SELECT TIPOPROMOCAO
                           , TIPOPOLITICA
                        INTO vvTipoPromocaoItemAux
                           , vvTipoPoliticaItemAux
                        FROM PCLOGPROMOCAOMED
                       WHERE (PCLOGPROMOCAOMED.CODPROMOCAOMED = vc_ItensPed.CODPROMOCAOMED)
                         AND (ROWNUM                          = 1);
                    EXCEPTION
                      WHEN NO_DATA_FOUND THEN
                        vvTipoPromocaoItemAux := NULL;
                        vvTipoPoliticaItemAux := NULL;
                   END;
                END;
                -- Se Promoção Combo por Preço Fixo
                -- 6214.147669.2017 - Estender a Todos os Tipos de Promoção de Preço Fixo
                IF --(vvTipoPromocaoItemAux = 'K') AND
                   (vvTipoPoliticaItemAux IN ('P','F')) THEN
                  vtIncluiItens(viIdxNew).vvUsarPrecoFixoPrioritario := 'S';
                  vtIncluiItens(viIdxNew).vnPrecoFixo                := NVL(vc_ItensPed.PRECOBRUTO,0);
                END IF;
              END IF; -- Fim: 4954.101076.2017

              -- 4415.145077.2018 - Alteração do Plano de Pagamento com Linhas de Prazo,
              -- passou a ler o plano de pagamento do Item do Pedido
              IF (vrParamFilial.vTIPOPRAZOMEDICAMEN = '4') THEN
                vtIncluiItens(viIdxNew).vnCodPlPag := NVL(vc_ItensPed.CODPLPAG,0);
              END IF;

            END IF; -- Fim Condição Se pode Carregar Item

          END LOOP; -- Fim Laço Itens do Pedido

        ------------------------------------------------
        -- ITENS DO PEDIDO QUE SÃO BONIFICAÇÃO DE BRINDE
        ------------------------------------------------
        ELSIF (pi_nTipoChamada IN (6,8)) THEN

          -- Carrega Array com Itens do Pedido
          FOR vc_ItensPed IN (SELECT PCPEDI.CODPROD
                                   , PCPEDI.QT
                                   , PCPEDI.PERDESC
                                   , PCPEDI.PERDESCBOLETO
                                   , PCPEDI.CODDESCONTO
                                   , PCPEDI.CODPROMOCAOMED
                                   --, PCPEDI.INICIOINTERVALODESCQUANT -->> Substituído por vnInicioIntervaloDescQuantBNF
                                   , PCPEDI.PERCOM
                                   , PCPEDI.NUMSEQ
                                   , PCPEDI.PTABELA
                                   , PCPEDI.PVENDA
                                   , PCPEDI.PBASERCA
                                   , PCPEDI.ST
                                   , PCPEDI.VLREPASSE
                                   , PCPROMOCAOMED.CODPRODBRINDE
                                   , PCPEDI.PERCDESCBASERCA
                                   , PCPEDI.TIPOCOMISSAOMED
                                   , PCPEDI.VLREDPVENDASIMPLESNA
                                   , PCPEDI.VLREDCMVSIMPLESNAC
                                   , PCPEDI.CODFILIALRETIRA
								   , PCPEDI.NUMVERBAREBCMV
                                FROM PCPEDI
                                   , PCPROMOCAOMED
                               WHERE (PCPROMOCAOMED.CODPROMOCAOMED = PCPEDI.CODPROMOCAOMED)
                                 AND (PCPROMOCAOMED.TIPOPROMOCAO   = 'B') -- Bonificação em Mercadoria
                                 AND (PCPEDI.NUMPED                = pi_nNumPed)) LOOP

            -- Revalida o Inicio do Intervalo para Calculo da Bonificação (BUSCA POR PRODUTO)
            BEGIN
              SELECT PCDESCONTO.CODDESCONTO
                   , PCDESCONTO.INICIOINTERVALOPROMOCAOMED
                   , PCDESCONTO.PERCBONIFICMERC
                INTO vnCodDesIntervaloDescQuantBNF
                   , vnInicioIntervaloDescQuantBNF
                   , vnPercBonificMerc
                FROM PCDESCONTO
               WHERE (PCDESCONTO.CODPROMOCAOMED              = vc_ItensPed.CODPROMOCAOMED)
                 AND (PCDESCONTO.CODPROD                     = vc_ItensPed.CODPROD) -->> Pesquisa pelo Código do Produto na Promoção
                 AND (PCDESCONTO.INICIOINTERVALOPROMOCAOMED <= vc_ItensPed.QT)
                 AND (PCDESCONTO.FIMINTERVALOPROMOCAOMED    >= vc_ItensPed.QT)
                 AND (ROWNUM                                 = 1);
            EXCEPTION
              WHEN NO_DATA_FOUND THEN
                vnCodDesIntervaloDescQuantBNF := 0;
                vnInicioIntervaloDescQuantBNF := 0;
                vnPercBonificMerc             := 0;
            END;
            -- Se não encontrar o Intervalo de BNF por Produto, pesquisa pelo Código do Desconto (Registros cadastrados por Linha, Fornecedor ...)
            IF (NVL(vnCodDesIntervaloDescQuantBNF,0) = 0) THEN
              -- Revalida o Inicio do Intervalo para Calculo da Bonificação (BUSCA POR CODDESCONTO)
              BEGIN
                SELECT PCDESCONTO.CODDESCONTO
                     , PCDESCONTO.INICIOINTERVALOPROMOCAOMED
                     , PCDESCONTO.PERCBONIFICMERC
                  INTO vnCodDesIntervaloDescQuantBNF
                     , vnInicioIntervaloDescQuantBNF
                     , vnPercBonificMerc
                  FROM PCDESCONTO
                 WHERE (PCDESCONTO.CODPROMOCAOMED              = vc_ItensPed.CODPROMOCAOMED)
                   AND (PCDESCONTO.CODDESCONTO                 = vc_ItensPed.CODDESCONTO) -->> Pesquisa pelo Código do Desconto na Promoção
                   AND (PCDESCONTO.INICIOINTERVALOPROMOCAOMED <= vc_ItensPed.QT)
                   AND (PCDESCONTO.FIMINTERVALOPROMOCAOMED    >= vc_ItensPed.QT)
                   AND (ROWNUM                                 = 1);
              EXCEPTION
                WHEN NO_DATA_FOUND THEN
                  vnCodDesIntervaloDescQuantBNF := 0;
                  vnInicioIntervaloDescQuantBNF := 0;
                  vnPercBonificMerc             := 0;
              END;
            END IF;

            -- Percentual de Bonificação é pesquisado nos Selects acima
            -----------------------------------------------------------
            -- Pesquisa o Percentual de Bonificação
            --BEGIN
            --  SELECT PCDESCONTO.PERCBONIFICMERC
            --    INTO vnPercBonificMerc
            --    FROM PCDESCONTO
            --   WHERE (PCDESCONTO.CODPROMOCAOMED             = vc_ItensPed.CODPROMOCAOMED)
            --     AND (PCDESCONTO.CODPROD                    = vc_ItensPed.CODPROD)
            --     AND (PCDESCONTO.INICIOINTERVALOPROMOCAOMED = vnInicioIntervaloDescQuantBNF) -->> Inicio Intervalo para a Quantidade Informada
            --     AND (ROWNUM                                = 1);
            --EXCEPTION
            --  WHEN NO_DATA_FOUND THEN
            --    vnPercBonificMerc := 0;
            --END;

            -- Se tem Percentual de Bonificação
            IF (NVL(vnPercBonificMerc,0) > 0) THEN

              -- Calcula a Qtde de Brindes - Arredonda para Baixo - Critério do Cliente
              IF (NVL(vrParamFilial.vQTDEREFPROMOBONIFICMERCMED,'1') = '2') THEN
                -- Opção Qtde Vendida
                vnQtdeBonificMerc := TRUNC((NVL(vc_ItensPed.QT,0) * (NVL(vnPercBonificMerc,0) / 100)));
              ELSE
                -- Opção Padrão - Quantidade Inicial do Intervalo
                vnQtdeBonificMerc := TRUNC((NVL(vnInicioIntervaloDescQuantBNF,0) * (NVL(vnPercBonificMerc,0) / 100)));
              END IF;

              -- Se calculou Bonificação em Mercadoria
              IF (NVL(vnQtdeBonificMerc,0) > 0) THEN

                -- Insere Item no Array
                viIdxNew                                           := NVL(vtIncluiItens.COUNT,0) + 1;
                IF (NVL(vc_ItensPed.CODPRODBRINDE,0) > 0) THEN
                  -- Se existe Produto diferenciado para Bonificação
                  vtIncluiItens(viIdxNew).vnCodProd                := vc_ItensPed.CODPRODBRINDE;
                ELSE
                  vtIncluiItens(viIdxNew).vnCodProd                := vc_ItensPed.CODPROD;
                END IF;
                vtIncluiItens(viIdxNew).vnQtde                     := NVL(vnQtdeBonificMerc,0); -->> QUANTIDADE DE BRINDES
                vtIncluiItens(viIdxNew).vnPercDesc                 := NVL(vc_ItensPed.PERDESC,0);
                vtIncluiItens(viIdxNew).vnPerDescBoleto            := NVL(vc_ItensPed.PERDESCBOLETO,0);
                vtIncluiItens(viIdxNew).vnCodDesconto              := vc_ItensPed.CODDESCONTO;
                vtIncluiItens(viIdxNew).vnCodPromocaoMed           := vc_ItensPed.CODPROMOCAOMED;
                vtIncluiItens(viIdxNew).vnInicioIntervaloDescQuant := vnInicioIntervaloDescQuantBNF; -->> AQUI NÃO PODE COLOCAR NVL()
                vtIncluiItens(viIdxNew).vnPerCom                   := NVL(vc_ItensPed.PERCOM,0);
                vtIncluiItens(viIdxNew).vnNumSeq                   := vc_ItensPed.NUMSEQ;
                vtIncluiItens(viIdxNew).vnPTabela                  := vc_ItensPed.PTABELA;
                vtIncluiItens(viIdxNew).vnPVenda                   := vc_ItensPed.PVENDA;
                vtIncluiItens(viIdxNew).vnPBaseRca                 := vc_ItensPed.PBASERCA;
                vtIncluiItens(viIdxNew).vnSt                       := vc_ItensPed.ST;
                vtIncluiItens(viIdxNew).vnVlRepasse                := vc_ItensPed.VLREPASSE;
                -- Somente Bonificação em TV1
                vtIncluiItens(viIdxNew).vvBonific                  := 'F';
                vtIncluiItens(viIdxNew).vnPBonific                 := vc_ItensPed.PVENDA;
                --
                vtIncluiItens(viIdxNew).vnPercDescBaseRca          := vc_ItensPed.PERCDESCBASERCA;
                vtIncluiItens(viIdxNew).vvTipoComissaoMed          := vc_ItensPed.TIPOCOMISSAOMED;
                vtIncluiItens(viIdxNew).vnVlRedPVendaSimplesNa     := vc_ItensPed.VLREDPVENDASIMPLESNA;
                vtIncluiItens(viIdxNew).vnVrRedCmvSimplesNac       := vc_ItensPed.VLREDCMVSIMPLESNAC;
                vtIncluiItens(viIdxNew).vnCodSt                    := NULL; -->> Aqui como pode ser outro código de produto (Brinde) melhor deixar o Sistema pesquisar a Tributação
                vtIncluiItens(viIdxNew).vvCodFilialRetira          := vc_ItensPed.CODFILIALRETIRA;
                vtIncluiItens(viIdxNew).vnNumverbarebcmv           := vc_ItensPed.Numverbarebcmv;				

              END IF; -- Fim Condição Se calculou  Bonificação em Mercadoria

            END IF; -- Fim Se tem Percentual de Bonificação

          END LOOP; -- Fim Laço Itens do Pedido

        ------------------------------------------
        -- ITENS SECUNDÁRIOS DA PROMOÇÃO CASADINHA
        ------------------------------------------
        ELSIF (pi_nTipoChamada IN (9)) THEN

          -- Controle de Ocorrências dos Produtos noutras Promoções
          viQtOcorrenciasOutrasPromo  := 0;
          vvMsgOcorrenciasOutrasPromo := NULL;

          -- Pesquisa a Quantidade de Unidades definidas na Promoção para o Produto Principal
          BEGIN
            SELECT INICIOINTERVALOPROMOCAOMED
              INTO vnQtdeCadastroProdPrincCasad
              FROM PCDESCONTO
             WHERE (PCDESCONTO.CODPROD        = pi_nCodProd)
               AND (PCDESCONTO.CODPROMOCAOMED = pi_nCodPromocaoMedPedido)
               AND (ROWNUM                    = 1);
          EXCEPTION
            WHEN NO_DATA_FOUND THEN
              po_vMotivoNaoPodeGravar := 'Produto ' || NVL(pi_nCodProd,0) || ' não encontrado na Promoção ' || NVL(pi_nCodPromocaoMedPedido,0);
              RAISE e_Tratado;
          END;

          -- Se o Produto Principal estiver sem Quantidade
          IF (NVL(vnQtdeCadastroProdPrincCasad,0) = 0) THEN
            po_vMotivoNaoPodeGravar := 'Produto ' || NVL(pi_nCodProd,0) || ' sem quantidade cadastrada na Promoção.';
            RAISE e_Tratado;
          END IF;

          -- Define o Fator de Quantidade da Casadinha
          viFatorQtdeCasadinha := TRUNC(NVL(pi_nQtCombos,0) / NVL(vnQtdeCadastroProdPrincCasad,0));

          -- Se o Fator não permitirá conceder itens casados
          IF (NVL(viFatorQtdeCasadinha,0) = 0) THEN
            po_vMotivoNaoPodeGravar := 'Quantidade vendida abaixo do mínimo para concessão dos itens da Promoção Casadinha.  ' || CHR(13) || 'Qtde Mínima: ' || NVL(vnQtdeCadastroProdPrincCasad,0);
            RAISE e_Tratado;
          END IF;

          -- Pesquisa os Produtos Secundários da Promoção Casadinha
          FOR vc_Promo IN (SELECT DISTINCT
                                  PCDESCONTO.CODPROD
                                , PCDESCONTO.INICIOINTERVALOPROMOCAOMED
                                , PCDESCONTO.PERCDESC
                                , PCDESCONTO.PERCDESCFIN
                                , MIN(PCDESCONTO.CODDESCONTO) CODDESCONTO -->> Pra não dar Duplicidade
                                , PCDESCONTO.CODPROMOCAOMED
                                , PCDESCONTO.PERCOMMINT
                                , PCDESCONTO.PERCOMEXT
                                , PCDESCONTO.PERCOMREP
                                , PCDESCONTO.CONSIDERACALCGIROMEDIC
                                , PCDESCONTO.PRECOFIXOPROMOCAOMED
                                , PCPRODUT.DESCRICAO
                                , PCDESCONTO.VLDESCCMVPROMOCAOMED -- DDMEDICA-5009
                                , PCPRODUT.CODFORNEC -- DDMEDICA-5009
                             FROM PCDESCONTO
                                , PCPRODUT
                                , PCPROMOCAOMED
                            WHERE (PCDESCONTO.CODPROD        = PCPRODUT.CODPROD)
                              AND (PCDESCONTO.CODPROMOCAOMED = PCPROMOCAOMED.CODPROMOCAOMED)
                              AND (PCDESCONTO.CODPROMOCAOMED = pi_nCodPromocaoMedPedido)
                              -- Inicio: Normalização PCDESCONTO: Como já está pasando o Código da Promoção Casadinha, não precisa dos filtros abaixo
                              --AND (PCDESCONTO.ORIGEMPED      = 'T') -->> Somente Televendas
                              --AND (PCDESCONTO.CODFILIAL      IS NULL OR PCDESCONTO.CODFILIAL = pi_vCodFilial)
                              --AND (PCDESCONTO.CODCLI         IS NULL OR PCDESCONTO.CODCLI    = pi_nCodCli)
                              --AND (PCDESCONTO.CODUSUR        IS NULL OR PCDESCONTO.CODUSUR   = pi_nCodUsur)
                              --AND (PCDESCONTO.CODPLPAG       IS NULL OR PCDESCONTO.CODPLPAG  = pi_nCodPlPag) -->> LIMITAÇÃO: GRUPO FATURAMENTO
                              --AND (PCDESCONTO.NUMREGIAO      IS NULL OR PCDESCONTO.NUMREGIAO = vrRegiao.nNUMREGIAO)
                              --AND (PCDESCONTO.CODPRACA       IS NULL OR PCDESCONTO.CODPRACA  = vrClienteDestino.nCODPRACA)
                              --AND (PCDESCONTO.CODATIV        IS NULL OR PCDESCONTO.CODATIV   = vrClienteDestino.vCODATV1)
                              -- Fim: Normalização PCDESCONTO
                              AND (PCDESCONTO.INICIOINTERVALOPROMOCAOMED > 0)         -->> GARANTIR SOMENTE COM QTDE > 0
                              AND (PCPROMOCAOMED.CODPRODBRINDE <> PCDESCONTO.CODPROD) -->> SOMENTE CONSULTAR OS PRODUTOS SECUNDÁRIOS
                            GROUP BY PCDESCONTO.CODPROD
                                   , PCDESCONTO.INICIOINTERVALOPROMOCAOMED
                                   , PCDESCONTO.PERCDESC
                                   , PCDESCONTO.PERCDESCFIN
                                   , PCDESCONTO.CODPROMOCAOMED
                                   , PCDESCONTO.PERCOMMINT
                                   , PCDESCONTO.PERCOMEXT
                                   , PCDESCONTO.PERCOMREP
                                   , PCDESCONTO.CONSIDERACALCGIROMEDIC
                                   , PCDESCONTO.PRECOFIXOPROMOCAOMED
                                   , PCPRODUT.DESCRICAO
                                   , PCDESCONTO.VLDESCCMVPROMOCAOMED -- DDMEDICA-5009
                                   , PCPRODUT.CODFORNEC -- DDMEDICA-5009
                                   ) LOOP

            -- Pesquisa ocorrências do Produto em Promoções diferentes
            -- (SE NÃO USA CHAVE TRIPLA CRITICA O PRODUTO JÁ INSERIDO)
            IF (NVL(vrParamFilial.vUSACHAVETRIPLAPCPEDI,'N') = 'N') THEN
              BEGIN
                SELECT 'S'
                  INTO vvAchouProduto
                  FROM PCPEDI
                 WHERE (PCPEDI.NUMPED                 = pi_nNumPed)
                   AND (PCPEDI.CODPROD                = vc_Promo.CODPROD)
                   AND (NVL(PCPEDI.CODPROMOCAOMED,0) <> NVL(vc_Promo.CODPROMOCAOMED,0))
                   AND (ROWNUM                        = 1);
               EXCEPTION
                 WHEN NO_DATA_FOUND THEN
                   vvAchouProduto := 'N';
              END;
              IF (vvAchouProduto = 'S') THEN
                -- Incrementa Controle de Ocorrências dos Produtos noutras Promoções
                viQtOcorrenciasOutrasPromo := NVL(viQtOcorrenciasOutrasPromo,0) + 1;
                -- Concatena Produtos
                IF (vvMsgOcorrenciasOutrasPromo IS NULL) THEN
                  vvMsgOcorrenciasOutrasPromo := vc_Promo.CODPROD || ' - ' || vc_Promo.DESCRICAO;
                ELSE
                  vvMsgOcorrenciasOutrasPromo := vvMsgOcorrenciasOutrasPromo || CHR(13) || vc_Promo.CODPROD || ' - ' || vc_Promo.DESCRICAO;
                END IF;
              END IF;
            END IF;

            -- Insere Item no Array
            viIdxNew                                           := NVL(vtIncluiItens.COUNT,0) + 1;
            vtIncluiItens(viIdxNew).vnCodProd                  := vc_Promo.CODPROD;
            vtIncluiItens(viIdxNew).vnQtde                     := TRUNC((NVL(vc_Promo.INICIOINTERVALOPROMOCAOMED,0) * NVL(viFatorQtdeCasadinha,0))); -->> MULTIPLICA PELO FATOR DA CASADINHA
            vtIncluiItens(viIdxNew).vnPercDesc                 := NVL(vc_Promo.PERCDESC,0);
            vtIncluiItens(viIdxNew).vnPerDescBoleto            := NVL(vc_Promo.PERCDESCFIN,0);
            vtIncluiItens(viIdxNew).vnCodDesconto              := vc_Promo.CODDESCONTO;
            vtIncluiItens(viIdxNew).vnCodPromocaoMed           := vc_Promo.CODPROMOCAOMED;
            vtIncluiItens(viIdxNew).vnInicioIntervaloDescQuant := NVL(vc_Promo.INICIOINTERVALOPROMOCAOMED,0);
            vtIncluiItens(viIdxNew).vnPerComInt                := NVL(vc_Promo.PERCOMMINT,0);
            vtIncluiItens(viIdxNew).vnPerComExt                := NVL(vc_Promo.PERCOMEXT,0);
            vtIncluiItens(viIdxNew).vnPerComRep                := NVL(vc_Promo.PERCOMREP,0);
            vtIncluiItens(viIdxNew).vvParticipaGiro            := NVL(vc_Promo.CONSIDERACALCGIROMEDIC,'S');
            vtIncluiItens(viIdxNew).vnPrecoFixo                := NVL(vc_Promo.PRECOFIXOPROMOCAOMED,0);
            vtIncluiItens(viIdxNew).vvBonific                  := 'N';
            vtIncluiItens(viIdxNew).vnPBonific                 := NULL;
            vtIncluiItens(viIdxNew).vnCodSt                    := NULL;
            vtIncluiItens(viIdxNew).vnFatorGramaturaLicit      := NULL;
            vtIncluiItens(viIdxNew).vvCodigoIntegracaoWms      := NULL;
            vtIncluiItens(viIdxNew).vvNumLotePromocaoMed       := NULL;
            -- Verba para Rebaixa de CMV da Promoção - DDMEDICA-5009
            vtIncluiItens(viIdxNew).vnVlDescCmvPromocaoMed     := vc_Promo.VLDESCCMVPROMOCAOMED;
            -- Obter Verba Relacionada com o Valor da Verba para Rebaixa de CMV da Promoção da PCDESCONTO - DDMEDICA-5009
            P_OBTER_VERBA_PROMOCAO(vc_Promo.CODPROMOCAOMED,
                                   vc_Promo.CODFORNEC,
                                   vtIncluiItens(viIdxNew).vnVlDescCmvPromocaoMed,
                                   vtIncluiItens(viIdxNew).vnNumVerbaCampanha,
                                   vtIncluiItens(viIdxNew).vnValorCotaNumVerba,
                                   vtIncluiItens(viIdxNew).vvSemVerbaVlDescCmv);

            -- Se a quantidade resultante do Fator retornar zero, aborta a aplicação
            IF (NVL(vtIncluiItens(viIdxNew).vnQtde,0) = 0) THEN
              po_vMotivoNaoPodeGravar := 'Quantidade vendida insuficiente para concessão do produto ' || NVL(vc_Promo.CODPROD,0);
              RAISE e_Tratado;
            END IF;

          END LOOP; -- Fim Laço Itens do Pedido

          -- Se Ocorrências dos Produtos noutras Promoções
          IF (viQtOcorrenciasOutrasPromo > 0) THEN
            IF    (viQtOcorrenciasOutrasPromo = 1) THEN
              vvMsgOcorrenciasOutrasPromo := 'Produto encontrado no Pedido para outra Promoção: ' || CHR(13) || vvMsgOcorrenciasOutrasPromo;
            ELSIF (viQtOcorrenciasOutrasPromo > 1) THEN
              vvMsgOcorrenciasOutrasPromo := 'Produtos encontrados no Pedido para outras Promoções: ' || CHR(13) || vvMsgOcorrenciasOutrasPromo;
            END IF;
            po_vMotivoNaoPodeGravar := SUBSTR(vvMsgOcorrenciasOutrasPromo,1,2000);
            RAISE e_Tratado;
          END IF;

        --------------------------------
        -- ITENS DO ORÇAMENTO
        --------------------------------
        ELSIF (pi_nTipoChamada = 11) THEN

          -- Trata o Pedido como utilizando Promoção de Preço Fixo pra usar o Preço do momento da gravação do Orçamento
          vvTipoPoliticaPedido := 'P';

          -- Monta SQL
          -- MED-1090 - Abater FCP no Preço Líquido
          -- DDMEDICA-7584 - Somar o Valor do Desconto da Redução PIS e COFINS
          -- DDMEDICA-7697 - Deduzir o ST Recolhido Anteriormente
          -- DDVENDAS-32472 - Preço Contrato
          vsSQL := 'SELECT PCORCAVENDAI.CODPROD
                   ,PCORCAVENDAI.QT
                   ,PCORCAVENDAI.PERDESC
                   ,PCORCAVENDAI.CODDESCONTO
                   ,PCORCAVENDAI.CODPROMOCAOMED
                   ,PCORCAVENDAI.INICIOINTERVALODESCQUANT
                   ,( (NVL(PCORCAVENDAI.PVENDA,0)  
                      - NVL(PCORCAVENDAI.ST,0) 
                      - NVL(PCORCAVENDAI.VLICMSSTRETANTERIOR,0) 
                      - NVL(PCORCAVENDAI.VLREPASSE,0) 
                      - NVL(PCORCAVENDAI.VLICMSPART,0) 
                      - NVL(PCORCAVENDAI.VLFECP,0)) 
                      + NVL(PCORCAVENDAI.VLDESCICMISENCAO,0) 
                      + NVL(PCORCAVENDAI.VLDESCSUFRAMA,0) 
                      + NVL(PCORCAVENDAI.VLDESCREDUCAOPIS,0) 
                      + NVL(PCORCAVENDAI.VLDESCREDUCAOCOFINS,0) ) PRECOFIXO
                   ,PCORCAVENDAI.NUMSEQITEMCONTRATO
                   ,PCORCAVENDAI.BONIFIC
                   ,PCORCAVENDAI.PERCOM
                   ,PCORCAVENDAI.LOTECONTRATO
                   ,PCORCAVENDAI.VLREDPVENDASIMPLESNA
                   ,PCORCAVENDAI.VLREDCMVSIMPLESNAC
                   ,NVL(PCORCAVENDAI.CODPLPAG,PCORCAVENDAC.CODPLPAG) CODPLPAG
                   ,NVL(PCORCAVENDAI.CODLINHAPRAZO,PCPRODUT.CODLINHAPRAZO) CODLINHAPRAZO
                   ,PCORCAVENDAI.FATORGRAMATURALICIT
                   ,PCORCAVENDAI.CODFILIALRETIRA
                   ,PCORCAVENDAI.CODIGOINTEGRACAOWMS
                   ,PCORCAVENDAI.NUMLOTEPROMOCAOMED
                   ,PCORCAVENDAI.VLDESCCMVPROMOCAOMED
                   ,PCORCAVENDAI.NUMVERBACAMPANHA
                   ,PCORCAVENDAI.VLVERBACMV
                   ,PCORCAVENDAI.PERCCUSTFORNEC
                   ,PCORCAVENDAI.CODAUXILIAR
                   ,PCORCAVENDAI.STCLIENTEGNRE
                   ,PCORCAVENDAI.BASEICST
                   ,PCORCAVENDAI.ST
                   ,CASE WHEN (NVL(PCORCAVENDAC.CODCONTRATO,0) > 0) THEN
                      ( (NVL(PCORCAVENDAI.PTABELA,0)  
                        - NVL(PCORCAVENDAI.ST,0) 
                        - NVL(PCORCAVENDAI.VLICMSSTRETANTERIOR,0) 
                        - NVL(PCORCAVENDAI.VLREPASSE,0) 
                        - NVL(PCORCAVENDAI.VLICMSPART,0) 
                        - NVL(PCORCAVENDAI.VLFECP,0)) 
                        + NVL(PCORCAVENDAI.VLDESCICMISENCAO,0) 
                        + NVL(PCORCAVENDAI.VLDESCSUFRAMA,0) 
                        + NVL(PCORCAVENDAI.VLDESCREDUCAOPIS,0) 
                        + NVL(PCORCAVENDAI.VLDESCREDUCAOCOFINS,0) )
                    ELSE
                      0
                    END PTABELACONTRATO,
                    PCORCAVENDAI.NUMVERBAREBCMV,
                    PCORCAVENDAI.NUMITEMPED,
                    PCORCAVENDAI.QTCOMBOVIRTUAL
               FROM PCORCAVENDAI
                   ,PCORCAVENDAC
                   ,PCPRODUT
              WHERE PCORCAVENDAI.NUMORCA = PCORCAVENDAC.NUMORCA
                AND PCORCAVENDAI.CODPROD = PCPRODUT.CODPROD
                AND PCORCAVENDAI.NUMORCA = ' || pi_nNumOrcamento;

          -- Processa Cursor
          OPEN vRefCursor FOR vsSQL;
          LOOP

            -- Leitura do Registro do Cursor
            FETCH vRefCursor INTO vrDadosOrcaI;
            EXIT WHEN vRefCursor%NOTFOUND;

            -- Insere Item no Array
            viIdxNew                                           := NVL(vtIncluiItens.COUNT,0) + 1;
            vtIncluiItens(viIdxNew).vnCodProd                  := vrDadosOrcaI.vnCODPROD;
            vtIncluiItens(viIdxNew).vnQtde                     := vrDadosOrcaI.vnQT;
            vtIncluiItens(viIdxNew).vnPercDesc                 := vrDadosOrcaI.vnPERDESC;
            vtIncluiItens(viIdxNew).vnPerDescBoleto            := 0;
            vtIncluiItens(viIdxNew).vnCodDesconto              := vrDadosOrcaI.vnCODDESCONTO;
            vtIncluiItens(viIdxNew).vnCodPromocaoMed           := vrDadosOrcaI.vnCODPROMOCAOMED;
            vtIncluiItens(viIdxNew).vnInicioIntervaloDescQuant := vrDadosOrcaI.vnINICIOINTERVALODESCQUANT;
            vtIncluiItens(viIdxNew).vnPerCom                   := vrDadosOrcaI.vnPERCOM;
            vtIncluiItens(viIdxNew).vvParticipaGiro            := 'S';
            vtIncluiItens(viIdxNew).vnPrecoFixo                := vrDadosOrcaI.vnPRECOFIXO; -->> PCNIL - Deve ser garantido o Preço Venda Líquido ao recuperar o Orçamento
            vtIncluiItens(viIdxNew).vvLoteContrato             := vrDadosOrcaI.vvLOTECONTRATO;
            vtIncluiItens(viIdxNew).vnNumSeqItemContrato       := vrDadosOrcaI.vnNUMSEQITEMCONTRATO;
            vtIncluiItens(viIdxNew).vvBonific                  := vrDadosOrcaI.vnBONIFIC;
            vtIncluiItens(viIdxNew).vnVlRedPVendaSimplesNa     := vrDadosOrcaI.vnVLREDPVENDASIMPLESNA;
            vtIncluiItens(viIdxNew).vnVrRedCmvSimplesNac       := vrDadosOrcaI.vnVLREDCMVSIMPLESNAC;
            vtIncluiItens(viIdxNew).vnCodPlPag                 := vrDadosOrcaI.vnCODPLPAG;
            vtIncluiItens(viIdxNew).vnCodLinhaPrazo            := vrDadosOrcaI.vnCODLINHAPRAZO;
            vtIncluiItens(viIdxNew).vnCodSt                    := NULL;
            vtIncluiItens(viIdxNew).vnFatorGramaturaLicit      := vrDadosOrcaI.vnFATORGRAMATURALICIT;
            vtIncluiItens(viIdxNew).vvCodFilialRetira          := vrDadosOrcaI.vvCODFILIALRETIRA;
            vtIncluiItens(viIdxNew).vvCodigoIntegracaoWms      := vrDadosOrcaI.vvCODIGOINTEGRACAOWMS;
            vtIncluiItens(viIdxNew).vvNumLotePromocaoMed       := vrDadosOrcaI.vvNUMLOTEPROMOCAOMED;
            -- Verba para Rebaixa de CMV da Promoção - DDMEDICA-5009
            vtIncluiItens(viIdxNew).vnVlDescCmvPromocaoMed     := vrDadosOrcaI.vnVLDESCCMVPROMOCAOMED;
            vtIncluiItens(viIdxNew).vnNumVerbaCampanha         := vrDadosOrcaI.vnNUMVERBACAMPANHA;
            vtIncluiItens(viIdxNew).vnVlVerbaCmv               := vrDadosOrcaI.vnVLVERBACMV;
            vtIncluiItens(viIdxNew).vnPercCustFornec           := vrDadosOrcaI.vnPERCCUSTFORNEC;
            vtIncluiItens(viIdxNew).vnCodAuxiliar              := vrDadosOrcaI.vnCODAUXILIAR;     -- DDMEDICA-7318
            vtIncluiItens(viIdxNew).vnStClienteGnre            := vrDadosOrcaI.vnSTCLIENTEGNRE;   -- DDMEDICA-7697
            vtIncluiItens(viIdxNew).vnBaseIcst                 := vrDadosOrcaI.vnBASEICST;        -- DDMEDICA-7697
            vtIncluiItens(viIdxNew).vnSt                       := vrDadosOrcaI.vnST;              -- DDMEDICA-7697            
            vtIncluiItens(viIdxNew).vnPtabelaContrato          := vrDadosOrcaI.vnPTABELACONTRATO; -- DDVENDAS-32472           
            vtIncluiItens(viIdxNew).vnNumverbarebcmv           := vrDadosOrcaI.vnNUMVERBAREBCMV;
            vtIncluiItens(viIdxNew).vnNumItemPed               := vrDadosOrcaI.vnNUMITEMPED;
            vtIncluiItens(viIdxNew).nQTCOMBOVIRTUAL            := vrDadosOrcaI.nQTCOMBOVIRTUAL;
            -- Controle de Rejeição
            vvRegistroValido := 'S';
            --vvMsgRejeicao    := NULL;

            -- Validação da Promoção
            IF     (NVL(vrDadosOrcaI.vnCODPROMOCAOMED,0) > 0) THEN
              BEGIN
                SELECT 'S'
                  INTO vvRegistroValido
                  FROM PCPROMOCAOMED
                 WHERE (PCPROMOCAOMED.CODPROMOCAOMED = vrDadosOrcaI.vnCODPROMOCAOMED)
                   AND (TRUNC(SYSDATE) BETWEEN PCPROMOCAOMED.DATAINICIAL AND PCPROMOCAOMED.DATAFINAL);
                -- Validação do Desconto na Promoção encontrada
                BEGIN
                  SELECT 'S'
                       , PCDESCONTO.PERCDESCFIN
                    INTO vvRegistroValido
                       , vtIncluiItens(viIdxNew).vnPerDescBoleto
                    FROM PCDESCONTO
                   WHERE (PCDESCONTO.CODPROMOCAOMED = vrDadosOrcaI.vnCODPROMOCAOMED)
                     AND (PCDESCONTO.CODDESCONTO = vrDadosOrcaI.vnCODDESCONTO)
                     AND (TRUNC(SYSDATE) BETWEEN PCDESCONTO.DTINICIO AND PCDESCONTO.DTFIM)
                     AND (ROWNUM = 1);
                EXCEPTION
                  WHEN NO_DATA_FOUND THEN
                    vvRegistroValido := 'N';
                    --vvMsgRejeicao    := 'Promoção ' || vrDadosOrcaI.vnCODPROMOCAOMED || ' não é mais válida para o item ' || vrDadosOrcaI.vnCODDESCONTO;
                END;
              EXCEPTION
                WHEN NO_DATA_FOUND THEN
                  vvRegistroValido := 'N';
                  --vvMsgRejeicao    := 'Promoção ' || vrDadosOrcaI.vnCODPROMOCAOMED || ' cancelada ou fora de vigência';
              END;
            -- Validação da Política
            ELSIF (NVL(vrDadosOrcaI.vnCODDESCONTO,0) > 0) THEN
              BEGIN
                SELECT 'S'
                     , PCDESCONTO.PERCDESCFIN
                  INTO vvRegistroValido
                     , vtIncluiItens(viIdxNew).vnPerDescBoleto
                  FROM PCDESCONTO
                 WHERE (PCDESCONTO.CODDESCONTO = vrDadosOrcaI.vnCODDESCONTO)
                   AND (TRUNC(SYSDATE) BETWEEN PCDESCONTO.DTINICIO AND PCDESCONTO.DTFIM)
                   AND (ROWNUM = 1);
              EXCEPTION
                WHEN NO_DATA_FOUND THEN
                  vvRegistroValido := 'N';
                  --vvMsgRejeicao    := 'Política de Desconto ' || vrDadosOrcaI.vnCODDESCONTO || ' cancelada ou fora de vigência';
              END;
            END IF;

          END LOOP; -- Fim Processamento Cursor

          -- Fecha Cursor
          CLOSE vRefCursor;

        ----------------------------------------------------------------------------------
        -- SE CHAMADO PARA CARREGAR A TABELA DE CAMPANHA  - HIS.01889.2017
        -- SE CHAMADO PARA CARREGAR A TABELA DE MIX/VALOR - HIS.01889.2017
        ----------------------------------------------------------------------------------
        ELSIF (pi_nTipoChamada IN (13,14)) THEN

          -- INICIO: DEFINIÇÃO DAS PROMOÇÕES VÁLIDAS DE CAMPANHA E MIX/VALOR/QTDE---------------------------------
          FOR vc_Promo IN (SELECT PCPROMOCAOMED.CODPROMOCAOMED
                                , PCPROMOCAOMED.DESCRICAORESUMIDA
                                --, PCPROMOCAOMED.TIPOPROMOCAO
                                -- MED_VLMIN_FXQ - Permitir que Promoção de Faixa de Quantidade com Valor Mínimo use os controles de Valor Mínimo
                                , CASE
                                    WHEN ((PCPROMOCAOMED.TIPOPROMOCAO = 'C') AND (PCPROMOCAOMED.TIPOPOLITICA IN ('Q','F','V')) AND (NVL(PCPROMOCAOMED.VLRMINITENSPROMOCAO,0) > 0)) THEN
                                      'F'
                                    ELSE
                                      PCPROMOCAOMED.TIPOPROMOCAO
                                  END TIPOPROMOCAO
                                , PCPROMOCAOMED.TIPOVALIDAVALORMIN
                                , CASE
                                    WHEN (PCPROMOCAOMED.TIPOPROMOCAO IN ('M','V')) OR
                                         ((PCPROMOCAOMED.TIPOPROMOCAO = 'N') AND (NVL(PCPROMOCAOMED.TIPOVALIDAVALORMIN,'S') IN ('M','V','Q'))) THEN
                                       PCPROMOCAOMED.VLRMINITENSPROMOCAO
                                    -- MED_VLMIN_FXQ
                                    WHEN ((PCPROMOCAOMED.TIPOPROMOCAO = 'C') AND (PCPROMOCAOMED.TIPOPOLITICA IN ('Q','F','V')) AND (NVL(PCPROMOCAOMED.VLRMINITENSPROMOCAO,0) > 0)) THEN
                                       PCPROMOCAOMED.VLRMINITENSPROMOCAO
                                    ELSE
                                      TO_NUMBER(NULL)
                                  END MINIMOPEDIDO
                                , PCPROMOCAOMED.TIPOCONCESSAOBRINDE
                                , CASE
                                    -- Somente Campanha tem Tipo Concessão Brinde
                                    WHEN (PCPROMOCAOMED.TIPOPROMOCAO = 'N') THEN
                                      CASE
                                        WHEN (NVL(PCPROMOCAOMED.TIPOCONCESSAOBRINDE,0) = 1) THEN
                                          -- Brinde em Unidades com escolha de produtos
                                          NVL(PCPROMOCAOMED.QTDEBRINDE,0)
                                        WHEN (NVL(PCPROMOCAOMED.TIPOCONCESSAOBRINDE,0) = 2) THEN
                                          -- Brinde em Unidades sem escolha de produtos
                                          (SELECT SUM(PCPROMOCAOBRINDEMED.QTDE)
                                             FROM PCPROMOCAOBRINDEMED
                                            WHERE (PCPROMOCAOBRINDEMED.CODPROMOCAOMED = PCPROMOCAOMED.CODPROMOCAOMED))
                                        WHEN (NVL(PCPROMOCAOMED.TIPOCONCESSAOBRINDE,0) = 3) THEN
                                          -- Brinde em % sobre a Venda
                                          NVL(PCPROMOCAOMED.QTDEBRINDE,0)
                                        ELSE
                                          TO_NUMBER(NULL)
                                      END
                                    ELSE
                                      TO_NUMBER(NULL)
                                  END BRINDESCONCESSAO
                                , PCPROMOCAOMED.MULTIPLOSBRINDES
                                , CAMINHOENCARTE
                                , ACEITADESCPROMCAMPANHA
                                , TIPOPOLITICA -- MED_VLMIN_FXQ
                             FROM PCPROMOCAOMED
                            WHERE (TRUNC(SYSDATE) BETWEEN PCPROMOCAOMED.DATAINICIAL AND PCPROMOCAOMED.DATAFINAL)
                              AND (NVL(PCPROMOCAOMED.BLOQUEIO,'N') <> 'S') -- DDVENDAS-38166
                              AND ( (PCPROMOCAOMED.TIPOPROMOCAO IN ('M','V','N')) OR
                                    ((PCPROMOCAOMED.TIPOPROMOCAO = 'C') AND (NVL(PCPROMOCAOMED.VLRMINITENSPROMOCAO,0) > 0)) ) -- MED_VLMIN_FXQ
                                 ) LOOP

            -- Se Campanha, somente carrega para chamada 13 e se for VENDA
            -- Se Mix/Valor, somente carrega para chamada 14
            IF ( (pi_nTipoChamada = 13) AND (vc_Promo.TIPOPROMOCAO IN ('N')) AND (pi_nCondVenda = 1) ) OR
               ( (pi_nTipoChamada = 14) AND (vc_Promo.TIPOPROMOCAO IN ('M','V')) ) OR
               ( (pi_nTipoChamada = 14) AND (vc_Promo.TIPOPROMOCAO = 'F') ) THEN -- MED_VLMIN_FXQ

              -- Se o Cliente pode comprar da Promoção
              IF (PKG_FUNCOESVENDAS_MED.F_PODECOMPRARPROMOCAO(vc_Promo.CODPROMOCAOMED,
                                                              pi_vCodFilial,
                                                              pi_nCodCli,
                                                              vrRegiao.nNUMREGIAO,
                                                              pi_nCodUsur,
                                                              pi_nCodPlPag,
                                                              pi_nCodCondicaoVenda,
                                                              pi_vOrigemPed,
                                                              SUBSTR(pi_vTipoFv,1,2),
                                                              TRUNC(SYSDATE)) = 'S') THEN

                -- Insere Promoção na Tabela Temporária de Campanha
                INSERT INTO PCMED_PROMOCAO_CAMPANHA
                          ( CODPROMOCAOMED
                          , DESCRICAOPROMOCAO
                          , TIPOPROMOCAO
                          , TIPOVALIDAVALORMIN
                          , MINIMOPEDIDO
                          , TIPOCONCESSAOBRINDE
                          , BRINDESCONCESSAO
                          , MULTIPLOSBRINDES
                          , CAMINHOENCARTE
                          , ACEITADESCPROMCAMPANHA )
                   VALUES ( vc_Promo.CODPROMOCAOMED
                          , vc_Promo.DESCRICAORESUMIDA
                          , vc_Promo.TIPOPROMOCAO
                          , vc_Promo.TIPOVALIDAVALORMIN
                          , vc_Promo.MINIMOPEDIDO
                          , vc_Promo.TIPOCONCESSAOBRINDE
                          , vc_Promo.BRINDESCONCESSAO
                          , vc_Promo.MULTIPLOSBRINDES
                          , vc_Promo.CAMINHOENCARTE
                          , vc_Promo.ACEITADESCPROMCAMPANHA );

              END IF; -- Fim Condição: Se o Cliente pode comprar da Promoção

            END IF; -- Fim Condição: Se Campanha ou Mix/Valor

          END LOOP; -- FIM LAÇO PROMOÇÕES VÁLIDAS
          -- FIM: DEFINIÇÃO DAS PROMOÇÕES VÁLIDAS DE CAMPANHA E MIX/VALOR------------------------------------

          -- INICIO: DEFINIÇÃO DO MIX VÁLIDO DA CAMPANHA E DA PROMOÇÃO DE MIX/VALOR--------------------------
          FOR vc_Promo IN (SELECT PCMED_PROMOCAO_CAMPANHA.CODPROMOCAOMED
                                , PCMED_PROMOCAO_CAMPANHA.TIPOPROMOCAO
                                , PCMED_PROMOCAO_CAMPANHA.TIPOVALIDAVALORMIN
                                , PCMED_PROMOCAO_CAMPANHA.TIPOCONCESSAOBRINDE
                                , PCPROMOCAOTELEVMED.CODPROD
                                -- MED_VLMIN_FXQ
                                , CASE
                                    WHEN (PCMED_PROMOCAO_CAMPANHA.TIPOPROMOCAO = 'F') THEN
                                      PCPROMOCAOTELEVMED.INICIOINTERVALO
                                    WHEN (NVL(PCPROMOCAOMED.PERMITEQTMINIMASEMOBRIG,'N') = 'S') THEN -- DDMEDICA-1212
                                      PCPROMOCAOTELEVMED.INICIOINTERVALO
                                    WHEN (NVL(PCPROMOCAOTELEVMED.OBRIGATORIO,'N') = 'S') THEN
                                      PCPROMOCAOTELEVMED.INICIOINTERVALO
                                    ELSE
                                      TO_NUMBER(NULL)
                                  END QTMIN
                                , NVL(PCPROMOCAOTELEVMED.OBRIGATORIO,'N') OBRIGATORIO
                                , PCPRODUT.DESCRICAO
                                , PCMARCA.MARCA
                             FROM PCMED_PROMOCAO_CAMPANHA -->> Somente as Promoções de Campanha Válidas OU Mix OU Valor
                                , PCPROMOCAOTELEVMED
                                , PCPROMOCAOMED
                                , PCPRODUT
                                , PCMARCA
                            WHERE (PCMED_PROMOCAO_CAMPANHA.CODPROMOCAOMED = PCPROMOCAOTELEVMED.CODPROMOCAOMED)
                              AND (PCPROMOCAOMED.CODPROMOCAOMED           = PCMED_PROMOCAO_CAMPANHA.CODPROMOCAOMED)
                              AND (PCPROMOCAOTELEVMED.CODPROD             = PCPRODUT.CODPROD)
                              AND (PCPRODUT.CODMARCA                      = PCMARCA.CODMARCA)) LOOP

            -- Insere na Tabela Temporária de Mix
            INSERT INTO PCMED_PROMOCAO_CAMPANHA_MIX
                      ( CODPROMOCAOMEDREF
                      , TIPOPROMOCAO
                      , TIPOVALIDAVALORMIN
                      , TIPOCONCESSAOBRINDE
                      , CODPROD
                      , DESCRICAOPRODUTO
                      , NOMEMARCA
                      , QTDEMINIMA
                      , OBRIGATORIO )
               VALUES ( vc_Promo.CODPROMOCAOMED
                      , vc_Promo.TIPOPROMOCAO
                      , vc_Promo.TIPOVALIDAVALORMIN
                      , vc_Promo.TIPOCONCESSAOBRINDE
                      , vc_Promo.CODPROD
                      , vc_Promo.DESCRICAO
                      , vc_Promo.MARCA
                      , vc_Promo.QTMIN
                      , vc_Promo.OBRIGATORIO );

          END LOOP; -- Fim Laço Itens do Pedido
          -- FIM: DEFINIÇÃO DO MIX VÁLIDO DA CAMPANHA E DA PROMOÇÃO DE MIX/VALOR-----------------------------

          -- INICIO: APURAÇÃO VENDA REALIZADA DO MIX VÁLIDO DA CAMPANHA E PROMOÇÃO DE MIX/VALOR--------------
          -- (OBS: Vai gerar produto cartesiano pq o produto pode estar em mais de uma Campanha)
          FOR vc_Venda IN (SELECT PCPEDI.CODFILIALRETIRA
                                , PCPEDI.CODPROD
                                , PCPEDI.QT
                                , (PCPEDI.PTABELA - NVL(PCPEDI.ST,0) - NVL(PCPEDI.VLFECP,0) - NVL(PCPEDI.VLREPASSE,0)) PRECO_TABELA
                                , (PCPEDI.PVENDA - NVL(PCPEDI.ST,0) - NVL(PCPEDI.VLFECP,0) - NVL(PCPEDI.VLREPASSE,0)) PRECO_LIQUIDO
                                , PCPEDI.CODPROMOCAOMED CODPROMOCAOMED_ITEMPED
                                , PCMED_PROMOCAO_CAMPANHA_MIX.CODPROMOCAOMEDREF CODPROMOCAOMED_MIXPROMO
                                , PCMED_PROMOCAO_CAMPANHA_MIX.TIPOPROMOCAO TIPOPROMOCAO_MIXPROMO
                                , PCPEDI.CODPROMOCAOMED
                                , PCPEDI.PERDESC
                                , PCMED_PROMOCAO_CAMPANHA.ACEITADESCPROMCAMPANHA
                                , PCPEDI.INICIOINTERVALODESCQUANT -- MED_VLMIN_FXQ
                             FROM PCPEDI
                                , PCMED_PROMOCAO_CAMPANHA_MIX
                                , PCMED_PROMOCAO_CAMPANHA
                            WHERE (PCPEDI.NUMPED                          = pi_nNumPed)
                              AND (PCMED_PROMOCAO_CAMPANHA_MIX.CODPROD    = PCPEDI.CODPROD)
                              AND (PCMED_PROMOCAO_CAMPANHA.CODPROMOCAOMED = PCMED_PROMOCAO_CAMPANHA_MIX.CODPROMOCAOMEDREF)) LOOP

            -- Pesquisa o Saldo Estoque
            BEGIN
              SELECT GREATEST(NVL(PCEST.QTESTGER,0) - NVL(PCEST.QTRESERV,0) - NVL(PCEST.QTBLOQUEADA,0),0)
                INTO vnSaldoEstoque
                FROM PCEST
               WHERE (PCEST.CODFILIAL = NVL(vc_Venda.CODFILIALRETIRA,pi_vCodFilial))
                 AND (PCEST.CODPROD   = vc_Venda.CODPROD);
            EXCEPTION
              WHEN NO_DATA_FOUND THEN
                vnSaldoEstoque := 0;
            END;

            -- Qtde Disponível para Pontuar
            IF (NVL(vnSaldoEstoque,0) >= NVL(vc_Venda.QT,0)) THEN
              vnQtdeDispPontuar := NVL(vc_Venda.QT,0);
            ELSE
              vnQtdeDispPontuar := NVL(vnSaldoEstoque,0);
            END IF;

            -- SOMENTE Produtos com Estoque Pontuam
            IF (NVL(vnQtdeDispPontuar,0) > 0) THEN

              -- Se Promoção de Mix ou Valor, a Promoção do MIX tem que ser a mesma da escolhida no Item do Pedido
              IF     (vc_Venda.TIPOPROMOCAO_MIXPROMO IN ('M','V')) AND
                     (NVL(vc_Venda.CODPROMOCAOMED_ITEMPED,0) = NVL(vc_Venda.CODPROMOCAOMED_MIXPROMO,0)) THEN
                -- Atualiza Mix
                UPDATE PCMED_PROMOCAO_CAMPANHA_MIX
                   SET QTDEVENDIDA            = NVL(QTDEVENDIDA,0)  + NVL(vnQtdeDispPontuar,0)                                   -->> Somente Qtde Disp. em Estoque
                     , VALORTABELA            = NVL(VALORTABELA,0)  + (NVL(vc_Venda.PRECO_TABELA,0) * NVL(vnQtdeDispPontuar,0))  -->> Somente Qtde Disp. em Estoque
                     , VALORLIQUIDO           = NVL(VALORLIQUIDO,0) + (NVL(vc_Venda.PRECO_LIQUIDO,0) * NVL(vnQtdeDispPontuar,0)) -->> Somente Qtde Disp. em Estoque
                 WHERE (CODPROMOCAOMEDREF = vc_Venda.CODPROMOCAOMED_MIXPROMO)
                   AND (CODPROD           = vc_Venda.CODPROD);
              -- MED_VLMIN_FXQ - Adicionado o Tipo F - Promoção por Faixa
              ELSIF  (vc_Venda.TIPOPROMOCAO_MIXPROMO = 'F') AND
                     (NVL(vc_Venda.CODPROMOCAOMED_ITEMPED,0) = NVL(vc_Venda.CODPROMOCAOMED_MIXPROMO,0)) THEN
                -- Atualiza Mix
                UPDATE PCMED_PROMOCAO_CAMPANHA_MIX
                   SET QTDEVENDIDA            = NVL(QTDEVENDIDA,0)  + NVL(vnQtdeDispPontuar,0)                                   -->> Somente Qtde Disp. em Estoque
                     , VALORTABELA            = NVL(VALORTABELA,0)  + (NVL(vc_Venda.PRECO_TABELA,0) * NVL(vnQtdeDispPontuar,0))  -->> Somente Qtde Disp. em Estoque
                     , VALORLIQUIDO           = NVL(VALORLIQUIDO,0) + (NVL(vc_Venda.PRECO_LIQUIDO,0) * NVL(vnQtdeDispPontuar,0)) -->> Somente Qtde Disp. em Estoque
                 WHERE (CODPROMOCAOMEDREF = vc_Venda.CODPROMOCAOMED_MIXPROMO)
                   AND (CODPROD           = vc_Venda.CODPROD)
                   AND (QTDEMINIMA        = vc_Venda.INICIOINTERVALODESCQUANT);
              END IF;

              -- Se Promoção de Campanha, não tem vínculo com a Promoção Selecionada, basta ser o mesmo Produto
              IF (vc_Venda.TIPOPROMOCAO_MIXPROMO IN ('N')) THEN
                -- Verifica se Aceita Desconto da Promoção na Campanha
                IF (NVL(vc_Venda.ACEITADESCPROMCAMPANHA,'N') <> 'S') THEN
                  IF (NVL(vc_Venda.CODPROMOCAOMED,0) > 0) AND
                     (NVL(vc_Venda.PERDESC,0) > 0)        THEN
                    -- Atualiza Mix
                    UPDATE PCMED_PROMOCAO_CAMPANHA_MIX
                       SET BLOQUEIODESCPROMCAMPANHA = 'S' -->> Flag para não apagar este alerta no final da validação
                         , ALERTA                   = 'S'
                         , OBSERVACAOALERTA         = 'Desc. Promocional em Itens da Campanha'
                     WHERE (CODPROMOCAOMEDREF = vc_Venda.CODPROMOCAOMED_MIXPROMO)
                       AND (CODPROD           = vc_Venda.CODPROD);
                  END IF;
                END IF;
                -- Atualiza Mix
                UPDATE PCMED_PROMOCAO_CAMPANHA_MIX
                   SET QTDEVENDIDA            = NVL(QTDEVENDIDA,0)  + NVL(vnQtdeDispPontuar,0)                                   -->> Somente Qtde Disp. em Estoque
                     , VALORTABELA            = NVL(VALORTABELA,0)  + (NVL(vc_Venda.PRECO_TABELA,0) * NVL(vnQtdeDispPontuar,0))  -->> Somente Qtde Disp. em Estoque
                     , VALORLIQUIDO           = NVL(VALORLIQUIDO,0) + (NVL(vc_Venda.PRECO_LIQUIDO,0) * NVL(vnQtdeDispPontuar,0)) -->> Somente Qtde Disp. em Estoque
                 WHERE (CODPROMOCAOMEDREF = vc_Venda.CODPROMOCAOMED_MIXPROMO)
                   AND (CODPROD           = vc_Venda.CODPROD);
              END IF;

            END IF; -- FIM CONDIÇÃO: SOMENTE Produtos com Estoque Pontuam

          END LOOP; -- FIM LAÇO VENDA REALIZADA DO MIX VÁLIDO
          -- FIM: APURAÇÃO VENDA REALIZADA DO MIX VÁLIDO DA CAMPANHA E PROMOÇÃO DE MIX/VALOR-----------------

          -- INICIO: ATUALIZAÇÃO DOS TOTAIS DA CAMPANHA E PROMOÇÃO DE MIX/VALOR/QTDE -----------------------------
          -- Promoção de MIX ou Campanha com Mix Mínimo
          FOR vc_Promo IN (SELECT CODPROMOCAOMEDREF
                                , COUNT(DISTINCT CODPROD) SKUS
                             FROM PCMED_PROMOCAO_CAMPANHA_MIX
                            WHERE (PCMED_PROMOCAO_CAMPANHA_MIX.QTDEVENDIDA > 0) -->> Itens do Mix com Venda
                              AND ( (PCMED_PROMOCAO_CAMPANHA_MIX.TIPOPROMOCAO = 'M') OR
                                    ((PCMED_PROMOCAO_CAMPANHA_MIX.TIPOPROMOCAO = 'N') AND (PCMED_PROMOCAO_CAMPANHA_MIX.TIPOVALIDAVALORMIN = 'M')) )
                            GROUP BY CODPROMOCAOMEDREF) LOOP
            UPDATE PCMED_PROMOCAO_CAMPANHA
               SET ATINGIDOPEDIDO  = vc_Promo.SKUS
             WHERE (CODPROMOCAOMED = vc_Promo.CODPROMOCAOMEDREF);
          END LOOP;
          -- Promoção de Valor ou Campanha com Valor Mínimo
          FOR vc_Promo IN (SELECT CODPROMOCAOMEDREF
                                , SUM(VALORLIQUIDO) VALORLIQUIDO
                             FROM PCMED_PROMOCAO_CAMPANHA_MIX
                            WHERE (PCMED_PROMOCAO_CAMPANHA_MIX.QTDEVENDIDA > 0) -->> Itens do Mix com Venda
                              AND ( (PCMED_PROMOCAO_CAMPANHA_MIX.TIPOPROMOCAO = 'V') OR
                                    ((PCMED_PROMOCAO_CAMPANHA_MIX.TIPOPROMOCAO = 'N') AND (PCMED_PROMOCAO_CAMPANHA_MIX.TIPOVALIDAVALORMIN = 'V')) )
                            GROUP BY CODPROMOCAOMEDREF) LOOP
            UPDATE PCMED_PROMOCAO_CAMPANHA
               SET ATINGIDOPEDIDO  = vc_Promo.VALORLIQUIDO
             WHERE (CODPROMOCAOMED = vc_Promo.CODPROMOCAOMEDREF);
          END LOOP;
          -- MED_VLMIN_FXQ - Promoção de Faixa de Quantidade com Valor Mínimo
          FOR vc_Promo IN (SELECT CODPROMOCAOMEDREF
                                , SUM(VALORLIQUIDO) VALORLIQUIDO
                             FROM PCMED_PROMOCAO_CAMPANHA_MIX
                            WHERE (PCMED_PROMOCAO_CAMPANHA_MIX.QTDEVENDIDA > 0) -->> Itens do Mix com Venda
                              AND (PCMED_PROMOCAO_CAMPANHA_MIX.TIPOPROMOCAO = 'F')
                            GROUP BY CODPROMOCAOMEDREF) LOOP
            UPDATE PCMED_PROMOCAO_CAMPANHA
               SET ATINGIDOPEDIDO  = vc_Promo.VALORLIQUIDO
             WHERE (CODPROMOCAOMED = vc_Promo.CODPROMOCAOMEDREF);
          END LOOP;
          -- Promoção de Campanha com Quantidade Mínima
          FOR vc_Promo IN (SELECT CODPROMOCAOMEDREF
                                , SUM(QTDEVENDIDA) QTDEVENDIDA
                             FROM PCMED_PROMOCAO_CAMPANHA_MIX
                            WHERE (PCMED_PROMOCAO_CAMPANHA_MIX.QTDEVENDIDA > 0) -->> Itens do Mix com Venda
                              AND ((PCMED_PROMOCAO_CAMPANHA_MIX.TIPOPROMOCAO = 'N') AND (PCMED_PROMOCAO_CAMPANHA_MIX.TIPOVALIDAVALORMIN = 'Q'))
                            GROUP BY CODPROMOCAOMEDREF) LOOP
            UPDATE PCMED_PROMOCAO_CAMPANHA
               SET ATINGIDOPEDIDO  = vc_Promo.QTDEVENDIDA
             WHERE (CODPROMOCAOMED = vc_Promo.CODPROMOCAOMEDREF);
          END LOOP;
          -- FIM: ATUALIZAÇÃO DOS TOTAIS DA CAMPANHA E PROMOÇÃO DE MIX/VALOR/QTDE --------------------------------

          -- INICIO: BRINDES VÁLIDOS CAMPANHA ---------------------------------------------------------------
          IF (pi_nTipoChamada = 13) THEN
            FOR vc_Promo IN (SELECT PCMED_PROMOCAO_CAMPANHA.CODPROMOCAOMED
                                  , PCMED_PROMOCAO_CAMPANHA.TIPOPROMOCAO
                                  , PCMED_PROMOCAO_CAMPANHA.TIPOVALIDAVALORMIN
                                  , PCMED_PROMOCAO_CAMPANHA.TIPOCONCESSAOBRINDE
                                  , PCPROMOCAOBRINDEMED.CAMPO
                                  , PCPROMOCAOBRINDEMED.CODIGO
                                  , CASE WHEN (NVL(PCMED_PROMOCAO_CAMPANHA.TIPOCONCESSAOBRINDE,0) = 2) THEN
                                      -- Brinde em Unidades sem escolha de produtos - a Qtde é Fixa e não altera
                                      PCPROMOCAOBRINDEMED.QTDE
                                    ELSE
                                      -- Demais casos, os brindes são selecionados pelo usuário
                                      TO_NUMBER(NULL)
                                    END QTDEBRINDES
                                  , CASE WHEN PCPROMOCAOBRINDEMED.CAMPO = 'PR' THEN                                  
                                      PCPROMOCAOBRINDEMED.PRECOFIXO
                                    ELSE
                                      TO_NUMBER(NULL)
                                    END PRECOFIXO  
                               FROM PCMED_PROMOCAO_CAMPANHA -->> Somente as Promoções de Campanha Válidas OU Mix OU Valor
                                  , PCPROMOCAOBRINDEMED
                              WHERE (PCMED_PROMOCAO_CAMPANHA.CODPROMOCAOMED = PCPROMOCAOBRINDEMED.CODPROMOCAOMED)) LOOP

              -- Laço para Gerar os Códigos de Produtos
              FOR vc_Produto IN (SELECT DISTINCT TABAUX.CODPROD, TABAUX.DESCRICAO, TABAUX.MARCA
                                   FROM (-- PELO CAMPO PR - Produto
                                         SELECT PCPRODUT.CODPROD
                                              , PCPRODUT.DESCRICAO
                                              , PCMARCA.MARCA
                                           FROM PCPRODUT
                                              , PCMARCA
                                          WHERE (PCPRODUT.CODMARCA = PCMARCA.CODMARCA)
                                            AND (vc_Promo.CAMPO    = 'PR') -->> Por Código de Produto
                                            AND (PCPRODUT.CODPROD  = vc_Promo.CODIGO)
                                         UNION
                                         -- PELO CAMPO MA - Marca
                                         SELECT PCPRODUT.CODPROD
                                              , PCPRODUT.DESCRICAO
                                              , PCMARCA.MARCA
                                           FROM PCPRODUT
                                              , PCMARCA
                                          WHERE (PCPRODUT.CODMARCA = PCMARCA.CODMARCA)
                                            AND (vc_Promo.CAMPO    = 'MA') -->> Por Código da Marca
                                            AND (PCPRODUT.CODMARCA = vc_Promo.CODIGO)
                                         UNION
                                         -- PELO CAMPO GP - Grupo de Produtos
                                         SELECT PCPRODUT.CODPROD
                                              , PCPRODUT.DESCRICAO
                                              , PCMARCA.MARCA
                                           FROM PCPRODUT
                                              , PCMARCA
                                              , PCGRUPOSCAMPANHAI
                                          WHERE (PCPRODUT.CODMARCA          = PCMARCA.CODMARCA)
                                            AND (PCGRUPOSCAMPANHAI.CODITEM  = PCPRODUT.CODPROD)
                                            AND (vc_Promo.CAMPO             = 'GP') -->> Por Código da Marca
                                            AND (PCGRUPOSCAMPANHAI.CODGRUPO = vc_Promo.CODIGO)
                                         ) TABAUX) LOOP

                -- Pesquisa a Filial Retira Padrão do Brinde - DDMEDICA-7318
                vvCodFilialRetiraBrinde := F_OBTEM_FILIAL_RETIRA_BRINDE(vrParamFilial.vUSAESTOQUEDEPFECHADO,
                                                                        vc_Produto.CODPROD,
                                                                        pi_vCodFilial,
                                                                        vvCodFilialRetira);
                     
                -- Pesquisa o Saldo Estoque, verificando primeiro a Filial Retira - DDMEDICA-7318
                BEGIN
                  SELECT GREATEST(NVL(PCEST.QTESTGER,0) - NVL(PCEST.QTRESERV,0) - NVL(PCEST.QTBLOQUEADA,0),0)
                    INTO vnSaldoEstoque
                    FROM PCEST
                   WHERE (PCEST.CODFILIAL = NVL(vvCodFilialRetiraBrinde,pi_vCodFilial)) -- DDMEDICA-7318
                     AND (PCEST.CODPROD   = vc_Produto.CODPROD);
                EXCEPTION
                  WHEN NO_DATA_FOUND THEN
                    vnSaldoEstoque := 0;
                END;

                -- Verifica se o Produto já foi inserido na Tabela Temporária para a Promoção
                BEGIN
                  SELECT 'S'
                    INTO vvAchouProduto
                    FROM PCMED_PROMOCAO_CAMPANHA_BRI
                   WHERE (PCMED_PROMOCAO_CAMPANHA_BRI.CODPROMOCAOMEDREF = vc_Promo.CODPROMOCAOMED)
                     AND (PCMED_PROMOCAO_CAMPANHA_BRI.CODPROD           = vc_Produto.CODPROD)
                     AND (ROWNUM                                        = 1);
                EXCEPTION
                  WHEN NO_DATA_FOUND THEN
                    vvAchouProduto := 'N';
                END;

                -- Insere na Tabela Temporária Brindes se ainda não inseriu Produto + Promoção
                IF (vvAchouProduto = 'N') THEN

                  -- SOMENTE Produtos com Estoque podem ser concedidos como Brinde
                  IF (NVL(vnSaldoEstoque,0) > 0) THEN

                    -- Insere Item no Array para fazer o Cálculo do Preço mais abaixo
                    viIdxNew := NVL(vtIncluiItens.COUNT,0) + 1;
                    vtIncluiItens(viIdxNew).vnCodPromocaoMed := vc_Promo.CODPROMOCAOMED;
                    vtIncluiItens(viIdxNew).vnCodProd        := vc_Produto.CODPROD;
                    vtIncluiItens(viIdxNew).vnQtde           := 1; -->> Coloca 1 para fazer o cálculo do Preço baseado em 1 unidade
                    IF (NVL(vc_Promo.PRECOFIXO,0) > 0) THEN
                      vtIncluiItens(viIdxNew).vvUsarPrecoFixoPrioritario := 'S';
                      vtIncluiItens(viIdxNew).vnPrecoFixo                := vc_Promo.PRECOFIXO; 
                    ELSE
                      vtIncluiItens(viIdxNew).vvUsarPrecoFixoPrioritario := 'N';
                      vtIncluiItens(viIdxNew).vnPrecoFixo                := NULL; 
                    END IF;

                    -- Insere na Tabela Temporária para Apresentação
                    INSERT INTO PCMED_PROMOCAO_CAMPANHA_BRI
                              ( CODPROMOCAOMEDREF
                              , TIPOPROMOCAO
                              , TIPOVALIDAVALORMIN
                              , TIPOCONCESSAOBRINDE
                              , CODPROD
                              , DESCRICAOPRODUTO
                              , NOMEMARCA
                              , QTDEBRINDES
                              , BLOQUEIOCAMPANHA
                              , MOTIVOBLOQUEIOCAMPANHA
                              , PRECOFIXO )
                       VALUES ( vc_Promo.CODPROMOCAOMED
                              , vc_Promo.TIPOPROMOCAO
                              , vc_Promo.TIPOVALIDAVALORMIN
                              , vc_Promo.TIPOCONCESSAOBRINDE
                              , vc_Produto.CODPROD
                              , vc_Produto.DESCRICAO
                              , vc_Produto.MARCA
                              , vc_Promo.QTDEBRINDES
                              , vvBloqueioCampanha
                              , vvMotivoBloqueioCampanha
                              , vtIncluiItens(viIdxNew).vnPrecoFixo );

                  END IF; -- Fim Condição: SOMENTE Produtos com Estoque podem ser concedidos como Brinde

                END IF; -- Fim Condição: Não Inseriu ainda o Prduto + Promoção na Tabela Temporária

              END LOOP; -- Fim Laço para Gerar os Códigos de Produtos

            END LOOP; -- FIM LAÇO BRINDES VÁLIDOS CAMPANHA
          END IF;
          -- FIM: BRINDES VÁLIDOS CAMPANHA ------------------------------------------------------------------

          -- INICIO: EXCLUI OS CABEÇALHOS DE PROMOÇAO DE MIX/VALOR QUE NÃO FORAM SELECIONADOS NO PEDIDO -----
          IF (pi_nTipoChamada = 14) THEN
            DELETE FROM PCMED_PROMOCAO_CAMPANHA_MIX WHERE CODPROMOCAOMEDREF IN (SELECT PCMED_PROMOCAO_CAMPANHA.CODPROMOCAOMED
                                                                                  FROM PCMED_PROMOCAO_CAMPANHA
                                                                                 WHERE (PCMED_PROMOCAO_CAMPANHA.TIPOPROMOCAO IN ('M','V','F')) -- MED_VLMIN_FXQ - Adicionado o Tipo 'F'
                                                                                   AND (NVL(PCMED_PROMOCAO_CAMPANHA.ATINGIDOPEDIDO,0) = 0));
            DELETE FROM PCMED_PROMOCAO_CAMPANHA
                  WHERE (PCMED_PROMOCAO_CAMPANHA.TIPOPROMOCAO IN ('M','V','F')) -- MED_VLMIN_FXQ - Adicionado o Tipo 'F'
                    AND (NVL(PCMED_PROMOCAO_CAMPANHA.ATINGIDOPEDIDO,0) = 0);
          END IF;
          -- FIM: EXCLUI OS CABEÇALHOS DE PROMOÇAO DE MIX/VALOR QUE NÃO FORAM SELECIONADOS NO PEDIDO --------

        --------------------------------------------------
        -- ITENS DO PEDIDO QUE SÃO BONIFICAÇÃO DE CAMPANHA
        --------------------------------------------------
        ELSIF (pi_nTipoChamada = 15) THEN

          -- Log do Item
          P_INSERE_LOG(0, 'Geração da Bonificação de Campanha');

          -- Carrega Array com Itens da Campanha
          FOR vc_ItensPed IN ( SELECT PCMED_PROMOCAO_CAMPANHA.CODPROMOCAOMED
                                    , PCMED_PROMOCAO_CAMPANHA_BRI.CODPROD
                                    , PCMED_PROMOCAO_CAMPANHA_BRI.QTDEBRINDES
                                    , PCMED_PROMOCAO_CAMPANHA_BRI.PRECOFIXO
                                 FROM PCMED_PROMOCAO_CAMPANHA
                                    , TABLE(PKG_FUNCOESVENDAS_MED.F_PROMOCAORESULTADOCAB(9999999999)) TAB -->> Passa um Limite de Crédito do RCA bem alto porque já foi validado anteriomente
                                    , PCMED_PROMOCAO_CAMPANHA_BRI
                                WHERE (PCMED_PROMOCAO_CAMPANHA.CODPROMOCAOMED   = TAB.CODPROMOCAOMED)
                                  AND (PCMED_PROMOCAO_CAMPANHA.CODPROMOCAOMED   = PCMED_PROMOCAO_CAMPANHA_BRI.CODPROMOCAOMEDREF)
                                  AND (PCMED_PROMOCAO_CAMPANHA.SEL              = 'S')
                                  AND (TAB.PROMOCAOCAMPANHAVALIDA               = 'S')
                                  AND (PCMED_PROMOCAO_CAMPANHA_BRI.QTDEBRINDES  > 0)) LOOP

            -- Pesquisa Dados do Produto
            BEGIN
              SELECT PCPRODUT.CODLINHAPRAZO
                INTO vrProduto_O.nCODLINHAPRAZO
                FROM PCPRODUT
               WHERE (PCPRODUT.CODPROD =  vc_ItensPed.CODPROD);
            EXCEPTION
              WHEN NO_DATA_FOUND THEN
                vrProduto_O.nCODLINHAPRAZO := NULL;
            END;

            -- Insere Item no Array
            viIdxNew                                 := NVL(vtIncluiItens.COUNT,0) + 1;
            vtIncluiItens(viIdxNew).vnCodPromocaoMed := vc_ItensPed.CODPROMOCAOMED;
            vtIncluiItens(viIdxNew).vnCodProd        := vc_ItensPed.CODPROD;
            vtIncluiItens(viIdxNew).vnQtde           := NVL(vc_ItensPed.QTDEBRINDES,0);
            vtIncluiItens(viIdxNew).vvParticipaGiro  := 'S';
            vtIncluiItens(viIdxNew).vvBonific        := 'F';
            vtIncluiItens(viIdxNew).vnCodPlPag       := 99; -- Coloca Plano 99 por causa da Quebra de Pedidos Bonificados
            vtIncluiItens(viIdxNew).vnCodLinhaPrazo  := vrProduto_O.nCODLINHAPRAZO;
            vtIncluiItens(viIdxNew).vnPercDesc       := 0;  -- Requerido NOT NUL
            IF (NVL(vc_ItensPed.PRECOFIXO,0) > 0) THEN
              vtIncluiItens(viIdxNew).vvUsarPrecoFixoPrioritario := 'S';
              vtIncluiItens(viIdxNew).vnPrecoFixo                := vc_ItensPed.PRECOFIXO; 
            ELSE
              vtIncluiItens(viIdxNew).vvUsarPrecoFixoPrioritario := 'N';
              vtIncluiItens(viIdxNew).vnPrecoFixo                := NULL;
            END IF; 

            -- DDMEDICA-7318 - Filial Retira nos Brindes
            IF (NVL(vrParamFilial.vUSAESTOQUEDEPFECHADO,'N') = 'S') THEN
              vtIncluiItens(viIdxNew).vvCodFilialRetira := F_OBTEM_FILIAL_RETIRA_BRINDE(vrParamFilial.vUSAESTOQUEDEPFECHADO,
                                                                                        vc_ItensPed.CODPROD,
                                                                                        pi_vCodFilial,
                                                                                        vvCodFilialRetira);                                                                                        
            END IF;                                                                                        

            -- Log do Item
            P_INSERE_LOG(0, 'Gerar Bonificação para Produto ' || vc_ItensPed.CODPROD || ' ; ' || NVL(vc_ItensPed.QTDEBRINDES,0) || ';' || NVL(vc_ItensPed.CODPROMOCAOMED,0) || ';' || vtIncluiItens(viIdxNew).vvCodFilialRetira);
            P_INSERE_LOG(0, 'Preço Fixo da Bonificação: ' || vc_ItensPed.PRECOFIXO);

          END LOOP; -- Fim Laço Itens do Pedido

        ----------------------------------------------
        -- INCLUIR ITENS CROSS DOCKING [16] - MED-1096
        ----------------------------------------------
        ELSIF (pi_nTipoChamada = 16) THEN

          -- Where do CrossDocking - DDMEDICA-619
          IF (pi_vInProdutosCrossDock IS NULL) THEN
            vvWhereCrossDocking := '(1=1)';
          ELSE
            vvWhereCrossDocking := '(TB.IDMOVIMENTACAO IN (' || pi_vInProdutosCrossDock || '))';
          END IF;

          -- Monta SQL (Vou usar a Tabela Temporária que já existia) (Este Select está também no DMMedicamento)
          IF (pi_nCondVenda = 10) THEN
            IF (pi_vOrigemPed = 'B') THEN
              -- Pedido Transferência Balcão
              vsSQL := ' SELECT TB.CODPROD
                              , TB.NUMLOTE
                              , TB.SALDO
                              , TB.CODIGODEPOSITOWMS
                              , 0 LIQDEVCLI
                           FROM TABLE(PKG_FUNCOESVENDAS_MED.F_OBTER_LOTES_PEDIDO(''PTB'',1,' || NVL(pi_nNumTransEntCrossDock,0) || ', ' || NVL(pi_nNumPed,0) || ')) TB
                          WHERE (RESTRICAO IS NULL) AND ' || vvWhereCrossDocking;
            ELSE
              -- Pedido Transferência Normal
              vsSQL := ' SELECT TB.CODPROD
                              , TB.NUMLOTE
                              , TB.SALDO
                              , TB.CODIGODEPOSITOWMS
                              , 0 LIQDEVCLI
                           FROM TABLE(PKG_FUNCOESVENDAS_MED.F_OBTER_LOTES_PEDIDO(''PT'',1,' || NVL(pi_nNumTransEntCrossDock,0) || ', ' || NVL(pi_nNumPed,0) || ')) TB
                          WHERE (RESTRICAO IS NULL) AND ' || vvWhereCrossDocking;
            END IF;
          ELSIF (NVL(pi_vTipoFv,'TL') = 'PA') THEN
            -- Troca de Nota de Venda de Avaria - DDMEDICA-1969
            vsSQL := ' SELECT TB.CODPROD
                            , TB.NUMLOTE
                            , TB.SALDO
                            , TB.CODIGODEPOSITOWMS
                            , TB.CUSTOFIN LIQDEVCLI
                         FROM TABLE(PKG_FUNCOESVENDAS_MED.F_OBTER_LOTES_PEDIDO(''PN'',1,' || NVL(pi_nNumTransEntCrossDock,0) || ', ' || NVL(pi_nNumPed,0) || ')) TB
                        WHERE (RESTRICAO IS NULL) AND ' || vvWhereCrossDocking;
          ELSE
            -- Pedido Crossdocking
            vsSQL := ' SELECT TB.CODPROD
                            , TB.NUMLOTE
                            , TB.SALDO
                            , TB.CODIGODEPOSITOWMS
                            , 0 LIQDEVCLI
                         FROM TABLE(PKG_FUNCOESVENDAS_MED.F_OBTER_LOTES_PEDIDO(''PC'',1,' || NVL(pi_nNumTransEntCrossDock,0) || ', ' || NVL(pi_nNumPed,0) || ', NULL, NULL, NULL, NULL, ' || NVL(pi_nCodPromocaoMedPedido,0) || ')) TB
                        WHERE (RESTRICAO IS NULL) AND ' || vvWhereCrossDocking;
          END IF;

          -- Processa Cursor
          OPEN vRefCursor FOR vsSQL;
          LOOP

            -- Leitura do Registro do Cursor
            FETCH vRefCursor INTO vrDadosCrossDock;
            EXIT WHEN vRefCursor%NOTFOUND;

            -- Insere Item no Array
            viIdxNew                                           := NVL(vtIncluiItens.COUNT,0) + 1;
            vtIncluiItens(viIdxNew).vnCodProd                  := vrDadosCrossDock.vnCodProd;
            vtIncluiItens(viIdxNew).vvNumLote                  := vrDadosCrossDock.vvNumLote;
            vtIncluiItens(viIdxNew).vnQtde                     := NVL(vrDadosCrossDock.vnQt,0);
            vtIncluiItens(viIdxNew).vnPercDesc                 := 0;
            vtIncluiItens(viIdxNew).vnPerDescBoleto            := 0;
            vtIncluiItens(viIdxNew).vnCodDesconto              := NULL;
            vtIncluiItens(viIdxNew).vnCodPromocaoMed           := NULL;
            vtIncluiItens(viIdxNew).vnInicioIntervaloDescQuant := NULL;
            vtIncluiItens(viIdxNew).vnPerComInt                := 0;
            vtIncluiItens(viIdxNew).vnPerComExt                := 0;
            vtIncluiItens(viIdxNew).vnPerComRep                := 0; -->> SERÁ CALCULADO MAIS ABAIXO
            vtIncluiItens(viIdxNew).vvParticipaGiro            := 'S';
            vtIncluiItens(viIdxNew).vnPrecoFixo                := NULL;
            vtIncluiItens(viIdxNew).vvLoteContrato             := NULL;
            vtIncluiItens(viIdxNew).vnNumSeqItemContrato       := NULL;
            vtIncluiItens(viIdxNew).vvBonific                  := 'N';
            vtIncluiItens(viIdxNew).vnPBonific                 := NULL;
            vtIncluiItens(viIdxNew).vnCodSt                    := NULL;
            vtIncluiItens(viIdxNew).vnFatorGramaturaLicit      := NULL;
            vtIncluiItens(viIdxNew).vvNumLotePromocaoMed       := NULL;
            vtIncluiItens(viIdxNew).vvCodigoIntegracaoWms      := vrDadosCrossDock.vnCodigoDepositoWms;
           -- Troca de Nota deve obedecer o Preço Líquido original da Devolução de Cliente de Origem
            IF (NVL(pi_vTipoFv,'TL') = 'PA') THEN
              vtIncluiItens(viIdxNew).vnPrecoFixo := vrDadosCrossDock.vnPrecoLiqDevCli;
              -- Trata o Pedido como utilizando Promoção de Preço Fixo pra usar o Preço do momento da gravação do Orçamento
              vvTipoPoliticaPedido                := 'P';
            END IF;


          END LOOP; -- Fim Processamento Cursor

          -- Fecha Cursor
          CLOSE vRefCursor;

        ----------------------
        -- ITENS DE IMPORTAÇÃO
        ----------------------
        ELSIF (pi_nTipoChamada = 17) THEN

          -- Monta SQL
          vsSQL := ' SELECT I.CODPROD, I.NUMLOTE, I.QT, I.CODIGOINTEGRACAOWMS FROM PCMED_TEMP_IMPORT_ITENS_PED I';

          -- Processa Cursor
          OPEN vRefCursor FOR vsSQL;
          LOOP

            -- Leitura do Registro do Cursor
            FETCH vRefCursor INTO vrDadosImportacao;
            EXIT WHEN vRefCursor%NOTFOUND;

            -- Insere Item no Array
            viIdxNew                                           := NVL(vtIncluiItens.COUNT,0) + 1;
            vtIncluiItens(viIdxNew).vnCodProd                  := vrDadosImportacao.vnCodProd;
            vtIncluiItens(viIdxNew).vvNumLote                  := vrDadosImportacao.vvNumLote;
            vtIncluiItens(viIdxNew).vnQtde                     := NVL(vrDadosImportacao.vnQt,0);
            vtIncluiItens(viIdxNew).vnPercDesc                 := 0;
            vtIncluiItens(viIdxNew).vnPerDescBoleto            := 0;
            vtIncluiItens(viIdxNew).vnCodDesconto              := NULL;
            vtIncluiItens(viIdxNew).vnCodPromocaoMed           := NULL;
            vtIncluiItens(viIdxNew).vnPerComInt                := 0;
            vtIncluiItens(viIdxNew).vnPerComExt                := 0;
            vtIncluiItens(viIdxNew).vnPerComRep                := 0;
            vtIncluiItens(viIdxNew).vvParticipaGiro            := 'N';
            vtIncluiItens(viIdxNew).vnPrecoFixo                := 0;
            vtIncluiItens(viIdxNew).vvLoteContrato             := NULL;
            vtIncluiItens(viIdxNew).vnNumSeqItemContrato       := NULL;
            vtIncluiItens(viIdxNew).vvBonific                  := 'N';
            vtIncluiItens(viIdxNew).vnPBonific                 := NULL;
            vtIncluiItens(viIdxNew).vnCodSt                    := NULL;
            vtIncluiItens(viIdxNew).vnFatorGramaturaLicit      := NULL;
            vtIncluiItens(viIdxNew).vvNumLotePromocaoMed       := NULL;
            vtIncluiItens(viIdxNew).vvCodigoIntegracaoWms      := vrDadosImportacao.vvCodigoIntegracaoWms;

          END LOOP; -- Fim Processamento Cursor

          -- Fecha Cursor
          CLOSE vRefCursor;

        END IF; -- Fim Condição Tipo de Chamada

      END IF; -- Fim Condição Se a Promoção do Cabeçalho do Pedido for KIT OU Geração de Pedido de Licitação OU Alteração da Promoção do Pedido

      ----------------------------------------------------------
      -- SE APLICAR BONIFICAÇÃO EM MERCADORIA DE PROMOÇÃO EM TV1
      ----------------------------------------------------------
      IF     (pi_nTipoChamada = 6) THEN
        -- Excluir Registros do Pedido de Promoções de Bonificação para incluir novamente (no caso de erro na gravação do pedido)
        PEXCLUI_ITENSBONIFIC(pi_nNumPed);
      ELSIF (pi_nTipoChamada = 15) THEN
        -- Excluir Registros do Pedido de Promoções de Campanha para incluir novamente (no caso de erro na gravação do pedido)
        PEXCLUI_ITENSCAMPANHA(pi_nNumPed);
      END IF;

     /***********************************
      Se tem Itens para Incluir no Pedido
      ***********************************/
      IF (vtIncluiItens.COUNT > 0) THEN

        ------------------------------------------------------
        -- Laço para fazer uma Pré-Validação de todos os Itens
        ------------------------------------------------------
        FOR viLacoValidar IN 1..2 LOOP

          -- Log do Item
          IF (pi_nTipoChamada IN (2,10,11,15
                                 ,16 -- ITENS CROSS DOCKING [16] - MED-1096
                                 ,17
                                 )) THEN
            P_INSERE_LOG(viLacoValidar, '*** INICIO PROCESSAMENTO DOS ITENS ***');
            P_INSERE_LOG(viLacoValidar, '*** pi_nTipoChamada: ' || NVL(pi_nTipoChamada,0));
          END IF;


          -- Inicializa a Quantidade de Produtos Inseridos
          viQtdeProdutosInseridos := 0;

          -- Log do Item
          vvLogProcItem           := NULL;

          ----------------------------------
          -- Laço de Processamento dos Itens
          ----------------------------------
          FOR viNumSeq IN vtIncluiItens.FIRST..vtIncluiItens.LAST LOOP

            -- Log do Item
            IF (pi_nTipoChamada IN (2,10,11,15
                                   ,16 -- ITENS CROSS DOCKING [16] - MED-1096
                                   ,17
                                   )) THEN
              P_INSERE_LOG(viLacoValidar, '>> Produto: ' || NVL(vtIncluiItens(viNumSeq).vnCodProd,0));
              P_INSERE_LOG(viLacoValidar, 'Promoção: ' || NVL(vtIncluiItens(viNumSeq).vnCodPromocaoMed,0));
              P_INSERE_LOG(viLacoValidar, 'Cód. Desconto: ' || NVL(vtIncluiItens(viNumSeq).vnCodDesconto,0));
              P_INSERE_LOG(viLacoValidar, '% Desconto: ' || NVL(vtIncluiItens(viNumSeq).vnPercDesc,0));
              P_INSERE_LOG(viLacoValidar, 'Cód. Desconto: ' || NVL(vtIncluiItens(viNumSeq).vnCodDesconto,0));
              -- DDMEDICA-5009
              P_INSERE_LOG(viLacoValidar, 'VlDescCmvPromocaoMed: ' || vtIncluiItens(viIdxNew).vnVlDescCmvPromocaoMed);
              P_INSERE_LOG(viLacoValidar, 'NumVerbaCampanha: '     || vtIncluiItens(viIdxNew).vnNumVerbaCampanha);
              P_INSERE_LOG(viLacoValidar, 'ValorCotaNumVerba: '    || vtIncluiItens(viIdxNew).vnValorCotaNumVerba);
              P_INSERE_LOG(viLacoValidar, 'SemVerbaVlDescCmv: '    || vtIncluiItens(viIdxNew).vvSemVerbaVlDescCmv);
            END IF;

            -- Inicializa Variável de Controle de Processamento do Produto
            vbPodeProcessarProduto := TRUE;

            -- Inicializa Record
            vrItemPedido := vrLimpaItemPedido;

            -- Dados da Promoção
            vrItemPedido.nCODPROD                  := vtIncluiItens(viNumSeq).vnCodProd;
            vrItemPedido.nQT                       := vtIncluiItens(viNumSeq).vnQtde;
            vrItemPedido.nPERDESC                  := vtIncluiItens(viNumSeq).vnPercDesc;
            vrItemPedido.nPERDESCBOLETO            := vtIncluiItens(viNumSeq).vnPerDescBoleto;
            vrItemPedido.nCODDESCONTO              := vtIncluiItens(viNumSeq).vnCodDesconto;
            vrItemPedido.nCODPROMOCAOMED           := vtIncluiItens(viNumSeq).vnCodPromocaoMed;
            vrItemPedido.nINICIOINTERVALODESCQUANT := vtIncluiItens(viNumSeq).vnInicioIntervaloDescQuant;
            vrItemPedido.vPARTICIPAGIRO            := vtIncluiItens(viNumSeq).vvParticipaGiro;
            -- Histórico da Promoção Anterior para Log - DDMEDICA-4799
            vrItemPedido.nCODPROMOCAOMED_OLD       := vtIncluiItens(viNumSeq).vnCodPromocaoMed;
            vrItemPedido.vOBSCODPROMOCAOMED_OLD    := NULL;

            -- Dados da Licitação
            vrItemPedido.vLOTECONTRATO             := vtIncluiItens(viNumSeq).vvLoteContrato;
            vrItemPedido.nNUMSEQITEMCONTRATO       := vtIncluiItens(viNumSeq).vnNumSeqItemContrato;
            -- Número da Sequência do Item (Somente usado na alteração da Promoção do Pedido
            vrItemPedido.nNUMSEQ                   := vtIncluiItens(viNumSeq).vnNumSeq;
            -- Tributação do Item (se item incluído pela 2316)
            vrItemPedido.nCODST                    := vtIncluiItens(viNumSeq).vnCodSt;
            -- Filial Retira
            vrItemPedido.nCODFILIALRETIRA          := vtIncluiItens(viNumSeq).vvCodFilialRetira;

            -------------------------------------------------------------------
            -- SE APLICAR BONIFICAÇÃO EM MERCADORIA DE PROMOÇÃO EM TV1
            -- SE BONIFICAÇÃO EM MERCADORIA DE PROMOÇÃO EM TV1 PARA TABELA TEMP
            -------------------------------------------------------------------
            --IF (pi_nTipoChamada IN (6,8)) THEN
            --  vrItemPedido.vBONIFIC  := vtIncluiItens(viNumSeq).vvBonific;
            --  vrItemPedido.nPBONIFIC := vtIncluiItens(viNumSeq).vnPBonific;
            --ELSE
            --  vrItemPedido.vBONIFIC  := 'N';
            --  vrItemPedido.nPBONIFIC := NULL;
            --END IF;
            -- ALTERADO PRA RECEBER OS VALORES DO ARRAY SEMPRE, NA ORIGEM DO ARRAY É QUE SERÃO DEFINIDOS OS VALORES
            -- (necessário devido à implementação do recálculo do pedido ao alterar o plano de pagamento)
            -- HIS.01889.2017 - Na Bonificação de Campanha irei o PBONIFIC na atualização do PTABELA
            vrItemPedido.vBONIFIC                := vtIncluiItens(viNumSeq).vvBonific;
            vrItemPedido.nPBONIFIC               := vtIncluiItens(viNumSeq).vnPBonific;

            -- Regra Específica - Desconto da Base do RCA da Importação do Pedido do Força de Vendas
            vrItemPedido.nPERCDESCBASERCA        := vtIncluiItens(viNumSeq).vnPercDescBaseRca;
            vrItemPedido.vTIPOCOMISSAOMED        := vtIncluiItens(viNumSeq).vvTipoComissaoMed;

            -- Valores para a Redução do Simples Nacional do CMV
            vrItemPedido.nVALORDESCSIMPLESNAC    := 0; -- Campo Temporário, não gravará na PCPEDI
            vrItemPedido.nVLREDPVENDASIMPLESNA   := vtIncluiItens(viNumSeq).vnVlRedPVendaSimplesNa;
            vrItemPedido.nVLREDCMVSIMPLESNAC     := vtIncluiItens(viNumSeq).vnVrRedCmvSimplesNac;

            -- Informações da Linha de Prazo
            vrItemPedido.nCODPLPAG               := vtIncluiItens(viNumSeq).vnCodPlPag;
            vrItemPedido.nCODLINHAPRAZO          := vtIncluiItens(viNumSeq).vnCodLinhaPrazo;

            -- Informações de Produto Bloqueado para a Campanha -- HIS.01889.2017
            vrItemPedido.vBLOQUEIOCAMPANHA       := 'N';
            vrItemPedido.vMOTIVOBLOQUEIOCAMPANHA := NULL;

            -- Fator da Gramatura da Licitação
            vrItemPedido.nFATORGRAMATURALICIT    := vtIncluiItens(viNumSeq).vnFatorGramaturaLicit;

            -- CrossDocking
            vrItemPedido.vNUMLOTE                := vtIncluiItens(viNumSeq).vvNumLote;
            vrItemPedido.vCODIGOINTEGRACAOWMS    := vtIncluiItens(viNumSeq).vvCodigoIntegracaoWms;

            -- Promoção por Lote
            vrItemPedido.vNUMLOTEPROMOCAOMED     := vtIncluiItens(viNumSeq).vvCodigoIntegracaoWms;

            -- DDMEDICA-5009 - Verba de Fornecedor da Promoção para Rebaixa de CMV
            vrItemPedido.nVLDESCCMVPROMOCAOMED   := vtIncluiItens(viNumSeq).vnVlDescCmvPromocaoMed;
            vrItemPedido.nNUMVERBACAMPANHA       := vtIncluiItens(viNumSeq).vnNumVerbaCampanha;
            vrItemPedido.nVLVERBACMV             := vtIncluiItens(viNumSeq).vnVlVerbaCmv;
            vrItemPedido.nPERCCUSTFORNEC         := vtIncluiItens(viNumSeq).vnPercCustFornec;
			vrItemPedido.nNUMVERBAREBCMV         := vtIncluiItens(viNumSeq).vnNumverbarebcmv;

            -- EAN do Produto - DDMEDICA-7318
            vrItemPedido.nCODAUXILIAR            := vtIncluiItens(viNumSeq).vnCodAuxiliar;

            -- ST CLIENTE GNRE - DDMEDICA-7697
            vrItemPedido.nSTCLIENTEGNRE          := vtIncluiItens(viNumSeq).vnStClienteGnre;
 
            -- ST PROPRIO - DDMEDICA-7697
            vrItemPedido.nBASEICST               := NVL(vtIncluiItens(viNumSeq).vnBaseIcst,0); -- DDVENDAS-33442
            vrItemPedido.nST                     := NVL(vtIncluiItens(viNumSeq).vnSt,0);       -- DDVENDAS-33442
            
            -- Novo Processo de Licitação - DDVENDAS-33442
            vrItemPedido.nCODEDITAL                := vtIncluiItens(viNumSeq).vnCodEdital;
            vrItemPedido.nQTPEDLICIT               := vtIncluiItens(viNumSeq).vnQtPedLicit;
            vrItemPedido.nTIPOCONVERSAOPEDLICIT    := vtIncluiItens(viNumSeq).vnTipoConversaoPedLicit;
            vrItemPedido.vUNIDADECONVERSAOPEDLICIT := vtIncluiItens(viNumSeq).vvUnidadeConversaoPedLicit;
            vrItemPedido.nFATORCONVERSAOPEDLICIT   := vtIncluiItens(viNumSeq).vnFatorConversaoPedLicit;
            vrItemPedido.vPRODDESCRICAODANFE       := vtIncluiItens(viNumSeq).vvDescricaoProdutoDanfe;
            vrItemPedido.vPRODDESCRICAOCONTRATO    := vtIncluiItens(viNumSeq).vvDescricaoProdutoDanfe;
            vrItemPedido.nNUMITEMPED               := vtIncluiItens(viNumSeq).vnNUMITEMPED;
            vrItemPedido.nQTCOMBOVIRTUAL           := vtIncluiItens(viNumSeq).nQTCOMBOVIRTUAL;
            
            if vvTipoPromocaoPedido = 'K' THEN
              vrItemPedido.nQTCOMBOVIRTUAL := PI_NQTCOMBOS;
            END IF;
            
            IF (pi_nTipoChamada IN (3,18)) THEN
              -- Log do Item
              P_INSERE_LOG(viLacoValidar, 'pi_nCodEdital: ' || pi_nCodEdital);
              P_INSERE_LOG(viLacoValidar, 'vUTILIZANOVOPROCESSOLICITACAO: ' || vrParamFilial.vUTILIZANOVOPROCESSOLICITACAO);
              P_INSERE_LOG(viLacoValidar, 'vMEDTIPOARREDQTPEDLICIT: ' || vrParamFilial.vMEDTIPOARREDQTPEDLICIT);
              P_INSERE_LOG(viLacoValidar, 'vvAplicarFatorLicitacao: ' || vvAplicarFatorLicitacao);
              P_INSERE_LOG(viLacoValidar, 'nCODEDITAL: ' || vrItemPedido.nCODEDITAL);
              P_INSERE_LOG(viLacoValidar, 'nQTPEDLICIT: ' || vrItemPedido.nQTPEDLICIT);
              P_INSERE_LOG(viLacoValidar, 'nTIPOCONVERSAOPEDLICIT: ' || vrItemPedido.nTIPOCONVERSAOPEDLICIT);
              P_INSERE_LOG(viLacoValidar, 'vUNIDADECONVERSAOPEDLICIT: ' || vrItemPedido.vUNIDADECONVERSAOPEDLICIT);
              P_INSERE_LOG(viLacoValidar, 'nFATORCONVERSAOPEDLICIT: ' || vrItemPedido.nFATORCONVERSAOPEDLICIT);
              P_INSERE_LOG(viLacoValidar, 'vPRODDESCRICAOCONTRATO: ' || vrItemPedido.vPRODDESCRICAOCONTRATO);
            END IF;                 

            -- Pesquisa Dados do Produto
            BEGIN
              SELECT PCPRODUT.PERCIPIVENDA
                   , PCPRODUT.PCOMINT1
                   , PCPRODUT.PCOMEXT1
                   , PCPRODUT.PCOMREP1
                   , PCPRODUT.CODLINHAPROD
                   , PCPRODUT.PESOBRUTO
                   , PCPRODUT.VOLUME
                   , PCPRODUT.TIPOCUSTOTRANSF
                   , PCPRODUT.GRUPOFATURAMENTO
                   , PCPRODUT.PERCBONIFICVENDA
                   --, PCPRODUT.CUSTOREP
                   --, PCPRODUT.CUSTOREPZFM
                   , PCPRODUT.TIPOMERC
                   , PCPRODUT.FRETEESPECIAL
                   , PCPRODUT.DESCRICAO
                   , PCPRODUT.UTILIZAPRECOFABRICA
                   , PCPRODUT.CODLINHAPRAZO
                   , PCPRODUT.VLPAUTAIPIVENDA
                   , PCPRODUT.CODSEC  -- MED-2453
                   , PCPRODUT.CODEPTO -- MED-2453
                   , PCPRODUT.PERCSUFRAMA -- DDMEDICA-1172
                INTO vrProduto_O.nPERCIPIVENDA
                   , vrProduto_O.nPCOMINT1
                   , vrProduto_O.nPCOMEXT1
                   , vrProduto_O.nPCOMREP1
                   , vrProduto_O.nCODLINHAPROD
                   , vrProduto_O.nPESOBRUTO
                   , vrProduto_O.nVOLUME
                   , vrProduto_O.vTIPOCUSTOTRANSF
                   , vrProduto_O.vGRUPOFATURAMENTO
                   , vrProduto_O.nPERCBONIFICVENDA
                   --, vrProduto_O.nCUSTOREP
                   --, vrProduto_O.nCUSTOREPZFM
                   , vrProduto_O.vTIPOMERC
                   , vrProduto_O.nFRETEESPECIAL
                   , vrProduto_O.vDESCRICAO
                   , vrProduto_O.vUTILIZAPRECOFABRICA
                   , vrProduto_O.nCODLINHAPRAZO
                   , vrProduto_O.nVLPAUTAIPIVENDA
                   , vrProduto_O.nCODSEC  -- MED-2453
                   , vrProduto_O.nCODEPTO -- MED-2453
                   , vrProduto_O.nPERCSUFRAMA -- DDMEDICA-1172
                FROM PCPRODUT
               WHERE (PCPRODUT.CODPROD = vrItemPedido.nCODPROD);
            EXCEPTION
              WHEN NO_DATA_FOUND THEN
                -- Informações de Produto Bloqueado para a Campanha -- HIS.01889.2017
                IF (pi_nTipoChamada = 13) THEN
                  vrItemPedido.vBLOQUEIOCAMPANHA       := 'S';
                  vrItemPedido.vMOTIVOBLOQUEIOCAMPANHA := 'Produto ' || NVL(vrItemPedido.nCODPROD,0) || ' não encontrado!';
                ELSE
                  -- Rejeita
                  po_vMotivoNaoPodeGravar := 'Produto ' || NVL(vrItemPedido.nCODPROD,0) || ' não encontrado!';
                  RAISE e_Tratado;
                END IF;
            END;

            -- Pesquisa Dados da PCEST para o Produto NA FILIAL DE ORIGEM
            IF (NVL(vrParamFilial.vORIGEMCUSTOFILIALRETIRA,'X') = 'V') THEN
              BEGIN
                SELECT PCEST.CUSTOREP
                     , PCEST.CUSTOREAL
                     , PCEST.CUSTOCONT
                     , CASE WHEN (NVL(vrParamFilial.vPRECIFICREGIAOFORAUFSEMST,'N') = 'S') AND (NVL(vrClienteDestino.vESTENT,' ') <> NVL(vrFilial.vUF,' ')) THEN
                         PCEST.CUSTOFINSEMST
                       ELSE  
                         PCEST.CUSTOFIN
                       END CUSTOFIN
                     , PCEST.CUSTOULTENT
                     , PCEST.VALORULTENT
                     , PCEST.CUSTOREALSEMST
                     , PCEST.VLULTENTCONTSEMST
                     , PCEST.CUSTOFORNEC
                     , PCEST.CUSTONFSEMST
                     , PCEST.STBCR
                  INTO vrCustoProduto_O.nCUSTOREP
                     , vrCustoProduto_O.nCUSTOREAL
                     , vrCustoProduto_O.nCUSTOCONT
                     , vrCustoProduto_O.nCUSTOFIN
                     , vrCustoProduto_O.nCUSTOULTENT
                     , vrCustoProduto_O.nVALORULTENT
                     , vrCustoProduto_O.nCUSTOREALSEMST
                     , vrCustoProduto_O.nVLULTENTCONTSEMST
                     , vrCustoProduto_O.nCUSTOFORNEC
                     , vrCustoProduto_O.nCUSTONFSEMST
                     , vrCustoProduto_O.nSTBCR
                  FROM PCEST
                 WHERE (PCEST.CODPROD   = vrItemPedido.nCODPROD)
                   AND (PCEST.CODFILIAL = pi_vCodFilial);
              EXCEPTION
                WHEN NO_DATA_FOUND THEN
                  -- Informações de Produto Bloqueado para a Campanha -- HIS.01889.2017
                  IF (pi_nTipoChamada = 13) THEN
                    vrItemPedido.vBLOQUEIOCAMPANHA       := 'S';
                    vrItemPedido.vMOTIVOBLOQUEIOCAMPANHA := 'Produto ' || NVL(vrItemPedido.nCODPROD,0) || ' sem informação de Custo na Filial ' || NVL(pi_vCodFilial,' ') || '!';
                  ELSE
                    -- Rejeita
                    po_vMotivoNaoPodeGravar := 'Produto ' || NVL(vrItemPedido.nCODPROD,0) || ' sem informação de Custo na Filial ' || NVL(pi_vCodFilial,' ') || '!';
                    RAISE e_Tratado;
                  END IF;
              END;
            ELSE
              BEGIN
                SELECT PCEST.CUSTOREP
                     , PCEST.CUSTOREAL
                     , PCEST.CUSTOCONT
                     , CASE WHEN (NVL(vrParamFilial.vPRECIFICREGIAOFORAUFSEMST,'N') = 'S') AND (NVL(vrClienteDestino.vESTENT,' ') <> NVL(vrFilial.vUF,' ')) THEN
                         PCEST.CUSTOFINSEMST
                       ELSE  
                         PCEST.CUSTOFIN
                       END CUSTOFIN
                     , PCEST.CUSTOULTENT
                     , PCEST.VALORULTENT
                     , PCEST.CUSTOREALSEMST
                     , PCEST.VLULTENTCONTSEMST
                     , PCEST.CUSTOFORNEC
                     , PCEST.CUSTONFSEMST
                  INTO vrCustoProduto_O.nCUSTOREP
                     , vrCustoProduto_O.nCUSTOREAL
                     , vrCustoProduto_O.nCUSTOCONT
                     , vrCustoProduto_O.nCUSTOFIN
                     , vrCustoProduto_O.nCUSTOULTENT
                     , vrCustoProduto_O.nVALORULTENT
                     , vrCustoProduto_O.nCUSTOREALSEMST
                     , vrCustoProduto_O.nVLULTENTCONTSEMST
                     , vrCustoProduto_O.nCUSTOFORNEC
                     , vrCustoProduto_O.nCUSTONFSEMST
                  FROM PCEST
                 WHERE (PCEST.CODPROD   = vrItemPedido.nCODPROD)
                   AND (PCEST.CODFILIAL = NVL(vrItemPedido.nCODFILIALRETIRA,NVL(vvCodFilialRetira,pi_vCodFilial)));
              EXCEPTION
                WHEN NO_DATA_FOUND THEN
                  -- Informações de Produto Bloqueado para a Campanha -- HIS.01889.2017
                  IF (pi_nTipoChamada = 13) THEN
                    vrItemPedido.vBLOQUEIOCAMPANHA       := 'S';
                    vrItemPedido.vMOTIVOBLOQUEIOCAMPANHA := 'Produto ' || NVL(vrItemPedido.nCODPROD,0) || ' sem informação de Custo na Filial Retira ' || NVL(NVL(vrItemPedido.nCODFILIALRETIRA,NVL(vvCodFilialRetira,pi_vCodFilial)),' ') || '!';
                  ELSE
                    -- Rejeita
                    po_vMotivoNaoPodeGravar := 'Produto ' || NVL(vrItemPedido.nCODPROD,0) || ' sem informação de Custo na Filial Retira ' || NVL(NVL(vrItemPedido.nCODFILIALRETIRA,NVL(vvCodFilialRetira,pi_vCodFilial)),' ') || '!';
                    RAISE e_Tratado;
                  END IF;
              END;
              BEGIN
                SELECT PCEST.STBCR
                  INTO vrCustoProduto_O.nSTBCR
                  FROM PCEST
                 WHERE (PCEST.CODPROD   = vrItemPedido.nCODPROD)
                   AND (PCEST.CODFILIAL = pi_vCodFilial);
              EXCEPTION
                WHEN NO_DATA_FOUND THEN
                  -- Informações de Produto Bloqueado para a Campanha -- HIS.01889.2017
                  IF (pi_nTipoChamada = 13) THEN
                    vrItemPedido.vBLOQUEIOCAMPANHA       := 'S';
                    vrItemPedido.vMOTIVOBLOQUEIOCAMPANHA := 'Produto ' || NVL(vrItemPedido.nCODPROD,0) || ' sem informação de Custo na Filial ' || NVL(pi_vCodFilial,' ') || '!';
                  ELSE
                    -- Rejeita
                    po_vMotivoNaoPodeGravar := 'Produto ' || NVL(vrItemPedido.nCODPROD,0) || ' sem informação de Custo na Filial ' || NVL(pi_vCodFilial,' ') || '!';
                    RAISE e_Tratado;
                  END IF;
              END;
            END IF;

            -------------------------------------------------
            -- MED-1096 - Se Pedido de Venda de Cross Docking
            -------------------------------------------------
            IF (pi_nNumTransEntCrossDock > 0) AND
               (pi_nCondVenda <> 10)          THEN

              -- Pesquisa Custo Financeiro da Nota de Entrada
              BEGIN
                SELECT PCMOVCOMPLE.CUSTOULTENTCONT
                  INTO vrCustoProduto_O.nCUSTOFIN
                  FROM PCMOV, PCMOVCOMPLE
                 WHERE (PCMOVCOMPLE.NUMTRANSITEM = PCMOV.NUMTRANSITEM)
                   AND (PCMOV.NUMTRANSENT        = pi_nNumTransEntCrossDock)
                   AND (PCMOV.CODPROD            = vrItemPedido.nCODPROD)
                   AND (ROWNUM                   = 1);
              EXCEPTION
                WHEN NO_DATA_FOUND THEN
                  -- Se não encontrar, mantém o Custo da PCEST
                  NULL;
              END;

            END IF; -- Fim: MED-1096 - Se Pedido de Venda de Cross Docking

            ----------------------------------
            -- DEFINIÇÃO DO PLANO DE PAGAMENTO
            ----------------------------------

            -- Inicializa o Plano de Pagamento com código recebido como parâmetro
            vnCodPlPagProduto := pi_nCodPlPag;

            -- Se o Cliente Utiliza Plano Ético e Genérico, verifica dados dos Planos Ético e Genérico
            IF (NVL(vrClienteDestino.vUTILIZAPLPAGMEDICAMENTO,'N') = 'S') AND
               (NVL(vrDadosPedidoAtual.nCODPLPAGETICO,0) > 0)             AND
               (NVL(vrDadosPedidoAtual.nCODPLPAGGENERICO,0) > 0)          THEN
              IF (NVL(vrProduto_O.vGRUPOFATURAMENTO,' ') = 'E') THEN
                vnCodPlPagProduto := vrDadosPedidoAtual.nCODPLPAGETICO;
              ELSE
                vnCodPlPagProduto := vrDadosPedidoAtual.nCODPLPAGGENERICO;
              END IF;
            END IF;

            -- Se Chamado do Orçamento usando Linhas de Prazo,
            -- pega Plano de Pagamento gravado no Item do Orçamento
            IF    (pi_nTipoChamada = 11) AND
                  (vrParamFilial.vTIPOPRAZOMEDICAMEN = '4') THEN
              vnCodPlPagProduto := vtIncluiItens(viNumSeq).vnCodPlPag;
            -- 4415.145077.2018 - Alteração do Plano de Pagamento com Linhas de Prazo,
            -- pega Plano de Pagamento gravado no Item do Pedido
            ELSIF (pi_nTipoChamada = 10) AND
                  (vrParamFilial.vTIPOPRAZOMEDICAMEN = '4') THEN
              vnCodPlPagProduto := vtIncluiItens(viNumSeq).vnCodPlPag;
            END IF;

            -- Pesquisa dados do Plano de Pagamento
            BEGIN
              SELECT 'S'
                   , PCPLPAG.TIPOVENDA
                   , PCPLPAG.NUMDIAS
                   , PCPLPAG.PRAZO1
                   , PCPLPAG.PRAZO2
                   , PCPLPAG.PRAZO3
                   , PCPLPAG.PRAZO4
                   , PCPLPAG.PRAZO5
                   , PCPLPAG.PRAZO6
                   , PCPLPAG.PRAZO7
                   , PCPLPAG.PRAZO8
                   , PCPLPAG.PRAZO9
                   , PCPLPAG.PRAZO10
                   , PCPLPAG.PRAZO11
                   , PCPLPAG.PRAZO12
                   , PCPLPAG.NUMPR
                   , PCPLPAG.PERTXFIM
                INTO vrPlanoPag.vcAchouPlPag
                   , vrPlanoPag.vTIPOVENDA
                   , vrPlanoPag.nNUMDIAS
                   , vrPlanoPag.nPRAZO1
                   , vrPlanoPag.nPRAZO2
                   , vrPlanoPag.nPRAZO3
                   , vrPlanoPag.nPRAZO4
                   , vrPlanoPag.nPRAZO5
                   , vrPlanoPag.nPRAZO6
                   , vrPlanoPag.nPRAZO7
                   , vrPlanoPag.nPRAZO8
                   , vrPlanoPag.nPRAZO9
                   , vrPlanoPag.nPRAZO10
                   , vrPlanoPag.nPRAZO11
                   , vrPlanoPag.nPRAZO12
                   , vrPlanoPag.nNUMPR
                   , vrPlanoPag.nPERTXFIM
                FROM PCPLPAG
               WHERE (PCPLPAG.CODPLPAG = vnCodPlPagProduto); -->> PLANO DE PAGAMENTO DO PRODUTO
            EXCEPTION
              WHEN NO_DATA_FOUND THEN
                -- Informações de Produto Bloqueado para a Campanha -- HIS.01889.2017
                IF (pi_nTipoChamada = 13) THEN
                  vrItemPedido.vBLOQUEIOCAMPANHA       := 'S';
                  vrItemPedido.vMOTIVOBLOQUEIOCAMPANHA := 'Dados do Plano de Pagamento ' || NVL(vnCodPlPagProduto,0) || ' não encontrados!';
                ELSE
                  -- Rejeita
                  po_vMotivoNaoPodeGravar := 'Dados do Plano de Pagamento ' || NVL(vnCodPlPagProduto,0) || ' não encontrados!';
                  RAISE e_Tratado;
                END IF;
            END;

            -- Se a Empresa Trabalha com Regra do Desconto Adicional Plano A Vista,
            -- o Sistema Ignorará o Desconto do Plano de Pagamento para evitar Duplicidade
            IF (NVL(vrParamFilial.vMEDUSADESCADICPLPAGVISTA,'N') = 'S') AND
               (NVL(vrParamFilial.nMEDPERDESCADICPLPAGVISTA,0) <> 0)    THEN
              vrPlanoPag.nPERTXFIM := 0;
            END IF;

            -- GUARDA O PRAZO MÉDIO DO ITEM DO PEDIDO - HIS.01240.2016
            vrItemPedido.nPRAZOMEDIO := NVL(vrPlanoPag.nNUMDIAS,0);

            -- PLANO DE PAGAMENTO DO ITEM - HIS.01240.2016
            IF (pi_nTipoChamada IN (10,11,12,13,14,15
                                   ,16 -- ITENS CROSS DOCKING [16] - MED-1096
                                   ,17
                                   )) THEN
              vrItemPedido.nCODPLPAG := vnCodPlPagProduto;
            END IF;

            ------------------------------------------
            -- DEFINIÇÃO DA COMISSÃO DO ITEM DO PEDIDO
            ------------------------------------------

            -- RCA DA LINHA - DDMEDICA-2028
            vnCodUsurLinha := NULL;
            IF (vrRegraMed.vAPURARCOMISSAOPELORCALINHA = 'S') THEN
              vnCodUsurLinha := F_OBTER_RCA_LINHAPROD(pi_nCodCli,
                                                      vrItemPedido.nCODPROD,
                                                      pi_vCodFilial,
                                                      vrParamFilial.vUSARCACLIENTELINHAPORFILIALME);
            END IF;

            -- Comissão do Item do Pedido
            IF (pi_nTipoChamada IN (4,5,6,8,10,11)) THEN
              -- Quando for Alteração da Promoção do Pedido, deve iniciar com a Comissão gravada no Item do Pedido
              vrItemPedido.nPERCOM := vtIncluiItens(viNumSeq).vnPerCom;
            -- Comissão do Combo --------------------------------------------------------------------
            ELSIF (pi_nTipoChamada IN (2)) THEN
              -- Verifica se Prioriza a Comissão da Promoção
              BEGIN
                SELECT PCPROMOCAOMED.PRIORIZACOMISSAO
                  INTO vvPriorizaComissao
                  FROM PCPROMOCAOMED
                 WHERE (CODPROMOCAOMED = vrItemPedido.nCODPROMOCAOMED);
              EXCEPTION
                WHEN NO_DATA_FOUND THEN
                  vvPriorizaComissao := 'N';
              END;
              -- Se Prioriza a Comissão da Promoção COMBO
              IF (NVL(vvPriorizaComissao,'N') = 'S') THEN
                IF    (NVL(vrRca.vTIPOVEND,' ') = 'I') THEN
                  vrItemPedido.nPERCOM  := vtIncluiItens(viNumSeq).vnPerComInt;
                ELSIF (NVL(vrRca.vTIPOVEND,' ') = 'E') THEN
                  vrItemPedido.nPERCOM  := vtIncluiItens(viNumSeq).vnPerComExt;
                ELSIF (NVL(vrRca.vTIPOVEND,' ') = 'R') THEN
                  vrItemPedido.nPERCOM  := vtIncluiItens(viNumSeq).vnPerComRep;
                ELSE
                  vrItemPedido.nPERCOM  := 0;
                END IF;

                -- Log da Comissão
                vrItemPedido.vTIPOCOMISSAOMED := 'TDS';

                -- Log do Item
                P_INSERE_LOG(viLacoValidar, '% Comissão Combo Priorizado: ' || NVL(vrItemPedido.nPERCOM,0));

              -- NÃO Se Prioriza a Comissão da Promoção COMBO
              ELSE
                -- Chama Procedimento para Obter a Comissão
                PKG_MEDICAMENTOS.P_OBTER_COMISSAO(4, -->> Chamado da Valida Promoção
                                                  1, -->> Comissão do Representante
                                                  vrItemPedido.nCODPROMOCAOMED,
                                                  vrItemPedido.nCODPROD,
                                                  pi_nCodCli,
                                                  vdDataPedido,
                                                  pi_vCodFilial,
                                                  vrRegiao.nNUMREGIAO,
                                                  NVL(vnCodUsurLinha,pi_nCodUsur), -- RCA da Linha ou do Cliente
                                                  pi_nCodMatricula,
                                                  vrDadosPedidoAtual.vORIGEMPED,
                                                  vrDadosPedidoAtual.vTIPOFV,
                                                  vnCodPlPagProduto,
                                                  vrItemPedido.nQT,
                                                  vrItemPedido.nPERDESC,
                                                  vrItemPedido.nCODDESCONTO,
                                                  NULL, -->> Passar nulo pra buscar todas as comissões, não um tipo específico
                                                  vrItemPedido.nPERCOM,
                                                  vvOcorreramErrosComissao,
                                                  vvMsgErrosComissao);
                -- Rejeita
                IF (vvOcorreramErrosComissao = 'S') THEN
                  -- Informações de Produto Bloqueado para a Campanha -- HIS.01889.2017
                  IF (pi_nTipoChamada = 13) THEN
                    vrItemPedido.vBLOQUEIOCAMPANHA       := 'S';
                    vrItemPedido.vMOTIVOBLOQUEIOCAMPANHA := 'Produto ' || NVL(vrItemPedido.nCODPROD,0) || ' com erro na Comissão: ' || vvMsgErrosComissao;
                  ELSE
                    po_vMotivoNaoPodeGravar := 'Produto ' || NVL(vrItemPedido.nCODPROD,0) || ' com erro na Comissão: ' || vvMsgErrosComissao;
                    RAISE e_Tratado;
                  END IF;
                ELSE
                  -- Log da Comissão
                  vrItemPedido.vTIPOCOMISSAOMED := SUBSTR(vvMsgErrosComissao,1,3);

                  -- Log do Item
                  P_INSERE_LOG(viLacoValidar, 'Comissão Tipo: ' || vrItemPedido.vTIPOCOMISSAOMED);
                  P_INSERE_LOG(viLacoValidar, '% Comissão Combo: ' || NVL(vrItemPedido.nPERCOM,0));

                  -- HIS.01889.2017 - Comissão do Acordo de Parceria  - Se não aplicou a Comissão da PCDESCONTO
                  -- OBSERVAÇÃO: Como o cálculo da Comissão do Acordo de Parceria é mais abaixo, tive que deslocar esta Regra
                  --IF (SUBSTR(vvMsgErrosComissao,2,2) <> 'DS') THEN
                  --  IF ((NVL(pi_nCodPromocaoMedPedido,0) > 0) AND
                  --      (NVL(vrItemPedido.vPRIORIZACOMISSACORDOPARC,'N') = 'S')) THEN
                  --    vrItemPedido.nPERCOM := vrItemPedido.nPERCOMACORDOPARCERIA;
                  --    vrItemPedido.vTIPOCOMISSAOMED := 'TAP';
                  --  END IF;
                  --END IF;
                END IF;
              END IF; -- Fim Condição: Se Prioriza a Comissão da Promoção COMBO
            -- Comissão da Atualização do Brinde ----------------------------------------------------
            -- Comissão da Campanha - HIS.01889.2017 ------------------------------------------------
            ELSIF (pi_nTipoChamada IN (12,13,15)) THEN
              vrItemPedido.nPERCOM := 0; -->> Brinde é BNF, não tem Comissão
              vrItemPedido.vTIPOCOMISSAOMED := 'T';
            -- ITENS CROSS DOCKING [16] - MED-1096 --------------------------------------------------
            -- ITENS IMPORTAÇÃO [17] - DDMEDICA-2028 ------------------------------------------------
            ELSIF (pi_nTipoChamada IN (16,17)) THEN
              -- Chama Procedimento para Obter a Comissão
              PKG_MEDICAMENTOS.P_OBTER_COMISSAO(4, -->> Chamado da Valida Promoção
                                                1, -->> Comissão do Representante
                                                vrItemPedido.nCODPROMOCAOMED,
                                                vrItemPedido.nCODPROD,
                                                pi_nCodCli,
                                                vdDataPedido,
                                                pi_vCodFilial,
                                                vrRegiao.nNUMREGIAO,
                                                NVL(vnCodUsurLinha,pi_nCodUsur), -- RCA da Linha ou do Cliente
                                                pi_nCodMatricula,
                                                vrDadosPedidoAtual.vORIGEMPED,
                                                vrDadosPedidoAtual.vTIPOFV,
                                                vnCodPlPagProduto,
                                                vrItemPedido.nQT,
                                                vrItemPedido.nPERDESC,
                                                vrItemPedido.nCODDESCONTO,
                                                NULL, -->> Passar nulo pra buscar todas as comissões, não um tipo específico
                                                vrItemPedido.nPERCOM,
                                                vvOcorreramErrosComissao,
                                                vvMsgErrosComissao);
            -- Comissão das Demais Promoções --------------------------------------------------------
            ELSE
              IF    (NVL(vrRca.vTIPOVEND,' ') = 'I') THEN
                vrItemPedido.nPERCOM  := vtIncluiItens(viNumSeq).vnPerComInt;
              ELSIF (NVL(vrRca.vTIPOVEND,' ') = 'E') THEN
                vrItemPedido.nPERCOM  := vtIncluiItens(viNumSeq).vnPerComExt;
              ELSIF (NVL(vrRca.vTIPOVEND,' ') = 'R') THEN
                vrItemPedido.nPERCOM  := vtIncluiItens(viNumSeq).vnPerComRep;
              ELSE
                vrItemPedido.nPERCOM  := 0;
              END IF;
              vrItemPedido.vTIPOCOMISSAOMED := 'TDS';
            END IF;

            ----------------------------------
            -- ANULAR COMISSÃO - DDMEDICA-2028
            ---------------------------------
            IF (F_BLOQUEIA_COMISSAO(NVL(vnCodUsurLinha,pi_nCodUsur)) = 'S') THEN
              vrItemPedido.nPERCOM := 0;
            END IF;

            ------------------------
            -- TRIBUTACÃO DO PRODUTO
            ------------------------
            IF (NVL(vrItemPedido.nCODST,0) = 0) THEN

              -- Se utiliza Tributação por UF, pesquisa na Tabela de Tributação por UF o Código da Tributação
              IF (NVL(vrPcConsum.vUSATRIBUTACAOPORUF,'N') = 'S') THEN
                BEGIN
                  SELECT PCTABTRIB.CODST
                    INTO vnCodSt
                    FROM PCTABTRIB
                   WHERE (PCTABTRIB.CODPROD     = vrItemPedido.nCODPROD)
                     AND (PCTABTRIB.CODFILIALNF = NVL(pi_vCodFilialNf,pi_vCodFilial)) -->> Tributação na Filial NF ou de Origem
                     AND (PCTABTRIB.UFDESTINO   = vrClienteDestino.vESTENT);          -->> Para a UF do Cliente
                EXCEPTION
                  WHEN NO_DATA_FOUND THEN
                    -- Informações de Produto Bloqueado para a Campanha -- HIS.01889.2017
                    IF (pi_nTipoChamada = 13) THEN
                      vrItemPedido.vBLOQUEIOCAMPANHA       := 'S';
                      vrItemPedido.vMOTIVOBLOQUEIOCAMPANHA := 'Não foi encontrada a tributação do Produto '      || NVL(vrItemPedido.nCODPROD,0) ||
                                                              ' na filial de origem ' || NVL(pi_vCodFilial,' ')  ||
                                                              ' para a UF ' || NVL(vrClienteDestino.vESTENT,' ') || '!';
                    ELSE
                      -- Rejeita
                      po_vMotivoNaoPodeGravar := 'Não foi encontrada a tributação do Produto '      || NVL(vrItemPedido.nCODPROD,0) ||
                                                 ' na filial de origem ' || NVL(pi_vCodFilial,' ')  ||
                                                 ' para a UF ' || NVL(vrClienteDestino.vESTENT,' ') || '!';
                      RAISE e_Tratado;
                    END IF;
                END;
              -- Se NÃO utiliza Tributação por UF, utiliza o Código da Tributação da Tabela de Preços
              ELSE
                -- Pesquisa Dados da Tabela de Preços do Produto
                BEGIN
                  SELECT PCTABPR.CODST
                    INTO vnCodSt
                    FROM PCTABPR
                   WHERE (PCTABPR.CODPROD   = vrItemPedido.nCODPROD)
                     AND (PCTABPR.NUMREGIAO = vrRegiao.nNUMREGIAO);
                EXCEPTION
                  WHEN NO_DATA_FOUND THEN
                    -- Informações de Produto Bloqueado para a Campanha -- HIS.01889.2017
                    IF (pi_nTipoChamada = 13) THEN
                      vrItemPedido.vBLOQUEIOCAMPANHA       := 'S';
                      vrItemPedido.vMOTIVOBLOQUEIOCAMPANHA := 'Produto ' || NVL(vrItemPedido.nCODPROD,0) || ' do KIT sem registro de Preço na Região ' || NVL(vrRegiao.nNUMREGIAO,0);
                    ELSE
                      -- Rejeita
                      po_vMotivoNaoPodeGravar := 'Produto ' || NVL(vrItemPedido.nCODPROD,0) || ' do KIT sem registro de Preço na Região ' || NVL(vrRegiao.nNUMREGIAO,0);
                      RAISE e_Tratado;
                    END IF;
                END;
              END IF;

              -- Guarda a Tributação encontrada para atualização no Item do Pedido
              vrItemPedido.nCODST := vnCodSt;

            END IF; -- Fim Condição Se não pesquisou ainda a Tributação

            ----------------------------------
            -- DEFINIÇÃO DE PREÇOS E DESCONTOS
            ----------------------------------

            -- Pesquisa Dados da Tabela de Preços do Produto
            BEGIN
              SELECT CASE WHEN (NVL(PCTRIBUT.UTILIZARSTFONTEPRECIFIC,'N') = 'S') THEN --PCNIL
                       ROUND(PCTABPR.PVENDASEMIMPOSTO1 * (1 + (NVL(PCPRODUT.PERCIPIVENDA,0) / 100)),vrParamFilial.nCON_NUMCASASDECVENDA)
                     ELSE
                       round(NVL(pctabpr.pvenda1, 0),vrParamFilial.nCON_NUMCASASDECVENDA)
                     END,
                     CASE WHEN (NVL(PCTRIBUT.UTILIZARSTFONTEPRECIFIC,'N') = 'S') THEN --PCNIL
                       ROUND(PCTABPR.PVENDASEMIMPOSTO2 * (1 + (NVL(PCPRODUT.PERCIPIVENDA,0) / 100)),vrParamFilial.nCON_NUMCASASDECVENDA)
                     ELSE
                       round(NVL(pctabpr.pvenda2, 0),vrParamFilial.nCON_NUMCASASDECVENDA)
                     END,
                     CASE WHEN (NVL(PCTRIBUT.UTILIZARSTFONTEPRECIFIC,'N') = 'S') THEN --PCNIL
                       ROUND(PCTABPR.PVENDASEMIMPOSTO3 * (1 + (NVL(PCPRODUT.PERCIPIVENDA,0) / 100)),vrParamFilial.nCON_NUMCASASDECVENDA)
                     ELSE
                       round(NVL(pctabpr.pvenda3, 0),vrParamFilial.nCON_NUMCASASDECVENDA)
                     END,
                     CASE WHEN (NVL(PCTRIBUT.UTILIZARSTFONTEPRECIFIC,'N') = 'S') THEN --PCNIL
                       ROUND(PCTABPR.PVENDASEMIMPOSTO4 * (1 + (NVL(PCPRODUT.PERCIPIVENDA,0) / 100)),vrParamFilial.nCON_NUMCASASDECVENDA)
                     ELSE
                       round(NVL(pctabpr.pvenda4, 0),vrParamFilial.nCON_NUMCASASDECVENDA)
                     END,
                     CASE WHEN (NVL(PCTRIBUT.UTILIZARSTFONTEPRECIFIC,'N') = 'S') THEN --PCNIL
                       ROUND(PCTABPR.PVENDASEMIMPOSTO5 * (1 + (NVL(PCPRODUT.PERCIPIVENDA,0) / 100)),vrParamFilial.nCON_NUMCASASDECVENDA)
                     ELSE
                       round(NVL(pctabpr.pvenda5, 0),vrParamFilial.nCON_NUMCASASDECVENDA)
                     END,
                     CASE WHEN (NVL(PCTRIBUT.UTILIZARSTFONTEPRECIFIC,'N') = 'S') THEN --PCNIL
                       ROUND(PCTABPR.PVENDASEMIMPOSTO6 * (1 + (NVL(PCPRODUT.PERCIPIVENDA,0) / 100)),vrParamFilial.nCON_NUMCASASDECVENDA)
                     ELSE
                       round(NVL(pctabpr.pvenda6, 0),vrParamFilial.nCON_NUMCASASDECVENDA)
                     END,
                     CASE WHEN (NVL(PCTRIBUT.UTILIZARSTFONTEPRECIFIC,'N') = 'S') THEN --PCNIL
                       ROUND(PCTABPR.PVENDASEMIMPOSTO7 * (1 + (NVL(PCPRODUT.PERCIPIVENDA,0) / 100)),vrParamFilial.nCON_NUMCASASDECVENDA)
                     ELSE
                       round(NVL(pctabpr.pvenda7, 0),vrParamFilial.nCON_NUMCASASDECVENDA)
                     END,
                     --
                     CASE WHEN (NVL(PCTRIBUT.UTILIZARSTFONTEPRECIFIC,'N') = 'S') THEN --PCNIL
                       ROUND(PCTABPR.PVENDAATACSEMIMPOSTO1 * (1 + (NVL(PCPRODUT.PERCIPIVENDA,0) / 100)),vrParamFilial.nCON_NUMCASASDECVENDA)
                     ELSE
                       round(NVL(pctabpr.pvendaatac1, 0),vrParamFilial.nCON_NUMCASASDECVENDA)
                     END,
                     CASE WHEN (NVL(PCTRIBUT.UTILIZARSTFONTEPRECIFIC,'N') = 'S') THEN --PCNIL
                       ROUND(PCTABPR.PVENDAATACSEMIMPOSTO2 * (1 + (NVL(PCPRODUT.PERCIPIVENDA,0) / 100)),vrParamFilial.nCON_NUMCASASDECVENDA)
                     ELSE
                       round(NVL(pctabpr.pvendaatac2, 0),vrParamFilial.nCON_NUMCASASDECVENDA)
                     END,
                     CASE WHEN (NVL(PCTRIBUT.UTILIZARSTFONTEPRECIFIC,'N') = 'S') THEN --PCNIL
                       ROUND(PCTABPR.PVENDAATACSEMIMPOSTO3 * (1 + (NVL(PCPRODUT.PERCIPIVENDA,0) / 100)),vrParamFilial.nCON_NUMCASASDECVENDA)
                     ELSE
                       round(NVL(pctabpr.pvendaatac3, 0),vrParamFilial.nCON_NUMCASASDECVENDA)
                     END,
                     CASE WHEN (NVL(PCTRIBUT.UTILIZARSTFONTEPRECIFIC,'N') = 'S') THEN --PCNIL
                       ROUND(PCTABPR.PVENDAATACSEMIMPOSTO4 * (1 + (NVL(PCPRODUT.PERCIPIVENDA,0) / 100)),vrParamFilial.nCON_NUMCASASDECVENDA)
                     ELSE
                       round(NVL(pctabpr.pvendaatac4, 0),vrParamFilial.nCON_NUMCASASDECVENDA)
                     END,
                     CASE WHEN (NVL(PCTRIBUT.UTILIZARSTFONTEPRECIFIC,'N') = 'S') THEN --PCNIL
                       ROUND(PCTABPR.PVENDAATACSEMIMPOSTO5 * (1 + (NVL(PCPRODUT.PERCIPIVENDA,0) / 100)),vrParamFilial.nCON_NUMCASASDECVENDA)
                     ELSE
                       round(NVL(pctabpr.pvendaatac5, 0),vrParamFilial.nCON_NUMCASASDECVENDA)
                     END,
                     CASE WHEN (NVL(PCTRIBUT.UTILIZARSTFONTEPRECIFIC,'N') = 'S') THEN --PCNIL
                       ROUND(PCTABPR.PVENDAATACSEMIMPOSTO6 * (1 + (NVL(PCPRODUT.PERCIPIVENDA,0) / 100)),vrParamFilial.nCON_NUMCASASDECVENDA)
                     ELSE
                       round(NVL(pctabpr.pvendaatac6, 0),vrParamFilial.nCON_NUMCASASDECVENDA)
                     END,
                     CASE WHEN (NVL(PCTRIBUT.UTILIZARSTFONTEPRECIFIC,'N') = 'S') THEN --PCNIL
                       ROUND(PCTABPR.PVENDAATACSEMIMPOSTO7 * (1 + (NVL(PCPRODUT.PERCIPIVENDA,0) / 100)),vrParamFilial.nCON_NUMCASASDECVENDA)
                     ELSE
                       round(NVL(pctabpr.pvendaatac7, 0),vrParamFilial.nCON_NUMCASASDECVENDA)
                     END,
                     --
                     --PCTABPR.CODST,
                     PCTABPR.PERCBONIFICVENDA,
                     1 QTUNIT, -- Não Usa PCEMBALAGEM aqui
                     PCTABPR.PERCDESCSIMPLESNAC,
                     PCTABPR.PERDESCMAX
                INTO vrTabPreco.nPVENDA1
                   , vrTabPreco.nPVENDA2
                   , vrTabPreco.nPVENDA3
                   , vrTabPreco.nPVENDA4
                   , vrTabPreco.nPVENDA5
                   , vrTabPreco.nPVENDA6
                   , vrTabPreco.nPVENDA7
                     --
                   , vrTabPreco.nPVENDAATAC1
                   , vrTabPreco.nPVENDAATAC2
                   , vrTabPreco.nPVENDAATAC3
                   , vrTabPreco.nPVENDAATAC4
                   , vrTabPreco.nPVENDAATAC5
                   , vrTabPreco.nPVENDAATAC6
                   , vrTabPreco.nPVENDAATAC7
                     --
                   --, vrTabPreco.nCODST
                   , vrTabPreco.nPERCBONIFICVENDA
                   , vrTabPreco.nQTUNIT
                   , vrTabPreco.nPERCDESCSIMPLESNAC
                   , vrTabPreco.nPERDESCMAX
                FROM PCTABPR
                   , PCPRODUT
                   , PCTRIBUT
               WHERE (PCTABPR.CODPROD   = vrItemPedido.nCODPROD)
                 AND (PCTABPR.NUMREGIAO = vrRegiao.nNUMREGIAO)
                 AND (PCPRODUT.CODPROD  = PCTABPR.CODPROD)
                 AND (PCTRIBUT.CODST    = vrItemPedido.nCODST);
            EXCEPTION
              WHEN NO_DATA_FOUND THEN
                -- Informações de Produto Bloqueado para a Campanha -- HIS.01889.2017
                IF (pi_nTipoChamada = 13) THEN
                  vrItemPedido.vBLOQUEIOCAMPANHA       := 'S';
                  vrItemPedido.vMOTIVOBLOQUEIOCAMPANHA := 'Produto ' || NVL(vrItemPedido.nCODPROD,0) || ' do KIT sem registro de Preço na Região ' || NVL(vrRegiao.nNUMREGIAO,0);
                ELSE
                  -- Rejeita
                  po_vMotivoNaoPodeGravar := 'Produto ' || NVL(vrItemPedido.nCODPROD,0) || ' do KIT sem registro de Preço na Região ' || NVL(vrRegiao.nNUMREGIAO,0);
                  RAISE e_Tratado;
                END IF;
            END;

            -- Define o PTABELA da Tabela PCPEDI (Preço Bruto) conforme a Tabela de Preços e o Número do Prazo do Plano de Pagamento
            --PCNIL - TIPO PRECIFICAÇÃO ATACADO
            IF (NVL(vrParamFilial.vTIPOPRECIFICACAO,'P') = 'A') THEN
              -- Qtde. Minima Atacado
              BEGIN
                SELECT PCPRODFILIAL.QTMINIMAATACADO
                  INTO vnQtMinimaAtacado
                  FROM PCPRODFILIAL
                 WHERE (PCPRODFILIAL.CODFILIAL = pi_vCodFilial)
                   AND (PCPRODFILIAL.CODPROD   = vrItemPedido.nCODPROD);
              EXCEPTION
                WHEN NO_DATA_FOUND THEN
                  vnQtMinimaAtacado := 0;
              END;
              -- Se a Quantidade Vendida for abaixo do Mínimo da Quantidade Atacado
              IF ((NVL(vrItemPedido.nQT,0) * NVL(vrTabPreco.nQTUNIT,0)) < NVL(vnQtMinimaAtacado,0)) AND
                  (NVL(vnQtMinimaAtacado,0) > 0) THEN
                IF    (vrPlanoPag.nNUMPR = 1) THEN
                  vrItemPedido.nPTABELA := NVL(vrTabPreco.nPVENDAATAC1,0);
                ELSIF (vrPlanoPag.nNUMPR = 2) THEN
                  vrItemPedido.nPTABELA := NVL(vrTabPreco.nPVENDAATAC2,0);
                ELSIF (vrPlanoPag.nNUMPR = 3) THEN
                  vrItemPedido.nPTABELA := NVL(vrTabPreco.nPVENDAATAC3,0);
                ELSIF (vrPlanoPag.nNUMPR = 4) THEN
                  vrItemPedido.nPTABELA := NVL(vrTabPreco.nPVENDAATAC4,0);
                ELSIF (vrPlanoPag.nNUMPR = 5) THEN
                  vrItemPedido.nPTABELA := NVL(vrTabPreco.nPVENDAATAC5,0);
                ELSIF (vrPlanoPag.nNUMPR = 6) THEN
                  vrItemPedido.nPTABELA := NVL(vrTabPreco.nPVENDAATAC6,0);
                ELSIF (vrPlanoPag.nNUMPR = 7) THEN
                  vrItemPedido.nPTABELA := NVL(vrTabPreco.nPVENDAATAC7,0);
                END IF;
              ELSE
                IF    (vrPlanoPag.nNUMPR = 1) THEN
                  vrItemPedido.nPTABELA := NVL(vrTabPreco.nPVENDA1,0);
                ELSIF (vrPlanoPag.nNUMPR = 2) THEN
                  vrItemPedido.nPTABELA := NVL(vrTabPreco.nPVENDA2,0);
                ELSIF (vrPlanoPag.nNUMPR = 3) THEN
                  vrItemPedido.nPTABELA := NVL(vrTabPreco.nPVENDA3,0);
                ELSIF (vrPlanoPag.nNUMPR = 4) THEN
                  vrItemPedido.nPTABELA := NVL(vrTabPreco.nPVENDA4,0);
                ELSIF (vrPlanoPag.nNUMPR = 5) THEN
                  vrItemPedido.nPTABELA := NVL(vrTabPreco.nPVENDA5,0);
                ELSIF (vrPlanoPag.nNUMPR = 6) THEN
                  vrItemPedido.nPTABELA := NVL(vrTabPreco.nPVENDA6,0);
                ELSIF (vrPlanoPag.nNUMPR = 7) THEN
                  vrItemPedido.nPTABELA := NVL(vrTabPreco.nPVENDA7,0);
                END IF;
              END IF;
            --PCNIL - TIPO PRECIFICAÇÃO PADRÃO
            ELSE
              IF    (vrPlanoPag.nNUMPR = 1) THEN
                vrItemPedido.nPTABELA := NVL(vrTabPreco.nPVENDA1,0);
              ELSIF (vrPlanoPag.nNUMPR = 2) THEN
                vrItemPedido.nPTABELA := NVL(vrTabPreco.nPVENDA2,0);
              ELSIF (vrPlanoPag.nNUMPR = 3) THEN
                vrItemPedido.nPTABELA := NVL(vrTabPreco.nPVENDA3,0);
              ELSIF (vrPlanoPag.nNUMPR = 4) THEN
                vrItemPedido.nPTABELA := NVL(vrTabPreco.nPVENDA4,0);
              ELSIF (vrPlanoPag.nNUMPR = 5) THEN
                vrItemPedido.nPTABELA := NVL(vrTabPreco.nPVENDA5,0);
              ELSIF (vrPlanoPag.nNUMPR = 6) THEN
                vrItemPedido.nPTABELA := NVL(vrTabPreco.nPVENDA6,0);
              ELSIF (vrPlanoPag.nNUMPR = 7) THEN
                vrItemPedido.nPTABELA := NVL(vrTabPreco.nPVENDA7,0);
              END IF;
            END IF; -- FIM CONDIÇÃO - TIPO PRECIFICAÇÃO PADRÃO
            IF (NVL(vrItemPedido.nPTABELA,0) = 0) THEN
              -- Informações de Produto Bloqueado para a Campanha -- HIS.01889.2017
              IF (pi_nTipoChamada = 13) THEN
                vrItemPedido.vBLOQUEIOCAMPANHA       := 'S';
                vrItemPedido.vMOTIVOBLOQUEIOCAMPANHA :=  'Produto ' || NVL(vrItemPedido.nCODPROD,0) || ' sem Preço de Tabela!';
              ELSE
                po_vMotivoNaoPodeGravar := 'Produto ' || NVL(vrItemPedido.nCODPROD,0) || ' sem Preço de Tabela!';
                RAISE e_Tratado;
              END IF;
            END IF;

            -- Origem do Preço
            vrItemPedido.vORIGEMPRECO := '1';

            -- Log do Item
            IF (pi_nTipoChamada IN (2,10,11,15
                                   ,16 -- ITENS CROSS DOCKING [16] - MED-1096
                                   ,17
                                   )) THEN
              P_INSERE_LOG(viLacoValidar, 'Preço de Tabela: ' || vrItemPedido.nPTABELA);
            END IF;

            -- Pesquisa Dados da Tributação do Produto
            BEGIN
              SELECT PCTRIBUT.PAUTA
                   , PCTRIBUT.IVA
                   , PCTRIBUT.ALIQICMS1
                   , PCTRIBUT.ALIQICMS2
                   , PCTRIBUT.PERCBASEREDST
                   , NVL(PCTRIBUT.TIPOCALCULOGNRETRANSF,NVL(PCTRIBUT.TIPOCALCULOGNRE,'P')) TIPOCALCULOGNRE
                   , PCTRIBUT.CODICMTAB
                   , PCTRIBUT.CODICMTABPF
                   , PCTRIBUT.PERDESCCUSTO
                   , PCTRIBUT.PERDESCREPASSE
                   , PCTRIBUT.IVAFONTE
                   , PCTRIBUT.ALIQICMS1FONTE
                   , PCTRIBUT.ALIQICMS2FONTE
                   , PCTRIBUT.PERCBASEREDSTFONTE
                   , PCTRIBUT.APLICADESCISENCAOMED
                   , PCTRIBUT.PERDESCICMISENCAO
                   , PCTRIBUT.USABCRULTENT
                   , PCTRIBUT.SITTRIBUT
                   , PCTRIBUT.CODICMTABINTERNAC -- HIS.02786.2016
                   , PCTRIBUT.PERDESCPISSUFRAMA -- DDMEDICA-1172
                   , PCTRIBUT.PERCDESCPIS       -- DDMEDICA-1172
                   , PCTRIBUT.PERCDESCCOFINS    -- DDMEDICA-1172
                   , PCTRIBUT.PERDESCSUFRAMA    -- DDMEDICA-1172
                   , PCTRIBUT.PERDESCCUSTOTRANSF
                   , PCTRIBUT.PERDESCCUSTOTRANSFTV9
                   , PCTRIBUT.DESTACDESCICMISENCAOCOMERCIAL
                INTO vrTribut.nPAUTA
                   , vrTribut.nIVA
                   , vrTribut.nALIQICMS1
                   , vrTribut.nALIQICMS2
                   , vrTribut.nPERCBASEREDST
                   , vrTribut.vTIPOCALCULOGNRE
                   , vrTribut.nCODICMTAB
                   , vrTribut.nCODICMTABPF
                   , vrTribut.nPERDESCCUSTO
                   , vrTribut.nPERDESCREPASSE
                   , vrTribut.nIVAFONTE
                   , vrTribut.nALIQICMS1FONTE
                   , vrTribut.nALIQICMS2FONTE
                   , vrTribut.nPERCBASEREDSTFONTE
                   , vrTribut.nAPLICADESCISENCAOMED
                   , vrTribut.nPERDESCICMISENCAO
                   , vrTribut.vUSABCRULTENT
                   , vrTribut.vSITTRIBUT
                   , vrTribut.nCODICMTABINTERNAC
                   , vrTribut.nPERDESCPISSUFRAMA -- DDMEDICA-1172
                   , vrTribut.nPERCDESCPIS       -- DDMEDICA-1172
                   , vrTribut.nPERCDESCCOFINS    -- DDMEDICA-1172
                   , vrTribut.nPERDESCSUFRAMA    -- DDMEDICA-1172
                   , vrTribut.nPERDESCCUSTOTRANSF
                   , vrTribut.nPERDESCCUSTOTRANSFTV9
                   , vrTribut.vDESTACDESCICMISENCAOCOMERCIAL
                FROM PCTRIBUT
               WHERE (PCTRIBUT.CODST = vrItemPedido.nCODST);
            EXCEPTION
              WHEN NO_DATA_FOUND THEN
                -- Informações de Produto Bloqueado para a Campanha -- HIS.01889.2017
                IF (pi_nTipoChamada = 13) THEN
                  vrItemPedido.vBLOQUEIOCAMPANHA       := 'S';
                  vrItemPedido.vMOTIVOBLOQUEIOCAMPANHA := 'Não foram encontrados os dados da Tributação ' || NVL(vrItemPedido.nCODST,0);
                ELSE
                  -- Rejeita
                  po_vMotivoNaoPodeGravar := 'Não foram encontrados os dados da Tributação ' || NVL(vrItemPedido.nCODST,0);
                  RAISE e_Tratado;
                END IF;
            END;

            --------------------------------------------------
            -- PREÇO DA TRANSFERÊNCIA
            -- PREÇO DA AVARIA DE PERDA
            --------------------------------------------------
            IF (pi_nCondVenda IN (9,10)) OR
               (pi_nTipoChamada = 17)    THEN

              IF (pi_nCondVenda = 9) THEN
                vvTipoCustoTransf := NVL(vrProduto_O.vTIPOCUSTOTRANSF,vrClienteDestino.vTIPOCUSTOTRANSFTV9);
              END IF;
              IF (pi_nCondVenda = 10) THEN
                vvTipoCustoTransf := NVL(vrProduto_O.vTIPOCUSTOTRANSF,vrClienteDestino.vTIPOCUSTOTRANSF);
              END IF;
              IF (pi_nTipoChamada = 17) THEN
                vvTipoCustoTransf := 'C'; -->> Perda de Avaria - Custo Contábil
              END IF;

              -- Define o PTABELA da Tabela PCPEDI (Preço Bruto) conforme o Tipo de Custo da Transferência
              IF    (vvTipoCustoTransf = 'E') THEN
                vrItemPedido.nPTABELA := NVL(vrCustoProduto_O.nCUSTOREP,0);
              ELSIF (vvTipoCustoTransf = 'R') THEN
                vrItemPedido.nPTABELA := NVL(vrCustoProduto_O.nCUSTOREAL,0);
              ELSIF (vvTipoCustoTransf = 'C') THEN
                vrItemPedido.nPTABELA := NVL(vrCustoProduto_O.nCUSTOCONT,0);
              ELSIF (vvTipoCustoTransf = 'F') THEN
                vrItemPedido.nPTABELA := NVL(vrCustoProduto_O.nCUSTOFIN,0);
              ELSIF (vvTipoCustoTransf = 'U') THEN
                vrItemPedido.nPTABELA := NVL(vrCustoProduto_O.nCUSTOULTENT,0);
              ELSIF (vvTipoCustoTransf = 'V') THEN
                vrItemPedido.nPTABELA := NVL(vrCustoProduto_O.nVALORULTENT,0);
              ELSIF (vvTipoCustoTransf = 'S') THEN
                vrItemPedido.nPTABELA := NVL(vrCustoProduto_O.nCUSTOREALSEMST,0);
              ELSIF (vvTipoCustoTransf = 'T') THEN
                vrItemPedido.nPTABELA := NVL(vrCustoProduto_O.nVLULTENTCONTSEMST,0);
              ELSIF (vvTipoCustoTransf = 'O') THEN
                vrItemPedido.nPTABELA := NVL(vrCustoProduto_O.nCUSTOFORNEC,0);
              ELSIF (vvTipoCustoTransf = 'A') THEN
                vrItemPedido.nPTABELA := FOBTEM_PRECO_ENTRADA(pi_vCodFilial,
                                                              vrItemPedido.nCODPROD,
                                                              vrCustoProduto_O.nCUSTOULTENT);
              END IF;

              -- Log do Item
              IF (vvTipoCustoTransf IS NOT NULL) THEN
                IF (pi_nTipoChamada IN (2,10,11,15
                                       ,16 -- ITENS CROSS DOCKING [16] - MED-1096
                                       ,17
                                       )) THEN
                  P_INSERE_LOG(viLacoValidar, 'Produto: '                    || vrItemPedido.nCODPROD);
                  P_INSERE_LOG(viLacoValidar, 'Tipo de Custo: '              || vvTipoCustoTransf);
                  P_INSERE_LOG(viLacoValidar, 'Preço de Tabela pelo Custo: ' || vrItemPedido.nPTABELA);
                END IF;
              END IF;

              -- Desconto de Custo no Preço
              vnPerDescCustoTransf := 0;
              IF (pi_nCondVenda = 9) AND
                 (vrParamFilial.vUSARTRIBTRANSFVENDA10 = 'S') THEN
                vnPerDescCustoTransf := vrTribut.nPERDESCCUSTOTRANSFTV9;
              END IF;
              IF (pi_nCondVenda = 10) AND
                 (vrParamFilial.vUSARTRIBTRANSFVENDA10 = 'S') THEN
                vnPerDescCustoTransf := vrTribut.nPERDESCCUSTOTRANSF;
              END IF;

              -- Se tem Desconto de Custo no Preço
              IF (NVL(vnPerDescCustoTransf,0) <> 0) THEN

                vrItemPedido.nPTABELA := vrItemPedido.nPTABELA * (1 - (NVL(vnPerDescCustoTransf,0) / 100));

                -- Log do Item
                IF (vvTipoCustoTransf IS NOT NULL) THEN
                  IF (pi_nTipoChamada IN (2,10,11,15
                                         ,16 -- ITENS CROSS DOCKING [16] - MED-1096
                                         ,17
                                         )) THEN
                    P_INSERE_LOG(viLacoValidar, 'Preço de Tabela após Desc. Custo: ' || vrItemPedido.nPTABELA);
                  END IF;
                END IF;

              END IF;

            END IF;

            --------------------------------------------------
            -- DESCONTO DO SIMPLES NACIONAL NO PREÇO DE TABELA
            -- Se Cliente Simples Nacional
            -- e Filial usa Desconto Simples
            --------------------------------------------------
            IF (NVL(vrClienteDestino.nSIMPLESNACIONAL,'N') = 'S') AND
               (NVL(vrParamFilial.vUSADESCSIMPLESNAC ,'N') = 'S') THEN

              -- Guarda o Valor do Desconto do Simples Nacional antes de aplicar o desconto do simples nacional
              vrItemPedido.nVALORDESCSIMPLESNAC := vrItemPedido.nPTABELA * (NVL(vrTabPreco.nPERCDESCSIMPLESNAC,0) / 100);

              -- Aplica o Desconto do Simples Nacional no Preço de Tabela
              vrItemPedido.nPTABELA := vrItemPedido.nPTABELA * (1 - (NVL(vrTabPreco.nPERCDESCSIMPLESNAC,0) / 100));

              -- Log do Item
              IF (pi_nTipoChamada IN (2,10,11,15
                                     ,16 -- ITENS CROSS DOCKING [16] - MED-1096
                                     ,17
                                     )) THEN
                P_INSERE_LOG(viLacoValidar, '% Desc. Simples Nac.: ' || vrTabPreco.nPERCDESCSIMPLESNAC);
                P_INSERE_LOG(viLacoValidar, 'Preço de Tabela c/ Simples Nac.: ' || vrItemPedido.nPTABELA);
              END IF;

            END IF;

            --------------------------------
            -- TAXAS SOBRE O PREÇO DE TABELA
            --------------------------------

            -- DDMEDICA-249 - Guarda o Preço de Tabela sem a Taxa para usar no cálculo da promoção de markup
            vrItemPedido.nPVENDA1BASEPROMOMARKUP := vrItemPedido.nPTABELA;

            -- Aplica no PTABELA Desconto ou Acrescimo do Plano de Pagamento
            vrItemPedido.nPTABELA := (vrItemPedido.nPTABELA + (vrItemPedido.nPTABELA * (NVL(vrPlanoPag.nPERTXFIM,0) / 100)));

            -- Log do Item
            IF (pi_nTipoChamada IN (2,10,11,15
                                   ,16 -- ITENS CROSS DOCKING [16] - MED-1096
                                   ,17
                                   )) THEN
              IF (NVL(vrPlanoPag.nPERTXFIM,0) <> 0) THEN
                P_INSERE_LOG(viLacoValidar, '% Taxa Plano: ' || vrPlanoPag.nPERTXFIM);
                P_INSERE_LOG(viLacoValidar, 'Preço de Tabela c/ % Taxa Plano: ' || vrItemPedido.nPTABELA);
              END IF;
            END IF;

            -- Aplica no PTABELA Desconto ou Acrescimo do Ramo de Atividade
            IF (NVL(vrParamFilial.vMEDAPLICARDESCOMCLIPTABELA,'N') = 'S') THEN
              vrItemPedido.nPTABELA      := (vrItemPedido.nPTABELA + (vrItemPedido.nPTABELA * (NVL(    (100 - ( (100 * (1 - (NVL(vrRamoAtividade.nPERCDESC,0)  / 100))) * (1 - ((NVL(vrClienteDestino.nPERDESC,0) * -1) / 100)) ))    ,0) / 100)));
              vrItemPedido.nPERCRAMOATIV := (100 - ( (100 * (1 - (NVL(vrRamoAtividade.nPERCDESC,0)  / 100))) * (1 - ((NVL(vrClienteDestino.nPERDESC,0) * -1) / 100)) ));
            ELSE
              vrItemPedido.nPTABELA      := (vrItemPedido.nPTABELA + (vrItemPedido.nPTABELA * (NVL(vrRamoAtividade.nPERCDESC,0) / 100)));
              vrItemPedido.nPERCRAMOATIV := NVL(vrRamoAtividade.nPERCDESC,0);
            END IF;

            -- Log do Item
            IF (pi_nTipoChamada IN (2,10,11,15
                                   ,16 -- ITENS CROSS DOCKING [16] - MED-1096
                                   ,17
                                   )) THEN
              IF (NVL(vrItemPedido.nPERCRAMOATIV,0) <> 0) THEN
                P_INSERE_LOG(viLacoValidar, '% Ramo Ativ.: ' || vrItemPedido.nPERCRAMOATIV);
                P_INSERE_LOG(viLacoValidar, 'Preço de Tabela c/ % Ramo Ativ.: ' || vrItemPedido.nPTABELA);
              END IF;
            END IF;

            ----------------------------------------
            -- TAXA ACORDO PARCERIA - HIS.01889.2017
            ----------------------------------------

            -- Log do Item
            IF (pi_nTipoChamada IN (2,10,11,15
                                   ,16 -- ITENS CROSS DOCKING [16] - MED-1096
                                   ,17
                                   )) THEN
              IF (vrParamFilial.vUSARACRESCDESCACORDOPARCERIA = 'S') THEN
                P_INSERE_LOG(viLacoValidar, 'Promoção do Pedido: ' || pi_nCodPromocaoMedPedido);
                P_INSERE_LOG(viLacoValidar, 'Preço de Tabela para aplicação a Taxa do Acordo: ' || vrItemPedido.nPTABELA);
              END IF;
            END IF;

            IF (NVL(vrParamFilial.vUSARACRESCDESCACORDOPARCERIA,'N') = 'S') AND
               (NVL(pi_nCodPromocaoMedPedido,0) > 0) THEN

              -- Busca Taxa
              PKG_MEDICAMENTOS.P_TAXACORDOPARCERIA(pi_vCodFilial,
                                                   pi_vCodFilialNf,
                                                   vtIncluiItens(viNumSeq).vnCodProd,
                                                   pi_nCodCli,
                                                   vrRegiao.nNUMREGIAO,
                                                   pi_nCondVenda,
                                                   pi_vOrigemPed,
                                                   SUBSTR(pi_vTipoFv,1,2),
                                                   0, -- pi_nIntegradora
                                                   vnCodPlPagProduto,
                                                   vdDataPedido,
                                                   vrAcordoParceria.AchouTaxa,
                                                   vrAcordoParceria.CodAcordo,
                                                   vrAcordoParceria.PercTaxa,
                                                   vrAcordoParceria.PerCom,
                                                   vrAcordoParceria.Campo);
              IF (vrAcordoParceria.AchouTaxa = 'S') THEN
                -- Aplica Taxa no Preço Tabela
                vrItemPedido.nPTABELA := (vrItemPedido.nPTABELA - (vrItemPedido.nPTABELA * (NVL(vrAcordoParceria.PercTaxa,0) / 100)));

                -- HIS.01889.2017 - Atualização da Variável de Priorização de Comissão do Acordo de Parceria
                IF (vrAcordoParceria.PerCom IS NOT NULL) THEN
                  vrItemPedido.vPRIORIZACOMISSACORDOPARC := 'S';
                ELSE
                  vrItemPedido.vPRIORIZACOMISSACORDOPARC := 'N';
                END IF;
                vrItemPedido.nPERCOMACORDOPARCERIA       := vrAcordoParceria.PerCom;
                vrItemPedido.nCODACORDOPARCERIA          := vrAcordoParceria.CodAcordo;
                vrItemPedido.nPERCDESCACORDOPARCERIA     := vrAcordoParceria.PercTaxa;

                -- Log do Item
                IF (pi_nTipoChamada IN (2,10,11,15
                                       ,16 -- ITENS CROSS DOCKING [16] - MED-1096
                                       ,17
                                       )) THEN
                  P_INSERE_LOG(viLacoValidar, 'Acordo: ' || NVL(vrAcordoParceria.CodAcordo,0));
                  P_INSERE_LOG(viLacoValidar, 'Taxa do Acordo: ' || NVL(vrAcordoParceria.PercTaxa,0));
                  P_INSERE_LOG(viLacoValidar, 'Preço de Tabela c/ Taxa do Acordo: ' || vrItemPedido.nPTABELA);
                  P_INSERE_LOG(viLacoValidar, 'Prioriza Comissão do Acordo: ' || vrItemPedido.vPRIORIZACOMISSACORDOPARC);
                  P_INSERE_LOG(viLacoValidar, 'Comissão do Acordo: ' || vrItemPedido.nPERCOMACORDOPARCERIA);
                END IF;

                -- HIS.01889.2017 - Comissão do Acordo de Parceria  - Se não aplicou a Comissão da PCDESCONTO
                IF (pi_nTipoChamada IN (2)) THEN
                  IF (SUBSTR(vrItemPedido.vTIPOCOMISSAOMED,2,2) <> 'DS') THEN
                    IF ((NVL(pi_nCodPromocaoMedPedido,0) > 0) AND
                        (NVL(vrItemPedido.vPRIORIZACOMISSACORDOPARC,'N') = 'S')) THEN
                      vrItemPedido.nPERCOM := vrItemPedido.nPERCOMACORDOPARCERIA;
                      vrItemPedido.vTIPOCOMISSAOMED := 'TAP';
                      -- Log do Item
                      P_INSERE_LOG(viLacoValidar, 'Comissão Item Ped. Ref. Acordo Parceria: ' || vrItemPedido.nPERCOM);
                    END IF;
                  END IF;
                END IF;

              ELSE

                vrItemPedido.vPRIORIZACOMISSACORDOPARC := 'N';
                vrItemPedido.nPERCOMACORDOPARCERIA     := vrAcordoParceria.PerCom;
                vrItemPedido.nCODACORDOPARCERIA        := vrAcordoParceria.CodAcordo;
                vrItemPedido.nPERCDESCACORDOPARCERIA   := vrAcordoParceria.PercTaxa;

              END IF;

            ELSE

              vrItemPedido.vPRIORIZACOMISSACORDOPARC := 'N';
              vrItemPedido.nPERCOMACORDOPARCERIA     := vrAcordoParceria.PerCom;
              vrItemPedido.nCODACORDOPARCERIA        := vrAcordoParceria.CodAcordo;
              vrItemPedido.nPERCDESCACORDOPARCERIA   := vrAcordoParceria.PercTaxa;

            END IF;

            -----------------------
            -- Guarda Preço Venda 1
            -----------------------
            vrItemPedido.nPVENDA1 := NVL(vrTabPreco.nPVENDA1,0);

            ------------------------------------
            -- DEFINIÇÃO DO PVENDA BASE
            ------------------------------------

            -- Define o Preço de Venda Base a partir do Preço de Tabela
            vrItemPedido.nPVENDABASE := vrItemPedido.nPTABELA;

            -------------------------------------------------
            -- ALTERAÇÃO DA PROMOÇÃO DO PEDIDO
            -- CROSS DOCKING PEGA TAMBÉM A PROMOÇÃO DO PEDIDO
            -- IMPORTAÇÃO DE PRODUTOS IDEM
            -------------------------------------------------
            IF    (pi_nTipoChamada IN (4,16,17)) THEN

              IF    (pi_nTipoChamada = 16) THEN
                vvTipoFvPromocao := 'PC';
              ELSIF (pi_nTipoChamada = 17) THEN
                vvTipoFvPromocao := 'PA';
              ELSE
                vvTipoFvPromocao := 'TL';
              END IF;

              -- Obtém Desconto para a Nova Promoção
              P_OBTEM_DESC_TELEVENDAS(2,                        -->> Obter as Promoções
                                      pi_nCodPromocaoMedPedido, -->> Nova Promoção
                                      vtIncluiItens(viNumSeq).vnCodProd,
                                      NULL,                     -->> Não precisa passar pi_nCodCondicaoVenda
                                      pi_nCodCli,
                                      vtIncluiItens(viNumSeq).vnQtde,
                                      TRUNC(SYSDATE),
                                      pi_vCodFilial,
                                      vrClienteDestino.nCODPRACA,
                                      vrRegiao.nNUMREGIAO,
                                      pi_nCodUsur,
                                      pi_vOrigemPed,
                                      vvTipoFvPromocao,         -->> TIPO FV DEPENDE DA CHAMADA
                                      vnCodPlPagProduto,        -->> PESQUISAR PELO CÓDIGO DO PLANO DE PAGAMENTO DO PRODUTO
                                      vrClienteDestino.vCLASSEVENDA,
                                      'N',  -->> Não usa Política Prioritária
                                      NULL, -->> Não precisa passar pi_nCodPromocaoItem, só necessário ao editar o item na 2316
                                      pi_vVisualizarPromoBloq,
                                      'S',  -->> Se chamou a procedure para atualizar a promoção, é porque já teve a permissão para escolher a nova promoção que passou no parâmetro na ObtemSelPromocao
                                      vrItemPedido.nPTABELA,
                                      vrItemPedido.nVLCUSTOFIN,
                                      vrDadosNovaPromocao.vnPerDesc,
                                      vrDadosNovaPromocao.vnPerBonific,
                                      vrDadosNovaPromocao.vnPerComerc,
                                      vrDadosNovaPromocao.vnPerBoleto,
                                      vrDadosNovaPromocao.vnPercDescFin,
                                      vrDadosNovaPromocao.vnCodLinhaPrazo,
                                      vrDadosNovaPromocao.vvOcorreramErros,
                                      vrDadosNovaPromocao.vvMsgErros);

              -- Pesquisa Dados da Promoção
              -- *** AQUI NÃO PRECISO ME PREOCUPAR COM A FAIXA DE QUANTIDADE, porque a nova promoção é de Cabeçalho, não tem Faixas
              BEGIN
                SELECT PERCDESC
                     , PERCDESCFIN
                     , ALTERAPTABELA
                     , PRECOFIXO
                     , INICIOINTERVALO
                     , CODDESCONTO
                     , CONSIDERACALCGIROMEDIC
                     , VLDESCCMVPROMOCAOMED
                  INTO vrDadosNovaPromocao.vnPerDesc
                     , vrDadosNovaPromocao.vnPerBoleto
                     , vrDadosNovaPromocao.vvAlteraPTabela
                     , vrDadosNovaPromocao.vnPrecoFixo
                     , vrDadosNovaPromocao.vnInicioIntervaloDescQuant
                     , vrDadosNovaPromocao.vnCodDesconto
                     , vrDadosNovaPromocao.vvParticipaGiro
                     , vrDadosNovaPromocao.vvVlDescCmvPromocaoMed
                  FROM PCMED_SELPROMOCAO
                 WHERE (CODPROMOCAOMED = pi_nCodPromocaoMedPedido)
                   AND (ROWNUM         = 1);
              EXCEPTION
                WHEN NO_DATA_FOUND THEN
                   vrDadosNovaPromocao.vnPerDesc                  := 0;
                   vrDadosNovaPromocao.vnPerBoleto                := 0;
                   vrDadosNovaPromocao.vvAlteraPTabela            := 'N';
                   vrDadosNovaPromocao.vnPrecoFixo                := 0;
                   vrDadosNovaPromocao.vnInicioIntervaloDescQuant := NULL;
                   vrDadosNovaPromocao.vnCodDesconto              := NULL;
                   vrDadosNovaPromocao.vvParticipaGiro            := NULL;
                   vrDadosNovaPromocao.vvVlDescCmvPromocaoMed     := NULL;
              END;
              -- Pesquisa Dados da Comissão
              BEGIN
                SELECT PERCOMMINT
                     , PERCOMEXT
                     , PERCOMREP
                  INTO vrDadosNovaPromocao.vnPerComInt
                     , vrDadosNovaPromocao.vnPerComExt
                     , vrDadosNovaPromocao.vnPerComRep
                  FROM PCDESCONTO
                 WHERE (CODDESCONTO    = vrDadosNovaPromocao.vnCodDesconto)
                   AND (CODPROMOCAOMED = pi_nCodPromocaoMedPedido)
                   AND (ROWNUM         = 1);
              EXCEPTION
                WHEN NO_DATA_FOUND THEN
                  vrDadosNovaPromocao.vnPerComInt := NULL;
                  vrDadosNovaPromocao.vnPerComExt := NULL;
                  vrDadosNovaPromocao.vnPerComRep := NULL;
              END;

              -- Calcula o Preço Liquido Anterior abatido do Desconto Financeiro
              vnPrecoLiquidoAnterior := (NVL(vtIncluiItens(viNumSeq).vnPVenda,0) - NVL(vtIncluiItens(viNumSeq).vnSt,0) - NVL(vtIncluiItens(viNumSeq).vnVlRepasse,0));
              vnPrecoLiquidoAnterior := NVL(vnPrecoLiquidoAnterior,0) * (1 - (vtIncluiItens(viNumSeq).vnPerDescBoleto / 100));
              vnPrecoLiquidoAnterior := ROUND(vnPrecoLiquidoAnterior, vrParamFilial.nCON_NUMCASASDECVENDA);

              -- Calcula novo Preço Líquido abatido do Desconto Financeiro
              IF (NVL(vrDadosNovaPromocao.vvAlteraPTabela,'N') = 'S') AND
                 (NVL(vrDadosNovaPromocao.vnPrecoFixo,0)       > 0)   THEN
                vnNovoPrecoLiquido := NVL(vrDadosNovaPromocao.vnPrecoFixo,0);
                vnNovoPrecoLiquido := ROUND(vnNovoPrecoLiquido, vrParamFilial.nCON_NUMCASASDECVENDA);
              ELSE
                vnNovoPrecoLiquido := NVL(vrItemPedido.nPTABELA,0);
                vnNovoPrecoLiquido := NVL(vnNovoPrecoLiquido,0) * (1 - (vrDadosNovaPromocao.vnPerDesc / 100));
                vnNovoPrecoLiquido := NVL(vnNovoPrecoLiquido,0) * (1 - (vrDadosNovaPromocao.vnPerBoleto / 100));
                vnNovoPrecoLiquido := ROUND(vnNovoPrecoLiquido, vrParamFilial.nCON_NUMCASASDECVENDA);
              END IF;

              -- Se a Nova Promoção não reduzir o Preço Atual
              -- (Por Causa do Cross Docking, limitar a Condição abaixo ao Tipo de Chamada 4,
              --  o Cross Docking sempre deve atualizar o Preço Líquido com o Desconto da Promoção)
              IF (pi_nTipoChamada = 4) AND
                 (NVL(vnNovoPrecoLiquido,0) >= NVL(vnPrecoLiquidoAnterior,0)) THEN
                -- NÃO PROCESSA O PRODUTO DO PEDIDO
                vbPodeProcessarProduto := FALSE;
              -- Se a Nova Promoção reduzir o Preço Atual usa ela
              ELSE
                vrItemPedido.nPERDESC                  := vrDadosNovaPromocao.vnPerDesc;
                vrItemPedido.nPERDESCBOLETO            := vrDadosNovaPromocao.vnPerBoleto;
                vrItemPedido.nCODDESCONTO              := vrDadosNovaPromocao.vnCodDesconto;
                vrItemPedido.nCODPROMOCAOMED           := pi_nCodPromocaoMedPedido;
                vrItemPedido.vOBSCODPROMOCAOMED_OLD    := 'Promoção do Pedido no processo ' || pi_nTipoChamada; -- DDMEDICA-4799
                vrItemPedido.nINICIOINTERVALODESCQUANT := vrDadosNovaPromocao.vnInicioIntervaloDescQuant;
                IF    (NVL(vrRca.vTIPOVEND,' ') = 'I') THEN
                  IF (vrDadosNovaPromocao.vnPerComInt IS NOT NULL) THEN
                    vrItemPedido.nPERCOM               := vrDadosNovaPromocao.vnPerComInt;
                  END IF;
                ELSIF (NVL(vrRca.vTIPOVEND,' ') = 'E') THEN
                  IF (vrDadosNovaPromocao.vnPerComExt IS NOT NULL) THEN
                    vrItemPedido.nPERCOM               := vrDadosNovaPromocao.vnPerComExt;
                  END IF;
                ELSIF (NVL(vrRca.vTIPOVEND,' ') = 'R') THEN
                  IF (vrDadosNovaPromocao.vnPerComRep IS NOT NULL) THEN
                    vrItemPedido.nPERCOM               := vrDadosNovaPromocao.vnPerComRep;
                  END IF;
                END IF;
                vrItemPedido.vPARTICIPAGIRO            := vrDadosNovaPromocao.vvParticipaGiro;
                -- DDMEDICA-5009 - Alterando a Promoção do Item, precisa atualizar o Valor da Verba de Fornecedor
                vrItemPedido.nVLDESCCMVPROMOCAOMED     := vrDadosNovaPromocao.vvVlDescCmvPromocaoMed;
                -- Obter Verba Relacionada com o Valor da Verba para Rebaixa de CMV da Promoção da PCDESCONTO - DDMEDICA-5009
                BEGIN
                  SELECT CODFORNEC
                    INTO vnCodFornecProduto
                    FROM PCPRODUT
                   WHERE (CODPROD = vrItemPedido.nCODPROD); 
                EXCEPTION
                  WHEN NO_DATA_FOUND THEN
                    vnCodFornecProduto := NULL;
                END;
                P_OBTER_VERBA_PROMOCAO(pi_nCodPromocaoMedPedido,
                                       vnCodFornecProduto,
                                       vrItemPedido.nVLDESCCMVPROMOCAOMED,
                                       vrItemPedido.nNUMVERBACAMPANHA, 
                                       vrDadosNovaPromocao.vnValorCotaNumVerba,
                                       vrDadosNovaPromocao.vvSemVerbaVlDescCmv);
              END IF;

              -- Log do Item
              IF (pi_nTipoChamada IN (2,10,11,15
                                     ,16 -- ITENS CROSS DOCKING [16] - MED-1096
                                     ,17
                                     )) THEN
                P_INSERE_LOG(viLacoValidar, 'pi_nCodPromocaoMedPedido CodProd: '     || vtIncluiItens(viNumSeq).vnCodProd);
                P_INSERE_LOG(viLacoValidar, 'pi_nCodPromocaoMedPedido CodPromocao: ' || vrItemPedido.nCODPROMOCAOMED);
                P_INSERE_LOG(viLacoValidar, 'pi_nCodPromocaoMedPedido CodDesconto: ' || vrItemPedido.nCODDESCONTO);
                P_INSERE_LOG(viLacoValidar, 'pi_nCodPromocaoMedPedido PerDesc: '     || vrItemPedido.nPERDESC);
                P_INSERE_LOG(viLacoValidar, 'pi_nCodPromocaoMedPedido PrecoFixo: '   || vrDadosNovaPromocao.vnPrecoFixo);
              END IF;

            ------------------------------------------------
            -- APLICACAO DO DESCONTO ADICIONAL PLANO A VISTA
            ------------------------------------------------
            ELSIF (pi_nTipoChamada = 5) THEN

              -- Se tem Desconto Adicional para Plano de Pagamento A Vista e o Produto não está em Promoção
              IF (NVL(vrParamFilial.vMEDUSADESCADICPLPAGVISTA,'N') = 'S') AND
                 (NVL(vrItemPedido.nCODPROMOCAOMED,0) IN (-1,0))          THEN

                -- Se o Plano de Pagamento Atual é à vista
                IF (NVL(vrPlanoPag.vTIPOVENDA,' ') = 'VV') THEN
                  -- Se não tiver o Desconto à Vista (procura manter o último desconto à vista porque pode ser editado para mais ou para menos)
                  IF (NVL(vrItemPedido.nPERDESC,0) = 0) THEN
                    IF (vrParamFilial.nMEDPERDESCADICPLPAGVISTA > 99.99) THEN
                      vrItemPedido.nPERDESC              := 99.99;
                    ELSE
                      vrItemPedido.nPERDESC              := NVL(vrParamFilial.nMEDPERDESCADICPLPAGVISTA,0);
                    END IF;
                    vrItemPedido.nCODPROMOCAOMED         := -1; -- Identifica que usou Desconto à vista
                    vrItemPedido.vOBSCODPROMOCAOMED_OLD  := 'Identificador Desconto à vista no processo ' || pi_nTipoChamada; -- DDMEDICA-4799                    
                  END IF;
                -- Se o Plano de Pagamento Atual NÃO FOR à vista - HIS.03612.2015
                ELSE
                  -- Se tinha um Desconto à Vista
                  IF (vrItemPedido.nCODPROMOCAOMED = -1) THEN
                    vrItemPedido.nPERDESC               := 0;
                    vrItemPedido.nCODPROMOCAOMED        := NULL; -- Retira Identificador que usa Desconto à vista
                    vrItemPedido.vOBSCODPROMOCAOMED_OLD := 'Remove Identificador do Desconto à vista no processo ' || pi_nTipoChamada; -- DDMEDICA-4799                    
                  END IF;
                END IF;
                vrItemPedido.nPERDESCBOLETO            := 0;
                vrItemPedido.nCODDESCONTO              := NULL;
                vrItemPedido.nINICIOINTERVALODESCQUANT := NULL;
                -- Remove Verba Relacionada com o Valor da Verba para Rebaixa de CMV da Promoção da PCDESCONTO - DDMEDICA-5009
                vrItemPedido.nVLDESCCMVPROMOCAOMED     := NULL;
                vrItemPedido.nNUMVERBACAMPANHA         := NULL; 
                -- Percom Mantém o do Pedido
                --vrItemPedido.nPERCOM
                --
                vrItemPedido.vPARTICIPAGIRO            := 'S';

              -- Se não tiver ignora a atualização do Produto
              ELSE
                -- NÃO PROCESSA O PRODUTO DO PEDIDO
                vbPodeProcessarProduto := FALSE;
              END IF;

            END IF; -- FIM CONDIÇÃO ALTERAÇÃO DA PROMOÇÃO DO PEDIDO

            ------------------------------------------------
            -- BUSCA DO PMC E PREÇO FÁBRICA
            ------------------------------------------------

            -- OBTEM PMC e PREÇO FÁBRICA - HIS.04408.2015
            PKG_MEDICAMENTOS.P_OBTEM_PMC_PRODUTO(pi_vCodFilial,
                                                 vrItemPedido.nCODPROD,
                                                 vrClienteDestino.vESTENT,
                                                 vrRegiao.nNUMREGIAO,
                                                 vnPrecoMaxConsum,
                                                 vnPrecoFabrica,
                                                 vvMensagemRetornoPMC);
            IF (vvMensagemRetornoPMC IS NOT NULL) THEN
              -- Informações de Produto Bloqueado para a Campanha -- HIS.01889.2017
              IF (pi_nTipoChamada = 13) THEN
                vrItemPedido.vBLOQUEIOCAMPANHA       := 'S';
                vrItemPedido.vMOTIVOBLOQUEIOCAMPANHA := 'Problemas ao pesquisar o PMC e Preço Fábrica do Produto ' || NVL(vrItemPedido.nCODPROD,0) ||
                                                        ' para a UF ' || NVL(vrClienteDestino.vESTENT,' ') || ': ' || vvMensagemRetornoPMC;
              ELSE
                -- Rejeita
                po_vMotivoNaoPodeGravar := 'Problemas ao pesquisar o PMC e Preço Fábrica do Produto ' || NVL(vrItemPedido.nCODPROD,0) ||
                                           ' para a UF ' || NVL(vrClienteDestino.vESTENT,' ') || ': ' || vvMensagemRetornoPMC;
                RAISE e_Tratado;
              END IF;
            END IF;

            ------------------------------------------------
            -- DEFINIÇÃO DO PREÇO ORIGINAL
            ------------------------------------------------

            -- Preço Original
            IF (NVL(vrProduto_O.vTIPOMERC,' ') IN ('M','MA','L')) OR   -- Se Medicamento
               (NVL(vrProduto_O.vUTILIZAPRECOFABRICA,'N') = 'S')  THEN -- Se Controla Preço Fábrica
              -- O Procedimento PKG_MEDICAMENTOS.P_OBTEM_PMC_PRODUTO já retorna o Preço Fábrica Correto
              --IF (NVL(vrRegiao.vREGIAOZFM,'N') = 'S') THEN
              --  vrItemPedido.nPORIGINAL := vrProduto_O.nCUSTOREPZFM;
              --ELSE
              --  vrItemPedido.nPORIGINAL := vrProduto_O.nCUSTOREP;
              --END IF;
              vrItemPedido.nPORIGINAL := vnPrecoFabrica;
            ELSE
              vrItemPedido.nPORIGINAL := vrItemPedido.nPTABELA;
            END IF;

            -------------------------------------------------------------------
            -- REDEFINIÇÃO DO PREÇO DE TABELA - EXCEÇÕES QUE DESVIAM DA PCTABPR
            -------------------------------------------------------------------

            -- Pesquisa Origem do Preço da Promoção
            BEGIN
              SELECT ORIGEMPRECO
                INTO vvOrigemPrecoPromocao
                FROM PCPROMOCAOMED
               WHERE (CODPROMOCAOMED = vrItemPedido.nCODPROMOCAOMED);
            EXCEPTION
              WHEN NO_DATA_FOUND THEN
                vvOrigemPrecoPromocao := 'T';
            END;

            --------------------------------------------------------------------------------
            -- PCNIL - ALTERAÇÃO DO PREÇO DE TABELA QUANDO A POLÍTICA DA 561 ALTERAR PTABELA
            --------------------------------------------------------------------------------
            IF (NVL(pi_nCodPromocaoMedPedido,0)     = 0) AND
               (NVL(vrItemPedido.nCODPROMOCAOMED,0) = 0) AND
               (NVL(vrItemPedido.nCODDESCONTO,0)    > 0) THEN

              -- Verifica na Política se Altera PTabela
              BEGIN
                SELECT PCDESCONTO.ALTERAPTABELA
                     , PCDESCONTO.PERCDESC
                  INTO vrPoliticaDesconto.vALTERAPTABELA
                     , vrPoliticaDesconto.nPERCDESC
                  FROM PCDESCONTO
                 WHERE (PCDESCONTO.CODDESCONTO = vrItemPedido.nCODDESCONTO)
                   AND (ROWNUM                 = 1);
              EXCEPTION
                WHEN NO_DATA_FOUND THEN
                  vrPoliticaDesconto.vALTERAPTABELA := 'N';
                  vrPoliticaDesconto.nPERCDESC      := 0;
              END;
              -- Se Política altera PTabela
              IF (vrPoliticaDesconto.vALTERAPTABELA = 'S') THEN
                vrItemPedido.nPTABELA := NVL(vrItemPedido.nPTABELA,0) * (1 - (NVL(vrPoliticaDesconto.nPERCDESC,0) / 100));
              END IF;

            END IF; -- FIM CONDIÇÃO PCNIL - ALTERAÇÃO DO PREÇO DE TABELA QUANDO A POLÍTICA DA 561 ALTERAR PTABELA
            ----------------------------------------------------------------------------------
            -- PCNIL - ALTERAÇÃO DO PREÇO DE TABELA QUANDO ORÇAMENTO C/ PROMOÇÃO DE PREÇO FIXO
            ----------------------------------------------------------------------------------
            IF (pi_nTipoChamada IN (11)) AND
               (NVL(vrItemPedido.nCODPROMOCAOMED,0) > 0) THEN

              -- Pesquisa Promoção
              BEGIN
                SELECT 'S'
                  INTO vvPromocaoDePreco
                  FROM PCPROMOCAOMED
                 WHERE (PCPROMOCAOMED.CODPROMOCAOMED = vrItemPedido.nCODPROMOCAOMED)
                   AND (PCPROMOCAOMED.TIPOPOLITICA   IN ('P','F'));
              EXCEPTION
                WHEN NO_DATA_FOUND THEN
                  vvPromocaoDePreco := 'N';
              END;

              -- Se Promoção de Preço
              IF (vvPromocaoDePreco = 'S') THEN

                -- Pesquisa Preço Fixo
                BEGIN
                  SELECT PCDESCONTO.PRECOFIXOPROMOCAOMED
                       , PCDESCONTO.CODDESCONTO
                    INTO vrItemPedido.nPTABELA
                       , vrItemPedido.nCODDESCONTO
                    FROM PCDESCONTO
                   WHERE (PCDESCONTO.CODPROMOCAOMED                    = vrItemPedido.nCODPROMOCAOMED)
                     AND (PCDESCONTO.CODPROD                           = vrItemPedido.nCODPROD) -->> Promoção de Preço sempre é por Produto, pode localizar por ele
                     AND (NVL(PCDESCONTO.INICIOINTERVALOPROMOCAOMED,0) = NVL(vrItemPedido.nINICIOINTERVALODESCQUANT,0)) -->> Colocar NVL() para o mesmo select poder ser usado em promoção sem faixa
                     AND (ROWNUM                 = 1);
                EXCEPTION
                  WHEN NO_DATA_FOUND THEN
                    NULL; -->> Se não achar manter o preço de tabela
                END;

              END IF; -- Fim Condição: Se Promoção de Preço

            END IF; -- FIM PCNIL - ALTERAÇÃO DO PREÇO DE TABELA QUANDO ORÇAMENTO C/ PROMOÇÃO DE PREÇO FIXO

            -- PCNIL - O Orçamento tem que garantir o Preço de Venda, o Preço de Tabela deve permanecer o Atual,
            --         a diferença será ajustada por desconto
            ----------------------------------------------------------------------------------------------------
            -- RECUPERAÇÃO DE ORÇAMENTO - Preço Tabela no momento da Gravação do Orçamento
            --IF (pi_nTipoChamada IN (11)) THEN
            --
            --  -- Altera PTabela com Preço de Tabela do momento da Gravação do Orçamento
            --  vrItemPedido.nPTABELA := vtIncluiItens(viNumSeq).vnPrecoFixo;
            --
            --ELSE

              -- PROMOÇÃO POR PREÇO FÁBRICA
              IF ( (NVL(vvOrigemPrecoPromocao,'N') = 'F') AND
                   ((NVL(vrProduto_O.vTIPOMERC,' ') IN ('M','MA','L'))   OR   -- Se Medicamento
                    (NVL(vrProduto_O.vUTILIZAPRECOFABRICA,'N') = 'S')) ) THEN -- Se Controla Preço Fábrica
                -- Altera PTabela com Preço Fábrica - SE TIVER PREÇO FÁBRICA - 0.130545.2016
                IF (vnPrecoFabrica > 0) THEN
                  vrItemPedido.nPTABELA := vrItemPedido.nPORIGINAL;
                END IF;
              ELSE
                -- PRECO PROMOCIONAL --
                IF (pi_nTipoChamada NOT IN (11)) THEN -->> Orçamento usa a variável "vnPrecoFixo", por isso não pode entrar aqui

                  -->> MED-871 - Merge Campanha
                  -- 4954.101076.2017 - Preço Fixo Prioritário sobre o Preço de Tabela
                  IF (NVL(vtIncluiItens(viNumSeq).vvUsarPrecoFixoPrioritario,'N') = 'S') AND
                     (NVL(vtIncluiItens(viNumSeq).vnPrecoFixo,0) > 0) THEN
                    -- Novas Regras onde o Preço Tabela deverá ser o Preço Fixo, utilizar "vvUsarPrecoFixoPrioritario" junto com "vnPrecoFixo"
                    vrItemPedido.nPTABELA := vtIncluiItens(viNumSeq).vnPrecoFixo;
                  ELSE
                    -- Se Recálculo do Pedido ao alterar o Plano de Pagamento,
                    -- verificar se usa Promoção de Preço Fixo
                    IF (pi_nTipoChamada = 10) THEN
                      -- Pesquisa Promoção
                      BEGIN
                        SELECT 'S'
                          INTO vvPromocaoDePreco
                          FROM PCPROMOCAOMED
                         WHERE (PCPROMOCAOMED.CODPROMOCAOMED = vrItemPedido.nCODPROMOCAOMED)
                           AND (PCPROMOCAOMED.TIPOPOLITICA   IN ('P','F'));
                      EXCEPTION
                        WHEN NO_DATA_FOUND THEN
                          vvPromocaoDePreco := 'N';
                      END;
                      -- Se Promoção de Preço, Substitui Preço Fixo
                      IF (vvPromocaoDePreco = 'S') THEN
                        -- Altera PTabela com Preço Fixo da Promoção
                        vrItemPedido.nPTABELA := vtIncluiItens(viNumSeq).vnPrecoFixo;
                      END IF;
                    END IF;
                  END IF;

                  -- Se a Promoção de Combo Virtual for de Preço Fixo
                  -- Aqui também entrará se for Pedido de Empenho de Licitação - O Preço da Licitação entrará como Preço Fixo
                  IF (vvTipoPoliticaPedido = 'P') AND
                     (NVL(vtIncluiItens(viNumSeq).vnPrecoFixo,0) > 0) THEN -->> Este campo só está sendo preenchido em Combo ou Licitação
                    -- Altera PTabela com Preço Fixo da Promoção
                    vrItemPedido.nPTABELA := vtIncluiItens(viNumSeq).vnPrecoFixo;
                    -- Zera o Desconto para que o PVenda fique igual ao PTabela
                    vrItemPedido.nPERDESC := 0;
                  END IF;
                END IF;
              END IF;

            --END IF;

            ------------------------------------
            -- DEFINIÇÃO DO PREÇO DE VENDA
            ------------------------------------

            -- RECUPERAÇÃO DE ORÇAMENTO - Preço Tabela no momento da Gravação do Orçamento
            IF (pi_nTipoChamada IN (11)) THEN
            
              -- DDVENDAS-32472 - Preço de Tabela baseado no Contrato Negociado no Orçamento
              IF (NVL(vtIncluiItens(viNumSeq).vnPtabelaContrato,0) > 0) THEN
                vrItemPedido.nPTABELA := NVL(vtIncluiItens(viNumSeq).vnPtabelaContrato,0);
                P_INSERE_LOG(viLacoValidar, 'vnPtabelaContrato: ' || vrItemPedido.nPTABELA);
              END IF;

              -- Preço de Venda = Preço Liquido Negociado no Orçamento
              vrItemPedido.nPVENDA := vtIncluiItens(viNumSeq).vnPrecoFixo;
              -- Refaz o Percentual de Desconto para o Preço de Tabela Atual x Preço de Venda do Orçamento
              IF (NVL(vrItemPedido.nPTABELA,0) <> 0) THEN
                vrItemPedido.nPERDESC := ((NVL(vrItemPedido.nPTABELA,0) - NVL(vrItemPedido.nPVENDA,0)) / NVL(vrItemPedido.nPTABELA,0)) * 100;
              ELSE
                vrItemPedido.nPERDESC := 0;
              END IF;

            -- DEMAIS CASOS
            ELSE

              -- Inicializa o Preço de Venda a partir do Preço de Tabela
              vrItemPedido.nPVENDA := vrItemPedido.nPTABELA;
              -- Aplica o Desconto SEM ARREDONDAR
              vrItemPedido.nPVENDA := (vrItemPedido.nPVENDA * (1 - (NVL(vrItemPedido.nPERDESC,0) / 100)));

            END IF;

            ----------------------------------
            -- PCNIL - CÁLCULO DO VALOR DO IPI
            ----------------------------------
            IF (NVL(vrParamFilial.vCALCULARIPIVENDA,'N') = 'S') AND  -->> Se a Filial Calcula IPI
               (NVL(vrClienteDestino.nISENTOIPI,'N')     = 'N') THEN -->> Se o Cliente não for Isento do IPI

              -- INICIALIZA VARIÁVEL DE CÁLCULO DO VALOR DO IPI
              vnVLIPI_pvenda  := 0;

              -- Retira o IPI do novo Preço de VENDA LIQUIDO com as Taxas para chegar ao novo Preço sem o IPI
              --vnPVENDA_SEMIPI := ((NVL(vrItemPedido.nPTABELA,0) * (1 - (NVL(vrItemPedido.nPERDESC,0) / 100))) / (1 + (NVL(vrProduto_O.nPERCIPIVENDA, 0) / 100)));
              vnPVENDA_SEMIPI := (NVL(vrItemPedido.nPVENDA,0) / (1 + (NVL(vrProduto_O.nPERCIPIVENDA, 0) / 100))); -->> Tive que usar diretamente o PVENDA, por causa do Orçamento (garantir o PVENDA Liquido)
              -- Arredonda para as casas decimais do Preço de Venda para bater com a 2316
              vnPVENDA_SEMIPI := ROUND(vnPVENDA_SEMIPI, vrParamFilial.nCON_NUMCASASDECVENDA);

              -----------------------------------------------------------
              --Autor: Rodrigo Santos
              --Solicitação: HIS.01467.2015
              --Data: 05/05/2015
              --Descrição: Implementação do redutor da alíquota de IPI,
              -- quando o parâmetro abaixo for informado (p_percredaliqipi > 0)
              -- assume que PCPRODUT.APLICAPERCREDALIQIPI = 'S', logo a aplicação
              -- da redução deve ser controlada pela passagem deste parâmetro.
              -- Ou seja, SE "p_percredaliqipi > 0" então PCPRODUT.APLICAPERCREDALIQIPI = 'S',
              -- ou SE "p_percredaliqipi = 0" então PCPRODUT.APLICAPERCREDALIQIPI = 'N'
              -----------------------------------------
              -- MEDICAMENTOS: SEM APLICAÇÃO DA REDUÇÃO
              -----------------------------------------
              --IF nvl(p_percredaliqipi,0) > 0 THEN
              --  vnPERCIPI_REDUZIDO := nvl(P_PERCIPIVENDA - (P_PERCIPIVENDA * (p_percredaliqipi / 100)),0);
              --ELSE
              vnPERCIPI_REDUZIDO := NVL(vrProduto_O.nPERCIPIVENDA,0);
              --END IF;
              -----------------------------------------------------------

              -- Se IPI por Pauta
              IF (NVL(vrProduto_O.nVLPAUTAIPIVENDA,0) > 0) THEN
                vnVLIPI_pvenda            := vrProduto_O.nVLPAUTAIPIVENDA;
                vrProduto_O.nPERCIPIVENDA := 0;
              END IF;

              -- Se tiver Percentual de IPI
              IF (NVL(vnPERCIPI_REDUZIDO,0) > 0) THEN

                vnVLIPI_pvenda            := vnPVENDA_SEMIPI * (vnPERCIPI_REDUZIDO / 100);
                vrProduto_O.nPERCIPIVENDA := vnPERCIPI_REDUZIDO;

              END IF;

              -- Regra de Arredondamento do IPI
              -- Se não for uma das condições mantem todas as casas decimais
              IF    (vrPcConsum.vTIPOCALCIPI = 'T2') THEN
                vnvlipi_pvenda := TRUNC(vnvlipi_pvenda * 100) / 100;
              ELSIF (vrPcConsum.vTIPOCALCIPI = 'A2') THEN
                vnvlipi_pvenda := ROUND(vnvlipi_pvenda, 2);
              ELSIF (vrPcConsum.vTIPOCALCIPI = 'PV') THEN
                vnvlipi_pvenda := ROUND(vnvlipi_pvenda, vrParamFilial.nCON_NUMCASASDECVENDA);
              END IF;

            ELSE

              vnVLIPI_pvenda            := 0;
              vrProduto_O.nPERCIPIVENDA := 0;

            END IF;

            -- FINALIZAÇÃO DO IPI NO ITEM DO PEDIDO
            vrItemPedido.nPERCIPI := NVL(vrProduto_O.nPERCIPIVENDA,0);
            vrItemPedido.nVLIPI   := NVL(vnvlipi_pvenda,0);

           /********************************************
            SE PODE CONTINUAR O PROCESSAMENTO DO PRODUTO
            ********************************************/
            IF (vbPodeProcessarProduto) THEN

              ------------------------------------
              -- DEFINIÇÃO DA BONIFICAÇÃO NA VENDA
              ------------------------------------

              -- Percentual de Bonificação na Venda
              IF (NVL(vrParamFilial.vUTILIZAPERCBONIFIVENDAREGIAO,'N') = 'S') THEN
                vrItemPedido.nPERBONIFIC := vrTabPreco.nPERCBONIFICVENDA;
              ELSE
                vrItemPedido.nPERBONIFIC := vrProduto_O.nPERCBONIFICVENDA;
              END IF;
              -- Valor de Bonificação na Venda
              vrItemPedido.nVLBONIFIC := (NVL(vrItemPedido.nPTABELA,0) * (NVL(vrItemPedido.nPERBONIFIC,0)/100)) ;

              -- Se Promoção por Preço Fábrica não pode ter Bonificação na Venda
              IF (vvOrigemPrecoPromocao = 'F') THEN
                vrItemPedido.nPERBONIFIC := 0;
                vrItemPedido.nVLBONIFIC  := 0;
              END IF;

             /*
              Anderson - Já definiu a tributação mais acima
              ------------------------
              -- TRIBUTACÃO DO PRODUTO
              ------------------------
              IF (NVL(vrItemPedido.nCODST,0) = 0) THEN

                -- Se utiliza Tributação por UF, pesquisa na Tabela de Tributação por UF o Código da Tributação
                IF (NVL(vrPcConsum.vUSATRIBUTACAOPORUF,'N') = 'S') THEN
                  BEGIN
                    SELECT PCTABTRIB.CODST
                      INTO vrItemPedido.nCODST
                      FROM PCTABTRIB
                     WHERE (PCTABTRIB.CODPROD     = vrItemPedido.nCODPROD)
                       AND (PCTABTRIB.CODFILIALNF = NVL(pi_vCodFilialNf,pi_vCodFilial)) -->> Tributação na Filial NF ou de Origem
                       AND (PCTABTRIB.UFDESTINO   = vrClienteDestino.vESTENT);          -->> Para a UF do Cliente
                  EXCEPTION
                    WHEN NO_DATA_FOUND THEN
                      -- Rejeita
                      po_vMotivoNaoPodeGravar := 'Não foi encontrada a tributação do Produto '      || NVL(vrItemPedido.nCODPROD,0) ||
                                                 ' na filial de origem ' || NVL(pi_vCodFilial,' ')  ||
                                                 ' para a UF ' || NVL(vrClienteDestino.vESTENT,' ') || ' para inclusão do KIT!';
                      RAISE e_Tratado;
                  END;
                -- Se NÃO utiliza Tributação por UF, utiliza o Código da Tributação da Tabela de Preços
                ELSE
                  vrItemPedido.nCODST := vrTabPreco.nCODST;
                END IF;

              END IF; -- Fim Condição se ainda não pesquisou a Tributação
              */

              -- OBTEM PMC
              vrItemPedido.nPRECOMAXCONSUM := vnPrecoMaxConsum; -->> Pesquisado mais acima no procedimento PKG_MEDICAMENTOS.P_OBTEM_PMC_PRODUTO
             /*
              PKG_MEDICAMENTOS.P_OBTEM_PMC_PRODUTO(pi_vCodFilial,
                                        vrItemPedido.nCODPROD,
                                        vrClienteDestino.vESTENT,
                                        vrRegiao.nNUMREGIAO,
                                        vrItemPedido.nPRECOMAXCONSUM,
                                        vnPrecoFabrica,
                                        vvMensagemRetornoPMC);
              IF (vvMensagemRetornoPMC IS NOT NULL) THEN
                -- Rejeita
                po_vMotivoNaoPodeGravar := 'Problemas ao pesquisar o PMC do Produto '         || NVL(vrItemPedido.nCODPROD,0) ||
                                           ' para a UF ' || NVL(vrClienteDestino.vESTENT,' ') || ' para inclusão do KIT: '    || vvMensagemRetornoPMC;
                RAISE e_Tratado;
              END IF;
              */

              IF (vrTribut.nCODICMTABPF IS NULL) THEN
                vrTribut.bCODICMTABPF_ISNULL := TRUE;
              ELSE
                vrTribut.bCODICMTABPF_ISNULL := FALSE;
              END IF;

              -- Validação Consignado Substituição Tributária - 0.018263.2016
              IF (pi_nCondVenda = 20) AND
                 ((vrTribut.vSITTRIBUT = '10') OR
                  (vrTribut.vSITTRIBUT = '70')) THEN
                -- Informações de Produto Bloqueado para a Campanha -- HIS.01889.2017
                IF (pi_nTipoChamada = 13) THEN
                  vrItemPedido.vBLOQUEIOCAMPANHA       := 'S';
                  vrItemPedido.vMOTIVOBLOQUEIOCAMPANHA := 'Produto ' || NVL(vrItemPedido.nCODPROD,0) || ' com ICMS de Subst. Tributária não pode ser vendido em consignação (TV20).' || CHR(13) ||
                                                          'CST não permitida em Consignado: 10 e 70. Verifique a Tributação ' || NVL(vrItemPedido.nCODST,0) || '.';
                ELSE
                  -- Rejeita
                  po_vMotivoNaoPodeGravar := 'Produto ' || NVL(vrItemPedido.nCODPROD,0) || ' com ICMS de Subst. Tributária não pode ser vendido em consignação (TV20).' || CHR(13) ||
                                             'CST não permitida em Consignado: 10 e 70. Verifique a Tributação ' || NVL(vrItemPedido.nCODST,0) || '.';
                  RAISE e_Tratado;
                END IF;
              END IF;

              -- Guarda Composição do Imposto que será gravado nos Itens do Pedido
              vrItemPedido.nIVA           := vrTribut.nIVA;
              vrItemPedido.nPAUTA         := vrTribut.nPAUTA;
              vrItemPedido.nALIQICMS1     := vrTribut.nALIQICMS1;
              vrItemPedido.nALIQICMS2     := vrTribut.nALIQICMS2;
              vrItemPedido.nPERCBASEREDST := vrTribut.nPERCBASEREDST;

              ----------------------------------------------------------------------------
              -- CÁLCULO DO REPASSE ANTES DE ARREDONDAR O PVENDA [Tarefa 4348.117705.2014]
              -- (Não soma o Repasse aqui para não afetar o C/C
              ----------------------------------------------------------------------------

              -- Inicializa Valores
              vrItemPedido.nVLREPASSE := 0;
              vrItemPedido.nVLOUTROS  := 0;

              if pi_nCondVenda = 1 then

                if vrProduto_O.vTIPOMERC in ('M','MA','L') and vrClienteDestino.vREPASSE = 'S' then

                  -- Pesquisa o Tipo de Aplicação do Repasse dos Parâmetros por Filial
                  POBTEM_PARAMFILIAL_STRING(pi_vCodFilial,
                                            'TIPOAPLICREPASSEFILIAL',
                                            vrParamFilial.vTIPOAPLICREPASSEFILIAL,
                                            vvErroPesqParam,
                                            vvMsgErroPesqParam);

                  -- Tipo de Aplicação do Repasse = Acréscimo sobre Preço Fábrica
                  if     (nvl(vrParamFilial.vTIPOAPLICREPASSEFILIAL,'AB') = 'AB') then
                     vrItemPedido.nVLREPASSE  := vrItemPedido.nPORIGINAL * (vrTribut.nPERDESCREPASSE/100);
                     vrItemPedido.nVLOUTROS   := vrItemPedido.nVLREPASSE;
                  -- Tipo de Aplicação do Repasse = Acréscimo ST Ult Ent - HIS.03788.2015
                  elsif  (nvl(vrParamFilial.vTIPOAPLICREPASSEFILIAL,'AB') = 'AS') then
                     -- Se usabcrultent
                     IF (NVL(vrTribut.vUSABCRULTENT,'N') = 'S')             AND
                        (NVL(vrClienteDestino.vCONSUMIDORFINAL,'N') <> 'S') THEN
                       vrItemPedido.nVLREPASSE := NVL(vrCustoProduto_O.nSTBCR,0);
                       vrItemPedido.nVLOUTROS  := vrItemPedido.nVLREPASSE;
                       -- Se não achou o ST BCR
                       IF (NVL(vrItemPedido.nVLREPASSE,0) <= 0) THEN
                         -- Informações de Produto Bloqueado para a Campanha -- HIS.01889.2017
                         IF (pi_nTipoChamada = 13) THEN
                           vrItemPedido.vBLOQUEIOCAMPANHA       := 'S';
                           vrItemPedido.vMOTIVOBLOQUEIOCAMPANHA := 'Produto ' || NVL(vtIncluiItens(viNumSeq).vnCodProd,0) || ' sem STBCR para cálculo do repasse';
                         ELSE
                           -- Rejeita
                           po_vMotivoNaoPodeGravar := 'Produto ' || NVL(vtIncluiItens(viNumSeq).vnCodProd,0) || ' sem STBCR para cálculo do repasse';
                           RAISE e_Tratado;
                         END IF;
                       END IF;
                     END IF; -- Fim Condição: usabcrultent
                  -- Tipo de Aplicação do Repasse = Acréscimo sobre Preço Liquido
                  elsif (nvl(vrParamFilial.vTIPOAPLICREPASSEFILIAL,'AB') = 'AL') then
                     vrItemPedido.nVLREPASSE := vrItemPedido.nPVENDA * (vrTribut.nPERDESCREPASSE/100);
                     vrItemPedido.nVLOUTROS  := vrItemPedido.nVLREPASSE;
                  end if;

                end if;
              end if;

              -- ARREDONDA O PREÇO DE VENDA --
              --------------------------------
              vrItemPedido.nPVENDA     := ROUND(vrItemPedido.nPVENDA, vrParamFilial.nCON_NUMCASASDECVENDA);

              --------------------------------------
              -- CONTA-CORRENTE DO RCA
              --------------------------------------

              -- SE USA PROMOÇÃO
              IF    (NVL(vrItemPedido.nCODPROMOCAOMED,0) > 0) THEN

                -- Pesquisa Dados da Promoção pelo CÓD. PROMOÇÃO + CÓD. DESCONTO
                IF (NVL(vrItemPedido.nCODDESCONTO,0) > 0) THEN
                  BEGIN
                    SELECT PCDESCONTO.PERCDESC
                         , PCDESCONTO.BASECREDDEBRCA
                         , PCDESCONTO.CREDITASOBREPOLITICA
                         , PCPROMOCAOMED.UTILIZAPERCDESCBASERCA
                         , PCDESCONTO.PERCDESCBASERCA
                         , PCDESCONTO.PERCMARKUPMED   -- MED-2634
                         , PCPROMOCAOMED.TIPOPOLITICA -- MED-2634
                         , PCPROMOCAOMED.TIPOPROMOCAO -- DDVENDAS-36806
                      INTO vrDadosPromocaoAtual.vnPerDesc
                         , vrDadosPromocaoAtual.vvBaseCredDebRca
                         , vrDadosPromocaoAtual.vvCreditaSobrePolitica
                         , vrDadosPromocaoAtual.vvUtilizaPercDescBaseRca
                         , vrDadosPromocaoAtual.vnPercDescBaseRCA
                         , vrDadosPromocaoAtual.vnPercMarkup   -- MED-2634
                         , vrDadosPromocaoAtual.vvTipoPolitica -- MED-2634
                         , vrDadosPromocaoAtual.vvTipoPromocao -- DDVENDAS-36806
                      FROM PCDESCONTO
                         , PCPROMOCAOMED
                     WHERE (PCDESCONTO.CODPROMOCAOMED = PCPROMOCAOMED.CODPROMOCAOMED)
                       AND (PCDESCONTO.CODPROMOCAOMED = vrItemPedido.nCODPROMOCAOMED)
                       AND (PCDESCONTO.CODDESCONTO    = vrItemPedido.nCODDESCONTO)
                       AND (ROWNUM                    = 1);
                  EXCEPTION
                    WHEN NO_DATA_FOUND THEN
                      -- 4493.105417.2016
                      BEGIN
                        SELECT PCLOGPROMOCAODESCONTOMED.PERCDESC
                             , PCLOGPROMOCAODESCONTOMED.BASECREDDEBRCA
                             , PCLOGPROMOCAODESCONTOMED.CREDITASOBREPOLITICA
                             , PCPROMOCAOMED.UTILIZAPERCDESCBASERCA
                             , PCLOGPROMOCAODESCONTOMED.PERCDESCBASERCA
                             , PCLOGPROMOCAODESCONTOMED.PERCMARKUPMED -- MED-2634
                             , PCPROMOCAOMED.TIPOPOLITICA  -- MED-2634
                             , PCPROMOCAOMED.TIPOPROMOCAO -- DDVENDAS-36806
                          INTO vrDadosPromocaoAtual.vnPerDesc
                             , vrDadosPromocaoAtual.vvBaseCredDebRca
                             , vrDadosPromocaoAtual.vvCreditaSobrePolitica
                             , vrDadosPromocaoAtual.vvUtilizaPercDescBaseRca
                             , vrDadosPromocaoAtual.vnPercDescBaseRCA
                             , vrDadosPromocaoAtual.vnPercMarkup   -- MED-2634
                             , vrDadosPromocaoAtual.vvTipoPolitica -- MED-2634
                             , vrDadosPromocaoAtual.vvTipoPromocao -- DDVENDAS-36806
                          FROM PCLOGPROMOCAODESCONTOMED
                             , PCPROMOCAOMED
                         WHERE (PCLOGPROMOCAODESCONTOMED.CODPROMOCAOMED = PCPROMOCAOMED.CODPROMOCAOMED)
                           AND (PCLOGPROMOCAODESCONTOMED.CODPROMOCAOMED = vrItemPedido.nCODPROMOCAOMED)
                           AND (PCLOGPROMOCAODESCONTOMED.CODDESCONTO    = vrItemPedido.nCODDESCONTO)
                           AND (ROWNUM                    = 1);
                      EXCEPTION
                        WHEN NO_DATA_FOUND THEN
                          -- MED-2634: IR NO LOG DA PROMOÇÃO
                          BEGIN
                            SELECT PCLOGPROMOCAODESCONTOMED.PERCDESC
                                 , PCLOGPROMOCAODESCONTOMED.BASECREDDEBRCA
                                 , PCLOGPROMOCAODESCONTOMED.CREDITASOBREPOLITICA
                                 , PCLOGPROMOCAOMED.UTILIZAPERCDESCBASERCA
                                 , PCLOGPROMOCAODESCONTOMED.PERCDESCBASERCA
                                 , PCLOGPROMOCAODESCONTOMED.PERCMARKUPMED   -- MED-2634
                                 , PCLOGPROMOCAOMED.TIPOPOLITICA -- MED-2634
                                 , PCLOGPROMOCAOMED.TIPOPROMOCAO -- DDVENDAS-36806
                              INTO vrDadosPromocaoAtual.vnPerDesc
                                 , vrDadosPromocaoAtual.vvBaseCredDebRca
                                 , vrDadosPromocaoAtual.vvCreditaSobrePolitica
                                 , vrDadosPromocaoAtual.vvUtilizaPercDescBaseRca
                                 , vrDadosPromocaoAtual.vnPercDescBaseRCA
                                 , vrDadosPromocaoAtual.vnPercMarkup   -- MED-2634
                                 , vrDadosPromocaoAtual.vvTipoPolitica -- MED-2634
                                 , vrDadosPromocaoAtual.vvTipoPromocao -- DDVENDAS-36806
                              FROM PCLOGPROMOCAODESCONTOMED
                                 , PCLOGPROMOCAOMED
                             WHERE (PCLOGPROMOCAODESCONTOMED.CODPROMOCAOMED = PCLOGPROMOCAOMED.CODPROMOCAOMED)
                               AND (PCLOGPROMOCAODESCONTOMED.CODPROMOCAOMED = vrItemPedido.nCODPROMOCAOMED)
                               AND (PCLOGPROMOCAODESCONTOMED.CODDESCONTO    = vrItemPedido.nCODDESCONTO)
                               AND (ROWNUM                    = 1);
                          EXCEPTION
                            WHEN NO_DATA_FOUND THEN
                          vrDadosPromocaoAtual.vnPerDesc                := 0;
                          vrDadosPromocaoAtual.vvBaseCredDebRca         := 'N';
                          vrDadosPromocaoAtual.vvCreditaSobrePolitica   := 'N';
                          vrDadosPromocaoAtual.vvUtilizaPercDescBaseRca := 'N';
                          vrDadosPromocaoAtual.vnPercDescBaseRCA        := 0;
                              vrDadosPromocaoAtual.vnPercMarkup             := 0; -- MED-2634
                              vrDadosPromocaoAtual.vvTipoPolitica           := NULL; -- DDVENDAS-36806
                              vrDadosPromocaoAtual.vvTipoPromocao           := NULL; -- DDVENDAS-36806
                         END;
                      END;
                  END;
                -- Pesquisa Dados da Promoção somente pelo CÓD. PROMOÇÃO (Case de Promoção com Desconto Zerado)
                ELSE
                  BEGIN
                    SELECT PCDESCONTO.PERCDESC
                         , PCDESCONTO.BASECREDDEBRCA
                         , PCDESCONTO.CREDITASOBREPOLITICA
                         , PCPROMOCAOMED.UTILIZAPERCDESCBASERCA
                         , PCDESCONTO.PERCDESCBASERCA
                         , PCDESCONTO.PERCMARKUPMED   -- MED-2634
                         , PCPROMOCAOMED.TIPOPOLITICA -- MED-2634
                         , PCPROMOCAOMED.TIPOPROMOCAO -- DDVENDAS-36806
                      INTO vrDadosPromocaoAtual.vnPerDesc
                         , vrDadosPromocaoAtual.vvBaseCredDebRca
                         , vrDadosPromocaoAtual.vvCreditaSobrePolitica
                         , vrDadosPromocaoAtual.vvUtilizaPercDescBaseRca
                         , vrDadosPromocaoAtual.vnPercDescBaseRCA
                         , vrDadosPromocaoAtual.vnPercMarkup   -- MED-2634
                         , vrDadosPromocaoAtual.vvTipoPolitica -- MED-2634
                         , vrDadosPromocaoAtual.vvTipoPromocao -- DDVENDAS-36806
                      FROM PCDESCONTO
                         , PCPROMOCAOMED
                     WHERE (PCDESCONTO.CODPROMOCAOMED = PCPROMOCAOMED.CODPROMOCAOMED)
                       AND (PCDESCONTO.CODPROMOCAOMED = vrItemPedido.nCODPROMOCAOMED)
                       AND (ROWNUM                    = 1);
                  EXCEPTION
                    WHEN NO_DATA_FOUND THEN
                      vrDadosPromocaoAtual.vnPerDesc                := 0;
                      vrDadosPromocaoAtual.vvBaseCredDebRca         := 'N';
                      vrDadosPromocaoAtual.vvCreditaSobrePolitica   := 'N';
                      vrDadosPromocaoAtual.vvUtilizaPercDescBaseRca := 'N';
                      vrDadosPromocaoAtual.vnPercDescBaseRCA        := 0;
                      vrDadosPromocaoAtual.vnPercMarkup             := 0;    -- MED-2634
                      vrDadosPromocaoAtual.vvTipoPolitica           := NULL; -- MED-2634
                      vrDadosPromocaoAtual.vvTipoPromocao           := NULL; -- DDVENDAS-36806
                  END;
                END IF;

                -- Log do Item
               IF (pi_nTipoChamada IN (2,10,11,15
                                      ,16 -- ITENS CROSS DOCKING [16] - MED-1096
                                      ,17
                                      )) THEN
                  P_INSERE_LOG(viLacoValidar, 'PBASERCA Promocão: '                 || vrItemPedido.nCODPROMOCAOMED);
                  P_INSERE_LOG(viLacoValidar, 'PBASERCA vnPerDesc: '                || vrDadosPromocaoAtual.vnPerDesc);
                  P_INSERE_LOG(viLacoValidar, 'PBASERCA vvBaseCredDebRca: '         || vrDadosPromocaoAtual.vvBaseCredDebRca);
                  P_INSERE_LOG(viLacoValidar, 'PBASERCA vvCreditaSobrePolitica: '   || vrDadosPromocaoAtual.vvCreditaSobrePolitica);
                  P_INSERE_LOG(viLacoValidar, 'PBASERCA vvUtilizaPercDescBaseRca: ' || vrDadosPromocaoAtual.vvUtilizaPercDescBaseRca);
                  P_INSERE_LOG(viLacoValidar, 'PBASERCA vnPercDescBaseRCA: '        || vrDadosPromocaoAtual.vnPercDescBaseRCA);
                  P_INSERE_LOG(viLacoValidar, 'PBASERCA vnPercMarkup: '             || vrDadosPromocaoAtual.vnPercMarkup);   -- MED-2634
                  P_INSERE_LOG(viLacoValidar, 'PBASERCA vvTipoPolitica: '           || vrDadosPromocaoAtual.vvTipoPolitica); -- MED-2634
                  P_INSERE_LOG(viLacoValidar, 'PBASERCA vvTipoPromocao: '           || vrDadosPromocaoAtual.vvTipoPromocao); -- DDVENDAS-36806
                END IF;

                -- MED-2634: SE MARKUP PRECISA CALCULAR O PERCENTUAL DE DESCONTO PARA O MARKUP CADASTRADO
                IF (vrDadosPromocaoAtual.vvTipoPromocao = 'R') THEN -- DDVENDAS-36806

                  vnPrecoTabelaMarkup := vrItemPedido.nPVENDA1BASEPROMOMARKUP; -- DDMEDICA-249

                  IF NVL(vrDadosPromocaoAtual.vnPercMarkup,0) = 0 THEN
                      vrDadosPromocaoAtual.vnPerDesc   := 0;
                  ELSE
                      IF (NVL(vrCustoProduto_O.nCUSTOFIN,0) = 0) THEN
                        -- 0.018397.2016 - Não carregar desconto da promoção markup com custo zero
                        vrDadosPromocaoAtual.vnPerDesc := 0;
                      ELSE
                        vnPrecoVendaMarkup             := NVL(vrCustoProduto_O.nCUSTOFIN,0) * (1+(NVL(vrDadosPromocaoAtual.vnPercMarkup,0) * 0.01));
                        vrDadosPromocaoAtual.vnPerDesc := (1-(vnPrecoVendaMarkup/vnPrecoTabelaMarkup))*100;
                      END IF;
                  END IF;
                  vrDadosPromocaoAtual.vnPercDescBaseRCA := vrDadosPromocaoAtual.vnPerDesc;

                  -- Log do Item
                  IF (pi_nTipoChamada IN (2,10,11,15
                                         ,16 -- ITENS CROSS DOCKING [16] - MED-1096
                                         ,17
                                         )) THEN
                     P_INSERE_LOG(viLacoValidar, 'PBASERCA vnPrecoTabelaMarkup: ' || vnPrecoTabelaMarkup);
                     P_INSERE_LOG(viLacoValidar, 'PBASERCA vnPrecoVendaMarkup: '  || vnPrecoVendaMarkup);
                     P_INSERE_LOG(viLacoValidar, 'PBASERCA vnPerDesc: '           || vrDadosPromocaoAtual.vnPerDesc);
                     P_INSERE_LOG(viLacoValidar, 'PBASERCA vnPercDescBaseRCA: '   || vrDadosPromocaoAtual.vnPercDescBaseRCA);
                   END IF;
                END IF;

              -- SE USA POLÍTICA
              ELSIF (NVL(vrItemPedido.nCODDESCONTO,0) > 0) THEN

                -- Pesquisa Dados da Política
                BEGIN
                  SELECT PCDESCONTO.PERCDESC
                       , PCDESCONTO.BASECREDDEBRCA
                       , PCDESCONTO.CREDITASOBREPOLITICA
                       , 'N' UTILIZAPERCDESCBASERCA
                       , PCDESCONTO.PERCDESCBASERCA
                    INTO vrDadosPromocaoAtual.vnPerDesc
                       , vrDadosPromocaoAtual.vvBaseCredDebRca
                       , vrDadosPromocaoAtual.vvCreditaSobrePolitica
                       , vrDadosPromocaoAtual.vvUtilizaPercDescBaseRca
                       , vrDadosPromocaoAtual.vnPercDescBaseRCA
                    FROM PCDESCONTO
                   WHERE (PCDESCONTO.CODDESCONTO = vrItemPedido.nCODDESCONTO)
                     AND (ROWNUM                 = 1);
                EXCEPTION
                  WHEN NO_DATA_FOUND THEN
                    vrDadosPromocaoAtual.vnPerDesc                := 0;
                    vrDadosPromocaoAtual.vvBaseCredDebRca         := 'N';
                    vrDadosPromocaoAtual.vvCreditaSobrePolitica   := 'N';
                    vrDadosPromocaoAtual.vvUtilizaPercDescBaseRca := 'N';
                    vrDadosPromocaoAtual.vnPercDescBaseRCA        := 0;
                END;

                -- Log do Item
                IF (pi_nTipoChamada IN (2,10,11,15
                                       ,16 -- ITENS CROSS DOCKING [16] - MED-1096
                                       ,17
                                       )) THEN
                  P_INSERE_LOG(viLacoValidar, 'PBASERCA Política: '                || vrItemPedido.nCODDESCONTO);
                  P_INSERE_LOG(viLacoValidar, 'PBASERCA vnPerDesc: '                || vrDadosPromocaoAtual.vnPerDesc);
                  P_INSERE_LOG(viLacoValidar, 'PBASERCA vvBaseCredDebRca: '         || vrDadosPromocaoAtual.vvBaseCredDebRca);
                  P_INSERE_LOG(viLacoValidar, 'PBASERCA vvCreditaSobrePolitica: '   || vrDadosPromocaoAtual.vvCreditaSobrePolitica);
                  P_INSERE_LOG(viLacoValidar, 'PBASERCA vvUtilizaPercDescBaseRca: ' || vrDadosPromocaoAtual.vvUtilizaPercDescBaseRca);
                  P_INSERE_LOG(viLacoValidar, 'PBASERCA vnPercDescBaseRCA: '        || vrDadosPromocaoAtual.vnPercDescBaseRCA);
                END IF;

              -- SEM PROMOÇÃO E SEM POLÍTICA
              ELSE

                vrDadosPromocaoAtual.vnPerDesc                := 0;
                vrDadosPromocaoAtual.vvBaseCredDebRca         := 'N';
                -- MED-851 - Para ficar igual à 2316, se não vinculou promoção no item, mas pedido de promoção, o padrão é Credita
                IF (NVL(pi_nCodPromocaoMedPedido,0) > 0) THEN
                  vrDadosPromocaoAtual.vvCreditaSobrePolitica := 'S';
                ELSE
                  vrDadosPromocaoAtual.vvCreditaSobrePolitica := 'N';
                END IF;
                vrDadosPromocaoAtual.vvUtilizaPercDescBaseRca := 'N';
                vrDadosPromocaoAtual.vnPercDescBaseRCA        := 0;

                -- Log do Item
                IF (pi_nTipoChamada IN (2,10,11,15
                                       ,16 -- ITENS CROSS DOCKING [16] - MED-1096
                                       ,17
                                       )) THEN
                  P_INSERE_LOG(viLacoValidar, 'PBASERCA SEM Promoção');
                  P_INSERE_LOG(viLacoValidar, 'PBASERCA vnPerDesc: '                || vrDadosPromocaoAtual.vnPerDesc);
                  P_INSERE_LOG(viLacoValidar, 'PBASERCA vvBaseCredDebRca: '         || vrDadosPromocaoAtual.vvBaseCredDebRca);
                  P_INSERE_LOG(viLacoValidar, 'PBASERCA vvCreditaSobrePolitica: '   || vrDadosPromocaoAtual.vvCreditaSobrePolitica);
                  P_INSERE_LOG(viLacoValidar, 'PBASERCA vvUtilizaPercDescBaseRca: ' || vrDadosPromocaoAtual.vvUtilizaPercDescBaseRca);
                  P_INSERE_LOG(viLacoValidar, 'PBASERCA vnPercDescBaseRCA: '        || vrDadosPromocaoAtual.vnPercDescBaseRCA);
                END IF;

              END IF;

             /*
              -- Obtém Desconto da PROMOÇÃO DO ITEM DO PEDIDO
              PRC_MED_OBTEM_DESC_TELEVENDAS(2,                        -->> Obter as Promoções
                                            pi_nCodPromocaoMedPedido, -->> Nova Promoção
                                            vtIncluiItens(viNumSeq).vnCodProd,
                                            NULL,                     -->> Não precisa passar pi_nCodCondicaoVenda
                                            pi_nCodCli,
                                            vtIncluiItens(viNumSeq).vnQtde,
                                            TRUNC(SYSDATE),
                                            pi_vCodFilial,
                                            vrClienteDestino.nCODPRACA,
                                            vrRegiao.nNUMREGIAO,
                                            pi_nCodUsur,
                                            vrDadosPedidoAtual.vORIGEMPED,
                                            'TL',
                                            vnCodPlPagProduto,        -->> PESQUISAR PELO CÓDIGO DO PLANO DE PAGAMENTO DO PRODUTO
                                            vrClienteDestino.vCLASSEVENDA,
                                            'N',  -->> Não usa Política Prioritária
                                            vrItemPedido.nCODPROMOCAOMED, -->> OBTER O DESCONTO DA PROMOÇÃO DO ITEM DO PEDIDO
                                            pi_vVisualizarPromoBloq,
                                            'S',  -->> Se chamou a procedure para atualizar a promoção, é porque já teve a permissão para escolher a nova promoção que passou no parâmetro na ObtemSelPromocao
                                            vrItemPedido.nPTABELA,
                                            vrItemPedido.nVLCUSTOFIN,
                                            vrDadosPromocaoAtual.vnPerDesc,
                                            vrDadosPromocaoAtual.vnPerBonific,
                                            vrDadosPromocaoAtual.vnPerComerc,
                                            vrDadosPromocaoAtual.vnPerBoleto,
                                            vrDadosPromocaoAtual.vnPercDescFin,
                                            vrDadosPromocaoAtual.vnCodLinhaPrazo,
                                            vrDadosPromocaoAtual.vvOcorreramErros,
                                            vrDadosPromocaoAtual.vvMsgErros);

              -- Pesquisa Dados da Promoção (TODAS AS INFORMAÇÕES INCLUSIVE O % DESCONTO COMERCIAL SERÁ DA PCMED_SELPROMOCAO)
              BEGIN
                SELECT PCMED_SELPROMOCAO.PERCDESC
                     , PCMED_SELPROMOCAO.BASECREDDEBRCA
                     , PCMED_SELPROMOCAO.CREDITASOBREPOLITICA
                     , PCMED_SELPROMOCAO.UTILIZAPERCDESCBASERCA
                     , PCMED_SELPROMOCAO.PERCDESCBASERCA
                  INTO vrDadosPromocaoAtual.vnPerDesc
                     , vrDadosPromocaoAtual.vvBaseCredDebRca
                     , vrDadosPromocaoAtual.vvCreditaSobrePolitica
                     , vrDadosPromocaoAtual.vvUtilizaPercDescBaseRca
                     , vrDadosPromocaoAtual.vnPercDescBaseRCA
                  FROM PCMED_SELPROMOCAO
                 WHERE (PCMED_SELPROMOCAO.CODPROMOCAOMED = vrItemPedido.nCODPROMOCAOMED)
                   AND (ROWNUM                           = 1);
              EXCEPTION
                WHEN NO_DATA_FOUND THEN
                  vrDadosPromocaoAtual.vnPerDesc                := 0;
                  vrDadosPromocaoAtual.vvBaseCredDebRca         := 'N';
                  vrDadosPromocaoAtual.vvCreditaSobrePolitica   := 'N';
                  vrDadosPromocaoAtual.vvUtilizaPercDescBaseRca := 'N';
                  vrDadosPromocaoAtual.vnPercDescBaseRCA        := 0;
              END;
              */

              -- Preço Aplicado o Desconto da Promoção
              vnPrecoAplicadoDescPolitica := NVL(vrItemPedido.nPTABELA,0) * (1 - (NVL(vrDadosPromocaoAtual.vnPerDesc,0) / 100));

              -- Pesquisa Número da Autorização de Preço - HIS.00961.2016
              BEGIN
                SELECT 'S'
                     , PCORIGEMPRECO.CODAUTORIZACAO
                  INTO vrOrigemPreco.vvAchouOrigemPreco
                     , vrOrigemPreco.vnCodAutorizacao
                  FROM PCORIGEMPRECO
                 WHERE (PCORIGEMPRECO.NUMPED  = pi_nNumPed)
                   AND (PCORIGEMPRECO.CODPROD = vrItemPedido.nCODPROD)
                   AND (PCORIGEMPRECO.NUMSEQ  = vrItemPedido.nNUMSEQ)
                   AND (ROWNUM                = 1);
              EXCEPTION
                WHEN NO_DATA_FOUND THEN
                  vrOrigemPreco.vvAchouOrigemPreco := 'N';
                  vrOrigemPreco.vnCodAutorizacao   := NULL;
              END;

              -- Pesquisa Dados da Autorização de Preço - HIS.00961.2016
              vrOrigemPreco.vvAchouAutoriPreco := 'N';
              IF (NVL(vrOrigemPreco.vvAchouOrigemPreco,'N')  = 'S') AND
                 (NVL(vrOrigemPreco.vnCodAutorizacao,0) > 0)        THEN
                BEGIN
                  SELECT 'S'
                       , NVL(PCAUTORI.BASECREDDEBRCA,'N')
                       , NVL(PCAUTORI.PERCDESCAUTOR,0)
                    INTO vrOrigemPreco.vvAchouAutoriPreco
                       , vrOrigemPreco.vvBaseCredDebRca
                       , vrOrigemPreco.vnPerdDescAutorizado
                    FROM PCAUTORI
                   WHERE (PCAUTORI.NRAUTORIZACAO = vrOrigemPreco.vnCodAutorizacao);
                EXCEPTION
                  WHEN NO_DATA_FOUND THEN
                    vrOrigemPreco.vvAchouAutoriPreco   := 'N';
                    vrOrigemPreco.vvBaseCredDebRca     := NULL;
                    vrOrigemPreco.vnPerdDescAutorizado := NULL;
                END;
              END IF;

              --------------------------------------------------------------------------
              -- DEFINIÇÃO da Base do RCA - Preço Autorizado Autorizado - HIS.00961.2016
              --------------------------------------------------------------------------
              IF (NVL(vrOrigemPreco.vvAchouAutoriPreco,'N') = 'S') THEN

                -- Recalcula o Preço Autorizado a partir do Desconto Autorizado (Arredonda em seguida igual à 2316)
                vrOrigemPreco.vnPrecoAutorizado := (vrItemPedido.nPTABELA - (vrItemPedido.nPTABELA * (NVL(vrOrigemPreco.vnPerdDescAutorizado,0) / 100)));
                vrOrigemPreco.vnPrecoAutorizado := ROUND(vrOrigemPreco.vnPrecoAutorizado , vrParamFilial.nCON_NUMCASASDECVENDA);

                -- Inicializa a Base do RCA com o Preço de Tabela
                vrItemPedido.nPBASERCA := NVL(vrItemPedido.nPTABELA,0);

                -- Se não Debita, iguala o PBASERCA com o PVENDA
                IF    (NVL(vrOrigemPreco.vvBaseCredDebRca,'N') = 'S') THEN
                  vrItemPedido.nPBASERCA := NVL(vrItemPedido.nPVENDA,0);
                  -- Log do Item
                  IF (pi_nTipoChamada IN (2,10,11,15
                                         ,16 -- ITENS CROSS DOCKING [16] - MED-1096
                                         ,17
                                         )) THEN
                    P_INSERE_LOG(viLacoValidar, 'PBASERCA Autorização "S": ' || vrItemPedido.nPBASERCA);
                  END IF;
                -- Se Preço Autorizado, atualiza o Preço Autorizado no PBASERCA
                ELSIF (NVL(vrOrigemPreco.vvBaseCredDebRca,'N') = 'A') THEN
                  vrItemPedido.nPBASERCA := NVL(vrOrigemPreco.vnPrecoAutorizado,0);
                  -- Log do Item
                  IF (pi_nTipoChamada IN (2,10,11,15
                                         ,16 -- ITENS CROSS DOCKING [16] - MED-1096
                                         ,17
                                         )) THEN
                    P_INSERE_LOG(viLacoValidar, 'PBASERCA Autorização "A": ' || vrItemPedido.nPBASERCA);
                  END IF;
                END IF;

              --------
              -- SENÃO
              --------
              ELSE

                --------------------------------------------------
                -- DEFINIÇÃO da Base do RCA - SEM PROMOÇÃO - PCNIL
                --------------------------------------------------
                IF (NVL(pi_nCodPromocaoMedPedido,0)     = 0) AND
                   (NVL(vrItemPedido.nCODPROMOCAOMED,0) = 0) THEN

                  -- Inicializa a Base do RCA
                  vrItemPedido.nPBASERCA := NVL(vrItemPedido.nPTABELA,0);
                  -- Log do Item
                  IF (pi_nTipoChamada IN (2,10,11,15
                                         ,16 -- ITENS CROSS DOCKING [16] - MED-1096
                                         ,17
                                         )) THEN
                    P_INSERE_LOG(viLacoValidar, 'PBASERCA Sem Promoção PTABELA: ' || vrItemPedido.nPBASERCA);
                  END IF;

                ------------------------------------------
                -- DEFINIÇÃO da Base do RCA - COM PROMOÇÃO
                ------------------------------------------
                ELSE

                  -- Desconto da Base do RCA - Se não tem desconto diferenciado para a Base RCA, utilizará o Desconto Comercial na Base do RCA
                  IF (NVL(vrDadosPromocaoAtual.vvUtilizaPercDescBaseRca,'N') <> 'S') THEN
                    vrDadosPromocaoAtual.vnPercDescBaseRCA := NVL(vrDadosPromocaoAtual.vnPerDesc,0);
                  END IF;

                  -- Regra Específica - Desconto da Base do RCA da Importação do Pedido do Força de Vendas
                  IF (FUtilizarPercDescBaseRCAOrigFv(vrDadosPedidoAtual.vORIGEMPED,
                                                     vrRegraMed.vUSARECALCULOPRECOTELEVENDAS,
                                                     vrItemPedido.vTIPOCOMISSAOMED)) THEN
                    vrDadosPromocaoAtual.vnPercDescBaseRCA := NVL(vrItemPedido.nPERCDESCBASERCA,0);
                  END IF;

                  -- Inicializa a Base do RCA
                  --//vnPERDESC_POLITICA_Base - Politica de desconto 561 - campo PCEDESCONTO.PERCDESC
                  IF (NVL(vrDadosPromocaoAtual.vnPercDescBaseRCA,0) <> 0) THEN
                    vrItemPedido.nPBASERCA := NVL(vrItemPedido.nPTABELA,0) * (1 - (NVL(vrDadosPromocaoAtual.vnPercDescBaseRCA,0) / 100));
                    -- Log do Item
                    IF (pi_nTipoChamada IN (2,10,11,15
                                           ,16 -- ITENS CROSS DOCKING [16] - MED-1096
                                           ,17
                                           )) THEN
                      P_INSERE_LOG(viLacoValidar, 'PercDescBaseRCA do PBASERCA: ' || vrDadosPromocaoAtual.vnPercDescBaseRCA);
                      P_INSERE_LOG(viLacoValidar, 'PBASERCA Promoção c/PercDescBaseRCA: ' || vrItemPedido.nPBASERCA);
                    END IF;
                  ELSE
                    vrItemPedido.nPBASERCA := NVL(vrItemPedido.nPTABELA,0);
                    -- Log do Item
                    IF (pi_nTipoChamada IN (2,10,11,15
                                           ,16 -- ITENS CROSS DOCKING [16] - MED-1096
                                           ,17
                                           )) THEN
                      P_INSERE_LOG(viLacoValidar, 'PBASERCA Promoção s/PercDescBaseRCA: ' || vrItemPedido.nPBASERCA);
                    END IF;
                  END IF;

                  -- Se Credita sobre Política
                  --IF (NVL(vrDadosPromocaoAtual.vnPerDesc,0) <> 0) AND
                  --   (NVL(vrItemPedido.nPVENDA,0) >= NVL(vrItemPedido.nPTABELA,0)) AND
                  --   (NVL(vrDadosPromocaoAtual.vvBaseCredDebRca,'N') = 'S') THEN
                  --  --//vsCreditaSobrePolitica - Politica de desconto 561 - campo PCEDESCONTO.CREDITASOBREPOLITICA
                  --  IF (NVL(vrDadosPromocaoAtual.vvCreditaSobrePolitica,'N') = 'N') THEN
                  --    vrItemPedido.nPBASERCA := NVL(vrItemPedido.nPVENDA,0);
                  --  ELSE
                  --    vrItemPedido.nPBASERCA := NVL(vnPrecoAplicadoDescPolitica,0);
                  --  END IF;
                  --END IF;

                  --// 4663.075505.2015 - Uso da Opção da 2323 Não Debitar Conta Corrente ao Conceder Desconto (PCEDESCONTO.BASECREDDEBRCA = 'S')
                  --// Uso do Parâmetro TIPOCONFIGDEBCREDRCAPROMOMED devido a conflito com a Máxima Sistemas detectado pela Palmed
                  IF ((NVL(vrParamFilial.vTIPOCONFIGDEBCREDRCAPROMOMED,'0') = '1') OR
                      (NVL(vrParamFilial.vTIPOCONFIGDEBCREDRCAPROMOMED,'0') = '2')) THEN
                    --//
                    --// Troquei nas condições (NVL(vrItemPedido.nPVENDA,0) < NVL(vnPrecoAplicadoDescPolitica,0)) e (NVL(vrItemPedido.nPVENDA,0) > NVL(vnPrecoAplicadoDescPolitica,0)) a variável vnPrecoAplicadoDescPolitica por vrItemPedido.nPBASERCA,
                    --// porque quando TIPOCONFIGDEBCREDRCAPROMOMED for igual a 1 ou 2, deve se comparar o PVENDA com o Preço Tabela - % Desconto Conta-Corrente e não com o PTABELA - % Desconto Comercial da Promoção
                    --//
                    -- Se aumentar o Preço mesmo com desconto zerado deve usar a regra
                    --IF (NVL(vrDadosPromocaoAtual.vnPerDesc,0) <> 0)  THEN --// Se a Promoção tinha Desconto
                      --// Se for debitar o conta-corrente (vendeu mais barato: Valor Liquido < Valor Tabela com Desconto da Promoção)
                      IF (NVL(vrItemPedido.nPVENDA,0) < NVL(vrItemPedido.nPBASERCA,0)) THEN
                        --// Opção da 2323 não debitar ao conceder desconto (PCEDESCONTO.BASECREDDEBRCA)
                        IF (NVL(vrDadosPromocaoAtual.vvBaseCredDebRca,'N') = 'S') THEN
                          --// Não debitará mais: Base do Rca será igual ao Valor Liquido
                          vrItemPedido.nPBASERCA := NVL(vrItemPedido.nPVENDA,0);
                          -- Log do Item
                          IF (pi_nTipoChamada IN (2,10,11,15
                                                 ,16 -- ITENS CROSS DOCKING [16] - MED-1096
                                                 ,17
                                                 )) THEN
                            P_INSERE_LOG(viLacoValidar, 'PBASERCA Promoção Não Debita: ' || vrItemPedido.nPBASERCA);
                          END IF;
                        END IF;
                      END IF;

                      --// Se for creditar o conta-corrente (vendeu mais caro: Valor Liquido > Valor Tabela com Desconto da Promoção)
                      IF (NVL(vrItemPedido.nPVENDA,0) > NVL(vrItemPedido.nPBASERCA,0)) THEN
                        --// Opção da 2323 Creditar a Conta-Corrente do RCA se não conceder desconto total (PCEDESCONTO.CREDITASOBREPOLITICA)
                        IF (NVL(vrDadosPromocaoAtual.vvCreditaSobrePolitica,'N') = 'N') then
                          vrItemPedido.nPBASERCA := NVL(vrItemPedido.nPVENDA,0); --// Não Creditará
                          -- Log do Item
                          IF (pi_nTipoChamada IN (2,10,11,15
                                                 ,16 -- ITENS CROSS DOCKING [16] - MED-1096
                                                 ,17
                                                 )) THEN
                            P_INSERE_LOG(viLacoValidar, 'PBASERCA Promoção Não Credita: ' || vrItemPedido.nPBASERCA);
                          END IF;
                        --ELSE
                        --  vrItemPedido.nPBASERCA := NVL(vrItemPedido.nPBASERCA,0); --// Creditará
                        END IF;
                      END IF;
                    --END IF; --// Fim Se a Promoção tinha Desconto

                  --// A regra abaixo estava implementado antes da Condição TIPOCONFIGDEBCREDRCAPROMOMED = 1 ou 2
                  --// Ela passou para este Else para que o código abaixo não interfira em hipótese alguma no valor da variável vrItemPedido.nPBASERCA quando TIPOCONFIGDEBCREDRCAPROMOMED for igual a 1 ou 2,
                  --// porque com esta parametrização o vrItemPedido.nPBASERCA deve chegar aqui obrigatoriamente com o valor de PTABELA - % Desconto Conta Corrente,
                  --// para confrontar com o PVENDA e assim determinar se a diferença entre os dois debitará ou creditará.
                  --//
                  --//----------------------------------------------------------------------
                  --// MODELO CONTA CORRENTE ANTERIOR - IGUAL AO PACOTE --------------------
                  --//----------------------------------------------------------------------
                  ELSE

                    -- Se Credita sobre Política
                    IF (NVL(vrDadosPromocaoAtual.vnPerDesc,0) <> 0) AND
                       (NVL(vrItemPedido.nPVENDA,0) >= NVL(vrItemPedido.nPTABELA,0)) AND
                       (NVL(vrDadosPromocaoAtual.vvBaseCredDebRca,'N') = 'S') THEN
                      --//vsCreditaSobrePolitica - Politica de desconto 561 - campo PCEDESCONTO.CREDITASOBREPOLITICA
                      IF (NVL(vrDadosPromocaoAtual.vvCreditaSobrePolitica,'N') = 'N') THEN
                        vrItemPedido.nPBASERCA := NVL(vrItemPedido.nPVENDA,0);
                        -- Log do Item
                        IF (pi_nTipoChamada IN (2,10,11,15
                                               ,16 -- ITENS CROSS DOCKING [16] - MED-1096
                                               ,17
                                               )) THEN
                          P_INSERE_LOG(viLacoValidar, 'PBASERCA Não Debita Pacote: ' || vrItemPedido.nPBASERCA);
                        END IF;
                      ELSE
                        vrItemPedido.nPBASERCA := NVL(vnPrecoAplicadoDescPolitica,0);
                        -- Log do Item
                        IF (pi_nTipoChamada IN (2,10,11,15
                                               ,16 -- ITENS CROSS DOCKING [16] - MED-1096
                                               ,17
                                               )) THEN
                          P_INSERE_LOG(viLacoValidar, 'PBASERCA Debita Pacote: ' || vrItemPedido.nPBASERCA);
                        END IF;
                      END IF;
                    END IF;

                  END IF;

                  --// 4493.040816.2016 - Alteração para garantir que nos cancelamentos noutros módulos não estorne o Conta-Corrente
                  --//                    nos Pedidos Televendas onde a Empresa bloqueia o débito e crédito no Televendas
                  IF (vrDadosPedidoAtual.vORIGEMPED         = 'T') AND
                     (vrParamFilial.vBLOQDEBCREDRCATELEVMED = 'S') THEN
                    vrItemPedido.nPBASERCA := NVL(vrItemPedido.nPVENDA,0); --// Não Creditará nem Debitará
                    -- Log do Item
                    IF (pi_nTipoChamada IN (2,10,11,15
                                           ,16 -- ITENS CROSS DOCKING [16] - MED-1096
                                           ,17
                                           )) THEN
                      P_INSERE_LOG(viLacoValidar, 'PBASERCA BLOQDEBCREDRCATELEVMED : ' || vrItemPedido.nPBASERCA);
                    END IF;
                  END IF;

                END IF; -- FIM CONDIÇÃO: DEFINIÇÃO da Base do RCA - Com ou Sem Promoção

              END IF; -- FIM CONDIÇÃO: DEFINIÇÃO da Base do RCA - Preço Autorizado Autorizado

              -- 4348.034902.2016 - Arredondamento do PBASERCA igual à 2316
              vrItemPedido.nPBASERCA := ROUND(vrItemPedido.nPBASERCA , vrParamFilial.nCON_NUMCASASDECVENDA);

              ---------------------------------------------------
              -- MED-2453 - Verba CMV do Cliente sobre o PBASERCA
              ---------------------------------------------------
              BEGIN
                P_CALCULARPERCVERBACMV(vrItemPedido.nCODPROD,
                                       vrProduto_O.nCODSEC,
                                       vrProduto_O.nCODEPTO,
                                       TRUNC(SYSDATE),
                                       pi_nCodCli,
                                       vrParamFilial.nCON_NUMCASASDECVENDA,
                                       vrClienteDestino.nCODREDE,
                                       vrItemPedido.nCODPROMOCAOMED,
                                       vrRetCmvCli.vALTERACONTACORRENTE,
                                       vrRetCmvCli.nPERCVERBA);
              EXCEPTION
                WHEN OTHERS THEN
                   vrRetCmvCli.vALTERACONTACORRENTE := 'N';
                   vrRetCmvCli.nPERCVERBA           := NULL;
              END;
              -- Se tem Verba CMV Cliente
              IF (NVL(vrRetCmvCli.nPERCVERBA,0) <> 0) THEN

                -- Alteração do Conta-Corrente do RCA
                IF (vrRetCmvCli.vALTERACONTACORRENTE = 'S') THEN

                  -- Log do Item
                  IF (pi_nTipoChamada IN (2,10,11,15
                                         ,16 -- ITENS CROSS DOCKING [16] - MED-1096
                                         ,17
                                         )) THEN
                    P_INSERE_LOG(viLacoValidar, 'ALTERACONTACORRENTE: ' || vrRetCmvCli.vALTERACONTACORRENTE);
                    P_INSERE_LOG(viLacoValidar, 'PBASERCA: '            || vrItemPedido.nPBASERCA);
                    P_INSERE_LOG(viLacoValidar, 'PERCVERBA: '           || vrRetCmvCli.nPERCVERBA);
                  END IF;

                  -- Igualar a 2316 (Sem Impostos)
                  IF (NVL(vrParamFilial.nTIPOCALCSTFONTE,'2') = '1') THEN
                    vrItemPedido.nPBASERCA := NVL(vrItemPedido.nPBASERCA,0) + ( NVL(vrItemPedido.nPTABELA,0) * (NVL(vrRetCmvCli.nPERCVERBA,0) / 100) );
                  ELSE
                    vrItemPedido.nPBASERCA := NVL(vrItemPedido.nPBASERCA,0) + ( NVL(vrItemPedido.nPVENDA,0)  * (NVL(vrRetCmvCli.nPERCVERBA,0) / 100) );
                  END IF;

                  -- Arredonda igual a 2316
                  vrItemPedido.nPBASERCA := ROUND(vrItemPedido.nPBASERCA,vrParamFilial.nCON_NUMCASASDECVENDA);

                  -- Log do Item
                  IF (pi_nTipoChamada IN (2,10,11,15
                                         ,16 -- ITENS CROSS DOCKING [16] - MED-1096
                                         ,17
                                         )) THEN
                    P_INSERE_LOG(viLacoValidar, 'PBASERCA: ' || vrItemPedido.nPBASERCA);
                  END IF;

                END IF;

              END IF;
              -------------------------------------------

             /*******************************************************************
              *******************************************************************
              **   INICIO: CALCULAR ICMS PARTILHA (normal) - HIS.04557.2015   ***
              *******************************************************************
              *******************************************************************/
              vrItemPedido.nVLBASEPARTDEST    := NULL;
              vrItemPedido.nALIQFCP           := NULL;
              vrItemPedido.nVLFCPPART         := NULL;
              vrItemPedido.nVLICMSPARTDEST    := NULL;
              vrItemPedido.nVLICMSPART        := NULL;
              vrItemPedido.nVLICMSDIFALIQPART := NULL;
              vrItemPedido.nPERCBASEREDPART   := NULL;
              vrItemPedido.nPERCPROVPART      := NULL;
              vrItemPedido.nVLICMSPARTREM     := NULL;
              vrItemPedido.nALIQINTERNADEST   := NULL;
              vrItemPedido.nALIQINTERORIGPART := NULL;
              vrItemPedido.nCODFISCAL         := NULL; -- HIS.03261.2016
              vrItemPedido.vSITTRIBUT         := NULL; -- HIS.03261.2016
              --
              vrRetDefinirCodFiscal.vnCodFiscal     := NULL; -- HIS.03261.2016
              vrRetDefinirCodFiscal.vvSitTrib       := NULL; -- HIS.03261.2016
              vrRetDefinirCodFiscal.vvTipoCodFiscal := NULL; -- HIS.03261.2016
              vrRetDefinirCodFiscal.vvTipoSitTrib   := NULL; -- HIS.03261.2016

              -- Se Existe ICMS PARTILHA
              IF F_EXISTEICMSPARTILHA(pi_nCodCli,
                                      pi_vCodFilial,
                                      pi_vCodFilialNf,
                                      vrClienteDestino.vESTENT) THEN

                -- Log do Item
                P_INSERE_LOG(viLacoValidar, 'Partilha do Produto e Filial ' || vrItemPedido.nCODPROD || ' ; ' || NVL(pi_vCodFilialNf,' ') || '/' || NVL(pi_vCodFilial,' '));
                P_INSERE_LOG(viLacoValidar, 'Preço de Referência: ' || vrItemPedido.nPVENDA);

                -- Chama procedimento para buscar o CFOP e CST -- HIS.03261.2016
                -- DDMEDICA-6772 - Alterada a chamada para a Package Medicamentos
                PKG_MEDICAMENTOS.P_DEFINIR_CODFISCAL(NVL(pi_vCodFilialNf,pi_vCodFilial),
                                                     pi_nCodCli,
                                                     vrItemPedido.nCODPROD,
                                                     vrItemPedido.nCODST,
                                                     pi_nCondVenda,
                                                     NULL, -- pi_nNumNotaConsign // Aqui na 2316 não tem Devolução Simbólica
                                                     NULL, -- pi_vTipoCfopTv4 // ICMS Partilha somente TV1 e TV5
                                                     pi_vCodCob,
                                                     NULL, -- pi_vProntaEntrega // ICMS Partilha somente TV1 e TV5
                                                     NULL, -- pi_vUsaCfopVendaNaTv10 // ICMS Partilha somente TV1 e TV5
                                                     NULL, -- pi_vVendaTriangular // ICMS Partilha somente TV1 e TV5
                                                     NULL, -- pi_vContaOrdem // ICMS Partilha somente TV1 e TV5
                                                     NULL, -- pi_nCodBnf
                                                     NULL, -- pi_vFornecEntrega // ICMS Partilha somente TV1 e TV5
                                                     NULL, -- pi_nNumTransEntOrigConsig // Aqui na 2316 não tem Devolução Simbólica
                                                     NULL, -- pi_nCfopNfDegusta // ICMS Partilha somente TV1 e TV5
                                                     0,    -- pi_nVlDescSuframa
                                                     vrItemPedido.nPVENDA,
                                                     vrItemPedido.vBONIFIC,
                                                     NULL, -- pi_vRegimeEspIsenStFonte // Se não passar esta opção, a procedure realiza o cálculo
                                                     vrRetDefinirCodFiscal.vnCodFiscal,
                                                     vrRetDefinirCodFiscal.vvSitTrib,
                                                     vrRetDefinirCodFiscal.vvTipoCodFiscal,
                                                     vrRetDefinirCodFiscal.vvTipoSitTrib);

                -- Log do Item
                P_INSERE_LOG(viLacoValidar, 'SitTrib: '       || vrRetDefinirCodFiscal.vvSitTrib);
                P_INSERE_LOG(viLacoValidar, 'CodFiscal: '     || vrRetDefinirCodFiscal.vnCodFiscal);
                P_INSERE_LOG(viLacoValidar, 'TipoCodFiscal: ' || vrRetDefinirCodFiscal.vvTipoCodFiscal);
                P_INSERE_LOG(viLacoValidar, 'TipoSitTrib: '   || vrRetDefinirCodFiscal.vvTipoSitTrib);

                -- Chama Serviço para Cálculo do ICMS Partilha
                vvErroIcmsPartilha := 'N';
                BEGIN
                  pkg_fwpc_fiscal.ICMSPARTILHA_CALCULAR_1_4(NVL(pi_vCodFilialNf,pi_vCodFilial),
                                                            pi_nCodCli,
                                                            '', -- P_UFOPERCONSUM
                                                            '', -- P_UFENTREGA
                                                            TRUNC(SYSDATE),
                                                            vrItemPedido.nPTABELA,
                                                            vrItemPedido.nCODST,
                                                            vrItemPedido.nCODPROD,
                                                            vrRetDefinirCodFiscal.vnCodFiscal, -- HIS.03261.2016
                                                            vrRetDefinirCodFiscal.vvSitTrib,   -- HIS.03261.2016
                                                            tICMSPARTILHA,
                                                            vnCodMSGPartilha,
                                                            vsMSGPartilha);
                  vrItemPedido.nPTABELA := vrItemPedido.nPTABELA + NVL(tICMSPARTILHA.VLICMSPART,0);
                  --
                  pkg_fwpc_fiscal.icmspartilha_calcular_1_4(NVL(pi_vCodFilialNf,pi_vCodFilial),
                                                            pi_nCodCli,
                                                            '', -- P_UFOPERCONSUM
                                                            '', -- P_UFENTREGA
                                                            TRUNC(SYSDATE),
                                                            vrItemPedido.nPBASERCA,
                                                            vrItemPedido.nCODST,
                                                            vrItemPedido.nCODPROD,
                                                            vrRetDefinirCodFiscal.vnCodFiscal, -- HIS.03261.2016
                                                            vrRetDefinirCodFiscal.vvSitTrib,   -- HIS.03261.2016
                                                            tICMSPARTILHA,
                                                            vnCodMSGPartilha,
                                                            vsMSGPartilha);
                  vrItemPedido.nPBASERCA := vrItemPedido.nPBASERCA + NVL(tICMSPARTILHA.VLICMSPART,0);
                  -- 3904.052131.2017 - O PVENDA DEVE VIR POR ÚLTIMO, PORQUE PRECISO SALVAR AS BASES EM CIMA DO PVENDA
                  pkg_fwpc_fiscal.icmspartilha_calcular_1_4(NVL(pi_vCodFilialNf,pi_vCodFilial),
                                                            pi_nCodCli,
                                                            '', -- P_UFOPERCONSUM
                                                            '', -- P_UFENTREGA
                                                            TRUNC(SYSDATE),
                                                            vrItemPedido.nPVENDA,
                                                            vrItemPedido.nCODST,
                                                            vrItemPedido.nCODPROD,
                                                            vrRetDefinirCodFiscal.vnCodFiscal, -- HIS.03261.2016
                                                            vrRetDefinirCodFiscal.vvSitTrib,   -- HIS.03261.2016
                                                            tICMSPARTILHA,
                                                            vnCodMSGPartilha,
                                                            vsMSGPartilha);
                  vrItemPedido.nPVENDA := vrItemPedido.nPVENDA + NVL(tICMSPARTILHA.VLICMSPART,0);
                  -- Log do Item
                  P_INSERE_LOG(viLacoValidar, 'Valor da Partilha: ' || NVL(tICMSPARTILHA.VLICMSPART,0));
                EXCEPTION
                  -- Caso esteja descompilado na primeira tentativa faz uma nova consulta
                  WHEN OTHERS THEN
                    BEGIN
                      pkg_fwpc_fiscal.icmspartilha_calcular_1_4(NVL(pi_vCodFilialNf,pi_vCodFilial),
                                                                pi_nCodCli,
                                                                '', -- P_UFOPERCONSUM
                                                                '', -- P_UFENTREGA
                                                                TRUNC(SYSDATE),
                                                                vrItemPedido.nPTABELA,
                                                                vrItemPedido.nCODST,
                                                                vrItemPedido.nCODPROD,
                                                                vrRetDefinirCodFiscal.vnCodFiscal, -- HIS.03261.2016
                                                                vrRetDefinirCodFiscal.vvSitTrib,   -- HIS.03261.2016
                                                                tICMSPARTILHA,
                                                                vnCodMSGPartilha,
                                                                vsMSGPartilha);
                      vrItemPedido.nPTABELA := vrItemPedido.nPTABELA + NVL(tICMSPARTILHA.VLICMSPART,0);
                      --
                      pkg_fwpc_fiscal.icmspartilha_calcular_1_4(NVL(pi_vCodFilialNf,pi_vCodFilial),
                                                                pi_nCodCli,
                                                                '', -- P_UFOPERCONSUM
                                                                '', -- P_UFENTREGA
                                                                TRUNC(SYSDATE),
                                                                vrItemPedido.nPBASERCA,
                                                                vrItemPedido.nCODST,
                                                                vrItemPedido.nCODPROD,
                                                                vrRetDefinirCodFiscal.vnCodFiscal, -- HIS.03261.2016
                                                                vrRetDefinirCodFiscal.vvSitTrib,   -- HIS.03261.2016
                                                                tICMSPARTILHA,
                                                                vnCodMSGPartilha,
                                                                vsMSGPartilha);
                      vrItemPedido.nPBASERCA := vrItemPedido.nPBASERCA + NVL(tICMSPARTILHA.VLICMSPART,0);
                      -- 3904.052131.2017 - O PVENDA DEVE VIR POR ÚLTIMO, PORQUE PRECISO SALVAR AS BASES EM CIMA DO PVENDA
                      pkg_fwpc_fiscal.icmspartilha_calcular_1_4(NVL(pi_vCodFilialNf,pi_vCodFilial),
                                                                pi_nCodCli,
                                                                '', -- P_UFOPERCONSUM
                                                                '', -- P_UFENTREGA
                                                                TRUNC(SYSDATE),
                                                                vrItemPedido.nPVENDA,
                                                                vrItemPedido.nCODST,
                                                                vrItemPedido.nCODPROD,
                                                                vrRetDefinirCodFiscal.vnCodFiscal, -- HIS.03261.2016
                                                                vrRetDefinirCodFiscal.vvSitTrib,   -- HIS.03261.2016
                                                                tICMSPARTILHA,
                                                                vnCodMSGPartilha,
                                                                vsMSGPartilha);
                      vrItemPedido.nPVENDA := vrItemPedido.nPVENDA + NVL(tICMSPARTILHA.VLICMSPART,0);
                      -- Log do Item
                      P_INSERE_LOG(viLacoValidar, '*Valor da Partilha: ' || NVL(tICMSPARTILHA.VLICMSPART,0));
                    EXCEPTION
                      WHEN OTHERS THEN
                        vvErroIcmsPartilha := 'S';
                    END;
                END;

                -- Se não ocorreram erros no Cálculo do ICMS Partilha
                IF (vvErroIcmsPartilha = 'N') THEN
                  vrItemPedido.nVLBASEPARTDEST    := tICMSPARTILHA.vlbasepartdest;
                  vrItemPedido.nALIQFCP           := tICMSPARTILHA.aliqfcp;
                  vrItemPedido.nVLFCPPART         := tICMSPARTILHA.vlfcppart;
                  vrItemPedido.nVLICMSPARTDEST    := tICMSPARTILHA.vlicmspartdest;
                  vrItemPedido.nVLICMSPART        := tICMSPARTILHA.vlicmspart;
                  vrItemPedido.nVLICMSDIFALIQPART := tICMSPARTILHA.vlicmsdifaliq;
                  vrItemPedido.nPERCBASEREDPART   := tICMSPARTILHA.percbasered;
                  vrItemPedido.nPERCPROVPART      := tICMSPARTILHA.percprovpart;
                  vrItemPedido.nVLICMSPARTREM     := tICMSPARTILHA.vlicmspartrem;
                  vrItemPedido.nALIQINTERNADEST   := tICMSPARTILHA.aliqinternadest;
                  vrItemPedido.nALIQINTERORIGPART := tICMSPARTILHA.aliqinterestadual;
                  --
                 vrItemPedido.nCODFISCAL          := vrRetDefinirCodFiscal.vnCodFiscal; -- HIS.03261.2016
                 vrItemPedido.vSITTRIBUT          := vrRetDefinirCodFiscal.vvSitTrib;   -- HIS.03261.2016
                ELSE
                  -- Log do Item
                  P_INSERE_LOG(viLacoValidar, 'Erro no cálculo da Partilha');
                END IF;

              END IF;
             /*******************************************************************
              *******************************************************************
              **     FIM: CALCULAR ICMS PARTILHA (normal) - HIS.04557.2015    ***
              *******************************************************************
              *******************************************************************/



              -------------------
              -- CÁLCULO ST FONTE
              -------------------

              -- CALCULA ST FONTE ONDE O PREÇO VENDA JÁ ESTÁ ARREDONDADO IGUAL A 2316--
              vrItemPedido.nVLFECP                   := NULL; -- MED-1090
              vrItemPedido.nVLBASEFCPST              := NULL; -- MED-1090
              vrItemPedido.nALIQICMSFECP             := NULL; -- MED-1090
              vrItemPedido.nBCSTRETANTERIOR          := 0;    -- DDMEDICA-7697
              vrItemPedido.nVLICMSSUBSTITUTOANTERIOR := 0;    -- DDMEDICA-7697
              vrItemPedido.nVLICMSSTRETANTERIOR      := 0;    -- DDMEDICA-7697
              vrItemPedido.nPMPFMEDICAMENTO          := 0;    -- DDMEDICA-7697

              IF (vrClienteDestino.vCLIENTEFONTEST = 'S') THEN

                -- DDMEDICA-7697 - Cálculo com o ST Recolhido Anteriormente
                PKG_MEDICAMENTOS.P_OBTEM_STFONTE_42(pi_vCodFilial,
                                                    vrItemPedido.nCODPROD,
                                                    pi_nCodCli,
                                                    vrRegiao.nNUMREGIAO,
                                                    pi_nCondVenda,
                                                    100, -- pi_nPercVenda
                                                    vrItemPedido.nCODST,
                                                    (NVL(vrItemPedido.nPVENDA,0) - NVL(vrItemPedido.nVLIPI,0)), -->> *** PASSA O PVENDA ***
                                                    NVL(vrItemPedido.nVLIPI,0),   -- pi_nValorIpi
                                                    vrItemPedido.nPRECOMAXCONSUM,
                                                    vrCustoProduto_O.nVALORULTENT,
                                                    vrCustoProduto_O.nCUSTONFSEMST,
                                                    (NVL(vrItemPedido.nPTABELA,0) - NVL(vrItemPedido.nVLIPI,0)),
                                                    'N',     -->> Padrão Não (Simples Nacional)
                                                    'N',     -->> Não Pesquisa Custos
                                                    NVL(vrItemPedido.vBONIFIC,'N'), -->>  MED-2521
                                                    0,       -->> Não passa Frete e Outras Despesas
                                                    vrItemPedido.nBASEICST,
                                                    vrItemPedido.nST, -->> *** RECEBE O ST DO PVENDA ***
                                                    vvMensagemRetornoSTFONTE,
                                                    vrItemPedido.nREGIMEESPISENSTFONTE,
                                                    vrItemPedido.nALIQICMS1,
                                                    vrItemPedido.nALIQICMS2,
                                                    vrItemPedido.nIVA,
                                                    vrItemPedido.nPERCBASEREDSTFONTE,
                                                    'O', -- Tipo Chamada = Outros
                                                    vrItemPedido.nQT,
                                                    pi_nNumPed,
                                                    pi_vCodFilialNf, -- HIS.03376.2017
                                                    vrItemPedido.nPAUTA, -- HIS.03376.2017
                                                    vrItemPedido.vOBSERVACAOSTFONTE,  -- HIS.03376.2017
                                                    vrItemPedido.vINDESCALARELEVANTE, -- HIS.03376.2017
                                                    vrItemPedido.vCNPJFABRICANTE, -- HIS.03376.2017
                                                    vrItemPedido.vFABRICANTE, -- HIS.03376.2017
                                                    vrDadosFuncep.nVLBASEFCPICMS,      -- MED-1090
                                                    vrDadosFuncep.nVLBASEFCPST,        -- MED-1090
                                                    vrDadosFuncep.nVLBCFCPSTRET,       -- MED-1090
                                                    vrDadosFuncep.nPERFCPSTRET,        -- MED-1090
                                                    vrDadosFuncep.nVLFCPSTRET,         -- MED-1090
                                                    vrDadosFuncep.nPERFCPSN,           -- MED-1090
                                                    vrDadosFuncep.nVLFECP,             -- MED-1090
                                                    vrDadosFuncep.nVLACRESCIMOFUNCEP,  -- MED-1090
                                                    vrDadosFuncep.nPERACRESCIMOFUNCEP, -- MED-1090
                                                    vrDadosFuncep.nALIQICMSFECP,       -- MED-1090
                                                    vrDadosFuncep.nVLCREDFCPICMSSN,    -- MED-1090
                                                    vrDadosFuncep.nCODCONFIGFUNCEPMED,
                                                    'F', -- pi_vOrdemCalculo
                                                    'N', -- pi_vMemoriaCalculo
                                                    0,   -- pi_nValorNotaFiscal
                                                    vvTributPedidoAvariaPerda,
                                                    vrItemPedido.nBCSTRETANTERIOR,          -- DDMEDICA-7697
                                                    vrItemPedido.nVLICMSSUBSTITUTOANTERIOR, -- DDMEDICA-7697
                                                    vrItemPedido.nVLICMSSTRETANTERIOR,      -- DDMEDICA-7697
                                                    vrItemPedido.nSTCLIENTEGNRE,            -- DDMEDICA-7697
                                                    vrItemPedido.nPMPFMEDICAMENTO,          -- DDMEDICA-7697
                                                    vvRetClienteFonteSt                     -- DDMEDICA-7697
                                                    );

                IF (vvMensagemRetornoSTFONTE IS NOT NULL) THEN
                  -- Informações de Produto Bloqueado para a Campanha -- HIS.01889.2017
                  IF (pi_nTipoChamada = 13) THEN
                    vrItemPedido.vBLOQUEIOCAMPANHA       := 'S';
                    vrItemPedido.vMOTIVOBLOQUEIOCAMPANHA := 'Problemas ao pesquisar o ST FONTE do Produto '    || NVL(vrItemPedido.nCODPROD,0) || ': ' || vvMensagemRetornoSTFONTE;
                  ELSE
                    -- Rejeita
                    po_vMotivoNaoPodeGravar := 'Problemas ao pesquisar o ST FONTE do Produto '    || NVL(vrItemPedido.nCODPROD,0) || ': ' || vvMensagemRetornoSTFONTE;
                    RAISE e_Tratado;
                  END IF;
                END IF;
                -- Guarda Composição do Imposto que será gravado nos Itens do Pedido
                vrItemPedido.nPAUTA := 0;
                -- Se não tem ST zera a Base
                IF (NVL(vrItemPedido.nST,0) <= 0) THEN
                  vrItemPedido.nBASEICST := 0;
                END IF;

                -- MED-1090 - Valores FCP
                vrItemPedido.nVLFECP       := vrDadosFuncep.nVLFECP;
                vrItemPedido.nVLBASEFCPST  := vrDadosFuncep.nVLBASEFCPST;
                vrItemPedido.nALIQICMSFECP := vrDadosFuncep.nALIQICMSFECP;

              -- Se não for ST Fonte - HIS.03764.2016
              ELSE

                -- MED-1090 - Limpa Dados do FUNCEP
                -- DDMEDICA-7697 - e do ST Recolhido Anteriormente
                vrItemPedido.nVLFECP                   := NULL;
                vrItemPedido.nVLBASEFCPST              := NULL;
                vrItemPedido.nALIQICMSFECP             := NULL;
                vrItemPedido.nBCSTRETANTERIOR          := 0;
                vrItemPedido.nVLICMSSUBSTITUTOANTERIOR := 0;
                vrItemPedido.nVLICMSSTRETANTERIOR      := 0;
                -- Limpa ST da Precificação já que não é Fonte nem Precificação
                IF (NVL(vrClienteDestino.vCALCULAST,'N') <> 'S') THEN
                  vrItemPedido.nBASEICST               := 0;
                  vrItemPedido.nST                     := 0;
                END IF;

                -- Pesquisa Dados do Produto por Filial - HIS.03764.2016
                BEGIN
                  SELECT NVL(PCPRODFILIAL.INDESCALARELEVANTE,'S') -->> PADRÃO SIM PARA CALCULAR ST (INDUSTRIA FARMACEUTICA RELEVANTE)
                       , PCPRODFILIAL.CNPJFABRICANTE
                       , PCPRODFILIAL.FABRICANTE
                    INTO vrItemPedido.vINDESCALARELEVANTE
                       , vrItemPedido.vCNPJFABRICANTE
                       , vrItemPedido.vFABRICANTE
                    FROM PCPRODFILIAL
                   WHERE (CODPROD   = vrItemPedido.nCODPROD)
                     AND (CODFILIAL = NVL(pi_vCodFilialNf,pi_vCodFilial));
                EXCEPTION
                  WHEN NO_DATA_FOUND THEN
                    vrItemPedido.vINDESCALARELEVANTE := 'S'; -->> PADRÃO SIM PARA CALCULAR ST (INDUSTRIA FARMACEUTICA RELEVANTE)
                    vrItemPedido.vCNPJFABRICANTE     := NULL;
                    vrItemPedido.vFABRICANTE         := NULL;
                END;

              END IF;

              -- SOMA O ST AO PVENDA (idem FUNCEP MED-1090) (idem ST Recolhido Anteriormente DDMEDICA-7697)
              vrItemPedido.nPVENDA    := NVL(vrItemPedido.nPVENDA,0)  
                                         + NVL(vrItemPedido.nST,0) 
                                         + NVL(vrItemPedido.nVLICMSSTRETANTERIOR,0) -- DDMEDICA-7697
                                         + NVL(vrItemPedido.nVLFECP,0);

              -- Soma ao PTabela o ST calculado sobre o PVenda (idem FUNCEP MED-1090) (idem ST Recolhido Anteriormente DDMEDICA-7697)
              vrItemPedido.nPTABELA   := NVL(vrItemPedido.nPTABELA,0)  
                                         + NVL(vrItemPedido.nST,0) 
                                         + NVL(vrItemPedido.nVLICMSSTRETANTERIOR,0) -- DDMEDICA-7697
                                         + NVL(vrItemPedido.nVLFECP,0);

              -- ST que foi somado no Preço de Tabela
              vrItemPedido.nSTPTABELA :=  NVL(vrItemPedido.nST,0);

              -- DDMEDICA-7609 - SEMPRE SOMAR NA BASE DO RCA O MESMO ST SOMADO AO PVENDA
              vrItemPedido.nSTPBASERCA :=  NVL(vrItemPedido.nST,0);

              -- SOMA O STPBASERCA AO PBASERCA (idem FUNCEP MED-1090) (idem ST Recolhido Anteriormente DDMEDICA-7697)
              vrItemPedido.nPBASERCA  := NVL(vrItemPedido.nPBASERCA,0)
                                         + NVL(vrItemPedido.nSTPBASERCA,0) 
                                         + NVL(vrItemPedido.nVLICMSSTRETANTERIOR,0) -- DDMEDICA-7697
                                         + NVL(vrItemPedido.nVLFECP,0);

              ----------------------------------------------------------------------------
              -- SOMA O REPASSE NO FINAL
              ----------------------------------------------------------------------------

              -- Soma ao PTabela o VLREPASSE
              vrItemPedido.nPTABELA  := NVL(vrItemPedido.nPTABELA,0) + NVL(vrItemPedido.nVLREPASSE,0);
              -- Soma ao PVenda o VLREPASSE
              vrItemPedido.nPVENDA   := NVL(vrItemPedido.nPVENDA,0) + NVL(vrItemPedido.nVLREPASSE,0);
              -- Soma ao PBaseRCA o VLREPASSE
              vrItemPedido.nPBASERCA := NVL(vrItemPedido.nPBASERCA,0) + NVL(vrItemPedido.nVLREPASSE,0);

              -- ARREDONDA O PREÇO DE TABELA E PREÇO DE VENDA --
              -----------------------------------------------
              vrItemPedido.nPTABELA  := ROUND(vrItemPedido.nPTABELA , vrParamFilial.nCON_NUMCASASDECVENDA);
              vrItemPedido.nPVENDA   := ROUND(vrItemPedido.nPVENDA  , vrParamFilial.nCON_NUMCASASDECVENDA);
              vrItemPedido.nPBASERCA := ROUND(vrItemPedido.nPBASERCA, vrParamFilial.nCON_NUMCASASDECVENDA);

              -----------------------------------------
              -- Procede ao Cálculo do Desconto Isenção
              -----------------------------------------

             /******************************************
              INICIO: BENEFÍCIOS FISCAIS - DDMEDICA-7584
              ******************************************/
              
              -- LOG
              P_INSERE_LOG(viLacoValidar, 'PREÇOS ANTES DOS BENEFICIOS FISCAIS');
              P_INSERE_LOG(viLacoValidar, 'Preço Tabela: ' || vrItemPedido.nPTABELA);
              P_INSERE_LOG(viLacoValidar, 'Preço Venda: '  || vrItemPedido.nPVENDA);
              P_INSERE_LOG(viLacoValidar, 'P. BaseRca: '   || vrItemPedido.nPBASERCA);
              
              -- Inicializa Valores dos Descontos dos Benefícios Fiscais
              vrItemPedido.nVLDESCREDUCAOPIS    := 0;
              vrItemPedido.nPERCDESCPIS         := 0;
              vrItemPedido.nVLDESCREDUCAOCOFINS := 0;
              vrItemPedido.nPERCDESCCOFINS      := 0;
              vrItemPedido.nPERDESCISENTOICMS   := 0;
              vrItemPedido.nVLDESCICMISENCAO    := 0;
              vrItemPedido.nVLDESCSUFRAMA       := 0;
              vrItemPedido.nVLDESCPISSUFRAMA    := 0; -- Descontinuado 
              
              -- Obter os Valores dos Descontos dos Benefícios Fiscais
              PKG_MEDICAMENTOS.P_OBTER_VALORES_BENEF_FISCAIS(pi_vCodFilial,
                                                             pi_vCodFilialNf,
                                                             pi_nCodCli,
                                                             vrItemPedido.nCODPROD,
                                                             vrItemPedido.nCODST,
                                                             vrParamFilial.nCON_NUMCASASDECVENDA,
                                                             vrPcConsum.vTIPOCALCSULFRAMA,
                                                             vrTribut.nPERDESCICMISENCAO,
                                                             vrTribut.nAPLICADESCISENCAOMED,
                                                             (vrItemPedido.nPVENDA
                                                              - nvl(vrItemPedido.nST,0)
                                                              - nvl(vrItemPedido.nVLIPI,0)
                                                              - nvl(vrItemPedido.nVLFECP,0)),
                                                             (vrItemPedido.nPTABELA
                                                              - nvl(vrItemPedido.nST,0)
                                                              - nvl(vrItemPedido.nVLIPI,0)
                                                              - nvl(vrItemPedido.nVLFECP,0)),
                                                             (vrItemPedido.nPBASERCA
                                                              - nvl(vrItemPedido.nST,0)
                                                              - nvl(vrItemPedido.nVLIPI,0)
                                                              - nvl(vrItemPedido.nVLFECP,0)),
                                                             vrItemPedido.nQT,
                                                             vrItemPedido.nVLDESCREDUCAOPIS,
                                                             vrItemPedido.nPERCDESCPIS,
                                                             vrItemPedido.nVLDESCREDUCAOCOFINS,
                                                             vrItemPedido.nPERCDESCCOFINS,
                                                             vrItemPedido.nVLDESCICMISENCAO,
                                                             vrItemPedido.nPERDESCISENTOICMS,
                                                             vrItemPedido.nVLDESCSUFRAMA,
                                                             vnPercDescSuframaResult,
                                                             vnPrecoLiqResultAuxBF,
                                                             vnPrecoTabResultAuxBF,
                                                             vnPrecoRcaResultAuxBF,
                                                             vvErrosBenefFiscaisBF,
                                                             vvMsgErrosBenefFiscaisBF);
              IF (vvErrosBenefFiscaisBF = 'S') THEN
                -- Rejeita
                po_vMotivoNaoPodeGravar := vvMsgErrosBenefFiscaisBF;
                RAISE e_Tratado;
              END IF;
              
              IF pi_nTipoChamada = 11 AND vrDadosPromocaoAtual.vvTipoPromocao = 'K' THEN
                 
                IF (pi_vTipoFv = 'OL') THEN
                  P_MED_OBTEM_QTCOMBOVIRTUAL(vrItemPedido.nCODPROMOCAOMED,
                                             pi_nNumRegiao,
                                             NULL, --pi_nCodPraca,
                                             NULL, --pi_nCodRede,
                                             pi_nCodCli,
                                             NULL, --pi_nRamoAtv,
                                             NULL, --pi_vCLASSE,
                                             NULL, --pi_codgrupo,
                                             NULL, --, pi_vUfCliente
                                             vnQtComboVirtual,
                                             vnQtCombovirtual_vendidos,
                                             vsTipoLimitador,
                                             NULL,
                                             pi_vTipoFv
                                             );
                   
                  vnQtCombovirtual_disponivel := nvl(vnQtComboVirtual,0) - vnQtCombovirtual_vendidos;                          
                   
                  IF (vnQtCombovirtual_vendidos + pi_nQtCombos)  > vnQtComboVirtual THEN
                    po_vMotivoNaoPodeGravar := 'O combo ' || vrItemPedido.nCODPROMOCAOMED || ' foi rejeitado pois não há mais quantidades disponíveis de acordo com os limitadores cadastrados. ' || CHR(13) ||
                                               'Tipo Limitador cadastrado: ' || vsTipoLimitador || ' ' || CHR(13) || 
                                               'Limite(Qt. Max. Combo): ' || vnQtComboVirtual || ' ' || CHR(13) ||
                                               'Qt. Disponível da restrição: ' || vnQtCombovirtual_disponivel;
                    RAISE e_Tratado;     
                  END IF;
                ELSE
                  P_MED_OBTEM_QTCOMBOVIRTUAL(vrItemPedido.nCODPROMOCAOMED,
                                             pi_nNumRegiao,
                                             NULL, --pi_nCodPraca,
                                             NULL, --pi_nCodRede,
                                             pi_nCodCli,
                                             NULL, --pi_nRamoAtv,
                                             NULL, --pi_vCLASSE,
                                             NULL, --pi_codgrupo,
                                             NULL, --, pi_vUfCliente
                                             vnQtComboVirtual,
                                             vnQtCombovirtual_vendidos,
                                             vsTipoLimitador
                                             );
                   
                  vnQtCombovirtual_disponivel := nvl(vnQtComboVirtual,0) - vnQtCombovirtual_vendidos;                          
                   
                  IF (vnQtCombovirtual_vendidos + pi_nQtCombos)  > vnQtComboVirtual THEN
                    po_vMotivoNaoPodeGravar := 'O combo ' || vrItemPedido.nCODPROMOCAOMED || ' foi rejeitado pois não há mais quantidades disponíveis de acordo com os limitadores cadastrados. ' || CHR(13) ||
                                               'Tipo Limitador cadastrado: ' || vsTipoLimitador || ' ' || CHR(13) || 
                                               'Limite(Qt. Max. Combo): ' || vnQtComboVirtual || ' ' || CHR(13) ||
                                               'Qt. Disponível da restrição: ' || vnQtCombovirtual_disponivel;
                    RAISE e_Tratado;     
                  END IF;      
                END IF;                                                                                    
                                                                                    
              END IF;                                           
              
              -- Aplica valores dos descontos dos Benefícios Fiscais nos Preços
              vrItemPedido.nPVENDA   := round((vrItemPedido.nPVENDA
                                               - nvl(vrItemPedido.nVLDESCREDUCAOPIS,0)
                                               - nvl(vrItemPedido.nVLDESCREDUCAOCOFINS,0)
                                               - nvl(vrItemPedido.nVLDESCICMISENCAO,0)
                                               - nvl(vrItemPedido.nVLDESCSUFRAMA,0)),
                                              vrParamFilial.nCON_NUMCASASDECVENDA);

              vrItemPedido.nPTABELA  := round((vrItemPedido.nPTABELA 
                                               - nvl(vrItemPedido.nVLDESCREDUCAOPIS,0)
                                               - nvl(vrItemPedido.nVLDESCREDUCAOCOFINS,0)
                                               - nvl(vrItemPedido.nVLDESCICMISENCAO,0)
                                               - nvl(vrItemPedido.nVLDESCSUFRAMA,0)),
                                              vrParamFilial.nCON_NUMCASASDECVENDA);

              vrItemPedido.nPBASERCA := round((vrItemPedido.nPBASERCA
                                               - nvl(vrItemPedido.nVLDESCREDUCAOPIS,0)
                                               - nvl(vrItemPedido.nVLDESCREDUCAOCOFINS,0)
                                               - nvl(vrItemPedido.nVLDESCICMISENCAO,0)
                                               - nvl(vrItemPedido.nVLDESCSUFRAMA,0)),
                                              vrParamFilial.nCON_NUMCASASDECVENDA);

              -- LOG
              P_INSERE_LOG(viLacoValidar, 'PREÇOS FINAIS');
              P_INSERE_LOG(viLacoValidar, 'Preço Tabela reduzido dos Benefícios Fiscais: ' || vrItemPedido.nPTABELA);
              P_INSERE_LOG(viLacoValidar, 'Preço Venda reduzido dos Benefícios Fiscais: '  || vrItemPedido.nPVENDA);
              P_INSERE_LOG(viLacoValidar, 'P. BaseRca reduzido dos Benefícios Fiscais: '   || vrItemPedido.nPBASERCA);
              P_INSERE_LOG(viLacoValidar, 'Valor Desc. PIS: '                              || nvl(vrItemPedido.nVLDESCREDUCAOPIS,0));
              P_INSERE_LOG(viLacoValidar, 'Valor Desc. COFINS: '                           || nvl(vrItemPedido.nVLDESCREDUCAOCOFINS,0));
              P_INSERE_LOG(viLacoValidar, 'Valor Desc. ICMS: '                             || nvl(vrItemPedido.nVLDESCICMISENCAO,0));
              P_INSERE_LOG(viLacoValidar, '% Desc. ICMS: '                                 || nvl(vrItemPedido.nPERDESCISENTOICMS,0));
              P_INSERE_LOG(viLacoValidar, 'Valor Desc. SUFRAMA: '                          || nvl(vrItemPedido.nVLDESCSUFRAMA,0));
              P_INSERE_LOG(viLacoValidar, '% Desc. SUFRAMA: '                              || nvl(vnPercDescSuframaResult,0));

             /******************************************
              FIM: BENEFÍCIOS FISCAIS - DDMEDICA-7584
              ******************************************/

              --------------------------------------------------
              -- Atualiza o PBONIFIC - CAMPANHA - HIS.01889.2017
              --------------------------------------------------
              IF (pi_nTipoChamada = 15) THEN
                vrItemPedido.nPBONIFIC := vrItemPedido.nPVENDA;
              END IF;

              -------------------------------------------
              -- Procede ao Cálculo do Desconto no Boleto
              -------------------------------------------

              -- Define o Valor do Desconto no Boleto
              -- OBS: Quando o ST somado ao PTABELA não for o ST mas STPTABELA ***
              IF (NVL(vrParamFilial.nBASECALCDESCFINMED,0) = 2) then
                vrItemPedido.nVLDESCBOLETO := ((NVL(vrItemPedido.nPVENDA,0) - NVL(vrItemPedido.nST,0) - NVL(vrItemPedido.nVLREPASSE,0) - NVL(vrItemPedido.nVLFECP,0))  * (NVL(vrItemPedido.nPERDESCBOLETO,0) / 100));
              ELSE
                vrItemPedido.nVLDESCBOLETO := ((NVL(vrItemPedido.nPTABELA,0) - NVL(vrItemPedido.nST,0) - NVL(vrItemPedido.nVLREPASSE,0) - NVL(vrItemPedido.nVLFECP,0)) * (NVL(vrItemPedido.nPERDESCBOLETO,0) / 100));
              END IF;

              ----------------------------
              -- Procede ao Cálculo do CMV
              ----------------------------

              -- Atualiza os custos do Item do Pedido
              vrItemPedido.nVLCUSTOCONT := NVL(vrCustoProduto_O.nCUSTOCONT,0);
              vrItemPedido.nVLCUSTOREP  := NVL(vrCustoProduto_O.nCUSTOREP,0);

              -- Comissão do CMV
              IF (NVL(vrPcConsum.vINCLUIRCOMISSAOCMVVENDA,'S') = 'N') THEN
                vnPerComCMV := 0;
              ELSE
                vnPerComCMV := NVL(vrItemPedido.nPERCOM,0);
              END IF;

              -- Se Utiliza PEPS para Nacional e Importado - ICMS - HIS.02786.2016
              IF (vrParamFilial.vTRIBUTSAIDAORIGEMNACIMP = 'S') THEN
                FUNCOES_MED.OBTER_DADOS_PEPS_ICMS(vrItemPedido.nCODPROD,
                                                  NVL(pi_vCodFilialNf, pi_vCodFilial),
                                                  vrItemPedido.nQT,
                                                  TRUNC(SYSDATE), -->> Data atual será a Data da Transferência
                                                  vrItemPedido.vPRODIMPORTADOPEPS,
                                                  vrItemPedido.nNUMTRANSENTPEPS,
                                                  vvMsgErroObterPepsIcms);
              END IF;

              -- Calcular CMV
              P_CALCULARCMV_MED(vrPcConsum.vABATERIMPOSTOSCOMISSAORCA,
                                vrPcConsum.vAPLICARINDICECMV,
                                vrPcConsum.vINCLUIRCOMISSAOSUGPVENDACMV,
                                vrPcConsum.nTXVENDA,
                                vrClienteDestino.vTIPOFJ,
                                vrClienteDestino.vUTILIZAIESIMPLIFICADA,
                                vrClienteDestino.vIEENT,
                                vrProduto_O.nFRETEESPECIAL,
                                vrRegiao.nPERFRETETERCEIROS,
                                vrRegiao.nPERFRETEESPECIAL,
                                vrCustoProduto_O.nCUSTOFIN,
                                vrCustoProduto_O.nCUSTOREAL,
                                vrTribut.nPERDESCCUSTO,
                                vrTribut.nCODICMTAB,
                                vrTribut.bCODICMTABPF_ISNULL,
                                vrTribut.nCODICMTABPF,
                                vrItemPedido.nPVENDA,
                                vnPerComCMV, -->> Percentual de Comissão que depende de Parâmetro
                                (NVL(vrItemPedido.nST,0) 
                                 + NVL(vrItemPedido.nVLFECP,0)), -- FCP - Somar ao ST
                                vrItemPedido.nVLIPI,
                                0,
                                vrClienteDestino.vCONTRIBUINTE,
                                vrItemPedido.nPRAZOMEDIO,            -- HIS.01240.2016
                                vrItemPedido.nVLDESCBOLETO,          -- HIS.01240.2016
                                vrParamFilial.vTIPOACRESCIMOSCMVMED, -- HIS.01240.2016
                                vrParamFilial.nPERCTAXAPRAZOCMVMED,  -- HIS.01240.2016
                                vrItemPedido.vPRODIMPORTADOPEPS,     -- HIS.02786.2016
                                vrTribut.nCODICMTABINTERNAC,         -- HIS.02786.2016
                                vrItemPedido.nVLDESCCMVPROMOCAOMED,  -- DDMEDICA-5009
                                NVL(vrItemPedido.nVLICMSSTRETANTERIOR,0), -- DDMEDICA-7697
                                vrItemPedido.nPERFRETECMV,
                                vrItemPedido.nCUSTOFINEST,
                                vrItemPedido.nTXVENDA,
                                vrItemPedido.nPERDESCCUSTO,
                                vrItemPedido.nCODICMTAB,
                                vrItemPedido.nVLCUSTOREAL,
                                vrItemPedido.nVLCUSTOFIN,
                                vrItemPedido.nVLDESCCUSTOCMV,
                                vrItemPedido.nVLTAXAPRAZOMEDCMV,    -- HIS.01240.2016
                                vrItemPedido.nPERCTAXAPRAZOMEDCMV,  -- HIS.01240.2016
                                vrItemPedido.nVLDESCBOLETOCMV);     -- HIS.01240.2016

              ---------------------------------------------------------------------
              -- DDMEDICA-5009 - Rebaixa de CMV com Verba de Fornecedor da Promoção
              ---------------------------------------------------------------------
              IF (NVL(vrItemPedido.nVLDESCCMVPROMOCAOMED,0) <> 0) THEN
                -- LOG
                P_INSERE_LOG(viLacoValidar, 'VERBA Fornecedor Produto: ' || vrItemPedido.nCODPROD);
                P_INSERE_LOG(viLacoValidar, 'OLD VLVERBACMV: ' || vrItemPedido.nVLVERBACMV);
                --                   
                vrItemPedido.nVLVERBACMV := vrItemPedido.nVLDESCCMVPROMOCAOMED;
                vnPRECOBRUTO := (NVL(vrItemPedido.nPTABELA,0) - NVL(vrItemPedido.nST,0) - NVL(vrItemPedido.nVLREPASSE,0) - NVL(vrItemPedido.nVLFECP,0));
                IF (vnPRECOBRUTO = 0) THEN
                  vrItemPedido.nPERCCUSTFORNEC := 0;
                ELSE
                  BEGIN
                    vrItemPedido.nPERCCUSTFORNEC := (NVL(vrItemPedido.nVLDESCCMVPROMOCAOMED,0) / NVL(vnPRECOBRUTO,0)) * 100;
                  EXCEPTION
                    WHEN OTHERS THEN 
                      vrItemPedido.nPERCCUSTFORNEC := NULL;
                  END;
                END IF;
                -- LOG
                P_INSERE_LOG(viLacoValidar, 'NEW VLVERBACMV: '       || vrItemPedido.nVLVERBACMV);
                P_INSERE_LOG(viLacoValidar, 'vldesccmvpromocaomed: ' || vrItemPedido.nVLDESCCMVPROMOCAOMED);
                P_INSERE_LOG(viLacoValidar, 'vnPRECOBRUTO: '         || vnPRECOBRUTO);
                P_INSERE_LOG(viLacoValidar, 'perccustfornec: '       || vrItemPedido.nPERCCUSTFORNEC);
                P_INSERE_LOG(viLacoValidar, 'numverbacampanha: '     || vrItemPedido.nNUMVERBACAMPANHA);
                --                                         
              ELSE
                IF NOT pi_nTipoChamada in (11) THEN
                  IF (vbUsaVerbaPromocao) AND nvl(vrItemPedido.nNUMVERBAREBCMV,0) = 0 THEN
                    P_INSERE_LOG(viLacoValidar, 'Removendo OLD VLVERBACMV: ' || vrItemPedido.nVLVERBACMV);
                    vrItemPedido.nVLVERBACMV := NULL;
                  END IF;                
                  vrItemPedido.nNUMVERBACAMPANHA     := NULL;
                  vrItemPedido.nVLDESCCMVPROMOCAOMED := NULL;
                  vrItemPedido.nPERCCUSTFORNEC       := NULL;
                END IF;     
              END IF;

              --// PCNIL - MERGE: 2316 - Tarefa 118427
              IF (NVL(vrParamFilial.vUSADESCSIMPLESNAC,'N') = 'S') THEN

                 -- Deve usar o Valor do Desconto do Simmples Nacional antes de aplicar qualquer política que altera PTabela
                 vrItemPedido.nVLREDPVENDASIMPLESNA := NVL(vrItemPedido.nVALORDESCSIMPLESNAC,0);

              END IF;

              --------------------------------
              -- Se Cliente Simples Nacional
              -- e Filial usa Desconto Simples
              --------------------------------
              IF (NVL(vrClienteDestino.nSIMPLESNACIONAL,'N') = 'S') AND
                 (NVL(vrParamFilial.vUSADESCSIMPLESNAC ,'N') = 'S') THEN

                --// Guarda o VLREDCMVSIMPLESNAC
                vrItemPedido.nVLREDCMVSIMPLESNAC := vrItemPedido.nCUSTOFINEST * (NVL(vrTabPreco.nPERCDESCSIMPLESNAC,0) / 100);
                --// Reduz o CMV igual a 2316
                vrItemPedido.nVLCUSTOFIN         := vrItemPedido.nVLCUSTOFIN  - NVL(vrItemPedido.nVLREDCMVSIMPLESNAC,0);
                vrItemPedido.nVLCUSTOREAL        := vrItemPedido.nVLCUSTOREAL - NVL(vrItemPedido.nVLREDCMVSIMPLESNAC,0);

              END IF;

              -------------------------------------------------
              -- MED-2453 - Verba CMV do Cliente
              -- (Aplicado sobre o Preço de Venda com Impostos)
              -------------------------------------------------
              IF (NVL(vrRetCmvCli.nPERCVERBA,0) <> 0) THEN

                -- Para igualar a 2316, será gravado no campo pcpedi.vlverbacmvcli
                vrItemPedido.nVLVERBACMVCLI := vrItemPedido.nPVENDA *(vrRetCmvCli.nPERCVERBA / 100);

                -- Soma Valor da Verba CMV Cliente no CMV
                vrItemPedido.nVLCUSTOFIN  := NVL(vrItemPedido.nVLCUSTOFIN,0)  + NVL(vrItemPedido.nVLVERBACMVCLI,0);
                vrItemPedido.nVLCUSTOREAL := NVL(vrItemPedido.nVLCUSTOREAL,0) + NVL(vrItemPedido.nVLVERBACMVCLI,0);

              END IF;
              -------------------------------------------

              --------------------------------------
              -- Inicializa outros valores do Pedido
              --------------------------------------

              vrItemPedido.vGRUPOFATURAMENTO    := vrProduto_O.vGRUPOFATURAMENTO;

              vrItemPedido.vBRINDE              := 'N';

              vrItemPedido.vTRUNCARITEM         := 'N';

              vrItemPedido.vPOLITICAPRIORITARIA := 'N';

              -- Tipo Entrega
              IF    (NVL(pi_nOpcaoTipoEntrega,0) = 1) THEN
                vrItemPedido.vTIPOENTREGA := 'RP';
              ELSIF (NVL(pi_nOpcaoTipoEntrega,0) = 2) THEN
                vrItemPedido.vTIPOENTREGA := 'RI';
              ELSIF (NVL(pi_nOpcaoTipoEntrega,0) = 3) THEN
                vrItemPedido.vTIPOENTREGA := 'EN';
              ELSE
                vrItemPedido.vTIPOENTREGA := NULL;
              END IF;

              ---------------------------------------------------------------------
              -- Regra Específica - Deixar o Percentual de Desconto igual ao Pacote
              ---------------------------------------------------------------------
              IF (vrRegraMed.vUSAREGRARECALCPERDESCIMPOSTOS = 'S') THEN
                IF (NVL(vrItemPedido.nPTABELA,0) > 0) THEN
                  vrItemPedido.nPERDESC := ((NVL(vrItemPedido.nPTABELA,0) - NVL(vrItemPedido.nPVENDA,0)) / NVL(vrItemPedido.nPTABELA,0)) * 100;
                ELSE
                  vrItemPedido.nPERDESC := 0;
                END IF;
                vrItemPedido.nPERDESC := ROUND(vrItemPedido.nPERDESC,4);
              END IF;

              -- Tipo de Desconto Flexível
              IF (NVL(vrItemPedido.nPERDESC,0) <= NVL(vrClienteDestino.nPERDESC,0)) THEN
                vrItemPedido.vTIPODESCFLEX := '1';
                vrItemPedido.nPERCDESCFLEX := NVL(vrClienteDestino.nPERDESC,0);
              ELSE
                IF (NVL(vrTabPreco.nPERDESCMAX,0) > NVL(vrClienteDestino.nPERDESC,0)) THEN
                  vrItemPedido.vTIPODESCFLEX := '2';
                  vrItemPedido.nPERCDESCFLEX := NVL(vrTabPreco.nPERDESCMAX,0);
                END IF;
              END IF;
              IF (NVL(vrItemPedido.nPERCDESCBASERCA,0) > NVL(vrItemPedido.nPERCDESCFLEX,0)) THEN
                vrItemPedido.vTIPODESCFLEX := '3';
                vrItemPedido.nPERCDESCFLEX := NVL(vrItemPedido.nPERCDESCBASERCA,0);
              END IF;
              IF (NVL(vrOrigemPreco.vvAchouAutoriPreco,'N') = 'S') AND
                 (NVL(vrOrigemPreco.vnCodAutorizacao,0) > 0) THEN
                vrItemPedido.vTIPODESCFLEX := '5';
                vrItemPedido.nPERCDESCFLEX := NVL(vrOrigemPreco.vnPerdDescAutorizado,0);
              END IF;
              
              -- Log de Alteração da Promoção Item - DDMEDICA-4799
              IF (NVL(vrItemPedido.nCODPROMOCAOMED,0) <> NVL(vrItemPedido.nCODPROMOCAOMED_OLD,0)) THEN
                P_INSERE_LOG(viLacoValidar, 'Produto em Promoção: ' || NVL(vtIncluiItens(viNumSeq).vnCodProd,0));
                P_INSERE_LOG(viLacoValidar, 'pi_nTipoChamada: ' || NVL(pi_nTipoChamada,0));
                P_INSERE_LOG(viLacoValidar, 'pi_nCodPromocaoMed: ' || NVL(pi_nCodPromocaoMedPedido,0));
                P_INSERE_LOG(viLacoValidar, 'Promoção do Item Anterior: ' || NVL(vrItemPedido.nCODPROMOCAOMED_OLD,0));
                P_INSERE_LOG(viLacoValidar, 'Nova Promoção do Item: ' || NVL(vrItemPedido.nCODPROMOCAOMED_OLD,0));
                P_INSERE_LOG(viLacoValidar, 'Observação: ' || vrItemPedido.vOBSCODPROMOCAOMED_OLD);
              END IF;
              
              -- DDVENDAS-33950 - Não permitir valores nulos
              IF (vrItemPedido.nBASEICST IS NULL) THEN
                vrItemPedido.nBASEICST := NVL(vrItemPedido.nBASEICST,0);
              END IF;
              IF (vrItemPedido.nST IS NULL) THEN
                vrItemPedido.nST := NVL(vrItemPedido.nST,0);
              END IF;

              --------------------------------------------------------------------------------------
              -- Insere na TABELA TEMP BONIFICAÇÃO EM MERCADORIA DE PROMOÇÃO somente no segundo laço
              --------------------------------------------------------------------------------------
              IF (viLacoValidar   = 2)      AND
                 (pi_nTipoChamada IN (6,8)) THEN

                -- Verifica se o Produto + Promoção já existe na Tabela Temporária
                BEGIN
                  SELECT 'S'
                    INTO vvAchouProduto
                    FROM PCMED_TEMP_PROMO_BONIFICMERC
                   WHERE (CODPROD        = vrItemPedido.nCODPROD)
                     AND (CODPROMOCAOMED = vrItemPedido.nCODPROMOCAOMED)
                     AND (ROWNUM         = 1);
                EXCEPTION
                  WHEN NO_DATA_FOUND THEN
                    vvAchouProduto := 'N';
                END;

                -- Se já existe na Tabela Temporária
                IF (vvAchouProduto = 'S') THEN
                  -- Atualiza na Tabela Temporária
                  UPDATE PCMED_TEMP_PROMO_BONIFICMERC
                     SET QUANTIDADE = NVL(QUANTIDADE,0) + NVL(vrItemPedido.nQT,0)
                       , VALORTOTAL = NVL(VALORTOTAL,0) + ((NVL(vrItemPedido.nPVENDA,0) - NVL(vrItemPedido.nST,0) - NVL(vrItemPedido.nVLFECP,0) - NVL(vrItemPedido.nVLREPASSE,0)) * NVL(vrItemPedido.nQT,0))
                   WHERE (TIPOREG        = 'I')
                     AND (CODPROD        = vrItemPedido.nCODPROD)
                     AND (CODPROMOCAOMED = vrItemPedido.nCODPROMOCAOMED);
                ELSE
                  -- Insere na Tabela Temporária
                  INSERT INTO PCMED_TEMP_PROMO_BONIFICMERC
                            ( TIPOREG
                            , CODPROD
                            , DESCRICAO
                            , QUANTIDADE
                            , VALORTOTAL
                            , CODPROMOCAOMED )
                     VALUES ( 'I'
                            , vrItemPedido.nCODPROD
                            , vrProduto_O.vDESCRICAO
                            , NVL(vrItemPedido.nQT,0)
                            , ((NVL(vrItemPedido.nPVENDA,0) - NVL(vrItemPedido.nST,0) - NVL(vrItemPedido.nVLFECP,0) - NVL(vrItemPedido.nVLREPASSE,0)) * NVL(vrItemPedido.nQT,0))
                            , vrItemPedido.nCODPROMOCAOMED );

                  -- Atualiza a Quantidade de Produtos Inseridos
                  viQtdeProdutosInseridos := NVL(viQtdeProdutosInseridos,0) + 1;
                END IF;

              END IF; -- Fim Condição Insere na TABELA TEMP BONIFICAÇÃO EM MERCADORIA DE PROMOÇÃO somente no segundo laço

              --------------------------------------------------------------------------------------
              -- Atualiza TABELA TEMP DE BRINDES DA CAMPANHA - HIS.01889.2017
              --------------------------------------------------------------------------------------
              IF (viLacoValidar   = 2)  AND
                 (pi_nTipoChamada = 13) THEN

                -- Atualiza na Tabela Temporária - BRINDES (Observação: O MIX só computo as Vendas, portanto já passou pelas Validações, não entra neste Laço, já atualizo no Laço da PCPEDI no inicio da proc.)
                UPDATE PCMED_PROMOCAO_CAMPANHA_BRI
                   SET PRECOTABELA            = (NVL(vrItemPedido.nPTABELA,0) - NVL(vrItemPedido.nST,0) - NVL(vrItemPedido.nVLREPASSE,0) - NVL(vrItemPedido.nVLFECP,0))
                     , PRECOLIQUIDO           = (NVL(vrItemPedido.nPVENDA,0)  - NVL(vrItemPedido.nST,0) - NVL(vrItemPedido.nVLREPASSE,0) - NVL(vrItemPedido.nVLFECP,0))
                     , BLOQUEIOCAMPANHA       = vrItemPedido.vBLOQUEIOCAMPANHA
                     , MOTIVOBLOQUEIOCAMPANHA = vrItemPedido.vMOTIVOBLOQUEIOCAMPANHA
                 WHERE (CODPROMOCAOMEDREF = vrItemPedido.nCODPROMOCAOMED)
                   AND (CODPROD           = vrItemPedido.nCODPROD);

              END IF; -- Fim Condição Atualiza TABELA TEMP DE BRINDES DA CAMPANHA - HIS.01889.2017

              -----------------------------------------------------------------------------------------------------------------------------
              -- Somente pode inserir na TABELA PCPEDI:
              -- se não for para Inserir Somente na TABELA TEMP BONIFICAÇÃO EM MERCADORIA DE PROMOÇÃO
              -- se não for para Inserir Somente na TABELA TEMP PROMOÇÃO DE CAMPANHA - HIS.01889.2017
              -- se não for para Validar Promoção de Mix/Valor Mínimo - HIS.01889.2017
              -----------------------------------------------------------------------------------------------------------------------------
              IF (pi_nTipoChamada NOT IN (8,13,14)) THEN

                -------------------------------------------
                -- Insere na PCPEDI somente no segundo Laço
                -------------------------------------------
                IF (viLacoValidar = 2) THEN

                  -- PEDIDO DE LICITAÇÃO - Sempre Insere os Itens
                  -- FOI ADICIONADO O TIPO CHAMADA 6, PARA QUE SEJA SEMPRE INCLUIDO O ITEM BONIFICADO,
                  -- ISSO FOI NECESSÁRIO PQ QUANDO O PRODUTO BONIFICADO ERA ELE MESMO, ESTAVA SOMANDO E O CORRETO ERA ADICIONAR UM NOVO REGISTO.
                  -- SE INCLUSÃO DO ITEM DE CAMPANNA - HIS.01889.2017
                  -- SE INCLUSAO DE ITENS DE CROSS DOCKING [16] - MED-1096
                  -- SE IMPORTAÇÃO DE PRODUTOS
                  IF    (pi_nTipoChamada IN (3,6,11,15
                                            ,16 -- ITENS CROSS DOCKING [16] - MED-1096
                                            ,17
                                            )) THEN

                    vvAchouProduto := 'N';

                  -- ALTERAÇÃO DE PROMOÇÃO DO PEDIDO - Sempre Atualiza os Itens
                  -- APLICAÇÃO DO DESCONTO ADICIONAL PLANO A VISTA - Sempre Atualiza os Itens
                  -- RECALCULO DO PEDIDO AO ALTERAR PLANO DE PAGAMENTO - Sempre Atualiza os Itens
                  -- ATUALIZAÇÃO DO PREÇO DO BRINDE - Sempre Atualiza os Itens
                  ELSIF (pi_nTipoChamada IN (4,5,10,12)) THEN

                    vvAchouProduto := 'S';

                  -- DEMAIS CHAMADAS
                  -- *** Inclusive BONIFICAÇÃO EM MERCADORIA DE PROMOÇÃO
                  ELSE
                    
                    -- Se Licitação não deixar Nulo
                    IF (pi_nTipoChamada = 18) THEN
                       vrItemPedido.nCODPROMOCAOMED := NVL(vrItemPedido.nCODPROMOCAOMED,0);
                    END IF;

                    -- Verifica se o Produto + Promoção já existe no Pedido
                    IF (vvCodFilialRetira IS NULL) THEN
                      BEGIN
                        SELECT 'S'
                          INTO vvAchouProduto
                          FROM PCPEDI
                         WHERE (NUMPED         = pi_nNumPed)
                           AND (CODPROD        = vrItemPedido.nCODPROD)
                           AND (CODPROMOCAOMED = vrItemPedido.nCODPROMOCAOMED)
                           AND (ROWNUM         = 1);
                      EXCEPTION
                        WHEN NO_DATA_FOUND THEN
                          vvAchouProduto := 'N';
                      END;
                    -- Verifica se o Produto + Promoção + Filial Retira já existe no Pedido
                    ELSE
                      BEGIN
                        SELECT 'S'
                          INTO vvAchouProduto
                          FROM PCPEDI
                         WHERE (NUMPED          = pi_nNumPed)
                           AND (CODPROD         = vrItemPedido.nCODPROD)
                           AND (CODPROMOCAOMED  = vrItemPedido.nCODPROMOCAOMED)
                           AND (CODFILIALRETIRA = NVL(vvCodFilialRetira,pi_vCodFilial))
                           AND (ROWNUM          = 1);
                      EXCEPTION
                        WHEN NO_DATA_FOUND THEN
                          vvAchouProduto := 'N';
                      END;
                    END IF;

                  END IF; -- Fim Condição pra definir se Atualiza ou Insere Item no Pedido

                  -- SE JÁ EXISTE O PRODUTO + PROMOÇÃO + (FILIAL RETIRA)
                  IF (NVL(vvAchouProduto,'N') = 'S') THEN

                    -- ALTERAÇÃO DE PROMOÇÃO DO PEDIDO
                    -- APLICAÇÃO DO DESCONTO ADICIONAL PLANO A VISTA
                    -- RECALCULO DO PEDIDO AO ALTERAR PLANO DE PAGAMENTO
                    -- ATUALIZAÇÃO DO PREÇO DO BRINDE
                    IF (pi_nTipoChamada IN (4,5,10,12)) THEN

                      -- Atualiza Item do Pedido
                      UPDATE PCPEDI
                         SET BASEICST                  = vrItemPedido.nBASEICST
                           , ST                        = vrItemPedido.nST
                           , PERFRETECMV               = vrItemPedido.nPERFRETECMV
                           , CUSTOFINEST               = vrItemPedido.nCUSTOFINEST
                           , TXVENDA                   = vrItemPedido.nTXVENDA
                           , PERDESCCUSTO              = vrItemPedido.nPERDESCCUSTO
                           , CODICMTAB                 = vrItemPedido.nCODICMTAB
                           , VLCUSTOFIN                = vrItemPedido.nVLCUSTOFIN
                           , VLCUSTOREAL               = vrItemPedido.nVLCUSTOREAL
                           , VLDESCCUSTOCMV            = vrItemPedido.nVLDESCCUSTOCMV
                             --
                           , PVENDA                   = vrItemPedido.nPVENDA
                           , PTABELA                  = vrItemPedido.nPTABELA
                           , PBASERCA                 = vrItemPedido.nPBASERCA
                           , STPBASERCA               = vrItemPedido.nSTPBASERCA
                           , STPTABELA                = vrItemPedido.nSTPTABELA
                           , REGIMEESPISENSTFONTE     = vrItemPedido.nREGIMEESPISENSTFONTE
                           , ALIQICMS1                = vrItemPedido.nALIQICMS1
                           , ALIQICMS2                = vrItemPedido.nALIQICMS2
                           , IVA                      = vrItemPedido.nIVA
                           , PERCBASEREDSTFONTE       = vrItemPedido.nPERCBASEREDSTFONTE
                             --
                           , PERDESC                  = vrItemPedido.nPERDESC
                           , PERDESCBOLETO            = vrItemPedido.nPERDESCBOLETO
                           , VLDESCBOLETO             = vrItemPedido.nPERDESCBOLETO
                           , CODDESCONTO              = vrItemPedido.nCODDESCONTO
                           , CODPROMOCAOMED           = vrItemPedido.nCODPROMOCAOMED
                           , INICIOINTERVALODESCQUANT = vrItemPedido.nINICIOINTERVALODESCQUANT
                           , PERCOM                   = vrItemPedido.nPERCOM
                           , PARTICIPAGIRO            = vrItemPedido.vPARTICIPAGIRO
                           --
                           , PERBONIFIC               = vrItemPedido.nPERBONIFIC
                           , VLBONIFIC                = vrItemPedido.nVLBONIFIC
                           --
                           , VLREDPVENDASIMPLESNA     = vrItemPedido.nVLREDPVENDASIMPLESNA
                           , VLREDCMVSIMPLESNAC       = vrItemPedido.nVLREDCMVSIMPLESNAC
                           --
                           , PRAZOMEDIO               = vrItemPedido.nPRAZOMEDIO          -- HIS.01240.2016
                           , VLTAXAPRAZOMEDCMV        = vrItemPedido.nVLTAXAPRAZOMEDCMV   -- HIS.01240.2016
                           , PERCTAXAPRAZOMEDCMV      = vrItemPedido.nPERCTAXAPRAZOMEDCMV -- HIS.01240.2016
                           , VLDESCBOLETOCMV          = vrItemPedido.nVLDESCBOLETOCMV     -- HIS.01240.2016
                           --
                           , VLBASEPARTDEST           = vrItemPedido.nVLBASEPARTDEST
                           , ALIQFCP                  = vrItemPedido.nALIQFCP
                           , VLFCPPART                = vrItemPedido.nVLFCPPART
                           , VLICMSPARTDEST           = vrItemPedido.nVLICMSPARTDEST
                           , VLICMSPART               = vrItemPedido.nVLICMSPART
                           , VLICMSDIFALIQPART        = vrItemPedido.nVLICMSDIFALIQPART
                           , PERCBASEREDPART          = vrItemPedido.nPERCBASEREDPART
                           , PERCPROVPART             = vrItemPedido.nPERCPROVPART
                           , VLICMSPARTREM            = vrItemPedido.nVLICMSPARTREM
                           , ALIQINTERNADEST          = vrItemPedido.nALIQINTERNADEST
                           , ALIQINTERORIGPART        = vrItemPedido.nALIQINTERORIGPART
                           , CODFISCAL                = vrItemPedido.nCODFISCAL -- HIS.03261.2016
                           , SITTRIBUT                = vrItemPedido.vSITTRIBUT -- HIS.03261.2016
                           -->> Somente Grava na Inclusão (Log Combo) - CAMPO TIPOCOMISSAOMED não atualiza aqui
                           , PAUTA                    = vrItemPedido.nPAUTA -- HIS.03376.2017
                           , OBSERVACAOSTFONTE        = vrItemPedido.vOBSERVACAOSTFONTE  -- HIS.03376.2017
                           , INDESCALARELEVANTE       = vrItemPedido.vINDESCALARELEVANTE -- HIS.03376.2017
                           , CNPJFABRICANTE           = vrItemPedido.vCNPJFABRICANTE -- HIS.03376.2017
                           , FABRICANTE               = vrItemPedido.vFABRICANTE -- HIS.03376.2017
                           -- MED-1090 - Valores FCP
                           , VLFECP                   = vrItemPedido.nVLFECP
                           , VLBASEFCPST              = vrItemPedido.nVLBASEFCPST
                           , ALIQICMSFECP             = vrItemPedido.nALIQICMSFECP
                           -- MED-2453
                           , VLVERBACMVCLI            = vrItemPedido.nVLVERBACMVCLI
                           -- DDMEDICA-1172
                           , VLDESCSUFRAMA            = vrItemPedido.nVLDESCSUFRAMA
                           , VLDESCPISSUFRAMA         = vrItemPedido.nVLDESCPISSUFRAMA
                           , VLDESCREDUCAOPIS         = vrItemPedido.nVLDESCREDUCAOPIS
                           , PERCDESCPIS              = vrItemPedido.nPERCDESCPIS
                           , VLDESCREDUCAOCOFINS      = vrItemPedido.nVLDESCREDUCAOCOFINS
                           , PERCDESCCOFINS           = vrItemPedido.nPERCDESCCOFINS
                           --
                           , CODIGOINTEGRACAOWMS      = vrItemPedido.vCODIGOINTEGRACAOWMS
                           -- DDMEDICA-5009
                           , VLDESCCMVPROMOCAOMED     = vrItemPedido.nVLDESCCMVPROMOCAOMED
                           , NUMVERBACAMPANHA         = vrItemPedido.nNUMVERBACAMPANHA
                           , VLVERBACMV               = vrItemPedido.nVLVERBACMV
                           , PERCCUSTFORNEC           = vrItemPedido.nPERCCUSTFORNEC
                           --
                           , VLDESCICMISENCAO         = vrItemPedido.nVLDESCICMISENCAO  -- DDMEDICA-6874
                           , PERDESCISENTOICMS        = vrItemPedido.nPERDESCISENTOICMS -- DDMEDICA-6874
                           -- DDMEDICA-7697
                           , BCSTRETANTERIOR          = vrItemPedido.nBCSTRETANTERIOR
                           , VLICMSSUBSTITUTOANTERIOR = vrItemPedido.nVLICMSSUBSTITUTOANTERIOR
                           , VLICMSSTRETANTERIOR      = vrItemPedido.nVLICMSSTRETANTERIOR                           
                           , STCLIENTEGNRE            = vrItemPedido.nSTCLIENTEGNRE
                           , PMPFMEDICAMENTO          = vrItemPedido.nPMPFMEDICAMENTO
                       WHERE (NUMPED        = pi_nNumPed)
                         AND (CODPROD       = vrItemPedido.nCODPROD)
                         AND (NVL(NUMSEQ,0) = vrItemPedido.nNUMSEQ);

                      -- Atualiza Origem do Preço
                      UPDATE PCORIGEMPRECO
                         SET USATRIBUTPORUF         = vrPcConsum.vUSATRIBUTACAOPORUF
                           , ORIGEMPRECO            = vrItemPedido.vORIGEMPRECO
                           , COLUNAPRECO            = vrPlanoPag.nNUMPR
                           , ORIGEMPED              = pi_vOrigemPed
                           , CODFILIAL              = pi_vCodFilial
                           , CODFILIALNF            = pi_vCodFilialNF
                           , PERBONIFIC             = vrItemPedido.nPERBONIFIC
                           , VLBONIFIC              = vrItemPedido.nVLBONIFIC
                           , VLREPASSE              = vrItemPedido.nVLREPASSE
                           , VLICMSPARTILHA         = vrItemPedido.nVLICMSPART
                           , VLDESCICMS             = vrItemPedido.nVLDESCICMISENCAO
                           , PERCPLPAG              = vrPlanoPag.nPERTXFIM
                           , PERCRAMOATIV           = vrItemPedido.nPERCRAMOATIV
                           , TIPODESCFLEX           = vrItemPedido.vTIPODESCFLEX
                           , PERCDESCFLEX           = vrItemPedido.nPERCDESCFLEX
                           , NUMREGIAO              = vrRegiao.nNUMREGIAO
                           , VLREDPVENDASIMPLESNA   = vrItemPedido.nVLREDPVENDASIMPLESNA
                           , CODACORDOPARCERIA      = vrItemPedido.nCODACORDOPARCERIA
                           , PERCDESCACORDOPARCERIA = vrItemPedido.nPERCDESCACORDOPARCERIA
                           , VLICMSSTRETANTERIOR    = vrItemPedido.nVLICMSSTRETANTERIOR
                       WHERE (NUMPED  = pi_nNumPed)
                         AND (CODPROD = vrItemPedido.nCODPROD)
                         AND (NUMSEQ  = vrItemPedido.nNUMSEQ);

                    -- APLICAÇÃO DA PROMOÇÃO CASADINHA
                    ELSIF (pi_nTipoChamada IN (9,18)) THEN

                      -- Atualiza
                      IF (vvCodFilialRetira IS NULL) THEN
                        UPDATE PCPEDI
                           SET QT = NVL(vrItemPedido.nQT,0),
                               QTCOMBOVIRTUAL = NVL(vrItemPedido.nQTCOMBOVIRTUAL,0)
                         WHERE (NUMPED         = pi_nNumPed)
                           AND (CODPROD        = vrItemPedido.nCODPROD)
                           AND (CODPROMOCAOMED = vrItemPedido.nCODPROMOCAOMED);
                      ELSE
                        UPDATE PCPEDI
                           SET QT = NVL(vrItemPedido.nQT,0),
                               QTCOMBOVIRTUAL = NVL(vrItemPedido.nQTCOMBOVIRTUAL,0)
                         WHERE (NUMPED          = pi_nNumPed)
                           AND (CODPROD         = vrItemPedido.nCODPROD)
                           AND (CODPROMOCAOMED  = vrItemPedido.nCODPROMOCAOMED)
                           AND (CODFILIALRETIRA = NVL(vvCodFilialRetira,pi_vCodFilial));
                      END IF;

                    -- ATUALIZAÇÃO DO KIT
                    -- *** Inclusive BONIFICAÇÃO EM MERCADORIA DE PROMOÇÃO
                    ELSE

                      -- Atualiza
                      IF (vvCodFilialRetira IS NULL) THEN
                        UPDATE PCPEDI
                           SET QT = NVL(QT,0) + NVL(vrItemPedido.nQT,0),
                               QTCOMBOVIRTUAL = NVL(QTCOMBOVIRTUAL,0) + NVL(vrItemPedido.nQTCOMBOVIRTUAL,0)
                         WHERE (NUMPED         = pi_nNumPed)
                           AND (CODPROD        = vrItemPedido.nCODPROD)
                           AND (CODPROMOCAOMED = vrItemPedido.nCODPROMOCAOMED);
                      ELSE
                        UPDATE PCPEDI
                           SET QT = NVL(QT,0) + NVL(vrItemPedido.nQT,0),
                               QTCOMBOVIRTUAL = NVL(QTCOMBOVIRTUAL,0) + NVL(vrItemPedido.nQTCOMBOVIRTUAL,0)
                         WHERE (NUMPED          = pi_nNumPed)
                           AND (CODPROD         = vrItemPedido.nCODPROD)
                           AND (CODPROMOCAOMED  = vrItemPedido.nCODPROMOCAOMED)
                           AND (CODFILIALRETIRA = NVL(vvCodFilialRetira,pi_vCodFilial));
                      END IF;

                    END IF;

                  -- SE NÃO EXISTE O PRODUTO + PROMOÇÃO + (FILIAL RETIRA)
                  ELSE

                    -- RCA DA LINHA - DDMEDICA-2028
                    vnCodUsurLinha := NULL;
                    IF (vrRegraMed.vAPURARCOMISSAOPELORCALINHA = 'S') THEN
                      vnCodUsurLinha := F_OBTER_RCA_LINHAPROD(pi_nCodCli,
                                                              vrItemPedido.nCODPROD,
                                                              pi_vCodFilial,
                                                              vrParamFilial.vUSARCACLIENTELINHAPORFILIALME);
                    END IF;

                    -- Próxima Seq. Item
                    SELECT NVL(MAX(PCPEDI.NUMSEQ),0) + 1
                      INTO vrItemPedido.nNUMSEQ
                      FROM PCPEDI
                     WHERE (NUMPED = pi_nNumPed);

                    -- DDMEDICA-5126 - Qt. Falta Digitação
                    BEGIN
                      SELECT PKG_FUNCOESVENDAS_MED.F_OBTER_ESTOQUE_DISP(vrItemPedido.nCODPROD,
                                                                        NVL(vrItemPedido.nCODFILIALRETIRA, 
                                                                            NVL(vvCodFilialRetira,
                                                                                pi_vCodFilial))) QTDISPONIVEL
                        INTO vnQtEstoqueDisp
                        FROM DUAL;
                    EXCEPTION
                      WHEN NO_DATA_FOUND THEN
                        vnQtEstoqueDisp := 0;
                    END;
                    IF (vnQtEstoqueDisp < 0) THEN
                      vnQtEstoqueDisp := 0;
                    END IF;
                    IF (NVL(vrItemPedido.nQT,0) > NVL(vnQtEstoqueDisp,0)) THEN
                      vnQtFaltaDigitacao := (NVL(vrItemPedido.nQT,0) - NVL(vnQtEstoqueDisp,0));
                    ELSE
                      vnQtFaltaDigitacao := 0;
                    END IF;

                    -- DDMEDICA-5420
                    nQTUNIT := NULL;

                    IF NVL(vrParamFilial.vUTILIZAVENDAPOREMBALAGEM,'N') = 'S' THEN
                      BEGIN
                          SELECT PCEMBALAGEM.QTUNIT
                            into nQTUNIT
                            FROM PCPRODUT, PCEMBALAGEM
                           WHERE (PCPRODUT.CODAUXILIAR  = PCEMBALAGEM.CODAUXILIAR)
                             AND (PCEMBALAGEM.CODFILIAL = pi_vCodFilial)
                             AND (PCPRODUT.CODPROD      = vrItemPedido.nCODPROD);
                      EXCEPTION
                        WHEN NO_DATA_FOUND THEN
                          nQTUNIT := NULL;
                      END;
                    END IF;

                    -- Insere
                    INSERT INTO PCPEDI
                              ( NUMPED
                              , CODPROD
                              , NUMSEQ
                              , QT
                              , PVENDA
                              , DATA
                              , CODCLI
                              , CODUSUR
