                              , PERBONIFIC
                              , VLBONIFIC
                              , PORIGINAL
                              , PBASERCA
                              , ROTINALANC
                              , CODDESCONTO
                              , CODPROMOCAOMED
                              , INICIOINTERVALODESCQUANT
                              , PARTICIPAGIRO
                              , TRUNCARITEM
                              , POLITICAPRIORITARIA
                              , PVENDA1
                              , STPTABELA
