                              , REGIMEESPISENSTFONTE
                              , VLDESCICMISENCAO
                              , PERDESCISENTOICMS
                              , LOTECONTRATO
                              , NUMSEQITEMCONTRATO
                              -- Valores Custo
                              , PERFRETECMV
                              , CUSTOFINEST
                              , TXVENDA
                              , PERDESCCUSTO
                              , CODICMTAB
                              , VLCUSTOFIN
                              , VLCUSTOREAL
                              , VLDESCCUSTOCMV
                              --
                              , PBONIFIC
                              --
                              , VLREDPVENDASIMPLESNA
                              , VLREDCMVSIMPLESNAC
                              --
                              , CODPLPAG
                              , CODLINHAPRAZO
                              --
                              , PRAZOMEDIO
                              , VLTAXAPRAZOMEDCMV
                              , PERCTAXAPRAZOMEDCMV
                              , VLDESCBOLETOCMV
                              --
                              , VLBASEPARTDEST
                              , ALIQFCP
                              , VLFCPPART
                              , VLICMSPARTDEST
                              , VLICMSPART
                              , VLICMSDIFALIQPART
                              , PERCBASEREDPART
                              , PERCPROVPART
                              , VLICMSPARTREM
                              , ALIQINTERNADEST
                              , ALIQINTERORIGPART
                              , CODFISCAL         -- HIS.03261.2016
                              , SITTRIBUT         -- HIS.03261.2016
                              , PRODIMPORTADOPEPS -- HIS.02786.2016
                              , NUMTRANSENTPEPS   -- HIS.02786.2016
                              , TIPOCOMISSAOMED   -->> Somente Grava na Inclusão (Log Combo)
                              --
                              , OBSERVACAOSTFONTE  -- HIS.03376.2017
                              , INDESCALARELEVANTE -- HIS.03376.2017
                              , CNPJFABRICANTE     -- HIS.03376.2017
                              , FABRICANTE         -- HIS.03376.2017
                              -- MED-1090 - Valores FCP
                              , VLFECP
                              , VLBASEFCPST
                              , ALIQICMSFECP
                              --
                              , FATORGRAMATURALICIT
                              -- MED-2453
                              , VLVERBACMVCLI
                              -- CROSSDOCKING
                              , NUMLOTE
                              -- DDMEDICA-1172
                              , VLDESCSUFRAMA
                              , VLDESCPISSUFRAMA
                              , VLDESCREDUCAOPIS
                              , VLDESCREDUCAOCOFINS
                              --
                              , CODIGOINTEGRACAOWMS
                              , NUMLOTEPROMOCAOMED
                              -- DDMEDICA-5009
                              , VLDESCCMVPROMOCAOMED
                              , NUMVERBACAMPANHA
                              , VLVERBACMV
                              , PERCCUSTFORNEC
                              , QTFALTADIGITACAO -- DDMEDICA-5126
                              , QTEMBALAGEM -- DDMEDICA-5420
                              , CODAUXILIAR -- DDMEDICA-7318
                              , PERCDESCPIS              
                              , PERCDESCCOFINS              
                              -- DDMEDICA-7697
                              , BCSTRETANTERIOR
                              , VLICMSSUBSTITUTOANTERIOR
                              , VLICMSSTRETANTERIOR
                              , PMPFMEDICAMENTO
                              -- DDVENDAS-33442
                              , CODEDITAL
                              , QTPEDLICIT
                              , TIPOCONVERSAOPEDLICIT
                              , UNIDADECONVERSAOPEDLICIT
                              , FATORCONVERSAOPEDLICIT
