                              , PRODDESCRICAOCONTRATO
                              , NUMVERBAREBCMV
                              , NUMITEMPED
                              , QTCOMBOVIRTUAL
                              )
                        VALUES( pi_nNumPed                            -- NUMPED
                              , vrItemPedido.nCODPROD                 -- CODPROD
                              , vrItemPedido.nNUMSEQ                  -->> Próx. Num. Seq. -- NUMSEQ
                              , vrItemPedido.nQT                      -- QT
                              , vrItemPedido.nPVENDA                  -- PVENDA
                              , vdDataItemPedido                      -- DATA -- Priorizar a Data do Cab. Pedido - 5232.029277.2017
                              , pi_nCodCli                            -- CODCLI
                              , DECODE(NVL(vnCodUsurLinha,0),0,
                                       pi_nCodUsur,
                                       vnCodUsurLinha)                -- CODUSUR - DDMEDICA-2028
                              , vrItemPedido.nPTABELA                 -- PTABELA
                              , pi_vPosicao                           -- POSICAO
                              , 0                                     -- NUMCAR
                              , vrItemPedido.nPVENDABASE              -- PVENDABASE
                              , vrItemPedido.nCODST                   -- CODST
                              , vrItemPedido.nPERDESC                 -- PERDESC
                              , vrItemPedido.nST                      -- ST
                              , vrItemPedido.nPERCIPI                 -- PERCIPI
                              , vrItemPedido.nVLIPI                   -- VLIPI
                              , vrItemPedido.nIVA                     -- IVA
                              , vrItemPedido.nPAUTA                   -- PAUTA
                              , vrItemPedido.nALIQICMS1               -- ALIQICMS1
