                              , vrItemPedido.nPERCBASEREDST           -- PERCBASEREDST
                              , vrItemPedido.nSTCLIENTEGNRE           -- STCLIENTEGNRE
                              , vrItemPedido.nPERCOM                  -- PERCOM
                              , vrItemPedido.nVLCUSTOCONT             -- VLCUSTOCONT
                              , vrItemPedido.nVLCUSTOREP              -- VLCUSTOREP
                              , vrItemPedido.vBRINDE                  -- BRINDE
                              , vrItemPedido.vBONIFIC                 -- BONIFIC
                              , vrItemPedido.vTIPOENTREGA             -- TIPOENTREGA
                              , vrItemPedido.nPRECOMAXCONSUM          -- PRECOMAXCONSUM
                              , vrItemPedido.nBASEICST                -- BASEICST
                              , vrItemPedido.vGRUPOFATURAMENTO        -- GRUPOFATURAMENTO
                              , vrItemPedido.nPERDESCBOLETO           -- PERDESCBOLETO
                              , vrItemPedido.nVLDESCBOLETO            -- VLDESCBOLETO
                              , vrItemPedido.nPERBONIFIC              -- PERBONIFIC
                              , vrItemPedido.nVLBONIFIC               -- VLBONIFIC
                              , vrItemPedido.nPORIGINAL               -- PORIGINAL
                              , vrItemPedido.nPBASERCA                -- PBASERCA
                              , pi_nRotinaLanc                        -- ROTINALANC
                              , vrItemPedido.nCODDESCONTO             -- CODDESCONTO
                              , vrItemPedido.nCODPROMOCAOMED          -- CODPROMOCAOMED
                              , vrItemPedido.nINICIOINTERVALODESCQUANT--INICIOINTERVALODESCQUAN
                              , vrItemPedido.vPARTICIPAGIRO           -- PARTICIPAGIRO
                              , vrItemPedido.vTRUNCARITEM             -- TRUNCARITEM
                              , vrItemPedido.vPOLITICAPRIORITARIA     -- POLITICAPRIORITARIA
                              , vrItemPedido.nPVENDA1                 -- PVENDA1
                              , vrItemPedido.nSTPTABELA               -- STPTABELA
                              , vrItemPedido.nSTPBASERCA              -- nSTPBASERCA
                              , vrItemPedido.nVLOUTROS                -- VLOUTROS
                              , vrItemPedido.nVLREPASSE               -- VLREPASSE
                              , vrItemPedido.nPERCBASEREDSTFONTE      -- PERCBASEREDSTFONTE
                              , NVL(vrItemPedido.nCODFILIALRETIRA,
                                    NVL(vvCodFilialRetira,
                                        pi_vCodFilial))               -- CODFILIALRETIRA
                              , vrItemPedido.nREGIMEESPISENSTFONTE    -- REGIMEESPISENSTFONTE
                              , vrItemPedido.nVLDESCICMISENCAO        -- VLDESCICMISENCAO
                              , vrItemPedido.nPERDESCISENTOICMS       -- PERDESCISENTOICMS
                              , vrItemPedido.vLOTECONTRATO            -- LOTECONTRATO
                              , vrItemPedido.nNUMSEQITEMCONTRATO      -- NUMSEQITEMCONTRATO
                              -- Valores Custo
                              , vrItemPedido.nPERFRETECMV
                              , vrItemPedido.nCUSTOFINEST
                              , vrItemPedido.nTXVENDA
                              , vrItemPedido.nPERDESCCUSTO
                              , vrItemPedido.nCODICMTAB
                              , vrItemPedido.nVLCUSTOFIN
                              , vrItemPedido.nVLCUSTOREAL
                              , vrItemPedido.nVLDESCCUSTOCMV
                              --
                              , vrItemPedido.nPBONIFIC
                              --
                              , vrItemPedido.nVLREDPVENDASIMPLESNA
                              , vrItemPedido.nVLREDCMVSIMPLESNAC
                              --
                              , vrItemPedido.nCODPLPAG
                              , vrItemPedido.nCODLINHAPRAZO
                              --
                              , vrItemPedido.nPRAZOMEDIO          -- HIS.01240.2016
                              , vrItemPedido.nVLTAXAPRAZOMEDCMV   -- HIS.01240.2016
                              , vrItemPedido.nPERCTAXAPRAZOMEDCMV -- HIS.01240.2016
                              , vrItemPedido.nVLDESCBOLETOCMV     -- HIS.01240.2016
                              --
                              , vrItemPedido.nVLBASEPARTDEST
                              , vrItemPedido.nALIQFCP
                              , vrItemPedido.nVLFCPPART
                              , vrItemPedido.nVLICMSPARTDEST
                              , vrItemPedido.nVLICMSPART
                              , vrItemPedido.nVLICMSDIFALIQPART
                              , vrItemPedido.nPERCBASEREDPART
                              , vrItemPedido.nPERCPROVPART
                              , vrItemPedido.nVLICMSPARTREM
                              , vrItemPedido.nALIQINTERNADEST
                              , vrItemPedido.nALIQINTERORIGPART
                              , vrItemPedido.nCODFISCAL         -- HIS.03261.2016
                              , vrItemPedido.vSITTRIBUT         -- HIS.03261.2016
                              , vrItemPedido.vPRODIMPORTADOPEPS -- HIS.02786.2016
                              , vrItemPedido.nNUMTRANSENTPEPS   -- HIS.02786.2016
                              , vrItemPedido.vTIPOCOMISSAOMED   -->> Somente Grava na Inclusão (Log Combo)
                              --
                              , vrItemPedido.vOBSERVACAOSTFONTE  -- HIS.03376.2017
                              , vrItemPedido.vINDESCALARELEVANTE -- HIS.03376.2017
                              , vrItemPedido.vCNPJFABRICANTE     -- HIS.03376.2017
                              , vrItemPedido.vFABRICANTE         -- HIS.03376.2017
                              -- MED-1090 - Valores FCP
                              , vrItemPedido.nVLFECP
                              , vrItemPedido.nVLBASEFCPST
                              , vrItemPedido.nALIQICMSFECP
                              , vrItemPedido.nFATORGRAMATURALICIT
                              -- MED-2453
                              , vrItemPedido.nVLVERBACMVCLI
                              -- CROSSDOCKING
                              , vrItemPedido.vNUMLOTE
                              -- DDMEDICA-1172
                              , vrItemPedido.nVLDESCSUFRAMA
                              , vrItemPedido.nVLDESCPISSUFRAMA
                              , vrItemPedido.nVLDESCREDUCAOPIS
                              , vrItemPedido.nVLDESCREDUCAOCOFINS
                              --
                              , vrItemPedido.vCODIGOINTEGRACAOWMS
                              , vrItemPedido.vNUMLOTEPROMOCAOMED
                              -- DDMEDICA-5009
                              , vrItemPedido.nVLDESCCMVPROMOCAOMED
                              , vrItemPedido.nNUMVERBACAMPANHA
                              , vrItemPedido.nVLVERBACMV
                              , vrItemPedido.nPERCCUSTFORNEC
                              , vnQtFaltaDigitacao -- DDMEDICA-5126
                              , nQTUNIT --DDMEDICA-5420
                              , vrItemPedido.nCODAUXILIAR -- DDMEDICA-7318
                              , vrItemPedido.nPERCDESCPIS
                              , vrItemPedido.nPERCDESCCOFINS
                              -- DDMEDICA-7697
                              , vrItemPedido.nBCSTRETANTERIOR
                              , vrItemPedido.nVLICMSSUBSTITUTOANTERIOR
                              , vrItemPedido.nVLICMSSTRETANTERIOR
                              , vrItemPedido.nPMPFMEDICAMENTO
                              -- DDVENDAS-33442
                              , vrItemPedido.nCODEDITAL
                              , vrItemPedido.nQTPEDLICIT
                              , vrItemPedido.nTIPOCONVERSAOPEDLICIT
                              , vrItemPedido.vUNIDADECONVERSAOPEDLICIT
                              , vrItemPedido.nFATORCONVERSAOPEDLICIT
                              , vrItemPedido.vPRODDESCRICAODANFE
                              , vrItemPedido.vPRODDESCRICAOCONTRATO
                              , vrItemPedido.nNUMVERBAREBCMV
							  , vrItemPedido.nNUMITEMPED
                              , vrItemPedido.nQTCOMBOVIRTUAL
                              );

                    -- Insere Origem Preço
                    BEGIN
                      SELECT 'S'
                        INTO vvAchouOrigemPreco
                        FROM PCORIGEMPRECO
                       WHERE (NUMPED  = pi_nNumPed)
                         AND (CODPROD = vrItemPedido.nCODPROD)
                         AND (NUMSEQ  = vrItemPedido.nNUMSEQ);
                    EXCEPTION
                      WHEN NO_DATA_FOUND THEN
                        vvAchouOrigemPreco := 'N';
                    END;
                    IF (vvAchouOrigemPreco = 'N') THEN
                      INSERT INTO PCORIGEMPRECO
                                ( NUMPED
                                , CODPROD
                                , NUMSEQ )
                         VALUES ( pi_nNumPed
                                , vrItemPedido.nCODPROD
                                , vrItemPedido.nNUMSEQ );
                    END IF;

                    -- Atualiza Origem do Preço
                    UPDATE PCORIGEMPRECO
                       SET USATRIBUTPORUF         = vrPcConsum.vUSATRIBUTACAOPORUF
                         , ORIGEMPRECO            = vrItemPedido.vORIGEMPRECO
                         , COLUNAPRECO            = vrPlanoPag.nNUMPR
                         , ORIGEMPED              = pi_vOrigemPed
                         , CODFILIAL              = pi_vCodFilial
                         , CODFILIALNF            = pi_vCodFilialNF
                         , PERBONIFIC             = vrItemPedido.nPERBONIFIC
                         , VLBONIFIC              = vrItemPedido.nVLBONIFIC
                         , VLREPASSE              = vrItemPedido.nVLREPASSE
                         , VLICMSPARTILHA         = vrItemPedido.nVLICMSPART
                         , VLDESCICMS             = vrItemPedido.nVLDESCICMISENCAO
                         , PERCPLPAG              = vrPlanoPag.nPERTXFIM
                         , PERCRAMOATIV           = vrItemPedido.nPERCRAMOATIV
                         , TIPODESCFLEX           = vrItemPedido.vTIPODESCFLEX
                         , PERCDESCFLEX           = vrItemPedido.nPERCDESCFLEX
                         , NUMREGIAO              = vrRegiao.nNUMREGIAO
                         , VLREDPVENDASIMPLESNA   = vrItemPedido.nVLREDPVENDASIMPLESNA
                         , CODACORDOPARCERIA      = vrItemPedido.nCODACORDOPARCERIA
                         , PERCDESCACORDOPARCERIA = vrItemPedido.nPERCDESCACORDOPARCERIA
                         , VLICMSSTRETANTERIOR    = vrItemPedido.nVLICMSSTRETANTERIOR
                     WHERE (NUMPED  = pi_nNumPed)
                       AND (CODPROD = vrItemPedido.nCODPROD)
                       AND (NUMSEQ  = vrItemPedido.nNUMSEQ);

                    -- Atualiza a Quantidade de Produtos Inseridos
                    viQtdeProdutosInseridos := NVL(viQtdeProdutosInseridos,0) + 1;

                  END IF; -- FIM CONDIÇÃO SE JÁ EXISTE O PRODUTO + PROMOÇÃO

                END IF; -- Fim Condição insere na PCPEDI (viLacoValidar = 2)

              END IF; -- Fim Condição Somente pode inserir na TABELA PCPEDI se não for para Inserir Somente na TABELA TEMP BONIFICAÇÃO EM MERCADORIA DE PROMOÇÃO (pi_nTipoChamada <> 8)

            END IF; -- Fim Condição SE PODE CONTINUAR O PROCESSAMENTO DO PRODUTO

          END LOOP; -- Fim Laço de Processamento dos Itens

