          -- Grava Log --
          ---------------
          P_GRAVA_LOG(viLacoValidar);

          --------------------------------------------------------------------
          -- PEDIDO DE LICITAÇÃO - Insere na PCPEDC somente no segundo laço --
          --------------------------------------------------------------------
          IF    (pi_nTipoChamada         IN (3)) AND
                (viLacoValidar           = 2)    AND
                (viQtdeProdutosInseridos > 0)    THEN

            -- Define a Data do Pedido
            vrPedido.dDATA      := TRUNC(SYSDATE);
            -- Define a Condição de Venda
            vrPedido.nCONDVENDA := 1;
            -- Define Gera Contas a Pagar
            vrPedido.vGERACP    := 'N';
            -- Código do Contrato
            BEGIN
              SELECT CODCONTRATO
                INTO vrPedido.nCODCONTRATO
                FROM PCCONTRATO
               WHERE (CODEDITAL = pi_nCodEdital)
                 AND (ROWNUM    = 1);
            EXCEPTION
              WHEN NO_DATA_FOUND THEN
                vrPedido.nCODCONTRATO := NULL;
            END;

            -- Insere na PCPEDC
            INSERT INTO PCPEDC
                      ( NUMPED
                      , PERCVENDA
                      , DATA
                      , CODCLI
                      , CODUSUR
                      , CODCOB
                      , POSICAO
                      , CONDVENDA
                      , CODFILIAL
                      , CODFILIALNF
                      , CODDISTRIB
                      , OPERACAO
                      , TIPOVENDA
                      , PRAZOMEDIO
                      , TIPOCARGA
                      , FRETEDESPACHO
                      , FRETEREDESPACHO
                      , DTENTREGA
                      , CODPLPAG
                      , OBSENTREGA1
                      , OBSENTREGA2
                      , OBSENTREGA3
                      , TIPOEMBALAGEM
                      , ORIGEMPED
                      , CODPRACA
                      , NUMCAR
                      , CODSUPERVISOR
                      , CODEMITENTE
                      , HORA
                      , MINUTO
                      , OBS
                      , GERACP
                      , PRAZO1
                      , PRAZO2
                      , PRAZO3
                      , PRAZO4
                      , PRAZO5
                      , PRAZO6
                      , PRAZO7
                      , PRAZO8
                      , PRAZO9
                      , PRAZO10
                      , PRAZO11
                      , PRAZO12
                      , ROTINALANC
                      , CODCONTRATO
                      , CODEDITAL
                      , NUMEMPENHO
                      , CODFUNCCALCFRETE
                      , DTCALCFRETE
                      , DATAPEDCLI
                      , BROKER
                      , CONCILIAIMPORTACAO
                      , NUMREGIAO
                      , GERARDADOSNFPAULISTA
                      , USAINTEGRACAOWMS
                      , BRINDE
                      , CONTAORDEM
                      , FORNECENTREGA
                      , PEDIDOAVARIA
                      )
                VALUES( pi_nNumPed                            -- NUMPED
                      , 100                                   -- PERCVENDA
                      , vrPedido.dDATA                        -- DATA
                      , pi_nCodCli                            -- CODCLI  (Passado no parâmetro)
                      , pi_nCodUsur                           -- CODUSUR (Passado no parâmetro)
                      , pi_vCodCob                            -- CODCOB  (Passado no parâmetro)
                      , 'B'                                   -- POSICAO (O Pedido sempre será gerado como Bloqueado)
                      , vrPedido.nCONDVENDA                   -- CONDVENDA
                      , pi_vCodFilial                         -- CODFILIAL
                      , pi_vCodFilial                         -- CODFILIALNF
                      , vrRca.vCODDISTRIB                     -- CODDISTRIB
                      , 'N'                                   -- OPERACAO
                      , vrPlanoPag.vTIPOVENDA                 -- TIPOVENDA
                      , vrPlanoPag.nNUMDIAS                   -- PRAZOMEDIO
                      , NULL                                  -- TIPOCARGA
                      , 'C'                                   -- FRETEDESPACHO
                      , NULL                                  -- FRETEREDESPACHO
                      , vrPedido.dDATA                        -- DTENTREGA
                      , pi_nCodPlPag                          -- CODPLPAG (Passado no parâmetro)
                      , vrClienteDestino.vOBSENTREGA1         -- OBSENTREGA1
                      , vrClienteDestino.vOBSENTREGA2         -- OBSENTREGA2
                      , vrClienteDestino.vOBSENTREGA3         -- OBSENTREGA3
                      , 'U'                                   -- TIPOEMBALAGEM
                      , 'T'                                   -- ORIGEMPED (Assume como se fosse Televendas)
                      , vrClienteDestino.nCODPRACA            -- CODPRACA
                      , 0                                     -- NUMCAR
                      , vrRca.nCODSUPERVISOR                  -- CODSUPERVISOR
                      , pi_nCodMatricula                      -- CODEMITENTE
                      , TO_CHAR(SYSDATE,'HH24')               -- HORA
                      , TO_CHAR(SYSDATE,'MI')                 -- MINUTO
                      , 'Ped. Licitação 4206'                 -- OBS
                      , vrPedido.vGERACP                      -- GERACP
                      , vrPedido.nPRAZO1                      -- PRAZO1
                      , vrPedido.nPRAZO2                      -- PPRAZO2
                      , vrPedido.nPRAZO3                      -- PPRAZO3
                      , vrPedido.nPRAZO4                      -- PPRAZO4
                      , vrPedido.nPRAZO5                      -- PPRAZO5
                      , vrPedido.nPRAZO6                      -- PPRAZO6
                      , vrPedido.nPRAZO7                      -- PPRAZO7
                      , vrPedido.nPRAZO8                      -- PPRAZO8
                      , vrPedido.nPRAZO9                      -- PPRAZO9
                      , vrPedido.nPRAZO10                     -- PPRAZO10
                      , vrPedido.nPRAZO11                     -- PPRAZO11
                      , vrPedido.nPRAZO12                     -- PPRAZO12
                      , 'PCSIS4206.EXE'                       -- ROTINALANC
                      , vrPedido.nCODCONTRATO                 -- CODCONTRATO
                      , pi_nCodEdital                         -- CODEDITAL  (Passado no parâmetro)
                      , pi_vNumEmpenho                        -- NUMEMPENHO (Passado no parâmetro)
                      , NULL                                  -- CODFUNCCALCFRETE
                      , NULL                                  -- DTCALCFRETE
                      , NULL                                  -- DATAPEDCLI
                      , 'N'                                   -- BROKER
                      , 'N'                                   -- CONCILIAIMPORTACAO
                      , vrRegiao.nNUMREGIAO                   -- NUMREGIAO
                      , 'N'                                   -- GERARDADOSNFPAULISTA
                      , 'N'                                   -- USAINTEGRACAOWMS
                      , 'N'                                   -- BRINDE
                      , 'N'                                   -- CONTAORDEM
                      , 'N'                                   -- FORNECENTREGA
                      , 'N'                                   -- PEDIDOAVARIA
                      );

            -- Atualiza Controle de Pedido Inserido
            vbInseriuPedido := TRUE;

            -------------------------------
            -- ATUALIZA TOTAIS DO PEDIDO --
            -------------------------------

            -- Calcula e Atualiza Totais do Pedido
            PTOTAIS_PEDIDO(pi_nNumPed);

            -- EFETIVA TRANSACÕES QUANDO PEDIDO DE LICITAÇÃO
            COMMIT;

          -------------------------------------------------------------------------------------
          -- BONIFICAÇÃO EM MERCADORIA DE PROMOÇÃO - Atualiza PCPEDC somente no segundo laço --
          -------------------------------------------------------------------------------------
          ELSIF (pi_nTipoChamada         = 6) AND
                (viLacoValidar           = 2) AND
                (viQtdeProdutosInseridos > 0) THEN

            -------------------------------
            -- ATUALIZA TOTAIS DO PEDIDO --
            -------------------------------

            -- Calcula e Atualiza Totais do Pedido
            PTOTAIS_PEDIDO(pi_nNumPed);

            -- *** NÃO PODE REALIZAR COMMIT neste tipo de chamada *** --

          END IF; -- Fim Condição PEDIDO DE LICITAÇÃO - insere na PCPEDC ou BONIFICAÇÃO DE PROMOÇÃO EM TV1 - Atualiza PCPEDC

          --------------------------------------------------------------------------------------------------------------
          -- BONIFICAÇÃO EM MERCADORIA DE PROMOÇÃO NA TABELA TEMP ou BONIFICAÇÃO DE PROMOÇÃO EM TV1 - Atualiza PCPEDC
          -- Insere na Temporária somente no segundo laço --
          --------------------------------------------------------------------------------------------------------------
          IF (pi_nTipoChamada         IN (6,8)) AND
             (viLacoValidar           = 2)      AND
             (viQtdeProdutosInseridos > 0)      THEN

            -- Calcula Totais da Bonificação em Mercadoria
            SELECT SUM(PCMED_TEMP_PROMO_BONIFICMERC.QUANTIDADE)
                 , SUM(PCMED_TEMP_PROMO_BONIFICMERC.VALORTOTAL)
              INTO vrTotaisBonifMerc.nQUANTIDADE
                 , vrTotaisBonifMerc.nVALORTOTAL
              FROM PCMED_TEMP_PROMO_BONIFICMERC;

            -- Insere Totais da Bonificação em Mercadoria
            INSERT INTO PCMED_TEMP_PROMO_BONIFICMERC
                      ( TIPOREG
                      , CODPROD
                      , DESCRICAO
                      , QUANTIDADE
                      , VALORTOTAL )
               VALUES ( 'T'
                      , NULL
                      , 'TOTAIS EM BONIFICAÇÃO DE MERCADORIA'
                      , NVL(vrTotaisBonifMerc.nQUANTIDADE,0)
                      , NVL(vrTotaisBonifMerc.nVALORTOTAL,0) );

            -- *** NÃO PODE REALIZAR COMMIT neste tipo de chamada *** --

          END IF; -- Fim Condição BONIFICAÇÃO EM MERCADORIA DE PROMOÇÃO NA TABELA TEMP ou BONIFICAÇÃO DE PROMOÇÃO EM TV1 - Atualiza PCPEDC

        END LOOP; -- Fim Laço para fazer uma Pré-Validação de todos os Itens

      END IF; -- Fim Condição Se tem Itens para Incluir no Pedido

      ---------------------------
      -- Critica de Pedido Gerado
      ---------------------------
      IF (pi_nTipoChamada IN (3)) THEN
        IF (NOT vbInseriuPedido) THEN
          po_vPodeGravarPedido    := 'N';
          po_vMotivoNaoPodeGravar := 'Não foram encontrados dados para Geração do Pedido';
        END IF;
      END IF;

   /******************************************************************************
    SE CHAMADO PARA EXCLUIR BONIFICAÇÃO EM MERCADORIA DE PROMOÇÃO
    *************************************************************/
    ELSIF (pi_nTipoChamada IN (7)) THEN

      -- Excluir Registros do Pedido de Promoções de Bonificação
      PEXCLUI_ITENSBONIFIC(pi_nNumPed);

      -- Calcula e Atualiza Totais do Pedido
      PTOTAIS_PEDIDO(pi_nNumPed);

      -- *** NÃO PODE REALIZAR COMMIT neste tipo de chamada *** --

    END IF; -- FIM CONDIÇÃO TIPO CHAMADA

   /*****************************************
    SE CHAMADO PARA ATUALIZAR PREÇO DE BRINDE
    *****************************************/
    IF (pi_nTipoChamada = (12)) THEN
      -- Manda informação para auditoria
      po_vMotivoNaoPodeGravar := 'Brindes: ' || NVL(viQtItensBrinde,0) || ' ; Não Brindes: ' || NVL(viQtItensNaoBrinde,0);
    END IF;

   /************************************************
    SE CHAMADO DA CARGA DOS BRINDES - HIS.01889.2017
    ************************************************/
    IF (pi_nTipoChamada = 13) THEN

      -- Deleta produtos com problemas cadastrais - BRINDES
      DELETE FROM PCMED_PROMOCAO_CAMPANHA_BRI
            WHERE (BLOQUEIOCAMPANHA = 'S');

      -- Deleta produtos com problemas cadastrais - MIX
      DELETE FROM PCMED_PROMOCAO_CAMPANHA_MIX
            WHERE (BLOQUEIOCAMPANHA = 'S');

      -- Aplicar Múltiplos Brindes para Promoções de Brindes Fixos - DDMEDICA-3103
      P_APLICA_MULTIPLOS_BRINDES;

      -- Atualiza de volta as quantidades de Brindes informadas pelo usuário
      FOR vc_BrindeInf IN (SELECT PCMED_PROMOCAO_CAMPANHA_INF.CODPROMOCAOMEDREF
                                , PCMED_PROMOCAO_CAMPANHA_INF.CODPROD
                                , PCMED_PROMOCAO_CAMPANHA_INF.QTDEBRINDES
                             FROM PCMED_PROMOCAO_CAMPANHA_INF) LOOP
        UPDATE PCMED_PROMOCAO_CAMPANHA_BRI
           SET QTDEBRINDES = vc_BrindeInf.QTDEBRINDES
         WHERE (CODPROMOCAOMEDREF = vc_BrindeInf.CODPROMOCAOMEDREF)
           AND (CODPROD           = vc_BrindeInf.CODPROD);
      END LOOP;

      -- Atualiza de volta as seleções realizadas s pelo usuário
      FOR vc_BrindeSel IN (SELECT PCMED_PROMOCAO_CAMPANHA_SEL.CODPROMOCAOMED
                                , PCMED_PROMOCAO_CAMPANHA_SEL.SEL
                             FROM PCMED_PROMOCAO_CAMPANHA_SEL) LOOP
        UPDATE PCMED_PROMOCAO_CAMPANHA
           SET SEL = vc_BrindeSel.SEL
         WHERE (CODPROMOCAOMED = vc_BrindeSel.CODPROMOCAOMED);
      END LOOP;

      -- Verifica se existe Estoque para a Qtde Informada pelo Usuário
      FOR vc_Brinde IN (SELECT PCMED_PROMOCAO_CAMPANHA_BRI.CODPROD
                             , SUM(PCMED_PROMOCAO_CAMPANHA_BRI.QTDEBRINDES) QTDEBRINDES
                             FROM PCMED_PROMOCAO_CAMPANHA_BRI
                             GROUP BY PCMED_PROMOCAO_CAMPANHA_BRI.CODPROD) LOOP

        -- Pesquisa a Filial Retira Padrão do Brinde - DDMEDICA-7318
        vvCodFilialRetiraBrinde := F_OBTEM_FILIAL_RETIRA_BRINDE(vrParamFilial.vUSAESTOQUEDEPFECHADO,
                                                                vc_Brinde.CODPROD,
                                                                pi_vCodFilial,
                                                                vvCodFilialRetira);

        -- Pesquisa o Saldo Estoque observando primeiro a Filial Retira - DDMEDICA-7318
        BEGIN
          SELECT GREATEST(NVL(PCEST.QTESTGER,0) - NVL(PCEST.QTRESERV,0) - NVL(PCEST.QTBLOQUEADA,0),0)
            INTO vnSaldoEstoque
            FROM PCEST
           WHERE (PCEST.CODFILIAL = NVL(vvCodFilialRetiraBrinde,pi_vCodFilial)) -- DDMEDICA-7318
             AND (PCEST.CODPROD   = vc_Brinde.CODPROD);
        EXCEPTION
          WHEN NO_DATA_FOUND THEN
            vnSaldoEstoque := 0;
        END;

        -- Se não existe Estoque para os Brindes com Qtde. escolhida
        IF (NVL(vnSaldoEstoque,0) < NVL(vc_Brinde.QTDEBRINDES,0)) THEN
          UPDATE PCMED_PROMOCAO_CAMPANHA_BRI
             SET ALERTA           = 'S'
               , OBSERVACAOALERTA = 'Qt. Brindes escolhidos: ' || NVL(vc_Brinde.QTDEBRINDES,0) || ' superior ao Estoque Disponível: ' || NVL(vnSaldoEstoque,0)
           WHERE (CODPROD = vc_Brinde.CODPROD)
             AND (QTDEBRINDES > 0);
        END IF;

      END LOOP;
      
      -- Totaliza por Promoção o Valor de todos os Produtos os Brindes Concedidos para validação da Cota de Brindes - DDVENDAS-38166
      FOR vc_Brinde IN (SELECT PCMED_PROMOCAO_CAMPANHA_BRI.CODPROMOCAOMEDREF
                             , SUM(PCMED_PROMOCAO_CAMPANHA_BRI.QTDEBRINDES * PCMED_PROMOCAO_CAMPANHA_BRI.PRECOLIQUIDO) VALORBRINDES
                          FROM PCMED_PROMOCAO_CAMPANHA_BRI
                         GROUP BY PCMED_PROMOCAO_CAMPANHA_BRI.CODPROMOCAOMEDREF) LOOP
                         
        -- Se tem brindes concedidos
        IF (NVL(vc_Brinde.VALORBRINDES,0) > 0) THEN
        
          PKG_FUNCOESVENDAS_MED.P_VALIDAR_COTAS_PROMOCAO(pi_nNumPed,
                                                         0, -- pi_nCodProd
                                                         0, -- pi_nNumSeq
                                                         vc_Brinde.CODPROMOCAOMEDREF,
                                                         pi_nCodCli,
                                                         0, -- pi_nPTabela
                                                         NVL(vc_Brinde.VALORBRINDES,0),
                                                         1, -- Na quantidade vendida passa 1 porque o valor dos brindes já está multiplicado pela quantidade
                                                         vvRejeitarVendaCota,
                                                         vvMsgVendaRejeitadaCota,
                                                         vnCotaUtilizadaGeral,
                                                         vnCotaUtilizadaCliente);    
        
          -- Se excedeu a Cota
          IF (vvRejeitarVendaCota = 'S') THEN
            -- Crítica de Cota de Brindes
            UPDATE PCMED_PROMOCAO_CAMPANHA_BRI
               SET ALERTA           = 'R' -- Restrição
                 , OBSERVACAOALERTA = SUBSTR(vvMsgVendaRejeitadaCota,1,250)
             WHERE (CODPROMOCAOMEDREF = vc_Brinde.CODPROMOCAOMEDREF)
               AND (QTDEBRINDES > 0);
          END IF;
                
        END IF;
                         
      END LOOP;
      
      -----------------------------------------------------------------------------------------------------
      -- Laço de Verificação se tem Mix Pontuando em mais de uma Campanha ou Qtde. Vendida Abaixo do Mínimo
      -----------------------------------------------------------------------------------------------------
      FOR vc_Mix IN (SELECT CODPROMOCAOMEDREF
                          , CODPROD
                          , QTDEVENDIDA
                          , QTDEMINIMA
                       FROM PCMED_PROMOCAO_CAMPANHA_MIX
                      WHERE (PCMED_PROMOCAO_CAMPANHA_MIX.TIPOPROMOCAO = 'N')
                        AND (PCMED_PROMOCAO_CAMPANHA_MIX.QTDEVENDIDA > 0)) LOOP

        -- Verifica se a Campanha do Laço está selecionada
        BEGIN
          SELECT SEL
            INTO vvCampanhaSelecionada
            FROM PCMED_PROMOCAO_CAMPANHA
           WHERE (CODPROMOCAOMED = vc_Mix.CODPROMOCAOMEDREF);
        EXCEPTION
          WHEN NO_DATA_FOUND THEN
            vvCampanhaSelecionada := 'N';
        END;

        -- Procura Ocorrência do Produto com Venda noutras Campanhas selecionadas
        SELECT COUNT(*)
          INTO viQtdeOcorrenciasCampanha
          FROM PCMED_PROMOCAO_CAMPANHA_MIX
         WHERE (PCMED_PROMOCAO_CAMPANHA_MIX.CODPROD            = vc_Mix.CODPROD)
           AND (PCMED_PROMOCAO_CAMPANHA_MIX.CODPROMOCAOMEDREF <> vc_Mix.CODPROMOCAOMEDREF)
           AND (PCMED_PROMOCAO_CAMPANHA_MIX.QTDEVENDIDA > 0)
           AND (PCMED_PROMOCAO_CAMPANHA_MIX.CODPROMOCAOMEDREF IN (SELECT PCMED_PROMOCAO_CAMPANHA.CODPROMOCAOMED
                                                                    FROM PCMED_PROMOCAO_CAMPANHA
                                                                   WHERE (PCMED_PROMOCAO_CAMPANHA.SEL = 'S')));

        -- Se Multiplas Ocorrências e a Campanha está Selecionada
        IF (viQtdeOcorrenciasCampanha > 0)        AND
           (NVL(vvCampanhaSelecionada,'N') = 'S') THEN

          UPDATE PCMED_PROMOCAO_CAMPANHA_MIX
             SET ALERTA           = 'S'
               , OBSERVACAOALERTA = 'Mix em mais de uma Campanha'
           WHERE (CODPROD                           = vc_Mix.CODPROD)
             AND (CODPROMOCAOMEDREF                 = vc_Mix.CODPROMOCAOMEDREF)
             AND (NVL(BLOQUEIODESCPROMCAMPANHA,'N') = 'N');

        -- Se NÃO TEM Multiplas Ocorrências
        ELSE

          -- Retira o Alerta
          UPDATE PCMED_PROMOCAO_CAMPANHA_MIX
             SET ALERTA           = NULL
               , OBSERVACAOALERTA = NULL
           WHERE (CODPROD                           = vc_Mix.CODPROD)
             AND (CODPROMOCAOMEDREF                 = vc_Mix.CODPROMOCAOMEDREF)
             AND (NVL(BLOQUEIODESCPROMCAMPANHA,'N') = 'N');

          -- Se Quantidade Vendida abaixo do Mínimo
          IF (NVL(vc_Mix.QTDEVENDIDA,0) < NVL(vc_Mix.QTDEMINIMA,0)) THEN

            UPDATE PCMED_PROMOCAO_CAMPANHA_MIX
               SET ALERTA           = 'Q'
                 , OBSERVACAOALERTA = 'Qt. Venda aAbaixo do Mínimo'
             WHERE (CODPROD           = vc_Mix.CODPROD)
               AND (CODPROMOCAOMEDREF = vc_Mix.CODPROMOCAOMEDREF)
               AND (NVL(BLOQUEIODESCPROMCAMPANHA,'N') = 'N');

          END IF;

        END IF;

      END LOOP; -- Fim do Laço de Verificação se tem Mix Pontuando em mais de uma Campanha ou Qtde. Vendida Abaixo do Mínimo

      -- *** NÃO PODE REALIZAR COMMIT neste tipo de chamada *** --

   /*************************************************************
    SE CHAMADO DA CARGA DA PROMOÇÃO DE MIX/VALOR - HIS.01889.2017
    *************************************************************/
    ELSIF (pi_nTipoChamada = 14) THEN

      -- Deleta produtos com problemas cadastrais - MIX
      DELETE FROM PCMED_PROMOCAO_CAMPANHA_MIX
            WHERE (BLOQUEIOCAMPANHA = 'S');

      -- Laço de Verificação de Qtde. Vendida Abaixo do Mínimo
      FOR vc_Mix IN (SELECT CODPROMOCAOMEDREF
                          , CODPROD
                          , QTDEVENDIDA
                          , QTDEMINIMA
                       FROM PCMED_PROMOCAO_CAMPANHA_MIX
                      WHERE (PCMED_PROMOCAO_CAMPANHA_MIX.TIPOPROMOCAO IN ('M','V','F')) -- MED_VLMIN_FXQ - Adicionado o Tipo 'F'
                        AND (PCMED_PROMOCAO_CAMPANHA_MIX.QTDEVENDIDA > 0)) LOOP

        -- Se Quantidade Vendida abaixo do Mínimo
        IF (NVL(vc_Mix.QTDEVENDIDA,0) < NVL(vc_Mix.QTDEMINIMA,0)) THEN

          UPDATE PCMED_PROMOCAO_CAMPANHA_MIX
             SET ALERTA           = 'Q'
               , OBSERVACAOALERTA = 'Qt. Venda abaixo do Mínimo'
           WHERE (CODPROD           = vc_Mix.CODPROD)
             AND (CODPROMOCAOMEDREF = vc_Mix.CODPROMOCAOMEDREF);

        END IF;

      END LOOP; -- Fim do Laço de Verificação se tem Mix Pontuando em mais de uma Campanha ou Qtde. Vendida Abaixo do Mínimo

      -- *** NÃO PODE REALIZAR COMMIT neste tipo de chamada *** --

    END IF;

  EXCEPTION
    WHEN e_Break THEN
      po_vPodeGravarPedido := 'S';
    WHEN e_Tratado THEN
      po_vPodeGravarPedido := 'N';
      IF (pi_nTipoChamada IN (3,11,17,18)) THEN
        IF (pi_nTipoChamada IN (3)) THEN
          ROLLBACK;
        END IF;
        IF vRefCursor%ISOPEN THEN
         CLOSE vRefCursor;
        END IF;
      END IF;
    WHEN OTHERS THEN
      po_vPodeGravarPedido    := 'N';
      po_vMotivoNaoPodeGravar := 'Erro ao validar a promoção: ' || SUBSTR('Erro: ' || DBMS_UTILITY.FORMAT_ERROR_BACKTRACE || ' >> ' || SQLERRM,1,240);
      IF (pi_nTipoChamada IN (3,11,17,18)) THEN
        IF (pi_nTipoChamada IN (3)) THEN
          ROLLBACK;
        END IF;
        IF vRefCursor%ISOPEN THEN
         CLOSE vRefCursor;
        END IF;
      END IF;
  END P_VALIDA_PROMOCAO;

 /*******************************************************************************
  Nome         : F_DEFINE_ACAO_EDICAO
  Descricão    : Função para definir a ação de Edição do Desconto
  *******************************************************************************/
  FUNCTION F_DEFINE_ACAO_EDICAO(pi_vPermiteEditarProduto IN VARCHAR2,
                                pi_vTipoEntidade         IN VARCHAR2,
                                pi_nCodEntidade          IN NUMBER,
                                pi_nInicioIntervalo      IN NUMBER,
                                pi_vTipoPromocao         IN VARCHAR2,
                                pi_vNumLote              IN VARCHAR2 DEFAULT 'X') 
  RETURN VARCHAR2 IS
    vvRetAcaoEdita           VARCHAR2(1);
    vvAchouRegistroOLD       VARCHAR2(1);                                 
    vvAchouRegistroNEW       VARCHAR2(1);   
    viQtdeControleDiferencas INTEGER;                              
  BEGIN
  
    -- Default - Inclui Desconto
    vvRetAcaoEdita := 'I';

    -- SE USA REGRA DE EDIÇÃO DE PROMOÇÃO
    IF (NVL(pi_vPermiteEditarProduto,'N') = 'S') THEN
    
      -- Promoção onde o Lote é a Chave -------------
      -----------------------------------------------
      IF (pi_vTipoPromocao = 'L') THEN
      
        -- Verifica se o registro existia na Promoção
        BEGIN
          SELECT 'S'
            INTO vvAchouRegistroOLD
            FROM PCMED_PROMOCAOPOLITICAS
           WHERE (TIPOREG         = 'O'||pi_vTipoEntidade)
             AND (CODIGO          = pi_nCodEntidade)
             AND (NUMLOTE         = pi_vNumLote)
             AND (ROWNUM          = 1);
        EXCEPTION
          WHEN NO_DATA_FOUND THEN
            vvAchouRegistroOLD := 'N';
        END;
        -- Verifica o registro existe na Promoção
        BEGIN
          SELECT 'S'
            INTO vvAchouRegistroNEW
            FROM PCMED_PROMOCAOPOLITICAS
           WHERE (TIPOREG         = 'N'||pi_vTipoEntidade)
             AND (CODIGO          = pi_nCodEntidade)
             AND (NUMLOTE         = pi_vNumLote)
             AND (ROWNUM          = 1);
        EXCEPTION
          WHEN NO_DATA_FOUND THEN
            vvAchouRegistroNEW := 'N';
        END;
  
        -- Se Inclusão (Se Exclusão de Registro, não existem dados para chegar aqui, o Registro é deletado no inicio da procedure)
        IF    ((vvAchouRegistroOLD = 'N') AND
               (vvAchouRegistroNEW = 'S')) THEN
          vvRetAcaoEdita := 'I';
        -- Se Alteração
        ELSE
          vvRetAcaoEdita := 'A';
        END IF;
  
        -- Se alteração
        IF (vvRetAcaoEdita = 'A') THEN
  
          -- Verifica se ocorreram mudanças
          SELECT COUNT(*)
            INTO viQtdeControleDiferencas
            FROM
          (
          SELECT *
            FROM PCMED_PROMOCAOPOLITICAS
           WHERE (TIPOREG         = 'O'||pi_vTipoEntidade)
             AND (CODIGO          = pi_nCodEntidade)
             AND (NUMLOTE         = pi_vNumLote)
          UNION -->> Sem o UNION ALL, se todos os campos estiverem iguais, somente gera uma linha
          SELECT *
            FROM PCMED_PROMOCAOPOLITICAS
           WHERE (TIPOREG         = 'N'||pi_vTipoEntidade)
             AND (CODIGO          = pi_nCodEntidade)
             AND (NUMLOTE         = pi_vNumLote)
          );
  
          -- Se os Campos do Registro não sofreram mudanças
          IF (viQtdeControleDiferencas = 1) THEN
            vvRetAcaoEdita := 'N'; -- Não altera a PCDESCONTO
          END IF;
  
        END IF; -- Fim Condição Se alteração
      
      -- Promoção onde o Inicio Intervalo não é chave
      -----------------------------------------------
      ELSIF (pi_vTipoPromocao IN ('M','V','K','N')) THEN
      
        -- Verifica se o registro existia na Promoção
        BEGIN
          SELECT 'S'
            INTO vvAchouRegistroOLD
            FROM PCMED_PROMOCAOPOLITICAS
           WHERE (TIPOREG         = 'O'||pi_vTipoEntidade)
             AND (CODIGO          = pi_nCodEntidade)
             AND (ROWNUM          = 1);
        EXCEPTION
          WHEN NO_DATA_FOUND THEN
            vvAchouRegistroOLD := 'N';
        END;
        -- Verifica o registro existe na Promoção
        BEGIN
          SELECT 'S'
            INTO vvAchouRegistroNEW
            FROM PCMED_PROMOCAOPOLITICAS
           WHERE (TIPOREG         = 'N'||pi_vTipoEntidade)
             AND (CODIGO          = pi_nCodEntidade)
             AND (ROWNUM          = 1);
        EXCEPTION
          WHEN NO_DATA_FOUND THEN
            vvAchouRegistroNEW := 'N';
        END;
  
        -- Se Inclusão (Se Exclusão de Registro, não existem dados para chegar aqui, o Registro é deletado no inicio da procedure)
        IF    ((vvAchouRegistroOLD = 'N') AND
               (vvAchouRegistroNEW = 'S')) THEN
          vvRetAcaoEdita := 'I';
        -- Se Alteração
        ELSE
          vvRetAcaoEdita := 'A';
        END IF;
  
        -- Se alteração
        IF (vvRetAcaoEdita = 'A') THEN
  
          -- Verifica se ocorreram mudanças
          SELECT COUNT(*)
            INTO viQtdeControleDiferencas
            FROM
          (
          SELECT *
            FROM PCMED_PROMOCAOPOLITICAS
           WHERE (TIPOREG         = 'O'||pi_vTipoEntidade)
             AND (CODIGO          = pi_nCodEntidade)
          UNION -->> Sem o UNION ALL, se todos os campos estiverem iguais, somente gera uma linha
          SELECT *
            FROM PCMED_PROMOCAOPOLITICAS
           WHERE (TIPOREG         = 'N'||pi_vTipoEntidade)
             AND (CODIGO          = pi_nCodEntidade)
          );
  
          -- Se os Campos do Registro não sofreram mudanças
          IF (viQtdeControleDiferencas = 1) THEN
            vvRetAcaoEdita := 'N'; -- Não altera a PCDESCONTO
          END IF;
  
        END IF; -- Fim Condição Se alteração      
      
      -- Demais Promoções ---------------------------
      -----------------------------------------------
      ELSE

        -- Verifica se o Registro existia na Promoção
        BEGIN
          SELECT 'S'
            INTO vvAchouRegistroOLD
            FROM PCMED_PROMOCAOPOLITICAS
           WHERE (TIPOREG         = 'O'||pi_vTipoEntidade)
             AND (CODIGO          = pi_nCodEntidade)
             AND (INICIOINTERVALO = NVL(pi_nInicioIntervalo,0))
             AND (ROWNUM          = 1);
        EXCEPTION
          WHEN NO_DATA_FOUND THEN
            vvAchouRegistroOLD := 'N';
        END;
        -- Verifica se o Registro existe na Promoção
        BEGIN
          SELECT 'S'
            INTO vvAchouRegistroNEW
            FROM PCMED_PROMOCAOPOLITICAS
           WHERE (TIPOREG         = 'N'||pi_vTipoEntidade)
             AND (CODIGO          = pi_nCodEntidade)
             AND (INICIOINTERVALO = NVL(pi_nInicioIntervalo,0))
             AND (ROWNUM          = 1);
        EXCEPTION
          WHEN NO_DATA_FOUND THEN
            vvAchouRegistroNEW := 'N';
        END;
  
        -- Se Inclusão (Se Exclusão de Registro, não existem dados para chegar aqui, o Registro é deletado no inicio da procedure)
        IF    ((vvAchouRegistroOLD = 'N') AND
               (vvAchouRegistroNEW = 'S')) THEN
          vvRetAcaoEdita := 'I';
        -- Se Alteração
        ELSE
          vvRetAcaoEdita := 'A';
        END IF;
  
        -- Se alteração
        IF (vvRetAcaoEdita = 'A') THEN
  
          -- Verifica se ocorreram mudanças
          SELECT COUNT(*)
            INTO viQtdeControleDiferencas
            FROM
          (
          SELECT *
            FROM PCMED_PROMOCAOPOLITICAS
           WHERE (TIPOREG         = 'O'||pi_vTipoEntidade)
             AND (CODIGO          = pi_nCodEntidade)
             AND (INICIOINTERVALO = NVL(pi_nInicioIntervalo,0))
          UNION -->> Sem o UNION ALL, se todos os campos estiverem iguais, somente gera uma linha
          SELECT *
            FROM PCMED_PROMOCAOPOLITICAS
           WHERE (TIPOREG         = 'N'||pi_vTipoEntidade)
             AND (CODIGO          = pi_nCodEntidade)
             AND (INICIOINTERVALO = NVL(pi_nInicioIntervalo,0))
          );
  
          -- Se os Campos do Registro não sofreram mudanças
          IF (viQtdeControleDiferencas = 1) THEN
            vvRetAcaoEdita := 'N'; -- Não altera a PCDESCONTO
          END IF;
  
        END IF; -- Fim Condição Se alteração
        
      END IF; -- Fim Condição: Se Promoção por Lote
      
    END IF; -- FIM CONDIÇÃO: SE USA REGRA DE EDIÇÃO DE PROMOÇÃO
    
    RETURN vvRetAcaoEdita;
 
  END F_DEFINE_ACAO_EDICAO;
  
 /*******************************************************************************
  Nome         : P_INSERE_PROMOCAOPOLITICAS
  Descricão    : Procedimento para inserir na PCMED_PROMOCAOPOLITICAS
  *******************************************************************************/
  PROCEDURE P_INSERE_PROMOCAOPOLITICAS(pi_nCodPromocaoMed IN NUMBER, 
                                       pi_vTabela         IN VARCHAR2,
                                       pi_vColuna         IN VARCHAR2,
                                       pi_vTipoReg        IN VARCHAR2,
                                       pi_vTipoPromocao   IN VARCHAR2,
                                       pi_vTipoPolitica   IN VARCHAR2) IS
    vvSqlInsertCols   VARCHAR2(4000);                                     
    vvSqlInsertValues VARCHAR2(4000);                                     
    vvSqlInsert       VARCHAR2(4000);  
    vvTabelaSelect    VARCHAR2(100);
    vvColunaSelect    VARCHAR2(100); 
    viInseridos       INTEGER;                               
  BEGIN
  
    IF (pi_vTipoPromocao <> 'N') AND
       ((pi_vTipoPromocao = 'L') OR
        (pi_vTipoPolitica IN ('F','Q','B','V'))) THEN
      vvTabelaSelect := pi_vTabela || '_FAIXA';
      vvColunaSelect := pi_vColuna || 'REF';
    ELSE
      vvTabelaSelect := pi_vTabela;
      vvColunaSelect := pi_vColuna;
    END IF;
  
    vvSqlInsertCols := 
      ' INSERT INTO PCMED_PROMOCAOPOLITICAS
                  ( TIPOREG
                  , CODIGO
                  , PERCDESC
                  , PERCDESCFIN
                  , PERCOMMINT
                  , PERCOMREP
                  , PERCOMEXT
                  , PARTICIPACOMISSGARANTIDA
                  , PERCDESCBASERCA
                  , DTINICIO
                  , DTFIM
                  , BASECREDDEBRCA
                  , CREDITASOBREPOLITICA
                  , CONSIDERACALCGIROMEDIC
                  , PRECOFIXO
                  , VLDESCCMVPROMOCAOMED
                  , INICIOINTERVALO
                  , FIMINTERVALO
                  , NUMLOTE
                  , VALORCOTA
                  , OBRIGATORIO
                  , QTKIT
                  , QTOBRIGATORIO
                  , PERMITIRAUMENTARQTDEKIT
                  , REGRAALTERARDESCONTO
                  ) ';

    vvSqlInsertValues := 
      ' SELECT '   || FQUOTEDSTR(pi_vTipoReg) || ' TIPOREG
             , D.' || vvColunaSelect          || '
             , NVL(D.PERCDESC,0)
             , NVL(D.PERCDESCFIN,0)
             , NVL(D.PERCOMMINT,0)
             , NVL(D.PERCOMREP,0)
             , NVL(D.PERCOMEXT,0)
             , NVL(D.PARTICIPACOMISSGARANTIDA,''N'')
             , NVL(D.PERCDESCBASERCA,0)
             , C.DATAINICIAL
             , C.DATAFINAL
             , NVL(C.BASECREDDEBRCA,''N'')
             , NVL(C.CREDITASOBREPOLITICA,''S'')
             , NVL(C.CONSIDERACALCGIROMEDIC,''N'') ';
    IF (vvTabelaSelect IN ('PCMED_PROMOCAOPRODUTO',
                           'PCMED_PROMOCAOPRODUTO_FAIXA')) THEN
      vvSqlInsertValues := vvSqlInsertValues ||
        ' , NVL(D.PRECOFIXO,0) ';
    ELSE
      vvSqlInsertValues := vvSqlInsertValues ||
        ' , 0 PRECOFIXO ';
    END IF;             
    IF (vvTabelaSelect IN ('PCMED_PROMOCAOPRODUTO',
                           'PCMED_PROMOCAOPRODUTO_FAIXA',
                           'PCMED_PROMOCAORESTGRUPRO',
                           'PCMED_PROMOCAORESTGRUPRO_FAIXA')) THEN
      vvSqlInsertValues := vvSqlInsertValues ||
        ' , NVL(D.VLDESCCMVPROMOCAOMED,0) ';
    ELSE
      vvSqlInsertValues := vvSqlInsertValues ||
        ' , 0 VLDESCCMVPROMOCAOMED ';
    END IF;             
    IF (pi_vTipoPromocao <> 'N') AND
       (pi_vTipoPolitica IN ('F','Q','B','V')) THEN
      vvSqlInsertValues := vvSqlInsertValues ||
        ' , NVL(D.INICIOINTERVALO,0)
          , NVL(D.FIMINTERVALO,0) ';
    ELSE
      vvSqlInsertValues := vvSqlInsertValues ||
        ' , 0 INICIOINTERVALO
          , 0 FIMINTERVALO ';
    END IF;
    IF ((pi_vTipoPromocao = 'L') AND 
        (vvTabelaSelect = 'PCMED_PROMOCAOPRODUTO_FAIXA')) THEN
      vvSqlInsertValues := vvSqlInsertValues ||
        ' , NVL(D.NUMLOTE,''X'')
          , NVL(D.VALORCOTA,0) ';
    ELSE
      vvSqlInsertValues := vvSqlInsertValues ||
        ' , ''X'' NUMLOTE
          , 0 VALORCOTA  ';
    END IF;
    IF (vvTabelaSelect = 'PCMED_PROMOCAOPRODUTO') THEN
      vvSqlInsertValues := vvSqlInsertValues ||
        ' , NVL(D.OBRIGATORIO,''N'')
          , NVL(D.QTKIT,0)
          , NVL(D.QTOBRIGATORIO,0)
          , NVL(D.PERMITIRAUMENTARQTDEKIT,''N'') ';
    ELSE
      vvSqlInsertValues := vvSqlInsertValues ||
        ' , ''N'' OBRIGATORIO
          , 0 QTKIT
          , 0 QTOBRIGATORIO
          , ''N'' PERMITIRAUMENTARQTDEKIT ';
    END IF;
    vvSqlInsertValues := vvSqlInsertValues ||
      '       , NVL(REGRAALTERARDESCONTO,''P'')
           FROM ' || vvTabelaSelect || ' D
              , PCMED_PROMOCAO C
          WHERE (C.CODPROMOCAOMED = ' || NVL(pi_nCodPromocaoMed,0) || ') ';
          
    vvSqlInsert := vvSqlInsertCols || ' ' || vvSqlInsertValues;
    
    EXECUTE IMMEDIATE vvSqlInsert;
    
    viInseridos := SQL%ROWCOUNT;
    viInseridos := viInseridos;
  
  EXCEPTION
    WHEN OTHERS THEN
      ROLLBACK;
      --INSERT INTO PCSCRIPTDEBUGMED(DTSCRIPT,ORIGEM,SCRIPT) VALUES (SYSDATE,'PKG_PROMOCAO_MED.P_INSERE_PROMOCAOPOLITICAS',vvSqlInsert); COMMIT;      
      RAISE_APPLICATION_ERROR(-20001, 'Instrução SQL com problemas: ' || SQLERRM);       
  END P_INSERE_PROMOCAOPOLITICAS;                

 /***********************************************************************************
  Nome         : P_REMOVE_PROMOCAOPOLITICAS
  Descricão    : Procedimento para remover Políticas conforme PCMED_PROMOCAOPOLITICAS
  ***********************************************************************************/
  PROCEDURE P_REMOVE_PROMOCAOPOLITICAS(pi_nCodPromocaoMed IN NUMBER, 
                                       pi_vColuna         IN VARCHAR2,
                                       pi_vTipoEntidade   IN VARCHAR2,
                                       pi_vTipoPromocao   IN VARCHAR2) IS
    vvSqlDelete VARCHAR2(4000);                                     
  BEGIN
  
    -- Exclui somente os registros que não estão mais na Promoção --
    ----------------------------------------------------------------
    
    -- Promoções de Valor usam o Inicio do Intervalo para Quantidade Mínima
    IF    (pi_vTipoPromocao IN ('M','V','K','N')) THEN
      FOR vc_RegistrosExcluidos IN (SELECT TAB_OLD.CODIGO
                                      FROM PCMED_PROMOCAOPOLITICAS TAB_OLD
                                     WHERE (TAB_OLD.TIPOREG = 'O'||pi_vTipoEntidade)
                                       AND (NOT EXISTS (SELECT 'S'
                                                          FROM PCMED_PROMOCAOPOLITICAS TAB_NEW
                                                         WHERE (TAB_NEW.TIPOREG         = 'N'||pi_vTipoEntidade)
                                                           AND (TAB_NEW.CODIGO          = TAB_OLD.CODIGO)))) LOOP
        vvSqlDelete := 
          ' DELETE FROM PCDESCONTO
                  WHERE (CODPROMOCAOMED = ' || NVL(pi_nCodPromocaoMed,0) || ')
                    AND (' || pi_vColuna || ' = ' || vc_RegistrosExcluidos.CODIGO || ')';
    
        EXECUTE IMMEDIATE vvSqlDelete;
                 
      END LOOP;    
    -- Promoções de Lote
    ELSIF (pi_vTipoPromocao = 'L') THEN
      FOR vc_RegistrosExcluidos IN (SELECT TAB_OLD.CODIGO
                                         , TAB_OLD.NUMLOTE
                                      FROM PCMED_PROMOCAOPOLITICAS TAB_OLD
                                     WHERE (TAB_OLD.TIPOREG = 'O'||pi_vTipoEntidade)
                                       AND (NOT EXISTS (SELECT 'S'
                                                          FROM PCMED_PROMOCAOPOLITICAS TAB_NEW
                                                         WHERE (TAB_NEW.TIPOREG         = 'N'||pi_vTipoEntidade)
                                                           AND (TAB_NEW.CODIGO          = TAB_OLD.CODIGO)
                                                           AND (TAB_NEW.NUMLOTE         = TAB_OLD.NUMLOTE)))) LOOP
        vvSqlDelete := 
          ' DELETE FROM PCDESCONTO
                  WHERE (CODPROMOCAOMED = ' || NVL(pi_nCodPromocaoMed,0) || ')
                    AND (' || pi_vColuna || ' = ' || vc_RegistrosExcluidos.CODIGO || ') 
                    AND (NUMLOTE = to_char(''' || vc_RegistrosExcluidos.NUMLOTE || ''') )';
    
        EXECUTE IMMEDIATE vvSqlDelete;
                 
      END LOOP;    
    ELSE
      FOR vc_RegistrosExcluidos IN (SELECT TAB_OLD.CODIGO
                                         , TAB_OLD.INICIOINTERVALO
                                      FROM PCMED_PROMOCAOPOLITICAS TAB_OLD
                                     WHERE (TAB_OLD.TIPOREG = 'O'||pi_vTipoEntidade)
                                       AND (NOT EXISTS (SELECT 'S'
                                                          FROM PCMED_PROMOCAOPOLITICAS TAB_NEW
                                                         WHERE (TAB_NEW.TIPOREG         = 'N'||pi_vTipoEntidade)
                                                           AND (TAB_NEW.CODIGO          = TAB_OLD.CODIGO)
                                                           AND (TAB_NEW.INICIOINTERVALO = TAB_OLD.INICIOINTERVALO)))) LOOP
        vvSqlDelete := 
          ' DELETE FROM PCDESCONTO
                  WHERE (CODPROMOCAOMED = ' || NVL(pi_nCodPromocaoMed,0) || ')
                    AND (' || pi_vColuna || ' = ' || vc_RegistrosExcluidos.CODIGO || ') 
                    AND (NVL(INICIOINTERVALOPROMOCAOMED,0) = ' || vc_RegistrosExcluidos.INICIOINTERVALO || ')';
    
        EXECUTE IMMEDIATE vvSqlDelete;
                 
      END LOOP;
    END IF;
   
  END P_REMOVE_PROMOCAOPOLITICAS;                

