  PROCEDURE P_ATUALIZAR_PROMOCAO(pi_vTipoChamada          IN  VARCHAR2,
                                 pi_nCodPromocao          IN  NUMBER,
                                 pi_nCodFunc              IN  NUMBER,
                                 pi_vListaPromocoes       IN  VARCHAR2,
                                 po_nCodPromocaoGerado    OUT NUMBER,
                                 po_vOcorreramErros       OUT VARCHAR2,
                                 po_vMsgErros             OUT VARCHAR2)
  IS

   /***********************
    Declaração de Variáveis
    ***********************/
    -- CREATE TABLE PCMED_LOGALTERACAO_PROMOCAO(DATALOG DATE, CODPROMOCAOMED NUMBER(9), OBSERVACAO VARCHAR2(200));

    -- Definição do Tipo dos Arrays
    TYPE TT_PCMED_PROMOCAOORIGEM       IS TABLE OF PCMED_PROMOCAOORIGEM%ROWTYPE INDEX BY PLS_INTEGER;
    TYPE TT_PCMED_PROMOCAOFIL          IS TABLE OF PCMED_PROMOCAOFIL%ROWTYPE INDEX BY PLS_INTEGER;
    TYPE TT_PCMED_PROMOCAOREG          IS TABLE OF PCMED_PROMOCAOREG%ROWTYPE INDEX BY PLS_INTEGER;
    TYPE TT_PCMED_PROMOCAOPRACA        IS TABLE OF PCMED_PROMOCAOPRACA%ROWTYPE INDEX BY PLS_INTEGER;
    TYPE TT_PCMED_PROMOCAOATIV         IS TABLE OF PCMED_PROMOCAOATIV%ROWTYPE INDEX BY PLS_INTEGER;
    TYPE TT_PCMED_PROMOCAOREDE         IS TABLE OF PCMED_PROMOCAOREDE%ROWTYPE INDEX BY PLS_INTEGER;
    TYPE TT_PCMED_PROMOCAOCLI          IS TABLE OF PCMED_PROMOCAOCLI%ROWTYPE INDEX BY PLS_INTEGER;
