    ------------------------------------------------------------------------------
    -- Função para Verificar se Usa Regra de Normalização da PCDESCONTO
    -------------------------------------------------------------------
    FUNCTION FUSA_REGRA_NORMALIZA_DESC
    RETURN VARCHAR2 IS
      vvRetUsaRegraNormalizaDesc VARCHAR2(1);
    BEGIN
      -- Verifica se usa regra
      BEGIN
        EXECUTE IMMEDIATE ' SELECT VALOR FROM PCREGRASEXCECAOMED WHERE NOME = ''USAREGRANORMALIZADESC'' AND CODFILIAL = ''99'' '
                     INTO vvRetUsaRegraNormalizaDesc;
      EXCEPTION
        WHEN NO_DATA_FOUND THEN
          vvRetUsaRegraNormalizaDesc := 'N';
        WHEN OTHERS THEN
          vvRetUsaRegraNormalizaDesc := 'N';
      END;
      -- Retorno
      RETURN vvRetUsaRegraNormalizaDesc;
    END FUSA_REGRA_NORMALIZA_DESC;

    ------------------------------------------------------------------------------
    -- Função para Verificar se Usa Regra de Edição de Produtos - EDTPRM
    --------------------------------------------------------------------
    FUNCTION FUSA_REGRA_EDICAO_PRODUTOS
    RETURN VARCHAR2 IS
      vvRetUsaRegraEdicaoProdutos VARCHAR2(1);
    BEGIN
      -- Verifica se usa regra
      BEGIN
        EXECUTE IMMEDIATE ' SELECT VALOR FROM PCREGRASEXCECAOMED WHERE NOME = ''USAREGRAEDICAOPRODPROMOCAO'' AND CODFILIAL = ''99'' '
                     INTO vvRetUsaRegraEdicaoProdutos;
      EXCEPTION
        WHEN NO_DATA_FOUND THEN
          vvRetUsaRegraEdicaoProdutos := 'N';
        WHEN OTHERS THEN
          vvRetUsaRegraEdicaoProdutos := 'N';
      END;
      -- Retorno
      RETURN vvRetUsaRegraEdicaoProdutos;
    END FUSA_REGRA_EDICAO_PRODUTOS;

    ------------------------------------------------------------------------------
    -- Função para Verificar se pode somente editar os produtos alterados - EDTPRM
    ------------------------------------------------------------------------------
    FUNCTION FPERMITE_EDITAR_PRODUTOS
    RETURN VARCHAR2 IS
      vvRetPermiteEditarProdutos VARCHAR2(1);
      viQtRegExc                 INTEGER;
      viQtRegAdd                 INTEGER;
      viQtdeCodigosOld           INTEGER;
      viQtdeCodigosNew           INTEGER;
      viQtdeControleDiferencas   INTEGER;
    BEGIN

      -- Retorno Default Não
      vvRetPermiteEditarProdutos := 'N';
      
      -- DDVENDAS-38534 - Somente se a Promoção estiver normalizada pode utilizar o Controle de Edição
      IF (FUSA_REGRA_NORMALIZA_DESC = 'S') THEN      

        -- Verifica se ocorreram mudanças no Cabeçalho que impedem a edição dos produtos
        SELECT COUNT(*)
          INTO viQtdeControleDiferencas
          FROM
        (
        SELECT
          TIPOPOLITICA,
          TIPOPROMOCAO,
          TIPORESTRICAO,
          UTILIZADESCREDE,
          TIPOPLANOPAG,
          ALTERADESCONTO,
          PRAZOPLPAGMANDATORIO,
          TIPOSIMPLESNACIONAL,
          PERMITECOMISSGARANTIDA,
          PERMITEQTMINIMASEMOBRIG,
          UTILIZAPERCDESCBASERCA,
          PERMITIRAUMENTARQTDEKIT,
          APLICADESCONTO
        FROM PCMED_PROMOCAOINICIAL
        UNION -->> Sem o UNION ALL, se todos os campos estiverem iguais, somente gera uma linha
        SELECT
          TIPOPOLITICA,
          TIPOPROMOCAO,
          TIPORESTRICAO,
          UTILIZADESCREDE,
          TIPOPLANOPAG,
          ALTERADESCONTO,
          PRAZOPLPAGMANDATORIO,
          TIPOSIMPLESNACIONAL,
          PERMITECOMISSGARANTIDA,
          PERMITEQTMINIMASEMOBRIG,
          UTILIZAPERCDESCBASERCA,
          PERMITIRAUMENTARQTDEKIT,
          APLICADESCONTO
        FROM PCMED_PROMOCAO
        ) PROMOCAO_CABECALHO;
  
        -- Se os Campos de Cabeçalho não sofreram mudanças
        IF (viQtdeControleDiferencas = 1) THEN
  
          -- Verifica se antes de editar existiam descontos por depto, seção, categoria ...
          SELECT COUNT(*)
            INTO viQtdeCodigosOld
            FROM PCMED_PROMOCAORESTRICOES
           WHERE (TIPOREG    = 'OLD')
             AND (TIPOCODIGO = 'XX');
          -- Verifica se depois de editar foram incluidos descontos por depto, seção, categoria ...
          SELECT COUNT(*)
            INTO viQtdeCodigosNew
            FROM PCMED_PROMOCAORESTRICOES
           WHERE (TIPOREG    = 'NEW')
             AND (TIPOCODIGO = 'XX');
  
          -- Se nem antes nem depois foram encontrados descontos por depto, seção, categoria ...
          IF (NVL(viQtdeCodigosOld,0) = 0) AND
             (NVL(viQtdeCodigosNew,0) = 0) THEN
  
            -- Verifica se alguma restrição foi excluída
            SELECT COUNT(*)
              INTO viQtRegExc
              FROM PCMED_PROMOCAORESTRICOES TAB_OLD
             WHERE (TAB_OLD.TIPOREG = 'OLD')
               AND (NOT EXISTS (SELECT 'S'
                                  FROM PCMED_PROMOCAORESTRICOES TAB_NEW
                                 WHERE (TAB_NEW.TIPOREG    = 'NEW')
                                   AND (TAB_NEW.TIPOCODIGO = TAB_OLD.TIPOCODIGO)
                                   AND (TAB_NEW.CODIGO     = TAB_OLD.CODIGO)));
            -- Verifica se alguma restrição foi adicionada
            SELECT COUNT(*)
              INTO viQtRegAdd
              FROM PCMED_PROMOCAORESTRICOES TAB_OLD
             WHERE (TAB_OLD.TIPOREG = 'NEW')
               AND (NOT EXISTS (SELECT 'S'
                                  FROM PCMED_PROMOCAORESTRICOES TAB_NEW
                                 WHERE (TAB_NEW.TIPOREG    = 'OLD')
                                   AND (TAB_NEW.TIPOCODIGO = TAB_OLD.TIPOCODIGO)
                                   AND (TAB_NEW.CODIGO     = TAB_OLD.CODIGO)));
  
            -- Se não ocorreu alteração nas Restrições
            IF (NVL(viQtRegExc,0) = 0) AND
               (NVL(viQtRegAdd,0) = 0) THEN
  
              -- Somente ocorreram mudanças nos Produtos, o retorno indicará que os produtos da promoção poderão ser editados
              vvRetPermiteEditarProdutos := 'S';
  
            END IF; -- Fim Condição Se não ocorreu alteração nas Restrições
  
          END IF; -- Fim Condição Se nem antes nem depois foram encontrados descontos por depto, seção, categoria ...
  
        END IF; -- Fim Condição Se os Campos de Cabeçalho não sofreram mudanças

      END IF; -- Fim Condição: Se Usa Normalização

      -- Retorno
      RETURN vvRetPermiteEditarProdutos;

    END FPERMITE_EDITAR_PRODUTOS;

    ------------------------------------------------------------------------------
    -- Função para Obter o Próximo Código da Promoção
    -------------------------------------------------
    FUNCTION FOBTEM_PROX_CODPROMOCAOMED
    RETURN NUMBER IS
      vnRetProxCodPromocaoMed NUMBER;
    BEGIN

      SELECT NVL(DFSEQ_PCPROMOCAOMED.NEXTVAL,0) PROXCODPROMOCAOMED
        INTO vnRetProxCodPromocaoMed
        FROM DUAL;

      -- Retorna o Sequencial
      RETURN vnRetProxCodPromocaoMed;

    END FOBTEM_PROX_CODPROMOCAOMED;

    ------------------------------------------------------------------------------
    -- Função para Obter o Próximo Código de Desconto
    -------------------------------------------------
    FUNCTION FOBTEM_PROX_CODDESCONTO
    RETURN NUMBER IS
      vnRetProxCodDesconto NUMBER;
    BEGIN

      SELECT NVL(DFSEQ_PCDESCONTO.NEXTVAL,0) PROXCODDESCONTO
        INTO vnRetProxCodDesconto
        FROM DUAL;

      -- Retorna o Sequencial
      RETURN vnRetProxCodDesconto;

    END FOBTEM_PROX_CODDESCONTO;

    ------------------------------------------------------------------------------
    -- Função para Obter o Próximo Código de Desconto por Quantidade
    ----------------------------------------------------------------
    FUNCTION FOBTEM_PROX_CODDESCQUANT
    RETURN NUMBER IS
      vnRetProxCodDescQuant NUMBER;
    BEGIN

      SELECT NVL(DFSEQ_PCDESCQUANT.NEXTVAL,0) PROXCODDESCQUANT
        INTO vnRetProxCodDescQuant
        FROM DUAL;

      -- Retorna o Sequencial
      RETURN vnRetProxCodDescQuant;

    END FOBTEM_PROX_CODDESCQUANT;

    ------------------------------------------------------------------------------
    -- Procedimento para limpar as Tabelas Temporárias do Relatório
    ---------------------------------------------------------------
    PROCEDURE PLIMPA_TABELAS_RELATORIO IS
    BEGIN

      DELETE FROM PCMED_PROMOCAORELCAB;
      DELETE FROM PCMED_PROMOCAORELDETDESC;
      DELETE FROM PCMED_PROMOCAORELDETREST;

    END PLIMPA_TABELAS_RELATORIO;

    ------------------------------------------------------------------------------
    -- Procedimento para limpar as Tabelas Temporárias
    --------------------------------------------------
    PROCEDURE PLIMPA_TABELAS_TEMPORARIAS IS
    BEGIN

      DELETE FROM PCMED_PROMOCAO;
      DELETE FROM PCMED_PROMOCAOORIGEM;
      DELETE FROM PCMED_PROMOCAOFIL;
      DELETE FROM PCMED_PROMOCAOREG;
      DELETE FROM PCMED_PROMOCAOPRACA;
      DELETE FROM PCMED_PROMOCAOATIV;
      DELETE FROM PCMED_PROMOCAOREDE;
      DELETE FROM PCMED_PROMOCAOCLI;
      DELETE FROM PCMED_PROMOCAOAREA;
      DELETE FROM PCMED_PROMOCAOSUP;
      DELETE FROM PCMED_PROMOCAOUSUR;
      DELETE FROM PCMED_PROMOCAOPLPAG;
      DELETE FROM PCMED_PROMOCAOCONDVENDA;
      DELETE FROM PCMED_PROMOCAOCLASSE;
      DELETE FROM PCMED_PROMOCAOGRUPOCOMERC;
      DELETE FROM PCMED_PROMOCAORESTCLI;
      DELETE FROM PCMED_PROMOCAORESTRCA;
      DELETE FROM PCMED_PROMOCAODEPTO;
      DELETE FROM PCMED_PROMOCAODEPTO_FAIXA;
      DELETE FROM PCMED_PROMOCAOSECAO;
      DELETE FROM PCMED_PROMOCAOSECAO_FAIXA;
      DELETE FROM PCMED_PROMOCAOCATEG;
      DELETE FROM PCMED_PROMOCAOCATEG_FAIXA;
      DELETE FROM PCMED_PROMOCAOFORNEC;
      DELETE FROM PCMED_PROMOCAOFORNEC_FAIXA;
      DELETE FROM PCMED_PROMOCAOMARCA;
      DELETE FROM PCMED_PROMOCAOMARCA_FAIXA;
      DELETE FROM PCMED_PROMOCAOLINHAPROD;
      DELETE FROM PCMED_PROMOCAOLINHAPROD_FAIXA;
      DELETE FROM PCMED_PROMOCAORESTGRUPRO; -- HIS.01889.2017
      DELETE FROM PCMED_PROMOCAORESTGRUPRO_FAIXA; -- HIS.01889.2017
      DELETE FROM PCMED_PROMOCAOPRODUTO;
      DELETE FROM PCMED_PROMOCAOPRODUTO_FAIXA;
      DELETE FROM PCMED_PROMOCAOBRINDE; -- HIS.01889.2017
      DELETE FROM PCMED_PROMOCAOVERBA; -- DDMEDICA-4915
      -->> Ao Confirmar a alteração de uma Promoção, precisa dos dados originais gravados ao Carregar a Promoção,
      -->> para poder comparar com os novos dados a serem confirmados pelo usuário - EDTPRM
      IF (pi_vTipoChamada <> '4') THEN
        -- Tabela Temporária com Cabeçalho Inicial antes da edição do usuário
        DELETE FROM PCMED_PROMOCAOINICIAL;
        -- Tabela Temporária de Restrições antes da edição do usuário
        DELETE FROM PCMED_PROMOCAORESTRICOES;
        -- Tabela Temporária de Políticas antes da edição do usuário
        DELETE FROM PCMED_PROMOCAOPOLITICAS;
      END IF;

    END PLIMPA_TABELAS_TEMPORARIAS;

    ------------------------------------------------------------------------------
    -- Procedimento para limpar as Restrições Específicas
    -----------------------------------------------------
    PROCEDURE PLIMPA_RESTRICOES_ESPECIFICAS IS
    BEGIN

      vrDESCONTO.nCODREDE       := NULL;
      vrDESCONTO.nCODCLI        := NULL;
      vrDESCONTO.vAREAATUACAO   := NULL;
      vrDESCONTO.nCODSUPERVISOR := NULL;
      vrDESCONTO.nCODUSUR       := NULL;
      vrDESCONTO.vTIPOGRUPOREST := NULL;
      vrDESCONTO.nCODGRUPOREST  := NULL;

    END PLIMPA_RESTRICOES_ESPECIFICAS;

    ------------------------------------------------------------------------------
    -- Função para Obter se Participa da Comissão Garantida
    -------------------------------------------------------
    FUNCTION F_PARTICIPACOMISSGARANTIDA(pi_vParticipaComissGarantida VARCHAR)
    RETURN VARCHAR2 IS
      vvRetParticipaComissGarantida VARCHAR2(1);
    BEGIN

     -- Se no Cabeçalho da Promoção permitir Comissão Garantida, retorna valor passado no parâmetro
     IF (NVL(vvPermiteComissGarantida,'N') = 'S') THEN
       vvRetParticipaComissGarantida := pi_vParticipaComissGarantida;
     -- Se no Cabeçalho da Promoção NÃO permitir Comissão Garantida, retorna SEMPRE N-Não
     ELSE
       vvRetParticipaComissGarantida := 'N';
     END IF;

      -- Retorna o Flag
      RETURN vvRetParticipaComissGarantida;

    END F_PARTICIPACOMISSGARANTIDA;

    ------------------------------------------------------------------------------
    -- Procedimento para Inserir os Descontos
    -----------------------------------------
    PROCEDURE PINSERE_DESCONTOS IS
      -- Variáveis Locais
      vvAchouSecaoDoDepto VARCHAR2(1);
      vvAchouCategDaSecao VARCHAR2(1);
    BEGIN

      -------------------------------------------------------------------------------------------------------------------
      -- Se Politica de Desconto/Desconto por Quantidade/Preço Fixo/ Preço por Quantidade/BonifMerc por Quantidade/Markup
      -------------------------------------------------------------------------------------------------------------------
      IF    (vvTipoPolitica IN ('D','Q','P','F','B','M','V')) THEN

        -- Laço de Departamentos para Inclusao do Departamento e Seção
        FOR idxDepto IN vtPCMED_PROMOCAODEPTO.FIRST..vtPCMED_PROMOCAODEPTO.LAST LOOP

          -- Preenche variável com os valor do Array para atualização da PCDESCONTO
          vrDESCONTO.nCODEPTO := vtPCMED_PROMOCAODEPTO(idxDepto).CODEPTO;

          -- Se informou o Departamento
          IF (vrDESCONTO.nCODEPTO IS NOT NULL) THEN

            -- De Política de Desconto ou Markup gera uma linha no Array com os dados do Departamento
            IF    (vvTipoPolitica IN ('D','M')) OR
                  (vvTipoPromocao IN ('N'))     THEN -- HIS.01889.2017 - Promoção de Campanha não tem Faixa de Qtde
              vtPCMED_PROMOCAODEPTO_FAIXA(1).PERCDESC                 := vtPCMED_PROMOCAODEPTO(idxDepto).PERCDESC;
              vtPCMED_PROMOCAODEPTO_FAIXA(1).PERCDESCFIN              := vtPCMED_PROMOCAODEPTO(idxDepto).PERCDESCFIN;
              vtPCMED_PROMOCAODEPTO_FAIXA(1).PERCOMEXT                := vtPCMED_PROMOCAODEPTO(idxDepto).PERCOMEXT;
              vtPCMED_PROMOCAODEPTO_FAIXA(1).PERCOMREP                := vtPCMED_PROMOCAODEPTO(idxDepto).PERCOMREP;
              vtPCMED_PROMOCAODEPTO_FAIXA(1).PERCOMMINT               := vtPCMED_PROMOCAODEPTO(idxDepto).PERCOMMINT;
              vtPCMED_PROMOCAODEPTO_FAIXA(1).INICIOINTERVALO          := NULL;
              vtPCMED_PROMOCAODEPTO_FAIXA(1).FIMINTERVALO             := NULL;
              vtPCMED_PROMOCAODEPTO_FAIXA(1).PARTICIPACOMISSGARANTIDA := vtPCMED_PROMOCAODEPTO(idxDepto).PARTICIPACOMISSGARANTIDA;
              vtPCMED_PROMOCAODEPTO_FAIXA(1).PERCDESCBASERCA          := vtPCMED_PROMOCAODEPTO(idxDepto).PERCDESCBASERCA;
              vtPCMED_PROMOCAODEPTO_FAIXA(1).REGRAALTERARDESCONTO     := vtPCMED_PROMOCAODEPTO(idxDepto).REGRAALTERARDESCONTO;
            -- De Desconto/BonifMerc por Quantidade por Quantidade Carrega Array as Faixas
            ELSIF (vvTipoPolitica IN ('Q','B','V')) THEN
              SELECT *
                BULK COLLECT INTO vtPCMED_PROMOCAODEPTO_FAIXA
                FROM PCMED_PROMOCAODEPTO_FAIXA
               WHERE (CODEPTOREF = vrDESCONTO.nCODEPTO);
            END IF;

            -- Se gerou as Faixas
            IF (vtPCMED_PROMOCAODEPTO_FAIXA.COUNT > 0) THEN
              FOR idxDeptoFaixa IN vtPCMED_PROMOCAODEPTO_FAIXA.FIRST..vtPCMED_PROMOCAODEPTO_FAIXA.LAST LOOP

                -- Pega Desconto informado no Departamento
                IF    (vvTipoPolitica IN ('B')) THEN -- Bonificação de Mercadoria
                  vrDESCONTO.nPERCBONIFICMERC          := vtPCMED_PROMOCAODEPTO_FAIXA(idxDeptoFaixa).PERCDESC;
                  vrDESCONTO.nPERCMARKUPMED            := NULL;
                  vrDESCONTO.nPERCDESC                 := 0;
                  vrDESCONTO.nPERCDESCFIN              := 0;
                -- Pega Markup informado no Departamento
                ELSIF (vvTipoPromocao IN ('R')) THEN -- Percentual de Markup
                  vrDESCONTO.nPERCBONIFICMERC          := NULL;
                  vrDESCONTO.nPERCMARKUPMED            := vtPCMED_PROMOCAODEPTO_FAIXA(idxDeptoFaixa).PERCDESC;
                  vrDESCONTO.nPERCDESC                 := 0;
                  vrDESCONTO.nPERCDESCFIN              := vtPCMED_PROMOCAODEPTO_FAIXA(idxDeptoFaixa).PERCDESCFIN;
                ELSE
                  vrDESCONTO.nPERCBONIFICMERC          := NULL;
                  vrDESCONTO.nPERCMARKUPMED            := NULL;
                  vrDESCONTO.nPERCDESC                 := vtPCMED_PROMOCAODEPTO_FAIXA(idxDeptoFaixa).PERCDESC;
                  vrDESCONTO.nPERCDESCFIN              := vtPCMED_PROMOCAODEPTO_FAIXA(idxDeptoFaixa).PERCDESCFIN;
                END IF;
                -- Pega as Comissões informadas no Departamento
                vrDESCONTO.nPERCOMEXT                  := vtPCMED_PROMOCAODEPTO_FAIXA(idxDeptoFaixa).PERCOMEXT;
                vrDESCONTO.nPERCOMREP                  := vtPCMED_PROMOCAODEPTO_FAIXA(idxDeptoFaixa).PERCOMREP;
                vrDESCONTO.nPERCOMMINT                 := vtPCMED_PROMOCAODEPTO_FAIXA(idxDeptoFaixa).PERCOMMINT;
                -- Pega as Faixas de Quantidade do Departamento
                vrDESCONTO.nINICIOINTERVALOPROMOCAOMED := vtPCMED_PROMOCAODEPTO_FAIXA(idxDeptoFaixa).INICIOINTERVALO;
                vrDESCONTO.nFIMINTERVALOPROMOCAOMED    := vtPCMED_PROMOCAODEPTO_FAIXA(idxDeptoFaixa).FIMINTERVALO;
                -- Não Altera Preço de Tabela
                vrDESCONTO.vALTERAPTABELA              := 'N';
                -- Participa da Comissão Garantida
                vrDESCONTO.vPARTICIPACOMISSGARANTIDA   := F_PARTICIPACOMISSGARANTIDA(vtPCMED_PROMOCAODEPTO_FAIXA(idxDeptoFaixa).PARTICIPACOMISSGARANTIDA);
                -- Desconto C/C
                vrDESCONTO.nPERCDESCBASERCA            := vtPCMED_PROMOCAODEPTO_FAIXA(idxDeptoFaixa).PERCDESCBASERCA;
                -- Regra de alteração do Desconto/Preço
                vrDESCONTO.nREGRAALTERARDESCONTO       := vtPCMED_PROMOCAODEPTO_FAIXA(idxDeptoFaixa).REGRAALTERARDESCONTO;

                -----------------------------------------------------------------------
                -- AÇÃO INCLUSÃO/ALTERAÇÃO/EXCLUSÃO DO DESCONTO POR DEPTO - EDTPRM
                -----------------------------------------------------------------------
                vrEditarPromocao.vvAcaoEditaDepto := F_DEFINE_ACAO_EDICAO(NVL(vrEditarPromocao.vvPermiteEditarProduto,'N'),
                                                                          'dp',
                                                                          vrDESCONTO.nCODEPTO,
                                                                          vrDESCONTO.nINICIOINTERVALOPROMOCAOMED,
                                                                          vvTipoPromocao, NULL);

                ---------------------------------------
                -- INCLUSÃO/ALTERAÇÃO/EXCLUSÃO DO DEPTO
                ---------------------------------------

                -- Insere na PCDESCONTO o Desconto do Depto
                IF    (vrEditarPromocao.vvAcaoEditaDepto = 'I') THEN

                -- Insere na PCDESCONTO o Desconto do Departamento
                vnNovoCodDesconto := FOBTEM_PROX_CODDESCONTO;
                INSERT INTO PCDESCONTO
                          ( CODDESCONTO
                          , CODPROMOCAOMED
                          , DTINICIO
                          , DTFIM
                          , APLICADESCONTO
                          , TIPO
                          , BASECREDDEBRCA
                          , CREDITASOBREPOLITICA
                          , CONSIDERACALCGIROMEDIC
                          , UTILIZADESCREDE
                          , APENASPLPAGMAX
                          --
                          , CODFUNCLANC
                          , DATALANC
                          , CODFUNCULTALTER
                          , DATAULTALTER
                          , ALTERAPTABELA
                          , PRIORITARIA
                          , QUESTIONAUSOPRIORITARIA
                          , APLICADESCSIMPLESNACIONAL
                          , PRIORITARIAGERAL
                          --
                          , PERCDESC
                          , PERCDESCFIN
                          --
                          , ORIGEMPED
                          , TIPOFV
                          , CODFILIAL
                          , NUMREGIAO
                          , CODPRACA
                          , CODATIV
                          , CLASSEVENDA
                          , CODPLPAG
                          , CODCONDICAOVENDA
                          , CODREDE
                          , CODCLI
                          , AREAATUACAO
                          , CODSUPERVISOR
                          , CODUSUR
                          , CODEPTO
                          --
                          , PERCOMEXT
                          , PERCOMREP
                          , PERCOMMINT
                          , TIPOPOLITICAPROMOCAOMED
                          , INICIOINTERVALOPROMOCAOMED
                          , FIMINTERVALOPROMOCAOMED
                          , PARTICIPACOMISSGARANTIDA
                          , PERCDESCBASERCA
                          , PERCBONIFICMERC
                          , PERCMARKUPMED
                          --
                          , TIPOVENDA
                          , REGRAALTERARDESCONTO
                          )
                   VALUES ( vnNovoCodDesconto
                          , vnNovoCodPromocaoMed -->> Novo Sequencial de Promoção
                          , vdDataInicial
                          , vdDataFinal
                          , vvAplicaDesconto --> HIS.02032.2017 - Flag 'Aplicar desconto automaticamente'
                          , 'C' -- Comercial
                          , vvBaseCredDebRca
                          , vvCreditaSobrePolitica
                          , vvConsideraCalcGiroMedic
                          , vvUtilizaDescRede
                          , vvApenasPlPagMax
                          --
                          , pi_nCodFunc
                          , SYSDATE
                          , pi_nCodFunc
                          , TRUNC(SYSDATE)
                          , vrDESCONTO.vALTERAPTABELA
                          , 'N'
                          , 'N'
                          , vvAplicaDescSimplesNacional
                          , 'N'
                          --
                          , vrDESCONTO.nPERCDESC
                          , vrDESCONTO.nPERCDESCFIN
                          --
                          , vrDESCONTO.vORIGEMPED
                          , vrDESCONTO.vTIPOFV
                          , vrDESCONTO.vCODFILIAL
                          , vrDESCONTO.nNUMREGIAO
                          , vrDESCONTO.nCODPRACA
                          , vrDESCONTO.nCODATIV
                          , vrDESCONTO.vCLASSEVENDA
                          , vrDESCONTO.nCODPLPAG
                          , vrDESCONTO.nCODCONDICAOVENDA
                          , vrDESCONTO.nCODREDE
                          , vrDESCONTO.nCODCLI
                          , vrDESCONTO.vAREAATUACAO
                          , vrDESCONTO.nCODSUPERVISOR
                          , vrDESCONTO.nCODUSUR
                          , vrDESCONTO.nCODEPTO
                          --
                          , vrDESCONTO.nPERCOMEXT
                          , vrDESCONTO.nPERCOMREP
                          , vrDESCONTO.nPERCOMMINT
                          , vvTipoPolitica
                          , vrDESCONTO.nINICIOINTERVALOPROMOCAOMED
                          , vrDESCONTO.nFIMINTERVALOPROMOCAOMED
                          , vrDESCONTO.vPARTICIPACOMISSGARANTIDA
                          , vrDESCONTO.nPERCDESCBASERCA
                          , vrDESCONTO.nPERCBONIFICMERC
                          , vrDESCONTO.nPERCMARKUPMED
                          --
                          , vrDESCONTO.vTIPOVENDA
                          , vrDESCONTO.nREGRAALTERARDESCONTO
                          );

                -- Altera na PCDESCONTO o Desconto do Depto - EDTPRM
                ELSIF (vrEditarPromocao.vvAcaoEditaDepto = 'A') THEN

                  UPDATE PCDESCONTO
                     SET DTINICIO                   = vdDataInicial
                       , DTFIM                      = vdDataFinal
                       , BASECREDDEBRCA             = vvBaseCredDebRca
                       , CREDITASOBREPOLITICA       = vvCreditaSobrePolitica
                       , CONSIDERACALCGIROMEDIC     = vvConsideraCalcGiroMedic
                       --
                       , PERCDESC                   = vrDESCONTO.nPERCDESC
                       , PERCDESCFIN                = vrDESCONTO.nPERCDESCFIN
                       , PERCOMEXT                  = vrDESCONTO.nPERCOMEXT
                       , PERCOMREP                  = vrDESCONTO.nPERCOMREP
                       , PERCOMMINT                 = vrDESCONTO.nPERCOMMINT
                       , TIPOPOLITICAPROMOCAOMED    = vvTipoPolitica
                       , PROMOCAOMEDOBRIGATORIO     = vvObrigatorio
                       , INICIOINTERVALOPROMOCAOMED = vrDESCONTO.nINICIOINTERVALOPROMOCAOMED
                       , FIMINTERVALOPROMOCAOMED    = vrDESCONTO.nFIMINTERVALOPROMOCAOMED
                       , PRECOFIXOPROMOCAOMED       = vrDESCONTO.nPRECOFIXOPROMOCAOMED
                       , PARTICIPACOMISSGARANTIDA   = vrDESCONTO.vPARTICIPACOMISSGARANTIDA
                       , PERCDESCBASERCA            = vrDESCONTO.nPERCDESCBASERCA
                       , PERCBONIFICMERC            = vrDESCONTO.nPERCBONIFICMERC
                       , PERCMARKUPMED              = vrDESCONTO.nPERCMARKUPMED
                       , APLICADESCONTO             = vvAplicaDesconto
                       , NUMLOTE                    = vrDESCONTO.vNUMLOTE
                       , VALORCOTAMED               = vrDESCONTO.nVALORCOTAMED
                       , CODIGOINTEGRACAOWMS        = vrDESCONTO.vCODIGOINTEGRACAOWMS
                       , VLDESCCMVPROMOCAOMED       = vrDESCONTO.nVLDESCCMVPROMOCAOMED
                       , REGRAALTERARDESCONTO       = vrDESCONTO.nREGRAALTERARDESCONTO
                   WHERE (CODPROMOCAOMED                    = vnNovoCodPromocaoMed)
                     AND (CODEPTO                           = vrDESCONTO.nCODEPTO)
                     AND (NVL(INICIOINTERVALOPROMOCAOMED,0) = NVL(vrDESCONTO.nINICIOINTERVALOPROMOCAOMED,0));

                -- Excluir na PCDESCONTO o Desconto - EDTPRM
                ELSIF (vrEditarPromocao.vvAcaoEditaDepto = 'E') THEN

                  DELETE FROM PCDESCONTO
                        WHERE (CODPROMOCAOMED                    = vnNovoCodPromocaoMed)
                          AND (CODEPTO                           = vrDESCONTO.nCODEPTO)
                          AND (NVL(INICIOINTERVALOPROMOCAOMED,0) = NVL(vrDESCONTO.nINICIOINTERVALOPROMOCAOMED,0));

                END IF; -- Fim Condição Tipo Ação da Edição do Depto

              END LOOP; -- Fim Laço de Faixas
            END IF; -- Fim Condição se Gerou Faixas

          END IF; -- Fim Condição se informou o Departamento

          -- Laço de Seções para Inclusão da Seção
          FOR idxSecao IN vtPCMED_PROMOCAOSECAO.FIRST..vtPCMED_PROMOCAOSECAO.LAST LOOP

            -- Preenche variável com os valor do Array para atualização da PCDESCONTO
            vrDESCONTO.nCODSEC := vtPCMED_PROMOCAOSECAO(idxSecao).CODSEC;

            -- Se informou a Seção
            IF (vrDESCONTO.nCODSEC IS NOT NULL) THEN

              -- Se informou o Departamento,
              -- verifica se a Seção pertence ao Departamento
              IF (vrDESCONTO.nCODEPTO IS NOT NULL) THEN
                BEGIN
                  SELECT 'S'
                    INTO vvAchouSecaoDoDepto
                    FROM PCSECAO
                   WHERE (CODSEC  = vrDESCONTO.nCODSEC)
                     AND (CODEPTO = vrDESCONTO.nCODEPTO);
                EXCEPTION
                  WHEN NO_DATA_FOUND THEN
                    vvAchouSecaoDoDepto := 'N';
                END;
              END IF;

              -- Se não informou o Departamento ou
              -- Se informou o Departamento e a Seção pertence ao Departamento
              IF (vrDESCONTO.nCODEPTO IS NULL) OR
                 ((vrDESCONTO.nCODEPTO IS NOT NULL) AND (NVL(vvAchouSecaoDoDepto,'N') = 'S')) THEN

                -- De Política de Desconto ou Markup gera uma linha no Array com os dados da Seção
                IF    (vvTipoPolitica IN ('D','M')) OR
                      (vvTipoPromocao IN ('N'))     THEN -- HIS.01889.2017 - Promoção de Campanha não tem Faixa de Qtde
                  vtPCMED_PROMOCAOSECAO_FAIXA(1).PERCDESC                 := vtPCMED_PROMOCAOSECAO(idxSecao).PERCDESC;
                  vtPCMED_PROMOCAOSECAO_FAIXA(1).PERCDESCFIN              := vtPCMED_PROMOCAOSECAO(idxSecao).PERCDESCFIN;
                  vtPCMED_PROMOCAOSECAO_FAIXA(1).PERCOMEXT                := vtPCMED_PROMOCAOSECAO(idxSecao).PERCOMEXT;
                  vtPCMED_PROMOCAOSECAO_FAIXA(1).PERCOMREP                := vtPCMED_PROMOCAOSECAO(idxSecao).PERCOMREP;
                  vtPCMED_PROMOCAOSECAO_FAIXA(1).PERCOMMINT               := vtPCMED_PROMOCAOSECAO(idxSecao).PERCOMMINT;
                  vtPCMED_PROMOCAOSECAO_FAIXA(1).INICIOINTERVALO          := NULL;
                  vtPCMED_PROMOCAOSECAO_FAIXA(1).FIMINTERVALO             := NULL;
                  vtPCMED_PROMOCAOSECAO_FAIXA(1).PARTICIPACOMISSGARANTIDA := vtPCMED_PROMOCAOSECAO(idxSecao).PARTICIPACOMISSGARANTIDA;
                  vtPCMED_PROMOCAOSECAO_FAIXA(1).PERCDESCBASERCA          := vtPCMED_PROMOCAOSECAO(idxSecao).PERCDESCBASERCA;
                  vtPCMED_PROMOCAOSECAO_FAIXA(1).REGRAALTERARDESCONTO     := vtPCMED_PROMOCAOSECAO(idxSecao).REGRAALTERARDESCONTO;
                -- De Desconto/BonifMerc por Quantidade por Quantidade Carrega Array as Faixas
                ELSIF (vvTipoPolitica IN ('Q','B','V')) THEN
                  SELECT *
                    BULK COLLECT INTO vtPCMED_PROMOCAOSECAO_FAIXA
                    FROM PCMED_PROMOCAOSECAO_FAIXA
                   WHERE (CODSECREF = vrDESCONTO.nCODSEC);
                END IF;

                -- Se gerou as Faixas
                IF (vtPCMED_PROMOCAOSECAO_FAIXA.COUNT > 0) THEN
                  FOR idxSecaoFaixa IN vtPCMED_PROMOCAOSECAO_FAIXA.FIRST..vtPCMED_PROMOCAOSECAO_FAIXA.LAST LOOP

                    -- Pega Desconto informado na Seção
                    IF (vvTipoPolitica IN ('B')) THEN -- Bonificação de Mercadoria
                      vrDESCONTO.nPERCBONIFICMERC          := vtPCMED_PROMOCAOSECAO_FAIXA(idxSecaoFaixa).PERCDESC;
                      vrDESCONTO.nPERCMARKUPMED            := NULL;
                      vrDESCONTO.nPERCDESC                 := 0;
                      vrDESCONTO.nPERCDESCFIN              := 0;
                    -- Pega Markup informado na Seção
                    ELSIF (vvTipoPromocao IN ('R')) THEN -- Percentual de Markup
                      vrDESCONTO.nPERCBONIFICMERC          := NULL;
                      vrDESCONTO.nPERCMARKUPMED            := vtPCMED_PROMOCAOSECAO_FAIXA(idxSecaoFaixa).PERCDESC;
                      vrDESCONTO.nPERCDESC                 := 0;
                      vrDESCONTO.nPERCDESCFIN              := vtPCMED_PROMOCAOSECAO_FAIXA(idxSecaoFaixa).PERCDESCFIN;
                    ELSE
                      vrDESCONTO.nPERCBONIFICMERC          := NULL;
                      vrDESCONTO.nPERCMARKUPMED            := NULL;
                      vrDESCONTO.nPERCDESC                 := vtPCMED_PROMOCAOSECAO_FAIXA(idxSecaoFaixa).PERCDESC;
                      vrDESCONTO.nPERCDESCFIN              := vtPCMED_PROMOCAOSECAO_FAIXA(idxSecaoFaixa).PERCDESCFIN;
                    END IF;
                    -- Pega as Comissões informadas na Seção
                    vrDESCONTO.nPERCOMEXT                  := vtPCMED_PROMOCAOSECAO_FAIXA(idxSecaoFaixa).PERCOMEXT;
                    vrDESCONTO.nPERCOMREP                  := vtPCMED_PROMOCAOSECAO_FAIXA(idxSecaoFaixa).PERCOMREP;
                    vrDESCONTO.nPERCOMMINT                 := vtPCMED_PROMOCAOSECAO_FAIXA(idxSecaoFaixa).PERCOMMINT;
                    -- Pega as Faixas de Quantidade na Seção
                    vrDESCONTO.nINICIOINTERVALOPROMOCAOMED := vtPCMED_PROMOCAOSECAO_FAIXA(idxSecaoFaixa).INICIOINTERVALO;
                    vrDESCONTO.nFIMINTERVALOPROMOCAOMED    := vtPCMED_PROMOCAOSECAO_FAIXA(idxSecaoFaixa).FIMINTERVALO;
                    -- Não Altera Preço de Tabela
                    vrDESCONTO.vALTERAPTABELA              := 'N';
                    -- Participa da Comissão Garantida
                    vrDESCONTO.vPARTICIPACOMISSGARANTIDA   := F_PARTICIPACOMISSGARANTIDA(vtPCMED_PROMOCAOSECAO_FAIXA(idxSecaoFaixa).PARTICIPACOMISSGARANTIDA);
                    -- Desconto C/C
                    vrDESCONTO.nPERCDESCBASERCA            := vtPCMED_PROMOCAOSECAO_FAIXA(idxSecaoFaixa).PERCDESCBASERCA;
                    -- Regra de alteração do Desconto/Preço
                    vrDESCONTO.nREGRAALTERARDESCONTO       := vtPCMED_PROMOCAOSECAO_FAIXA(idxSecaoFaixa).REGRAALTERARDESCONTO;

                    -----------------------------------------------------------------------
                    -- AÇÃO INCLUSÃO/ALTERAÇÃO/EXCLUSÃO DO DESCONTO POR SEÇÃO - EDTPRM
                    -----------------------------------------------------------------------
                    vrEditarPromocao.vvAcaoEditaSecao := F_DEFINE_ACAO_EDICAO(NVL(vrEditarPromocao.vvPermiteEditarProduto,'N'),
                                                                              'sc',
                                                                              vrDESCONTO.nCODSEC,
                                                                              vrDESCONTO.nINICIOINTERVALOPROMOCAOMED,
                                                                              vvTipoPromocao, NULL);

                    ---------------------------------------
                    -- INCLUSÃO/ALTERAÇÃO/EXCLUSÃO DA SEÇÃO
                    ---------------------------------------

                    -- Insere na PCDESCONTO o Desconto da Seção
                    IF    (vrEditarPromocao.vvAcaoEditaSecao = 'I') THEN

                    -- Insere na PCDESCONTO o Desconto da Seção
                    vnNovoCodDesconto := FOBTEM_PROX_CODDESCONTO;
                    INSERT INTO PCDESCONTO
                              ( CODDESCONTO
                              , CODPROMOCAOMED
                              , DTINICIO
                              , DTFIM
                              , APLICADESCONTO
                              , TIPO
                              , BASECREDDEBRCA
                              , CREDITASOBREPOLITICA
                              , CONSIDERACALCGIROMEDIC
                              , UTILIZADESCREDE
                              , APENASPLPAGMAX
                              --
                              , CODFUNCLANC
                              , DATALANC
                              , CODFUNCULTALTER
                              , DATAULTALTER
                              , ALTERAPTABELA
                              , PRIORITARIA
                              , QUESTIONAUSOPRIORITARIA
                              , APLICADESCSIMPLESNACIONAL
                              , PRIORITARIAGERAL
                              --
                              , PERCDESC
                              , PERCDESCFIN
                              --
                              , ORIGEMPED
                              , TIPOFV
                              , CODFILIAL
                              , NUMREGIAO
                              , CODPRACA
                              , CODATIV
                              , CLASSEVENDA
                              , CODPLPAG
                              , CODCONDICAOVENDA
                              , CODREDE
                              , CODCLI
                              , AREAATUACAO
                              , CODSUPERVISOR
                              , CODUSUR
                              , CODEPTO
                              , CODSEC
                              --
                              , PERCOMEXT
                              , PERCOMREP
                              , PERCOMMINT
                              , TIPOPOLITICAPROMOCAOMED
                              , INICIOINTERVALOPROMOCAOMED
                              , FIMINTERVALOPROMOCAOMED
                              , PARTICIPACOMISSGARANTIDA
                              , PERCDESCBASERCA
                              , PERCBONIFICMERC
                              , PERCMARKUPMED
                              --
                              , TIPOVENDA
                              , REGRAALTERARDESCONTO
                              )
                       VALUES ( vnNovoCodDesconto
                              , vnNovoCodPromocaoMed -->> Novo Sequencial de Promoção
                              , vdDataInicial
                              , vdDataFinal
                              , vvAplicaDesconto --> HIS.02032.2017 - Flag 'Aplicar desconto automaticamente'
                              , 'C' -- Comercial
                              , vvBaseCredDebRca
                              , vvCreditaSobrePolitica
                              , vvConsideraCalcGiroMedic
                              , vvUtilizaDescRede
                              , vvApenasPlPagMax
                              --
                              , pi_nCodFunc
                              , SYSDATE
                              , pi_nCodFunc
                              , TRUNC(SYSDATE)
                              , vrDESCONTO.vALTERAPTABELA
                              , 'N'
                              , 'N'
                              , vvAplicaDescSimplesNacional
                              , 'N'
                              --
                              , vrDESCONTO.nPERCDESC
                              , vrDESCONTO.nPERCDESCFIN
                              --
                              , vrDESCONTO.vORIGEMPED
                              , vrDESCONTO.vTIPOFV
                              , vrDESCONTO.vCODFILIAL
                              , vrDESCONTO.nNUMREGIAO
                              , vrDESCONTO.nCODPRACA
                              , vrDESCONTO.nCODATIV
                              , vrDESCONTO.vCLASSEVENDA
                              , vrDESCONTO.nCODPLPAG
                              , vrDESCONTO.nCODCONDICAOVENDA
                              , vrDESCONTO.nCODREDE
                              , vrDESCONTO.nCODCLI
                              , vrDESCONTO.vAREAATUACAO
                              , vrDESCONTO.nCODSUPERVISOR
                              , vrDESCONTO.nCODUSUR
                              , vrDESCONTO.nCODEPTO
                              , vrDESCONTO.nCODSEC
                              --
                              , vrDESCONTO.nPERCOMEXT
                              , vrDESCONTO.nPERCOMREP
                              , vrDESCONTO.nPERCOMMINT
                              , vvTipoPolitica
                              , vrDESCONTO.nINICIOINTERVALOPROMOCAOMED
                              , vrDESCONTO.nFIMINTERVALOPROMOCAOMED
                              , vrDESCONTO.vPARTICIPACOMISSGARANTIDA
                              , vrDESCONTO.nPERCDESCBASERCA
                              , vrDESCONTO.nPERCBONIFICMERC
                              , vrDESCONTO.nPERCMARKUPMED
                              --
                              , vrDESCONTO.vTIPOVENDA
                              , vrDESCONTO.nREGRAALTERARDESCONTO
                              );

                  -- Altera na PCDESCONTO o Desconto da Seção - EDTPRM
                  ELSIF (vrEditarPromocao.vvAcaoEditaSecao = 'A') THEN
  
                    UPDATE PCDESCONTO
                       SET DTINICIO                   = vdDataInicial
                         , DTFIM                      = vdDataFinal
                         , BASECREDDEBRCA             = vvBaseCredDebRca
                         , CREDITASOBREPOLITICA       = vvCreditaSobrePolitica
                         , CONSIDERACALCGIROMEDIC     = vvConsideraCalcGiroMedic
                         --
                         , PERCDESC                   = vrDESCONTO.nPERCDESC
                         , PERCDESCFIN                = vrDESCONTO.nPERCDESCFIN
                         , PERCOMEXT                  = vrDESCONTO.nPERCOMEXT
                         , PERCOMREP                  = vrDESCONTO.nPERCOMREP
                         , PERCOMMINT                 = vrDESCONTO.nPERCOMMINT
                         , TIPOPOLITICAPROMOCAOMED    = vvTipoPolitica
                         , PROMOCAOMEDOBRIGATORIO     = vvObrigatorio
                         , INICIOINTERVALOPROMOCAOMED = vrDESCONTO.nINICIOINTERVALOPROMOCAOMED
                         , FIMINTERVALOPROMOCAOMED    = vrDESCONTO.nFIMINTERVALOPROMOCAOMED
                         , PRECOFIXOPROMOCAOMED       = vrDESCONTO.nPRECOFIXOPROMOCAOMED
                         , PARTICIPACOMISSGARANTIDA   = vrDESCONTO.vPARTICIPACOMISSGARANTIDA
                         , PERCDESCBASERCA            = vrDESCONTO.nPERCDESCBASERCA
                         , PERCBONIFICMERC            = vrDESCONTO.nPERCBONIFICMERC
                         , PERCMARKUPMED              = vrDESCONTO.nPERCMARKUPMED
                         , APLICADESCONTO             = vvAplicaDesconto
                         , NUMLOTE                    = vrDESCONTO.vNUMLOTE
                         , VALORCOTAMED               = vrDESCONTO.nVALORCOTAMED
                         , CODIGOINTEGRACAOWMS        = vrDESCONTO.vCODIGOINTEGRACAOWMS
                         , VLDESCCMVPROMOCAOMED       = vrDESCONTO.nVLDESCCMVPROMOCAOMED
                         , REGRAALTERARDESCONTO       = vrDESCONTO.nREGRAALTERARDESCONTO                         
                     WHERE (CODPROMOCAOMED                    = vnNovoCodPromocaoMed)
                       AND (NVL(CODEPTO,0)                    = NVL(vrDESCONTO.nCODEPTO,0))
                       AND (CODSEC                            = vrDESCONTO.nCODSEC)
                       AND (NVL(INICIOINTERVALOPROMOCAOMED,0) = NVL(vrDESCONTO.nINICIOINTERVALOPROMOCAOMED,0));
  
                  -- Excluir na PCDESCONTO o Desconto - EDTPRM
                  ELSIF (vrEditarPromocao.vvAcaoEditaSecao = 'E') THEN
  
                    DELETE FROM PCDESCONTO
                          WHERE (CODPROMOCAOMED                    = vnNovoCodPromocaoMed)
                            AND (NVL(CODEPTO,0)                    = NVL(vrDESCONTO.nCODEPTO,0))
                            AND (CODSEC                            = vrDESCONTO.nCODSEC)
                            AND (NVL(INICIOINTERVALOPROMOCAOMED,0) = NVL(vrDESCONTO.nINICIOINTERVALOPROMOCAOMED,0));
  
                  END IF; -- Fim Condição Tipo Ação da Edição da Seção

                  END LOOP; -- Fim Laço de Faixas
                END IF; -- Fim Condição se Gerou Faixas

              END IF; -- Fim Condição insere o Desconto da Seção

            END IF; -- Fim Condição se informou a Seção

          END LOOP; -- Fim Laço de Seções para Inclusão da Seção

        END LOOP; -- Fim Laço de Departamentos para Inclusao do Departamento e Seção

        -- Laço de Seções para Inclusão da Categoria
        FOR idxSecao IN vtPCMED_PROMOCAOSECAO.FIRST..vtPCMED_PROMOCAOSECAO.LAST LOOP

          -- Preenche variável com os valor do Array para atualização da PCDESCONTO
          vrDESCONTO.nCODSEC := vtPCMED_PROMOCAOSECAO(idxSecao).CODSEC;

          -- Laço de Categorias para Inclusão da Categoria
          FOR idxCateg IN vtPCMED_PROMOCAOCATEG.FIRST..vtPCMED_PROMOCAOCATEG.LAST LOOP

           -- Preenche variável com os valor do Array para atualização da PCDESCONTO
            vrDESCONTO.nCODCATEGORIA := vtPCMED_PROMOCAOCATEG(idxCateg).CODCATEGORIA;

            -- Se informou a Categoria
            IF (vrDESCONTO.nCODCATEGORIA IS NOT NULL) THEN

              -- Se informou a Seção,
              -- verifica se a Categoria pertence à Seção
              IF (vrDESCONTO.nCODSEC IS NOT NULL) THEN
                BEGIN
                  SELECT 'S'
                    INTO vvAchouCategDaSecao
                    FROM PCCATEGORIA
                   WHERE (CODCATEGORIA = vrDESCONTO.nCODCATEGORIA)
                     AND (CODSEC       = vrDESCONTO.nCODSEC);
                EXCEPTION
                  WHEN NO_DATA_FOUND THEN
                    vvAchouCategDaSecao := 'N';
                END;
              END IF;

              -- Se não informou a Seção ou
              -- Se informou a Seção e a Categoria pertence à Seção
              IF (vrDESCONTO.nCODSEC IS NULL) OR
                 ((vrDESCONTO.nCODSEC IS NOT NULL) AND (NVL(vvAchouCategDaSecao,'N') = 'S')) THEN

                -- De Política de Desconto ou Markup gera uma linha no Array com os dados da Categoria
                IF    (vvTipoPolitica IN ('D','M')) OR
                      (vvTipoPromocao IN ('N'))     THEN -- HIS.01889.2017 - Promoção de Campanha não tem Faixa de Qtde
                  vtPCMED_PROMOCAOCATEG_FAIXA(1).PERCDESC                 := vtPCMED_PROMOCAOCATEG(idxCateg).PERCDESC;
                  vtPCMED_PROMOCAOCATEG_FAIXA(1).PERCDESCFIN              := vtPCMED_PROMOCAOCATEG(idxCateg).PERCDESCFIN;
                  vtPCMED_PROMOCAOCATEG_FAIXA(1).PERCOMEXT                := vtPCMED_PROMOCAOCATEG(idxCateg).PERCOMEXT;
                  vtPCMED_PROMOCAOCATEG_FAIXA(1).PERCOMREP                := vtPCMED_PROMOCAOCATEG(idxCateg).PERCOMREP;
                  vtPCMED_PROMOCAOCATEG_FAIXA(1).PERCOMMINT               := vtPCMED_PROMOCAOCATEG(idxCateg).PERCOMMINT;
                  vtPCMED_PROMOCAOCATEG_FAIXA(1).INICIOINTERVALO          := NULL;
                  vtPCMED_PROMOCAOCATEG_FAIXA(1).FIMINTERVALO             := NULL;
                  vtPCMED_PROMOCAOCATEG_FAIXA(1).PARTICIPACOMISSGARANTIDA := vtPCMED_PROMOCAOCATEG(idxCateg).PARTICIPACOMISSGARANTIDA;
                  vtPCMED_PROMOCAOCATEG_FAIXA(1).PERCDESCBASERCA          := vtPCMED_PROMOCAOCATEG(idxCateg).PERCDESCBASERCA;
                  vtPCMED_PROMOCAOCATEG_FAIXA(1).REGRAALTERARDESCONTO     := vtPCMED_PROMOCAOCATEG(idxCateg).REGRAALTERARDESCONTO;
                -- De Desconto/BonifMerc por Quantidade por Quantidade Carrega Array as Faixas
                ELSIF (vvTipoPolitica IN ('Q','B','V')) THEN
                  SELECT *
                    BULK COLLECT INTO vtPCMED_PROMOCAOCATEG_FAIXA
                    FROM PCMED_PROMOCAOCATEG_FAIXA
                   WHERE (CODCATEGORIAREF = vrDESCONTO.nCODCATEGORIA);
                END IF;

                -- Se gerou as Faixas
                IF (vtPCMED_PROMOCAOCATEG_FAIXA.COUNT > 0) THEN
                  FOR idxCategFaixa IN vtPCMED_PROMOCAOCATEG_FAIXA.FIRST..vtPCMED_PROMOCAOCATEG_FAIXA.LAST LOOP

                    -- Pega Desconto informado na Categoria
                    IF (vvTipoPolitica IN ('B')) THEN -- Bonificação de Mercadoria
                      vrDESCONTO.nPERCBONIFICMERC          := vtPCMED_PROMOCAOCATEG_FAIXA(idxCategFaixa).PERCDESC;
                      vrDESCONTO.nPERCMARKUPMED            := NULL;
                      vrDESCONTO.nPERCDESC                 := 0;
                      vrDESCONTO.nPERCDESCFIN              := 0;
                    -- Pega Markup informado na Categoria
                    ELSIF (vvTipoPromocao IN ('R')) THEN -- Percentual de Markup
                      vrDESCONTO.nPERCBONIFICMERC          := NULL;
                      vrDESCONTO.nPERCMARKUPMED            := vtPCMED_PROMOCAOCATEG_FAIXA(idxCategFaixa).PERCDESC;
                      vrDESCONTO.nPERCDESC                 := 0;
                      vrDESCONTO.nPERCDESCFIN              := vtPCMED_PROMOCAOCATEG_FAIXA(idxCategFaixa).PERCDESCFIN;
                    ELSE
                      vrDESCONTO.nPERCBONIFICMERC          := NULL;
                      vrDESCONTO.nPERCMARKUPMED            := NULL;
                      vrDESCONTO.nPERCDESC                 := vtPCMED_PROMOCAOCATEG_FAIXA(idxCategFaixa).PERCDESC;
                      vrDESCONTO.nPERCDESCFIN              := vtPCMED_PROMOCAOCATEG_FAIXA(idxCategFaixa).PERCDESCFIN;
                    END IF;
                    -- Pega as Comissões informadas na Categoria
                    vrDESCONTO.nPERCOMEXT                  := vtPCMED_PROMOCAOCATEG_FAIXA(idxCategFaixa).PERCOMEXT;
                    vrDESCONTO.nPERCOMREP                  := vtPCMED_PROMOCAOCATEG_FAIXA(idxCategFaixa).PERCOMREP;
                    vrDESCONTO.nPERCOMMINT                 := vtPCMED_PROMOCAOCATEG_FAIXA(idxCategFaixa).PERCOMMINT;
                    -- Pega as Faixas de Quantidade na Categoria
                    vrDESCONTO.nINICIOINTERVALOPROMOCAOMED := vtPCMED_PROMOCAOCATEG_FAIXA(idxCategFaixa).INICIOINTERVALO;
                    vrDESCONTO.nFIMINTERVALOPROMOCAOMED    := vtPCMED_PROMOCAOCATEG_FAIXA(idxCategFaixa).FIMINTERVALO;
                    -- Não Altera Preço de Tabela
                    vrDESCONTO.vALTERAPTABELA              := 'N';
                    -- Participa da Comissão Garantida
                    vrDESCONTO.vPARTICIPACOMISSGARANTIDA   := F_PARTICIPACOMISSGARANTIDA(vtPCMED_PROMOCAOCATEG_FAIXA(idxCategFaixa).PARTICIPACOMISSGARANTIDA);
                    -- Desconto C/C
                    vrDESCONTO.nPERCDESCBASERCA            := vtPCMED_PROMOCAOCATEG_FAIXA(idxCategFaixa).PERCDESCBASERCA;
                    -- Regra de alteração do Desconto/Preço
                    vrDESCONTO.nREGRAALTERARDESCONTO       := vtPCMED_PROMOCAOCATEG_FAIXA(idxCategFaixa).REGRAALTERARDESCONTO;
    
                    -----------------------------------------------------------------------
                    -- AÇÃO INCLUSÃO/ALTERAÇÃO/EXCLUSÃO DO DESCONTO POR CATEGORIA - EDTPRM
                    -----------------------------------------------------------------------
                    vrEditarPromocao.vvAcaoEditaCategoria := F_DEFINE_ACAO_EDICAO(NVL(vrEditarPromocao.vvPermiteEditarProduto,'N'),
                                                                                  'ct',
                                                                                  vrDESCONTO.nCODCATEGORIA,
                                                                                  vrDESCONTO.nINICIOINTERVALOPROMOCAOMED,
                                                                                  vvTipoPromocao, NULL);

                    --------------------------------------------
                    -- INCLUSÃO/ALTERAÇÃO/EXCLUSÃO DA CATEGORIA
                    --------------------------------------------

                    -- Insere na PCDESCONTO o Desconto da Categoria
                    IF    (vrEditarPromocao.vvAcaoEditaCategoria = 'I') THEN

                    -- Insere na PCDESCONTO o Desconto da Categoria
                    vnNovoCodDesconto := FOBTEM_PROX_CODDESCONTO;
                    INSERT INTO PCDESCONTO
                              ( CODDESCONTO
                              , CODPROMOCAOMED
                              , DTINICIO
                              , DTFIM
                              , APLICADESCONTO
                              , TIPO
                              , BASECREDDEBRCA
                              , CREDITASOBREPOLITICA
                              , CONSIDERACALCGIROMEDIC
                              , UTILIZADESCREDE
                              , APENASPLPAGMAX
                              --
                              , CODFUNCLANC
                              , DATALANC
                              , CODFUNCULTALTER
                              , DATAULTALTER
                              , ALTERAPTABELA
                              , PRIORITARIA
                              , QUESTIONAUSOPRIORITARIA
                              , APLICADESCSIMPLESNACIONAL
                              , PRIORITARIAGERAL
                              --
                              , PERCDESC
                              , PERCDESCFIN
                              --
                              , ORIGEMPED
                              , TIPOFV
                              , CODFILIAL
                              , NUMREGIAO
                              , CODPRACA
                              , CODATIV
                              , CLASSEVENDA
                              , CODPLPAG
                              , CODCONDICAOVENDA
                              , CODREDE
                              , CODCLI
                              , AREAATUACAO
                              , CODSUPERVISOR
                              , CODUSUR
                              , CODSEC
                              , CODCATEGORIA
                              --
                              , PERCOMEXT
                              , PERCOMREP
                              , PERCOMMINT
                              , TIPOPOLITICAPROMOCAOMED
                              , INICIOINTERVALOPROMOCAOMED
                              , FIMINTERVALOPROMOCAOMED
                              , PARTICIPACOMISSGARANTIDA
                              , PERCDESCBASERCA
                              , PERCBONIFICMERC
                              , PERCMARKUPMED
                              --
                              , TIPOVENDA
                              , REGRAALTERARDESCONTO
                              )
                       VALUES ( vnNovoCodDesconto
                              , vnNovoCodPromocaoMed -->> Novo Sequencial de Promoção
                              , vdDataInicial
                              , vdDataFinal
                              , vvAplicaDesconto --> HIS.02032.2017 - Flag 'Aplicar desconto automaticamente'
                              , 'C' -- Comercial
                              , vvBaseCredDebRca
                              , vvCreditaSobrePolitica
                              , vvConsideraCalcGiroMedic
                              , vvUtilizaDescRede
                              , vvApenasPlPagMax
                              --
                              , pi_nCodFunc
                              , SYSDATE
                              , pi_nCodFunc
                              , TRUNC(SYSDATE)
                              , vrDESCONTO.vALTERAPTABELA
                              , 'N'
                              , 'N'
                              , vvAplicaDescSimplesNacional
                              , 'N'
                              --
                              , vrDESCONTO.nPERCDESC
                              , vrDESCONTO.nPERCDESCFIN
                              --
                              , vrDESCONTO.vORIGEMPED
                              , vrDESCONTO.vTIPOFV
                              , vrDESCONTO.vCODFILIAL
                              , vrDESCONTO.nNUMREGIAO
                              , vrDESCONTO.nCODPRACA
                              , vrDESCONTO.nCODATIV
                              , vrDESCONTO.vCLASSEVENDA
                              , vrDESCONTO.nCODPLPAG
                              , vrDESCONTO.nCODCONDICAOVENDA
                              , vrDESCONTO.nCODREDE
                              , vrDESCONTO.nCODCLI
                              , vrDESCONTO.vAREAATUACAO
                              , vrDESCONTO.nCODSUPERVISOR
                              , vrDESCONTO.nCODUSUR
                              , vrDESCONTO.nCODSEC
                              , vrDESCONTO.nCODCATEGORIA
                              --
                              , vrDESCONTO.nPERCOMEXT
                              , vrDESCONTO.nPERCOMREP
                              , vrDESCONTO.nPERCOMMINT
                              , vvTipoPolitica
                              , vrDESCONTO.nINICIOINTERVALOPROMOCAOMED
                              , vrDESCONTO.nFIMINTERVALOPROMOCAOMED
                              , vrDESCONTO.vPARTICIPACOMISSGARANTIDA
                              , vrDESCONTO.nPERCDESCBASERCA
                              , vrDESCONTO.nPERCBONIFICMERC
                              , vrDESCONTO.nPERCMARKUPMED
                              --
                              , vrDESCONTO.vTIPOVENDA
                              , vrDESCONTO.nREGRAALTERARDESCONTO
                              );

                  -- Altera na PCDESCONTO o Desconto da Categoria - EDTPRM
                  ELSIF (vrEditarPromocao.vvAcaoEditaCategoria = 'A') THEN
  
                    UPDATE PCDESCONTO
                       SET DTINICIO                   = vdDataInicial
                         , DTFIM                      = vdDataFinal
                         , BASECREDDEBRCA             = vvBaseCredDebRca
                         , CREDITASOBREPOLITICA       = vvCreditaSobrePolitica
                         , CONSIDERACALCGIROMEDIC     = vvConsideraCalcGiroMedic
                         --
                         , PERCDESC                   = vrDESCONTO.nPERCDESC
                         , PERCDESCFIN                = vrDESCONTO.nPERCDESCFIN
                         , PERCOMEXT                  = vrDESCONTO.nPERCOMEXT
                         , PERCOMREP                  = vrDESCONTO.nPERCOMREP
                         , PERCOMMINT                 = vrDESCONTO.nPERCOMMINT
                         , TIPOPOLITICAPROMOCAOMED    = vvTipoPolitica
                         , PROMOCAOMEDOBRIGATORIO     = vvObrigatorio
                         , INICIOINTERVALOPROMOCAOMED = vrDESCONTO.nINICIOINTERVALOPROMOCAOMED
                         , FIMINTERVALOPROMOCAOMED    = vrDESCONTO.nFIMINTERVALOPROMOCAOMED
                         , PRECOFIXOPROMOCAOMED       = vrDESCONTO.nPRECOFIXOPROMOCAOMED
                         , PARTICIPACOMISSGARANTIDA   = vrDESCONTO.vPARTICIPACOMISSGARANTIDA
                         , PERCDESCBASERCA            = vrDESCONTO.nPERCDESCBASERCA
                         , PERCBONIFICMERC            = vrDESCONTO.nPERCBONIFICMERC
                         , PERCMARKUPMED              = vrDESCONTO.nPERCMARKUPMED
                         , APLICADESCONTO             = vvAplicaDesconto
                         , NUMLOTE                    = vrDESCONTO.vNUMLOTE
                         , VALORCOTAMED               = vrDESCONTO.nVALORCOTAMED
                         , CODIGOINTEGRACAOWMS        = vrDESCONTO.vCODIGOINTEGRACAOWMS
                         , VLDESCCMVPROMOCAOMED       = vrDESCONTO.nVLDESCCMVPROMOCAOMED
                         , REGRAALTERARDESCONTO       = vrDESCONTO.nREGRAALTERARDESCONTO
                     WHERE (CODPROMOCAOMED                    = vnNovoCodPromocaoMed)
                       AND (NVL(CODSEC,0)                     = NVL(vrDESCONTO.nCODSEC,0))
                       AND (CODCATEGORIA                      = vrDESCONTO.nCODCATEGORIA)
                       AND (NVL(INICIOINTERVALOPROMOCAOMED,0) = NVL(vrDESCONTO.nINICIOINTERVALOPROMOCAOMED,0));
  
                  -- Excluir na PCDESCONTO o Desconto - EDTPRM
                  ELSIF (vrEditarPromocao.vvAcaoEditaCategoria = 'E') THEN
  
                    DELETE FROM PCDESCONTO
                          WHERE (CODPROMOCAOMED                    = vnNovoCodPromocaoMed)
                            AND (NVL(CODSEC,0)                     = NVL(vrDESCONTO.nCODSEC,0))
                            AND (CODCATEGORIA                      = vrDESCONTO.nCODCATEGORIA)
                            AND (NVL(INICIOINTERVALOPROMOCAOMED,0) = NVL(vrDESCONTO.nINICIOINTERVALOPROMOCAOMED,0));
  
                  END IF; -- Fim Condição Tipo Ação da Edição da Categoria

                  END LOOP; -- Fim Laço de Faixas
                END IF; -- Fim Condição se Gerou Faixas

              END IF; -- Fim Condição insere o Desconto da Categoria

            END IF; -- Fim Condição se informou a Categoria

          END LOOP; -- Fim Laço de Categorias para Inclusão da Categoria

        END LOOP; -- Fim Laço de Seções para Inclusão da Categoria

        -- Laço de Fornecedores
        IF (vtPCMED_PROMOCAOFORNEC.COUNT > 0) THEN
          FOR idxFornec IN vtPCMED_PROMOCAOFORNEC.FIRST..vtPCMED_PROMOCAOFORNEC.LAST LOOP

            -- Preenche variável com os valor do Array para atualização da PCDESCONTO
            vrDESCONTO.nCODFORNEC := vtPCMED_PROMOCAOFORNEC(idxFornec).CODFORNEC;

            -- De Política de Desconto ou Markup gera uma linha no Array com os dados do Fornecedor
            IF    (vvTipoPolitica IN ('D','M')) OR
                  (vvTipoPromocao IN ('N'))     THEN -- HIS.01889.2017 - Promoção de Campanha não tem Faixa de Qtde
              vtPCMED_PROMOCAOFORNEC_FAIXA(1).PERCDESC                 := vtPCMED_PROMOCAOFORNEC(idxFornec).PERCDESC;
              vtPCMED_PROMOCAOFORNEC_FAIXA(1).PERCDESCFIN              := vtPCMED_PROMOCAOFORNEC(idxFornec).PERCDESCFIN;
              vtPCMED_PROMOCAOFORNEC_FAIXA(1).PERCOMEXT                := vtPCMED_PROMOCAOFORNEC(idxFornec).PERCOMEXT;
              vtPCMED_PROMOCAOFORNEC_FAIXA(1).PERCOMREP                := vtPCMED_PROMOCAOFORNEC(idxFornec).PERCOMREP;
              vtPCMED_PROMOCAOFORNEC_FAIXA(1).PERCOMMINT               := vtPCMED_PROMOCAOFORNEC(idxFornec).PERCOMMINT;
              vtPCMED_PROMOCAOFORNEC_FAIXA(1).INICIOINTERVALO          := NULL;
              vtPCMED_PROMOCAOFORNEC_FAIXA(1).FIMINTERVALO             := NULL;
              vtPCMED_PROMOCAOFORNEC_FAIXA(1).PARTICIPACOMISSGARANTIDA := vtPCMED_PROMOCAOFORNEC(idxFornec).PARTICIPACOMISSGARANTIDA;
              vtPCMED_PROMOCAOFORNEC_FAIXA(1).PERCDESCBASERCA          := vtPCMED_PROMOCAOFORNEC(idxFornec).PERCDESCBASERCA;
              vtPCMED_PROMOCAOFORNEC_FAIXA(1).REGRAALTERARDESCONTO     := vtPCMED_PROMOCAOFORNEC(idxFornec).REGRAALTERARDESCONTO;
            -- De Desconto/BonifMerc por Quantidade por Quantidade Carrega Array as Faixas
            ELSIF (vvTipoPolitica IN ('Q','B','V')) THEN
              SELECT *
                BULK COLLECT INTO vtPCMED_PROMOCAOFORNEC_FAIXA
                FROM PCMED_PROMOCAOFORNEC_FAIXA
               WHERE (CODFORNECREF = vrDESCONTO.nCODFORNEC);
            END IF;

            -- Se gerou as Faixas
            IF (vtPCMED_PROMOCAOFORNEC_FAIXA.COUNT > 0) THEN
              FOR idxFornecFaixa IN vtPCMED_PROMOCAOFORNEC_FAIXA.FIRST..vtPCMED_PROMOCAOFORNEC_FAIXA.LAST LOOP

                -- Pega Desconto informado no Fornecedor
                IF (vvTipoPolitica IN ('B')) THEN -- Bonificação de Mercadoria
                  vrDESCONTO.nPERCBONIFICMERC          := vtPCMED_PROMOCAOFORNEC_FAIXA(idxFornecFaixa).PERCDESC;
                  vrDESCONTO.nPERCMARKUPMED            := NULL;
                  vrDESCONTO.nPERCDESC                 := 0;
                  vrDESCONTO.nPERCDESCFIN              := 0;
                -- Pega Markup informado no Fornecedor
                ELSIF (vvTipoPromocao IN ('R')) THEN -- Percentual de Markup
                  vrDESCONTO.nPERCBONIFICMERC          := NULL;
                  vrDESCONTO.nPERCMARKUPMED            := vtPCMED_PROMOCAOFORNEC_FAIXA(idxFornecFaixa).PERCDESC;
                  vrDESCONTO.nPERCDESC                 := 0;
                  vrDESCONTO.nPERCDESCFIN              := vtPCMED_PROMOCAOFORNEC_FAIXA(idxFornecFaixa).PERCDESCFIN;
                ELSE
                  vrDESCONTO.nPERCBONIFICMERC          := NULL;
                  vrDESCONTO.nPERCMARKUPMED            := NULL;
                  vrDESCONTO.nPERCDESC                 := vtPCMED_PROMOCAOFORNEC_FAIXA(idxFornecFaixa).PERCDESC;
                  vrDESCONTO.nPERCDESCFIN              := vtPCMED_PROMOCAOFORNEC_FAIXA(idxFornecFaixa).PERCDESCFIN;
                END IF;
                -- Pega as Comissões informadas no Fornecedor
                vrDESCONTO.nPERCOMEXT                  := vtPCMED_PROMOCAOFORNEC_FAIXA(idxFornecFaixa).PERCOMEXT;
                vrDESCONTO.nPERCOMREP                  := vtPCMED_PROMOCAOFORNEC_FAIXA(idxFornecFaixa).PERCOMREP;
                vrDESCONTO.nPERCOMMINT                 := vtPCMED_PROMOCAOFORNEC_FAIXA(idxFornecFaixa).PERCOMMINT;
                -- Pega as Faixas de Quantidade no Fornecedor
                vrDESCONTO.nINICIOINTERVALOPROMOCAOMED := vtPCMED_PROMOCAOFORNEC_FAIXA(idxFornecFaixa).INICIOINTERVALO;
                vrDESCONTO.nFIMINTERVALOPROMOCAOMED    := vtPCMED_PROMOCAOFORNEC_FAIXA(idxFornecFaixa).FIMINTERVALO;
                -- Não Altera Preço de Tabela
                vrDESCONTO.vALTERAPTABELA              := 'N';
                -- Participa da Comissão Garantida
                vrDESCONTO.vPARTICIPACOMISSGARANTIDA   := F_PARTICIPACOMISSGARANTIDA(vtPCMED_PROMOCAOFORNEC_FAIXA(idxFornecFaixa).PARTICIPACOMISSGARANTIDA);
                -- Desconto C/C
                vrDESCONTO.nPERCDESCBASERCA            := vtPCMED_PROMOCAOFORNEC_FAIXA(idxFornecFaixa).PERCDESCBASERCA;
                -- Regra de alteração do Desconto/Preço
                vrDESCONTO.nREGRAALTERARDESCONTO       := vtPCMED_PROMOCAOFORNEC_FAIXA(idxFornecFaixa).REGRAALTERARDESCONTO;

                -----------------------------------------------------------------------
                -- AÇÃO INCLUSÃO/ALTERAÇÃO/EXCLUSÃO DO DESCONTO POR FORNECEDOR - EDTPRM
                -----------------------------------------------------------------------
                vrEditarPromocao.vvAcaoEditaFornecedor := F_DEFINE_ACAO_EDICAO(NVL(vrEditarPromocao.vvPermiteEditarProduto,'N'),
                                                                               'fr',
                                                                               vrDESCONTO.nCODFORNEC,
                                                                               vrDESCONTO.nINICIOINTERVALOPROMOCAOMED,
                                                                               vvTipoPromocao, NULL);

                --------------------------------------------
                -- INCLUSÃO/ALTERAÇÃO/EXCLUSÃO DO FORNECEDOR
                --------------------------------------------

                -- Insere na PCDESCONTO o Desconto do Fornecedor
                IF    (vrEditarPromocao.vvAcaoEditaFornecedor = 'I') THEN

                -- Insere na PCDESCONTO o Desconto do Fornecedor
                vnNovoCodDesconto := FOBTEM_PROX_CODDESCONTO;
                INSERT INTO PCDESCONTO
                          ( CODDESCONTO
                          , CODPROMOCAOMED
                          , DTINICIO
                          , DTFIM
                          , APLICADESCONTO
                          , TIPO
                          , BASECREDDEBRCA
                          , CREDITASOBREPOLITICA
                          , CONSIDERACALCGIROMEDIC
                          , UTILIZADESCREDE
                          , APENASPLPAGMAX
                          --
                          , CODFUNCLANC
                          , DATALANC
                          , CODFUNCULTALTER
                          , DATAULTALTER
                          , ALTERAPTABELA
                          , PRIORITARIA
                          , QUESTIONAUSOPRIORITARIA
                          , APLICADESCSIMPLESNACIONAL
                          , PRIORITARIAGERAL
                          --
                          , PERCDESC
                          , PERCDESCFIN
                          --
                          , ORIGEMPED
                          , TIPOFV
                          , CODFILIAL
                          , NUMREGIAO
                          , CODPRACA
                          , CODATIV
                          , CLASSEVENDA
                          , CODPLPAG
                          , CODCONDICAOVENDA
                          , CODREDE
                          , CODCLI
                          , AREAATUACAO
                          , CODSUPERVISOR
                          , CODUSUR
                          , CODFORNEC
                          --
                          , PERCOMEXT
                          , PERCOMREP
                          , PERCOMMINT
                          , TIPOPOLITICAPROMOCAOMED
                          , INICIOINTERVALOPROMOCAOMED
                          , FIMINTERVALOPROMOCAOMED
                          , PARTICIPACOMISSGARANTIDA
                          , PERCDESCBASERCA
                          , PERCBONIFICMERC
                          , PERCMARKUPMED
                          --
                          , TIPOVENDA
                          , REGRAALTERARDESCONTO
                          )
                   VALUES ( vnNovoCodDesconto
                          , vnNovoCodPromocaoMed -->> Novo Sequencial de Promoção
                          , vdDataInicial
                          , vdDataFinal
                          , vvAplicaDesconto --> HIS.02032.2017 - Flag 'Aplicar desconto automaticamente'
                          , 'C' -- Comercial
                          , vvBaseCredDebRca
                          , vvCreditaSobrePolitica
                          , vvConsideraCalcGiroMedic
                          , vvUtilizaDescRede
                          , vvApenasPlPagMax
                          --
                          , pi_nCodFunc
                          , SYSDATE
                          , pi_nCodFunc
                          , TRUNC(SYSDATE)
                          , vrDESCONTO.vALTERAPTABELA
                          , 'N'
                          , 'N'
                          , vvAplicaDescSimplesNacional
                          , 'N'
                          --
                          , vrDESCONTO.nPERCDESC
                          , vrDESCONTO.nPERCDESCFIN
                          --
                          , vrDESCONTO.vORIGEMPED
                          , vrDESCONTO.vTIPOFV
                          , vrDESCONTO.vCODFILIAL
                          , vrDESCONTO.nNUMREGIAO
                          , vrDESCONTO.nCODPRACA
                          , vrDESCONTO.nCODATIV
                          , vrDESCONTO.vCLASSEVENDA
                          , vrDESCONTO.nCODPLPAG
                          , vrDESCONTO.nCODCONDICAOVENDA
                          , vrDESCONTO.nCODREDE
                          , vrDESCONTO.nCODCLI
                          , vrDESCONTO.vAREAATUACAO
                          , vrDESCONTO.nCODSUPERVISOR
                          , vrDESCONTO.nCODUSUR
                          , vrDESCONTO.nCODFORNEC
                          --
                          , vrDESCONTO.nPERCOMEXT
                          , vrDESCONTO.nPERCOMREP
                          , vrDESCONTO.nPERCOMMINT
                          , vvTipoPolitica
                          , vrDESCONTO.nINICIOINTERVALOPROMOCAOMED
                          , vrDESCONTO.nFIMINTERVALOPROMOCAOMED
                          , vrDESCONTO.vPARTICIPACOMISSGARANTIDA
                          , vrDESCONTO.nPERCDESCBASERCA
                          , vrDESCONTO.nPERCBONIFICMERC
                          , vrDESCONTO.nPERCMARKUPMED
                          --
                          , vrDESCONTO.vTIPOVENDA
                          , vrDESCONTO.nREGRAALTERARDESCONTO
                          );

                -- Altera na PCDESCONTO o Desconto do Fornecedor - EDTPRM
                ELSIF (vrEditarPromocao.vvAcaoEditaFornecedor = 'A') THEN

                  UPDATE PCDESCONTO
                     SET DTINICIO                   = vdDataInicial
                       , DTFIM                      = vdDataFinal
                       , BASECREDDEBRCA             = vvBaseCredDebRca
                       , CREDITASOBREPOLITICA       = vvCreditaSobrePolitica
                       , CONSIDERACALCGIROMEDIC     = vvConsideraCalcGiroMedic
                       --
                       , PERCDESC                   = vrDESCONTO.nPERCDESC
                       , PERCDESCFIN                = vrDESCONTO.nPERCDESCFIN
                       , PERCOMEXT                  = vrDESCONTO.nPERCOMEXT
                       , PERCOMREP                  = vrDESCONTO.nPERCOMREP
                       , PERCOMMINT                 = vrDESCONTO.nPERCOMMINT
                       , TIPOPOLITICAPROMOCAOMED    = vvTipoPolitica
                       , PROMOCAOMEDOBRIGATORIO     = vvObrigatorio
                       , INICIOINTERVALOPROMOCAOMED = vrDESCONTO.nINICIOINTERVALOPROMOCAOMED
                       , FIMINTERVALOPROMOCAOMED    = vrDESCONTO.nFIMINTERVALOPROMOCAOMED
                       , PRECOFIXOPROMOCAOMED       = vrDESCONTO.nPRECOFIXOPROMOCAOMED
                       , PARTICIPACOMISSGARANTIDA   = vrDESCONTO.vPARTICIPACOMISSGARANTIDA
                       , PERCDESCBASERCA            = vrDESCONTO.nPERCDESCBASERCA
                       , PERCBONIFICMERC            = vrDESCONTO.nPERCBONIFICMERC
                       , PERCMARKUPMED              = vrDESCONTO.nPERCMARKUPMED
                       , APLICADESCONTO             = vvAplicaDesconto
                       , NUMLOTE                    = vrDESCONTO.vNUMLOTE
                       , VALORCOTAMED               = vrDESCONTO.nVALORCOTAMED
                       , CODIGOINTEGRACAOWMS        = vrDESCONTO.vCODIGOINTEGRACAOWMS
                       , VLDESCCMVPROMOCAOMED       = vrDESCONTO.nVLDESCCMVPROMOCAOMED
                       , REGRAALTERARDESCONTO       = vrDESCONTO.nREGRAALTERARDESCONTO
                   WHERE (CODPROMOCAOMED                    = vnNovoCodPromocaoMed)
                     AND (CODFORNEC                         = vrDESCONTO.nCODFORNEC)
                     AND (NVL(INICIOINTERVALOPROMOCAOMED,0) = NVL(vrDESCONTO.nINICIOINTERVALOPROMOCAOMED,0));

                -- Excluir na PCDESCONTO o Desconto - EDTPRM
                ELSIF (vrEditarPromocao.vvAcaoEditaFornecedor = 'E') THEN

                  DELETE FROM PCDESCONTO
                        WHERE (CODPROMOCAOMED                    = vnNovoCodPromocaoMed)
                          AND (CODFORNEC                         = vrDESCONTO.nCODFORNEC)
                          AND (NVL(INICIOINTERVALOPROMOCAOMED,0) = NVL(vrDESCONTO.nINICIOINTERVALOPROMOCAOMED,0));

                END IF; -- Fim Condição Tipo Ação da Edição do Fornecedor

              END LOOP; -- Fim Laço de Faixas
            END IF; -- Fim Condição se Gerou Faixas

          END LOOP; -- Fim Laço de Fornecedores
        END IF;

        -- Laço de Marcas
        IF (vtPCMED_PROMOCAOMARCA.COUNT > 0) THEN
          FOR idxMarca IN vtPCMED_PROMOCAOMARCA.FIRST..vtPCMED_PROMOCAOMARCA.LAST LOOP

            -- Preenche variável com os valor do Array para atualização da PCDESCONTO
            vrDESCONTO.nCODMARCA := vtPCMED_PROMOCAOMARCA(idxMarca).CODMARCA;

            -- De Política de Desconto ou Markup gera uma linha no Array com os dados da Marca
            IF    (vvTipoPolitica IN ('D','M')) OR
                  (vvTipoPromocao IN ('N'))     THEN -- HIS.01889.2017 - Promoção de Campanha não tem Faixa de Qtde
              vtPCMED_PROMOCAOMARCA_FAIXA(1).PERCDESC                 := vtPCMED_PROMOCAOMARCA(idxMarca).PERCDESC;
              vtPCMED_PROMOCAOMARCA_FAIXA(1).PERCDESCFIN              := vtPCMED_PROMOCAOMARCA(idxMarca).PERCDESCFIN;
              vtPCMED_PROMOCAOMARCA_FAIXA(1).PERCOMEXT                := vtPCMED_PROMOCAOMARCA(idxMarca).PERCOMEXT;
              vtPCMED_PROMOCAOMARCA_FAIXA(1).PERCOMREP                := vtPCMED_PROMOCAOMARCA(idxMarca).PERCOMREP;
              vtPCMED_PROMOCAOMARCA_FAIXA(1).PERCOMMINT               := vtPCMED_PROMOCAOMARCA(idxMarca).PERCOMMINT;
              vtPCMED_PROMOCAOMARCA_FAIXA(1).INICIOINTERVALO          := NULL;
              vtPCMED_PROMOCAOMARCA_FAIXA(1).FIMINTERVALO             := NULL;
              vtPCMED_PROMOCAOMARCA_FAIXA(1).PARTICIPACOMISSGARANTIDA := vtPCMED_PROMOCAOMARCA(idxMarca).PARTICIPACOMISSGARANTIDA;
              vtPCMED_PROMOCAOMARCA_FAIXA(1).PERCDESCBASERCA          := vtPCMED_PROMOCAOMARCA(idxMarca).PERCDESCBASERCA;
              vtPCMED_PROMOCAOMARCA_FAIXA(1).REGRAALTERARDESCONTO     := vtPCMED_PROMOCAOMARCA(idxMarca).REGRAALTERARDESCONTO;
            -- De Desconto/BonifMerc por Quantidade por Quantidade Carrega Array as Faixas
            ELSIF (vvTipoPolitica IN ('Q','B','V')) THEN
              SELECT *
                BULK COLLECT INTO vtPCMED_PROMOCAOMARCA_FAIXA
                FROM PCMED_PROMOCAOMARCA_FAIXA
               WHERE (CODMARCAREF = vrDESCONTO.nCODMARCA);
            END IF;

            -- Se gerou as Faixas
            IF (vtPCMED_PROMOCAOMARCA_FAIXA.COUNT > 0) THEN
              FOR idxMarcaFaixa IN vtPCMED_PROMOCAOMARCA_FAIXA.FIRST..vtPCMED_PROMOCAOMARCA_FAIXA.LAST LOOP

                -- Pega Desconto informado na Marca
                IF (vvTipoPolitica IN ('B')) THEN -- Bonificação de Mercadoria
                  vrDESCONTO.nPERCBONIFICMERC          := vtPCMED_PROMOCAOMARCA_FAIXA(idxMarcaFaixa).PERCDESC;
                  vrDESCONTO.nPERCMARKUPMED            := NULL;
                  vrDESCONTO.nPERCDESC                 := 0;
                  vrDESCONTO.nPERCDESCFIN              := 0;
                -- Pega Markup informado na Marca
                ELSIF (vvTipoPromocao IN ('R')) THEN -- Percentual de Markup
                  vrDESCONTO.nPERCBONIFICMERC          := NULL;
                  vrDESCONTO.nPERCMARKUPMED            := vtPCMED_PROMOCAOMARCA_FAIXA(idxMarcaFaixa).PERCDESC;
                  vrDESCONTO.nPERCDESC                 := 0;
                  vrDESCONTO.nPERCDESCFIN              := vtPCMED_PROMOCAOMARCA_FAIXA(idxMarcaFaixa).PERCDESCFIN;
                ELSE
                  vrDESCONTO.nPERCBONIFICMERC          := NULL;
                  vrDESCONTO.nPERCMARKUPMED            := NULL;
                  vrDESCONTO.nPERCDESC                 := vtPCMED_PROMOCAOMARCA_FAIXA(idxMarcaFaixa).PERCDESC;
                  vrDESCONTO.nPERCDESCFIN              := vtPCMED_PROMOCAOMARCA_FAIXA(idxMarcaFaixa).PERCDESCFIN;
                END IF;
                -- Pega as Comissões informadas na Marca
                vrDESCONTO.nPERCOMEXT                  := vtPCMED_PROMOCAOMARCA_FAIXA(idxMarcaFaixa).PERCOMEXT;
                vrDESCONTO.nPERCOMREP                  := vtPCMED_PROMOCAOMARCA_FAIXA(idxMarcaFaixa).PERCOMREP;
                vrDESCONTO.nPERCOMMINT                 := vtPCMED_PROMOCAOMARCA_FAIXA(idxMarcaFaixa).PERCOMMINT;
                -- Pega as Faixas de Quantidade na Marca
                vrDESCONTO.nINICIOINTERVALOPROMOCAOMED := vtPCMED_PROMOCAOMARCA_FAIXA(idxMarcaFaixa).INICIOINTERVALO;
                vrDESCONTO.nFIMINTERVALOPROMOCAOMED    := vtPCMED_PROMOCAOMARCA_FAIXA(idxMarcaFaixa).FIMINTERVALO;
                -- Não Altera Preço de Tabela
                vrDESCONTO.vALTERAPTABELA              := 'N';
                -- Participa da Comissão Garantida
                vrDESCONTO.vPARTICIPACOMISSGARANTIDA   := F_PARTICIPACOMISSGARANTIDA(vtPCMED_PROMOCAOMARCA_FAIXA(idxMarcaFaixa).PARTICIPACOMISSGARANTIDA);
                -- Desconto C/C
                vrDESCONTO.nPERCDESCBASERCA            := vtPCMED_PROMOCAOMARCA_FAIXA(idxMarcaFaixa).PERCDESCBASERCA;
                -- Regra de alteração do Desconto/Preço
                vrDESCONTO.nREGRAALTERARDESCONTO       := vtPCMED_PROMOCAOMARCA_FAIXA(idxMarcaFaixa).REGRAALTERARDESCONTO;

                -----------------------------------------------------------------------
                -- AÇÃO INCLUSÃO/ALTERAÇÃO/EXCLUSÃO DO DESCONTO POR MARCA - EDTPRM
                -----------------------------------------------------------------------
                vrEditarPromocao.vvAcaoEditaMarca := F_DEFINE_ACAO_EDICAO(NVL(vrEditarPromocao.vvPermiteEditarProduto,'N'),
                                                                          'ma',
                                                                          vrDESCONTO.nCODMARCA,
                                                                          vrDESCONTO.nINICIOINTERVALOPROMOCAOMED,
                                                                          vvTipoPromocao, NULL);

                ---------------------------------------
                -- INCLUSÃO/ALTERAÇÃO/EXCLUSÃO DA MARCA
                ---------------------------------------

                -- Insere na PCDESCONTO o Desconto da Marca
                IF    (vrEditarPromocao.vvAcaoEditaMarca = 'I') THEN

                -- Insere na PCDESCONTO o Desconto da Marca
                vnNovoCodDesconto := FOBTEM_PROX_CODDESCONTO;
                INSERT INTO PCDESCONTO
                          ( CODDESCONTO
                          , CODPROMOCAOMED
                          , DTINICIO
                          , DTFIM
                          , APLICADESCONTO
                          , TIPO
                          , BASECREDDEBRCA
                          , CREDITASOBREPOLITICA
                          , CONSIDERACALCGIROMEDIC
                          , UTILIZADESCREDE
                          , APENASPLPAGMAX
                          --
                          , CODFUNCLANC
                          , DATALANC
                          , CODFUNCULTALTER
                          , DATAULTALTER
                          , ALTERAPTABELA
                          , PRIORITARIA
                          , QUESTIONAUSOPRIORITARIA
                          , APLICADESCSIMPLESNACIONAL
                          , PRIORITARIAGERAL
                          --
                          , PERCDESC
                          , PERCDESCFIN
                          --
                          , ORIGEMPED
                          , TIPOFV
                          , CODFILIAL
                          , NUMREGIAO
                          , CODPRACA
                          , CODATIV
                          , CLASSEVENDA
                          , CODPLPAG
                          , CODCONDICAOVENDA
                          , CODREDE
                          , CODCLI
                          , AREAATUACAO
                          , CODSUPERVISOR
                          , CODUSUR
                          , CODMARCA
                          --
                          , PERCOMEXT
                          , PERCOMREP
                          , PERCOMMINT
                          , TIPOPOLITICAPROMOCAOMED
                          , INICIOINTERVALOPROMOCAOMED
                          , FIMINTERVALOPROMOCAOMED
                          , PARTICIPACOMISSGARANTIDA
                          , PERCDESCBASERCA
                          , PERCBONIFICMERC
                          , PERCMARKUPMED
                          --
                          , TIPOVENDA
                          , REGRAALTERARDESCONTO
                          )
                   VALUES ( vnNovoCodDesconto
                          , vnNovoCodPromocaoMed -->> Novo Sequencial de Promoção
                          , vdDataInicial
                          , vdDataFinal
                          , vvAplicaDesconto --> HIS.02032.2017 - Flag 'Aplicar desconto automaticamente'
                          , 'C' -- Comercial
                          , vvBaseCredDebRca
                          , vvCreditaSobrePolitica
                          , vvConsideraCalcGiroMedic
                          , vvUtilizaDescRede
                          , vvApenasPlPagMax
                          --
                          , pi_nCodFunc
                          , SYSDATE
                          , pi_nCodFunc
                          , TRUNC(SYSDATE)
                          , vrDESCONTO.vALTERAPTABELA
                          , 'N'
                          , 'N'
                          , vvAplicaDescSimplesNacional
                          , 'N'
                          --
                          , vrDESCONTO.nPERCDESC
                          , vrDESCONTO.nPERCDESCFIN
                          --
                          , vrDESCONTO.vORIGEMPED
                          , vrDESCONTO.vTIPOFV
                          , vrDESCONTO.vCODFILIAL
                          , vrDESCONTO.nNUMREGIAO
                          , vrDESCONTO.nCODPRACA
                          , vrDESCONTO.nCODATIV
                          , vrDESCONTO.vCLASSEVENDA
                          , vrDESCONTO.nCODPLPAG
                          , vrDESCONTO.nCODCONDICAOVENDA
                          , vrDESCONTO.nCODREDE
                          , vrDESCONTO.nCODCLI
                          , vrDESCONTO.vAREAATUACAO
                          , vrDESCONTO.nCODSUPERVISOR
                          , vrDESCONTO.nCODUSUR
                          , vrDESCONTO.nCODMARCA
                          --
                          , vrDESCONTO.nPERCOMEXT
                          , vrDESCONTO.nPERCOMREP
                          , vrDESCONTO.nPERCOMMINT
                          , vvTipoPolitica
                          , vrDESCONTO.nINICIOINTERVALOPROMOCAOMED
                          , vrDESCONTO.nFIMINTERVALOPROMOCAOMED
                          , vrDESCONTO.vPARTICIPACOMISSGARANTIDA
                          , vrDESCONTO.nPERCDESCBASERCA
                          , vrDESCONTO.nPERCBONIFICMERC
                          , vrDESCONTO.nPERCMARKUPMED
                          --
                          , vrDESCONTO.vTIPOVENDA
                          , vrDESCONTO.nREGRAALTERARDESCONTO
                          );

                -- Altera na PCDESCONTO o Desconto da Marca - EDTPRM
                ELSIF (vrEditarPromocao.vvAcaoEditaMarca = 'A') THEN

                  UPDATE PCDESCONTO
                     SET DTINICIO                   = vdDataInicial
                       , DTFIM                      = vdDataFinal
                       , BASECREDDEBRCA             = vvBaseCredDebRca
                       , CREDITASOBREPOLITICA       = vvCreditaSobrePolitica
                       , CONSIDERACALCGIROMEDIC     = vvConsideraCalcGiroMedic
                       --
                       , PERCDESC                   = vrDESCONTO.nPERCDESC
                       , PERCDESCFIN                = vrDESCONTO.nPERCDESCFIN
                       , PERCOMEXT                  = vrDESCONTO.nPERCOMEXT
                       , PERCOMREP                  = vrDESCONTO.nPERCOMREP
                       , PERCOMMINT                 = vrDESCONTO.nPERCOMMINT
                       , TIPOPOLITICAPROMOCAOMED    = vvTipoPolitica
                       , PROMOCAOMEDOBRIGATORIO     = vvObrigatorio
                       , INICIOINTERVALOPROMOCAOMED = vrDESCONTO.nINICIOINTERVALOPROMOCAOMED
                       , FIMINTERVALOPROMOCAOMED    = vrDESCONTO.nFIMINTERVALOPROMOCAOMED
                       , PRECOFIXOPROMOCAOMED       = vrDESCONTO.nPRECOFIXOPROMOCAOMED
                       , PARTICIPACOMISSGARANTIDA   = vrDESCONTO.vPARTICIPACOMISSGARANTIDA
                       , PERCDESCBASERCA            = vrDESCONTO.nPERCDESCBASERCA
                       , PERCBONIFICMERC            = vrDESCONTO.nPERCBONIFICMERC
                       , PERCMARKUPMED              = vrDESCONTO.nPERCMARKUPMED
                       , APLICADESCONTO             = vvAplicaDesconto
                       , NUMLOTE                    = vrDESCONTO.vNUMLOTE
                       , VALORCOTAMED               = vrDESCONTO.nVALORCOTAMED
                       , CODIGOINTEGRACAOWMS        = vrDESCONTO.vCODIGOINTEGRACAOWMS
                       , VLDESCCMVPROMOCAOMED       = vrDESCONTO.nVLDESCCMVPROMOCAOMED
                       , REGRAALTERARDESCONTO       = vrDESCONTO.nREGRAALTERARDESCONTO
                   WHERE (CODPROMOCAOMED                    = vnNovoCodPromocaoMed)
                     AND (CODMARCA                          = vrDESCONTO.nCODMARCA)
                     AND (NVL(INICIOINTERVALOPROMOCAOMED,0) = NVL(vrDESCONTO.nINICIOINTERVALOPROMOCAOMED,0));

                -- Excluir na PCDESCONTO o Desconto - EDTPRM
                ELSIF (vrEditarPromocao.vvAcaoEditaMarca = 'E') THEN

                  DELETE FROM PCDESCONTO
                        WHERE (CODPROMOCAOMED                    = vnNovoCodPromocaoMed)
                          AND (CODMARCA                          = vrDESCONTO.nCODMARCA)
                          AND (NVL(INICIOINTERVALOPROMOCAOMED,0) = NVL(vrDESCONTO.nINICIOINTERVALOPROMOCAOMED,0));

                END IF; -- Fim Condição Tipo Ação da Edição da Marca

              END LOOP; -- Fim Laço de Faixas
            END IF; -- Fim Condição se Gerou Faixas

          END LOOP; -- Fim Laço de Marcas
        END IF;

        -- Laço de Linhas de Produto
        IF (vtPCMED_PROMOCAOLINHAPROD.COUNT > 0) THEN
          FOR idxLinhaProd IN vtPCMED_PROMOCAOLINHAPROD.FIRST..vtPCMED_PROMOCAOLINHAPROD.LAST LOOP

            -- Preenche variável com os valor do Array para atualização da PCDESCONTO
            vrDESCONTO.nCODLINHAPROD := vtPCMED_PROMOCAOLINHAPROD(idxLinhaProd).CODLINHAPROD;

            -- De Política de Desconto ou Markup gera uma linha no Array com os dados da Linha do Produto
            IF    (vvTipoPolitica IN ('D','M')) OR
                  (vvTipoPromocao IN ('N'))     THEN -- HIS.01889.2017 - Promoção de Campanha não tem Faixa de Qtde
              vtPCMED_PROMOCAOLINHAPROD_FA(1).PERCDESC                 := vtPCMED_PROMOCAOLINHAPROD(idxLinhaProd).PERCDESC;
              vtPCMED_PROMOCAOLINHAPROD_FA(1).PERCDESCFIN              := vtPCMED_PROMOCAOLINHAPROD(idxLinhaProd).PERCDESCFIN;
              vtPCMED_PROMOCAOLINHAPROD_FA(1).PERCOMEXT                := vtPCMED_PROMOCAOLINHAPROD(idxLinhaProd).PERCOMEXT;
              vtPCMED_PROMOCAOLINHAPROD_FA(1).PERCOMREP                := vtPCMED_PROMOCAOLINHAPROD(idxLinhaProd).PERCOMREP;
              vtPCMED_PROMOCAOLINHAPROD_FA(1).PERCOMMINT               := vtPCMED_PROMOCAOLINHAPROD(idxLinhaProd).PERCOMMINT;
              vtPCMED_PROMOCAOLINHAPROD_FA(1).INICIOINTERVALO          := NULL;
              vtPCMED_PROMOCAOLINHAPROD_FA(1).FIMINTERVALO             := NULL;
              vtPCMED_PROMOCAOLINHAPROD_FA(1).PARTICIPACOMISSGARANTIDA := vtPCMED_PROMOCAOLINHAPROD(idxLinhaProd).PARTICIPACOMISSGARANTIDA;
              vtPCMED_PROMOCAOLINHAPROD_FA(1).PERCDESCBASERCA          := vtPCMED_PROMOCAOLINHAPROD(idxLinhaProd).PERCDESCBASERCA;
              vtPCMED_PROMOCAOLINHAPROD_FA(1).REGRAALTERARDESCONTO     := vtPCMED_PROMOCAOLINHAPROD(idxLinhaProd).REGRAALTERARDESCONTO;
            -- De Desconto por Quantidade Carrega Array as Faixas
            ELSIF (vvTipoPolitica IN ('Q','B','V')) THEN
              SELECT *
                BULK COLLECT INTO vtPCMED_PROMOCAOLINHAPROD_FA
                FROM PCMED_PROMOCAOLINHAPROD_FAIXA
               WHERE (CODLINHAPRODREF = vrDESCONTO.nCODLINHAPROD);
            END IF;

            -- Se gerou as Faixas
            IF (vtPCMED_PROMOCAOLINHAPROD_FA.COUNT > 0) THEN
              FOR idxLinhaProdFaixa IN vtPCMED_PROMOCAOLINHAPROD_FA.FIRST..vtPCMED_PROMOCAOLINHAPROD_FA.LAST LOOP

                -- Pega Desconto informado na Linha do Produto
                IF (vvTipoPolitica IN ('B')) THEN -- Bonificação de Mercadoria
                  vrDESCONTO.nPERCBONIFICMERC          := vtPCMED_PROMOCAOLINHAPROD_FA(idxLinhaProdFaixa).PERCDESC;
                  vrDESCONTO.nPERCMARKUPMED            := NULL;
                  vrDESCONTO.nPERCDESC                 := 0;
                  vrDESCONTO.nPERCDESCFIN              := 0;
                -- Pega Markup informado na Linha do Produto
                ELSIF (vvTipoPromocao IN ('R')) THEN -- Percentual de Markup
                  vrDESCONTO.nPERCBONIFICMERC          := NULL;
                  vrDESCONTO.nPERCMARKUPMED            := vtPCMED_PROMOCAOLINHAPROD_FA(idxLinhaProdFaixa).PERCDESC;
                  vrDESCONTO.nPERCDESC                 := 0;
                  vrDESCONTO.nPERCDESCFIN              := vtPCMED_PROMOCAOLINHAPROD_FA(idxLinhaProdFaixa).PERCDESCFIN;
                ELSE
                  vrDESCONTO.nPERCBONIFICMERC          := NULL;
                  vrDESCONTO.nPERCMARKUPMED            := NULL;
                  vrDESCONTO.nPERCDESC                 := vtPCMED_PROMOCAOLINHAPROD_FA(idxLinhaProdFaixa).PERCDESC;
                  vrDESCONTO.nPERCDESCFIN              := vtPCMED_PROMOCAOLINHAPROD_FA(idxLinhaProdFaixa).PERCDESCFIN;
                END IF;
                -- Pega as Comissões informadas na Linha do Produto
                vrDESCONTO.nPERCOMEXT                  := vtPCMED_PROMOCAOLINHAPROD_FA(idxLinhaProdFaixa).PERCOMEXT;
                vrDESCONTO.nPERCOMREP                  := vtPCMED_PROMOCAOLINHAPROD_FA(idxLinhaProdFaixa).PERCOMREP;
                vrDESCONTO.nPERCOMMINT                 := vtPCMED_PROMOCAOLINHAPROD_FA(idxLinhaProdFaixa).PERCOMMINT;
                -- Pega as Faixas de Quantidade na Linha do Produto
                vrDESCONTO.nINICIOINTERVALOPROMOCAOMED := vtPCMED_PROMOCAOLINHAPROD_FA(idxLinhaProdFaixa).INICIOINTERVALO;
                vrDESCONTO.nFIMINTERVALOPROMOCAOMED    := vtPCMED_PROMOCAOLINHAPROD_FA(idxLinhaProdFaixa).FIMINTERVALO;
                -- Não Altera Preço de Tabela
                vrDESCONTO.vALTERAPTABELA              := 'N';
                -- Participa da Comissão Garantida
                vrDESCONTO.vPARTICIPACOMISSGARANTIDA   := F_PARTICIPACOMISSGARANTIDA(vtPCMED_PROMOCAOLINHAPROD_FA(idxLinhaProdFaixa).PARTICIPACOMISSGARANTIDA);
                -- Desconto C/C
                vrDESCONTO.nPERCDESCBASERCA            := vtPCMED_PROMOCAOLINHAPROD_FA(idxLinhaProdFaixa).PERCDESCBASERCA;
                -- Regra de alteração do Desconto/Preço
                vrDESCONTO.nREGRAALTERARDESCONTO       := vtPCMED_PROMOCAOLINHAPROD_FA(idxLinhaProdFaixa).REGRAALTERARDESCONTO;

                -----------------------------------------------------------------------
                -- AÇÃO INCLUSÃO/ALTERAÇÃO/EXCLUSÃO DO DESCONTO POR LINHA - EDTPRM
                -----------------------------------------------------------------------
                vrEditarPromocao.vvAcaoEditaLinha := F_DEFINE_ACAO_EDICAO(NVL(vrEditarPromocao.vvPermiteEditarProduto,'N'),
                                                                          'ln',
                                                                          vrDESCONTO.nCODLINHAPROD,
                                                                          vrDESCONTO.nINICIOINTERVALOPROMOCAOMED,
                                                                          vvTipoPromocao, NULL);

                ---------------------------------------
                -- INCLUSÃO/ALTERAÇÃO/EXCLUSÃO DA LINHA
                ---------------------------------------

                -- Insere na PCDESCONTO o Desconto da Linha
                IF    (vrEditarPromocao.vvAcaoEditaLinha = 'I') THEN

                -- Insere na PCDESCONTO o Desconto da Linha de Produto
                vnNovoCodDesconto := FOBTEM_PROX_CODDESCONTO;
                INSERT INTO PCDESCONTO
                          ( CODDESCONTO
                          , CODPROMOCAOMED
                          , DTINICIO
                          , DTFIM
                          , APLICADESCONTO
                          , TIPO
                          , BASECREDDEBRCA
                          , CREDITASOBREPOLITICA
                          , CONSIDERACALCGIROMEDIC
                          , UTILIZADESCREDE
                          , APENASPLPAGMAX
                          --
                          , CODFUNCLANC
                          , DATALANC
                          , CODFUNCULTALTER
                          , DATAULTALTER
                          , ALTERAPTABELA
                          , PRIORITARIA
                          , QUESTIONAUSOPRIORITARIA
                          , APLICADESCSIMPLESNACIONAL
                          , PRIORITARIAGERAL
                          --
                          , PERCDESC
                          , PERCDESCFIN
                          --
                          , ORIGEMPED
                          , TIPOFV
                          , CODFILIAL
                          , NUMREGIAO
                          , CODPRACA
                          , CODATIV
                          , CLASSEVENDA
                          , CODPLPAG
                          , CODCONDICAOVENDA
                          , CODREDE
                          , CODCLI
                          , AREAATUACAO
                          , CODSUPERVISOR
                          , CODUSUR
                          , CODLINHAPROD
                          --
                          , PERCOMEXT
                          , PERCOMREP
                          , PERCOMMINT
                          , TIPOPOLITICAPROMOCAOMED
                          , INICIOINTERVALOPROMOCAOMED
                          , FIMINTERVALOPROMOCAOMED
                          , PARTICIPACOMISSGARANTIDA
                          , PERCDESCBASERCA
                          , PERCBONIFICMERC
                          , PERCMARKUPMED
                          --
                          , TIPOVENDA
                          , REGRAALTERARDESCONTO
                          )
                   VALUES ( vnNovoCodDesconto
                          , vnNovoCodPromocaoMed -->> Novo Sequencial de Promoção
                          , vdDataInicial
                          , vdDataFinal
                          , vvAplicaDesconto --> HIS.02032.2017 - Flag 'Aplicar desconto automaticamente'
                          , 'C' -- Comercial
                          , vvBaseCredDebRca
                          , vvCreditaSobrePolitica
                          , vvConsideraCalcGiroMedic
                          , vvUtilizaDescRede
                          , vvApenasPlPagMax
                          --
                          , pi_nCodFunc
                          , SYSDATE
                          , pi_nCodFunc
                          , TRUNC(SYSDATE)
                          , vrDESCONTO.vALTERAPTABELA
                          , 'N'
                          , 'N'
                          , vvAplicaDescSimplesNacional
                          , 'N'
                          --
                          , vrDESCONTO.nPERCDESC
                          , vrDESCONTO.nPERCDESCFIN
                          --
                          , vrDESCONTO.vORIGEMPED
                          , vrDESCONTO.vTIPOFV
                          , vrDESCONTO.vCODFILIAL
                          , vrDESCONTO.nNUMREGIAO
                          , vrDESCONTO.nCODPRACA
                          , vrDESCONTO.nCODATIV
                          , vrDESCONTO.vCLASSEVENDA
                          , vrDESCONTO.nCODPLPAG
                          , vrDESCONTO.nCODCONDICAOVENDA
                          , vrDESCONTO.nCODREDE
                          , vrDESCONTO.nCODCLI
                          , vrDESCONTO.vAREAATUACAO
                          , vrDESCONTO.nCODSUPERVISOR
                          , vrDESCONTO.nCODUSUR
                          , vrDESCONTO.nCODLINHAPROD
                          --
                          , vrDESCONTO.nPERCOMEXT
                          , vrDESCONTO.nPERCOMREP
                          , vrDESCONTO.nPERCOMMINT
                          , vvTipoPolitica
                          , vrDESCONTO.nINICIOINTERVALOPROMOCAOMED
                          , vrDESCONTO.nFIMINTERVALOPROMOCAOMED
                          , vrDESCONTO.vPARTICIPACOMISSGARANTIDA
                          , vrDESCONTO.nPERCDESCBASERCA
                          , vrDESCONTO.nPERCBONIFICMERC
                          , vrDESCONTO.nPERCMARKUPMED
                          --
                          , vrDESCONTO.vTIPOVENDA
                          , vrDESCONTO.nREGRAALTERARDESCONTO
                          );

                -- Altera na PCDESCONTO o Desconto da Linha - EDTPRM
                ELSIF (vrEditarPromocao.vvAcaoEditaLinha = 'A') THEN

                  UPDATE PCDESCONTO
                     SET DTINICIO                   = vdDataInicial
                       , DTFIM                      = vdDataFinal
                       , BASECREDDEBRCA             = vvBaseCredDebRca
                       , CREDITASOBREPOLITICA       = vvCreditaSobrePolitica
                       , CONSIDERACALCGIROMEDIC     = vvConsideraCalcGiroMedic
                       --
                       , PERCDESC                   = vrDESCONTO.nPERCDESC
                       , PERCDESCFIN                = vrDESCONTO.nPERCDESCFIN
                       , PERCOMEXT                  = vrDESCONTO.nPERCOMEXT
                       , PERCOMREP                  = vrDESCONTO.nPERCOMREP
                       , PERCOMMINT                 = vrDESCONTO.nPERCOMMINT
                       , TIPOPOLITICAPROMOCAOMED    = vvTipoPolitica
                       , PROMOCAOMEDOBRIGATORIO     = vvObrigatorio
                       , INICIOINTERVALOPROMOCAOMED = vrDESCONTO.nINICIOINTERVALOPROMOCAOMED
                       , FIMINTERVALOPROMOCAOMED    = vrDESCONTO.nFIMINTERVALOPROMOCAOMED
                       , PRECOFIXOPROMOCAOMED       = vrDESCONTO.nPRECOFIXOPROMOCAOMED
                       , PARTICIPACOMISSGARANTIDA   = vrDESCONTO.vPARTICIPACOMISSGARANTIDA
                       , PERCDESCBASERCA            = vrDESCONTO.nPERCDESCBASERCA
                       , PERCBONIFICMERC            = vrDESCONTO.nPERCBONIFICMERC
                       , PERCMARKUPMED              = vrDESCONTO.nPERCMARKUPMED
                       , APLICADESCONTO             = vvAplicaDesconto
                       , NUMLOTE                    = vrDESCONTO.vNUMLOTE
                       , VALORCOTAMED               = vrDESCONTO.nVALORCOTAMED
                       , CODIGOINTEGRACAOWMS        = vrDESCONTO.vCODIGOINTEGRACAOWMS
                       , VLDESCCMVPROMOCAOMED       = vrDESCONTO.nVLDESCCMVPROMOCAOMED
                       , REGRAALTERARDESCONTO       = vrDESCONTO.nREGRAALTERARDESCONTO
                   WHERE (CODPROMOCAOMED                    = vnNovoCodPromocaoMed)
                     AND (CODLINHAPROD                      = vrDESCONTO.nCODLINHAPROD)
                     AND (NVL(INICIOINTERVALOPROMOCAOMED,0) = NVL(vrDESCONTO.nINICIOINTERVALOPROMOCAOMED,0));

                -- Excluir na PCDESCONTO o Desconto - EDTPRM
                ELSIF (vrEditarPromocao.vvAcaoEditaLinha = 'E') THEN

                  DELETE FROM PCDESCONTO
                        WHERE (CODPROMOCAOMED                    = vnNovoCodPromocaoMed)
                          AND (CODLINHAPROD                      = vrDESCONTO.nCODLINHAPROD)
                          AND (NVL(INICIOINTERVALOPROMOCAOMED,0) = NVL(vrDESCONTO.nINICIOINTERVALOPROMOCAOMED,0));

                END IF; -- Fim Condição Tipo Ação da Edição da Linha

              END LOOP; -- Fim Laço de Faixas
            END IF; -- Fim Condição se Gerou Faixas

          END LOOP; -- Fim Laço de Linhas de Produto
        END IF;

        -- Laço de Grupos de Produtos -- HIS.01889.2017
        IF (vtPCMED_PROMOCAORESTGRUPRO.COUNT > 0) THEN
          FOR idxGruProd IN vtPCMED_PROMOCAORESTGRUPRO.FIRST..vtPCMED_PROMOCAORESTGRUPRO.LAST LOOP

            -- Preenche variável com os valor do Array para atualização da PCDESCONTO
            vrDESCONTO.vTIPOGRUPOREST := 'GP';
            vrDESCONTO.nCODGRUPOREST  := vtPCMED_PROMOCAORESTGRUPRO(idxGruProd).CODGRUPO;

            -- De Política de Desconto ou Markup gera uma linha no Array com os dados dos Grupos de Produtos
            IF    (vvTipoPolitica IN ('D','M')) OR
                  (vvTipoPromocao IN ('N'))     THEN -- HIS.01889.2017 - Promoção de Campanha não tem Faixa de Qtde
              vtPCMED_PROMOCAORESTGRUPRO_FA(1).PERCDESC                 := vtPCMED_PROMOCAORESTGRUPRO(idxGruProd).PERCDESC;
              vtPCMED_PROMOCAORESTGRUPRO_FA(1).PERCDESCFIN              := vtPCMED_PROMOCAORESTGRUPRO(idxGruProd).PERCDESCFIN;
              vtPCMED_PROMOCAORESTGRUPRO_FA(1).PERCOMEXT                := vtPCMED_PROMOCAORESTGRUPRO(idxGruProd).PERCOMEXT;
              vtPCMED_PROMOCAORESTGRUPRO_FA(1).PERCOMREP                := vtPCMED_PROMOCAORESTGRUPRO(idxGruProd).PERCOMREP;
              vtPCMED_PROMOCAORESTGRUPRO_FA(1).PERCOMMINT               := vtPCMED_PROMOCAORESTGRUPRO(idxGruProd).PERCOMMINT;
              vtPCMED_PROMOCAORESTGRUPRO_FA(1).INICIOINTERVALO          := NULL;
              vtPCMED_PROMOCAORESTGRUPRO_FA(1).FIMINTERVALO             := NULL;
              vtPCMED_PROMOCAORESTGRUPRO_FA(1).PARTICIPACOMISSGARANTIDA := vtPCMED_PROMOCAORESTGRUPRO(idxGruProd).PARTICIPACOMISSGARANTIDA;
              vtPCMED_PROMOCAORESTGRUPRO_FA(1).PERCDESCBASERCA          := vtPCMED_PROMOCAORESTGRUPRO(idxGruProd).PERCDESCBASERCA;
              vtPCMED_PROMOCAORESTGRUPRO_FA(1).VLDESCCMVPROMOCAOMED     := vtPCMED_PROMOCAORESTGRUPRO(idxGruProd).VLDESCCMVPROMOCAOMED;
              vtPCMED_PROMOCAORESTGRUPRO_FA(1).REGRAALTERARDESCONTO     := vtPCMED_PROMOCAORESTGRUPRO(idxGruProd).REGRAALTERARDESCONTO;
            -- De Desconto por Quantidade Carrega Array as Faixas
            ELSIF (vvTipoPolitica IN ('Q','B','V')) THEN
              SELECT *
                BULK COLLECT INTO vtPCMED_PROMOCAORESTGRUPRO_FA
                FROM PCMED_PROMOCAORESTGRUPRO_FAIXA
               WHERE (CODGRUPOREF = vrDESCONTO.nCODGRUPOREST);
            END IF;

            -- Se gerou as Faixas
            IF (vtPCMED_PROMOCAORESTGRUPRO_FA.COUNT > 0) THEN
              FOR idxGruProdFaixa IN vtPCMED_PROMOCAORESTGRUPRO_FA.FIRST..vtPCMED_PROMOCAORESTGRUPRO_FA.LAST LOOP

                -- Pega Desconto informado na Linha do Produto
                IF (vvTipoPolitica IN ('B')) THEN -- Bonificação de Mercadoria
                  vrDESCONTO.nPERCBONIFICMERC          := vtPCMED_PROMOCAORESTGRUPRO_FA(idxGruProdFaixa).PERCDESC;
                  vrDESCONTO.nPERCMARKUPMED            := NULL;
                  vrDESCONTO.nPERCDESC                 := 0;
                  vrDESCONTO.nPERCDESCFIN              := 0;
                -- Pega Markup informado na Linha do Produto
                ELSIF (vvTipoPromocao IN ('R')) THEN -- Percentual de Markup
                  vrDESCONTO.nPERCBONIFICMERC          := NULL;
                  vrDESCONTO.nPERCMARKUPMED            := vtPCMED_PROMOCAORESTGRUPRO_FA(idxGruProdFaixa).PERCDESC;
                  vrDESCONTO.nPERCDESC                 := 0;
                  vrDESCONTO.nPERCDESCFIN              := vtPCMED_PROMOCAORESTGRUPRO_FA(idxGruProdFaixa).PERCDESCFIN;
                ELSE
                  vrDESCONTO.nPERCBONIFICMERC          := NULL;
                  vrDESCONTO.nPERCMARKUPMED            := NULL;
                  vrDESCONTO.nPERCDESC                 := vtPCMED_PROMOCAORESTGRUPRO_FA(idxGruProdFaixa).PERCDESC;
                  vrDESCONTO.nPERCDESCFIN              := vtPCMED_PROMOCAORESTGRUPRO_FA(idxGruProdFaixa).PERCDESCFIN;
                END IF;
                -- Pega as Comissões informadas na Linha do Produto
                vrDESCONTO.nPERCOMEXT                  := vtPCMED_PROMOCAORESTGRUPRO_FA(idxGruProdFaixa).PERCOMEXT;
                vrDESCONTO.nPERCOMREP                  := vtPCMED_PROMOCAORESTGRUPRO_FA(idxGruProdFaixa).PERCOMREP;
                vrDESCONTO.nPERCOMMINT                 := vtPCMED_PROMOCAORESTGRUPRO_FA(idxGruProdFaixa).PERCOMMINT;
                -- Pega as Faixas de Quantidade na Linha do Produto
                vrDESCONTO.nINICIOINTERVALOPROMOCAOMED := vtPCMED_PROMOCAORESTGRUPRO_FA(idxGruProdFaixa).INICIOINTERVALO;
                vrDESCONTO.nFIMINTERVALOPROMOCAOMED    := vtPCMED_PROMOCAORESTGRUPRO_FA(idxGruProdFaixa).FIMINTERVALO;
                -- Não Altera Preço de Tabela
                vrDESCONTO.vALTERAPTABELA              := 'N';
                -- Participa da Comissão Garantida
                vrDESCONTO.vPARTICIPACOMISSGARANTIDA   := F_PARTICIPACOMISSGARANTIDA(vtPCMED_PROMOCAORESTGRUPRO_FA(idxGruProdFaixa).PARTICIPACOMISSGARANTIDA);
                -- Desconto C/C
                vrDESCONTO.nPERCDESCBASERCA            := vtPCMED_PROMOCAORESTGRUPRO_FA(idxGruProdFaixa).PERCDESCBASERCA;
                -- Desconto CMV (Verba do Fornecedor)
                vrDESCONTO.nVLDESCCMVPROMOCAOMED       := vtPCMED_PROMOCAORESTGRUPRO_FA(idxGruProdFaixa).VLDESCCMVPROMOCAOMED;
                -- Regra de alteração do Desconto/Preço
                vrDESCONTO.nREGRAALTERARDESCONTO       := vtPCMED_PROMOCAORESTGRUPRO_FA(idxGruProdFaixa).REGRAALTERARDESCONTO;

                ------------------------------------------------------------------------------
                -- AÇÃO INCLUSÃO/ALTERAÇÃO/EXCLUSÃO DO DESCONTO POR GRUPO DE PRODUTOS - EDTPRM
                ------------------------------------------------------------------------------
                vrEditarPromocao.vvAcaoEditaGrupoProd := F_DEFINE_ACAO_EDICAO(NVL(vrEditarPromocao.vvPermiteEditarProduto,'N'),
                                                                              'gp',
                                                                              vrDESCONTO.nCODGRUPOREST,
                                                                              vrDESCONTO.nINICIOINTERVALOPROMOCAOMED,
                                                                              vvTipoPromocao, NULL);

                ---------------------------------------------------
                -- INCLUSÃO/ALTERAÇÃO/EXCLUSÃO DO GRUPO DE PRODUTOS
                ---------------------------------------------------

                -- Insere na PCDESCONTO o Desconto do Grupo de Produtos
                IF    (vrEditarPromocao.vvAcaoEditaGrupoProd = 'I') THEN

                -- Insere na PCDESCONTO o Desconto do Grupo de Produtos
                vnNovoCodDesconto := FOBTEM_PROX_CODDESCONTO;
                INSERT INTO PCDESCONTO
                          ( CODDESCONTO
                          , CODPROMOCAOMED
                          , DTINICIO
                          , DTFIM
                          , APLICADESCONTO
                          , TIPO
                          , BASECREDDEBRCA
                          , CREDITASOBREPOLITICA
                          , CONSIDERACALCGIROMEDIC
                          , UTILIZADESCREDE
                          , APENASPLPAGMAX
                          --
                          , CODFUNCLANC
                          , DATALANC
                          , CODFUNCULTALTER
                          , DATAULTALTER
                          , ALTERAPTABELA
                          , PRIORITARIA
                          , QUESTIONAUSOPRIORITARIA
                          , APLICADESCSIMPLESNACIONAL
                          , PRIORITARIAGERAL
                          --
                          , PERCDESC
                          , PERCDESCFIN
                          --
                          , ORIGEMPED
                          , TIPOFV
                          , CODFILIAL
                          , NUMREGIAO
                          , CODPRACA
                          , CODATIV
                          , CLASSEVENDA
                          , CODPLPAG
                          , CODCONDICAOVENDA
                          , CODREDE
                          , CODCLI
                          , AREAATUACAO
                          , CODSUPERVISOR
                          , CODUSUR
                          , PERCOMEXT
                          , PERCOMREP
                          , PERCOMMINT
                          , TIPOPOLITICAPROMOCAOMED
                          , INICIOINTERVALOPROMOCAOMED
                          , FIMINTERVALOPROMOCAOMED
                          , PARTICIPACOMISSGARANTIDA
                          , PERCDESCBASERCA
                          , PERCBONIFICMERC
                          , PERCMARKUPMED
                          --
                          , TIPOGRUPOREST -- HIS.01889.2017
                          , CODGRUPOREST -- HIS.01889.2017
                          --
                          , TIPOVENDA
                          , VLDESCCMVPROMOCAOMED
                          , REGRAALTERARDESCONTO
                          )
                   VALUES ( vnNovoCodDesconto
                          , vnNovoCodPromocaoMed -->> Novo Sequencial de Promoção
                          , vdDataInicial
                          , vdDataFinal
                          , vvAplicaDesconto --> HIS.02032.2017 - Flag 'Aplicar desconto automaticamente'
                          , 'C' -- Comercial
                          , vvBaseCredDebRca
                          , vvCreditaSobrePolitica
                          , vvConsideraCalcGiroMedic
                          , vvUtilizaDescRede
                          , vvApenasPlPagMax
                          --
                          , pi_nCodFunc
                          , SYSDATE
                          , pi_nCodFunc
                          , TRUNC(SYSDATE)
                          , vrDESCONTO.vALTERAPTABELA
                          , 'N'
                          , 'N'
                          , vvAplicaDescSimplesNacional
                          , 'N'
                          --
                          , vrDESCONTO.nPERCDESC
                          , vrDESCONTO.nPERCDESCFIN
                          --
                          , vrDESCONTO.vORIGEMPED
                          , vrDESCONTO.vTIPOFV
                          , vrDESCONTO.vCODFILIAL
                          , vrDESCONTO.nNUMREGIAO
                          , vrDESCONTO.nCODPRACA
                          , vrDESCONTO.nCODATIV
                          , vrDESCONTO.vCLASSEVENDA
                          , vrDESCONTO.nCODPLPAG
                          , vrDESCONTO.nCODCONDICAOVENDA
                          , vrDESCONTO.nCODREDE
                          , vrDESCONTO.nCODCLI
                          , vrDESCONTO.vAREAATUACAO
                          , vrDESCONTO.nCODSUPERVISOR
                          , vrDESCONTO.nCODUSUR
                          , vrDESCONTO.nPERCOMEXT
                          , vrDESCONTO.nPERCOMREP
                          , vrDESCONTO.nPERCOMMINT
                          , vvTipoPolitica
                          , vrDESCONTO.nINICIOINTERVALOPROMOCAOMED
                          , vrDESCONTO.nFIMINTERVALOPROMOCAOMED
                          , vrDESCONTO.vPARTICIPACOMISSGARANTIDA
                          , vrDESCONTO.nPERCDESCBASERCA
                          , vrDESCONTO.nPERCBONIFICMERC
                          , vrDESCONTO.nPERCMARKUPMED
                          --
                          , vrDESCONTO.vTIPOGRUPOREST -- HIS.01889.2017
                          , vrDESCONTO.nCODGRUPOREST -- HIS.01889.2017
                          --
                          , vrDESCONTO.vTIPOVENDA
                          , vrDESCONTO.nVLDESCCMVPROMOCAOMED
                          , vrDESCONTO.nREGRAALTERARDESCONTO
                          );

                -- Altera na PCDESCONTO o Desconto do Grupo de Produtos - EDTPRM
                ELSIF (vrEditarPromocao.vvAcaoEditaGrupoProd = 'A') THEN

                  UPDATE PCDESCONTO
                     SET DTINICIO                   = vdDataInicial
                       , DTFIM                      = vdDataFinal
                       , BASECREDDEBRCA             = vvBaseCredDebRca
                       , CREDITASOBREPOLITICA       = vvCreditaSobrePolitica
                       , CONSIDERACALCGIROMEDIC     = vvConsideraCalcGiroMedic
                       --
                       , PERCDESC                   = vrDESCONTO.nPERCDESC
                       , PERCDESCFIN                = vrDESCONTO.nPERCDESCFIN
                       , PERCOMEXT                  = vrDESCONTO.nPERCOMEXT
                       , PERCOMREP                  = vrDESCONTO.nPERCOMREP
                       , PERCOMMINT                 = vrDESCONTO.nPERCOMMINT
                       , TIPOPOLITICAPROMOCAOMED    = vvTipoPolitica
                       , PROMOCAOMEDOBRIGATORIO     = vvObrigatorio
                       , INICIOINTERVALOPROMOCAOMED = vrDESCONTO.nINICIOINTERVALOPROMOCAOMED
                       , FIMINTERVALOPROMOCAOMED    = vrDESCONTO.nFIMINTERVALOPROMOCAOMED
                       , PRECOFIXOPROMOCAOMED       = vrDESCONTO.nPRECOFIXOPROMOCAOMED
                       , PARTICIPACOMISSGARANTIDA   = vrDESCONTO.vPARTICIPACOMISSGARANTIDA
                       , PERCDESCBASERCA            = vrDESCONTO.nPERCDESCBASERCA
                       , PERCBONIFICMERC            = vrDESCONTO.nPERCBONIFICMERC
                       , PERCMARKUPMED              = vrDESCONTO.nPERCMARKUPMED
                       , APLICADESCONTO             = vvAplicaDesconto
                       , NUMLOTE                    = vrDESCONTO.vNUMLOTE
                       , VALORCOTAMED               = vrDESCONTO.nVALORCOTAMED
                       , CODIGOINTEGRACAOWMS        = vrDESCONTO.vCODIGOINTEGRACAOWMS
                       , VLDESCCMVPROMOCAOMED       = vrDESCONTO.nVLDESCCMVPROMOCAOMED
                       , REGRAALTERARDESCONTO       = vrDESCONTO.nREGRAALTERARDESCONTO
                   WHERE (CODPROMOCAOMED                    = vnNovoCodPromocaoMed)
                     AND (TIPOGRUPOREST                     = vrDESCONTO.vTIPOGRUPOREST)
                     AND (CODGRUPOREST                      = vrDESCONTO.nCODGRUPOREST)
                     AND (NVL(INICIOINTERVALOPROMOCAOMED,0) = NVL(vrDESCONTO.nINICIOINTERVALOPROMOCAOMED,0));

                -- Excluir na PCDESCONTO o Desconto - EDTPRM
                ELSIF (vrEditarPromocao.vvAcaoEditaGrupoProd = 'E') THEN

                  DELETE FROM PCDESCONTO
                        WHERE (CODPROMOCAOMED                    = vnNovoCodPromocaoMed)
                          AND (TIPOGRUPOREST                     = vrDESCONTO.vTIPOGRUPOREST)
                          AND (CODGRUPOREST                      = vrDESCONTO.nCODGRUPOREST)
                          AND (NVL(INICIOINTERVALOPROMOCAOMED,0) = NVL(vrDESCONTO.nINICIOINTERVALOPROMOCAOMED,0));

                END IF; -- Fim Condição Tipo Ação da Edição do Grupo de Produtos

              END LOOP; -- Fim Laço de Faixas
            END IF; -- Fim Condição se Gerou Faixas

          END LOOP; -- Fim Laço de Grupos de Produtos
        END IF;

        -- Laço de Produtos
        IF (vtPCMED_PROMOCAOPRODUTO.COUNT > 0) THEN
          FOR idxProduto IN vtPCMED_PROMOCAOPRODUTO.FIRST..vtPCMED_PROMOCAOPRODUTO.LAST LOOP

            -- Preenche variável com os valor do Array para atualização da PCDESCONTO
            vrDESCONTO.nCODPROD := vtPCMED_PROMOCAOPRODUTO(idxProduto).CODPROD;

            -- Promoção por Lote Carrega Array as Faixas
            IF (vvTipoPromocao IN ('L')) THEN -->> PROMOÇÃO POR LOTE

              SELECT *
                BULK COLLECT INTO vtPCMED_PROMOCAOPRODUTO_FAIXA
                FROM PCMED_PROMOCAOPRODUTO_FAIXA
               WHERE (CODPRODREF = vrDESCONTO.nCODPROD);
              -- Sem Campo de Controle de Item Obrigatório
              vvObrigatorio     := NULL;
              vnQtdeObrigatorio := NULL;
              -- Sem Campo de Controle de Qtde KIT
              vnQtdeKit         := NULL;

            -- De Política de Desconto,  Markup ou Preço Fixo, gera uma linha no Array com os dados do Produto
            ELSIF (vvTipoPolitica IN ('D','P','M')) OR
                  (vvTipoPromocao IN ('N'))         THEN -- HIS.01889.2017 - Promoção de Campanha não tem Faixa de Qtde

              vtPCMED_PROMOCAOPRODUTO_FAIXA(1).PERCDESC                 := vtPCMED_PROMOCAOPRODUTO(idxProduto).PERCDESC;
              vtPCMED_PROMOCAOPRODUTO_FAIXA(1).PERCDESCFIN              := vtPCMED_PROMOCAOPRODUTO(idxProduto).PERCDESCFIN;
              vtPCMED_PROMOCAOPRODUTO_FAIXA(1).PERCOMEXT                := vtPCMED_PROMOCAOPRODUTO(idxProduto).PERCOMEXT;
              vtPCMED_PROMOCAOPRODUTO_FAIXA(1).PERCOMREP                := vtPCMED_PROMOCAOPRODUTO(idxProduto).PERCOMREP;
              vtPCMED_PROMOCAOPRODUTO_FAIXA(1).PERCOMMINT               := vtPCMED_PROMOCAOPRODUTO(idxProduto).PERCOMMINT;
              vtPCMED_PROMOCAOPRODUTO_FAIXA(1).INICIOINTERVALO          := NULL;
              vtPCMED_PROMOCAOPRODUTO_FAIXA(1).FIMINTERVALO             := NULL;
              vtPCMED_PROMOCAOPRODUTO_FAIXA(1).PRECOFIXO                := vtPCMED_PROMOCAOPRODUTO(idxProduto).PRECOFIXO;
              vtPCMED_PROMOCAOPRODUTO_FAIXA(1).PARTICIPACOMISSGARANTIDA := vtPCMED_PROMOCAOPRODUTO(idxProduto).PARTICIPACOMISSGARANTIDA;
              vtPCMED_PROMOCAOPRODUTO_FAIXA(1).PERCDESCBASERCA          := vtPCMED_PROMOCAOPRODUTO(idxProduto).PERCDESCBASERCA;
              vtPCMED_PROMOCAOPRODUTO_FAIXA(1).NUMLOTE                  := NULL;
              vtPCMED_PROMOCAOPRODUTO_FAIXA(1).VALORCOTA                := NULL;
              vtPCMED_PROMOCAOPRODUTO_FAIXA(1).CODIGOINTEGRACAOWMS      := NULL;
              vtPCMED_PROMOCAOPRODUTO_FAIXA(1).VLDESCCMVPROMOCAOMED     := vtPCMED_PROMOCAOPRODUTO(idxProduto).VLDESCCMVPROMOCAOMED;
              vtPCMED_PROMOCAOPRODUTO_FAIXA(1).REGRAALTERARDESCONTO     := vtPCMED_PROMOCAOPRODUTO(idxProduto).REGRAALTERARDESCONTO;

              -- Campo de Controle de Item Obrigatório
              IF    vvTipoPromocao = 'K' THEN
                vvPermitirAumentarQtdeKit_Prod := vtPCMED_PROMOCAOPRODUTO(idxProduto).PERMITIRAUMENTARQTDEKIT;
                vvObrigatorio                  := vtPCMED_PROMOCAOPRODUTO(idxProduto).OBRIGATORIO;
                vnQtdeObrigatorio              := NULL;
              -- HIS.01889.2017 - Promoção de Campanha tem Controle de Obrigatório no Produto
              ELSIF vvTipoPromocao = 'N' THEN
                vvObrigatorio                  := vtPCMED_PROMOCAOPRODUTO(idxProduto).OBRIGATORIO;
                vnQtdeObrigatorio              := vtPCMED_PROMOCAOPRODUTO(idxProduto).QTOBRIGATORIO;
              ELSE
                vvPermitirAumentarQtdeKit_Prod := NULL;
                vvObrigatorio                  := vtPCMED_PROMOCAOPRODUTO(idxProduto).OBRIGATORIO;
                vnQtdeObrigatorio              := vtPCMED_PROMOCAOPRODUTO(idxProduto).QTOBRIGATORIO;
              END IF; -- Fim-se Tipo Promoção = 'K'

              -- Campo de Controle de Qtde KIT
              vnQtdeKit                                                 := vtPCMED_PROMOCAOPRODUTO(idxProduto).QTKIT;
            -- De Desconto/BonifMerc por Quantidade por Quantidade ou Preço por Quantidade Carrega Array as Faixas
            ELSIF (vvTipoPolitica IN ('Q','F','B','V')) THEN

              SELECT *
                BULK COLLECT INTO vtPCMED_PROMOCAOPRODUTO_FAIXA
                FROM PCMED_PROMOCAOPRODUTO_FAIXA
               WHERE (CODPRODREF = vrDESCONTO.nCODPROD);
              -- Sem Campo de Controle de Item Obrigatório
              vvObrigatorio     := NULL;
              vnQtdeObrigatorio := NULL;
              -- Sem Campo de Controle de Qtde KIT
              vnQtdeKit         := NULL;

            END IF;

            -- Se gerou as Faixas
            IF (vtPCMED_PROMOCAOPRODUTO_FAIXA.COUNT > 0) THEN
              FOR idxProdutoFaixa IN vtPCMED_PROMOCAOPRODUTO_FAIXA.FIRST..vtPCMED_PROMOCAOPRODUTO_FAIXA.LAST LOOP

                -- Pega Desconto informado no Produto
                IF (vvTipoPolitica IN ('B')) THEN -- Bonificação de Mercadoria
                  vrDESCONTO.nPERCBONIFICMERC          := vtPCMED_PROMOCAOPRODUTO_FAIXA(idxProdutoFaixa).PERCDESC;
                  vrDESCONTO.nPERCMARKUPMED            := NULL;
                  vrDESCONTO.nPERCDESC                 := 0;
                  vrDESCONTO.nPERCDESCFIN              := 0;
                -- Pega Markup informado no Produto
                ELSIF (vvTipoPromocao IN ('R')) THEN -- Percentual de Markup
                  vrDESCONTO.nPERCBONIFICMERC          := NULL;
                  vrDESCONTO.nPERCMARKUPMED            := vtPCMED_PROMOCAOPRODUTO_FAIXA(idxProdutoFaixa).PERCDESC;
                  vrDESCONTO.nPERCDESC                 := 0;
                  vrDESCONTO.nPERCDESCFIN              := vtPCMED_PROMOCAOPRODUTO_FAIXA(idxProdutoFaixa).PERCDESCFIN;
                ELSE
                  vrDESCONTO.nPERCBONIFICMERC          := NULL;
                  vrDESCONTO.nPERCMARKUPMED            := NULL;
                  vrDESCONTO.nPERCDESC                 := vtPCMED_PROMOCAOPRODUTO_FAIXA(idxProdutoFaixa).PERCDESC;
                  vrDESCONTO.nPERCDESCFIN              := vtPCMED_PROMOCAOPRODUTO_FAIXA(idxProdutoFaixa).PERCDESCFIN;
                END IF;
                -- Pega as Comissões informadas no Produto
                vrDESCONTO.nPERCOMEXT                  := vtPCMED_PROMOCAOPRODUTO_FAIXA(idxProdutoFaixa).PERCOMEXT;
                vrDESCONTO.nPERCOMREP                  := vtPCMED_PROMOCAOPRODUTO_FAIXA(idxProdutoFaixa).PERCOMREP;
                vrDESCONTO.nPERCOMMINT                 := vtPCMED_PROMOCAOPRODUTO_FAIXA(idxProdutoFaixa).PERCOMMINT;
                -- Pega as Faixas de Quantidade no Produto
                vrDESCONTO.nINICIOINTERVALOPROMOCAOMED := vtPCMED_PROMOCAOPRODUTO_FAIXA(idxProdutoFaixa).INICIOINTERVALO;
                vrDESCONTO.nFIMINTERVALOPROMOCAOMED    := vtPCMED_PROMOCAOPRODUTO_FAIXA(idxProdutoFaixa).FIMINTERVALO;
                -- Pega o Preço Fixo no Produto
                vrDESCONTO.nPRECOFIXOPROMOCAOMED       := vtPCMED_PROMOCAOPRODUTO_FAIXA(idxProdutoFaixa).PRECOFIXO;
                -- Altera Preço de Tabela se usar Preço Fixo
                IF (vvTipoPolitica IN ('P','F')) THEN
                  vrDESCONTO.vALTERAPTABELA            := 'S';
                ELSE
                  vrDESCONTO.vALTERAPTABELA            := 'N';
                END IF;
                -- Se Promoção de Valor e Mix de Produto
                -- HIS.01889.2017 - Promoção de Campanha tem Controle de Obrigatório no Produto
                IF    (vvTipoPromocao IN ('V','M','N')) THEN
                  -- Se permite Qt Mínima S/ Obrigatoriedade do Produto no Pedido e Qt. Mínima informada  [HIS.04779.2014]
                  IF (NVL(vvPermiteQtMinimaSemObrig,'N') = 'S') AND (vnQtdeObrigatorio > 0) THEN
                    vrDESCONTO.nINICIOINTERVALOPROMOCAOMED := vnQtdeObrigatorio;
                    vrDESCONTO.nFIMINTERVALOPROMOCAOMED    := 999999;
                    vrDESCONTO.vOBRIGATORIO                := vvObrigatorio;
                  -- Se não, mas produto é obrigatório
                  ELSIF (NVL(vvObrigatorio,'N') = 'S') THEN
                    vrDESCONTO.nINICIOINTERVALOPROMOCAOMED := vnQtdeObrigatorio;
                    vrDESCONTO.nFIMINTERVALOPROMOCAOMED    := 999999;
                  ELSE
                    vrDESCONTO.nINICIOINTERVALOPROMOCAOMED := NULL;
                    vrDESCONTO.nFIMINTERVALOPROMOCAOMED    := NULL;
                  END IF;
                -- Se Controla Qtde. KIT  (Promoção por Combo Virtual - KIT) ou Promo Casadinha [HIS.01151.2015]
                ELSIF (vvTipoPromocao in ('K','S')) THEN
                  vrDESCONTO.nINICIOINTERVALOPROMOCAOMED := vnQtdeKit;
                  vrDESCONTO.nFIMINTERVALOPROMOCAOMED    := vnQtdeKit;
                  -- Se Kit, grava o campo OBRIGATORIO HIS.04456.2015
                  IF (vvTipoPromocao = 'K') THEN
                    vrDESCONTO.vOBRIGATORIO                := vvObrigatorio;
                  END IF;
                -- Promoção por Lote não terá Inicio e Fim do Intervalo, ignora valores usados somente como indexadores na 2323
                ELSIF (vvTipoPromocao IN ('L')) THEN
                  vrDESCONTO.nINICIOINTERVALOPROMOCAOMED  := NULL;
                  vrDESCONTO.nFIMINTERVALOPROMOCAOMED     := NULL;
                END IF;
                -- Participa da Comissão Garantida
                vrDESCONTO.vPARTICIPACOMISSGARANTIDA     := F_PARTICIPACOMISSGARANTIDA(vtPCMED_PROMOCAOPRODUTO_FAIXA(idxProdutoFaixa).PARTICIPACOMISSGARANTIDA);
                -- Desconto C/C
                vrDESCONTO.nPERCDESCBASERCA              := vtPCMED_PROMOCAOPRODUTO_FAIXA(idxProdutoFaixa).PERCDESCBASERCA;
                -- Cota
                vrDESCONTO.vNUMLOTE                      := vtPCMED_PROMOCAOPRODUTO_FAIXA(idxProdutoFaixa).NUMLOTE;
                vrDESCONTO.nVALORCOTAMED                 := vtPCMED_PROMOCAOPRODUTO_FAIXA(idxProdutoFaixa).VALORCOTA;
                -- Depósito WMS
                vrDESCONTO.vCODIGOINTEGRACAOWMS          := vtPCMED_PROMOCAOPRODUTO_FAIXA(idxProdutoFaixa).CODIGOINTEGRACAOWMS;
                -- Desconto CMV (Verba do Fornecedor)
                vrDESCONTO.nVLDESCCMVPROMOCAOMED         := vtPCMED_PROMOCAOPRODUTO_FAIXA(idxProdutoFaixa).VLDESCCMVPROMOCAOMED;
                -- Regra de alteração do Desconto/Preço
                vrDESCONTO.nREGRAALTERARDESCONTO         := vtPCMED_PROMOCAOPRODUTO_FAIXA(idxProdutoFaixa).REGRAALTERARDESCONTO;

                -----------------------------------------------------------------------
                -- AÇÃO INCLUSÃO/ALTERAÇÃO/EXCLUSÃO DO DESCONTO POR PRODUTO - EDTPRM
                -----------------------------------------------------------------------
                vrEditarPromocao.vvAcaoEditaProduto := F_DEFINE_ACAO_EDICAO(NVL(vrEditarPromocao.vvPermiteEditarProduto,'N'),
                                                                            'pr',
                                                                            vrDESCONTO.nCODPROD,
                                                                            vrDESCONTO.nINICIOINTERVALOPROMOCAOMED,
                                                                            vvTipoPromocao,
                                                                            vrDESCONTO.vNUMLOTE);

                -----------------------------------------
                -- INCLUSÃO/ALTERAÇÃO/EXCLUSÃO DO PRODUTO
                -----------------------------------------

                -- Insere na PCDESCONTO o Desconto do Produto
                IF    (vrEditarPromocao.vvAcaoEditaProduto = 'I') THEN

                  vnNovoCodDesconto := FOBTEM_PROX_CODDESCONTO;
                  INSERT INTO PCDESCONTO
                            ( CODDESCONTO
                            , CODPROMOCAOMED
                            , DTINICIO
                            , DTFIM
                            , APLICADESCONTO
                            , TIPO
                            , BASECREDDEBRCA
                            , CREDITASOBREPOLITICA
                            , CONSIDERACALCGIROMEDIC
                            , UTILIZADESCREDE
                            , APENASPLPAGMAX
                            --
                            , CODFUNCLANC
                            , DATALANC
                            , CODFUNCULTALTER
                            , DATAULTALTER
                            , ALTERAPTABELA
                            , PRIORITARIA
                            , QUESTIONAUSOPRIORITARIA
                            , APLICADESCSIMPLESNACIONAL
                            , PRIORITARIAGERAL
                            --
                            , PERCDESC
                            , PERCDESCFIN
                            --
                            , ORIGEMPED
                            , TIPOFV
                            , CODFILIAL
                            , NUMREGIAO
                            , CODPRACA
                            , CODATIV
                            , CLASSEVENDA
                            , CODPLPAG
                            , CODCONDICAOVENDA
                            , CODREDE
                            , CODCLI
                            , AREAATUACAO
                            , CODSUPERVISOR
                            , CODUSUR
                            , CODPROD
                            , PERCOMEXT
                            , PERCOMREP
                            , PERCOMMINT
                            --
                            , TIPOPOLITICAPROMOCAOMED
                            , PROMOCAOMEDOBRIGATORIO
                            , INICIOINTERVALOPROMOCAOMED
                            , FIMINTERVALOPROMOCAOMED
                            , PRECOFIXOPROMOCAOMED
                            , PARTICIPACOMISSGARANTIDA
                            , PERCDESCBASERCA
                            , PERCBONIFICMERC
                            , PERCMARKUPMED
                            , PERMITIRAUMENTARQTDEKITMED
                            --
                            , TIPOVENDA
                            --
                            , NUMLOTE
                            , VALORCOTAMED
                            , CODIGOINTEGRACAOWMS
                            --
                            , VLDESCCMVPROMOCAOMED
                            , REGRAALTERARDESCONTO                            
                            )
                     VALUES ( vnNovoCodDesconto
                            , vnNovoCodPromocaoMed -->> Novo Sequencial de Promoção
                            , vdDataInicial
                            , vdDataFinal
                            , vvAplicaDesconto --> HIS.02032.2017 - Flag 'Aplicar desconto automaticamente'
                            , 'C' -- Comercial
                            , vvBaseCredDebRca
                            , vvCreditaSobrePolitica
                            , vvConsideraCalcGiroMedic
                            , vvUtilizaDescRede
                            , vvApenasPlPagMax
                            --
                            , pi_nCodFunc
                            , SYSDATE
                            , pi_nCodFunc
                            , TRUNC(SYSDATE)
                            , vrDESCONTO.vALTERAPTABELA
                            , 'N'
                            , 'N'
                            , vvAplicaDescSimplesNacional
                            , 'N'
                            --
                            , vrDESCONTO.nPERCDESC
                            , vrDESCONTO.nPERCDESCFIN
                            --
                            , vrDESCONTO.vORIGEMPED
                            , vrDESCONTO.vTIPOFV
                            , vrDESCONTO.vCODFILIAL
                            , vrDESCONTO.nNUMREGIAO
                            , vrDESCONTO.nCODPRACA
                            , vrDESCONTO.nCODATIV
                            , vrDESCONTO.vCLASSEVENDA
                            , vrDESCONTO.nCODPLPAG
                            , vrDESCONTO.nCODCONDICAOVENDA
                            , vrDESCONTO.nCODREDE
                            , vrDESCONTO.nCODCLI
                            , vrDESCONTO.vAREAATUACAO
                            , vrDESCONTO.nCODSUPERVISOR
                            , vrDESCONTO.nCODUSUR
                            , vrDESCONTO.nCODPROD
                            , vrDESCONTO.nPERCOMEXT
                            , vrDESCONTO.nPERCOMREP
                            , vrDESCONTO.nPERCOMMINT
                            --
                            , vvTipoPolitica
                            , vvObrigatorio
                            , vrDESCONTO.nINICIOINTERVALOPROMOCAOMED
                            , vrDESCONTO.nFIMINTERVALOPROMOCAOMED
                            , vrDESCONTO.nPRECOFIXOPROMOCAOMED
                            , vrDESCONTO.vPARTICIPACOMISSGARANTIDA
                            , vrDESCONTO.nPERCDESCBASERCA
                            , vrDESCONTO.nPERCBONIFICMERC
                            , vrDESCONTO.nPERCMARKUPMED
                            , vvPermitirAumentarQtdeKit_Prod
                            --
                            , vrDESCONTO.vTIPOVENDA
                            --
                            , vrDESCONTO.vNUMLOTE
                            , vrDESCONTO.nVALORCOTAMED
                            , vrDESCONTO.vCODIGOINTEGRACAOWMS
                            --
                            , vrDESCONTO.nVLDESCCMVPROMOCAOMED
                            , vrDESCONTO.nREGRAALTERARDESCONTO
                            );

                -- Altera na PCDESCONTO o Desconto do Produto - EDTPRM
                ELSIF (vrEditarPromocao.vvAcaoEditaProduto = 'A') THEN

                  -- Promoções de Valor e Combo e Campanha usam o Inicio do Intervalo para Quantidade Mínima
                  IF (vvTipoPromocao IN ('M','V','K','N')) THEN
                    UPDATE PCDESCONTO
                       SET DTINICIO                   = vdDataInicial
                         , DTFIM                      = vdDataFinal
                         , BASECREDDEBRCA             = vvBaseCredDebRca
                         , CREDITASOBREPOLITICA       = vvCreditaSobrePolitica
                         , CONSIDERACALCGIROMEDIC     = vvConsideraCalcGiroMedic
                         --
                         , PERCDESC                   = vrDESCONTO.nPERCDESC
                         , PERCDESCFIN                = vrDESCONTO.nPERCDESCFIN
                         , PERCOMEXT                  = vrDESCONTO.nPERCOMEXT
                         , PERCOMREP                  = vrDESCONTO.nPERCOMREP
                         , PERCOMMINT                 = vrDESCONTO.nPERCOMMINT
                         , TIPOPOLITICAPROMOCAOMED    = vvTipoPolitica
                         , PROMOCAOMEDOBRIGATORIO     = vvObrigatorio
                         , INICIOINTERVALOPROMOCAOMED = vrDESCONTO.nINICIOINTERVALOPROMOCAOMED
                         , FIMINTERVALOPROMOCAOMED    = vrDESCONTO.nFIMINTERVALOPROMOCAOMED
                         , PRECOFIXOPROMOCAOMED       = vrDESCONTO.nPRECOFIXOPROMOCAOMED
                         , PARTICIPACOMISSGARANTIDA   = vrDESCONTO.vPARTICIPACOMISSGARANTIDA
                         , PERCDESCBASERCA            = vrDESCONTO.nPERCDESCBASERCA
                         , PERCBONIFICMERC            = vrDESCONTO.nPERCBONIFICMERC
                         , PERCMARKUPMED              = vrDESCONTO.nPERCMARKUPMED
                         , APLICADESCONTO             = vvAplicaDesconto
                         , NUMLOTE                    = vrDESCONTO.vNUMLOTE
                         , VALORCOTAMED               = vrDESCONTO.nVALORCOTAMED
                         , CODIGOINTEGRACAOWMS        = vrDESCONTO.vCODIGOINTEGRACAOWMS
                         , VLDESCCMVPROMOCAOMED       = vrDESCONTO.nVLDESCCMVPROMOCAOMED
                         --
                         , PERMITIRAUMENTARQTDEKITMED = vvPermitirAumentarQtdeKit_Prod
                         --
                         , REGRAALTERARDESCONTO       = vrDESCONTO.nREGRAALTERARDESCONTO
                     WHERE (CODPROMOCAOMED                    = vnNovoCodPromocaoMed)
                       AND (CODPROD                           = vrDESCONTO.nCODPROD);                  
                  -- Promoções de Lote
                  ELSIF (vvTipoPromocao = 'L') THEN
                    UPDATE PCDESCONTO
                       SET DTINICIO                   = vdDataInicial
                         , DTFIM                      = vdDataFinal
                         , BASECREDDEBRCA             = vvBaseCredDebRca
                         , CREDITASOBREPOLITICA       = vvCreditaSobrePolitica
                         , CONSIDERACALCGIROMEDIC     = vvConsideraCalcGiroMedic
                         --
                         , PERCDESC                   = vrDESCONTO.nPERCDESC
                         , PERCDESCFIN                = vrDESCONTO.nPERCDESCFIN
                         , PERCOMEXT                  = vrDESCONTO.nPERCOMEXT
                         , PERCOMREP                  = vrDESCONTO.nPERCOMREP
                         , PERCOMMINT                 = vrDESCONTO.nPERCOMMINT
                         , TIPOPOLITICAPROMOCAOMED    = vvTipoPolitica
                         , PROMOCAOMEDOBRIGATORIO     = vvObrigatorio
                         , INICIOINTERVALOPROMOCAOMED = vrDESCONTO.nINICIOINTERVALOPROMOCAOMED
                         , FIMINTERVALOPROMOCAOMED    = vrDESCONTO.nFIMINTERVALOPROMOCAOMED
                         , PRECOFIXOPROMOCAOMED       = vrDESCONTO.nPRECOFIXOPROMOCAOMED
                         , PARTICIPACOMISSGARANTIDA   = vrDESCONTO.vPARTICIPACOMISSGARANTIDA
                         , PERCDESCBASERCA            = vrDESCONTO.nPERCDESCBASERCA
                         , PERCBONIFICMERC            = vrDESCONTO.nPERCBONIFICMERC
                         , PERCMARKUPMED              = vrDESCONTO.nPERCMARKUPMED
                         , APLICADESCONTO             = vvAplicaDesconto
                         , NUMLOTE                    = vrDESCONTO.vNUMLOTE
                         , VALORCOTAMED               = vrDESCONTO.nVALORCOTAMED
                         , CODIGOINTEGRACAOWMS        = vrDESCONTO.vCODIGOINTEGRACAOWMS
                         , VLDESCCMVPROMOCAOMED       = vrDESCONTO.nVLDESCCMVPROMOCAOMED
                         --
                         , PERMITIRAUMENTARQTDEKITMED = vvPermitirAumentarQtdeKit_Prod
                         --
                         , REGRAALTERARDESCONTO       = vrDESCONTO.nREGRAALTERARDESCONTO
                     WHERE (CODPROMOCAOMED                    = vnNovoCodPromocaoMed)
                       AND (CODPROD                           = vrDESCONTO.nCODPROD)
                       AND (NUMLOTE                           = vrDESCONTO.vNUMLOTE); 
                  ELSE
                    UPDATE PCDESCONTO
                       SET DTINICIO                   = vdDataInicial
                         , DTFIM                      = vdDataFinal
                         , BASECREDDEBRCA             = vvBaseCredDebRca
                         , CREDITASOBREPOLITICA       = vvCreditaSobrePolitica
                         , CONSIDERACALCGIROMEDIC     = vvConsideraCalcGiroMedic
                         --
                         , PERCDESC                   = vrDESCONTO.nPERCDESC
                         , PERCDESCFIN                = vrDESCONTO.nPERCDESCFIN
                         , PERCOMEXT                  = vrDESCONTO.nPERCOMEXT
                         , PERCOMREP                  = vrDESCONTO.nPERCOMREP
                         , PERCOMMINT                 = vrDESCONTO.nPERCOMMINT
                         , TIPOPOLITICAPROMOCAOMED    = vvTipoPolitica
                         , PROMOCAOMEDOBRIGATORIO     = vvObrigatorio
                         , INICIOINTERVALOPROMOCAOMED = vrDESCONTO.nINICIOINTERVALOPROMOCAOMED
                         , FIMINTERVALOPROMOCAOMED    = vrDESCONTO.nFIMINTERVALOPROMOCAOMED
                         , PRECOFIXOPROMOCAOMED       = vrDESCONTO.nPRECOFIXOPROMOCAOMED
                         , PARTICIPACOMISSGARANTIDA   = vrDESCONTO.vPARTICIPACOMISSGARANTIDA
                         , PERCDESCBASERCA            = vrDESCONTO.nPERCDESCBASERCA
                         , PERCBONIFICMERC            = vrDESCONTO.nPERCBONIFICMERC
                         , PERCMARKUPMED              = vrDESCONTO.nPERCMARKUPMED
                         , APLICADESCONTO             = vvAplicaDesconto
                         , NUMLOTE                    = vrDESCONTO.vNUMLOTE
                         , VALORCOTAMED               = vrDESCONTO.nVALORCOTAMED
                         , CODIGOINTEGRACAOWMS        = vrDESCONTO.vCODIGOINTEGRACAOWMS
                         , VLDESCCMVPROMOCAOMED       = vrDESCONTO.nVLDESCCMVPROMOCAOMED
                         --
                         , PERMITIRAUMENTARQTDEKITMED = vvPermitirAumentarQtdeKit_Prod
                         --
                         , REGRAALTERARDESCONTO       = vrDESCONTO.nREGRAALTERARDESCONTO                         
                     WHERE (CODPROMOCAOMED                    = vnNovoCodPromocaoMed)
                       AND (CODPROD                           = vrDESCONTO.nCODPROD)
                       AND (NVL(INICIOINTERVALOPROMOCAOMED,0) = NVL(vrDESCONTO.nINICIOINTERVALOPROMOCAOMED,0));
                  END IF;

                -- Excluir na PCDESCONTO o Desconto - EDTPRM
                ELSIF (vrEditarPromocao.vvAcaoEditaProduto = 'E') THEN

                  -- Promoções de Valor e Combo e Campanha usam o Inicio do Intervalo para Quantidade Mínima
                  IF (vvTipoPromocao IN ('M','V','K','N')) THEN
                    DELETE FROM PCDESCONTO
                          WHERE (CODPROMOCAOMED = vnNovoCodPromocaoMed)
                            AND (CODPROD        = vrDESCONTO.nCODPROD);
                  -- Promoções de Lote
                  ELSIF (vvTipoPromocao = 'L') THEN
                    DELETE FROM PCDESCONTO
                          WHERE (CODPROMOCAOMED = vnNovoCodPromocaoMed)
                            AND (CODPROD        = vrDESCONTO.nCODPROD)
                            AND (NUMLOTE        = vrDESCONTO.vNUMLOTE); 
                  ELSE
                    DELETE FROM PCDESCONTO
                          WHERE (CODPROMOCAOMED                    = vnNovoCodPromocaoMed)
                            AND (CODPROD                           = vrDESCONTO.nCODPROD)
                            AND (NVL(INICIOINTERVALOPROMOCAOMED,0) = NVL(vrDESCONTO.nINICIOINTERVALOPROMOCAOMED,0));
                  END IF;
                  
                END IF; -- Fim Condição Tipo Ação da Edição do Produto

              END LOOP; -- Fim Laço de Faixas
            END IF; -- Fim Condição se Gerou Faixas

          END LOOP; -- Fim Laço de Produtos
        END IF;

      END IF; -- Fim Condição Tipo Política

    END PINSERE_DESCONTOS;

