                , CODPRODPRINC
                , NUMORCA
                , CLASSEVENDA
                , APLICADESCONTO
                , TIPOCARGA
                , CREDITASOBREPOLITICA
                , TIPO
                , PERCDESCFIN
                , ALTERAPTABELA
                , TIPOAPLICDESCONTOCB
                , CODPRODCB
                , PERCDESCFORNEC
                , AREAATUACAO
                , CODFILIAL
                , QTDEMAXIMAPOLITICA
                , QTDEMAXIMAPEDIDO
                , CODGRUPO
                , APENASPLPAGMAX
                , PERCOMMINT
                , PERCOMREP
                , PERCOMEXT
                , APLICADESCSIMPLESNACIONAL
                , CODMARCA
                , CODREDE
                , CONSIDERACALCGIROMEDIC
                , CODIDENTIFICADOR
                , PERDESCFORNEC
                , CODPROMOCAOMED
                , vdDtExclusao -- Data Exclusão
                , pi_nCodFunc  -- Código do Funcionário da Exclusão
                , CODLINHAPROD
                , TIPOPOLITICAPROMOCAOMED
                , INICIOINTERVALOPROMOCAOMED
                , FIMINTERVALOPROMOCAOMED
                , PRECOFIXOPROMOCAOMED
                , PARTICIPACOMISSGARANTIDA
                , PERCDESCBASERCA
                , PERCBONIFICMERC
                , PERCMARKUPMED
                , TIPOGRUPOREST -- HIS.01889.2017
                , CODGRUPOREST  -- HIS.01889.2017
                , VALORCOTAMED
                , CODIGOINTEGRACAOWMS
                , VLDESCCMVPROMOCAOMED
                , REGRAALTERARDESCONTO
             FROM PCDESCONTO
            WHERE (CODPROMOCAOMED = pi_nCodPromocao);

      -- Insere Descontos por Quantidade no Log
      INSERT INTO PCLOGDESCQUANT(
                  CODPROD
                , INICIOINTERVALO
                , FIMINTERVALO
                , PERCDESC
                , NUMREGIAO
                , DTINICIO
                , DTFIM
                , CODPRACA
                , PERCDESCVRJ
                , PERCDESCVP
                , PERCDESCFINVV
                , PERCDESCFINVP
                , PERDESCMAX
                , TIPODESCONTO
                , CODPLPAGMAX
                , CREDITASOBREPTABELA
                , CODDESCONTO
                , CONSIDERACALCGIROMEDIC
                , CODPROMOCAOMED
                , CODLINHAPROD
                , PERCOMMINT
                , PERCOMREP
                , PERCOMEXT )
           SELECT NVL(CODPROD,0) CODPROD -->> Não pode gravar no Log NULL
                , INICIOINTERVALO
                , FIMINTERVALO
                , PERCDESC
                , NUMREGIAO
                , DTINICIO
                , DTFIM
                , CODPRACA
                , PERCDESCVRJ
                , PERCDESCVP
                , PERCDESCFINVV
                , PERCDESCFINVP
                , PERDESCMAX
                , TIPODESCONTO
                , CODPLPAGMAX
                , CREDITASOBREPTABELA
                , CODDESCONTO
                , CONSIDERACALCGIROMEDIC
                , CODPROMOCAOMED
                , CODLINHAPROD
                , PERCOMMINT
                , PERCOMREP
                , PERCOMEXT
                 FROM PCDESCQUANT
            WHERE (CODPROMOCAOMED = pi_nCodPromocao);

      --******************************
      -- COM NORMALIZAÇÃO NA PCDESCNTO
      --******************************

      -- Origens informadas
      INSERT INTO PCLOGPROMOCAOORIGEMMED(
                  CODPROMOCAOMED
                , ORIGEMPED
                , DTEXCLUSAO )
           SELECT CODPROMOCAOMED
                , ORIGEMPED
                , vdDtExclusao
             FROM PCPROMOCAOORIGEMMED
            WHERE (CODPROMOCAOMED = pi_nCodPromocao);

      -- Filiais informadas
      INSERT INTO PCLOGPROMOCAOFILMED(
                  CODPROMOCAOMED
                , CODFILIAL
                , DTEXCLUSAO )
           SELECT CODPROMOCAOMED
                , CODFILIAL
                , vdDtExclusao
             FROM PCPROMOCAOFILMED
            WHERE (CODPROMOCAOMED = pi_nCodPromocao);

      -- Regiões informadas
      INSERT INTO PCLOGPROMOCAOREGIAOMED(
                  CODPROMOCAOMED
                , NUMREGIAO
                , DTEXCLUSAO
                , QTMAXCOMBOMED )
           SELECT CODPROMOCAOMED
                , NUMREGIAO
                , vdDtExclusao
                , QTMAXCOMBOMED
             FROM PCPROMOCAOREGIAOMED
            WHERE (CODPROMOCAOMED = pi_nCodPromocao);

      -- Praças informadas
      INSERT INTO PCLOGPROMOCAOPRACAMED(
                  CODPROMOCAOMED
                , CODPRACA
                , DTEXCLUSAO
                , QTMAXCOMBOMED )
           SELECT CODPROMOCAOMED
                , CODPRACA
                , vdDtExclusao
                , QTMAXCOMBOMED
             FROM PCPROMOCAOPRACAMED
            WHERE (CODPROMOCAOMED = pi_nCodPromocao);

      -- Atividades informadas
      INSERT INTO PCLOGPROMOCAORAMOATIVMED(
                  CODPROMOCAOMED
                , CODATIV
                , DTEXCLUSAO
                , QTMAXCOMBOMED )
           SELECT CODPROMOCAOMED
                , CODATIV
                , vdDtExclusao
                , QTMAXCOMBOMED
             FROM PCPROMOCAORAMOATIVMED
            WHERE (CODPROMOCAOMED = pi_nCodPromocao);

      -- Redes informadas
      INSERT INTO PCLOGPROMOCAOREDEMED(
                  CODPROMOCAOMED
                , CODREDE
                , DTEXCLUSAO
                , QTMAXCOMBOMED )
           SELECT CODPROMOCAOMED
                , CODREDE
                , vdDtExclusao
                , QTMAXCOMBOMED
             FROM PCPROMOCAOREDEMED
            WHERE (CODPROMOCAOMED = pi_nCodPromocao);

      -- Clientes informados
      INSERT INTO PCLOGPROMOCAOCLIMED(
                  CODPROMOCAOMED
                , CODCLI
                , DTEXCLUSAO
                , QTMAXCOMBOMED )
           SELECT CODPROMOCAOMED
                , CODCLI
                , vdDtExclusao
                , QTMAXCOMBOMED
             FROM PCPROMOCAOCLIMED
            WHERE (CODPROMOCAOMED = pi_nCodPromocao);

      -- Áreas informadas
      INSERT INTO PCLOGPROMOCAOAREAATUACAOMED(
                  CODPROMOCAOMED
                , AREAATUACAO
                , DTEXCLUSAO )
           SELECT CODPROMOCAOMED
                , AREAATUACAO
                , vdDtExclusao
             FROM PCPROMOCAOAREAATUACAOMED
            WHERE (CODPROMOCAOMED = pi_nCodPromocao);

      -- Supervisores informados
      INSERT INTO PCLOGPROMOCAOSUPERVMED(
                  CODPROMOCAOMED
                , CODSUPERV
                , DTEXCLUSAO )
           SELECT CODPROMOCAOMED
                , CODSUPERV
                , vdDtExclusao
             FROM PCPROMOCAOSUPERVMED
            WHERE (CODPROMOCAOMED = pi_nCodPromocao);

      -- RCA's informados
      -- (Pode ficar sem dados no Array)
      INSERT INTO PCLOGPROMOCAOUSURMED(
                  CODPROMOCAOMED
                , CODUSUR
                , DTEXCLUSAO )
           SELECT CODPROMOCAOMED
                , CODUSUR
                , vdDtExclusao
             FROM PCPROMOCAOUSURMED
            WHERE (CODPROMOCAOMED = pi_nCodPromocao);

      -- Planos de Pagamento informados
      INSERT INTO PCLOGPROMOCAOPLPAGMED(
                  CODPROMOCAOMED
                , CODPLPAG
                , DTEXCLUSAO )
           SELECT CODPROMOCAOMED
                , CODPLPAG
                , vdDtExclusao
             FROM PCLOGPROMOCAOPLPAGMED
            WHERE (CODPROMOCAOMED = pi_nCodPromocao);

      -- Condições de Venda informadas
      INSERT INTO PCLOGPROMOCAOCONDVENDAMED(
                  CODPROMOCAOMED
                , CODCONDICAOVENDA
                , DTEXCLUSAO )
           SELECT CODPROMOCAOMED
                , CODCONDICAOVENDA
                , vdDtExclusao
             FROM PCPROMOCAOCONDVENDAMED
            WHERE (CODPROMOCAOMED = pi_nCodPromocao);

      -- Classes informadas
      -- Grupos Comerciais informados
      -- DDMEDICA-2258 (Somente carregará as inf se a promoção não for "Por Rede/Cliente (1)")
      IF ((nvl(vnTipoRestricao,0) NOT IN (1, 4))) THEN
        INSERT INTO PCLOGPROMOCAOCLASSEVENDAMED(
                    CODPROMOCAOMED
                  , CLASSEVENDA
                  , DTEXCLUSAO
                  , QTMAXCOMBOMED )
             SELECT CODPROMOCAOMED
                  , CLASSEVENDA
                  , vdDtExclusao
                  , QTMAXCOMBOMED
               FROM PCPROMOCAOCLASSEVENDAMED
              WHERE (CODPROMOCAOMED = pi_nCodPromocao);
        --
        INSERT INTO PCLOGPROMOCAOGRUPOCOMERCMED(
                    CODPROMOCAOMED
                  , CODGRUPOCOMERCIALMED
                  , DTEXCLUSAO
                  , QTMAXCOMBOMED )
             SELECT CODPROMOCAOMED
                  , CODGRUPOCOMERCIALMED
                  , vdDtExclusao
                  , QTMAXCOMBOMED
               FROM PCPROMOCAOGRUPOCOMERCMED
              WHERE (CODPROMOCAOMED = pi_nCodPromocao);
      END IF;

      -- Brindes informados -- HIS.01889.2017
      INSERT INTO PCLOGPROMOCAOBRINDEMED(
                  CODPROMOCAOMED
                , CAMPO
                , CODIGO
                , QTDE
                , DTEXCLUSAO
                , PRECOFIXO )
           SELECT CODPROMOCAOMED
                , CAMPO
                , CODIGO
                , QTDE
                , vdDtExclusao
                , PRECOFIXO
             FROM PCPROMOCAOBRINDEMED
            WHERE (CODPROMOCAOMED = pi_nCodPromocao);

      -- Verbas informadas -- DDMEDICA-4915
      INSERT INTO PCLOGPROMOCAOVERBAMED(
                  CODPROMOCAOMED
                , NUMVERBA
                , VALORCOTA
                , DTEXCLUSAO )
           SELECT CODPROMOCAOMED
                , NUMVERBA
                , VALORCOTA
                , vdDtExclusao
             FROM PCPROMOCAOVERBAMED
            WHERE (CODPROMOCAOMED = pi_nCodPromocao);

    END PINSERE_LOG;

    ------------------------------------------------------------------------------
    -- Procedimento para Obter Desconto da Política
    -----------------------------------------------
    PROCEDURE PINSERE_PCPROMOCAOTELEVMED(pi_nCodPromocao IN NUMBER) IS

      vnNumCasasDecVenda    PCCONSUM.NUMCASASDECVENDA%TYPE;
      vvTipoPromocao        PCPROMOCAOMED.TIPOPROMOCAO%TYPE; -- 4493.034989.2017
      vvTipoPolitica        PCPROMOCAOMED.TIPOPOLITICA%TYPE; -- DDMEDICA-5751
      vnVlrMinItensPromocao PCPROMOCAOMED.VLRMINITENSPROMOCAO%TYPE; -- DDMEDICA-5751

      PROCEDURE P_GERAR_DESC_TELEVENDAS(pi_nCodPromocaoMed   IN NUMBER,
                                        pi_nCodProd          IN NUMBER,
                                        pi_nNumCasasDecVenda IN NUMBER,
                                        pi_vTipoPromocao     IN VARCHAR2,    -- DDVENDAS-38892
                                        pi_vTipoPolitica     IN VARCHAR2) IS -- DDVENDAS-38892

        --Dados do Produto
        vncodfornec                    NUMBER;
        vncodepto                      NUMBER;
        vncodsec                       NUMBER;
        vncodcategoria                 NUMBER;
        vncodsubcategoria              NUMBER;
        vncodmarca                     pcprodut.codmarca%type;
        vncodlinhaprod                 pcprodut.codlinhaprod%type;
        
        -- DDVENDAS-38892
        TYPE TRecPolitica              IS RECORD(
             vnCodDesconto             PCDESCONTO.CODDESCONTO%TYPE,
             vnPercDesc                PCDESCONTO.PERCDESC%TYPE,
             vnPercDescFin             PCDESCONTO.PERCDESCFIN%TYPE,
             vnInicioIntervalo         PCDESCONTO.INICIOINTERVALOPROMOCAOMED%TYPE,
             vnPercMarkup              PCDESCONTO.PERCMARKUPMED%TYPE,
             vvObrigatorio             PCDESCONTO.PROMOCAOMEDOBRIGATORIO%TYPE,
             viExiste                  INTEGER);
        vrPolitica                     TRecPolitica; 
        TYPE TTvPoliticas              IS TABLE OF TRecPolitica INDEX BY BINARY_INTEGER;
        vtPoliticas                    TTvPoliticas;
        
        PROCEDURE ADD_POLITICAS_QTDE(nPERCDESC        IN NUMBER,
                                     nPERCDESCFIN     IN NUMBER,
                                     nINICIOINTERVALO IN NUMBER) IS
        BEGIN
          vrPolitica.vnPercDesc        := nPERCDESC;
          vrPolitica.vnPercDescFin     := nPERCDESCFIN;
          vrPolitica.vnInicioIntervalo := nINICIOINTERVALO;
          vtPoliticas(NVL(vtPoliticas.COUNT,0) + 1) := vrPolitica;
        END;

      /*******************************************************************************
                         INICIO DO PROCESSAMENTO PRINCIPAL
       *******************************************************************************/
      BEGIN

        -- Limpa Tabela Temporária
        DELETE FROM PCMED_SELPROMOCAO;

        -- Dados cadastrais do Produto para aplicação nos filtros da promoção
        BEGIN
          SELECT codfornec,
                 codepto,
                 codsec,
                 codcategoria,
                 codsubcategoria,
                 codmarca,
                 codlinhaprod
            INTO vncodfornec,
                 vncodepto,
                 vncodsec,
                 vncodcategoria,
                 vncodsubcategoria,
                 vncodmarca,
                 vncodlinhaprod
            FROM pcprodut
           WHERE codprod = pi_nCodProd;
        EXCEPTION
          WHEN NO_DATA_FOUND THEN
            NULL;
        END;   
        
        -- DDVENDAS-38892 - usar os dados na tabela temporária no processo de gravação da PCPROMOCAOTELEVMED
        
        vtPoliticas.DELETE;

        -- Por faixa de quantidade
        -- Bonificação ou Lote
        IF (pi_vTipoPolitica IN ('Q','F','V')) OR
           (pi_vTipoPromocao IN ('L','B')) THEN    
        
          -- Politica por produto
          FOR vc_Politicas IN (SELECT P.PERCDESC
                                    , P.PERCDESCFIN
                                    , P.INICIOINTERVALO
                                 FROM PCMED_PROMOCAOPRODUTO_FAIXA P
                                WHERE (P.CODPRODREF = pi_nCodProd)
                                ) LOOP
           ADD_POLITICAS_QTDE(vc_Politicas.PERCDESC,
                              vc_Politicas.PERCDESCFIN,
                              vc_Politicas.INICIOINTERVALO);                                                
          END LOOP;                                  
          -- Politica por grupo de produto
          IF (NVL(vtPoliticas.COUNT,0) = 0) THEN
            FOR vc_Politicas IN (SELECT P.PERCDESC
                                      , P.PERCDESCFIN
                                      , P.INICIOINTERVALO
                                   FROM PCMED_PROMOCAORESTGRUPRO_FAIXA P
                                  WHERE (P.CODGRUPOREF = (SELECT PCGRUPOSCAMPANHAI.CODGRUPO
                                                            FROM PCGRUPOSCAMPANHAI
                                                            WHERE PCGRUPOSCAMPANHAI.DTEXCLUSAO IS NULL
                                                             AND PCGRUPOSCAMPANHAI.CODGRUPO = P.CODGRUPOREF
                                                             AND PCGRUPOSCAMPANHAI.CODITEM  = pi_nCodProd))
                                  ) LOOP
             ADD_POLITICAS_QTDE(vc_Politicas.PERCDESC,
                                vc_Politicas.PERCDESCFIN,
                                vc_Politicas.INICIOINTERVALO);                                                
            END LOOP;                                  
            -- Politica por fornecedor
            IF (NVL(vtPoliticas.COUNT,0) = 0) THEN
              FOR vc_Politicas IN (SELECT P.PERCDESC
                                        , P.PERCDESCFIN
                                        , P.INICIOINTERVALO
                                     FROM PCMED_PROMOCAOFORNEC_FAIXA P
                                    WHERE (P.CODFORNECREF = vncodfornec)
                                    ) LOOP
               ADD_POLITICAS_QTDE(vc_Politicas.PERCDESC,
                                  vc_Politicas.PERCDESCFIN,
                                  vc_Politicas.INICIOINTERVALO);                                                
              END LOOP;                                  
              -- Politica por marca
              IF (NVL(vtPoliticas.COUNT,0) = 0) THEN
                FOR vc_Politicas IN (SELECT P.PERCDESC
                                          , P.PERCDESCFIN
                                          , P.INICIOINTERVALO
                                       FROM PCMED_PROMOCAOMARCA_FAIXA P
                                      WHERE (P.CODMARCAREF = vncodmarca)
                                      ) LOOP
                 ADD_POLITICAS_QTDE(vc_Politicas.PERCDESC,
                                    vc_Politicas.PERCDESCFIN,
                                    vc_Politicas.INICIOINTERVALO);                                                
                END LOOP;
                -- Politica por categoria
                IF (NVL(vtPoliticas.COUNT,0) = 0) THEN
                  FOR vc_Politicas IN (SELECT P.PERCDESC
                                            , P.PERCDESCFIN
                                            , P.INICIOINTERVALO
                                         FROM PCMED_PROMOCAOCATEG_FAIXA P
                                        WHERE (P.CODCATEGORIAREF = vncodcategoria)
                                        ) LOOP
                   ADD_POLITICAS_QTDE(vc_Politicas.PERCDESC,
                                      vc_Politicas.PERCDESCFIN,
                                      vc_Politicas.INICIOINTERVALO);                                                
                  END LOOP;
                  -- Politica por seção
                  IF (NVL(vtPoliticas.COUNT,0) = 0) THEN
                    FOR vc_Politicas IN (SELECT P.PERCDESC
                                              , P.PERCDESCFIN
                                              , P.INICIOINTERVALO
                                           FROM PCMED_PROMOCAOSECAO_FAIXA P
                                          WHERE (P.CODSECREF = vncodsec)
                                          ) LOOP
                     ADD_POLITICAS_QTDE(vc_Politicas.PERCDESC,
                                        vc_Politicas.PERCDESCFIN,
                                        vc_Politicas.INICIOINTERVALO);                                                
                    END LOOP;
                    -- Politica por linha
                    IF (NVL(vtPoliticas.COUNT,0) = 0) THEN
                      FOR vc_Politicas IN (SELECT P.PERCDESC
                                                , P.PERCDESCFIN
                                                , P.INICIOINTERVALO
                                             FROM PCMED_PROMOCAOLINHAPROD_FAIXA P
                                            WHERE (P.CODLINHAPRODREF = vncodlinhaprod)
                                            ) LOOP
                       ADD_POLITICAS_QTDE(vc_Politicas.PERCDESC,
                                          vc_Politicas.PERCDESCFIN,
                                          vc_Politicas.INICIOINTERVALO);                                                
                      END LOOP;
                      -- Politica por departamento
                      IF (NVL(vtPoliticas.COUNT,0) = 0) THEN
                        FOR vc_Politicas IN (SELECT P.PERCDESC
                                                  , P.PERCDESCFIN
                                                  , P.INICIOINTERVALO
                                               FROM PCMED_PROMOCAODEPTO_FAIXA P
                                              WHERE (P.CODEPTOREF = vncodepto)
                                              ) LOOP
                         ADD_POLITICAS_QTDE(vc_Politicas.PERCDESC,
                                            vc_Politicas.PERCDESCFIN,
                                            vc_Politicas.INICIOINTERVALO);                                                
                        END LOOP;                                  
                      END IF;                        
                    END IF;                      
                  END IF;                    
                END IF;                  
              END IF;  
            END IF;  
          END IF;  

        -- Sem faixa de quantidade
        ELSE
        
          -- Politica por produto
          BEGIN
            SELECT P.PERCDESC
                 , P.PERCDESCFIN
                 , P.OBRIGATORIO
                 , 1
                 , P.QTOBRIGATORIO				 
              INTO vrPolitica.vnPercDesc
                 , vrPolitica.vnPercDescFin
                 , vrPolitica.vvObrigatorio
                 , vrPolitica.viExiste
                 , vrPolitica.vnInicioIntervalo				 
              FROM PCMED_PROMOCAOPRODUTO P
             WHERE (P.CODPROD = pi_nCodProd)
               AND (ROWNUM    = 1);
          EXCEPTION
            WHEN NO_DATA_FOUND THEN
              -- Politica por grupo de produto
              BEGIN
                SELECT P.PERCDESC
                     , P.PERCDESCFIN
                     , 1
                  INTO vrPolitica.vnPercDesc
                     , vrPolitica.vnPercDescFin
                     , vrPolitica.viExiste
                  FROM PCMED_PROMOCAORESTGRUPRO P
                 WHERE (P.CODGRUPO = (SELECT PCGRUPOSCAMPANHAI.CODGRUPO
                                        FROM PCGRUPOSCAMPANHAI
                                       WHERE PCGRUPOSCAMPANHAI.DTEXCLUSAO IS NULL
                                         AND PCGRUPOSCAMPANHAI.CODGRUPO = P.CODGRUPO
                                         AND PCGRUPOSCAMPANHAI.CODITEM  = pi_nCodProd))
                   AND (ROWNUM    = 1);
              EXCEPTION
                WHEN NO_DATA_FOUND THEN
                  -- Politica por fornecedor
                  BEGIN
                    SELECT P.PERCDESC
                         , P.PERCDESCFIN
                         , 1
                      INTO vrPolitica.vnPercDesc
                         , vrPolitica.vnPercDescFin
                         , vrPolitica.viExiste
                      FROM PCMED_PROMOCAOFORNEC P
                     WHERE (P.CODFORNEC = vncodfornec)
                       AND (ROWNUM      = 1);
                  EXCEPTION
                    WHEN NO_DATA_FOUND THEN
                      -- Politica por marca
                      BEGIN
                        SELECT P.PERCDESC
                             , P.PERCDESCFIN
                             , 1
                          INTO vrPolitica.vnPercDesc
                             , vrPolitica.vnPercDescFin
                             , vrPolitica.viExiste
                          FROM PCMED_PROMOCAOMARCA P
                         WHERE (P.CODMARCA = vncodmarca)
                           AND (ROWNUM     = 1);
                      EXCEPTION
                        WHEN NO_DATA_FOUND THEN
                          -- Politica por categoria
                          BEGIN
                            SELECT P.PERCDESC
                                 , P.PERCDESCFIN
                                 , 1
                              INTO vrPolitica.vnPercDesc
                                 , vrPolitica.vnPercDescFin
                                 , vrPolitica.viExiste
                              FROM PCMED_PROMOCAOCATEG P
                             WHERE (P.CODCATEGORIA = vncodcategoria)
                               AND (ROWNUM         = 1);
                          EXCEPTION
                            WHEN NO_DATA_FOUND THEN
                              -- Politica por seção
                              BEGIN
                                SELECT P.PERCDESC
                                     , P.PERCDESCFIN
                                     , 1
                                  INTO vrPolitica.vnPercDesc
                                     , vrPolitica.vnPercDescFin
                                     , vrPolitica.viExiste
                                  FROM PCMED_PROMOCAOSECAO P
                                 WHERE (P.CODSEC = vncodsec)
                                   AND (ROWNUM   = 1);
                              EXCEPTION
                                WHEN NO_DATA_FOUND THEN
                                  -- Politica por linha
                                  BEGIN
                                    SELECT P.PERCDESC
                                         , P.PERCDESCFIN
                                         , 1
                                      INTO vrPolitica.vnPercDesc
                                         , vrPolitica.vnPercDescFin
                                         , vrPolitica.viExiste                                           
                                      FROM PCMED_PROMOCAOLINHAPROD P
                                     WHERE (P.CODLINHAPROD = vncodlinhaprod)
                                       AND (ROWNUM         = 1);
                                  EXCEPTION
                                    WHEN NO_DATA_FOUND THEN
                                      -- Politica por departamento
                                      BEGIN
                                        SELECT P.PERCDESC
                                             , P.PERCDESCFIN
                                             , 1
                                          INTO vrPolitica.vnPercDesc
                                             , vrPolitica.vnPercDescFin
                                             , vrPolitica.viExiste                                               
                                          FROM PCMED_PROMOCAODEPTO P
                                         WHERE (P.CODEPTO = vncodepto)
                                           AND (ROWNUM    = 1);
                                      EXCEPTION
                                        WHEN NO_DATA_FOUND THEN
                                          vrPolitica.viExiste := 0;
                                      END;
                                  END;
                              END;
                          END;
                      END;
                  END;
              END;
          END;
          
          vtPoliticas(NVL(vtPoliticas.COUNT,0) + 1) := vrPolitica;
                    
        END IF;
        
        IF (vtPoliticas.COUNT > 0) THEN
        
          IF    (pi_vTipoPromocao = 'R') THEN   
            FOR viIdx IN vtPoliticas.FIRST..vtPoliticas.LAST LOOP
              vtPoliticas(viIdx).vnPercMarkup  := vtPoliticas(viIdx).vnPercDesc;              
              vtPoliticas(viIdx).vnPercDesc    := 0;              
            END LOOP;         
          ELSIF (pi_vTipoPromocao = 'B') THEN   
            FOR viIdx IN vtPoliticas.FIRST..vtPoliticas.LAST LOOP
              vtPoliticas(viIdx).vnPercDesc    := 0;              
              vtPoliticas(viIdx).vnPercDescFin := 0;              
            END LOOP;         
          ELSIF (pi_vTipoPolitica IN ('P','F')) THEN   
            FOR viIdx IN vtPoliticas.FIRST..vtPoliticas.LAST LOOP
              vtPoliticas(viIdx).vnPercDesc    := 0;              
              vtPoliticas(viIdx).vnPercDescFin := 0;              
            END LOOP;         
          END IF;
          
          FOR viIdx IN vtPoliticas.FIRST..vtPoliticas.LAST LOOP
            INSERT INTO PCMED_SELPROMOCAO
                      ( CODPROMOCAOMED
                      , CODDESCONTO
                      , PERCDESC
                      , PERCDESCFIN
                      , PERCMARKUPMED
                      , INICIOINTERVALO
                      , PROMOCAOMEDOBRIGATORIO )                      
               VALUES ( pi_nCodPromocaoMed
                      , viIdx
                      , vtPoliticas(viIdx).vnPercDesc
                      , vtPoliticas(viIdx).vnPercDescFin
                      , vtPoliticas(viIdx).vnPercMarkup
                      , vtPoliticas(viIdx).vnInicioIntervalo
                      , vtPoliticas(viIdx).vvObrigatorio );
          END LOOP;         
                    
        END IF;

      END P_GERAR_DESC_TELEVENDAS;

    -- INICIO DO PROCEDIMENTO PARA OBTER DESCONTO DA POLÍTICA
    ---------------------------------------------------------
    BEGIN

      -- Obtém a Qtde. de Casas Decimais
      BEGIN
        SELECT PCCONSUM.NUMCASASDECVENDA
          INTO vnNumCasasDecVenda
          FROM PCCONSUM;
      EXCEPTION
        WHEN NO_DATA_FOUND THEN
          vnNumCasasDecVenda := 2;
      END;

      -- Obtém o Tipo de Promoção -- 4493.034989.2017
      BEGIN
        SELECT TIPOPROMOCAO
             , TIPOPOLITICA -- DDMEDICA-5751
             , VLRMINITENSPROMOCAO -- DDMEDICA-5751
          INTO vvTipoPromocao
             , vvTipoPolitica -- DDMEDICA-5751
             , vnVlrMinItensPromocao -- DDMEDICA-5751
          FROM PCPROMOCAOMED
         WHERE (CODPROMOCAOMED = pi_nCodPromocao);
      EXCEPTION
        WHEN NO_DATA_FOUND THEN
          vvTipoPromocao        := NULL;
          vvTipoPolitica        := NULL;
          vnVlrMinItensPromocao := NULL;
      END;

      -- Exclui Produtos para a Promoção
      DELETE FROM PCPROMOCAOTELEVMED WHERE (CODPROMOCAOMED = pi_nCodPromocao);

      -- SOMENTE SE USAR NORMALIZAÇÃO PODE DAR CARGA NA TABELA - MED-2479
      IF ((NVL(FUSA_REGRA_NORMALIZA_DESC,'N') = 'S') AND
           (NVL(vvTipoPromocao,' ') NOT IN ('K','S'))) OR
         ((NVL(FUSA_REGRA_NORMALIZA_DESC,'N') = 'N') AND
          (NVL(vvTipoPromocao,' ') IN ('N','V','M'))) OR -- DDMEDICA-5751 "V" e "M"
         ((NVL(FUSA_REGRA_NORMALIZA_DESC,'N') = 'N') AND
          (NVL(vvTipoPolitica,' ') IN ('F','Q','V'))     AND
          (NVL(vnVlrMinItensPromocao,0) > 0))        THEN -- DDMEDICA-5751 Faixa Qtde e Valor Mínimo

        -- Todos os Produtos
        FOR vc_Produto IN (SELECT CODPROD
                            FROM PCPRODUT
                           WHERE (NVL(PCPRODUT.REVENDA, 'S') <> 'N')
                             AND (PCPRODUT.DTEXCLUSAO IS NULL) 
                             AND ( (PCPRODUT.CODPROD      IN (SELECT CODPROD FROM PCMED_PROMOCAOPRODUTO))                             OR
                                   (PCPRODUT.CODPROD      IN (SELECT PCGRUPOSCAMPANHAI.CODITEM 
                                                                FROM PCMED_PROMOCAORESTGRUPRO
                                                                   , PCGRUPOSCAMPANHAI
                                                               WHERE PCGRUPOSCAMPANHAI.DTEXCLUSAO IS NULL
                                                                 AND PCGRUPOSCAMPANHAI.CODGRUPO = PCMED_PROMOCAORESTGRUPRO.CODGRUPO)) OR
                                   (PCPRODUT.CODFORNEC    IN (SELECT CODFORNEC    FROM PCMED_PROMOCAOFORNEC))                         OR
                                   (PCPRODUT.CODMARCA     IN (SELECT CODMARCA     FROM PCMED_PROMOCAOMARCA))                          OR 
                                   (PCPRODUT.CODCATEGORIA IN (SELECT CODCATEGORIA FROM PCMED_PROMOCAOCATEG))                          OR
                                   (PCPRODUT.CODSEC       IN (SELECT CODSEC       FROM PCMED_PROMOCAOSECAO))                          OR
                                   (PCPRODUT.CODLINHAPROD IN (SELECT CODLINHAPROD FROM PCMED_PROMOCAOLINHAPROD))                      OR
                                   (PCPRODUT.CODEPTO      IN (SELECT CODEPTO      FROM PCMED_PROMOCAODEPTO)) )
                            ) LOOP

          P_GERAR_DESC_TELEVENDAS(pi_nCodPromocao,
                                  vc_Produto.CODPROD,
                                  vnNumCasasDecVenda,
                                  vvTipoPromocao,  -- DDVENDAS-38892
                                  vvTipoPolitica); -- DDVENDAS-38892

          INSERT INTO PCPROMOCAOTELEVMED
                    ( CODPROMOCAOMED
                    , CODPROD
                    , PERCDESCTOTAL
                    , PERCDESC
                    , PERCDESCFIN
                    , INICIOINTERVALO
                    , OBRIGATORIO
                    , PERCMARKUPMED )
               SELECT DISTINCT -->> PRECISA DO DISTINCT porque quando tiver várias origens, duplica
                      CODPROMOCAOMED
                    , vc_Produto.CODPROD
                    , (NVL(PCMED_SELPROMOCAO.PERCDESC,0) + NVL(PCMED_SELPROMOCAO.PERCDESCFIN,0)) PERCMAIORDESC
                    , PCMED_SELPROMOCAO.PERCDESC
                    , PCMED_SELPROMOCAO.PERCDESCFIN
                    , PCMED_SELPROMOCAO.INICIOINTERVALO
                    , PCMED_SELPROMOCAO.PROMOCAOMEDOBRIGATORIO
                    , PCMED_SELPROMOCAO.PERCMARKUPMED
                 FROM PCMED_SELPROMOCAO;
                --//HIS.01889.2017 - Por Causa da Campanha não pode ter esta Condição//WHERE ((NVL(PCMED_SELPROMOCAO.PERCDESC,0) + NVL(PCMED_SELPROMOCAO.PERCDESCFIN,0)) > 0);

        END LOOP;

      END IF; -- MED-2479 - FIM: USA NORMALIZAÇÃO

    END PINSERE_PCPROMOCAOTELEVMED;

   /******************************************************************************
                      INICIO DO PROCESSAMENTO PRINCIPAL
    ******************************************************************************/
  BEGIN

    -- DDMEDICA-840 - Normalização como Processo Default da Empresa
    IF (NVL(FUSA_REGRA_NORMALIZA_DESC,'N') <> 'S') THEN
      BEGIN
        SELECT 'S'
          INTO vvExistePromocao
          FROM PCPROMOCAOMED
         WHERE (ROWNUM = 1);
      EXCEPTION
        WHEN NO_DATA_FOUND THEN
         vvExistePromocao := 'N';
      END;
      IF (vvExistePromocao = 'N') THEN
        BEGIN
          INSERT INTO PCREGRASEXCECAOMED(NOME,CODFILIAL,VALOR) VALUES ('USAREGRANORMALIZADESC','99','S');
        EXCEPTION
          WHEN OTHERS THEN NULL;
        END;
      END IF;
    END IF;

    -- Inicializa Variável de Edição de Produtos da Promoção - EDTPRM
    vrEditarPromocao.vvPermiteEditarProduto := 'N';

    -- Log Alteração
    --IF (pi_vTipoChamada = '4') THEN INSERT INTO PCMED_LOGALTERACAO_PROMOCAO VALUES (SYSDATE, pi_nCodPromocao, 'INICIO'); END IF;

   /******************************************************************************
    Se chamado para Limpar as Tabelas Temporárias
    *********************************************/
    IF    (pi_vTipoChamada = '1') THEN

      -- Limpa Tabelas Temporárias
      PLIMPA_TABELAS_TEMPORARIAS;

      -- Efetiva Transações
      COMMIT;

   /******************************************************************************
    Se chamado para Gravar a Tabela PCPROMOCAOTELEVMED
    **************************************************/
    ELSIF (pi_vTipoChamada IN ('9')) THEN

      -- Procedimento para inserir na PCPROMOCAOTELEVMED
      --PINSERE_PCPROMOCAOTELEVMED(pi_nCodPromocao);
      --
      --COMMIT;
      NULL; -- DDVENDAS-38892 - Não realiza novamente porque já o faz na chamada tipo '2'

   /******************************************************************************
    Se chamado para Incluir uma Promoção
    ************************************/
    ELSIF (pi_vTipoChamada IN ('2','4','8')) THEN

      ---------------------------------------------------------------------------
      -- Pesquisa Tipo Politica e Tipo Restrição da Promoção
      ------------------------------------------------------
      BEGIN
        SELECT IDENTIFICADORPROMOCAO
             , DESCRICAORESUMIDA
             , DESCRICAODETALHADA
             , TIPOPOLITICA
             , TIPOPROMOCAO
             , TIPORESTRICAO
             , DATAINICIAL
             , DATAFINAL
             , BASECREDDEBRCA
             , CREDITASOBREPOLITICA
             , CONSIDERACALCGIROMEDIC
             , UTILIZADESCREDE
             , TIPOPLANOPAG
             , APLICAFAMILIAPRODUTOS
             , ALTERADESCONTO
             , ENCARTEFECHADO
             , PRIORIZACOMISSAO
             , PRAZOPLPAGMANDATORIO
             , VALIDARINTERVALOVALIDADEPROD
             , DTINICIOPROMOLOTE
             , DTFIMPROMOLOTE
             , VLRMINITENSPROMOCAO
             , TIPOSIMPLESNACIONAL
             , PONTUARACORDOPARCERIA
             , PERMITECOMISSGARANTIDA
             , PERMITEQTMINIMASEMOBRIG
             , BLOQUEIO
             , VISUALIZARPROMOESP
             , CODFUNCULTALTERBLOQ
             , DTULTALTERBLOQ
             , UTILIZAPERCDESCBASERCA
             , PERMITIRAUMENTARQTDEKIT
             , NVL(ORIGEMPRECO,'T')
             , CODPRODBRINDE
             , USANORMALIZACAODESC
             , PARTICIPAPREMIACAOCLI
             , APLICADESCONTO
             , TIPOVALIDAVALORMIN -- HIS.01889.2017
             , TIPOCONCESSAOBRINDE -- HIS.01889.2017
             , QTDEBRINDE -- HIS.01889.2017
             , MULTIPLOSBRINDES -- HIS.01889.2017
             , CODBNF -- HIS.01889.2017
             , CAMINHOENCARTE
             , ACEITADESCPROMCAMPANHA
             , TIPOSOLICITANTE
             , CODSOLICITANTE
             , CASE WHEN (NVL(PRIORIZACOMISSAO,'N') = 'S') THEN
                 CODGRUPOCOMISSAO
               ELSE
                 NULL
               END CODGRUPOCOMISSAO
             , VALIDARMULTEMBMASTER
             , DESTACARULTCOMPRAS
             , PARTICIPAPREMIACAOIND
             , INCLUIRFILTROTELEVENDAS
             , ISENTOREBAIXACMV
             , TIPOCOTAGERAL
             , VALORCOTAGERAL
             , TIPOCOTACLIENTE
             , VALORCOTACLIENTE
             , TIPOLIMITADOR
             , QTMINCOMBOLIBMED
             , QTMAXCOMBOMED
             , CODLIBERACAOCANAIS
             , CODREFERENCIA
          INTO vvIdentificadorPromocao
             , vvDescricaoResumida
             , vvDescricaoDetalhada
             , vvTipoPolitica
             , vvTipoPromocao
             , vnTipoRestricao
             , vdDataInicial
             , vdDataFinal
             , vvBaseCredDebRca
             , vvCreditaSobrePolitica
             , vvConsideraCalcGiroMedic
             , vvUtilizaDescRede
             , vvTipoPlanoPag
             , vvAplicaFamiliaProdutos
             , vvAlteraDesconto
             , vvEncarteFechado
             , vvPriorizaComissao
             , vvPRAZOPLPAGMANDATORIO
             , vvVALIDARINTERVALOVALIDADEPROD
             , vvDTINICIOPROMOLOTE
             , vvDTFIMPROMOLOTE
             , vnVlrMinItensPromocao
             , vvTipoSimplesNacional
             , vvPontuarAcordoParceria
             , vvPermiteComissGarantida
             , vvPermiteQtMinimaSemObrig
             , vvBloqueio
             , vvVisualizaPromoEsp
             , vnCodFuncUltAlterBloq
             , vdDtUltAlterBloq
             , vvUtilizaPercDescBaseRca
             , vvPermitirAumentarQtdeKit
             , vvOrigemPreco
             , vnCodProdBrinde
             , vvUsaNormalizacaoDesc
             , vvParticipaPremiacaoCli
             , vvAplicaDesconto
             , vvTipoValidaValorMin -- HIS.01889.2017
             , vnTipoConcessaoBrinde -- HIS.01889.2017
             , vnQtdeBrinde -- HIS.01889.2017
             , vvMultiplosBrindes -- HIS.01889.2017
             , vnCodBnf -- HIS.01889.2017
             , vvCaminhoEncarte
             , vvAceitaDescPromCampanha
             , vvTipoSolicitante
             , vnCodSolicitante
             , vnCodGrupoComissao
             , vvValidarMultEmbMaster
             , vvDestacarUltCompras
             , vvParticipaPremiacaoInd
             , vvIncluirFiltroTelevendas
             , vvIsentoRebaixaCmnv
             , vvTipoCotaGeral
             , vnValorCotaGeral
             , vvTipoCotaCliente
             , vnValorCotaCliente
             , vnTipoLimitador
             , vnQtMinComboLibMed
             , vnQtMaxComboMed
             , vnCodLiberacaoCanais
             , vnCodReferencia
         FROM PCMED_PROMOCAO;
      EXCEPTION
        WHEN NO_DATA_FOUND THEN
          vvMsgErroGenerico := 'Não foram encontrados os dados da Promoção!';
          RAISE e_Generico;
        WHEN TOO_MANY_ROWS THEN
          vvMsgErroGenerico := 'Dados da Promoção duplicados!';
          RAISE e_Generico;
      END;

      -- Define Valor do Campo APENASPLPAGMAX
      IF (NVL(vvTipoPlanoPag,' ') = '2') THEN
        vvApenasPlPagMax := 'S';
      ELSE
        vvApenasPlPagMax := 'N';
      END IF;

      -- Define Valor do Campo
      IF    (NVL(vvTipoSimplesNacional,' ') = '1') THEN
        vvAplicaDescSimplesNacional := 'N';
      ELSIF (NVL(vvTipoSimplesNacional,' ') = '2') THEN
        vvAplicaDescSimplesNacional := 'S';
      ELSE
        vvAplicaDescSimplesNacional := 'T';
      END IF;

      -- Se chamado da Confirmação da inclusao ou alteração
      IF (pi_vTipoChamada in('2', '4', '8')) THEN

        ---------------------------------
        -- Comissão por Grupo de Comissão
        ---------------------------------
        -- Verifica se existem Grupos de Comissão
        BEGIN
          SELECT 'S'
            INTO vvExistemGruposComissao
           FROM PCGRUPOCOMISSAOMED
          WHERE (ROWNUM = 1);
        EXCEPTION
          WHEN NO_DATA_FOUND THEN
            vvExistemGruposComissao := 'N';
        END;
        -- Se existem Grupos de Comissão
        IF (vvExistemGruposComissao = 'S') THEN
          -- Pesquisa Grupo de Comissão da Promoção
          BEGIN
            SELECT CASE WHEN (NVL(PRIORIZACOMISSAO,'N') = 'S') THEN
                     CODGRUPOCOMISSAO
                   ELSE
                     NULL
                   END CODGRUPOCOMISSAO
              INTO vnCodGrupoComissao
             FROM PCMED_PROMOCAO;
          EXCEPTION
            WHEN NO_DATA_FOUND THEN
              vnCodGrupoComissao := NULL;
            WHEN TOO_MANY_ROWS THEN
              vnCodGrupoComissao := NULL;
          END;
          -- Promoção por Produto
          UPDATE PCMED_PROMOCAOPRODUTO
             SET PERCOMREP = (SELECT T.PERCENTUAL
                                FROM PCTABELACOMISSAOGRUPOMED T
                               WHERE T.CODGRUPO = vnCodGrupoComissao
                                 AND T.CAMPO    = 'MA'
                                 AND T.CODIGO   = (SELECT P.CODMARCA FROM PCPRODUT P WHERE P.CODPROD = PCMED_PROMOCAOPRODUTO.CODPROD))
               , PERCOMEXT = (SELECT T.PERCENTUAL
                                FROM PCTABELACOMISSAOGRUPOMED T
                               WHERE T.CODGRUPO = vnCodGrupoComissao
                                 AND T.CAMPO    = 'MA'
                                 AND T.CODIGO   = (SELECT P.CODMARCA FROM PCPRODUT P WHERE P.CODPROD = PCMED_PROMOCAOPRODUTO.CODPROD))
               , PERCOMMINT = (SELECT T.PERCENTUAL
                                 FROM PCTABELACOMISSAOGRUPOMED T
                                WHERE T.CODGRUPO = vnCodGrupoComissao
                                  AND T.CAMPO    = 'MA'
                                  AND T.CODIGO   = (SELECT P.CODMARCA FROM PCPRODUT P WHERE P.CODPROD = PCMED_PROMOCAOPRODUTO.CODPROD));
          -- Promoção por Produto/Faixa
          UPDATE PCMED_PROMOCAOPRODUTO_FAIXA
             SET PERCOMREP = (SELECT T.PERCENTUAL
                                FROM PCTABELACOMISSAOGRUPOMED T
                               WHERE T.CODGRUPO = vnCodGrupoComissao
                                 AND T.CAMPO    = 'MA'
                                 AND T.CODIGO   = (SELECT P.CODMARCA FROM PCPRODUT P WHERE P.CODPROD = PCMED_PROMOCAOPRODUTO_FAIXA.CODPRODREF))
               , PERCOMEXT = (SELECT T.PERCENTUAL
                                FROM PCTABELACOMISSAOGRUPOMED T
                               WHERE T.CODGRUPO = vnCodGrupoComissao
                                 AND T.CAMPO    = 'MA'
                                 AND T.CODIGO   = (SELECT P.CODMARCA FROM PCPRODUT P WHERE P.CODPROD = PCMED_PROMOCAOPRODUTO_FAIXA.CODPRODREF))
               , PERCOMMINT = (SELECT T.PERCENTUAL
                                 FROM PCTABELACOMISSAOGRUPOMED T
                                WHERE T.CODGRUPO = vnCodGrupoComissao
                                  AND T.CAMPO    = 'MA'
                                  AND T.CODIGO   = (SELECT P.CODMARCA FROM PCPRODUT P WHERE P.CODPROD = PCMED_PROMOCAOPRODUTO_FAIXA.CODPRODREF));
          -- Promoção por Marca
          UPDATE PCMED_PROMOCAOMARCA
             SET PERCOMREP = (SELECT T.PERCENTUAL
                                FROM PCTABELACOMISSAOGRUPOMED T
                               WHERE T.CODGRUPO = vnCodGrupoComissao
                                 AND T.CAMPO    = 'MA'
                                 AND T.CODIGO   = PCMED_PROMOCAOMARCA.CODMARCA)
               , PERCOMEXT = (SELECT T.PERCENTUAL
                                FROM PCTABELACOMISSAOGRUPOMED T
                               WHERE T.CODGRUPO = vnCodGrupoComissao
                                 AND T.CAMPO    = 'MA'
                                 AND T.CODIGO   = PCMED_PROMOCAOMARCA.CODMARCA)
               , PERCOMMINT = (SELECT T.PERCENTUAL
                                 FROM PCTABELACOMISSAOGRUPOMED T
                                WHERE T.CODGRUPO = vnCodGrupoComissao
                                  AND T.CAMPO    = 'MA'
                                  AND T.CODIGO   = PCMED_PROMOCAOMARCA.CODMARCA);
          -- Promoção por Marca/Faixa
          UPDATE PCMED_PROMOCAOMARCA_FAIXA
             SET PERCOMREP = (SELECT T.PERCENTUAL
                                FROM PCTABELACOMISSAOGRUPOMED T
                               WHERE T.CODGRUPO = vnCodGrupoComissao
                                 AND T.CAMPO    = 'MA'
                                 AND T.CODIGO   = PCMED_PROMOCAOMARCA_FAIXA.CODMARCAREF)
               , PERCOMEXT = (SELECT T.PERCENTUAL
                                FROM PCTABELACOMISSAOGRUPOMED T
                               WHERE T.CODGRUPO = vnCodGrupoComissao
                                 AND T.CAMPO    = 'MA'
                                 AND T.CODIGO   = PCMED_PROMOCAOMARCA_FAIXA.CODMARCAREF)
               , PERCOMMINT = (SELECT T.PERCENTUAL
                                 FROM PCTABELACOMISSAOGRUPOMED T
                                WHERE T.CODGRUPO = vnCodGrupoComissao
                                  AND T.CAMPO    = 'MA'
                                  AND T.CODIGO   = PCMED_PROMOCAOMARCA_FAIXA.CODMARCAREF);
        END IF; -- Fim Condição: Existem Grupos de Comissão
      END IF;		 

      -- Se chamado da Confirmação da alteração
      IF (pi_vTipoChamada = '4') THEN
        ---------------------------------
        -- Edição de Produtos da Promoção
        ---------------------------------

        -- Guarda Valores de Restrições após edição do usuário
        INSERT INTO PCMED_PROMOCAORESTRICOES(TIPOREG, TIPOCODIGO, CODIGO) SELECT 'NEW' TIPOREG, 'OP' TIPOCODIGO, ORIGEMPED              FROM PCMED_PROMOCAOORIGEM;

        -- Guarda Valores de Políticas de Produtos após edição do usuário
        P_INSERE_PROMOCAOPOLITICAS(pi_nCodPromocao, 
                                   'PCMED_PROMOCAOPRODUTO',
                                   'CODPROD',
                                   'Npr',
                                   vvTipoPromocao, vvTipoPolitica);

        -- Guarda Valores de Políticas de Fornecedores após edição do usuário
        P_INSERE_PROMOCAOPOLITICAS(pi_nCodPromocao, 
                                   'PCMED_PROMOCAOFORNEC',
                                   'CODFORNEC',
                                   'Nfr',
                                   vvTipoPromocao, vvTipoPolitica);

        -- Guarda Valores de Políticas de Marcas após edição do usuário
        P_INSERE_PROMOCAOPOLITICAS(pi_nCodPromocao, 
                                   'PCMED_PROMOCAOMARCA',
                                   'CODMARCA',
                                   'Nma',
                                   vvTipoPromocao, vvTipoPolitica);

        -- Guarda Valores de Políticas de Linhas após edição do usuário
        P_INSERE_PROMOCAOPOLITICAS(pi_nCodPromocao, 
                                   'PCMED_PROMOCAOLINHAPROD',
                                   'CODLINHAPROD',
                                   'Nln',
                                   vvTipoPromocao, vvTipoPolitica);

        -- Guarda Valores de Políticas de Departamento após edição do usuário
        P_INSERE_PROMOCAOPOLITICAS(pi_nCodPromocao, 
                                   'PCMED_PROMOCAODEPTO',
                                   'CODEPTO',
                                   'Ndp',
                                   vvTipoPromocao, vvTipoPolitica);

        -- Guarda Valores de Políticas de Seção após edição do usuário
        P_INSERE_PROMOCAOPOLITICAS(pi_nCodPromocao, 
                                   'PCMED_PROMOCAOSECAO',
                                   'CODSEC',
                                   'Nsc',
                                   vvTipoPromocao, vvTipoPolitica);

        -- Guarda Valores de Políticas de Categoria após edição do usuário
        P_INSERE_PROMOCAOPOLITICAS(pi_nCodPromocao, 
                                   'PCMED_PROMOCAOCATEG',
                                   'CODCATEGORIA',
                                   'Nct',
                                   vvTipoPromocao, vvTipoPolitica);

        -- Guarda Valores de Políticas de Grupo de Produtos após edição do usuário
        P_INSERE_PROMOCAOPOLITICAS(pi_nCodPromocao, 
                                   'PCMED_PROMOCAORESTGRUPRO',
                                   'CODGRUPO',
                                   'Ngp',
                                   vvTipoPromocao, vvTipoPolitica);

        -- Variável de Controle para Indicar que os Produtos podem ser Editados
        vrEditarPromocao.vvPermiteEditarProduto := FPERMITE_EDITAR_PRODUTOS;

        -- Chama Procedimento interno para inserir no Log os dados atuais
        PINSERE_LOG;

        -- Se permite editar Produto
        IF (NVL(vrEditarPromocao.vvPermiteEditarProduto,'N') = 'S') THEN
          -- Exclui somente os Produtos que não estão mais na Promoção
          P_REMOVE_PROMOCAOPOLITICAS(pi_nCodPromocao, 
                                     'CODPROD',
                                     'pr',
                                     vvTipoPromocao);
          -- Exclui somente os Fornecedores que não estão mais na Promoção
          P_REMOVE_PROMOCAOPOLITICAS(pi_nCodPromocao, 
                                     'CODFORNEC',
                                     'fr',
                                     vvTipoPromocao);
          -- Exclui somente as Marcas que não estão mais na Promoção
          P_REMOVE_PROMOCAOPOLITICAS(pi_nCodPromocao, 
                                     'CODMARCA',
                                     'ma',
                                     vvTipoPromocao);
          -- Exclui somente as Linhas que não estão mais na Promoção
          P_REMOVE_PROMOCAOPOLITICAS(pi_nCodPromocao, 
                                     'CODLINHAPROD',
                                     'ln',
                                     vvTipoPromocao);
          -- Exclui somente os Departamentos que não estão mais na Promoção
          P_REMOVE_PROMOCAOPOLITICAS(pi_nCodPromocao, 
                                     'CODEPTO',
                                     'dp',
                                     vvTipoPromocao);
          -- Exclui somente as Seções que não estão mais na Promoção
          P_REMOVE_PROMOCAOPOLITICAS(pi_nCodPromocao, 
                                     'CODSEC',
                                     'sc',
                                     vvTipoPromocao);
          -- Exclui somente as Categorias que não estão mais na Promoção
          P_REMOVE_PROMOCAOPOLITICAS(pi_nCodPromocao, 
                                     'CODCATEGORIA',
                                     'ct',
                                     vvTipoPromocao);
          -- Exclui somente os Grupos que não estão mais na Promoção
          P_REMOVE_PROMOCAOPOLITICAS(pi_nCodPromocao, 
                                     'CODGRUPOREST',
                                     'gp',
                                     vvTipoPromocao);
        -- Se NÃO permite editar Produto
        ELSE
          DELETE FROM PCDESCONTO
           WHERE (CODPROMOCAOMED = pi_nCodPromocao);
        END IF;
        -- Apaga dados atuais para serem
        -- inseridos novamente a partir das tabelas temporárias
        DELETE FROM PCDESCQUANT
         WHERE (CODPROMOCAOMED = pi_nCodPromocao);
        DELETE FROM PCPROMOCAOFILMED
         WHERE (CODPROMOCAOMED = pi_nCodPromocao);
        -- Normalização PCDESCONTO
        DELETE FROM PCPROMOCAOORIGEMMED      WHERE (CODPROMOCAOMED = pi_nCodPromocao);
        DELETE FROM PCPROMOCAOCLIMED         WHERE (CODPROMOCAOMED = pi_nCodPromocao);
        DELETE FROM PCPROMOCAOREDEMED        WHERE (CODPROMOCAOMED = pi_nCodPromocao);
        DELETE FROM PCPROMOCAOUSURMED        WHERE (CODPROMOCAOMED = pi_nCodPromocao);
        DELETE FROM PCPROMOCAOSUPERVMED      WHERE (CODPROMOCAOMED = pi_nCodPromocao);
        DELETE FROM PCPROMOCAOPRACAMED       WHERE (CODPROMOCAOMED = pi_nCodPromocao);
        DELETE FROM PCPROMOCAOREGIAOMED      WHERE (CODPROMOCAOMED = pi_nCodPromocao);
        DELETE FROM PCPROMOCAOPLPAGMED       WHERE (CODPROMOCAOMED = pi_nCodPromocao);
        DELETE FROM PCPROMOCAOCONDVENDAMED   WHERE (CODPROMOCAOMED = pi_nCodPromocao);
        DELETE FROM PCPROMOCAORAMOATIVMED    WHERE (CODPROMOCAOMED = pi_nCodPromocao);
        DELETE FROM PCPROMOCAOCLASSEVENDAMED WHERE (CODPROMOCAOMED = pi_nCodPromocao);
        DELETE FROM PCPROMOCAOGRUPOCOMERCMED WHERE (CODPROMOCAOMED = pi_nCodPromocao);
        DELETE FROM PCPROMOCAOAREAATUACAOMED WHERE (CODPROMOCAOMED = pi_nCodPromocao);
        --
        DELETE FROM PCPROMOCAOTELEVMED       WHERE (CODPROMOCAOMED = pi_nCodPromocao);
        --
        DELETE FROM PCPROMOCAOBRINDEMED      WHERE (CODPROMOCAOMED = pi_nCodPromocao); -- HIS.01889.2017
        --
        DELETE FROM PCPROMOCAOVERBAMED       WHERE (CODPROMOCAOMED = pi_nCodPromocao); -- HIS.01889.2017
        --
        DELETE FROM PCPROMOCAOMED
         WHERE (CODPROMOCAOMED = pi_nCodPromocao);

      END IF;

      ----------------------------------------------------------------------------
      -- Insere Cabeçalho da Promoção
      -------------------------------

      -- Se chamado da Inclusão da Promoção
      IF    (pi_vTipoChamada = '2') THEN
        -- Gera novo Sequencial de Promoção
        vnNovoCodPromocaoMed  := FOBTEM_PROX_CODPROMOCAOMED;
        po_nCodPromocaoGerado := vnNovoCodPromocaoMed;
      -- Se chamado da Confirmação da alteração
      ELSIF (pi_vTipoChamada = '4') THEN
        -- O Sequencial de Promoção será mantido
        vnNovoCodPromocaoMed := pi_nCodPromocao;
      -- Se chamado da Confirmação de uma replicação
      ELSIF (pi_vTipoChamada = '8') THEN
        -- O Sequencial de Promoção será mantido
        vnNovoCodPromocaoMed  := pi_nCodPromocao;
        po_nCodPromocaoGerado := vnNovoCodPromocaoMed;
      END IF;

      -- Insere Cabeçalho da Promoção
      INSERT INTO PCPROMOCAOMED (
                  CODPROMOCAOMED
                , IDENTIFICADORPROMOCAO
                , TIPOPOLITICA
                , DESCRICAORESUMIDA
                , DESCRICAODETALHADA
                , DATAINICIAL
                , DATAFINAL
                , TIPOPROMOCAO
                , TIPORESTRICAO
                , BASECREDDEBRCA
                , CREDITASOBREPOLITICA
                , CONSIDERACALCGIROMEDIC
                , UTILIZADESCREDE
                , TIPOPLANOPAG
                , APLICAFAMILIAPRODUTOS
                , ALTERADESCONTO
                , CODFUNCLANC
                , DATALANC
                , ENCARTEFECHADO
                , PRIORIZACOMISSAO
                , PRAZOPLPAGMANDATORIO
                , VALIDARINTERVALOVALIDADEPROD
                , DTINICIOPROMOLOTE
                , DTFIMPROMOLOTE
                , VLRMINITENSPROMOCAO
                , TIPOSIMPLESNACIONAL
                , PONTUARACORDOPARCERIA
                , PERMITECOMISSGARANTIDA
                , PERMITEQTMINIMASEMOBRIG
                , BLOQUEIO
                , VISUALIZARPROMOESP
                , CODFUNCULTALTERBLOQ
                , DTULTALTERBLOQ
                , UTILIZAPERCDESCBASERCA
                , PERMITIRAUMENTARQTDEKIT
                , ORIGEMPRECO
                , CODPRODBRINDE
                , USANORMALIZACAODESC
                , PARTICIPAPREMIACAOCLI
                , APLICADESCONTO
                , TIPOVALIDAVALORMIN -- HIS.01889.2017
                , TIPOCONCESSAOBRINDE -- HIS.01889.2017
                , QTDEBRINDE -- HIS.01889.2017
                , MULTIPLOSBRINDES -- HIS.01889.2017
                , CODBNF -- HIS.01889.2017
                , CAMINHOENCARTE
                , ACEITADESCPROMCAMPANHA
                , TIPOSOLICITANTE
                , CODSOLICITANTE
                , CODGRUPOCOMISSAO
                , VALIDARMULTEMBMASTER
                , DESTACARULTCOMPRAS
                , PARTICIPAPREMIACAOIND
                , INCLUIRFILTROTELEVENDAS
                , ISENTOREBAIXACMV
                , TIPOCOTAGERAL
                , VALORCOTAGERAL
                , TIPOCOTACLIENTE
                , VALORCOTACLIENTE
                , TIPOLIMITADOR
                , QTMINCOMBOLIBMED
                , QTMAXCOMBOMED
                , CODLIBERACAOCANAIS
                , CODREFERENCIA
                )
         VALUES ( vnNovoCodPromocaoMed -->> Novo Sequencial de Promoção
                , vvIdentificadorPromocao
                , vvTipoPolitica
                , vvDescricaoResumida
                , vvDescricaoDetalhada
                , vdDataInicial
                , vdDataFinal
                , vvTipoPromocao
                , vnTipoRestricao
                , vvBaseCredDebRca
                , vvCreditaSobrePolitica
                , vvConsideraCalcGiroMedic
                , vvUtilizaDescRede
                , vvTipoPlanoPag
                , vvAplicaFamiliaProdutos
                , vvAlteraDesconto
                , pi_nCodFunc
                , SYSDATE
                , vvEncarteFechado
                , vvPriorizaComissao
                , vvPRAZOPLPAGMANDATORIO
                , vvVALIDARINTERVALOVALIDADEPROD
                , vvDTINICIOPROMOLOTE
                , vvDTFIMPROMOLOTE
                , vnVlrMinItensPromocao
                , vvTipoSimplesNacional
                , vvPontuarAcordoParceria
                , vvPermiteComissGarantida
                , vvPermiteQtMinimaSemObrig
                , vvBloqueio
                , vvVisualizaPromoEsp
                , pi_nCodFunc
                , SYSDATE
                , vvUtilizaPercDescBaseRca
                , vvPermitirAumentarQtdeKit
                , NVL(vvOrigemPreco,'T')
                , vnCodProdBrinde
                , 'S'
                , vvParticipaPremiacaoCli
                , vvAplicaDesconto
                , vvTipoValidaValorMin -- HIS.01889.2017
                , vnTipoConcessaoBrinde -- HIS.01889.2017
                , vnQtdeBrinde -- HIS.01889.2017
                , vvMultiplosBrindes -- HIS.01889.2017
                , vnCodBnf -- HIS.01889.2017
                , vvCaminhoEncarte
                , vvAceitaDescPromCampanha
                , vvTipoSolicitante
                , vnCodSolicitante
                , vnCodGrupoComissao
                , vvValidarMultEmbMaster
                , vvDestacarUltCompras
                , vvParticipaPremiacaoInd
                , vvIncluirFiltroTelevendas
                , vvIsentoRebaixaCmnv
                , vvTipoCotaGeral
                , vnValorCotaGeral
                , vvTipoCotaCliente
                , vnValorCotaCliente
                , vnTipoLimitador
                , vnQtMinComboLibMed
                , vnQtMaxComboMed
                , vnCodLiberacaoCanais
                , vnCodReferencia
                );

      ----------------------------------------------------------------------------
      -- Carrega Arrays a partir das Tabelas Temporárias
      --------------------------------------------------

      -- Log Alteração
      --IF (pi_vTipoChamada = '4') THEN INSERT INTO PCMED_LOGALTERACAO_PROMOCAO VALUES (SYSDATE, pi_nCodPromocao, 'Carregando Arrays'); END IF;

      -- Carrega Array com as Origens informadas
      -- (ORIGENS SERÁ O ÚNICO PRODUTO CARTESIANO NA PCDESCONTO COM NORMALIZAÇÃO (IMPACTO por causa do TIPOFV nas Querys)
      SELECT *
        BULK COLLECT INTO vtPCMED_PROMOCAOORIGEM
        FROM PCMED_PROMOCAOORIGEM;
      -- Se não informou Origens, insere uma linha em branco
      IF (vtPCMED_PROMOCAOORIGEM.COUNT = 0) THEN
        vtPCMED_PROMOCAOORIGEM(1).ORIGEMPED := NULL;
      END IF;

      --*******************************
      -- COM NORMALIZAÇÃO NA PCDESCONTO
      --*******************************

      -- Arrays que não podem ficar vazios
      vtPCMED_PROMOCAOFIL(1).CODFILIAL                    := NULL;
      vtPCMED_PROMOCAOREG(1).NUMREGIAO                    := NULL;
      vtPCMED_PROMOCAOPRACA(1).CODPRACA                   := NULL;
      vtPCMED_PROMOCAOATIV(1).CODATIV                     := NULL;
      vtPCMED_PROMOCAOPLPAG(1).CODPLPAG                   := NULL;
      vtPCMED_PROMOCAOCONDVENDA(1).CODCONDICAOVENDA       := NULL;
      vtPCMED_PROMOCAOCLASSE(1).CLASSE                    := NULL;
      vtPCMED_PROMOCAOGRUPOCOMERC(1).CODGRUPOCOMERCIALMED := NULL;

      --***************************************
      -- INICIO: SEM NORMALIZAÇÃO NA PCDESCONTO
      --***************************************
      IF (NVL(FUSA_REGRA_NORMALIZA_DESC,'N') = 'N') THEN

        -- Carrega Array com as Regiões informadas
        SELECT *
          BULK COLLECT INTO vtPCMED_PROMOCAOREG
          FROM PCMED_PROMOCAOREG;
        -- Se não informou Origens, insere uma linha em branco
        IF (vtPCMED_PROMOCAOREG.COUNT = 0) THEN
          vtPCMED_PROMOCAOREG(1).NUMREGIAO := NULL;
        END IF;

        -- Carrega Array com as Praças informadas
        SELECT *
          BULK COLLECT INTO vtPCMED_PROMOCAOPRACA
          FROM PCMED_PROMOCAOPRACA;
        -- Se não informou Praças, insere uma linha em branco
        IF (vtPCMED_PROMOCAOPRACA.COUNT = 0) THEN
          vtPCMED_PROMOCAOPRACA(1).CODPRACA := NULL;
        END IF;

        -- Carrega Array com as Atividades informadas
        IF ((vnTipoRestricao NOT IN (1, 4))) THEN -- Não for Rede/Cliente
          SELECT *
            BULK COLLECT INTO vtPCMED_PROMOCAOATIV
            FROM PCMED_PROMOCAOATIV;
          -- Se não informou Atividades, insere uma linha em branco
          IF (vtPCMED_PROMOCAOATIV.COUNT = 0) THEN
            vtPCMED_PROMOCAOATIV(1).CODATIV := NULL;
          END IF;
        ELSE
          vtPCMED_PROMOCAOATIV(1).CODATIV := NULL;
        END IF;

        -- Carrega Array com as Redes informadas
        -- (Pode ficar sem dados no Array)
        IF ((vnTipoRestricao IN (1, 4))) THEN -- Se Rede/Cliente
          SELECT *
            BULK COLLECT INTO vtPCMED_PROMOCAOREDE
            FROM PCMED_PROMOCAOREDE;
        END IF;

        -- Carrega Array com os Clientes informados
        -- (Pode ficar sem dados no Array)
        IF ((vnTipoRestricao IN (1, 4))) THEN -- Se Rede/Cliente
          SELECT *
            BULK COLLECT INTO vtPCMED_PROMOCAOCLI
            FROM PCMED_PROMOCAOCLI;
        END IF;

        -- Carrega Array com as Áreas informadas
        -- (Pode ficar sem dados no Array)
        IF ((vnTipoRestricao IN (3))) THEN -- Se Área Atuação
          SELECT *
            BULK COLLECT INTO vtPCMED_PROMOCAOAREA
            FROM PCMED_PROMOCAOAREA;
        END IF;

        -- Carrega Array com os Supervisores informados
        -- (Pode ficar sem dados no Array)
        IF ((vnTipoRestricao IN (2, 4))) THEN -- Se Supervisor/RCA
          SELECT *
            BULK COLLECT INTO vtPCMED_PROMOCAOSUP
            FROM PCMED_PROMOCAOSUP;
        END IF;

        -- Carrega Array com os RCA's informados
        -- (Pode ficar sem dados no Array)
        IF ((vnTipoRestricao IN (2, 4))) THEN -- Se Supervisor/RCA
          SELECT *
            BULK COLLECT INTO vtPCMED_PROMOCAOUSUR
            FROM PCMED_PROMOCAOUSUR;
        END IF;

        -- Carrega Array com Planos de Pagamento informados
        SELECT *
          BULK COLLECT INTO vtPCMED_PROMOCAOPLPAG
          FROM PCMED_PROMOCAOPLPAG;
        -- Se não informou Planos de Pagamento, insere uma linha em branco
        IF (vtPCMED_PROMOCAOPLPAG.COUNT = 0) THEN
          vtPCMED_PROMOCAOPLPAG(1).CODPLPAG := NULL;
        END IF;

        -- Carrega Array com as Condições de Venda informadas
        SELECT *
          BULK COLLECT INTO vtPCMED_PROMOCAOCONDVENDA
          FROM PCMED_PROMOCAOCONDVENDA;
        -- Se não informou Condições de Venda, insere uma linha em branco
        IF (vtPCMED_PROMOCAOCONDVENDA.COUNT = 0) THEN
          vtPCMED_PROMOCAOCONDVENDA(1).CODCONDICAOVENDA := NULL;
        END IF;

        -- Carrega Array com as Classes informadas
        -- Carrega Array com os Grupos Comerciais informados
        -- DDMEDICA-1104 (Somente carregará as inf se a promoção for "Sem Restrições")
        IF ((nvl(vnTipoRestricao,0) IN (0))) THEN
          SELECT *
            BULK COLLECT INTO vtPCMED_PROMOCAOCLASSE
            FROM PCMED_PROMOCAOCLASSE;
          --
          SELECT *
            BULK COLLECT INTO vtPCMED_PROMOCAOGRUPOCOMERC
            FROM PCMED_PROMOCAOGRUPOCOMERC;
        END IF;
        -- Se não informou Classes, insere uma linha em branco
        IF (vtPCMED_PROMOCAOCLASSE.COUNT = 0) THEN
          vtPCMED_PROMOCAOCLASSE(1).CLASSE := NULL;
        END IF;
        -- Se não informou Grupos Comerciais, insere uma linha em branco
        IF (vtPCMED_PROMOCAOGRUPOCOMERC.COUNT = 0) THEN
          vtPCMED_PROMOCAOGRUPOCOMERC(1).CODGRUPOCOMERCIALMED := NULL;
        END IF;
      END IF; -- Fim Condição: Se não Usa Normalização
      --************************************
      -- FIM: SEM NORMALIZAÇÃO NA PCDESCONTO
      --************************************

      -- Carrega Array com os Departamentos informados
      IF (vvTipoPolitica IN ('D','Q','B','M','V')) THEN  -- Se Desconto/Desconto ou BonifMerc por Quantidade/Markup
        SELECT *
          BULK COLLECT INTO vtPCMED_PROMOCAODEPTO
          FROM PCMED_PROMOCAODEPTO;
        -- Se não informou Departamentos, insere uma linha em branco
        IF (vtPCMED_PROMOCAODEPTO.COUNT = 0) THEN
          vtPCMED_PROMOCAODEPTO(1).CODEPTO := NULL;
        END IF;
      ELSE
        vtPCMED_PROMOCAODEPTO(1).CODEPTO := NULL;
      END IF;

      -- Carrega Array com as Seções informadas
      IF (vvTipoPolitica IN ('D','Q','B','M','V')) THEN  -- Se Desconto/Desconto ou BonifMerc por Quantidade/Markup
        SELECT *
          BULK COLLECT INTO vtPCMED_PROMOCAOSECAO
          FROM PCMED_PROMOCAOSECAO;
        -- Se não informou Seções, insere uma linha em branco
        IF (vtPCMED_PROMOCAOSECAO.COUNT = 0) THEN
          vtPCMED_PROMOCAOSECAO(1).CODSEC := NULL;
        END IF;
      ELSE
        vtPCMED_PROMOCAOSECAO(1).CODSEC := NULL;
      END IF;

      -- Carrega Array com as Categorias informadas
      IF (vvTipoPolitica IN ('D','Q','B','M','V')) THEN  -- Se Desconto/Desconto ou BonifMerc por Quantidade/Markup
        SELECT *
          BULK COLLECT INTO vtPCMED_PROMOCAOCATEG
          FROM PCMED_PROMOCAOCATEG;
        -- Se não informou Categorias, insere uma linha em branco
        IF (vtPCMED_PROMOCAOCATEG.COUNT = 0) THEN
          vtPCMED_PROMOCAOCATEG(1).CODCATEGORIA := NULL;
        END IF;
      ELSE
        vtPCMED_PROMOCAOCATEG(1).CODCATEGORIA := NULL;
      END IF;

      -- Carrega Array com os Fornecedores informados
      -- (Pode ficar sem dados no Array)
      IF (vvTipoPolitica IN ('D','Q','B','M','V')) THEN  -- Se Desconto/Desconto ou BonifMerc por Quantidade/Markup
        SELECT *
          BULK COLLECT INTO vtPCMED_PROMOCAOFORNEC
          FROM PCMED_PROMOCAOFORNEC;
      END IF;

      -- Carrega Array com as Marcas informadas
      -- (Pode ficar sem dados no Array)
      IF (vvTipoPolitica IN ('D','Q','B','M','V')) THEN  -- Se Desconto/Desconto ou BonifMerc por Quantidade/Markup
        SELECT *
          BULK COLLECT INTO vtPCMED_PROMOCAOMARCA
          FROM PCMED_PROMOCAOMARCA;
      END IF;

      -- Carrega Array com as Linhas de Produto informados
      -- (Pode ficar sem dados no Array)
      IF (vvTipoPolitica IN ('D','Q','B','M','V')) THEN  -- Se Desconto/Desconto ou BonifMerc por Quantidade/Markup
        SELECT *
          BULK COLLECT INTO vtPCMED_PROMOCAOLINHAPROD
          FROM PCMED_PROMOCAOLINHAPROD;
      END IF;

      -- Carrega Array com os Grupos de Produtos informados - HIS.01889.2017
      -- (Pode ficar sem dados no Array)
      IF (vvTipoPolitica IN ('D','Q','B','M','V')) THEN  -- Se Desconto/Desconto ou BonifMerc por Quantidade/Markup
        SELECT *
          BULK COLLECT INTO vtPCMED_PROMOCAORESTGRUPRO
          FROM PCMED_PROMOCAORESTGRUPRO;
      END IF;

      -- Carrega Array com os Produtos informados
      -- (Pode ficar sem dados no Array)
      IF (vvTipoPolitica IN ('D','Q','P','F','B','M','V')) THEN  -- Se Desconto/Desconto ou BonifMerc por Quantidade por Quantidade/Preço Fixo/Preço por Quantidade/Markup
        SELECT *
          BULK COLLECT INTO vtPCMED_PROMOCAOPRODUTO
          FROM PCMED_PROMOCAOPRODUTO;
      END IF;

      ----------------------------------------------------------------------------
      -- Processamento dos Arrays
      ---------------------------

      -- Log Alteração
      --IF (pi_vTipoChamada = '4') THEN INSERT INTO PCMED_LOGALTERACAO_PROMOCAO VALUES (SYSDATE, pi_nCodPromocao, 'Processando Arrays'); END IF;

      -- Laço de Origens
      FOR idxOrigem IN vtPCMED_PROMOCAOORIGEM.FIRST..vtPCMED_PROMOCAOORIGEM.LAST LOOP
        -- Laço de Filiais
        FOR idxFilial IN vtPCMED_PROMOCAOFIL.FIRST..vtPCMED_PROMOCAOFIL.LAST LOOP
          -- Laço de Regiões
          FOR idxRegiao IN vtPCMED_PROMOCAOREG.FIRST..vtPCMED_PROMOCAOREG.LAST LOOP
            -- Laço de Praças
            FOR idxPraca IN vtPCMED_PROMOCAOPRACA.FIRST..vtPCMED_PROMOCAOPRACA.LAST LOOP
              -- Laço de Atividades
              FOR idxAtiv IN vtPCMED_PROMOCAOATIV.FIRST..vtPCMED_PROMOCAOATIV.LAST LOOP
                -- Laço de Classes
                FOR idxClasse IN vtPCMED_PROMOCAOCLASSE.FIRST..vtPCMED_PROMOCAOCLASSE.LAST LOOP
                  -- Laço de Planos de Pagamento
                  FOR idxPlPag IN vtPCMED_PROMOCAOPLPAG.FIRST..vtPCMED_PROMOCAOPLPAG.LAST LOOP
                    -- Laço de Condições de Venda
                    FOR idxCondVenda IN vtPCMED_PROMOCAOCONDVENDA.FIRST..vtPCMED_PROMOCAOCONDVENDA.LAST LOOP

                      -- Inicializa flag para indicar se foi usado qualquer tipo de Restrição
                      vbUsouRestricao := FALSE;

                      -- Preenche variáveis com os valores dos Arrays para atualização da PCDESCONTO
                      vrDESCONTO.vCODFILIAL        := vtPCMED_PROMOCAOFIL(idxFilial).CODFILIAL;
                      vrDESCONTO.nNUMREGIAO        := vtPCMED_PROMOCAOREG(idxRegiao).NUMREGIAO;
                      vrDESCONTO.nCODPRACA         := vtPCMED_PROMOCAOPRACA(idxPraca).CODPRACA;
                      vrDESCONTO.nCODATIV          := vtPCMED_PROMOCAOATIV(idxAtiv).CODATIV;
                      vrDESCONTO.vCLASSEVENDA      := vtPCMED_PROMOCAOCLASSE(idxClasse).CLASSE;
                      vrDESCONTO.nCODPLPAG         := vtPCMED_PROMOCAOPLPAG(idxPlPag).CODPLPAG;
                      vrDESCONTO.nCODCONDICAOVENDA := vtPCMED_PROMOCAOCONDVENDA(idxCondVenda).CODCONDICAOVENDA;
                      -- Define Variáveis que definem se Aplica Operador Logístico ou Pedido Eletrônico
                      IF    (NVL(vtPCMED_PROMOCAOORIGEM(idxOrigem).ORIGEMPED,'T') = 'T') THEN
                        vrDESCONTO.vORIGEMPED      := 'T';
                        vrDESCONTO.vTIPOFV         := NULL;
                        vrDESCONTO.vAPLICAOPERLOG  := 'N';
                        vrDESCONTO.vAPLICAPEDELET  := 'N';
                        vrDESCONTO.vENVIAFV        := 'N';
                        vrDESCONTO.vTIPOVENDA      := NULL;
                      ELSIF (NVL(vtPCMED_PROMOCAOORIGEM(idxOrigem).ORIGEMPED,'T') = 'L') THEN
                        vrDESCONTO.vORIGEMPED      := 'F';
                        vrDESCONTO.vTIPOFV         := 'OL';
                        vrDESCONTO.vAPLICAOPERLOG  := 'S';
                        vrDESCONTO.vAPLICAPEDELET  := 'N';
                        vrDESCONTO.vENVIAFV        := 'N';
                        vrDESCONTO.vTIPOVENDA      := NULL;
                      ELSIF (NVL(vtPCMED_PROMOCAOORIGEM(idxOrigem).ORIGEMPED,'T') = 'E') THEN
                        vrDESCONTO.vORIGEMPED      := 'F';
                        vrDESCONTO.vTIPOFV         := 'PE';
                        vrDESCONTO.vAPLICAOPERLOG  := 'N';
                        vrDESCONTO.vAPLICAPEDELET  := 'S';
                        vrDESCONTO.vENVIAFV        := 'N';
                        vrDESCONTO.vTIPOVENDA      := NULL;
                      ELSIF (NVL(vtPCMED_PROMOCAOORIGEM(idxOrigem).ORIGEMPED,'T') = 'F') THEN
                        vrDESCONTO.vORIGEMPED      := 'F';
                        vrDESCONTO.vTIPOFV         := NULL;
                        vrDESCONTO.vAPLICAOPERLOG  := 'N';
                        vrDESCONTO.vAPLICAPEDELET  := 'N';
                        vrDESCONTO.vENVIAFV        := 'S';
                        vrDESCONTO.vTIPOVENDA      := NULL;
                      ELSIF (NVL(vtPCMED_PROMOCAOORIGEM(idxOrigem).ORIGEMPED,'T') = 'V') THEN
                        vrDESCONTO.vORIGEMPED      := 'B';
                        vrDESCONTO.vTIPOFV         := NULL;
                        vrDESCONTO.vAPLICAOPERLOG  := 'N';
                        vrDESCONTO.vAPLICAPEDELET  := 'N';
                        vrDESCONTO.vENVIAFV        := 'N';
                        vrDESCONTO.vTIPOVENDA      := 'PA';
                      ELSIF (NVL(vtPCMED_PROMOCAOORIGEM(idxOrigem).ORIGEMPED,'T') = 'D') THEN
                        vrDESCONTO.vORIGEMPED      := 'B';
                        vrDESCONTO.vTIPOFV         := NULL;
                        vrDESCONTO.vAPLICAOPERLOG  := 'N';
                        vrDESCONTO.vAPLICAPEDELET  := 'N';
                        vrDESCONTO.vENVIAFV        := 'N';
                        vrDESCONTO.vTIPOVENDA      := 'PC';
                      ELSIF (NVL(vtPCMED_PROMOCAOORIGEM(idxOrigem).ORIGEMPED,'T') = 'G') THEN
                        vrDESCONTO.vORIGEMPED      := 'T';
                        vrDESCONTO.vTIPOFV         := NULL;
                        vrDESCONTO.vAPLICAOPERLOG  := 'N';
                        vrDESCONTO.vAPLICAPEDELET  := 'N';
                        vrDESCONTO.vENVIAFV        := 'N';
                        vrDESCONTO.vTIPOVENDA      := 'PG';
                      ELSE
                        vrDESCONTO.vORIGEMPED      := vtPCMED_PROMOCAOORIGEM(idxOrigem).ORIGEMPED;
                        vrDESCONTO.vTIPOFV         := NULL;
                        vrDESCONTO.vAPLICAOPERLOG  := 'N';
                        vrDESCONTO.vAPLICAPEDELET  := 'N';
                        vrDESCONTO.vENVIAFV        := 'N';
                        vrDESCONTO.vTIPOVENDA      := NULL;
                      END IF;

                      -- Laço de Redes
                      IF (vtPCMED_PROMOCAOREDE.COUNT > 0) THEN
                        FOR idxRede IN vtPCMED_PROMOCAOREDE.FIRST..vtPCMED_PROMOCAOREDE.LAST LOOP

                          -- Limpa Restrições Específicas
                          PLIMPA_RESTRICOES_ESPECIFICAS;

                          -- Preenche variável com os valor do Array para atualização da PCDESCONTO
                          vrDESCONTO.nCODREDE := vtPCMED_PROMOCAOREDE(idxRede).CODREDE;

                          -- Chama Procedimento para Inserir os Descontos
                          PINSERE_DESCONTOS;

                          -- Muda Flag indicando que usou Restrição
                          vbUsouRestricao := TRUE;

                        END LOOP; -- Fim Laço de Redes
                      END IF;

                      -- Laço de Clientes
                      IF (vtPCMED_PROMOCAOCLI.COUNT > 0) THEN
                        FOR idxCliente IN vtPCMED_PROMOCAOCLI.FIRST..vtPCMED_PROMOCAOCLI.LAST LOOP

                          -- Limpa Restrições Específicas
                          PLIMPA_RESTRICOES_ESPECIFICAS;

                          -- Preenche variável com os valor do Array para atualização da PCDESCONTO
                          vrDESCONTO.nCODCLI := vtPCMED_PROMOCAOCLI(idxCliente).CODCLI;

                          -- Chama Procedimento para Inserir os Descontos
                          PINSERE_DESCONTOS;

                          -- Muda Flag indicando que usou Restrição
                          vbUsouRestricao := TRUE;

                        END LOOP; -- Fim Laço de Clientes
                      END IF;

                      -- Laço de Áreas de Atuação
                      IF (vtPCMED_PROMOCAOAREA.COUNT > 0) THEN
                        FOR idxArea IN vtPCMED_PROMOCAOAREA.FIRST..vtPCMED_PROMOCAOAREA.LAST LOOP

                          -- Limpa Restrições Específicas
                          PLIMPA_RESTRICOES_ESPECIFICAS;

                          -- Preenche variável com os valor do Array para atualização da PCDESCONTO
                          vrDESCONTO.vAREAATUACAO := vtPCMED_PROMOCAOAREA(idxArea).CODIGO;

                          -- Muda Flag indicando que usou Restrição
                          vbUsouRestricao := TRUE;

                        END LOOP; -- Fim Laço de Áreas de Atuação
                      END IF;

                      -- Laço de Supervisores
                      IF (vtPCMED_PROMOCAOSUP.COUNT > 0) THEN
                        FOR idxSup IN vtPCMED_PROMOCAOSUP.FIRST..vtPCMED_PROMOCAOSUP.LAST LOOP

                          -- Limpa Restrições Específicas
                          PLIMPA_RESTRICOES_ESPECIFICAS;

                          -- Preenche variável com os valor do Array para atualização da PCDESCONTO
                          vrDESCONTO.nCODSUPERVISOR := vtPCMED_PROMOCAOSUP(idxSup).CODSUPERVISOR;

                          -- Chama Procedimento para Inserir os Descontos
                          PINSERE_DESCONTOS;

                          -- Muda Flag indicando que usou Restrição
                          vbUsouRestricao := TRUE;

                        END LOOP; -- Fim Laço de Supervisores
                      END IF;

                      -- Laço de RCA's
                      IF (vtPCMED_PROMOCAOUSUR.COUNT > 0) THEN
                        FOR idxRca IN vtPCMED_PROMOCAOUSUR.FIRST..vtPCMED_PROMOCAOUSUR.LAST LOOP

                          -- Limpa Restrições Específicas
                          PLIMPA_RESTRICOES_ESPECIFICAS;

                          -- Preenche variável com os valor do Array para atualização da PCDESCONTO
                          vrDESCONTO.nCODUSUR := vtPCMED_PROMOCAOUSUR(idxRca).CODUSUR;

                          -- Chama Procedimento para Inserir os Descontos
                          PINSERE_DESCONTOS;

                          -- Muda Flag indicando que usou Restrição
                          vbUsouRestricao := TRUE;

                        END LOOP; -- Fim Laço de RCA's
                      END IF;

                      -- Laço de Restrições de Clientes
                      IF (vtPCMED_PROMOCAORESTCLI.COUNT > 0) THEN
                        FOR idxRestCli IN vtPCMED_PROMOCAORESTCLI.FIRST..vtPCMED_PROMOCAORESTCLI.LAST LOOP

                          -- Limpa Restrições Específicas
                          PLIMPA_RESTRICOES_ESPECIFICAS;

                          -- Preenche variável com os valor do Array para atualização da PCDESCONTO
                          vrDESCONTO.vTIPOGRUPOREST := 'CL';
                          vrDESCONTO.nCODGRUPOREST  := vtPCMED_PROMOCAORESTCLI(idxRestCli).CODGRUPO;

                          -- Chama Procedimento para Inserir os Descontos
                          PINSERE_DESCONTOS;

                          -- Muda Flag indicando que usou Restrição
                          vbUsouRestricao := TRUE;

                        END LOOP; -- Fim Laço de Restrições de Clientes
                      END IF;

                      -- Laço de Restrições de RCA's
                      IF (vtPCMED_PROMOCAORESTRCA.COUNT > 0) THEN
                        FOR idxRestRca IN vtPCMED_PROMOCAORESTRCA.FIRST..vtPCMED_PROMOCAORESTRCA.LAST LOOP

                          -- Limpa Restrições Específicas
                          PLIMPA_RESTRICOES_ESPECIFICAS;

                          -- Preenche variável com os valor do Array para atualização da PCDESCONTO
                          vrDESCONTO.vTIPOGRUPOREST := 'GR';
                          vrDESCONTO.nCODGRUPOREST  := vtPCMED_PROMOCAORESTRCA(idxRestRca).CODGRUPO;

                          -- Chama Procedimento para Inserir os Descontos
                          PINSERE_DESCONTOS;

                          -- Muda Flag indicando que usou Restrição
                          vbUsouRestricao := TRUE;

                        END LOOP; -- Fim Laço de Restrições de RCA's
                      END IF;

                      -- Se não foi usado qualquer Tipo de Restrição
                      IF (NOT vbUsouRestricao) THEN

                        -- Limpa Restrições Específicas
                        PLIMPA_RESTRICOES_ESPECIFICAS;

                        -- Chama Procedimento para Inserir os Descontos
                        PINSERE_DESCONTOS;

                      END IF; -- Fim Condição Se não foi usado qualquer Tipo de Restrição

                    END LOOP; -- Fim Laço de Condições de Venda
                  END LOOP; -- Fim Laço de Plano de Pagamento
                END LOOP; -- Fim Laço de Classes
              END LOOP; -- Fim Laço de Atividades
            END LOOP; -- Fim Laço de Praças
          END LOOP; -- Fim Laço de Regiões
        END LOOP; -- Fim Laço de Filiais
      END LOOP; -- Fim Laço de Origens

      -- Log Alteração
      --IF (pi_vTipoChamada = '4') THEN INSERT INTO PCMED_LOGALTERACAO_PROMOCAO VALUES (SYSDATE, pi_nCodPromocao, 'Fim Processamento Arrays'); END IF;

      --******************************
      -- COM NORMALIZAÇÃO NA PCDESCNTO
      --******************************

      -- Origens informadas
      INSERT INTO PCPROMOCAOORIGEMMED(
                  CODPROMOCAOMED
                , ORIGEMPED )
           SELECT vnNovoCodPromocaoMed -->> Novo Sequencial de Promoção
                , ORIGEMPED
             FROM PCMED_PROMOCAOORIGEM;

      -- Filiais informadas
      INSERT INTO PCPROMOCAOFILMED(
                  CODPROMOCAOMED
                , CODFILIAL )
           SELECT vnNovoCodPromocaoMed -->> Novo Sequencial de Promoção
                , CODFILIAL
             FROM PCMED_PROMOCAOFIL;

      -- Regiões informadas
      INSERT INTO PCPROMOCAOREGIAOMED(
                  CODPROMOCAOMED
                , NUMREGIAO
                , QTMAXCOMBOMED )
           SELECT vnNovoCodPromocaoMed -->> Novo Sequencial de Promoção
                , NUMREGIAO
                , QTMAXCOMBOMED
             FROM PCMED_PROMOCAOREG;

      -- Praças informadas
      INSERT INTO PCPROMOCAOPRACAMED(
                  CODPROMOCAOMED
                , CODPRACA
                , QTMAXCOMBOMED )
           SELECT vnNovoCodPromocaoMed -->> Novo Sequencial de Promoção
                , CODPRACA
                , QTMAXCOMBOMED
             FROM PCMED_PROMOCAOPRACA;

      -- Atividades informadas
      IF ((vnTipoRestricao NOT IN (1, 4))) THEN -- Não for Rede/Cliente
        INSERT INTO PCPROMOCAORAMOATIVMED(
                    CODPROMOCAOMED
                  , CODATIV
                  , QTMAXCOMBOMED )
             SELECT vnNovoCodPromocaoMed -->> Novo Sequencial de Promoção
                  , CODATIV
                  , QTMAXCOMBOMED
               FROM PCMED_PROMOCAOATIV;
      END IF;

      -- Redes informadas
      IF ((vnTipoRestricao IN (1, 4))) THEN -- Se Rede/Cliente
        INSERT INTO PCPROMOCAOREDEMED(
                    CODPROMOCAOMED
                  , CODREDE
                  , QTMAXCOMBOMED )
             SELECT vnNovoCodPromocaoMed -->> Novo Sequencial de Promoção
                  , CODREDE
                  , QTMAXCOMBOMED
               FROM PCMED_PROMOCAOREDE;
      END IF;

      -- Clientes informados
      IF ((vnTipoRestricao IN (1, 4))) THEN -- Se Rede/Cliente
        INSERT INTO PCPROMOCAOCLIMED(
                    CODPROMOCAOMED
                  , CODCLI
                  , QTMAXCOMBOMED )
             SELECT vnNovoCodPromocaoMed -->> Novo Sequencial de Promoção
                  , CODCLI
                  , QTMAXCOMBOMED
               FROM PCMED_PROMOCAOCLI;
      END IF;

      -- Áreas informadas
      IF ((vnTipoRestricao IN (3))) THEN -- Se Área Atuação
        INSERT INTO PCPROMOCAOAREAATUACAOMED(
                    CODPROMOCAOMED
                  , AREAATUACAO )
             SELECT vnNovoCodPromocaoMed -->> Novo Sequencial de Promoção
                  , CODIGO
               FROM PCMED_PROMOCAOAREA;
      END IF;

      -- Supervisores informados
      IF ((vnTipoRestricao IN (2, 4))) THEN -- Se Supervisor/RCA
        INSERT INTO PCPROMOCAOSUPERVMED(
                    CODPROMOCAOMED
                  , CODSUPERV )
             SELECT vnNovoCodPromocaoMed -->> Novo Sequencial de Promoção
                  , CODSUPERVISOR
               FROM PCMED_PROMOCAOSUP;
      END IF;

      -- RCA's informados
      -- (Pode ficar sem dados no Array)
      IF ((vnTipoRestricao IN (2, 4))) THEN -- Se Supervisor/RCA
        INSERT INTO PCPROMOCAOUSURMED(
                    CODPROMOCAOMED
                  , CODUSUR )
             SELECT vnNovoCodPromocaoMed -->> Novo Sequencial de Promoção
                  , CODUSUR
               FROM PCMED_PROMOCAOUSUR;
      END IF;

      -- Planos de Pagamento informados
      INSERT INTO PCPROMOCAOPLPAGMED(
                  CODPROMOCAOMED
                , CODPLPAG )
           SELECT vnNovoCodPromocaoMed -->> Novo Sequencial de Promoção
                , CODPLPAG
             FROM PCMED_PROMOCAOPLPAG;

      -- Condições de Venda informadas
      INSERT INTO PCPROMOCAOCONDVENDAMED(
                  CODPROMOCAOMED
                , CODCONDICAOVENDA )
           SELECT vnNovoCodPromocaoMed -->> Novo Sequencial de Promoção
                , CODCONDICAOVENDA
             FROM PCMED_PROMOCAOCONDVENDA;

      -- Classes informadas
      -- Grupos Comerciais informados
      -- DDMEDICA-2258 (Somente carregará as inf se a promoção não for "Por Rede/Cliente (1)")
      IF ((nvl(vnTipoRestricao,0) NOT IN (1, 4))) THEN
        INSERT INTO PCPROMOCAOCLASSEVENDAMED(
                    CODPROMOCAOMED
                  , CLASSEVENDA
                  , QTMAXCOMBOMED )
             SELECT vnNovoCodPromocaoMed -->> Novo Sequencial de Promoção
                  , CLASSE
                  , QTMAXCOMBOMED
               FROM PCMED_PROMOCAOCLASSE;
        --
        INSERT INTO PCPROMOCAOGRUPOCOMERCMED(
                    CODPROMOCAOMED
                  , CODGRUPOCOMERCIALMED
                  , QTMAXCOMBOMED )
             SELECT vnNovoCodPromocaoMed -->> Novo Sequencial de Promoção
                  , CODGRUPOCOMERCIALMED
                  , QTMAXCOMBOMED
               FROM PCMED_PROMOCAOGRUPOCOMERC;
      END IF;

      -- Brindes informados - HIS.01889.2017
      INSERT INTO PCPROMOCAOBRINDEMED(
                  CODPROMOCAOMED
                , CAMPO
                , CODIGO
                , QTDE
                , PRECOFIXO )
           SELECT vnNovoCodPromocaoMed -->> Novo Sequencial de Promoção
                , CAMPO
                , CODIGO
                , QTDE
                , PRECOFIXO
             FROM PCMED_PROMOCAOBRINDE;

      -- Verbas informadas - DDMEDICA-4915
      INSERT INTO PCPROMOCAOVERBAMED(
                  CODPROMOCAOMED
                , NUMVERBA
                , VALORCOTA )
           SELECT vnNovoCodPromocaoMed -->> Novo Sequencial de Promoção
                , NUMVERBA
                , VALORCOTA
             FROM PCMED_PROMOCAOVERBA;

     /*------------------------------------------------
              Gravar a Tabela PCPROMOCAOTELEVMED
      (DDVENDAS-38892 - Antes de Limpar as Temporárias)
      ------------------------------------------------*/
      PINSERE_PCPROMOCAOTELEVMED(vnNovoCodPromocaoMed);

      -- Limpa Tabelas Temporárias
      PLIMPA_TABELAS_TEMPORARIAS;

      -- Efetiva Transações
      COMMIT;

   /******************************************************************************
    Se chamado para Carregar uma Promoção
    ou Carregar Dados do Relatório da Promoção
    ******************************************/
    ELSIF (pi_vTipoChamada IN ('3', '6', '7')) THEN

      -- Se for para Carregar uma Promoção
      IF    (pi_vTipoChamada = '3') THEN
      
        -- Atualiza Array com a Promoçao passada no Parâmetro
        SELECT CODPROMOCAOMED
          BULK COLLECT INTO vtListaPromocaoSel
          FROM PCPROMOCAOMED
         WHERE (CODPROMOCAOMED = pi_nCodPromocao);

      -- Se for para Carregar Dados do Relatório da Promoção
      ELSIF (pi_vTipoChamada = '6') THEN

        -- Limpa Tabelas do Relatório
        PLIMPA_TABELAS_RELATORIO;

        -- Atualiza Array com as Promoções contidas na Lista de Promoções passadas
        -- como Parâmetro da Proc.
        SELECT CODPROMOCAOMED
          BULK COLLECT INTO vtListaPromocaoSel
          FROM PCPROMOCAOMED
         WHERE (INSTR((','||pi_vListaPromocoes||','),(','||TO_CHAR(CODPROMOCAOMED)||',')) > 0);

      -- Se for para replicar então irá incrementar o ID baseado no último da PCPROMOCAOMED
      ELSIF (pi_vTipoChamada = '7') THEN
        vnCodPromocaoReplicacao := FOBTEM_PROX_CODPROMOCAOMED;

        -- Atualiza Array com a Promoçao passada no Parâmetro
        SELECT CODPROMOCAOMED
          BULK COLLECT INTO vtListaPromocaoSel
          FROM PCPROMOCAOMED
         WHERE (CODPROMOCAOMED = pi_nCodPromocao);

      END IF; -- Fim Condição Tipo Chamada

      ----------------------------------------------------------------------------
      -- Processamento das Promoções Selecionadas
      -------------------------------------------
      IF (vtListaPromocaoSel.COUNT > 0) THEN
        FOR idxPromo IN vtListaPromocaoSel.FIRST..vtListaPromocaoSel.LAST LOOP

          -- Limpa Tabelas Temporárias
          PLIMPA_TABELAS_TEMPORARIAS;

          -- Pega o Código da Promoção Selecionada
          vnCodPromocaoSel := vtListaPromocaoSel(idxPromo);

          -- Carrega Tabela Temporária da Promoção
          INSERT INTO PCMED_PROMOCAO(
                      CODPROMOCAOMED
                    , IDENTIFICADORPROMOCAO
                    , TIPOPOLITICA
                    , DESCRICAORESUMIDA
                    , DESCRICAODETALHADA
                    , DATAINICIAL
                    , DATAFINAL
                    , TIPOPROMOCAO
                    , TIPORESTRICAO
                    , BASECREDDEBRCA
                    , CREDITASOBREPOLITICA
                    , CONSIDERACALCGIROMEDIC
                    , UTILIZADESCREDE
                    , TIPOPLANOPAG
                    , APLICAFAMILIAPRODUTOS
                    , ALTERADESCONTO
                    , ENCARTEFECHADO
                    , PRIORIZACOMISSAO
                    , PRAZOPLPAGMANDATORIO
                    , VALIDARINTERVALOVALIDADEPROD
                    , DTINICIOPROMOLOTE
                    , DTFIMPROMOLOTE
                    , VLRMINITENSPROMOCAO
                    , TIPOSIMPLESNACIONAL
                    , PONTUARACORDOPARCERIA
                    , PERMITECOMISSGARANTIDA
                    , PERMITEQTMINIMASEMOBRIG
                    , BLOQUEIO
                    , VISUALIZARPROMOESP
                    , CODFUNCULTALTERBLOQ
                    , DTULTALTERBLOQ
                    , UTILIZAPERCDESCBASERCA
                    , PERMITIRAUMENTARQTDEKIT
                    , ORIGEMPRECO
                    , CODPRODBRINDE
                    , PARTICIPAPREMIACAOCLI
                    , APLICADESCONTO
                    , TIPOVALIDAVALORMIN -- HIS.01889.2017
                    , TIPOCONCESSAOBRINDE -- HIS.01889.2017
                    , QTDEBRINDE -- HIS.01889.2017
                    , MULTIPLOSBRINDES -- HIS.01889.2017
                    , CODBNF -- HIS.01889.2017
                    , CAMINHOENCARTE
                    , ACEITADESCPROMCAMPANHA
                    , TIPOSOLICITANTE
                    , CODSOLICITANTE
                    , CODGRUPOCOMISSAO
                    , VALIDARMULTEMBMASTER
                    , DESTACARULTCOMPRAS
                    , PARTICIPAPREMIACAOIND
                    , INCLUIRFILTROTELEVENDAS
                    , ISENTOREBAIXACMV
                    , TIPOCOTAGERAL
                    , VALORCOTAGERAL
                    , TIPOCOTACLIENTE
                    , VALORCOTACLIENTE
                    , TIPOLIMITADOR
                    , QTMINCOMBOLIBMED
                    , QTMAXCOMBOMED
                    , CODLIBERACAOCANAIS
                    , CODREFERENCIA
                    )
             SELECT   CASE
                        WHEN NVL(pi_vTipoChamada,'0') = '7' THEN -->> SE REPLICAÇÃO, GRAVA O NOVO CÓDIGO DA PROMOÇÃO NA TABELA TEMPORÁRIA
                           vnCodPromocaoReplicacao
                        ELSE -->> DEMAIS CASOS MANTÉM REGRA ATUAL, GRAVAR NA TABELA TEMPORÁRIA O CÓDIGO DA PROMOÇÃO SELECIONADA
                          CODPROMOCAOMED
                      END CODPROMOCAOMED
                    , IDENTIFICADORPROMOCAO
                    , TIPOPOLITICA
                    , DESCRICAORESUMIDA
                    , DESCRICAODETALHADA
                    , DATAINICIAL
                    , DATAFINAL
                    , TIPOPROMOCAO
                    , TIPORESTRICAO
                    , BASECREDDEBRCA
                    , CREDITASOBREPOLITICA
                    , CONSIDERACALCGIROMEDIC
                    , UTILIZADESCREDE
                    , TIPOPLANOPAG
                    , APLICAFAMILIAPRODUTOS
                    , ALTERADESCONTO
                    , ENCARTEFECHADO
                    , PRIORIZACOMISSAO
                    , PRAZOPLPAGMANDATORIO
                    , VALIDARINTERVALOVALIDADEPROD
                    , DTINICIOPROMOLOTE
                    , DTFIMPROMOLOTE
                    , VLRMINITENSPROMOCAO
                    , TIPOSIMPLESNACIONAL
                    , PONTUARACORDOPARCERIA
                    , PERMITECOMISSGARANTIDA
                    , PERMITEQTMINIMASEMOBRIG
                    , CASE
                        WHEN NVL(pi_vTipoChamada,'0') = '7' THEN --> Quando for Replicação
                          -- Grava de acordo com o parâmetro 9857: Se trabalha com bloqueio de promoções
                          (SELECT NVL(VALOR,'N')
                               FROM PCPARAMFILIAL
                              WHERE UPPER(NOME) = 'UTILIZABLOQUEIOPROMOCOESMED'
                                AND CODFILIAL = '99')
                        ELSE
                          BLOQUEIO
                      END BLOQUEIO
                    , VISUALIZARPROMOESP
                    , CODFUNCULTALTERBLOQ
                    , DTULTALTERBLOQ
                    , UTILIZAPERCDESCBASERCA
                    , PERMITIRAUMENTARQTDEKIT
                    , NVL(ORIGEMPRECO,'T')
                    , CODPRODBRINDE
                    , NVL(PARTICIPAPREMIACAOCLI,'S') --> Padrão = SIM
                    , NVL(APLICADESCONTO,'S') --> Padrão = SIM
                    , TIPOVALIDAVALORMIN -- HIS.01889.2017
                    , TIPOCONCESSAOBRINDE -- HIS.01889.2017
                    , QTDEBRINDE -- HIS.01889.2017
                    , MULTIPLOSBRINDES -- HIS.01889.2017
                    , CODBNF -- HIS.01889.2017
                    , CAMINHOENCARTE
                    , ACEITADESCPROMCAMPANHA
                    , TIPOSOLICITANTE
                    , CODSOLICITANTE
                    , CASE WHEN (NVL(PRIORIZACOMISSAO,'N') = 'S') THEN
                        CODGRUPOCOMISSAO
                      ELSE
                        NULL
                      END CODGRUPOCOMISSAO
                    , VALIDARMULTEMBMASTER
                    , DESTACARULTCOMPRAS
                    , PARTICIPAPREMIACAOIND
                    , INCLUIRFILTROTELEVENDAS
                    , ISENTOREBAIXACMV
                    , TIPOCOTAGERAL
                    , VALORCOTAGERAL
                    , TIPOCOTACLIENTE
                    , VALORCOTACLIENTE
                    , TIPOLIMITADOR
                    , QTMINCOMBOLIBMED
                    , QTMAXCOMBOMED
                    , CODLIBERACAOCANAIS
                    , CODREFERENCIA
                 FROM PCPROMOCAOMED
                WHERE (CODPROMOCAOMED = vnCodPromocaoSel);

          -- Pesquisa Tipo de Promoção
          BEGIN
            SELECT TIPOPOLITICA
                 , TIPOPROMOCAO
              INTO vvTipoPolitica
                 , vvTipoPromocao
              FROM PCPROMOCAOMED
             WHERE (CODPROMOCAOMED = vnCodPromocaoSel);
          EXCEPTION
            WHEN NO_DATA_FOUND THEN
              vvMsgErroGenerico := 'Promoção ' || vnCodPromocaoSel || ' não encontrada!';
              RAISE e_Generico;
          END;

          ----------------
          -- RESTRIÇÕES --
          ----------------

          BEGIN
            SELECT PCPROMOCAOMED.USANORMALIZACAODESC
              INTO vvUsaRegraNormalizaDesc
              FROM PCPROMOCAOMED
             WHERE (PCPROMOCAOMED.CODPROMOCAOMED = vnCodPromocaoSel);
          EXCEPTION
            WHEN NO_DATA_FOUND THEN
              vvUsaRegraNormalizaDesc := 'N';
          END;

          --*****************************************************************************
          -- BUSCA DAS NOVAS TABELAS NORMALIZADAS SE REALIZOU A NORMALIZAÇÃO DA PCDESCNTO
          --*****************************************************************************
          IF    (NVL(vvUsaRegraNormalizaDesc,'N') = 'S') THEN

            -- Carrega Tabela Temporária de Origens
            IF (vvTipoPolitica IN ('D','Q','P','F','B','M','V')) THEN
              INSERT INTO PCMED_PROMOCAOORIGEM(
                          ORIGEMPED )
                   SELECT ORIGEMPED
                     FROM PCPROMOCAOORIGEMMED
                    WHERE (CODPROMOCAOMED = vnCodPromocaoSel);
            END IF;

            -- Carrega Tabela Temporária de Filiais
            IF (vvTipoPolitica IN ('D','Q','P','F','B','M','V')) THEN
              INSERT INTO PCMED_PROMOCAOFIL(
                          CODFILIAL )
                   SELECT CODFILIAL
                     FROM PCPROMOCAOFILMED
                    WHERE (CODPROMOCAOMED = vnCodPromocaoSel);
            END IF;

            -- Carrega Tabela Temporária de Regiões
            IF (vvTipoPolitica IN ('D','Q','P','F','B','M','V')) THEN
              INSERT INTO PCMED_PROMOCAOREG(
                          NUMREGIAO
                        , QTMAXCOMBOMED )
                   SELECT NUMREGIAO
                        , QTMAXCOMBOMED
                     FROM PCPROMOCAOREGIAOMED
                    WHERE (CODPROMOCAOMED = vnCodPromocaoSel);
             END IF;

            -- Carrega Tabela Temporária de Praças
            IF (vvTipoPolitica IN ('D','Q','P','F','B','M','V')) THEN
                INSERT INTO PCMED_PROMOCAOPRACA(
                            CODPRACA
                          , QTMAXCOMBOMED )
                     SELECT CODPRACA
                          , QTMAXCOMBOMED
                       FROM PCPROMOCAOPRACAMED
                      WHERE (CODPROMOCAOMED = vnCodPromocaoSel);
            END IF;

            -- Carrega Tabela Temporária de Ramos de Atividade
            IF (vvTipoPolitica IN ('D','Q','P','F','B','M','V')) THEN
              INSERT INTO PCMED_PROMOCAOATIV(
                          CODATIV
                        , QTMAXCOMBOMED )
                   SELECT CODATIV
                        , QTMAXCOMBOMED
                     FROM PCPROMOCAORAMOATIVMED
                    WHERE (CODPROMOCAOMED = vnCodPromocaoSel);
            END IF;

            -- Carrega Tabela Temporária de Redes
            IF (vvTipoPolitica IN ('D','Q','P','F','B','M','V')) THEN
              INSERT INTO PCMED_PROMOCAOREDE(
                          CODREDE
                        , QTMAXCOMBOMED )
                   SELECT CODREDE
                        , QTMAXCOMBOMED
                     FROM PCPROMOCAOREDEMED
                    WHERE (CODPROMOCAOMED = vnCodPromocaoSel);
            END IF;

            -- Carrega Tabela Temporária de Clientes
            IF (vvTipoPolitica IN ('D','Q','P','F','B','M','V')) THEN
              INSERT INTO PCMED_PROMOCAOCLI(
                          CODCLI
                        , QTMAXCOMBOMED )
                   SELECT CODCLI
                        , QTMAXCOMBOMED
                     FROM PCPROMOCAOCLIMED
                    WHERE (CODPROMOCAOMED = vnCodPromocaoSel);
            END IF;

            -- Carrega Tabela Temporária de Areas de Atuação
            IF (vvTipoPolitica IN ('D','Q','P','F','B','M','V')) THEN
              INSERT INTO PCMED_PROMOCAOAREA(
                          CODIGO )
                   SELECT AREAATUACAO
                     FROM PCPROMOCAOAREAATUACAOMED
                    WHERE (CODPROMOCAOMED = vnCodPromocaoSel);
            END IF;

            -- Carrega Tabela Temporária de Supervisores
            IF (vvTipoPolitica IN ('D','Q','P','F','B','M','V')) THEN
              INSERT INTO PCMED_PROMOCAOSUP(
                          CODSUPERVISOR )
                   SELECT CODSUPERV
                     FROM PCPROMOCAOSUPERVMED
                    WHERE (CODPROMOCAOMED = vnCodPromocaoSel);
            END IF;

            -- Carrega Tabela Temporária de RCA's
            IF (vvTipoPolitica IN ('D','Q','P','F','B','M','V')) THEN
              INSERT INTO PCMED_PROMOCAOUSUR(
                          CODUSUR )
                   SELECT CODUSUR
                     FROM PCPROMOCAOUSURMED
                    WHERE (CODPROMOCAOMED = vnCodPromocaoSel);
            END IF;

            -- Carrega Tabela Temporária de Planos de Pagamento
            IF (vvTipoPolitica IN ('D','Q','P','F','B','M','V')) THEN
              INSERT INTO PCMED_PROMOCAOPLPAG(
