                      , FIMINTERVALOPROMOCAOMED
                      , PARTICIPACOMISSGARANTIDA
                      , PERCDESCBASERCA
                      , VLDESCCMVPROMOCAOMED
                      , REGRAALTERARDESCONTO
                   FROM PCDESCONTO
                  WHERE (CODPROMOCAOMED = vnCodPromocaoSel)
                    AND (CODGRUPOREST IS NOT NULL)
                    AND (TIPOGRUPOREST = 'GP');
          END IF;

          -- Carrega Tabela Temporária de Produtos
          IF (vvTipoPromocao IN ('L')) THEN -->> PROMOÇÃO POR LOTE
            INSERT INTO PCMED_PROMOCAOPRODUTO(
                        CODPROD
                      )
                 SELECT DISTINCT
                        CODPROD
                   FROM PCDESCONTO
                  WHERE (CODPROMOCAOMED = vnCodPromocaoSel)
                    AND (CODPROD        IS NOT NULL);
            INSERT INTO PCMED_PROMOCAOPRODUTO_FAIXA(
                        CODPRODREF
                      , PERCDESC
                      , PERCDESCFIN
                      , PERCOMEXT
                      , PERCOMREP
                      , PERCOMMINT
                      , INICIOINTERVALO
                      , FIMINTERVALO
                      , PRECOFIXO
                      , PARTICIPACOMISSGARANTIDA
                      , PERCDESCBASERCA
                      , NUMLOTE
                      , VALORCOTA
                      , CODIGOINTEGRACAOWMS
                      , VLDESCCMVPROMOCAOMED
                      , REGRAALTERARDESCONTO
                      )
                 SELECT T.CODPROD
                      , T.PERCDESC
                      , T.PERCDESCFIN
                      , T.PERCOMEXT
                      , T.PERCOMREP
                      , T.PERCOMMINT
                      , ROWNUM INICIOINTERVALOPROMOCAOMED -->> Somente serve como Indexador na 2323, por isso ROWNUM
                      , ROWNUM FIMINTERVALOPROMOCAOMED    -->> Somente serve como Indexador na 2323, por isso ROWNUM
                      , T.PRECOFIXOPROMOCAOMED
                      , T.PARTICIPACOMISSGARANTIDA
                      , T.PERCDESCBASERCA
                      , T.NUMLOTE
                      , T.VALORCOTAMED
                      , T.CODIGOINTEGRACAOWMS
                      , T.VLDESCCMVPROMOCAOMED
                      , T.REGRAALTERARDESCONTO
                 FROM
                 (
                 SELECT DISTINCT
                        CODPROD
                      , PERCDESC
                      , PERCDESCFIN
                      , PERCOMEXT
                      , PERCOMREP
                      , PERCOMMINT
                      , 0 INICIOINTERVALOPROMOCAOMED -->> Somente serve como Indexador na 2323
                      , 0 FIMINTERVALOPROMOCAOMED    -->> Somente serve como Indexador na 2323
                      , PRECOFIXOPROMOCAOMED
                      , PARTICIPACOMISSGARANTIDA
                      , PERCDESCBASERCA
                      , NUMLOTE
                      , VALORCOTAMED
                      , CODIGOINTEGRACAOWMS
                      , VLDESCCMVPROMOCAOMED
                      , REGRAALTERARDESCONTO
                   FROM PCDESCONTO
                  WHERE (CODPROMOCAOMED = vnCodPromocaoSel)
                    AND (CODPROD        IS NOT NULL)
                 ) T;
          ELSIF (vvTipoPolitica IN ('D','P','M')) OR
                (vvTipoPromocao IN ('N'))         THEN -- HIS.01889.2017 - Promoção de Campanha também Controla Item Obtrigatório
            -- Se Controla Item Obrigatório (Promoção de Valor e Mix de Produto)
            -- HIS.01889.2017 - Promoção de Campanha também Controla Item Obtrigatório
            IF     (NVL(vvTipoPromocao,' ') IN ('V','M','N')) THEN
               -- Verifica se Promoção Permite Qt. Mínima sem Obrigatoriedade do Produto no Pedido [HIS.04779.2014]
              BEGIN
                SELECT NVL(UPPER(PERMITEQTMINIMASEMOBRIG),'N')
                  INTO vvPermiteQtMinimaSemObrig
                  FROM PCMED_PROMOCAO
                 WHERE CODPROMOCAOMED = vnCodPromocaoSel;
              EXCEPTION WHEN NO_DATA_FOUND THEN
                vvPermiteQtMinimaSemObrig := 'N';
              END;

              INSERT INTO PCMED_PROMOCAOPRODUTO(
                          CODPROD
                        , PERCDESC
                        , PERCDESCFIN
                        , PERCOMEXT
                        , PERCOMREP
                        , PERCOMMINT
                        , PRECOFIXO
                        , OBRIGATORIO
                        , QTOBRIGATORIO
                        , PARTICIPACOMISSGARANTIDA
                        , PERCDESCBASERCA
                        , VLDESCCMVPROMOCAOMED
                        , REGRAALTERARDESCONTO
                        )
                   SELECT DISTINCT
                          CODPROD
                        , PERCDESC
                        , PERCDESCFIN
                        , PERCOMEXT
                        , PERCOMREP
                        , PERCOMMINT
                        , PRECOFIXOPROMOCAOMED
                        , CASE WHEN NVL(vvPermiteQtMinimaSemObrig,'N') = 'S' THEN
                            NVL(PROMOCAOMEDOBRIGATORIO,'N')
                          ELSE
                            CASE WHEN (NVL(INICIOINTERVALOPROMOCAOMED,0) >= 1) THEN
                              'S'
                            ELSE
                              'N'
                            END
                          END OBRIGATORIO
                        , INICIOINTERVALOPROMOCAOMED
                        , PARTICIPACOMISSGARANTIDA
                        , PERCDESCBASERCA
                        , VLDESCCMVPROMOCAOMED
                        , REGRAALTERARDESCONTO
                     FROM PCDESCONTO
                    WHERE (CODPROMOCAOMED = vnCodPromocaoSel)
                      AND (CODPROD        IS NOT NULL);
             -- Se Controla Qtde. KIT (Promoção por Combo Virtual - KIT) ou Promo Casadinha [HIS.01151.2015]
             ELSIF (NVL(vvTipoPromocao,' ') in ('K','S')) THEN
               -- Verifica se Promoção Permite Alterar Qt. do Item no Combo (KIT) no CABEÇALHO
               BEGIN
                 SELECT NVL(UPPER(PERMITIRAUMENTARQTDEKIT),'N')
                   INTO vvPermitirAumentarQtdeKit
                   FROM PCMED_PROMOCAO
                  WHERE CODPROMOCAOMED = vnCodPromocaoSel;
               EXCEPTION WHEN NO_DATA_FOUND THEN
                 vvPermitirAumentarQtdeKit := 'N';
               END;

              INSERT INTO PCMED_PROMOCAOPRODUTO(
                          CODPROD
                        , PERCDESC
                        , PERCDESCFIN
                        , PERCOMEXT
                        , PERCOMREP
                        , PERCOMMINT
                        , PRECOFIXO
                        , QTKIT
                        , PARTICIPACOMISSGARANTIDA
                        , PERCDESCBASERCA
                        , PERMITIRAUMENTARQTDEKIT
                        , OBRIGATORIO
                        , VLDESCCMVPROMOCAOMED
                        , REGRAALTERARDESCONTO
                        )
                   SELECT DISTINCT
                          CODPROD
                        , PERCDESC
                        , PERCDESCFIN
                        , PERCOMEXT
                        , PERCOMREP
                        , PERCOMMINT
                        , PRECOFIXOPROMOCAOMED
                        , INICIOINTERVALOPROMOCAOMED
                        , PARTICIPACOMISSGARANTIDA
                        , PERCDESCBASERCA
                        , CASE
                            WHEN vvTipoPromocao = 'K' THEN
                              NVL(NVL(PERMITIRAUMENTARQTDEKITMED  --> HIS.04608.2015 - Permitir alterar qt de itens do combo por Produto
                                     ,vvPermitirAumentarQtdeKit)  --> Campo do Cabeçalho e Campo do Produto NULOS, assume 'N'.
                                     ,'N')                        --> Campo do Cabeçalho preenchido e Produto NULO, assume o valor do cabeçalho,
                                                                  --> Campo do Produto preenchido, assume ele mesmo.
                          ELSE
                            NULL
                          END PERMITIRAUMENTARQTDEKIT
                        , NVL(PROMOCAOMEDOBRIGATORIO,'N')
                        , VLDESCCMVPROMOCAOMED
                        , REGRAALTERARDESCONTO
                     FROM PCDESCONTO
                    WHERE (CODPROMOCAOMED = vnCodPromocaoSel)
                      AND (CODPROD        IS NOT NULL);
            ELSE
              INSERT INTO PCMED_PROMOCAOPRODUTO(
                          CODPROD
                        , PERCDESC
                        , PERCDESCFIN
                        , PERCOMEXT
                        , PERCOMREP
                        , PERCOMMINT
                        , PRECOFIXO
                        , PARTICIPACOMISSGARANTIDA
                        , PERCDESCBASERCA
                        , VLDESCCMVPROMOCAOMED
                        , REGRAALTERARDESCONTO
                        )
                   SELECT DISTINCT
                          CODPROD
                        , DECODE(vvTipoPromocao,'R',PERCMARKUPMED,PERCDESC)
                        , PERCDESCFIN
                        , PERCOMEXT
                        , PERCOMREP
                        , PERCOMMINT
                        , PRECOFIXOPROMOCAOMED
                        , PARTICIPACOMISSGARANTIDA
                        , PERCDESCBASERCA
                        , VLDESCCMVPROMOCAOMED
                        , REGRAALTERARDESCONTO
                     FROM PCDESCONTO
                    WHERE (CODPROMOCAOMED = vnCodPromocaoSel)
                      AND (CODPROD        IS NOT NULL);
            END IF;
          ELSIF (vvTipoPolitica IN ('Q','F','B','V')) THEN -->> POR PRODUTOS É O ÚNICO QUE TEM PREÇO FIXO POR FAIXA DE QUANTIDADE
            INSERT INTO PCMED_PROMOCAOPRODUTO(
                        CODPROD
                      )
                 SELECT DISTINCT
                        CODPROD
                   FROM PCDESCONTO
                  WHERE (CODPROMOCAOMED = vnCodPromocaoSel)
                    AND (CODPROD        IS NOT NULL);
            INSERT INTO PCMED_PROMOCAOPRODUTO_FAIXA(
                        CODPRODREF
                      , PERCDESC
                      , PERCDESCFIN
                      , PERCOMEXT
                      , PERCOMREP
                      , PERCOMMINT
                      , INICIOINTERVALO
                      , FIMINTERVALO
                      , PRECOFIXO
                      , PARTICIPACOMISSGARANTIDA
                      , PERCDESCBASERCA
                      , VLDESCCMVPROMOCAOMED
                      , REGRAALTERARDESCONTO
                      )
                 SELECT DISTINCT
                        CODPROD
                      , DECODE(vvTipoPromocao,'R',PERCMARKUPMED,DECODE(vvTipoPolitica,'B',PERCBONIFICMERC,PERCDESC))
                      , DECODE(vvTipoPolitica,'B',0,PERCDESCFIN)
                      , PERCOMEXT
                      , PERCOMREP
                      , PERCOMMINT
                      , INICIOINTERVALOPROMOCAOMED
                      , FIMINTERVALOPROMOCAOMED
                      , PRECOFIXOPROMOCAOMED
                      , PARTICIPACOMISSGARANTIDA
                      , PERCDESCBASERCA
                      , VLDESCCMVPROMOCAOMED
                      , REGRAALTERARDESCONTO
                   FROM PCDESCONTO
                  WHERE (CODPROMOCAOMED = vnCodPromocaoSel)
                    AND (CODPROD        IS NOT NULL);
          END IF;

          -- Carrega Tabela Temporária de Brindes - HIS.01889.2017
          IF (vvTipoPromocao IN ('N','K')) THEN
            INSERT INTO PCMED_PROMOCAOBRINDE(
                        CAMPO
                      , CODIGO
                      , QTDE
                      , PRECOFIXO )
                 SELECT CAMPO
                      , CODIGO
                      , QTDE
                      , PRECOFIXO
                   FROM PCPROMOCAOBRINDEMED
                  WHERE (CODPROMOCAOMED = vnCodPromocaoSel);
          END IF;

          -- Carrega Tabela Temporária de Verbas - DDMEDICA-4915
          IF (vvTipoPolitica IN ('D','Q','P','F','M','V')) THEN
            INSERT INTO PCMED_PROMOCAOVERBA(
                        NUMVERBA
                      , VALORCOTA )
                 SELECT NUMVERBA
                      , VALORCOTA
                   FROM PCPROMOCAOVERBAMED
                  WHERE (CODPROMOCAOMED = vnCodPromocaoSel);
          END IF;

          ------------------------------
          -- Editar Produtos da Promoção
          ------------------------------
          IF (pi_vTipoChamada = '3') THEN -->> Se Chamado para Carregar uma Promoção

            -- Guarda Cabeçalho Inicial
            INSERT INTO PCMED_PROMOCAOINICIAL
                      ( CODPROMOCAOMED, IDENTIFICADORPROMOCAO, TIPOPOLITICA, DESCRICAORESUMIDA, DESCRICAODETALHADA,
                        DATAINICIAL, DATAFINAL, TIPOPROMOCAO, TIPORESTRICAO, BASECREDDEBRCA, CREDITASOBREPOLITICA,
                        CONSIDERACALCGIROMEDIC, UTILIZADESCREDE, TIPOPLANOPAG, APLICAFAMILIAPRODUTOS, ALTERADESCONTO,
                        ENCARTEFECHADO, PRIORIZACOMISSAO, PRAZOPLPAGMANDATORIO, VALIDARINTERVALOVALIDADEPROD, DTINICIOPROMOLOTE,
                        DTFIMPROMOLOTE, VLRMINITENSPROMOCAO, TIPOSIMPLESNACIONAL, PONTUARACORDOPARCERIA, PERMITECOMISSGARANTIDA,
                        PERMITEQTMINIMASEMOBRIG, BLOQUEIO, VISUALIZARPROMOESP, CODFUNCULTALTERBLOQ, DTULTALTERBLOQ,
                        UTILIZAPERCDESCBASERCA, PERMITIRAUMENTARQTDEKIT, ORIGEMPRECO, CODPRODBRINDE, USANORMALIZACAODESC,
                        PARTICIPAPREMIACAOCLI, TIPOVALIDAVALORMIN, TIPOCONCESSAOBRINDE, QTDEBRINDE, MULTIPLOSBRINDES,
                        CODBNF, APLICADESCONTO, CAMINHOENCARTE, ACEITADESCPROMCAMPANHA, TIPOSOLICITANTE, CODSOLICITANTE,
                        CODGRUPOCOMISSAO, VALIDARMULTEMBMASTER, DESTACARULTCOMPRAS, PARTICIPAPREMIACAOIND, INCLUIRFILTROTELEVENDAS,
                        ISENTOREBAIXACMV, TIPOLIMITADOR, QTMINCOMBOLIBMED, QTMAXCOMBOMED, CODLIBERACAOCANAIS, CODREFERENCIA )
                 SELECT CODPROMOCAOMED, IDENTIFICADORPROMOCAO, TIPOPOLITICA, DESCRICAORESUMIDA, DESCRICAODETALHADA,
                        DATAINICIAL, DATAFINAL, TIPOPROMOCAO, TIPORESTRICAO, BASECREDDEBRCA, CREDITASOBREPOLITICA,
                        CONSIDERACALCGIROMEDIC, UTILIZADESCREDE, TIPOPLANOPAG, APLICAFAMILIAPRODUTOS, ALTERADESCONTO,
                        ENCARTEFECHADO, PRIORIZACOMISSAO, PRAZOPLPAGMANDATORIO, VALIDARINTERVALOVALIDADEPROD, DTINICIOPROMOLOTE,
                        DTFIMPROMOLOTE, VLRMINITENSPROMOCAO, TIPOSIMPLESNACIONAL, PONTUARACORDOPARCERIA, PERMITECOMISSGARANTIDA,
                        PERMITEQTMINIMASEMOBRIG, BLOQUEIO, VISUALIZARPROMOESP, CODFUNCULTALTERBLOQ, DTULTALTERBLOQ,
                        UTILIZAPERCDESCBASERCA, PERMITIRAUMENTARQTDEKIT, ORIGEMPRECO, CODPRODBRINDE, USANORMALIZACAODESC,
                        PARTICIPAPREMIACAOCLI, TIPOVALIDAVALORMIN, TIPOCONCESSAOBRINDE, QTDEBRINDE, MULTIPLOSBRINDES,
                        CODBNF, APLICADESCONTO, CAMINHOENCARTE, ACEITADESCPROMCAMPANHA, TIPOSOLICITANTE, CODSOLICITANTE,
                        CODGRUPOCOMISSAO, VALIDARMULTEMBMASTER, DESTACARULTCOMPRAS, PARTICIPAPREMIACAOIND, INCLUIRFILTROTELEVENDAS,
                        ISENTOREBAIXACMV, TIPOLIMITADOR, QTMINCOMBOLIBMED, QTMAXCOMBOMED, CODLIBERACAOCANAIS, CODREFERENCIA
                   FROM PCMED_PROMOCAO;
            -- Guarda Valores de Restrições antes da edição do usuário
            INSERT INTO PCMED_PROMOCAORESTRICOES(TIPOREG, TIPOCODIGO, CODIGO) SELECT 'OLD' TIPOREG, 'OP' TIPOCODIGO, ORIGEMPED              FROM PCMED_PROMOCAOORIGEM;

            -- Guarda Valores de Políticas de Produtos antes da edição do usuário
            P_INSERE_PROMOCAOPOLITICAS(pi_nCodPromocao, 
                                       'PCMED_PROMOCAOPRODUTO',
                                       'CODPROD',
                                       'Opr',
                                       vvTipoPromocao, vvTipoPolitica);
  
            -- Guarda Valores de Políticas de Fornecedores antes da edição do usuário
            P_INSERE_PROMOCAOPOLITICAS(pi_nCodPromocao, 
                                       'PCMED_PROMOCAOFORNEC',
                                       'CODFORNEC',
                                       'Ofr',
                                       vvTipoPromocao, vvTipoPolitica);
  
            -- Guarda Valores de Políticas de Marcas antes da edição do usuário
            P_INSERE_PROMOCAOPOLITICAS(pi_nCodPromocao, 
                                       'PCMED_PROMOCAOMARCA',
                                       'CODMARCA',
                                       'Oma',
                                       vvTipoPromocao, vvTipoPolitica);
  
            -- Guarda Valores de Políticas de Linhas antes da edição do usuário
            P_INSERE_PROMOCAOPOLITICAS(pi_nCodPromocao, 
                                       'PCMED_PROMOCAOLINHAPROD',
                                       'CODLINHAPROD',
                                       'Oln',
                                       vvTipoPromocao, vvTipoPolitica);
  
            -- Guarda Valores de Políticas de Departamento antes da edição do usuário
            P_INSERE_PROMOCAOPOLITICAS(pi_nCodPromocao, 
                                       'PCMED_PROMOCAODEPTO',
                                       'CODEPTO',
                                       'Odp',
                                       vvTipoPromocao, vvTipoPolitica);
  
            -- Guarda Valores de Políticas de Seção antes da edição do usuário
            P_INSERE_PROMOCAOPOLITICAS(pi_nCodPromocao, 
                                       'PCMED_PROMOCAOSECAO',
                                       'CODSEC',
                                       'Osc',
                                       vvTipoPromocao, vvTipoPolitica);
  
            -- Guarda Valores de Políticas de Categoria antes da edição do usuário
            P_INSERE_PROMOCAOPOLITICAS(pi_nCodPromocao, 
                                       'PCMED_PROMOCAOCATEG',
                                       'CODCATEGORIA',
                                       'Oct',
                                       vvTipoPromocao, vvTipoPolitica);
  
            -- Guarda Valores de Políticas de Grupo de Produtos antes da edição do usuário
            P_INSERE_PROMOCAOPOLITICAS(pi_nCodPromocao, 
                                       'PCMED_PROMOCAORESTGRUPRO',
                                       'CODGRUPO',
                                       'Ogp',
                                       vvTipoPromocao, vvTipoPolitica);
          END IF; -->> Fim Condição Se Chamado para Carregar uma Promoção

          ------------------------------------
          -- Gravação das Tabelas de Relatório
          ------------------------------------
          IF (pi_vTipoChamada = '6') THEN

            -- Cabeçalho do Relatório
            INSERT INTO PCMED_PROMOCAORELCAB(
                        CODPROMOCAOMED
                      , IDENTIFICADORPROMOCAO
                      , DESCRICAORESUMIDA
                      , DATAINICIAL
                      , DATAFINAL
                      , CODPRODBRINDE
                      , TIPOPOLITICA
                      , TIPOPROMOCAO
                      , DESCRICAOREGRAALTDESC )
                SELECT  CODPROMOCAOMED
                      , IDENTIFICADORPROMOCAO
                      , DESCRICAORESUMIDA
                      , DATAINICIAL
                      , DATAFINAL
                      , CODPRODBRINDE
                      , TIPOPOLITICA
                      , TIPOPROMOCAO
                      , DECODE(ALTERADESCONTO,
                               'S','S - Permitir alterar o desconto/preço',
                               'N','N - Não permitir alterar o desconto/preço',
                               'B','B - Permitir somente alterar o desconto/preço para um preço líquido menor que o cadastrado',
                               'C','C - Permitir somente alterar o desconto/preço para um preço líquido maior que o cadastrado',
                               ALTERADESCONTO)
                   FROM PCMED_PROMOCAO;

            -- Insere no Detalhe do Relatório os Brindes - Campanha
            IF (vvTipoPromocao IN ('N','K')) THEN
              INSERT INTO PCMED_PROMOCAORELDETDESC(
                          CODPROMOCAOMEDREF
                        , TIPO
                        , CODIGO
                        , DESCRICAO
                        , PERCDESC
                        , PRECOFIXO )
                   SELECT vnCodPromocaoSel
                        , CASE
                            WHEN CAMPO = 'GP' THEN
                              'Grupos de Produtos'
                            WHEN CAMPO = 'MA' THEN
                              'Marcas'
                            WHEN CAMPO = 'PR' THEN
                              'Produtos'
                          END TIPO
                        , CODIGO
                        , CASE
                            WHEN CAMPO = 'GP' THEN
                              (SELECT PCGRUPOSCAMPANHAC.DESCRICAO FROM PCGRUPOSCAMPANHAC WHERE PCGRUPOSCAMPANHAC.CODGRUPO = PCMED_PROMOCAOBRINDE.CODIGO)
                            WHEN CAMPO = 'MA' THEN
                              (SELECT PCMARCA.MARCA FROM PCMARCA WHERE PCMARCA.CODMARCA = PCMED_PROMOCAOBRINDE.CODIGO)
                            WHEN CAMPO = 'PR' THEN
                              (SELECT PCPRODUT.DESCRICAO FROM PCPRODUT WHERE PCPRODUT.CODPROD = PCMED_PROMOCAOBRINDE.CODIGO)
                          END DESCRICAO
                        , QTDE
                        , PRECOFIXO
                     FROM PCMED_PROMOCAOBRINDE;
            END IF;

            -- Insere no Detalhe do Relatório as Restrições dos Departamentos - Campanha
            IF (vvTipoPromocao = 'N') THEN
              INSERT INTO PCMED_PROMOCAORELDETREST(
                          CODPROMOCAOMEDREF
                        , TIPO
                        , CODIGO
                        , DESCRICAO )
                   SELECT vnCodPromocaoSel
                        , 'Departamentos' TIPO
                        , PCMED_PROMOCAODEPTO.CODEPTO
                        , PCDEPTO.DESCRICAO -- Descrição
                     FROM PCMED_PROMOCAODEPTO
                        , PCDEPTO
                    WHERE (PCMED_PROMOCAODEPTO.CODEPTO = PCDEPTO.CODEPTO(+));
            -- Insere no Detalhe do Relatório os Descontos dos Departamentos
            ELSIF (vvTipoPolitica = 'D') THEN
              INSERT INTO PCMED_PROMOCAORELDETDESC(
                          CODPROMOCAOMEDREF
                        , TIPO
                        , CODIGO
                        , DESCRICAO
                        , PERCDESC
                        , PERCDESCFIN
                        , PERCOMEXT
                        , PERCOMREP
                        , PERCOMMINT
                        , PERCDESCBASERCA
                        , REGRAALTERARDESCONTO )
                   SELECT vnCodPromocaoSel
                        , 'Departamentos' TIPO
                        , PCMED_PROMOCAODEPTO.CODEPTO
                        , PCDEPTO.DESCRICAO -- Descrição
                        , PCMED_PROMOCAODEPTO.PERCDESC
                        , PCMED_PROMOCAODEPTO.PERCDESCFIN
                        , PCMED_PROMOCAODEPTO.PERCOMEXT
                        , PCMED_PROMOCAODEPTO.PERCOMREP
                        , PCMED_PROMOCAODEPTO.PERCOMMINT
                        , PCMED_PROMOCAODEPTO.PERCDESCBASERCA
                        , PCMED_PROMOCAODEPTO.REGRAALTERARDESCONTO
                     FROM PCMED_PROMOCAODEPTO
                        , PCDEPTO
                    WHERE (PCMED_PROMOCAODEPTO.CODEPTO = PCDEPTO.CODEPTO(+));
            ELSIF (vvTipoPolitica IN ('Q','B','V')) THEN
              INSERT INTO PCMED_PROMOCAORELDETDESC(
                          CODPROMOCAOMEDREF
                        , TIPO
                        , CODIGO
                        , DESCRICAO
                        , PERCDESC
                        , PERCDESCFIN
                        , PERCOMEXT
                        , PERCOMREP
                        , PERCOMMINT
                        , INICIOINTERVALO
                        , FIMINTERVALO
                        , PERCDESCBASERCA
                        , REGRAALTERARDESCONTO )
                   SELECT vnCodPromocaoSel
                        , 'Departamentos' TIPO
                        , PCMED_PROMOCAODEPTO_FAIXA.CODEPTOREF
                        , PCDEPTO.DESCRICAO -- Descrição
                        , PCMED_PROMOCAODEPTO_FAIXA.PERCDESC
                        , PCMED_PROMOCAODEPTO_FAIXA.PERCDESCFIN
                        , PCMED_PROMOCAODEPTO_FAIXA.PERCOMEXT
                        , PCMED_PROMOCAODEPTO_FAIXA.PERCOMREP
                        , PCMED_PROMOCAODEPTO_FAIXA.PERCOMMINT
                        , PCMED_PROMOCAODEPTO_FAIXA.INICIOINTERVALO
                        , PCMED_PROMOCAODEPTO_FAIXA.FIMINTERVALO
                        , PCMED_PROMOCAODEPTO_FAIXA.PERCDESCBASERCA
                        , PCMED_PROMOCAODEPTO_FAIXA.REGRAALTERARDESCONTO
                     FROM PCMED_PROMOCAODEPTO_FAIXA
                        , PCDEPTO
                    WHERE (PCMED_PROMOCAODEPTO_FAIXA.CODEPTOREF = PCDEPTO.CODEPTO(+));
            END IF;

            -- Insere no Detalhe do Relatório as Restrições das Seções - Campanha
            IF (vvTipoPromocao = 'N') THEN
              INSERT INTO PCMED_PROMOCAORELDETREST(
                          CODPROMOCAOMEDREF
                        , TIPO
                        , CODIGO
                        , DESCRICAO )
                   SELECT vnCodPromocaoSel
                        , 'Seções' TIPO
                        , PCMED_PROMOCAOSECAO.CODSEC
                        , PCSECAO.DESCRICAO -- Descrição
                     FROM PCMED_PROMOCAOSECAO
                        , PCSECAO
                    WHERE (PCMED_PROMOCAOSECAO.CODSEC = PCSECAO.CODSEC(+));
            -- Insere no Detalhe do Relatório os Descontos das Seções
            ELSIF (vvTipoPolitica = 'D') THEN
              INSERT INTO PCMED_PROMOCAORELDETDESC(
                          CODPROMOCAOMEDREF
                        , TIPO
                        , CODIGO
                        , DESCRICAO
                        , PERCDESC
                        , PERCDESCFIN
                        , PERCOMEXT
                        , PERCOMREP
                        , PERCOMMINT
                        , PERCDESCBASERCA
                        , REGRAALTERARDESCONTO )
                   SELECT vnCodPromocaoSel
                        , 'Seções' TIPO
                        , PCMED_PROMOCAOSECAO.CODSEC
                        , PCSECAO.DESCRICAO -- Descrição
                        , PCMED_PROMOCAOSECAO.PERCDESC
                        , PCMED_PROMOCAOSECAO.PERCDESCFIN
                        , PCMED_PROMOCAOSECAO.PERCOMEXT
                        , PCMED_PROMOCAOSECAO.PERCOMREP
                        , PCMED_PROMOCAOSECAO.PERCOMMINT
                        , PCMED_PROMOCAOSECAO.PERCDESCBASERCA
